window.__QUIZ_SUBJECT__=[{"id": "objective>Biology>1993>1", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The organ which is sensitive to light in Euglena is the", "images": [], "options": {"A": "gullet", "B": "chloroplast", "C": "eye spot", "D": "contractile vacuole"}, "answer": "C", "explanation": "The organ that is sensitive to light in Euglena is the eye spot. The eye spot, or stigma, is a light-sensitive organelle that helps the organism detect light, allowing it to move towards it for photosynthesis.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1993>2", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which of the following is a similarity between a typical animal cell and a typical plant cell? Presence of", "images": [], "options": {"A": "cellulose cell wall", "B": "chlorophyll", "C": "centrally-placed nucleus", "D": "cell membrane"}, "answer": "D", "explanation": "A typical animal cell and a typical plant cell both possess a cell membrane. While plant cells have a cellulose cell wall, chlorophyll, and a large central vacuole, animal cells do not have these features. However, both types of cells share the presence of a cell membrane, which is a crucial structure that regulates the entry and exit of substances.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1993>3", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL THEORY", "question": "The first scientist to describe the cell was", "images": [], "options": {"A": "Theodor Schwann", "B": "Felix Dujardin", "C": "Robert Hooke", "D": "Charles Darwin"}, "answer": "C", "explanation": "The first scientist to describe the cell was Robert Hooke. He observed cork under a microscope in 1665 and coined the term 'cell' to describe the small, box-like structures he saw.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1993>4", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "In which of the following parts of a cell is the chromosome found", "images": [], "options": {"A": "Nucleus", "B": "Golgi body", "C": "Cytoplasm", "D": "Cell membrane"}, "answer": "A", "explanation": "Chromosomes are found in the nucleus of a cell. The nucleus is the membrane-bound organelle that contains the cell's genetic material, organized into chromosomes, which are crucial for cell division and genetic inheritance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1993>5", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "Use the diagram below to answer the question      The part labelled VII is the", "images": ["Biology/imgs/1993/3F4YKG.jpg"], "options": {"A": "pleural cavity", "B": "lung", "C": "rib", "D": "diaphragm"}, "answer": "D", "explanation": "The diaphragm is a dome-shaped sheet of muscle and tendon located below the lungs.  It separates the thoracic cavity (chest, containing the lungs and heart) from the abdominal cavity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>6", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Use the diagram below to answer the question    The part labelled I is the?", "images": ["Biology/imgs/1993/3F4YKG.jpg"], "options": {"A": "epiglottis", "B": "larynx", "C": "oesophagus", "D": "trachea"}, "answer": "B", "explanation": "The larynx is located in the neck, just above the trachea (windpipe) and below the pharynx (throat).    It is made up of cartilages (like the thyroid cartilage which forms the \"Adam's apple\") and muscles.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>7", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Use the diagram below to answer the question    Exchange of gases takes place in the air sacs contained in the", "images": ["Biology/imgs/1993/3F4YKG.jpg"], "options": {"A": "I", "B": "II", "C": "IV", "D": "V"}, "answer": "C", "explanation": "The exchange of gases (oxygen and carbon dioxide) in humans and other mammals takes place in the air sacs contained in the lungs, called alveoli.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>8", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Use the diagram below to answer the question    During the process of breathing, volume and pressure change occur as a result of the movement of the parts labelled?", "images": ["Biology/imgs/1993/3F4YKG.jpg"], "options": {"A": "I and II", "B": "II and IV", "C": "III and VII", "D": "IV and V"}, "answer": "C", "explanation": "During the process of breathing, changes in volume and pressure occur inside the thoracic cavity as a result of the movement of the diaphragm and the intercostal muscles (rib cage).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>9", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : PUBLIC HEALTH", "question": "Which of the following diseases is caused by deficiency of insulin in the body?", "images": [], "options": {"A": "Malaria", "B": "Diabetes mellitus", "C": "Hepatitis", "D": "Gonorrhoea"}, "answer": "B", "explanation": "Diabetes mellitus is caused by a deficiency of insulin in the body. Insulin is a hormone produced by the pancreas that regulates blood sugar levels. A deficiency can lead to high blood sugar and the symptoms associated with diabetes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1993>10", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "Which of the following is the medium of transportation of nutrients within unicellular organisms?", "images": [], "options": {"A": "Blood", "B": "Serum", "C": "Protoplasm", "D": "Plasma"}, "answer": "C", "explanation": "Protoplasm is the medium of transportation of nutrients within unicellular organisms. It is the living substance within a cell, consisting of cytoplasm and the nucleus, where various cellular processes occur.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1993>11", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Which of the following blood vessels carries oxygenated blood into the heart?", "images": [], "options": {"A": "Pulmonary vein", "B": "Anterior vena cava", "C": "Pulmonary artery", "D": "Aorta"}, "answer": "A", "explanation": "The pulmonary vein is the blood vessel that carries oxygenated blood from the lungs to the heart. Unlike other vessels listed, which either carry deoxygenated blood or serve different functions, the pulmonary vein specifically transports oxygen-rich blood, making it the correct answer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1993>12", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "The conditions that ensure successful exchange of gases in multicellular organisms include the following except", "images": [], "options": {"A": "concentration gradient across the respiratory surface", "B": "presence of thin membrane as the respiratory surface", "C": "last transportation of absorbed gases", "D": "presence of small, dry surface area of the respiratory organ"}, "answer": "D", "explanation": "The presence of a small, dry surface area of the respiratory organ is not conducive to successful gas exchange. Effective gas exchange requires a large, moist surface area to facilitate diffusion. Therefore, this option is the exception among the conditions listed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>13", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "The respiratory organ found in the cockroach is the", "images": [], "options": {"A": "air sac", "B": "trachea", "C": "lung book", "D": "lung"}, "answer": "B", "explanation": "The trachea is the respiratory organ found in cockroaches, which is part of their tracheal system. This system consists of a network of tubes that deliver oxygen directly to tissues, bypassing the need for lungs.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1993>14", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which of the following structures functions as an excretory, system found in flatworm?", "images": [], "options": {"A": "Contractile vacuole", "B": "Nephridium", "C": "Flame cell", "D": "Malplghlan tubule"}, "answer": "C", "explanation": "Flame cells are the excretory structures found in flatworms. They function in osmoregulation and excretion, filtering waste from the body and expelling it through the excretory system.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1993>15", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which of the following organs is associated with deamination of proteins?", "images": [], "options": {"A": "Lung", "B": "Stomach", "C": "Kidney", "D": "Liver"}, "answer": "D", "explanation": "The liver is the organ associated with the deamination of proteins. Deamination is the process of removing an amino group from an amino acid, which occurs primarily in the liver, allowing the body to utilize the remaining carbon skeleton for energy or convert it to glucose.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1993>16", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Ultrafiltration in the kidney takes place in the", "images": [], "options": {"A": "loop of Henle", "B": "renal vein", "C": "Bowman's capsule", "D": "pelvis"}, "answer": "C", "explanation": "Ultrafiltration in the kidney occurs in the Bowman's capsule, which is part of the nephron. During ultrafiltration, blood pressure forces water and small solutes from the blood in the glomerulus into the Bowman's capsule, forming a filtrate that will eventually become urine.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1993>17", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "When an axon is at rest, the concentration of ions on either side of the membrane are different. Which of the following is correct about the concentrations ions on either side of the membrane?", "images": [], "options": {"A": "There is an excess of potassium ions inside the axon and an excess of sodium ions outside", "B": "The inside of the axon becomes positively charged while the outside is negatively charged", "C": "There is an excess of sodium ions on the inner side of the axon", "D": "Chloride and potassium ions begin to move across the membrane"}, "answer": "A", "explanation": "When an axon is at rest, there is a higher concentration of potassium ions (K+) inside the axon and a higher concentration of sodium ions (Na+) outside. This difference in ion concentration is crucial for the generation of action potentials and is maintained by the sodium-potassium pump, which actively transports Na+ out of the cell and K+ into the cell.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1993>18", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The groups of sensory cells found on the upper surface of the tongue are called", "images": [], "options": {"A": "ampullae", "B": "taste bud", "C": "nerve cells", "D": "somatic cells"}, "answer": "B", "explanation": "The groups of sensory cells found on the upper surface of the tongue are called taste buds. These structures contain taste receptor cells that are responsible for detecting different taste modalities such as sweet, sour, salty, bitter, and umami.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>19", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "Which type of eye defect is illustrated in the diagram above?", "images": ["Biology/imgs/1993/DWL7B7.png"], "options": {"A": "Hypermetropia", "B": "myopia", "C": "Cataract", "D": "Astigmatism"}, "answer": "A", "explanation": "Hypermetropia (long-sightedness) is an eye defect in which a person can see distant objects clearly but has difficulty seeing near objects.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1993>20", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "This defect can be corrected by the use of", "images": ["Biology/imgs/1993/DWL7B7.png"], "options": {"A": "convex lens", "B": "concave lens", "C": "cylindrical lens", "D": "surgical operation"}, "answer": "A", "explanation": "Corrected by using convex (converging) lenses in spectacles.    The convex lens bends the light rays inward before they enter the eye, so they are focused directly on the retina.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1993>21", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following is not a courtship behaviour exhibited of animals?", "images": [], "options": {"A": "Pairing", "B": "Display", "C": "Seasonal migration", "D": "Hibernation"}, "answer": "C", "explanation": "Seasonal migration is not a courtship behavior; it is a survival strategy used by some animals to find food or breeding grounds. Courtship behaviors are specific actions or displays that animals perform to attract mates, such as pairing, display, and territorialism.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1993>22", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS", "question": "Which of the following mineral salts is a trace element?", "images": [], "options": {"A": "Zinc", "B": "Carbon", "C": "Hydrogen", "D": "Potassium"}, "answer": "A", "explanation": "Zinc is a trace element, which means it is required by organisms in very small amounts for various biological functions. The other options (Carbon, Hydrogen, Potassium, Calcium) are not classified as trace elements; they are essential macronutrients or elements needed in larger quantities.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1993>23", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "Which of the following organisms reduces nitrates in the soil to gaseous nitrogen?", "images": [], "options": {"A": "Euglena", "B": "Protozoan", "C": "Denitrifying bacterium", "D": "Parasitic mould"}, "answer": "C", "explanation": "Denitrifying bacteria are responsible for reducing nitrates in the soil to gaseous nitrogen, a process that is part of the nitrogen cycle. This process helps to return nitrogen to the atmosphere, completing the cycle of nitrogen in the ecosystem.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1993>24", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "The process whereby microorganisms can convert atmospheric nitrogen into nitrogenous compound is  known as", "images": [], "options": {"A": "nitrogen cycle", "B": "nitrogen fixation", "C": "denitrification", "D": "putrefaction"}, "answer": "B", "explanation": "The process whereby microorganisms convert atmospheric nitrogen into nitrogenous compounds is known as nitrogen fixation. This is crucial for making nitrogen available to plants, as they cannot use atmospheric nitrogen directly.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>25", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : PLANT STRUCTURE", "question": "What is the function of the part labelled ll?", "images": ["Biology/imgs/1993/BH22N2.jpg"], "options": {"A": "Attraction of insects", "B": "Secretion of nectar", "C": "Protection of the stigma", "D": "Attachment of flower to the shoot"}, "answer": "A", "explanation": "Petals are often brightly coloured and sometimes scented.    They attract insects, birds, and other pollinators needed for pollination.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>26", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The function of the part labelled l is to", "images": ["Biology/imgs/1993/BH22N2.jpg"], "options": {"A": "receive pollen grains", "B": "produce nectar", "C": "store the pollen grains", "D": "store the ovules"}, "answer": "A", "explanation": "The function of the part labelled 'l' is to receive pollen grains. In flowering plants, the stigma is the part of the pistil that receives pollen during pollination, which is essential for fertilization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>27", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "How would you describe the position of the ovary in relation to the receptacle?", "images": ["Biology/imgs/1993/BH22N2.jpg"], "options": {"A": "Superior", "B": "lnferior", "C": "Semi-inferior", "D": "Gamosepalous"}, "answer": "A", "explanation": "The ovary sits above the receptacle (on top of where the sepals, petals, and stamens are attached).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>28", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS", "question": "What type of relationship exists between a tapeworm an an infected mammals?", "images": [], "options": {"A": "Symbiosis", "B": "Commensalism", "C": "Predation", "D": "Parasitism"}, "answer": "D", "explanation": "The relationship between a tapeworm and an infected mammal is classified as parasitism. In this relationship, the tapeworm benefits by obtaining nutrients at the expense of the host, which is harmed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1993>29", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The parts labelled IV, V and VI respectively are the", "images": ["Biology/imgs/1993/R2DC6M.png"], "options": {"A": "ciliary body, optic nerve and yellow spot", "B": "blind spot, optic nerve and suspensory ligament", "C": "vitreous humour, yellow spot and optic nerve", "D": "blind spot, optic nerve and pupil"}, "answer": "C", "explanation": "The parts labelled IV, V and VI respectively are the vitreous humour, yellow spot and optic nerve.  Vitreous humour: A clear, jelly-like substance that fills the space between the lens and the retina, helping the eye maintain its shape and allowing light to pass to the retina.    Yellow spot (fovea centralis): A small, yellowish area on the retina with a high concentration of cones, responsible for sharp, detailed central vision.    Optic nerve: A bundle of nerve fibers that carries visual information from the retina to the brain for interpretation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>30", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The light ray entering the eye goes through the following route", "images": ["Biology/imgs/1993/R2DC6M.png"], "options": {"A": "II, III, I, IV, V", "B": "II, I, VII, III", "C": "II, I, III, IV", "D": "V, VI, III, I"}, "answer": "C", "explanation": "The light ray entering the eye goes through the following route II, I, III, IV", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>31", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "Which of the following structures are adjusted in focusing the image of a distant or near object on the retina?", "images": [], "options": {"A": "I and II", "B": "II and III", "C": "III and VII", "D": "IV and V"}, "answer": "C", "explanation": "The structures that adjust in focusing the image of a distant or near object on the retina are primarily the lens (II) and the ciliary muscles (I). The lens changes shape to focus light on the retina, while the ciliary muscles control the shape of the lens. Therefore, the correct option is 'I and II'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>32", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "Which of the following best describes a marine habitat? A large body of water", "images": [], "options": {"A": "which has no distinctive colour or taste", "B": "with high concentration of salt", "C": "with little suspended materials", "D": "with no water weeds"}, "answer": "B", "explanation": "A marine habitat is characterized by a high concentration of salt, as it refers to oceanic or sea environments. This distinguishes it from freshwater habitats. Therefore, the correct option is 'with high concentration of salt'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1993>33", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "The following are features of the tropical rain forest except", "images": [], "options": {"A": "abundant water supply", "B": "loose and moist soil", "C": "short trees growing beneath tall trees", "D": "scanty trees with small leaves"}, "answer": "D", "explanation": "The tropical rain forest is known for its abundant water supply, loose and moist soil, tall trees, and a rich diversity of animals. However, 'scanty trees with small leaves' does not accurately describe a tropical rain forest, as it typically has a dense canopy and large leaves. Therefore, the correct option is 'scanty trees with small leaves'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>34", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "The following are features of Northern Guinea Savanna except", "images": [], "options": {"A": "presence of tall trees with thick bark", "B": "bare soil with very few trees", "C": "presence of fire-resistant trees", "D": "predominance of woody trees."}, "answer": "D", "explanation": "The Northern Guinea Savanna is characterized by the presence of fire-resistant trees, abundant herbivores, and a mix of woody trees and bare soil. However, 'predominance of woody trees' is not a defining feature, as the savanna is more open with scattered trees rather than a dense forest. Therefore, the correct option is 'predominance of woody trees'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>35", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Which of the following explains the term pyramid of numbers?", "images": [], "options": {"A": "The number of organisms in a trophic level", "B": "The relationship between plants in different trophic levels", "C": "The number of saprophytes and parasites in a habitat", "D": "Progressive decrease in the number of individuals from lower to higher trophic level"}, "answer": "D", "explanation": "The pyramid of numbers illustrates the number of organisms at each trophic level in an ecosystem, typically showing a progressive decrease in the number of individuals from lower to higher trophic levels. Therefore, the correct option is 'Progressive decrease in the number of individuals from lower to higher trophic level'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>36", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "In which of the following processes is carbondioxide not given out?", "images": [], "options": {"A": "Respiration in plants", "B": "Decay of organism", "C": "Burning of organic matter", "D": "During photosynthesis."}, "answer": "D", "explanation": "During photosynthesis, plants take in carbon dioxide and convert it into glucose and oxygen, thus not releasing carbon dioxide. This process is essential for plant growth and contributes to the oxygen supply in the atmosphere.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1993>37", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Sea water taken in by a living organism can be recycled into the atmosphere through all the following  processes except", "images": [], "options": {"A": "transpiration", "B": "digestion", "C": "excretion", "D": "respiration"}, "answer": "B", "explanation": "Digestion is the process by which organisms break down food into smaller components for absorption. It does not directly recycle sea water into the atmosphere, unlike transpiration, excretion, respiration, and decay, which can involve water loss to the atmosphere.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>38", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : PUBLIC HEALTH", "question": "Which of the following water pollutant may contain organisms that cause dysentery?", "images": [], "options": {"A": "Pesticides", "B": "Sewage", "C": "Industrial wastes", "D": "Fertilizers"}, "answer": "B", "explanation": "Sewage can contain pathogens, including organisms that cause dysentery, such as bacteria and viruses. Proper treatment of sewage is crucial to prevent waterborne diseases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>39", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following is not an adaptation of plants or animals to desert environment?", "images": [], "options": {"A": "Well developed tap root system", "B": "Small leaves with thick Epidermis", "C": "Stems with spike-like leaves", "D": "Broad leaves for storage"}, "answer": "D", "explanation": "Broad leaves for storage are not an adaptation to desert environments. Instead, desert plants typically have small leaves or spines to reduce water loss, while broad leaves are more common in humid environments where water is abundant.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>40", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : COMMUNITY", "question": "A climax community is characterised by", "images": [], "options": {"A": "a stable composition of plant and animal species", "B": "rapid changes in the composition of species", "C": "constant changes in appearance of the habitat", "D": "different species occurring at different times"}, "answer": "A", "explanation": "A climax community is characterized by a stable composition of plant and animal species, which means that the community has reached a stable state where species composition remains relatively constant over time, barring any major environmental changes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>41", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING", "question": "Which of the following is not a characteristic of overcrowding in plant and animal community?", "images": [], "options": {"A": "Population outstripping available space", "B": "Population exceeding available food", "C": "Competition within the population", "D": "increase in primary production"}, "answer": "D", "explanation": "The option 'increase in primary production' is not a characteristic of overcrowding. Overcrowding typically leads to resource depletion and competition, which can actually decrease primary production due to limited resources.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>42", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "APPLICATION OF VARIATIONS :", "question": "The use of predators or parasites to control pests in the farm is known as", "images": [], "options": {"A": "predator control", "B": "chemical control", "C": "biological control", "D": "animal control"}, "answer": "C", "explanation": "The use of predators or parasites to control pests is known as 'biological control'. This method utilizes natural enemies to manage pest populations, contrasting with chemical control which uses pesticides.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>43", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION", "question": "Which of the following substances cannot control the growth of harmful micro organisms?", "images": [], "options": {"A": "Antibiotics", "B": "Hypertonic salt solution", "C": "Disinfectants", "D": "isotonic sugar solution"}, "answer": "D", "explanation": "An isotonic sugar solution does not control the growth of harmful microorganisms. In fact, isotonic solutions do not create a hostile environment for microbes, unlike hypertonic solutions which can dehydrate and kill them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>44", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "APPLICATION OF VARIATIONS :", "question": "Which of the following is the underlining Principle in the adoption of biological control of pests?", "images": [], "options": {"A": "Knowledge of agricultural practices by the farmer", "B": "Relationship between plants and animals", "C": "The presence of poisonous chemicals in the farm", "D": "The predator prey relationship in ecological community"}, "answer": "D", "explanation": "The predator-prey relationship is a fundamental principle in biological control. Understanding this relationship helps in effectively managing pest populations by introducing natural predators.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>45", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "The following agencies are responsible for conservation of in Nigeria except", "images": [], "options": {"A": "Forest department", "B": "Nigerian conservation society", "C": "Games reserve authority", "D": "Nigerian red cross society"}, "answer": "D", "explanation": "The Nigerian Red Cross Society is primarily focused on humanitarian efforts and disaster response, rather than conservation. The other agencies listed are directly involved in conservation efforts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>46", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "The largest game reserve in Nigeria is the", "images": [], "options": {"A": "Kianji game reserve in Niger state", "B": "Zamfara Forest Reserve In Sokoto state", "C": "Yankari game reserve in Bauchi state", "D": "Borgu park reserve in Niger state"}, "answer": "C", "explanation": "The largest game reserve in Nigeria is the Yankari Game Reserve, located in Bauchi State. It is well-known for its diverse wildlife and natural hot springs, making it a significant conservation area.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>47", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "The table below indicates the result of an experiment during which grains of different colours in two maize cobs were counted  Maize cob\t   White \t    Pink  \t    Red    I\t     30\t     60\t    30   II\t     50\t     99\t    49  Which of the following ratios agrees with the results?", "images": [], "options": {"A": "9:3:3", "B": "1:2:1", "C": "1:3:1", "D": "2:1:1"}, "answer": "B", "explanation": "The ratios of the colors of grains in the two maize cobs that agrees with the result is 1:2:1", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>1993>48", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY", "question": "One of the factors that must be considered for safe blood transfusion is", "images": [], "options": {"A": "social class of the donor", "B": "age of the recipient", "C": "rhesus factors of the donor and the recipient", "D": "nationality of the donor"}, "answer": "C", "explanation": "For safe blood transfusion, it is crucial to consider the rhesus factors of both the donor and the recipient. This is because incompatible rhesus factors can lead to serious immune reactions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>49", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : LINKAGE, SEX DETERMINATION AND SEX LINKED CHARACTERS", "question": "One of the major criticisms against 'Mendelian laws is that they do not recognize that", "images": [], "options": {"A": "one trait is often controlled by many pairs of genes", "B": "single factor inheritance is never a reality", "C": "complete dominance is always possible", "D": "incomplete dominance is not possible"}, "answer": "A", "explanation": "One of the major criticisms against Mendelian laws is that they do not recognize that one trait can be controlled by many pairs of genes, a concept known as polygenic inheritance. This complexity is not accounted for in simple Mendelian ratios.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>1993>50", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "Identical twins inherit their genes from", "images": [], "options": {"A": "the same ovum and different sperms", "B": "the same sperm and different ova", "C": "different sperms and many ova", "D": "the same ovum and the same sperm"}, "answer": "D", "explanation": "Identical twins inherit their genes from the same ovum and the same sperm. This results in them having identical genetic material, which is why they are referred to as monozygotic twins.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>51", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "The offspring produced when pure strains interbreed is described as", "images": [], "options": {"A": "dominance", "B": "phenotype", "C": "allele", "D": "hybrid"}, "answer": "D", "explanation": "The offspring produced when pure strains interbreed is described as a 'hybrid'. A hybrid is the result of combining the qualities of two organisms of different breeds, varieties, species, or genera through sexual reproduction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>52", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY", "question": "Which of the following diseases or disorders can be prevented by the application of the knowledge of  heredity through marriage counselling?", "images": [], "options": {"A": "Sickle cell anaemia", "B": "Haemophilia", "C": "Diabetes mellitus", "D": "Colour blindness"}, "answer": "A", "explanation": "Sickle cell anaemia can be prevented through marriage counselling by understanding the genetic risks involved. If both parents are carriers of the sickle cell trait, there is a 25% chance that their child will have sickle cell disease. Knowledge of heredity can help couples make informed decisions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>53", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "Study the genetic cross above showing the inheritance of blood groups from the cross above    Which of the following F1 offspring does not belong to the father?", "images": ["Biology/imgs/1993/L29DCN.png"], "options": {"A": "AA", "B": "AO", "C": "OB", "D": "OO"}, "answer": "D", "explanation": "In a genetic cross for blood groups, the F1 offspring that does not belong to the father can be determined by the alleles contributed by the parents. If the father has genotype AB, he can pass on either A or B alleles. The OO offspring would not be possible if the father does not have the O allele.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>1993>54", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "Which of the following is a function of the chromosome?", "images": [], "options": {"A": "Transmission of hereditary traits", "B": "Protein synthesis", "C": "Excretion", "D": "Energy production"}, "answer": "A", "explanation": "The primary function of chromosomes is the transmission of hereditary traits. Chromosomes carry genes, which are the units of heredity, and ensure that genetic information is accurately replicated and distributed during cell division.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>55", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following does not illustrate adaptation to the environment?", "images": [], "options": {"A": "Colour changes by chameleon", "B": "Streamline shape of fishes", "C": "Light bones in birds", "D": "Development of big muscles by a weight lifter"}, "answer": "D", "explanation": "The development of big muscles by a weight lifter does not illustrate adaptation to the environment in the same way that the other options do. Adaptation refers to changes that occur over generations in response to environmental pressures, while muscle growth from weight lifting is an individual response to training, not a genetic adaptation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>56", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "EVOLUTION : ADAPTIVE COLOURATION", "question": "The changing of colour by a chameleon to that of the environment is an example of", "images": [], "options": {"A": "adaptive radiation", "B": "protective coloration", "C": "courtship display", "D": "display of body colour"}, "answer": "B", "explanation": "The changing of color by a chameleon to match its environment is an example of protective coloration. This adaptation helps the chameleon avoid predators by blending in with its surroundings, which is a survival strategy. Protective coloration is a form of camouflage that allows animals to avoid detection.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>57", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The division of labour in social insects is an example of", "images": [], "options": {"A": "structural adaptation", "B": "physiological adaptation", "C": "commensalism", "D": "behavioural adaptation"}, "answer": "D", "explanation": "The division of labor in social insects, such as ants and bees, is an example of behavioral adaptation. This adaptation allows different members of the colony to specialize in certain tasks, such as foraging, nursing, or defending the nest, which increases the efficiency and survival of the colony as a whole.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>58", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The swarming especially at the beginning of the rainy season is a courtship behaviour shown by?", "images": [], "options": {"A": "migratory birds", "B": "pigeons", "C": "crickets", "D": "winged termites"}, "answer": "D", "explanation": "The swarming behavior at the beginning of the rainy season is typically exhibited by winged termites. This behavior is part of their courtship rituals, where they swarm to mate and establish new colonies. Courtship behavior is a set of actions performed by animals to attract mates.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>1993>59", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "EVOLUTION : ADAPTATION FOR SURVIVAL", "question": "Lamarck's evolution theory could be summarised by the statement that", "images": [], "options": {"A": "only the fittest can survive in a challenging environment", "B": "species that are unable to adapt become extinct", "C": "new characteristics do not arise in organisms in time of need", "D": "the changing environment imposes structural physiological and behavioural changes in organisms"}, "answer": "D", "explanation": "Lamarck's theory of evolution can be summarized by the idea that the changing environment imposes structural, physiological, and behavioral changes in organisms. This theory suggests that organisms can acquire traits during their lifetime that can be passed on to their offspring, which is a key aspect of Lamarckism.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1993>60", "subject": "Biology", "year": "1993", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS", "question": "The property of clay soil that prevents it from supporting thick vegetation is its", "images": [], "options": {"A": "possession of chemically weathered granite rocks", "B": "inability to retain much water", "C": "tendency of becoming waterlogged", "D": "porosity and low water retention ability"}, "answer": "C", "explanation": "The property of clay soil that prevents it from supporting thick vegetation is its tendency to become waterlogged. Clay soil has very small particles that compact tightly, leading to poor drainage and high water retention. This waterlogging can suffocate plant roots and inhibit growth, making it difficult for thick vegetation to thrive.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>1", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : PRODUCERS", "question": "All animals are dependent on green plants because plants", "images": [], "options": {"A": "shelter them from excessive heat from the sun", "B": "give them protection from enemies", "C": "are used for building houses and furniture", "D": "manufacture food for animals"}, "answer": "D", "explanation": "All animals are dependent on green plants because plants manufacture food for animals through the process of photosynthesis. This food is essential for the survival of herbivores, which are then consumed by carnivores, creating a food chain.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>2", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL THEORY", "question": "The scientist who discovered the cell while examining a thin slice of cork under the microscope was", "images": [], "options": {"A": "Robert Hooke", "B": "Anton van Leeuwenhoek", "C": "Matthias Schleiden", "D": "Theodor Schwann"}, "answer": "A", "explanation": "The scientist who discovered the cell while examining a thin slice of cork under the microscope was Robert Hooke. He coined the term 'cell' after observing the small, box-like structures in the cork.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>3", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The two important physical processes involved in the absorption and transport of materials in plants are", "images": [], "options": {"A": "diffusion and plasmolysis", "B": "cohesion and adhesion", "C": "flaccidity and turgidity", "D": "osmosis and diffusion"}, "answer": "D", "explanation": "The two important physical processes involved in the absorption and transport of materials in plants are osmosis and diffusion. Osmosis is the movement of water across a semi-permeable membrane, while diffusion is the movement of solutes from an area of higher concentration to an area of lower concentration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>4", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION", "question": "The process by which plants manufacture food from carbondioxide and water, using energy from the sun is  termed", "images": [], "options": {"A": "chemosynthesis", "B": "photosynthesis", "C": "autotrophism", "D": "heterotrophism"}, "answer": "B", "explanation": "The process by which plants manufacture food from carbon dioxide and water, using energy from the sun, is termed photosynthesis. During this process, plants convert light energy into chemical energy stored in glucose.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>5", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "EVOLUTION : ADAPTATION FOR SURVIVAL", "question": "The process in which insects undergo conspicuous changes in form and appearance during development  is known as", "images": [], "options": {"A": "ecdysis", "B": "metamorphosis", "C": "aestivation", "D": "migration"}, "answer": "B", "explanation": "The process in which insects undergo conspicuous changes in form and appearance during development is known as metamorphosis. This process includes stages such as larva, pupa, and adult, leading to significant physical changes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>6", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "What is the foot labelled I adapted to?", "images": ["Biology/imgs/1994/8BEAXJ.png"], "options": {"A": "Feeding on flesh", "B": "Eating grains", "C": "Swimming in water", "D": "Perching on trees"}, "answer": "C", "explanation": "The foot labelled I is webbed foot, Webbed feet are a structural adaptation found in aquatic animals like ducks, frogs, and some reptiles.  A duck swims with its webbed feet, which act like paddles to push against water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>7", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The foot labelled III is strong and has blunt claws on its digits, This implies that the bird", "images": ["Biology/imgs/1994/8BEAXJ.png"], "options": {"A": "is a scavenger", "B": "is a bird of prey", "C": "is a marine bird", "D": "uses the foot to scratch the soil"}, "answer": "D", "explanation": "This implies that the bird is adapted for scratching the ground in search of food such as seeds, roots, and insects.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>8", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The long and sharp claws in the font labelled ll show that the bird uses them to?", "images": ["Biology/imgs/1994/8BEAXJ.png"], "options": {"A": "hold onto its prey", "B": "paddle in water", "C": "glide in the alt", "D": "scratch the earth for worms"}, "answer": "A", "explanation": "Long and sharp claws are typically used by birds to hold onto their prey. This adaptation is crucial for hunting and capturing food, making 'hold onto its prey' the correct option.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>9", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : DECOMPOSITION", "question": "Conventional method of sewage disposal involves all the following except defaecating", "images": [], "options": {"A": "into pit latrines", "B": "in open fields", "C": "into cesspit", "D": "into water home sewage system"}, "answer": "D", "explanation": "The conventional method of sewage disposal typically does not involve defecating into a water home sewage system, as this is a method of disposal rather than a location for defecation. Therefore, the correct option is 'into water home sewage system'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>10", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "Which of the following actions is not an example of a simple reflex action?", "images": [], "options": {"A": "Knee jerk", "B": "Blinking of the eye", "C": "Withdrawal of hand from hot object", "D": "Reading a book"}, "answer": "D", "explanation": "Reading a book is a complex cognitive task that involves higher brain functions and is not a simple reflex action. Simple reflex actions are automatic responses to stimuli, such as the knee jerk or withdrawal from a hot object. Thus, the correct option is 'Reading a book'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>11", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "In which of the following is a cellulose cell wall present", "images": [], "options": {"A": "Amoeba", "B": "Mammalian white blood corpuscle", "C": "spirogyra", "D": "paramecium"}, "answer": "C", "explanation": "Cellulose cell walls are characteristic of plant cells and certain algae. Among the options, Spirogyra is a green algae that has a cellulose cell wall, while the other options (Amoeba, Mammalian white blood corpuscle, Paramecium, and parasitic worms) do not have cellulose cell walls.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>12", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : COMMUNITY", "question": "Which of the following organisms exists as a filament?", "images": [], "options": {"A": "Euglena", "B": "Amoeba", "C": "Volvox", "D": "Spirogyra"}, "answer": "D", "explanation": "Spirogyra is a filamentous green algae that exists in long, thread-like structures. The other options (Euglena, Amoeba, Volvox, and Paramecium) do not typically form filaments.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>13", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "All the following can illustrate the dynamic nature of the ecosystem except", "images": [], "options": {"A": "nitrogen cycle", "B": "carbon cycle", "C": "water cycle", "D": "locomotion in organisms"}, "answer": "D", "explanation": "Locomotion in organisms does not illustrate the dynamic nature of ecosystems in the same way that the cycles of nitrogen, carbon, water, and nutrients do. The latter are processes that involve the flow and transformation of energy and matter in ecosystems.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>14", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Which of the following measures does not ensure conservation?", "images": [], "options": {"A": "Establishing forest and game reserves", "B": "Encouraging people to plant trees", "C": "Founding societies that promote conservation", "D": "Enclosing fishes in ponds where they will not be stolen"}, "answer": "D", "explanation": "Enclosing fishes in ponds where they will not be stolen does not ensure conservation in the broader sense. Conservation typically involves protecting habitats and ecosystems, rather than simply preventing theft of individual species.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>15", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : PRODUCERS", "question": "Which of the following is not required for primary production to occur in plants?", "images": [], "options": {"A": "Chlorophyll", "B": "Sugar", "C": "Water", "D": "Carbon dioxide"}, "answer": "B", "explanation": "Sugar is not required for primary production to occur in plants. Primary production primarily requires chlorophyll, water, carbon dioxide, and solar energy to convert light energy into chemical energy through photosynthesis. Sugar is a product of this process, not a requirement.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>16", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of the following blood group(s) is/are the universal donor(s)", "images": [], "options": {"A": "O", "B": "A", "C": "B", "D": "AB"}, "answer": "A", "explanation": "The universal donor blood group is O because it does not have A or B antigens on the surface of its red blood cells. This means that people with blood group O can donate blood to individuals of any other blood group without the risk of an immune reaction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>17", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "The branch of science which deals with resemblances, origin and expression of biological variations is called", "images": [], "options": {"A": "embryology", "B": "ecology", "C": "entomology", "D": "genetics"}, "answer": "D", "explanation": "The branch of science that deals with resemblances, origin, and expression of biological variations is called genetics. Genetics studies how traits are inherited and how variations occur in organisms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>18", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Which of the following can cause desert encroachment?", "images": [], "options": {"A": "Afforestation", "B": "Irrigation", "C": "Planting of trees", "D": "Overgrazing"}, "answer": "D", "explanation": "Overgrazing can lead to desert encroachment as it removes vegetation cover, which is essential for maintaining soil structure and preventing erosion. Without sufficient plant cover, soil can become degraded and desertification can occur.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>19", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The morphological, physiological and behavioural characteristics which enable an organism to survive in  its environment is called", "images": [], "options": {"A": "heredity", "B": "ecology", "C": "competition", "D": "adaptation"}, "answer": "D", "explanation": "Adaptation refers to the morphological, physiological, and behavioral characteristics that enable an organism to survive in its environment. These adaptations can be structural (like the shape of a beak), physiological (like the ability to conserve water), or behavioral (like migration patterns).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>20", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which of the following performs the same function as the contractile vacuole of a unicellular organism?", "images": [], "options": {"A": "Kidney", "B": "Alimentary canal", "C": "Liver", "D": "Pancreas"}, "answer": "A", "explanation": "The kidney performs a similar function to the contractile vacuole of a unicellular organism, as both are involved in the regulation of water and waste removal. The contractile vacuole expels excess water and waste from the cell, while the kidney filters blood to remove waste and regulate fluid balance in the body.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>21", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Which of the following represents the correct order in a possible food chain?", "images": [], "options": {"A": "Crustacean -> diatom -> fish -> man", "B": "Fish -> crustacean -> man -> diatom", "C": "Man -> fish -> crustacean -> diatom", "D": "Diatom -> crustacean -> fish -> man"}, "answer": "D", "explanation": "The correct order in a food chain typically starts with producers and moves up to consumers. In this case, 'Diatom -> crustacean -> fish -> man' represents a logical food chain where diatoms (a type of phytoplankton) are consumed by crustaceans, which are then eaten by fish, and finally, humans consume fish.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>22", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : COMMUNITY", "question": "Which of the following relationships illustrates competition?", "images": [], "options": {"A": "Cattle egret moving along with cattle", "B": "Goats and cows grazing on a small grass lawn", "C": "Mosses succeeding lichens in a rocky terrain", "D": "Red mangrove swamp dying and replaced by white mangrove"}, "answer": "B", "explanation": "Competition occurs when two or more organisms vie for the same resources, such as food or space. In this case, 'Goats and cows grazing on a small grass lawn' illustrates competition as both species are competing for the limited grass available in that area.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>23", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Which of the following agents is responsible for the dispersal of the seed shown above?", "images": ["Biology/imgs/1994/YYY8CF.png"], "options": {"A": "man", "B": "Water", "C": "Wind", "D": "Explosive mechanism"}, "answer": "C", "explanation": "Tridax seeds have tufts of fine hairs (pappus) attached to them.    These hairs act like parachutes, allowing the seeds to be carried away by the wind.    This type of dispersal is called anemochory (wind dispersal).", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>24", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The structure used by fishes to detect the presence and movement of other animals by the vibration they produce is the", "images": [], "options": {"A": "eye", "B": "nostril", "C": "lateral line", "D": "scales"}, "answer": "C", "explanation": "The lateral line is a sensory organ found in fish that detects vibrations and movement in the water. It allows fish to sense their environment and detect the presence of other animals, making it the correct answer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>25", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "CONCEPT OF LIVING : MUSCULAR SYSTEM", "question": "Muscles are attached to bones by means of", "images": [], "options": {"A": "ligament", "B": "cartilage", "C": "capillaries", "D": "tendons"}, "answer": "D", "explanation": "Muscles are attached to bones by tendons. Tendons are strong connective tissues that connect muscles to bones, allowing for movement when muscles contract.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>26", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The ability of the eye to alter the focal length of the lens, with regard to the distance of the object from the eye is known as", "images": [], "options": {"A": "binocular vision", "B": "nocturnal vision", "C": "distortion", "D": "accommodation"}, "answer": "D", "explanation": "The ability of the eye to alter the focal length of the lens to focus on objects at different distances is known as accommodation. This process involves the ciliary muscles adjusting the shape of the lens to ensure that light rays converge correctly on the retina, allowing for clear vision at varying distances.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>27", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "What is the fate of the ovary of a flower after fertilization?", "images": [], "options": {"A": "becomes the seed", "B": "withers away", "C": "becomes the fruit", "D": "develops more nuclei"}, "answer": "C", "explanation": "After fertilization, the ovary of a flower develops into the fruit. This process is part of the reproductive cycle of flowering plants, where the ovary contains ovules that develop into seeds, and the surrounding ovary tissue matures into the fruit, which aids in seed dispersal.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>28", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The diagrams above represent a group of insects known to be", "images": ["Biology/imgs/1994/TCHHHG.png"], "options": {"A": "colonial", "B": "parasitic", "C": "soldier", "D": "carnivorous"}, "answer": "C", "explanation": "Termites live in colonies with a caste system: king, queen, workers, and soldiers.    Soldier termites have:    Large heads    Strong mandibles (jaws) or sometimes a long snout for defense    Their main role is to protect the colony from enemies (like ants).", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>29", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "In their system of organisation, the diagram labelled II plays the role of a", "images": ["Biology/imgs/1994/TCHHHG.png"], "options": {"A": "worker", "B": "soldier", "C": "queen", "D": "drone"}, "answer": "B", "explanation": "Soldier termites are specialized for defending the colony, not for feeding or reproduction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>30", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : SEX DETERMINATION AND SEX LINKED CHARACTERS", "question": "Which of the following determines a normal male offspring?", "images": [], "options": {"A": "X", "B": "Y", "C": "XX", "D": "XY"}, "answer": "D", "explanation": "A normal male offspring is determined by the presence of one X chromosome and one Y chromosome, which is represented as XY. The Y chromosome carries genes that are responsible for male sex determination, while the X chromosome carries genes that are essential for both sexes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>31", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "What is the theoretical probability that a normal male child will be born?", "images": [], "options": {"A": "1\\2", "B": "1\\4", "C": "1\\3", "D": "1"}, "answer": "B", "explanation": "The theoretical probability of a normal male child being born is 1/2, as there are two possible outcomes for the sex of a child (male or female), assuming equal likelihood. Therefore, the correct option is (1/2).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>32", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "Which of these is not part of the appendicular skeleton?", "images": [], "options": {"A": "Clavicle", "B": "Vertebral column", "C": "Scapula", "D": "Femur"}, "answer": "B", "explanation": "The vertebral column is part of the axial skeleton, not the appendicular skeleton. The appendicular skeleton includes the limbs and the girdles that attach them to the axial skeleton. Therefore, the correct option is B (Vertebral column).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>33", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION", "question": "Which of the following factors does not control population growth?", "images": [], "options": {"A": "Food shortage", "B": "Emigration", "C": "Abundance of food", "D": "Predation"}, "answer": "C", "explanation": "Abundance of food does not control population growth; rather, it supports it. The other factors listed (food shortage, emigration, predation, and natural disaster) can limit or reduce population growth. Therefore, the correct option is C (Abundance of food).", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>34", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "The following conditions form the basis of competition in a habitat except", "images": [], "options": {"A": "food", "B": "space", "C": "reproductive mate", "D": "body structure"}, "answer": "D", "explanation": "Body structure is not a condition that forms the basis of competition in a habitat. The other options (food, space, reproductive mate, light) are direct resources or conditions that organisms compete for. Therefore, the correct option is E (body structure).", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>35", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The part of the ear which equalizes air pressure on either side of the eardrum is the", "images": [], "options": {"A": "auditory meatus", "B": "malleus", "C": "Eustachian tube", "D": "oval window"}, "answer": "C", "explanation": "The Eustachian tube is the part of the ear that equalizes air pressure on either side of the eardrum. It connects the middle ear to the nasopharynx and helps maintain equal pressure, which is essential for proper hearing. Therefore, the correct option is C (Eustachian tube).", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>36", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "EVOLUTION : ADAPTATION FOR SURVIVAL", "question": "Mutation leads to evolution in that it", "images": [], "options": {"A": "gives rise to offspring which have the same characteristics as the parents", "B": "kill all organism where it has occurred", "C": "gives rise to new individuals which differs considerably from their parents", "D": "always confers adaptability of the offspring"}, "answer": "C", "explanation": "Mutation introduces genetic variation in a population, which can lead to new traits that differ from those of the parents. This variation is essential for evolution, as it provides the raw material for natural selection to act upon. The correct option states that mutation gives rise to new individuals that differ considerably from their parents, which aligns with the concept of genetic diversity and evolution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>37", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "The process whereby poisonous compounds are made harmless in the liver is called", "images": [], "options": {"A": "deamination", "B": "glycolysis", "C": "dehydration", "D": "detoxification"}, "answer": "D", "explanation": "The process of detoxification in the liver involves the conversion of harmful substances into less toxic forms, allowing for their safe excretion from the body. This is a crucial function of the liver, as it helps to protect the body from the effects of toxins and drugs. The correct option, detoxification, accurately describes this process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>38", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The deficiency of calcium in a plant may result in", "images": [], "options": {"A": "stunted growth and poor root development", "B": "poor growth, leaves become orange or brown", "C": "stunted growth, slender stem and yellowing of leaves", "D": "very small leaves and yellowing of leaves"}, "answer": "C", "explanation": "Calcium is essential for various physiological functions in plants, including cell wall structure and growth. A deficiency in calcium can lead to stunted growth, slender stems, and yellowing of leaves, a condition known as blossom end rot in some plants. The correct option reflects these symptoms associated with calcium deficiency.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>39", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "Which of the following is the least safe method of birth control? Using", "images": [], "options": {"A": "spermicide creams", "B": "contraceptive pills", "C": "barriers such as condoms", "D": "the withdrawal method"}, "answer": "D", "explanation": "The withdrawal method, also known as coitus interruptus, is considered the least safe method of birth control because it relies heavily on self-control and timing, which can lead to a higher failure rate compared to other methods. The correct option identifies this method as the least reliable for preventing pregnancy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>40", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Which of the following does not imply attempt at conservation?", "images": [], "options": {"A": "Limit on the size of nets used in fishing", "B": "Limit on the size of vessels to be used in fishing", "C": "Prohibition of hunting or fishing at a certain season", "D": "Retraining from the use of the natural resource"}, "answer": "D", "explanation": "Retraining from the use of a natural resource does not imply an attempt at conservation; rather, it suggests a complete cessation of use. Conservation typically involves sustainable management and use of resources, rather than complete withdrawal. Therefore, the correct option indicates that this action does not align with conservation efforts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>41", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "EVOLUTION : ADAPTATION FOR SURVIVAL", "question": "The gradual, cumulative, adaptive and heritable changes in an organism over a long period of time resulting in emergence of new species is known as", "images": [], "options": {"A": "adaption", "B": "survival", "C": "regeneration", "D": "organic evolution"}, "answer": "D", "explanation": "The gradual, cumulative, adaptive and heritable changes in an organism over a long period of time resulting in the emergence of new species is known as organic evolution. This concept refers to the process by which species change over time through mechanisms such as natural selection, genetic drift, and mutation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>42", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The structure that produces the energy required by the cell is labelled", "images": ["Biology/imgs/1994/E6RJBT.png"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "B", "explanation": "The structure that produces the energy required by the cell is the mitochondrion.   Mitochondria are called the \"powerhouse of the cell.\"    They carry out cellular respiration, a process that breaks down glucose in the presence of oxygen to release ATP (adenosine triphosphate).", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>43", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The structure labelled V is the", "images": ["Biology/imgs/1994/E6RJBT.png"], "options": {"A": "mitochondrion", "B": "ribosome", "C": "nucleus", "D": "centriole"}, "answer": "B", "explanation": "Ribosomes are the site of protein synthesis.  They read the genetic code (mRNA) and join amino acids together to form proteins.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>44", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "In which of the following organisms is the siphon found?", "images": [], "options": {"A": "Tadpole", "B": "Pupa of mosquito", "C": "Tilapia", "D": "Crayfish"}, "answer": "D", "explanation": "The siphon is found in organisms like crayfish. A siphon is a tube-like structure that allows for the movement of water and is commonly associated with aquatic organisms, particularly in the context of respiration and locomotion.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>45", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE", "question": "Which of the following is not a pollution control measure?", "images": [], "options": {"A": "Penalising those who dump refuse on water or land", "B": "Controlling the emission of smoke from automobiles and industries", "C": "Ensuring that there is no spillage of oil.", "D": "Channelling sewage into streams"}, "answer": "D", "explanation": "Channelling sewage into streams is not a pollution control measure; rather, it is a source of pollution. Effective pollution control measures aim to prevent or reduce pollution, while this option describes an action that would exacerbate environmental contamination.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>46", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "Which pair of structures contributes to balance in mammals?", "images": [], "options": {"A": "Utriculus and Sacculus", "B": "Malleus and Stapes", "C": "Sacculus and cochlea", "D": "Utriculus and pinna"}, "answer": "A", "explanation": "The utriculus and sacculus are parts of the inner ear that play a crucial role in maintaining balance in mammals. They are responsible for detecting linear accelerations and the position of the head relative to gravity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>47", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "Spermatogenesis and Oogenesis are both terms used to describe", "images": [], "options": {"A": "mitosis", "B": "meiosis", "C": "mating", "D": "gametogenesis"}, "answer": "D", "explanation": "Spermatogenesis and oogenesis are both processes involved in gametogenesis, which is the formation of gametes (sperm and eggs) through meiosis. This process is essential for sexual reproduction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>48", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Which of the following is not a continuous variation?", "images": [], "options": {"A": "Height of plants", "B": "Skin colour", "C": "Ability to roll tongue", "D": "Length of fingers"}, "answer": "C", "explanation": "The ability to roll the tongue is a trait that exhibits discrete variation, as it is typically classified as either present or absent. In contrast, height, skin color, length of fingers, and leaf size are examples of continuous variation, where traits can exist on a spectrum.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>49", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Which of the following is not a conservable natural resource?", "images": [], "options": {"A": "Water", "B": "Sunlight", "C": "Forest", "D": "Soil"}, "answer": "B", "explanation": "Sunlight is not a conservable natural resource because it is an abundant and renewable source of energy that cannot be depleted. In contrast, water, forests, soil, and minerals can be depleted or degraded through overuse and mismanagement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>50", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION", "question": "Which of the following plant diseases is indicated when grains of cereals are covered with a mass of spores?", "images": [], "options": {"A": "Smut", "B": "Mosaic", "C": "Maize streak", "D": "Fungal blast"}, "answer": "A", "explanation": "Smut is a plant disease caused by certain fungi that produce dark, powdery spores, often covering the grains of cereals. This is a characteristic symptom of smut infections in crops.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>51", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "Which of the following structural features in animals does not affect control of body temperature?", "images": [], "options": {"A": "Scales", "B": "Skin", "C": "fur", "D": "Feathers"}, "answer": "A", "explanation": "Scales are a structural feature found in reptiles and some fish that primarily serve to protect the body and reduce water loss. Unlike skin, fur, capillaries, and feathers, which play significant roles in thermoregulation (the process of maintaining body temperature), scales do not directly contribute to the control of body temperature. Skin can regulate temperature through sweat glands, fur provides insulation, capillaries can dilate or constrict to control heat loss, and feathers trap air for insulation in birds. Therefore, the correct answer is 'Scales'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>52", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "The control of water and salt requirements of the body in order to maintain a stable internal environment is known as", "images": [], "options": {"A": "osmosis", "B": "excretion", "C": "plasmolysis", "D": "homeostasis"}, "answer": "D", "explanation": "The control of water and salt requirements of the body in order to maintain a stable internal environment is known as homeostasis. Homeostasis is the process by which biological systems maintain stability while adjusting to conditions that are optimal for survival. This includes regulating internal conditions such as temperature, pH, and the concentration of ions and water. The other options do not accurately describe this process: osmosis refers to the movement of water across a semipermeable membrane, excretion is the removal of waste products, plasmolysis is the process in which cells lose water in a hypertonic solution, and ultrafiltration is a process used in kidney function to filter blood.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>53", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : LIFE CYCLES", "question": "Which of the following is not a condition necessary for germination to occur in most seeds?", "images": [], "options": {"A": "Water", "B": "Air", "C": "Activation of enzymes", "D": "Soil fertility"}, "answer": "D", "explanation": "Soil fertility is not a necessary condition for germination. The primary conditions required for seed germination are water, air, activation of enzymes, and temperature. While soil fertility can influence the growth of the plant after germination, it is not essential for the germination process itself.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>54", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION", "question": "Which of the following structural features adapts Drosera (Sundew) to its carnivorous mode of nutrition?", "images": [], "options": {"A": "Long root with glandular hairs", "B": "Club-shaped glandular hairs on leaves", "C": "Prominent lenticel on the stem", "D": "Broad leaves with long spines"}, "answer": "B", "explanation": "Drosera, commonly known as Sundew, has club-shaped glandular hairs on its leaves that secrete a sticky substance to trap insects. This adaptation is crucial for its carnivorous mode of nutrition, allowing it to obtain nutrients from the prey it captures.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>55", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "APPLICATION OF VARIATIONS :", "question": "Which of the following terms is not associated with finger prints?", "images": [], "options": {"A": "Arch", "B": "Loop", "C": "Suture", "D": "Whorl"}, "answer": "C", "explanation": "The term 'Suture' is not associated with fingerprints. Fingerprints are classified into three main patterns: Arch, Loop, and Whorl. 'Compound' is not a standard classification for fingerprints either, but 'Suture' refers to a type of joint in the skull, making it unrelated to fingerprint classification.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>56", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "In human beings the albino trait it recessive and the normal skin colour is dominant. Therefore the probability of parent's that are heterozygous for albinism, having an albino child", "images": [], "options": {"A": "1\\4", "B": "1\\2", "C": "1\\3", "D": "2\\3"}, "answer": "A", "explanation": "In genetics, when both parents are heterozygous for a trait, the probability of having an offspring with a recessive trait can be calculated using a Punnett square. For albinism, which is recessive (aa), if both parents are heterozygous (Aa), the possible combinations are: AA, Aa, Aa, aa. Thus, the probability of having an albino child (aa) is 1 out of 4, or 1/4.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>57", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "Which of the following is the carrier of hereditary materials?", "images": [], "options": {"A": "Centriole", "B": "Cytoplasm", "C": "Nucleolus", "D": "Chromosome"}, "answer": "D", "explanation": "The carrier of hereditary materials in living organisms is the chromosome. Chromosomes are structures within cells that contain DNA, which carries genetic information. Other options like centriole, cytoplasm, nucleolus, and lysosome do not carry hereditary materials.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>58", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of these statements is correct in the human ABO blood grouping system?", "images": [], "options": {"A": "B is recessive", "B": "A is dominant over B", "C": "O is recessive", "D": "O has antigene A and B"}, "answer": "C", "explanation": "In the ABO blood grouping system, type O blood is considered recessive because it does not produce A or B antigens. Therefore, individuals with type O blood have no antigens on their red blood cells, making the statement 'O is recessive' correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1994>59", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : CARRIERS OF MICROORGANISMS", "question": "In man, adult schistosoma is found in the", "images": [], "options": {"A": "blood vessels of the bladder", "B": "red blood corpuscles", "C": "lymphatic vessel", "D": "blood vessels of the lung"}, "answer": "A", "explanation": "Adult schistosoma, a type of parasitic worm, is typically found in the blood vessels of the bladder in humans. This is where they reside and reproduce, making option 'blood vessels of the bladder' the correct answer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1994>60", "subject": "Biology", "year": "1994", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following structures does not function as support in animals?", "images": [], "options": {"A": "Cuticle in arthropods", "B": "Scales in birds", "C": "Cartilage in mammals", "D": "Body fluid in earthworms"}, "answer": "D", "explanation": "Body fluid in earthworms does not function as a structural support in the same way that bones, cartilage, cuticles, and scales do. Instead, body fluid provides turgor pressure, which helps maintain the shape of the earthworm but does not provide rigid support.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1995>1", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "At what level of organisation is Amoeba?", "images": [], "options": {"A": "Tissue", "B": "Organ", "C": "Cellular", "D": "System"}, "answer": "C", "explanation": "Amoeba is a single-celled organism. It is not a tissue, organ, or system, which are all composed of multiple cells. Therefore, the level of organization of Amoeba is cellular.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1995>2", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "Which of these could be regarded as an advantage of complexity in higher organisms?", "images": [], "options": {"A": "there is no cellular differentiation", "B": "Cellular differentiation leads to loss of independence of the cells", "C": "Cellular differentiation occurs in few cells only", "D": "Cellular differentiation leads to internal structural specialization"}, "answer": "D", "explanation": "Complexity in higher organisms is often associated with cellular differentiation, which leads to internal structural specialization. This means that different cells have different roles, allowing the organism to perform a variety of functions efficiently. For example, in humans, we have nerve cells for transmitting signals, red blood cells for carrying oxygen, and so on. This specialization is an advantage of complexity in higher organisms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>3", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "Which of the following organisms is one-celled and free-living?", "images": [], "options": {"A": "Volvox", "B": "Spirogyra", "C": "Rhizopus", "D": "Chlamydomonas"}, "answer": "D", "explanation": "Chlamydomonas is a one-celled and free-living organism. It is a type of green algae that is found in stagnant water and on damp soil. Unlike Volvox, Spirogyra, and Rhizopus, which are multicellular, Chlamydomonas is unicellular. It is capable of photosynthesis, and it can move using its two flagella. It is considered free-living because it does not rely on a host or other organism for survival.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1995>4", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "One of the differences between plant and animal cells is that in plants", "images": [], "options": {"A": "cells have less distinct outline, but animal cells have distinct outline", "B": "cell wall is made of cellulose, but animal cell wall is made of chitin", "C": "large vacuoles are absent, but present in animals", "D": "carbohydrates are stored as starch, but as glycogen in animals."}, "answer": "D", "explanation": "One of the differences between plant and animal cells is that plant cells store carbohydrates as starch, while animal cells store them as glycogen. This is because starch is the primary form of carbohydrate storage in plants, while glycogen serves the same purpose in animals. The other options are incorrect because plant cells have a distinct outline due to the presence of a cell wall, the cell wall in plants is made of cellulose while animal cells do not have a cell wall, and large vacuoles are present in plant cells but are smaller or absent in animal cells.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>5", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Carbondioxide enters the stomata during photosynthesis through the process known as", "images": [], "options": {"A": "osmosis", "B": "active transport", "C": "diffusion", "D": "inhalation"}, "answer": "C", "explanation": "During photosynthesis, carbon dioxide enters the stomata through the process known as diffusion. Diffusion is the movement of molecules from an area of higher concentration to an area of lower concentration. In this case, the concentration of carbon dioxide is usually higher in the atmosphere than inside the leaf, so it diffuses into the stomata.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>6", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following groups carry out similar functions in living things?", "images": [], "options": {"A": "Vertebral column, chitin, and guard cells", "B": "Sclerenchyma, cartilage and chitin", "C": "Tendon, chitin and neurone", "D": "Collenchyma, Intercellular spaces and blood vessels"}, "answer": "B", "explanation": "Sclerenchyma is a type of plant tissue that provides support and protection, while cartilage is a type of connective tissue in animals that provides cushioning and support. Chitin,  provides support and protection to arthropods and some fungi. Sclerenchyma, cartilage, and chitin all carry out similar functions of providing support and protection.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>7", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following statements is correct?", "images": [], "options": {"A": "biceps muscles has its origin on the head of the humerus", "B": "biceps muscle is inserted at the ulna", "C": "triceps muscle originated at the scapula and head of the humerus", "D": "ulna is pulled up when the biceps is relaxed"}, "answer": "C", "explanation": "The triceps brachii muscle has three heads: the long head originating from the scapula and the lateral and medial heads originating from the posterior surface of the humerus. The biceps brachii does not insert into the ulna; it inserts into the radial tuberosity of the radius. The triceps brachii originates from the scapula and the humerus.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1995>8", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following pairs of tissues is responsible for strengthening the plant?", "images": [], "options": {"A": "Phloem and Epidermis", "B": "Parenchyma and Cambium", "C": "Collenchyma and Sclerenchyma", "D": "Collenchyma and Cambium"}, "answer": "C", "explanation": "Collenchyma provides extra mechanical and structural support, particularly in regions of new growth. Sclerenchyma provides the main structural support to a plant.  Collenchyma: Provides flexible support to growing regions of the plant, such as stems and leaves.  Sclerenchyma: Provides rigid support to mature parts of the plant, with thick, lignified cell walls that contribute significantly to the plant's structural integrity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>9", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following is not a tissue found in plants?", "images": [], "options": {"A": "Epidermis", "B": "Phloem", "C": "Xylem", "D": "Dermis"}, "answer": "D", "explanation": "In the context of plant biology, the dermis is not a tissue found in plants. The dermis is a layer of skin found in animals, not plants. On the other hand, Epidermis, Phloem, and Xylem are all types of tissues found in plants. The Epidermis is the outermost layer of cells covering the plant, Phloem is the vascular tissue in plants which conducts sugars and other metabolic products downwards from the leaves, and Xylem is the vascular tissue in plants that conducts water and dissolved nutrients upwards from the root and also helps to form the woody element in the stem.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>10", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "Higher organisms use a transport system and not diffusion only to distribute nutrients because", "images": [], "options": {"A": "the ratio of their surface area to volume is small", "B": "metabolic waste products diffuse to the surface of the organisms", "C": "the rate at which nutrients and other substances diffuse increases", "D": "substances to be transported move shorter distances to reach the numerous cells"}, "answer": "A", "explanation": "Higher organisms use a transport system and not diffusion only to distribute nutrients because the ratio of their surface area to volume is small. This means that the surface area is not large enough to allow sufficient nutrients to diffuse into the organism to meet its needs. Therefore, a transport system is needed to distribute nutrients effectively. Diffusion is a process where molecules move from an area of high concentration to an area of low concentration. In larger organisms, this process alone is not efficient enough to distribute nutrients to all cells, hence the need for a transport system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>11", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "In complex food relationships in a community, the primary, secondary and tertiary consumers are referred to as", "images": [], "options": {"A": "symbionts", "B": "omnivores", "C": "heterotrophs", "D": "autotrophs"}, "answer": "C", "explanation": "In a food chain, the primary, secondary, and tertiary consumers are referred to as heterotrophs. Heterotrophs are organisms that cannot produce their own food and rely on other organisms for their nutrition. They consume other organisms to get the energy and nutrients they need to live. This includes all animals, some types of fungi, and some bacteria. The options 'symbionts', 'omnivores', and 'autotrophs' are incorrect because symbionts are organisms that live in close association with another organism, omnivores are animals that eat both plants and animals, and autotrophs are organisms that can produce their own food from inorganic substances.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>12", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "The cell membrane of a cell is said to be semi-permeable because", "images": [], "options": {"A": "it allows only large molecular substances to pass through it into the cell", "B": "it is actively involved in energy production in the cell", "C": "it actively allows all substances to pass through it by diffusion", "D": "it is actively selective in allowing substances pass through it"}, "answer": "D", "explanation": "The cell membrane is semi-permeable because it is selectively permeable, meaning it allows certain substances to pass through it while blocking others. This is achieved through various mechanisms such as passive transport (diffusion and osmosis), active transport, and vesicular transport. The cell membrane controls the movement of substances in and out of the cell, maintaining the cell's internal balance. Therefore, option 4 is correct as it states that the cell membrane is actively selective in allowing substances to pass through it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>13", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Use the diagram below to answer the question       The function of the part labelled I is", "images": ["Biology/imgs/1995/part.png"], "options": {"A": "controlling water loss", "B": "trapping solar energy", "C": "absorbing water", "D": "storing sugar"}, "answer": "B", "explanation": "The part labeled \"I\" is identified as a chloroplast based on its shape and location within the plant cell. Chloroplasts are organelles responsible for photosynthesis, capturing solar energy and converting it into chemical energy. This accurately fits the description of trapping solar energy", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>14", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Use the diagram below to answer the question     The part labelled ll is the", "images": ["Biology/imgs/1995/part.png"], "options": {"A": "stoma", "B": "palisade cell", "C": "spongy cell", "D": "guard cell"}, "answer": "A", "explanation": "Guard cells surround an opening called the stoma. The stoma is the actual pore that allows for gas exchange. Therefore, the part labeled \"II,\" which appears to be an opening flanked by two specialized cells, is the stoma.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>15", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Use the diagram below to answer the question     The structure that will be stained blue-black by iodine is labelled", "images": ["Biology/imgs/1995/part.png"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "A", "explanation": "Iodine stains starch blue-black. The part labeled \"I\" appears to be chloroplasts, which are sites of starch storage in leaf cells. Therefore, the structure labeled \"I\" will be stained blue-black by iodine due to the presence of starch.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>16", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "In the anaerobic stage of respiration, the net ATP molecules produced per glucose molecule", "images": [], "options": {"A": "one", "B": "two", "C": "three", "D": "four"}, "answer": "B", "explanation": "In the anaerobic stage of respiration, also known as glycolysis, one glucose molecule is broken down into two molecules of pyruvate. This process results in the net production of two ATP molecules. Therefore, the correct answer is 'two'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>17", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Reabsorption of the metabolic products along the kidney tubules is made possible by the", "images": [], "options": {"A": "closeness of the intestine to the kidney", "B": "convoluted nature of the tubules", "C": "presence of convoluted tubules in the medulla", "D": "presence of network of capillaries around the convoluted tubules"}, "answer": "D", "explanation": "Presence of network of capillaries around the convoluted tubules: The peritubular capillaries wrap around the proximal and distal convoluted tubules, providing a large surface area for the exchange of substances. This network is essential for reabsorbing water, glucose, amino acids, and ions from the filtrate back into the blood, ensuring that valuable substances are not lost in urine. The close proximity of these capillaries to the tubules facilitates efficient transfer of metabolic products, making reabsorption possible.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>18", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "Hormones are transported around the mammalian body by", "images": [], "options": {"A": "water", "B": "nerves", "C": "blood", "D": "osmosis"}, "answer": "C", "explanation": "Hormones are transported around the mammalian body by the circulatory system, specifically through the blood. Hormones are chemical messengers that are secreted directly into the blood, which carries them to organs and tissues of the body to exert their functions. They are not transported by water, nerves or osmosis. Therefore, the correct answer is 'blood'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>19", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "Which of the following is not a function of insulin?", "images": [], "options": {"A": "Accelerates the rate at which glucose is converted to glycogen", "B": "Promotes the uptake of glucose by tissues", "C": "Regulates the amount of glucose in the blood", "D": "Stimulates muscles to oxidize glucose."}, "answer": "D", "explanation": "Insulin is a hormone produced by the pancreas that regulates the amount of glucose in the blood. It promotes the uptake of glucose by tissues and accelerates the rate at which glucose is converted to glycogen for storage. However, insulin does not directly stimulate muscles to oxidize glucose. The oxidation of glucose in muscles is a process that occurs during cellular respiration to produce energy, and while insulin can influence this process indirectly by controlling the amount of glucose available, it does not directly stimulate it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>20", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "Which of the following is the correct route of transmission of impulses along a reflex arc?", "images": [], "options": {"A": "Receptor → sensory neurone → synapse → intermediate neurone → synapse → motor neurone → effector", "B": "Receptor → motor neutron e synapse → intermediate neurone → synapse → sensory neurone effector", "C": "Receptor → synapse → sensory neurone → intermediate neurone → synapse → effector → motor neurone", "D": "Effector → motor neurone → synapse → sensory neurone → synapse → intermediate neurone → receptor"}, "answer": "A", "explanation": "A reflex arc is a neural pathway that controls a reflex action. In a reflex arc, the stimulus (received by the receptor) is directly relayed into the sensory neuron, which then sends the information to the intermediate neuron in the spinal cord. This intermediate neuron then sends the signal through a synapse to the motor neuron, which finally carries the signal to the effector (muscle or gland) to respond to the stimulus.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>21", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "Which of the following statements is false?", "images": [], "options": {"A": "Human sense of smell is easily fatigued", "B": "The skin can perceive the sensations of touch, pain, pressure and temperature", "C": "Taste buds and olfactory cells are active when wet as well as when dry", "D": "Sensory nerve endings receive stimuli and send to the central nervous system"}, "answer": "C", "explanation": "Taste buds and olfactory cells are only active when wet. They require a moist environment to function properly. Taste buds are specialized sensory cells located on the tongue that allow us to perceive different tastes (sweet, sour, bitter, salty, and umami). Olfactory cells, located in the nasal cavity, allow us to perceive smells. Both of these types of cells require a moist environment to dissolve the chemicals they detect, which is why our sense of taste and smell can be impaired when our mouth or nose is dry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>22", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The following are directly involved in transmission of sound waves to the brain except", "images": [], "options": {"A": "eardrum", "B": "auditory meatus", "C": "auditory ossicles", "D": "eustachian tube"}, "answer": "D", "explanation": "Sound waves are transmitted to the brain through a series of structures in the ear. The process begins when sound waves enter the ear through the auditory meatus (ear canal) and cause the eardrum to vibrate. These vibrations are then transferred to the auditory ossicles (tiny bones in the middle ear), which amplify the sound and send it to the inner ear. From there, the sound is converted into electrical signals that are transmitted to the brain. The eustachian tube, however, is not directly involved in the transmission of sound waves to the brain. Its primary function is to equalize pressure between the middle ear and the atmosphere, which is important for the proper functioning of the eardrum and ossicles, but it does not directly transmit sound.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>23", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The term syncarpous is used to describe a flower when the carpels are", "images": [], "options": {"A": "many and fused", "B": "two only", "C": "two and separate", "D": "many and free"}, "answer": "A", "explanation": "The term syncarpous is used to describe a flower when the carpels are many and fused. Syncarpous: Syncarpous is a condition in which the carpels of the gynoecium are united in a compound ovary. Blooms having syncarpous ovaries include tomato and mustard flowers. It can be either unilocular or multilocular in nature but only one ovary is present. It matures into one fruit with one or more seeds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>24", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following structures are characteristics of insect pollinated flowers?", "images": [], "options": {"A": "Dull coloured flowers with no nectar", "B": "Very light numerous and pendulous stamen", "C": "Brightly coloured petals, scent nectar", "D": "Flowers are usually small and inconspicuous"}, "answer": "C", "explanation": "Insect pollinated flowers, also known as entomophilous flowers, are usually brightly colored and have a strong scent to attract insects. They also produce nectar which serves as a food source for the insects. The insects, while feeding on the nectar, pick up pollen from the flower and transfer it to other flowers, thereby aiding in pollination. Therefore, the option 'Brightly coloured petals, scent nectar' is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>25", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION", "question": "Which of the following statements is not correct?", "images": [], "options": {"A": "Shortage of food may be caused by pestilence, rinderpest and neglect of farming", "B": "Shortage of food may lead to competition, emigration, death and decline in the rate of reproduction", "C": "Over-crowding may lead to scarcity of food", "D": "Territorial defence encourages food scarcity in a habitat"}, "answer": "D", "explanation": "Territorial defense does not encourage food scarcity in a habitat. Instead, it is a behavior exhibited by animals to protect their territory, or the area which they inhabit and where they find their food, from intruders. This behavior ensures that the resources within their territory, including food, are not depleted by others. Therefore, territorial defense is a strategy to prevent food scarcity, not to encourage it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>26", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING", "question": "Which of the following is an advantage of dispersal of fruits and seeds? It allows", "images": [], "options": {"A": "fair distribution of source of food for animals", "B": "growth in close association with parent plant", "C": "even distribution of plants and reduction of intraspecific competition", "D": "keen competition for food"}, "answer": "C", "explanation": "The dispersal of fruits and seeds allows for the even distribution of plants and reduction of intraspecific competition. Dispersal is a mechanism that plants use to colonize new areas, which can be far from the parent plant. This reduces intraspecific competition, which is competition among members of the same species for the same resources. By spreading out, plants can access resources without having to compete with their siblings. Dispersal does not necessarily ensure a fair distribution of food for animals, it does not promote growth in close association with the parent plant, and it does not lead to keen competition for food.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1995>27", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The series of changes that occur in a seed by which the embryo develops into a seedling is known as", "images": [], "options": {"A": "fertilization", "B": "gametogenesis", "C": "pollination", "D": "germination"}, "answer": "D", "explanation": "The series of changes that occur in a seed by which the embryo develops into a seedling is known as germination. Germination is the process by which an organism grows from a seed or similar structure. The most common example of germination is the sprouting of a seedling from a seed of an angiosperm or gymnosperm. In contrast, fertilization is the fusion of gametes to initiate the development of a new individual organism. Gametogenesis is a biological process by which diploid or haploid precursor cells undergo cell division and differentiation to form mature haploid gametes. Pollination is the transfer of pollen from a male part of a plant to a female part of a plant, later enabling fertilisation and the production of seeds, most often by an animal or by wind.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>28", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS", "question": "Which of the following organisms has a symbiotic relationship with green algae?", "images": [], "options": {"A": "Amoeba", "B": "Paramecium", "C": "Hydra", "D": "Euglena"}, "answer": "C", "explanation": "Hydra has a symbiotic relationship with green algae. In this relationship, the green algae live in the cells of the hydra and perform photosynthesis, providing the hydra with nutrients. In return, the hydra provides the algae with protection and access to light. This is a type of mutualistic symbiosis, where both organisms benefit from the relationship.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>29", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "At the end of photosynthesis, the green leaf is tested for starch and not glucose, because", "images": [], "options": {"A": "the glucose is used up immediately to provide energy for the needs of the leaf", "B": "the glucose formed is immediately converted to starch", "C": "starch is stored only in leaves", "D": "there are no chemicals for glucose test in leaves"}, "answer": "B", "explanation": "During photosynthesis, plants convert carbon dioxide and water into glucose. This glucose is then immediately converted into starch for storage. Starch is a polysaccharide, a large molecule made up of many glucose units. It is more efficient for plants to store glucose in the form of starch because it is less reactive and takes up less space due to its structure. Therefore, at the end of photosynthesis, the leaf is tested for starch and not glucose because the glucose formed is immediately converted to starch.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>30", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following equations is not associated with photosynthesis?", "images": [], "options": {"A": "H2O → H + OH", "B": "C6H12O6 → 2C2H5OH + 2CO2", "C": "CO2 + [4H] → CH2O + H2O", "D": "4[OH] → 2H2O + O2"}, "answer": "B", "explanation": "Photosynthesis is the process by which green plants and some other organisms use sunlight to synthesize foods with the aid of chlorophyll pigments. The general equation for photosynthesis is 6CO2 + 6H2O → C6H12O6 + 6O2. This means that carbon dioxide and water, in the presence of light energy, are converted to glucose and oxygen. The second option, C6H12O6 → 2C2H5OH + 2CO2, is the equation for the fermentation of glucose into ethanol and carbon dioxide, not photosynthesis.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>1995>31", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "Which of these processes removes carbon from the atmosphere?", "images": [], "options": {"A": "Putrefaction of animals", "B": "Burning of fuels", "C": "Photosynthesis", "D": "Volcanic eruption"}, "answer": "C", "explanation": "Photosynthesis is the process by which green plants and some other organisms use sunlight to synthesize foods with the help of chlorophyll pigments. During photosynthesis, plants absorb carbon dioxide (CO2) from the atmosphere and use it to produce glucose (C6H12O6), which is a type of sugar. This process effectively removes carbon from the atmosphere, thus helping to reduce the overall concentration of atmospheric CO2. The other options such as putrefaction of animals, burning of fuels, and volcanic eruption all contribute to the release of carbon into the atmosphere, not its removal.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>32", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following conditions is not necessary for photosynthesis to occur in plants?", "images": [], "options": {"A": "There must be light", "B": "There must be xylem tissue used to conduct water", "C": "There must be chlorophyll to trap radiant energy", "D": "Carbondioxide must be present"}, "answer": "B", "explanation": "Photosynthesis is the process by which green plants and some other organisms use sunlight to synthesize foods with the aid of chlorophyll pigments. The necessary conditions for photosynthesis to occur include light, chlorophyll, and carbon dioxide. However, the presence of xylem tissue is not a direct requirement for photosynthesis. Xylem tissue is involved in the transport of water from the roots to other parts of the plant, but it is not a condition for photosynthesis to occur. Therefore, the statement 'There must be xylem tissue used to conduct water' is not a necessary condition for photosynthesis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>33", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "The distribution of organisms in a fresh - water habitat like a stream or pond is determined by the following except", "images": [], "options": {"A": "rainfall", "B": "temperature", "C": "pH of soil", "D": "light penetration"}, "answer": "C", "explanation": "The distribution of organisms in a fresh-water habitat like a stream or pond is determined by several factors such as temperature, light penetration, and rainfall. These factors directly affect the living conditions of the organisms. For instance, temperature affects the metabolic rates of organisms, light penetration affects photosynthetic organisms, and rainfall can affect the water level and flow rate. However, the pH of soil is not a direct factor in determining the distribution of organisms in a fresh-water habitat. The pH of the water itself could be a factor, but not the pH of the soil. Therefore, the correct answer is 'pH of soil'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>34", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "Which of the following is characteristics of a swamp?", "images": [], "options": {"A": "Vegetation with stratified arrangement", "B": "mesophytes with broad leaves", "C": "The ground is flooded most of the time", "D": "Predominance of climbing plants"}, "answer": "C", "explanation": "A swamp is a wetland that is forested, meaning it is covered with water for most of the time. Therefore, the characteristic of a swamp is that the ground is flooded most of the time. The other options do not accurately describe a swamp. Stratified arrangement of vegetation is more characteristic of a rainforest, mesophytes with broad leaves are plants that live in an environment with a moderate amount of water, and predominance of climbing plants is more characteristic of a tropical rainforest.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>35", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "Very low annual rainfall, sparse vegetation, high day temperatures and cold nights are the characteristic of the biome known as", "images": [], "options": {"A": "swamp", "B": "tropical forest", "C": "southern guinea savanna", "D": "desert"}, "answer": "D", "explanation": "The characteristics described in the question are typical of a desert biome. Deserts are known for their very low annual rainfall, sparse vegetation due to the lack of water, and extreme temperature fluctuations between day and night. During the day, the temperatures can be extremely high due to the direct exposure to the sun's rays, while at night, the temperatures can drop significantly due to the lack of humidity and cloud cover to trap the heat.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>36", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The graphs below show the results of experiments which investigated the effect of temperature and oxygen on the rate of uptake of certain ions labelled X and Y by a plant root. Use them to answer the question       Which of the following conclusions cannot be drawn from the graphs?", "images": ["Biology/imgs/1995/CT2WE4.png"], "options": {"A": "Ion is taken up more rapidly at suitable temperature", "B": "Suitable oxygen concentration increases ion uptake", "C": "Ion uptake requires energy from aerobic respiration of sugar", "D": "The quantity of ions absorbed is inversely proportional to the quantity of carbohydrate (sugar) synthesized."}, "answer": "D", "explanation": "While the right graph shows a decrease in sugar levels as ion uptake increases with oxygen concentration, it does not explicitly demonstrate a direct inverse proportionality between ion absorption and carbohydrate synthesis. The relationship might suggest a trend, but the graphs do not provide enough evidence to conclude an exact inverse proportional relationship.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>1995>37", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The graphs below show the results of experiments which investigated the effect of temperature and oxygen on the rate of uptake of certain ions labelled X and Y by a plant root. Use them to answer the question     Which of the temperature ranges will likely favour the plant best?", "images": ["Biology/imgs/1995/CT2WE4.png"], "options": {"A": "0 -10oC", "B": "15 -20oC", "C": "30 -40oC", "D": "45 -50oC"}, "answer": "C", "explanation": "30o -40oC. Both ions X and Y show their maximum uptake within the temperature range of 30o to 40oC  . This indicates that the plant's ion uptake mechanisms operate most efficiently within this range, making it the most favorable temperature range for the plant's ion absorption.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>38", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Which of the following is the correct chain for the organism found in an aquatic community?", "images": [], "options": {"A": "Paramecium, Phytoplankton, Prawn, Waterflea, Tilapia, Shark", "B": "Waterflea, Paramecium, Phytoplankton, Prawn, Tilapia, Shark", "C": "Phytoplankton, Waterflea, Paramecium, Prawn, Shark, `tilapia", "D": "Phytoplankton, Paramecium, Waterflea, Prawn, Tilapia, Shark"}, "answer": "D", "explanation": "In an aquatic community, the food chain typically starts with Phytoplankton, which are primary producers. They are eaten by Paramecium (a type of zooplankton), which in turn are eaten by Waterfleas. Waterfleas are then consumed by Prawns, which are eaten by Tilapia (a type of fish). Finally, Sharks, being apex predators, eat Tilapia. Therefore, the correct chain is Phytoplankton, Paramecium, Waterflea, Prawn, Tilapia, Shark.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>39", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "In a food chain the position occupied by an organism is called", "images": [], "options": {"A": "the trophic level", "B": "energy level", "C": "the feeding level", "D": "the habitat level"}, "answer": "A", "explanation": "In a food chain, the position occupied by an organism is called the trophic level. A trophic level of an organism is the position it occupies in a food chain. The primary producers (plants) occupy the first trophic level, primary consumers (herbivores) occupy the second trophic level, secondary consumers (carnivores) occupy the third trophic level, and so on. The other options do not accurately describe the position of an organism in a food chain.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>40", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Which of these statements about food chain is not correct?", "images": [], "options": {"A": "Animals in the chain are consumers", "B": "A food chain usually begins with a green plant", "C": "All organisms in a food chain are animals", "D": "Living things are dependent on one another"}, "answer": "C", "explanation": "A food chain represents the flow of energy and nutrients in an ecosystem, starting from producers (usually green plants) and moving up to different levels of consumers (animals). The statement 'All organisms in a food chain are animals' is incorrect because a food chain starts with plants (producers) which are not animals. They use sunlight to produce food through a process called photosynthesis. Herbivores (plant-eating animals) then eat these plants, and carnivores (meat-eating animals) eat the herbivores. Hence, a food chain includes both plants and animals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>41", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "Which of these is not applicable to the circulation of water in nature?", "images": [], "options": {"A": "Water removed from oceans are Permanently lost", "B": "Water constantly evaporates from the seas, rivers, lakes and soil", "C": "Water vapour rises, cools, condenses and precipitates as rain and dew", "D": "Water is absorbed by plants and animals from their external environment"}, "answer": "A", "explanation": "The statement 'Water removed from oceans are Permanently lost' is not applicable to the circulation of water in nature. This is because the water cycle, also known as the hydrologic cycle, is a continuous process where water evaporates, travels into the air and becomes part of a cloud, falls down to earth as precipitation, and then evaporates again. This cycle is a closed system, meaning no water is permanently lost from the oceans. The other options correctly describe processes involved in the water cycle.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>42", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS", "question": "An association between two organisms in which both benefit is called", "images": [], "options": {"A": "parasitism", "B": "commensalism", "C": "symbiosis", "D": "Predation"}, "answer": "C", "explanation": "The association between two organisms in which both benefit is called symbiosis. In biology, symbiosis refers to a close, long-term interaction between two different species. In a symbiotic relationship, both organisms benefit from the association. Parasitism is a non-mutual relationship between species, where one species, the parasite, benefits at the expense of the other, the host. Commensalism is a relationship between two organisms where one organism benefits without affecting the other. Predation is a biological interaction where a predator (an organism that is hunting) feeds on its prey (the organism that is attacked).", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1995>43", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "ECOLOGY OF POPULATION : ECOLOGICAL SUCCESSION", "question": "Which of the following is not an outcome of ecological succession?", "images": [], "options": {"A": "There is a progressive change in species structure, organic matter and energy flow", "B": "The climax stage consists of a comparatively long lasting species composition", "C": "There is no dynamic equilibrium between the community and habitat in the climax stage", "D": "Communities occurring later in the sequence of succession are more complex"}, "answer": "C", "explanation": "Ecological succession is the process of change in the species structure of an ecological community over time. The climax stage in ecological succession is characterized by a stable community which has reached a steady state, or dynamic equilibrium, with the environment. This means that there is indeed a dynamic equilibrium between the community and habitat in the climax stage", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>44", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION", "question": "Which of the following is not an effect of over-crowding on a population?", "images": [], "options": {"A": "Death", "B": "Competition", "C": "Commensalism", "D": "Aggression"}, "answer": "C", "explanation": "Overcrowding in a population often leads to increased death rates, competition for resources, and aggression among individuals. However, commensalism, which is a type of symbiotic relationship where one organism benefits while the other is neither harmed nor benefited, is not a direct effect of overcrowding. Overcrowding does not necessarily lead to commensalism as this relationship depends more on the specific interactions between different species rather than the density of a population.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1995>45", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION", "question": "The diagram above represent the shape of major group of bacteria  The groups staphylococci and streptobacilli are represented by", "images": ["Biology/imgs/1995/bacteria.png"], "options": {"A": "I and II", "B": "II and IV", "C": "III and VII", "D": "IV and VII"}, "answer": "D", "explanation": "IV (Staphylococci): This group is characterized by the grape-like clusters of spherical bacteria, typical of the staphylococci arrangement.  VII (Streptobacilli): This group is characterized by the chain-like arrangement of rod-shaped bacteria, typical of streptobacilli.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>46", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "Prevention of erosion could best be carried out by", "images": [], "options": {"A": "crop rotation and mulching", "B": "contouring of slopping ground and afforestation", "C": "grazing, terracing and shifting cultivation", "D": "strip cropping and poaching"}, "answer": "B", "explanation": "Erosion is the process of wearing away of the land surface by physical forces such as rainfall, flowing water, wind, ice, temperature change, gravity or other natural or anthropogenic agents. It can be prevented by various methods. Among the given options, contouring of sloping ground and afforestation is the best method to prevent erosion. Contouring of sloping ground involves plowing across a slope following its elevation contour lines. These contour lines create a water break which reduces the formation of rills and gullies during times of heavy water run-off; which is a major cause of top soil loss and soil erosion. Afforestation is the establishment of a forest, or stand of trees, in an area where there was no forest. This is often done to prevent erosion as trees prevent erosion by binding the soil with their roots. The other options like crop rotation and mulching, grazing terracing and shifting cultivation, strip cropping and poaching also help in preventing erosion but not as effectively as contouring and afforestation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>47", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "The following are useful measures for conserving forest except", "images": [], "options": {"A": "preventing and controlling accidental forest fire", "B": "encouraging the use of charcoal for industrial and domestic purposes", "C": "combating and preventing plant diseases", "D": "reafforestation of depleted forest"}, "answer": "B", "explanation": "The correct answer is 'encouraging the use of charcoal for industrial and domestic purposes'. This is because the production of charcoal involves cutting down trees and burning them, which contributes to deforestation. Deforestation is the opposite of forest conservation. The other options involve measures that help to protect and restore forests. Preventing and controlling accidental forest fires helps to prevent the destruction of forests. Combating and preventing plant diseases helps to keep the trees in the forest healthy. Reafforestation of depleted forest involves planting new trees in areas where the forest has been cut down, which helps to restore the forest.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>48", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "The following practices are aimed at soil conservation except", "images": [], "options": {"A": "contour ridging", "B": "application of manures", "C": "strip cropping", "D": "bush clearing"}, "answer": "D", "explanation": "Soil conservation involves practices that are aimed at preventing soil erosion or degradation. Contour ridging, application of manures, and strip cropping are all practices that help in soil conservation. Contour ridging helps in reducing the speed of water flow, thus reducing soil erosion. Application of manures improves the soil structure and its capacity to hold water, thus reducing soil erosion. Strip cropping involves growing crops in a systematic way in rows or strips which helps in reducing soil erosion. On the other hand, bush clearing, which involves removing vegetation cover, can lead to soil erosion as it exposes the soil to wind and water. Therefore, bush clearing is not aimed at soil conservation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1995>49", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS", "question": "Which of the following natural resources is most readily available to all organisms?", "images": [], "options": {"A": "Water", "B": "Oil", "C": "Food", "D": "Air"}, "answer": "D", "explanation": "The most readily available natural resource to all organisms is air. All organisms, regardless of their habitat, require air to survive. Air is composed of various gases such as oxygen, which is essential for respiration in animals, and carbon dioxide, which is necessary for photosynthesis in plants. Water, food, and oil are also natural resources, but their availability varies greatly depending on the organism and its habitat. For example, desert organisms have adapted to survive with very little water, and not all organisms require oil or the same type of food. Therefore, air is the most universally available resource to all organisms.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1995>50", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Which of the following is an example of discontinuous variation?", "images": [], "options": {"A": "Height", "B": "Size of head", "C": "Blood group", "D": "Skin colour"}, "answer": "C", "explanation": "Discontinuous variation refers to the variation in characteristics that have a definite form. These characteristics are controlled by a single pair of genes. Examples of discontinuous variation include blood group, ability to roll the tongue, etc. In this case, the blood group is an example of discontinuous variation because there are distinct categories (A, B, AB, O) and no intermediates.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>51", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Hereditary variation is best described as", "images": [], "options": {"A": "characters transmitted from generation to generation", "B": "traits acquired from diseases", "C": "characters that show up due to social conditions", "D": "traits acquired from habits and environmental conditions"}, "answer": "A", "explanation": "Hereditary variation refers to the differences that exist within species that are passed down through successive generations. These variations are caused by genetic differences, which are transmitted from parents to offspring. Therefore, the best description of hereditary variation is 'characters transmitted from generation to generation'. The other options refer to acquired traits, which are not hereditary in nature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>52", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "An individual with blood group AB can receive blood from those in blood group(s)", "images": [], "options": {"A": "AB only B", "B": "A and B only", "C": "B only", "D": "A, B, AB and O"}, "answer": "D", "explanation": "An individual with blood group AB is considered a universal recipient. This is because they have both A and B antigens on their red blood cells, and therefore, their immune system will not produce antibodies against either A or B blood types. As a result, they can receive blood from donors of any blood group: A, B, AB, or O.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>53", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "The statement that the environment determines which organisms survives to reproduce", "images": [], "options": {"A": "explains the theory of acquired characters", "B": "supports Jean Lamarck's theory of use and disuse", "C": "supports the idea of survival of the fittest", "D": "is refuted by fossil records"}, "answer": "C", "explanation": "The statement that the environment determines which organisms survive to reproduce supports the idea of survival of the fittest. This concept is a key component of the theory of natural selection, proposed by Charles Darwin. According to this theory, individuals that are better adapted to their environment are more likely to survive and reproduce, thereby passing on their advantageous traits to the next generation. This process leads to changes in the species over time, a process known as evolution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>54", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of the following is a definition of heredity? It is the", "images": [], "options": {"A": "non-resemblance of closely related organisms", "B": "total absence of parental traits in offspring", "C": "absence of variation in organisms", "D": "transfer of characteristics from parents to offspring"}, "answer": "D", "explanation": "Heredity is the transfer of characteristics from parents to offspring. This is a fundamental concept in genetics, the study of how traits are passed from one generation to the next. Traits can include physical characteristics like eye color or hair type, or more complex traits like susceptibility to certain diseases. The other options do not accurately define heredity. Non-resemblance of closely related organisms, total absence of parental traits in offspring, and absence of variation in organisms are not definitions of heredity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1995>55", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "Which of the following is not a reason why an offspring looks different from its parents?", "images": [], "options": {"A": "Random reorganisation of chromosome during gamete formation", "B": "Existence of multiple alleles in organisms", "C": "Formation of chasmata in chromatids during meiosis", "D": "Mitosis of the zygote produces new combination of chromosomes"}, "answer": "D", "explanation": "An offspring looks different from its parents due to genetic variation, which can be caused by several factors such as random reorganisation of chromosomes during gamete formation, existence of multiple alleles in organisms, and formation of chasmata in chromatids during meiosis. However, mitosis of the zygote does not produce new combinations of chromosomes. Instead, it results in identical cells with the same genetic information as the parent cell. Therefore, mitosis of the zygote is not a reason why an offspring looks different from its parents.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>56", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "The pair of genes expressed in a heterozygous individual is described as", "images": [], "options": {"A": "allele", "B": "chromatid", "C": "dominant gene", "D": "centrosome"}, "answer": "A", "explanation": "In genetics, an allele refers to one of two or more versions of a gene that are found at the same place on a chromosome. In a heterozygous individual, two different alleles of a gene are present. Therefore, the pair of genes expressed in a heterozygous individual is described as an allele. A chromatid is one half of a duplicated chromosome, a dominant gene is an allele that is fully expressed in the phenotype of a heterozygote, and a centrosome is an organelle that serves as the main microtubule organizing center of the animal cell as well as a regulator of cell-cycle progression.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>57", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The following structures are adaptation for water conservation except", "images": [], "options": {"A": "sunken stomata", "B": "scales in animals", "C": "lenticels in stems", "D": "spines in plants"}, "answer": "C", "explanation": "Adaptations for water conservation in organisms include features that reduce water loss. Sunken stomata, scales in animals, and spines in plants are all adaptations that help to conserve water. Sunken stomata are a feature of many desert plants that help to reduce water loss during transpiration. Scales in animals, particularly reptiles, help to prevent water loss from the body surface. Spines in plants, which are modified leaves, reduce the surface area for water loss. However, lenticels in stems are not an adaptation for water conservation. Lenticels are small pores in the bark of stems and roots of woody plants that allow for gas exchange between the atmosphere and the internal tissues. They do not play a role in water conservation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>58", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Which of the following ecological factors causes food shortage?", "images": [], "options": {"A": "Low rate of reproduction", "B": "Emigration", "C": "Drought", "D": "Topography"}, "answer": "C", "explanation": "Drought is an ecological factor that can cause food shortage. Drought conditions can lead to a lack of water, which is essential for the growth of plants. Plants form the base of the food chain, and a decrease in plant growth can lead to a decrease in the availability of food for herbivores. This can then affect the entire food chain, leading to a food shortage. Low rate of reproduction, emigration, and topography can affect the availability of food, but they do not directly cause food shortage.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>59", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING", "question": "Density, mortality rate, birth rate are the factors that affect", "images": [], "options": {"A": "population", "B": "dominance", "C": "cover", "D": "habitat"}, "answer": "A", "explanation": "Density, mortality rate, and birth rate are all factors that directly influence the size and growth of a population. Density refers to the number of individuals per unit area or volume. Mortality rate is the number of deaths in a population over a certain period of time, while birth rate is the number of live births over the same period. These factors together determine the size of the population and its growth rate. Therefore, the correct answer is 'population'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1995>60", "subject": "Biology", "year": "1995", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Ultra-filtration process at the Bowman's capsule is facilitated by", "images": [], "options": {"A": "the volume of water in the blood", "B": "the high concentration of urea in the blood of the Bowman's capsule", "C": "the differential blood pressure between the glomerulus and the Bowman's capsule", "D": "the differential blood volume between the glomerulus and the Bowman's capsule"}, "answer": "C", "explanation": "Ultra-filtration in the Bowman's capsule is facilitated by the differential blood pressure between the glomerulus and the Bowman's capsule. This process involves the filtration of blood under high pressure in the glomerulus, leading to the formation of glomerular filtrate in the Bowman's capsule. The high pressure is due to the difference in the diameter of the afferent and efferent arterioles. The afferent arteriole that brings blood to the glomerulus is wider than the efferent arteriole that carries blood away from the glomerulus. This creates a pressure gradient which aids in the filtration process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>1", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "Which of the following levels of organisation in living things is in the correct sequence, starting from the most complex to me simplest?", "images": [], "options": {"A": "tissue → cell → organ → system", "B": "System → organ → tissue → cell", "C": "Cell → tissue → system → organ", "D": "Cell → tissue → organ → system"}, "answer": "B", "explanation": "The correct sequence of organization in living things, starting from the most complex to the simplest, is System → Organ → Tissue → Cell. A system is a group of organs that work together to perform a specific function. An organ is a group of tissues that perform a specific function. A tissue is a group of similar cells that work together to perform a specific function. A cell is the basic unit of life.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>2", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "A few drops of fehling's solution was added to juice extracted from fresh maize grain and boiled. A red precipitate was formed, indicating the presence of", "images": [], "options": {"A": "alcohol", "B": "protein", "C": "non-reducing sugar", "D": "reducing sugar"}, "answer": "C", "explanation": "Fehling's solution is specifically used to test for reducing sugars. The formation of a red precipitate upon adding Fehling's solution and boiling indicates the presence of reducing sugars.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>3", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which of the following is not a cell organelle?", "images": [], "options": {"A": "Golgi body", "B": "Nucleus", "C": "Fat droplets", "D": "Ribosome"}, "answer": "C", "explanation": "Cell organelles are specialized structures within the cell that perform specific functions. The Golgi body, nucleus, and ribosome are all examples of cell organelles. The Golgi body is involved in packaging and transport of proteins, the nucleus houses the cell's DNA and controls the cell's activities, and ribosomes are involved in protein synthesis. Fat droplets, on the other hand, are not considered cell organelles. They are simply accumulations of lipids within the cell, but they do not have a specific function or structure that would classify them as an organelle.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1996>4", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "One of the differences between plants and animals is that", "images": [], "options": {"A": "growth is indefinite in animals but definite in plants", "B": "nutrition is autotrophic in plants but holophytic in animals", "C": "in plants there are excretory systems but in animals waste products are stored away", "D": "plants react slowly to external stimuli while animals react more quickly"}, "answer": "D", "explanation": "The correct answer is that plants react slowly to external stimuli while animals react more quickly. This is because plants lack a nervous system and muscles, which in animals allow for quick responses to stimuli. Instead, plants respond to stimuli like light, gravity, and touch through slower processes like differential cell growth and development.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>5", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Which of the following are the final products of aerobic respiration?", "images": [], "options": {"A": "Water, carbondioxide and energy", "B": "Pyruvic acid, carbondioxide and water", "C": "Glucose, energy and urea", "D": "Energy and carbondioxide"}, "answer": "A", "explanation": "Water: Although water is necessary for many biochemical processes, in the context of aerobic respiration, it is produced as a waste product when oxygen acts as the final electron acceptor in the electron transport chain, combining with hydrogen ions and electrons.  Carbon Dioxide: Carbon dioxide is produced as a waste product during the Krebs cycle when acetyl-CoA is oxidized. Each turn of the Krebs cycle releases two molecules of CO2.  Adenosine Triphosphate (ATP): ATP, the main energy carrier in the cell, is produced through substrate-level phosphorylation in glycolysis and the Krebs cycle, and mainly through oxidative phosphorylation in the electron transport chain. ATP is generated by the addition of a phosphate group to ADP, utilizing the energy released from the transfer of electrons through the electron transport chain.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>6", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "Movement of water across a semi-permeable membrane from a weaker solution to a stronger solution is known as", "images": [], "options": {"A": "transpiration", "B": "diffusion", "C": "active transport", "D": "osmosis"}, "answer": "D", "explanation": "The movement of water across a semi-permeable membrane from a weaker solution (lower concentration) to a stronger solution (higher concentration) is known as osmosis. Osmosis is a type of passive transport that occurs naturally, without the need for energy. It's a vital process in biological systems, for example, it regulates the water flow in and out of cells. Transpiration is the process of water movement through a plant and its evaporation from aerial parts, such as leaves, stems and flowers. Diffusion is the movement of molecules from an area of higher concentration to an area of lower concentration. Active transport is the movement of ions or molecules across a cell membrane into a region of higher concentration, assisted by enzymes and requiring energy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>7", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "ln which of the following structures will cells undergoing meiosis be seen?", "images": [], "options": {"A": "At the apices of stem and root", "B": "In the cortex of the stem", "C": "In the pallisade mesophyll of the leaf", "D": "ln the ovary of a flower"}, "answer": "D", "explanation": "Meiosis is a type of cell division that results in four daughter cells each with half the number of chromosomes of the parent cell. It is a process that leads to the formation of sex cells or gametes (sperm and egg cells). In plants, meiosis occurs in the reproductive organs, specifically in the anthers (male) and ovaries (female) of the flower. Therefore, cells undergoing meiosis will be seen in the ovary of a flower.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>8", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS", "question": "Which of these instruments can be used to perform an experiment on geotropism?", "images": [], "options": {"A": "Potometer", "B": "Cup anemometer", "C": "Klinostat", "D": "Kymograph"}, "answer": "C", "explanation": "A klinostat is a device which uses rotation to negate the effects of gravitational pull on plant growth ( gravitropism) and development ( gravimorphism).   Geotropism is the directional growth of an organism in response to gravity. Roots display positive geotropism when they grow downwards, while shoots display negative geotropism when they grow upwards. A Klinostat is an instrument used to negate the effect of gravity and light on the growth of plants, thus it can be used to perform an experiment on geotropism. A Potometer is used to measure the rate of transpiration in plants, a Cup anemometer is used to measure wind speed, and a Kymograph is used to record variations in pressure, velocity and other variables.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>9", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The thoracic vertebra differs from all the other vertebrae by the possession of", "images": [], "options": {"A": "long neural spine", "B": "odontoid process", "C": "vertebraterial canal", "D": "Large centrum"}, "answer": "A", "explanation": "The thoracic vertebrae are most distinctly characterized by their long neural spines. This feature is specific and easily identifiable compared to other vertebrae.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>10", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Study the list below  The vertebral column of mammals consists of the following:  I. Lumbar vertebrae II. Thoracic vertebrae III. Caudal vertebrae IV Cervical vertebrae V. Sacral vertebrae.    Which of the following are found immediately next to the skull?", "images": [], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "D", "explanation": "The vertebral column of mammals is divided into several regions, which from top to bottom are: the cervical, thoracic, lumbar, sacral, and caudal vertebrae. The cervical vertebrae are the ones found immediately next to the skull. Therefore, the correct answer is IV. Cervical vertebrae.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>11", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "Study the list below  The vertebral column of mammals consists of the following:  I. Lumbar vertebrae II. Thoracic vertebrae III. Caudal vertebrae IV Cervical vertebrae V. Sacral vertebrae. Which of the following articulates with the ribs?", "images": [], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "B", "explanation": "The thoracic vertebrae articulate with the ribs. The thoracic vertebrae are the only vertebrae that have facets on their bodies and transverse processes for rib articulation. The ribs connect to the thoracic vertebrae at two points: the head of the rib connects to the body of the vertebrae and the tubercle of the rib connects to the transverse process. This allows for the movement of the ribs during respiration.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1996>12", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "Study the list below  The vertebral column of mammals consists of the following:  I. Lumbar vertebrae II. Thoracic vertebrae III. Caudal vertebrae IV Cervical vertebrae V. Sacral vertebrae. Which of the following articulates with the pelvic girdle?", "images": [], "options": {"A": "V", "B": "IV", "C": "III", "D": "II"}, "answer": "A", "explanation": "The vertebral column of mammals consists of several types of vertebrae. The sacral vertebrae (option V) are the ones that articulate with the pelvic girdle. The sacrum is a large, triangular bone at the base of the spine and at the upper and back part of the pelvic cavity, where it is inserted like a wedge between the two hip bones. Its upper part connects with the last lumbar vertebra, and bottom part with the coccyx (tailbone).", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1996>13", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which of the following is more concentrated in the blood within the renal artery than the blood within the renal vein?", "images": [], "options": {"A": "Urea", "B": "Red blood cells", "C": "Glucose", "D": "Protein"}, "answer": "A", "explanation": "The renal artery carries blood to the kidneys for filtration. During this process, waste products such as urea are removed from the blood. Therefore, the concentration of urea is higher in the blood within the renal artery than in the blood within the renal vein, which carries filtered blood away from the kidneys. The other options (red blood cells, glucose, protein) are not typically removed or significantly reduced during filtration, so their concentrations would not be higher in the renal artery than in the renal vein.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>14", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "Which of the following statements about the lymphatic system is not correct?", "images": [], "options": {"A": "The lymph vessels are always larger in size than the arteries", "B": "The flow of lymph is assisted by general muscular movement", "C": "Lymph flows only in one direction due to the presence of valves", "D": "Lymph is emptied into the blood circulatory system through a vein"}, "answer": "A", "explanation": "The lymphatic system is a network of tissues and organs that help rid the body of toxins, waste and other unwanted materials. The primary function of the lymphatic system is to transport lymph, a fluid containing infection-fighting white blood cells, throughout the body. The lymph vessels are not always larger in size than the arteries. In fact, they are generally smaller. The other options are correct: the flow of lymph is indeed assisted by general muscular movement, lymph does flow only in one direction due to the presence of valves, and lymph is emptied into the blood circulatory system through a vein.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>15", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "In which of the following groups is nephridium found?", "images": [], "options": {"A": "Crustaceans", "B": "Reptiles", "C": "Birds", "D": "Annelids"}, "answer": "D", "explanation": "Annelida, also called segmented worm, any member of a phylum of invertebrate animals that are characterized by the possession of a body cavity (or coelom ), movable bristles (or setae ), and a body divided into segments by transverse rings. a segmented worm of the phylum Annelida, such as an earthworm or leech.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>16", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "The maintenance of a constant internal environment of an organism is known as", "images": [], "options": {"A": "homeostasis", "B": "homeorhesis", "C": "turgidity", "D": "homoiothermy"}, "answer": "A", "explanation": "The maintenance of a constant internal environment of an organism is known as homeostasis. Homeostasis is a biological concept referring to the ability of an organism or cell to maintain equilibrium by adjusting its physiological processes. The other options do not correctly define this concept. Homeorhesis refers to the stability of a pathway, process or system. Turgidity is the state of being swollen or distended, often in relation to plant cells. Homoiothermy is the ability of some organisms to maintain a stable body temperature.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1996>17", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT", "question": "Which of the following is the effect of continuous tillage on an ecological system?", "images": [], "options": {"A": "Addition of more. humus to the soil", "B": "Decrease in productivity", "C": "Increase in yield", "D": "Improved fertility"}, "answer": "B", "explanation": "Continuous tillage of an ecological system often leads to a decrease in productivity. This is because continuous tillage can lead to soil degradation, which in turn reduces the soil's ability to support plant growth. Soil degradation can occur as a result of various factors, including erosion, compaction, nutrient imbalance, and disruption of soil organisms. None of the other options are correct because continuous tillage does not add more humus to the soil, does not increase yield, and does not improve fertility. In fact, it often has the opposite effect.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>18", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The most sensitive part of the retina is called", "images": [], "options": {"A": "blindspot", "B": "conjuctiva", "C": "fovea centralis", "D": "choroid coat"}, "answer": "C", "explanation": "fovea centralis; a small depression in the retina of the eye where visual acuity is highest. The centre of the field of vision is focused in this region, where retinal cones are particularly concentrated.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1996>19", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "Which of the following pairs consists of gametes?", "images": [], "options": {"A": "Ova and spermatozoa", "B": "Spores and sporangium", "C": "Flowers and pollen grains", "D": "Testes and ovaries"}, "answer": "A", "explanation": "Gametes are the reproductive cells that combine to form offspring. In humans and many other species, there are two main types of gametes, and these are sperm (from males) and eggs or ova (from females). Therefore, the pair that consists of gametes is 'Ova and spermatozoa'. Spores and sporangium, Flowers and pollen grains, Testes and ovaries are not pairs of gametes. Spores are reproductive cells in fungi, algae, and plants, but sporangium is a structure that produces and contains spores, not a gamete. Flowers and pollen grains are parts of plants, but only pollen grains can be considered as gametes (male gametes in plants). Testes and ovaries are reproductive organs that produce gametes, but they are not gametes themselves.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>20", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "Which of the labelled structures is the nucleus?", "images": ["Biology/imgs/1996/A7GJNB.jpg"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "B", "explanation": "The nucleus of the sperm cell, which houses the DNA, is located within the head. Label II points to this specific region.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>21", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "Which of the following labelled structures secretes enzymes which facilitate penetration of the egg?", "images": ["Biology/imgs/1996/A7GJNB.jpg"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "A", "explanation": "Structure I (labelled in the image) is located at the head of the sperm cell. The acrosome is situated at the anterior part of the sperm head and contains hydrolytic enzymes. These enzymes are released upon contact with the egg's zona pellucida to facilitate sperm penetration through this protective layer during fertilization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>22", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "Which of the following labelled structures is similar to the locomotory structure in Euglena?", "images": ["Biology/imgs/1996/A7GJNB.jpg"], "options": {"A": "I", "B": "II", "C": "III", "D": "V"}, "answer": "D", "explanation": "Among the labelled options (I, II, III, IV, V), the correct answer is (V). Structure V (labelled in the image) corresponds to a flagellum. Flagella are long, whip-like appendages used for locomotion in many organisms, including Euglena. Euglena uses its flagellum to move through water by beating it in a characteristic waving motion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>23", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The part labelled I in A represents the", "images": ["Biology/imgs/1996/coty.png"], "options": {"A": "root", "B": "radicle", "C": "hypocotyl", "D": "shoot"}, "answer": "C", "explanation": "The part labelled I in A represents the hypocotyl. The hypocotyl is the first part of the embryo to emerge from a seed that has been planted in the soil.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1996>24", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The part labelled II represents the", "images": ["Biology/imgs/1996/coty.png"], "options": {"A": "root", "B": "epicotyl", "C": "hypocotyl", "D": "cotyledon"}, "answer": "D", "explanation": "Cotyledons are seed leaves that serve essential functions during the early stages of a plant's life, particularly before it can photosynthesize on its own.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1996>25", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "What is the importance of the part labelled II to the seedling? It", "images": ["Biology/imgs/1996/coty.png"], "options": {"A": "protects the foliage leaves", "B": "grows into the first foliage leaves", "C": "later develops into the fruit", "D": "provides the seedling with food"}, "answer": "D", "explanation": "Cotyledons play a vital role in the early development and survival of seedlings by providing nutrients, protection, and sometimes even contributing to photosynthesis until the plant becomes self-sufficient with its true leaves.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>26", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "In grasshopper/cockroach digestion starts from the", "images": [], "options": {"A": "oesophagus", "B": "crop", "C": "gizzard", "D": "mouth"}, "answer": "D", "explanation": "In grasshoppers and cockroaches, digestion starts from the mouth. The food is first ingested through the mouth where it is broken down into smaller pieces by the mandibles (jaws). The food is then mixed with saliva for further breakdown. Therefore, the correct answer is 'mouth'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1996>27", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "In a water culture experiment, the culture solution in a transparent beaker turned green. What precaution should have been taken to prevent the culture solution from turning green?", "images": [], "options": {"A": "Changing the culture solution regularly", "B": "Increasing the number of times the culture is aerated", "C": "Covering the transparent beaker with black cloth", "D": "Adding warm alcohol to bleach the green colour"}, "answer": "C", "explanation": "The culture solution turned green because of the growth of algae, which is facilitated by light. Covering the transparent beaker with a black cloth would prevent light from reaching the solution, thereby inhibiting the growth of algae. Changing the culture solution regularly or increasing the number of times the culture is aerated would not necessarily prevent the growth of algae. Adding warm alcohol would not prevent the growth of algae, but rather kill them and possibly other organisms in the culture solution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>28", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : NITROGEN CYCLE", "question": "Which of the following is responsible for the conversion of nitrites to nitrates in the nitrogen cycle?", "images": [], "options": {"A": "Denitrifying bacteria", "B": "Nitrifying bacteria", "C": "Lightening", "D": "Fungi"}, "answer": "B", "explanation": "As nitrifying bacteria name signifies the conversion of ammonia into nitrites or nitrates. These are the bacterias that break down the nitrated and return nitrogen to the air. Nitrification is the biological oxidation of ammonia to nitrite followed by the oxidation of the nitrite to nitrate occurring through separate organisms", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1996>29", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Hydra captures small crustaceans by means of", "images": [], "options": {"A": "pseudopodia", "B": "musculo-epithelial cells", "C": "tentacles", "D": "enteron"}, "answer": "C", "explanation": "Hydra, a small, simple aquatic animal, captures its prey, which includes small crustaceans, by means of its tentacles. The tentacles are equipped with specialized cells called cnidocytes, which contain structures called nematocysts. When a prey animal comes into contact with the tentacles, the nematocysts are triggered, firing a barbed thread that penetrates and immobilizes the prey. The prey is then moved to the mouth opening by the tentacles. Therefore, the correct answer is 'tentacles'. Pseudopodia are extensions of the cell used by some protozoans for movement or capturing food, which is not applicable to Hydra. Musculo-epithelial cells are a type of cell found in Hydra, but they are not directly involved in capturing prey. The enteron is the digestive cavity of the Hydra, not the means by which it captures prey.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>30", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "Which of the following processes is not due to interaction between the biotic and abiotic components of an ecosystem?", "images": [], "options": {"A": "Soil nutrient depletion", "B": "Condensation", "C": "Decomposition", "D": "Osmosis"}, "answer": "B", "explanation": "The interaction between biotic (living organisms) and abiotic (non-living elements) components of an ecosystem results in processes like soil nutrient depletion, decomposition, and osmosis. Soil nutrient depletion occurs when plants absorb nutrients from the soil, which is an interaction between a biotic component (plants) and an abiotic component (soil). Decomposition is the process by which dead organic substances are broken down into simpler organic or inorganic matter such as carbon dioxide, water, simple sugars and mineral salts, which is an interaction between biotic components (decomposers like bacteria and fungi) and abiotic components (dead organic matter). Osmosis is the process by which water molecules move from a region of lower concentration to a region of higher concentration through a semi-permeable membrane, which is an interaction between biotic components (cells) and abiotic components (water). However, condensation is a physical process where water vapor becomes liquid. It is a part of the water cycle, and it happens when the temperature drops or the amount of moisture in the air increases. It is not due to interaction between the biotic and abiotic components of an ecosystem.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>31", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "The entire habits and habitat of an organism can be described as its", "images": [], "options": {"A": "ecological community", "B": "ecological niche", "C": "habitat factor", "D": "biotic factor"}, "answer": "B", "explanation": "The entire habits and habitat of an organism can be described as its ecological niche.   In biology and ecology, a niche pertains to any of the following:    The specific area where an organism inhabits  The role or function of an organism or species in an ecosystem  The interrelationship of a species with all the biotic and abiotic factors affecting it", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>32", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "Which of these is not a true characteristic of the tropical rain forest?", "images": [], "options": {"A": "Vegetation consists predominantly of tall trees, with thick canopy", "B": "Forest is rich in epipphysis and climbers", "C": "Annual rainfall is less than 100 cm", "D": "interior has low light intensity, high humidity and damp floor"}, "answer": "C", "explanation": "Tropical rainforests are characterized by high rainfall, with minimum normal annual rainfall between 1750–2000 mm (68-78 inches). Therefore, the statement 'Annual rainfall is less than 100 cm' is not a true characteristic of the tropical rain forest.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>33", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING", "question": "The frequency of andropogon in a grass lawn is 90 by 100. Throws were made with 1 meter square quadrat. What is the density of andropogon in the field?", "images": [], "options": {"A": "0.09 per m2", "B": "0.90 per m2", "C": "9.0 per m2", "D": "90 per m2"}, "answer": "B", "explanation": "If a 1-meter square quadrat is used, the population density will be 90/100 per m2. So, the answer is 0.90 peer m2", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>1996>34", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS", "question": "Which of the following is the correct method of collecting soil organism?", "images": [], "options": {"A": "Heating the soil sample in an oven", "B": "Aerating the soil sample", "C": "Refrigerating the soil for some hours", "D": "Placing a lighted electric bulb over soil in a funnel"}, "answer": "D", "explanation": "The correct method of collecting soil organisms is by placing a lighted electric bulb over soil in a funnel. This method is known as the Tullgren funnel method. The heat from the bulb dries the soil, causing the organisms to move downwards and eventually fall into a collecting jar placed beneath the funnel.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>35", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "Which of these groups of organisms is responsible for capturing energy for the biotic community?", "images": [], "options": {"A": "Decomposers", "B": "Omnivores", "C": "Consumers", "D": "Producers"}, "answer": "D", "explanation": "Producers is responsible for capturing energy for the biotic community. At the base of almost every food chain is a producer. These are plants or algae, which photosynthesise. This means they convert energy from the sun into glucose during photosynthesis, which produces biomass. It is this which feeds the rest of the food chain.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1996>36", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "The following are pathways of energy in the biosphere  I. Heat energy is lost from body metabolism to the surrounding air   II. Energy passes to decomposers and parasites   III. Energy is transferred to the next higher level in a food chain   IV. Energy is also passed by conduction to clothing and other objects    Which pathway directly leads to transfer of useful energy within a biological community?", "images": [], "options": {"A": "I only", "B": "II and III only", "C": "I and III only", "D": "I and II only"}, "answer": "B", "explanation": "In a biological community, energy is transferred in various ways. The useful energy transfer within a biological community is through the food chain and to decomposers and parasites. In a food chain, energy is transferred from one trophic level to the next higher level. This is represented by statement III. Decomposers and parasites also play a crucial role in energy transfer as they break down dead organisms and waste materials, releasing the energy stored in them back into the ecosystem. This is represented by statement II. Therefore, the correct answer is 'II and III only'. Heat energy lost from body metabolism to the surrounding air (statement I) and energy passed by conduction to clothing and other objects (statement IV) are forms of energy loss, not useful energy transfer within a biological community.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>1996>37", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "The following are pathways of energy in the biosphere  I. Heat energy is lost from body metabolism to the surrounding air   II. Energy passes to decomposers and parasites   III. Energy is transferred to the next higher level in a food chain   IV. Energy is also passed by conduction to clothing and other objects   Which of the following pathways will energy follow to reach plasmodium in the red blood cells?", "images": [], "options": {"A": "I, II and III", "B": "I and II", "C": "II only", "D": "III and IV"}, "answer": "C", "explanation": "Plasmodium is a parasite that lives in the red blood cells of its host. Therefore, the energy pathway to reach plasmodium in the red blood cells is through decomposers and parasites (II). The other pathways (I, III, IV) are not relevant to the energy flow to plasmodium.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>1996>38", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS", "question": "What type of relationship exists in the large intestine of the sheep, between bacteria and the sheep?", "images": [], "options": {"A": "Symbiosis", "B": "Commensalism", "C": "Predation", "D": "Parasitism"}, "answer": "A", "explanation": "A symbiosis is an evolved interaction or close living relationship between organisms from different species, usually with benefits to one or both of the individuals involved.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>39", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS", "question": "The Tulgren's funnel is used to", "images": [], "options": {"A": "extract minute soil organisms", "B": "measure the amount of rainfall", "C": "collect water from habitats", "D": "pour liquid into containers with narrow mouth"}, "answer": "A", "explanation": "The Tullgren's funnel is a device used in soil biology to extract small soil-dwelling animals, including insects, mites, spiders, and other minute soil organisms. The device works by applying a heat source from above which drives the organisms downwards and they eventually fall into a collecting jar. Therefore, the correct answer is 'extract minute soil organisms'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1996>40", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "Which of the following is not an aquatic habitat?", "images": [], "options": {"A": "Estuaries", "B": "Ponds", "C": "Rainforest", "D": "Swamp"}, "answer": "C", "explanation": "An aquatic habitat is a habitat with water. It includes areas that are permanently covered by water and surrounding areas that are occasionally covered by water. Estuaries, ponds, and swamps are all types of aquatic habitats as they contain water. However, a rainforest is not an aquatic habitat. It is a terrestrial habitat characterized by high rainfall, with annual rainfall in the case of tropical rainforests between 2.5 and 4.5 meters, and definitions varying by region for temperate rainforests.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1996>41", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS", "question": "Which of these materials is not required for insect collection in an ecological field-trip?", "images": [], "options": {"A": "Pooter", "B": "Secchi disc", "C": "Spreading board", "D": "Jar containing alcohol"}, "answer": "B", "explanation": "A Secchi disc is not required for insect collection in an ecological field-trip. A Secchi disc is a circular disc used to measure water transparency in oceans and lakes. The other options, Pooter, Spreading board, and Jar containing alcohol, are all tools commonly used in insect collection. A Pooter is a device used for catching small insects and other small creatures. A Spreading board is used to pin and display collected insects, and a Jar containing alcohol is used to preserve collected insects.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1996>42", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "The factors which determine the type of vegetation a particular habitat will support are related to the following except", "images": [], "options": {"A": "nature of the soil particles", "B": "amount of rainfall", "C": "mineral content of the soil", "D": "farming activities"}, "answer": "D", "explanation": "The factors which determine the type of vegetation a particular habitat will support are related to several factors, including the nature of the soil particles, the amount of rainfall, the mineral content of the soil, and the depth of the water-table. However, farming activities are not a natural factor but a human activity that can alter the natural vegetation and ecosystem of an area.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>43", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING", "question": "Which of the following statements is not true of population?", "images": [], "options": {"A": "Members of a population may be of the same species", "B": "Members of a population may be of the same species but do not interbreed", "C": "Size of a population may be limited by space", "D": "Some species can form another population elsewhere"}, "answer": "B", "explanation": "A population is a group of individuals of the same species that live in the same area and interbreed. Therefore, the statement 'Members of a population may be of the same species but do not interbreed' is not true of a population. All other options correctly describe characteristics of a population.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>44", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Which of the following is an abiotic factor which affects a population?", "images": [], "options": {"A": "Predator", "B": "Parasite", "C": "Consumer", "D": "Temperature"}, "answer": "D", "explanation": "An abiotic factor refers to non-living physical and chemical elements in the ecosystem. Abiotic factors could include temperature, light, water, air, soil, pH, and nutrients. These factors have a significant impact on the survival and reproduction of species in an ecosystem. In the given options, 'Temperature' is an abiotic factor. Predators, parasites, and consumers are all biotic factors, meaning they are living organisms that affect a population.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1996>45", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "One of the ecological conditions which favour the spread of malaria is", "images": [], "options": {"A": "improper disposal of decaying organic matter", "B": "clearing bushes around dwelling houses", "C": "presence of water weeds", "D": "presence of stagnant water in ponds"}, "answer": "D", "explanation": "Malaria is a disease caused by a parasite that is transmitted to humans through the bite of the female Anopheles mosquito. These mosquitoes breed in areas with stagnant water. Therefore, the presence of stagnant water in ponds creates a favorable environment for the breeding of these mosquitoes, leading to the spread of malaria. The other options do not directly relate to the spread of malaria.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>46", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "Which of the following resources is non-renewable?", "images": [], "options": {"A": "Livestock", "B": "Minerals", "C": "Forest", "D": "Soil"}, "answer": "B", "explanation": "A non-renewable resource is a resource that does not renew itself at a sufficient rate for sustainable economic extraction in meaningful human timeframes. Minerals are considered non-renewable resources as they do not form or replenish in a short period of time. Livestock, forests, and soil are all renewable resources because they can be replenished naturally in a relatively short amount of time.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1996>47", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT", "question": "The following are the effects of overgrazing except", "images": [], "options": {"A": "depletion of useful fodder crops", "B": "soil and wind erosion of pastureland", "C": "epidemic of cattle diseases", "D": "migration of herdsmen"}, "answer": "C", "explanation": "Overgrazing refers to the situation where plants are exposed to intensive grazing for extended periods of time, or without sufficient recovery periods. It can be caused by either livestock in poorly managed agricultural applications, or by overpopulations of native or non-native wild animals. Overgrazing reduces the usefulness, productivity, and biodiversity of the land and is one cause of desertification and erosion. It's effects include depletion of useful fodder crops and soil and wind erosion of pastureland. However, it does not directly cause an epidemic of cattle diseases. Diseases in cattle can be caused by a variety of factors including bacteria, viruses, parasites, and certain environmental factors, but not directly by overgrazing. Therefore, the statement 'epidemic of cattle diseases' is not an effect of overgrazing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>48", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Which of the following is not a way of conserving natural resources?", "images": [], "options": {"A": "Adopting good farming practices", "B": "Establishing forest reserves", "C": "Establishing of game reserves", "D": "Encouraging poaching"}, "answer": "D", "explanation": "Conservation of natural resources involves practices that protect, preserve, and sustainably manage these resources. Good farming practices help to maintain soil fertility and prevent soil erosion. Establishing forest reserves and game reserves helps to protect biodiversity by providing habitats for various species. However, poaching, which is the illegal hunting or capturing of wild animals, is not a way of conserving natural resources. Instead, it threatens biodiversity and can lead to the extinction of species.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>49", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "The need for conservation includes the following except to", "images": [], "options": {"A": "keep natural resources for future generations", "B": "preserve them for scientific and recreational purposes", "C": "maximise the use of natural resources", "D": "make sure the natural resources are not used"}, "answer": "D", "explanation": "Conservation is the sustainable use and management of natural resources including wildlife, water, air, and earth deposits. The aim of conservation is not to make sure the natural resources are not used, but rather to ensure that they are used in a sustainable manner that ensures their availability for future generations, for scientific and recreational purposes, and to maximize their use. Therefore, the option 'make sure the natural resources are not used' is not a reason for conservation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>50", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of these is not a hereditary variation?", "images": [], "options": {"A": "Infant paralysis", "B": "Blood group", "C": "Sickle cell", "D": "Shape of face and nose"}, "answer": "A", "explanation": "Hereditary variations are differences that are passed from parents to offspring through genes. These include traits like blood group, sickle cell trait, and physical features like the shape of face and nose. Infant paralysis, however, is not a hereditary variation. It is a condition that can occur due to various reasons such as injury, illness, or malnutrition, but it is not passed down through genes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>51", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of these statements is correct?", "images": [], "options": {"A": "Recombination at fertilization does not occur between two homologous chromosome", "B": "In homologous chromosome two genes very close to each other are more likely to form recombinants meiotic prophase I", "C": "A dominant gene masks the presence of a recessive gene", "D": "Meiosis leads to the formation of daughter cells with diploid chromosome number"}, "answer": "C", "explanation": "A dominant gene masks the presence of a recessive gene. This is a fundamental principle of genetics. In a pair of alleles, if one is dominant and the other is recessive, the dominant allele will express itself in the phenotype, effectively 'masking' the presence of the recessive allele. This is why the recessive trait only appears when an individual has two copies of the recessive allele. The other options are incorrect. Recombination does occur between homologous chromosomes during meiosis, genes close to each other on a chromosome are less likely to recombine due to genetic linkage, and meiosis results in haploid, not diploid, daughter cells.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>52", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY", "question": "One of Mendel's experiments was repeated by crossing a red variety of pepper with that of a yellow variety which produced all red offspring. The red offspring were then self pollinated and these produced both red and yellow pepper. The yellow colour can be said to be", "images": [], "options": {"A": "dominant to red", "B": "recessive to red", "C": "homozygous to red", "D": "heterozygous to red"}, "answer": "B", "explanation": "In Mendelian genetics, a trait that appears in the first generation (F1) when parents with different traits are crossed is said to be dominant, while the trait that is masked in the F1 generation but reappears in the second generation (F2) is said to be recessive. In the given question, the red color appears in the F1 generation when a red pepper is crossed with a yellow pepper, indicating that red is the dominant trait. The yellow color, which is masked in the F1 generation but reappears in the F2 generation, is therefore the recessive trait. Hence, the yellow color is recessive to red.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>53", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "Which of the following statements is not true about chromosomes?", "images": [], "options": {"A": "Each chromosome is made up of two chromatids", "B": "Body cells have diploid numbers of chromosomes", "C": "Homologous chromosomes do not occur in pairs naturally", "D": "The sex cells have haploid number of chromosomes"}, "answer": "C", "explanation": "Homologous chromosomes do not occur in pairs naturally is not true about chromosomes. Homologous chromosomes occur in pairs naturally in diploid organisms. Homologous chromosomes are similar in size, shape, and carry genes for the same traits, but they may have different versions of those genes. During meiosis, homologous chromosomes pair up and exchange genetic information through a process called crossing over, which contributes to genetic diversity", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>54", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY", "question": "Cross-breeding is a way of", "images": [], "options": {"A": "developing superior varieties of plants only", "B": "developing superior varieties of animals only", "C": "developing disease-resistant varieties only", "D": "applying the principles of heredity in agriculture"}, "answer": "D", "explanation": "Cross-breeding is a method used in agriculture to combine the desirable traits of two different species or varieties to produce a superior variety. This method is not limited to plants or animals only, it can be applied to both. It is also not limited to developing disease-resistant varieties only, it can be used to improve various traits such as yield, quality, adaptability to environmental conditions, etc. Therefore, the correct answer is 'applying the principles of heredity in agriculture'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>55", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "The wings of bats and birds, the flippers of whale and the fins of fish are examples of", "images": [], "options": {"A": "adaptive radiation", "B": "vestigial organs", "C": "continuous variation", "D": "convergent evolution"}, "answer": "D", "explanation": ". The wings of bats, birds, the flippers of whales, and the fins of fish are all examples of structures that have evolved independently in different groups of animals, but serve similar functions. This is known as convergent evolution, where unrelated organisms evolve similar structures or functions due to similar selection pressures. In this case, the ability to fly, swim, or move through the water efficiently, respectively, has led to the development of these similar structures", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>56", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following is a social insect?", "images": [], "options": {"A": "Mosquito", "B": "Butterfly", "C": "Honey bee", "D": "Grasshopper"}, "answer": "C", "explanation": "Honey bee is a social insect.social insect, any of numerous species of insects that live in colonies and manifest three characteristics: group integration, division of labour, and overlap of generations. Social insects are best exemplified by all termites (Isoptera; sometimes Blattodea) and ants.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1996>57", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "The phenomenon whereby some organisms get established in an environment after struggling for existence by taking advantage of some special features possessed by the organism is called", "images": [], "options": {"A": "partial selection", "B": "artificial selection", "C": "natural selection", "D": "mutation"}, "answer": "C", "explanation": "The phenomenon described in the question is known as natural selection. Natural selection is a process where organisms that are better adapted to their environment tend to survive and produce more offspring. This process makes them get established in an environment after struggling for existence by taking advantage of some special features possessed by the organism. The other options do not accurately describe this process. Partial selection and artificial selection are not natural processes, and mutation is a change in the DNA sequence, not a process of survival and establishment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>58", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "The statements below are about evolution of species  I. Members of a species vary ll. Organisms produce many offspring lll. The mechanism of evolution is  inheritance of acquired characters IV. Changes in the phenotype is brought about by the individual itself    Which of the statement(s) is/are related to the Darwin's theory of evolution?", "images": [], "options": {"A": "I only", "B": "II only", "C": "I, II and IV", "D": "I and II only"}, "answer": "D", "explanation": "Darwin's theory of evolution, also known as Darwinism, includes two key ideas: that evolution occurs and that evolution occurs through natural selection. Statement I, 'Members of a species vary', refers to the concept of variation, which is a fundamental aspect of Darwin's theory. Statement II, 'Organisms produce many offspring', refers to the concept of overproduction, which is also a key aspect of Darwin's theory. Overproduction leads to competition for resources, and those individuals with advantageous variations are more likely to survive and reproduce. Therefore, statements I and II are related to Darwin's theory of evolution. Statements III and IV are not related to Darwin's theory. Statement III, 'The mechanism of evolution is inheritance of acquired characters', refers to Lamarck's theory of evolution, not Darwin's. Statement IV, 'Changes in the phenotype is brought about by the individual itself', is also not part of Darwin's theory. Therefore, the correct answer is 'I and II only'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>1996>59", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Which of the following fields of study may not yield strong evidence of evolution?", "images": [], "options": {"A": "Fossil", "B": "Histology", "C": "Ecology", "D": "Genetics"}, "answer": "C", "explanation": "Evolution is the process of change in all forms of life over generations. It is studied through various fields such as genetics, paleontology (study of fossils), comparative anatomy, and molecular biology. Among the given options, 'Ecology' is the least likely to yield strong evidence of evolution. Ecology is the study of the interactions between organisms and their environment. While it can provide some insights into the adaptive strategies of organisms, it does not directly deal with the genetic changes over generations that is the core of evolutionary studies. Therefore, the answer is 'Ecology'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1996>60", "subject": "Biology", "year": "1996", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS", "question": "Which of the following is the simplest method of finding the magnification of the drawing of a specimen?", "images": [], "options": {"A": "(length of drawing/width of drawing) / (length of specimen/width of specimen)", "B": "(length of specimen/width of specimen) / (length of drawing/width of drawing)", "C": "length of drawing x 2/ length of specimen", "D": "length of drawing / width of specimen"}, "answer": "A", "explanation": "Magnification=(length of drawing/width of drawing) / (length of specimen/width of specimen)", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>1", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "Which of the following organism possesses both plant and animal characteristics?", "images": [], "options": {"A": "Amoeba", "B": "Paramecium", "C": "Euglena", "D": "Mucor"}, "answer": "C", "explanation": "Euglena is a genus of single-celled flagellate eukaryotes. It is the best known and most widely studied member of the class Euglenoidea, a diverse group containing some 54 genera and at least 800 species. Species of Euglena are found in fresh and salt waters. They are often abundant in quiet inland waters where they may bloom in numbers sufficient to color the surface of ponds and ditches green (Euglena viridis) or red (Euglena sanguinea). The species possess both plant and animal characteristics. As a plant, it can photosynthesize and as an animal, it can move around in search of food using its flagella.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>2", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The structure represented in the diagram above is", "images": ["Biology/imgs/1997/spirogyra.png"], "options": {"A": "a colony", "B": "a tissue", "C": "a filament", "D": "a pseudopodium"}, "answer": "C", "explanation": "The structure represented in the diagram above is a filament. Spirogyras are filamentous green algae, named for their spiraling chloroplasts. Each cell of the filaments features a large central vacuole, within which the nucleus is suspended by fine strands of cytoplasm", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>3", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The part labelled I in the diagram is the", "images": ["Biology/imgs/1997/spirogyra.png"], "options": {"A": "cytoplasm", "B": "chloroplast", "C": "chlorophyll", "D": "nucleus"}, "answer": "B", "explanation": "The part labelled I in the diagram is the chloroplast. chloroplast, structure within the cells of plants and green algae that is the site of photosynthesis, the process by which light energy is converted to chemical energy, resulting in the production of oxygen and energy-rich organic compounds.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>4", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "What is the function of the part labelled II in the diagram? It", "images": ["Biology/imgs/1997/spirogyra.png"], "options": {"A": "manufactures food", "B": "protects the chloroplast", "C": "produces protein", "D": "suspends the nucleus"}, "answer": "D", "explanation": "The cytoplasm surrounds and supports the nucleus along with other organelles, ensuring they remain in place and can function properly within the cell. This suspension also allows for the distribution of nutrients and waste products within the cell.  The Other Options Are Incorrect  Manufactures food: This function is specific to chloroplasts, which are the site of photosynthesis.  Protects the chloroplast: This role is generally associated with the cell wall or cell membrane, which encases the entire cell, including the chloroplasts.  Produces protein: Ribosomes are the primary site for protein synthesis, not the cytoplasm itself.  Digests starch: This function is associated with amyloplasts, which are specialized for storing and converting starch.  Therefore, based on the structure and function of the cytoplasm, Suspends the nucleus is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>5", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which of the following organelles helps to remove excess water from cells?", "images": [], "options": {"A": "Mitochondrion", "B": "Ribosome", "C": "Contractile vacuole", "D": "Golgi body"}, "answer": "C", "explanation": "The contractile vacuole is an organelle in certain cells, particularly in protozoa, that expels excess water out of the cell. It performs osmoregulation, the process of regulating water potential in order to keep fluid and electrolyte balance within the cell. The other options, Mitochondrion, Ribosome, and Golgi body, do not perform this function. Mitochondrion is involved in energy production, Ribosome in protein synthesis, and Golgi body in processing and packaging proteins.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>6", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "Which of the following processes occurs by diffusion?", "images": [], "options": {"A": "Reabsorption of water in kidney tubules", "B": "Entry of water into the cytoplasm of unicellular animals", "C": "Absorption of water in the large intestine", "D": "Exchange of nutrients between a mother and the foetus"}, "answer": "D", "explanation": "Certain nutrients and gases like oxygen and carbon dioxide do indeed move by simple diffusion across the placental barrier. This passive movement is from areas of higher concentration to lower concentration. Thus, given that simple diffusion is involved in the exchange of some nutrients and gases (like oxygen and carbon dioxide) between the mother and the foetus is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>7", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION", "question": "Which of the following is a product of brewing when yeast is used as a fermenting agent?", "images": [], "options": {"A": "Nitrogen", "B": "Oxygen", "C": "Malt", "D": "Ethanol"}, "answer": "D", "explanation": "The process of brewing involves the fermentation of sugars by yeast. The yeast consumes the sugars and produces ethanol and carbon dioxide as by-products. Therefore, the product of brewing when yeast is used as a fermenting agent is ethanol.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>8", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following hind limb bones is equivalent to the humerus of the forelimb?", "images": [], "options": {"A": "Patella", "B": "Tarsal", "C": "Tibia", "D": "Femur"}, "answer": "D", "explanation": "The humerus is the single long bone of the upper arm in the forelimb. The femur is the single long bone of the upper leg (thigh) in the hind limb. These bones are structurally and functionally analogous: Both are the longest bones in their respective limbs. Both articulate with the bones of the lower segment (radius/ulna in the forelimb and tibia/fibula in the hind limb).Both are involved in similar functions related to movement and support. Thus, the femur is the hind limb bone equivalent to the humerus in the forelimb.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>9", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Clotting of blood is a function of", "images": [], "options": {"A": "vitamin C", "B": "vitamin K", "C": "vitamin B2", "D": "vitamin E"}, "answer": "B", "explanation": "Clotting of blood is a function of Vitamin K. Vitamin K is a fat-soluble vitamin that plays a key role in helping the blood clot, preventing excessive bleeding. Unlike many other vitamins, vitamin K is not typically used as a dietary supplement. Vitamin K is actually a group of compounds. The most important of these compounds appears to be vitamin K1 and vitamin K2. Vitamin K1 is obtained from leafy greens and some other vegetables. Vitamin K2 is a group of compounds largely obtained from meats, cheeses, and eggs, and synthesized by bacteria.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>10", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Which of the following structures is associated with respiration in insects?", "images": [], "options": {"A": "Air sac", "B": "Spiracle", "C": "Lung", "D": "Alveolus"}, "answer": "B", "explanation": "Spiracles are small openings located on the sides of an insect's body. They are the entry and exit points for air in the tracheal system. Air enters the spiracles, moves through the tracheae, and diffuses directly into the insect's tissues. Spiracles are crucial because they control the opening and closing to regulate air flow and water loss. The tracheal system directly delivers oxygen to tissues and removes carbon dioxide, which is different from the circulatory system used in vertebrates.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>11", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The diagram below represents a section of the stem of a plant, use it to answer the question       Which of the labelled parts is made up of dead cells?", "images": ["Biology/imgs/1997/DFAY3C.png"], "options": {"A": "III and IV", "B": "I, II and IV", "C": "IV and V", "D": "II and III"}, "answer": "A", "explanation": "II: Cortex - composed of parenchyma cells, generally living cells.  III: Vascular bundle - includes both xylem (often dead at maturity) and phloem (living cells).  IV: Xylem - made up of dead cells that provide support and transport water and minerals.    Thus, the most accurate option is: III and IV, since the vascular bundle (III) includes xylem, which is made up of dead cells, and xylem (IV) itself is dead.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>12", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The diagram below represents a section of the stem of a plant, use it to answer the question     The part labelled I in the diagram is called", "images": ["Biology/imgs/1997/DFAY3C.png"], "options": {"A": "stoma", "B": "epidermis", "C": "lenticel", "D": "cortex"}, "answer": "C", "explanation": "The part labelled I in the diagram is called Ienticel. A lenticel is a porous tissue made up of vast intercellular gaps between cells. On stems and roots, lenticels appear as elevated circular, oval, or elongated patches", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>13", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "The malpighian tubule plays a major role in", "images": [], "options": {"A": "inspiration", "B": "digestion", "C": "secretion", "D": "excretion"}, "answer": "D", "explanation": "The malpighian tubule plays a major role in excretion. Malpighian tubules are excretory systems found in insects, located in the abdominal body cavity and draining between the midgut and hindgut", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>14", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "Filtered blood from the kidney is carried back to the circulatory system through the", "images": [], "options": {"A": "hepatic portal vein", "B": "renal artery", "C": "renal vein", "D": "pulmonary vein"}, "answer": "C", "explanation": "The renal vein is the blood vessel that carries filtered blood away from the kidney and back into the circulatory system. After the blood has been filtered in the nephrons of the kidney, it is collected in the renal vein. This vein then carries the filtered blood back to the inferior vena cava, which then takes the blood to the heart for re-oxygenation and distribution to the rest of the body. The other options are incorrect because the hepatic portal vein carries blood from the gastrointestinal tract to the liver, the renal artery carries unfiltered blood to the kidney, and the pulmonary vein carries oxygenated blood from the lungs to the heart.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>15", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "The early removal of the pituary gland in animals may cause", "images": [], "options": {"A": "ceasation of growth", "B": "gigantism", "C": "poor mental development", "D": "goitre"}, "answer": "A", "explanation": "The pituitary gland is a small pea-sized gland that plays a major role in regulating vital body functions and general wellbeing. It is referred to as the body's 'master gland' because it controls the activity of most other hormone-secreting glands. One of the hormones it produces is the growth hormone, which is essential for growth and development. If the pituitary gland is removed early in life, the production of growth hormone will cease, leading to stunted growth or cessation of growth.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>16", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "A high concentration of auxin in the root will", "images": [], "options": {"A": "inhibit growth", "B": "stimulate growth", "C": "not affect growth", "D": "cause the root to rot"}, "answer": "A", "explanation": "Auxin is a type of plant hormone that plays a crucial role in the growth and behavior of plants. It is primarily involved in cell elongation, but its effects can vary depending on the concentration and location within the plant. In the roots, a high concentration of auxin inhibits growth, while a low concentration promotes it. This is because auxin concentration in the root is inversely proportional to the rate of cell division and elongation. Therefore, a high concentration of auxin in the root will inhibit growth.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>17", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "The part labelled II in the diagram is the", "images": ["Biology/imgs/1997/CYKRCL.jpg"], "options": {"A": "central canal", "B": "grey matter", "C": "spinal cord", "D": "dorsal root"}, "answer": "B", "explanation": "Grey matter: This is the butterfly-shaped area in the center of the spinal cord.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>18", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "Which of the labelled parts is filled with cerebrospinal fluid?", "images": ["Biology/imgs/1997/spine.png"], "options": {"A": "V and I", "B": "I only", "C": "III only", "D": "II and I"}, "answer": "B", "explanation": "Cerebrospinal Fluid (CSF): The CSF primarily fills the central canal of the spinal cord and the subarachnoid space surrounding the brain and spinal cord.  Correct Identifications: I (Central canal): Filled with cerebrospinal fluid.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>19", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "Which of the following is an example of a reflex action?", "images": [], "options": {"A": "Sneezing", "B": "Biting", "C": "Dancing", "D": "Singing"}, "answer": "A", "explanation": "A reflex action is an involuntary and nearly instantaneous movement in response to a stimulus. Sneezing is a reflex action because it is an automatic response of the body to foreign particles in the nose. Biting, dancing, and singing are not reflex actions because they are voluntary actions that are under conscious control.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>20", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "During mating, the male toad holds the female with its?", "images": [], "options": {"A": "sticky tongue", "B": "jelly", "C": "webbed hind limbs", "D": "nuptial pad"}, "answer": "D", "explanation": "During mating, the male toad holds the female with its nuptial pad. The nuptial pad is a gland. It is a secondary sex characteristic. The male animals use the nuptual pad to hold on to females when they mate, but it does not make or move sperm itself.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>21", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The diagram above represents a?", "images": ["Biology/imgs/1997/grain.png"], "options": {"A": "germinating seed", "B": "radicle", "C": "shoot showing negative phototropism", "D": "germinating pollen grain"}, "answer": "D", "explanation": "The diagram above represents a germinating pollen grain. The germination of pollen grains begins by absorption of water and nutrients and the pollen grain produces a tiny pollen tube through the style to the ovary. The tube cell enlarges and comes out of the pollen grain through one of the germ pores to form a pollen tube.The tube nucleus descends to the tip of the pollen tube.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>22", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The part labelled I in the diagram is the", "images": ["Biology/imgs/1997/grain.png"], "options": {"A": "cytoplasm", "B": "pollen nucleus", "C": "pollen tube", "D": "exine"}, "answer": "D", "explanation": "The part labelled I in the diagram, which is the outermost layer of the pollen grain, must be the exine.  Cytoplasm: This is the gel-like substance within the cell membrane that contains all organelles and cell parts. It is not a structure that forms a distinct outer layer.  Pollen nucleus: This is located inside the pollen grain and is involved in fertilization. It is not a structural component seen from the outside.  Pollen tube: This is a structure that forms during the germination of pollen and grows towards the ovule for fertilization. It is not visible in a simple diagram of a pollen grain before germination.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>23", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following fruits is a schizocarp?", "images": [], "options": {"A": "Groundnut", "B": "Desmodium", "C": "crotalaria", "D": "Cashew"}, "answer": "B", "explanation": "A schizocarp is a type of dry fruit that splits into two or more parts (called mericarps) at maturity, but the parts remain attached to each other. Desmodium is a type of plant that produces schizocarp fruits. Groundnut, crotalaria, and cashew do not produce schizocarp fruits.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>24", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following is not a characteristic of wind dispersed fruits and seeds?", "images": [], "options": {"A": "Light weight", "B": "Wing", "C": "Floss", "D": "Stickyjuice"}, "answer": "D", "explanation": "Wind dispersed fruits and seeds have certain characteristics that enable them to be carried by the wind. These include being lightweight, having wings or other structures to catch the wind (like floss), and being dry. Sticky juice is not a characteristic of wind dispersed fruits and seeds because it would make them heavier and stick to surfaces, preventing them from being carried by the wind. Therefore, the correct answer is 'Sticky juice'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>25", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "Which of the following structures transports water from the roots to the leaves?", "images": [], "options": {"A": "Phloem", "B": "Cambium", "C": "Pericycle", "D": "Xylem"}, "answer": "D", "explanation": "The structure that transports water from the roots to the leaves is the Xylem. Xylem is one of the two types of transport tissue in vascular plants, phloem being the other. The basic function of xylem is to transport water from roots to stems and leaves, but it also transports nutrients. Phloem, on the other hand, is the living tissue that transports the soluble organic compounds made during photosynthesis and known as photosynthates, in particular, sugar, from leaves where they are produced by photosynthesis to rest of the plant. Cambium is a type of plant tissue located between the xylem and the phloem in the stem and root of a vascular plant, and is the part of the plant where growth takes place. Pericycle is a thin layer of plant tissue between the endodermis and the phloem and is responsible for the production of lateral roots.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>26", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The eye defect represented in the diagram is?", "images": ["Biology/imgs/1997/defect.png"], "options": {"A": "myopia", "B": "hypermetropia", "C": "presbyopia", "D": "astigmatism"}, "answer": "A", "explanation": "Nearsightedness (myopia) is a common vision condition in which near objects appear clear, but objects farther away look blurry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>27", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The above defect is corrected by using a?", "images": ["Biology/imgs/1997/defect.png"], "options": {"A": "concave lens", "B": "converging lens", "C": "cylindrical lens", "D": "bi-focal lens"}, "answer": "A", "explanation": "They are concave-shaped and help the eyes focus light properly.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>28", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "Which of the following organisms is viviparous?", "images": [], "options": {"A": "Tapeworm", "B": "Snail", "C": "Sheep", "D": "Grasshopper"}, "answer": "C", "explanation": "Viviparous organisms are those that give birth to live young ones instead of laying eggs. Among the options provided, only sheep fall under this category. Tapeworms, snails, and grasshoppers are all oviparous, meaning they lay eggs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>29", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : NITROGEN CYCLE", "question": "The reduction of nitrates to gaseous nitrogen is", "images": [], "options": {"A": "nitrogen fixing", "B": "nitrogen cycle", "C": "ammonification", "D": "denitrification"}, "answer": "D", "explanation": "The reduction of nitrates to gaseous nitrogen is denitrification. Denitrification is the process that converts nitrate to nitrogen gas, thus removing bioavailable nitrogen and returning it to the atmosphere.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>30", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS", "question": "The association between protozoa and termites is an example of", "images": [], "options": {"A": "symbiosis", "B": "parasitism", "C": "predation", "D": "saprophytism"}, "answer": "A", "explanation": "The association between protozoa and termites is an example of symbiosis. A symbiosis is an evolved interaction or close living relationship between organisms from different species, usually with benefits to one or both of the individuals involved.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>31", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "Flatworms are classified as", "images": [], "options": {"A": "Platyhelminthes", "B": "coelenlerata", "C": "annelida", "D": "nematoda"}, "answer": "A", "explanation": "Flatworms are classified as Platyhelminthes. The phylum Platyhelminthes consists of simple worm-like animals called flatworms. Platyhelminthes have the following important characteristics: They are triploblastic, acoelomate, and bilaterally symmetrical.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>32", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "The essential parts of a flower are", "images": [], "options": {"A": "petals and sepals", "B": "anther and filament", "C": "stigma and style", "D": "androecium and gynoecium"}, "answer": "D", "explanation": "The essential parts of a flower are androecium and gynoecium. Androecium and gynoecium are the two, opposite reproductive organs of the flower, the sexual reproductive structures in angiosperms. Androecium is also called stamens, which comprises of anther and filaments while gynoecium is also called the pistil or carpel, which comprises of stigma, style, and ovary.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>33", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which of the following parts of the tooth is first damaged during dental decay?", "images": [], "options": {"A": "Cement", "B": "Enamel", "C": "Dentine", "D": "Root"}, "answer": "B", "explanation": "Tooth decay begins when bacteria in your mouth make acids that attack the tooth's surface (enamel). This can lead to a small hole in a tooth, called a cavity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>34", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "The set- up above is used to demonstrate", "images": ["Biology/imgs/1997/set.png"], "options": {"A": "plasmolysis", "B": "osmosis", "C": "suction pressure", "D": "fermentation"}, "answer": "D", "explanation": "Fermentation: Fermentation involves the conversion of sugars into alcohol or acids by microorganisms like yeast. Test tube A contains 5% sucrose solution and yeast, which are ideal conditions for fermentation. The yeast will metabolize the sugars in the sucrose solution and produce carbon dioxide gas and alcohol (in the case of yeast fermentation).    Given the description that test tube A contains yeast and a sugar solution (5% sucrose), this is indeed indicative of a setup used to demonstrate fermentation", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>35", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : MICROORGANISMS: MAN AND HIS HEALTH.", "question": "What will be the colour of the solution in the test tube labelled II at the end of the experiment?", "images": ["Biology/imgs/1997/set.png"], "options": {"A": "Pink", "B": "Yellow", "C": "Milky", "D": "Reddish white"}, "answer": "C", "explanation": "At the end of the experiment, the solution in test tube II (the lime water) will turn milky or cloudy due to the presence of carbon dioxide gas produced during fermentation in test tube A    The other options are not correct:  Pink: There is no indication that the solution will turn pink.  Yellow: Lime water is normally colorless, and the reaction with carbon dioxide does not produce a yellow color.  Reddish white: This color change is not associated with the reaction between carbon dioxide and lime water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>36", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : MICROORGANISMS: MAN AND HIS HEALTH.", "question": "Which gas will pass into the test tube labelled II from I?", "images": ["Biology/imgs/1997/set.png"], "options": {"A": "Carbon monoxide", "B": "Carbon dioxide", "C": "Oxygen", "D": "Ammonia"}, "answer": "B", "explanation": "The experiment is designed to demonstrate fermentation, which produces carbon dioxide gas as a byproduct. The carbon dioxide gas produced in test tube A (where the yeast is fermenting the sucrose) will pass through the U-tube and into test tube II (containing lime water).    Carbon monoxide: This gas is not produced during fermentation.    Oxygen: While oxygen may be present in the air, it is not the gas produced during fermentation that passes into test tube II.    Ammonia: This gas is not produced during fermentation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>37", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "In which of these forms is carbohydrate stored in yam?", "images": [], "options": {"A": "Glucose", "B": "Maltose", "C": "Starch", "D": "Glycogen"}, "answer": "C", "explanation": "Carbohydrates in yams are stored in the form of starch. Starch is a polysaccharide carbohydrate consisting of a large number of glucose units joined together by glycosidic bonds. This polysaccharide is produced by most green plants as energy storage. It is the most common carbohydrate in human diets and is contained in large amounts in staple foods like potatoes, wheat, maize (corn), rice, and cassava.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>38", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "Northern Guinea savanna is associated with", "images": [], "options": {"A": "abundant rainfall", "B": "abundant trees and shrubs", "C": "soil with very little plant cover", "D": "abundant grasses"}, "answer": "D", "explanation": "Northern Guinea savanna is associated with abundant grasses. The Guinea savanna is a type of grassland with scattered trees and shrubs, which can be found between the rain forest and desert. The vegetation of the Guinea savanna is interspersed with trees such as baobabs and acacias, and grasses and herbs are abundant. The grasses found in the savanna are tall and coarse and are interspersed with areas of woodland and tall vegetation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>39", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING", "question": "Which of the following activities is not necessary in population sampling?", "images": [], "options": {"A": "Selecting the habitat", "B": "Dividing the selected habitat into portions", "C": "Throwing the quadrat randomly", "D": "Feeding the organisms"}, "answer": "D", "explanation": "Population sampling is a method used in ecology to measure the abundance and distribution of a particular species within a specified area. The process involves selecting the habitat, dividing the selected habitat into portions, and throwing the quadrat randomly. However, feeding the organisms is not a necessary activity in population sampling. It does not contribute to the measurement of the species' abundance or distribution.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>40", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Which of the following is an abiotic factor?", "images": [], "options": {"A": "Predation", "B": "Rainfall", "C": "Cropping", "D": "Grazing"}, "answer": "B", "explanation": "Abiotic factors are non-living physical and chemical elements in the ecosystem. They can influence living organisms in terms of growth, development, and distribution. Examples of abiotic factors include sunlight, temperature, wind, water, soil, and rainfall. Therefore, rainfall is an abiotic factor. Predation, cropping, and grazing are biotic factors as they involve interactions between living organisms.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>41", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS", "question": "The maximum and minimum thermometer is used to measure", "images": [], "options": {"A": "light intensity", "B": "highest and lowest temperature of the day", "C": "atmospheric pressure", "D": "highest and lowest amount of rainfall in a month"}, "answer": "B", "explanation": "A maximum and minimum thermometer, also known as a Six's thermometer, is a thermometer which registers the maximum and minimum temperatures reached over a period of time, typically 24 hours. It is used to record the extremes of temperature at a location, for instance in meteorology and horticulture. It is not used to measure light intensity, atmospheric pressure or rainfall.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>42", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Which of the following organisms will have the highest biomass?", "images": [], "options": {"A": "Small fish", "B": "Tadpole", "C": "Hawk", "D": "Phytoplankton"}, "answer": "D", "explanation": "In an ecological pyramid, biomass decreases as we move from the producers to the top carnivores. Phytoplankton, being the primary producers in aquatic ecosystems, have the highest biomass. Hawks, being top carnivores, have the least biomass. Small fish and tadpoles, being in the middle of the food chain, have less biomass than phytoplankton but more than hawks.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>43", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "Which of the following is the correct sequence for energy transfer and nutrient cycling among living things in an ecosystem?", "images": [], "options": {"A": "Consumers → producers → decomposers", "B": "Producers → decomposers → consumers", "C": "Decomposers → producers → consumers", "D": "Producers → consumers → decomposers"}, "answer": "D", "explanation": "In an ecosystem, the energy transfer and nutrient cycling among living things follow the sequence: Producers → consumers → decomposers. Producers, such as plants, produce their own food through photosynthesis. Consumers, such as animals, consume the producers for energy. Decomposers, such as fungi and bacteria, break down dead or decaying organisms, returning nutrients back to the environment for use by producers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>44", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Which of the following factors does not affect the distribution of organisms in an aquatic habitat?", "images": [], "options": {"A": "Turbidity", "B": "Depth of water", "C": "Humidity", "D": "Temperature"}, "answer": "C", "explanation": "Humidity does not affect the distribution of organisms in an aquatic habitat. Humidity refers to the amount of water vapor in the air, which is more relevant to terrestrial habitats. In contrast, factors like turbidity (cloudiness of the water), depth of water, and temperature can significantly influence the types of organisms that can survive in an aquatic habitat.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>45", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "A habitat with low rainfall, very low humidity, exposed soil with little plant cover, few trees and shrubs is likely to be", "images": [], "options": {"A": "a rain forest", "B": "a mangrove forest", "C": "a desert", "D": "a swamp"}, "answer": "C", "explanation": "A habitat with low rainfall, very low humidity, exposed soil with little plant cover, few trees and shrubs is likely to be a desert. Deserts are characterized by extremely low rainfall, low humidity, and sparse vegetation due to the harsh climatic conditions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>46", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION", "question": "Which of the following factors may not cause over-crowding?", "images": [], "options": {"A": "Limited space", "B": "Scarcity of food", "C": "Reduced birth rate", "D": "Lose immigration conditions"}, "answer": "C", "explanation": "Overcrowding is typically caused by factors that increase the population density in a given area. These factors can include limited space, scarcity of food, and loose immigration conditions, which can all lead to an increase in the number of individuals in a given area. However, a reduced birth rate would not cause overcrowding. In fact, it would likely alleviate overcrowding, as fewer individuals are being added to the population.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>47", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Crops grown mainly to feed animals are called", "images": [], "options": {"A": "forage crops", "B": "fibre crops", "C": "wood crops", "D": "oil crops"}, "answer": "A", "explanation": "Crops grown mainly to feed animals are called forage crops. Forage crops are crops on which animals graze independently – they are grown specifically to be grazed by livestock or conserved as hay or silage.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>48", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE", "question": "The farming practice by which an exhausted farm land is left for a number of years before cultivation is known as", "images": [], "options": {"A": "crop rotation", "B": "continuous cropping", "C": "monocropping", "D": "bush fallowing"}, "answer": "D", "explanation": "Bush fallowing is a farming method, where a piece of land is cultivated for several years and left to fallow or rest of some years to allow it regain its fertility.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>49", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION", "question": "In palm-wine, yeast acts as a", "images": [], "options": {"A": "carrier", "B": "culturing agent", "C": "preservative", "D": "catalyst"}, "answer": "D", "explanation": "A catalyst is a substance that speeds up a chemical reaction without undergoing any permanent change itself.Yeast population, among other organisms, have been found to vary in palm wine depending on the source. The yeasts quantitatively convert the sugars in the palm wine into alcohol. Hence, the physicochemical condition of palm wine is a function of the metabolic activities of the inherent yeasts in palm wine.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>50", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT", "question": "Which of the following farm practices can cause loss of soil fertility?", "images": [], "options": {"A": "Mulching", "B": "Compost application", "C": "Use of fertilizers", "D": "intensive cropping"}, "answer": "D", "explanation": "Intensive cropping can cause loss of soil fertility. Intensive cropping, also known as intensive agriculture, is a type of agricultural practice where a lot of labor and capital are used to increase the yield or output from a given area of land. This practice often involves the use of high amounts of fertilizers and pesticides, which can lead to soil degradation and loss of soil fertility over time. The other options like mulching, compost application, and use of fertilizers are practices that improve soil fertility.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>51", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "APPLICATION OF VARIATIONS :", "question": "One of the use of variation is in", "images": [], "options": {"A": "determining the size and weight of an individual", "B": "determining paternity", "C": "conservation of wildlife", "D": "controlling of disease vector"}, "answer": "B", "explanation": "Variation is a fundamental aspect of life because it results in the differences between individuals of the same species. It can be used in determining paternity. This is because children inherit genes from their parents, so the genetic information in an individual can be used to confirm or disprove that the individual is the biological parent of a child.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>52", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "In which of the underlisted blood groupings is agglutination likely to occur during transfusion?  DONORRECEPIENTI toto TATAII TBTOTBTBIII TATATATB IV TATB totoV toto TBTB", "images": [], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "D", "explanation": "Agglutination, or clumping of cells, is likely to occur during a blood transfusion if the recipient's immune system recognizes the donor blood as foreign. This usually happens if the recipient has antibodies against the donor's blood type. In the given options, agglutination is likely to occur in option IV where the donor has blood type AB (TATB) and the recipient has blood type O (toto). This is because individuals with blood type O have both anti-A and anti-B antibodies, which will react with the A and B antigens on the red blood cells of the donor blood, causing agglutination.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>1997>53", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Which of the following is not a morphological variation", "images": [], "options": {"A": "Shape of nose", "B": "Colour of skin", "C": "Colour of eyes", "D": "Tongue rolling"}, "answer": "D", "explanation": "Morphological variations refer to the observable physical differences between individuals of a species. These differences can be in size, shape, color, structure, etc. However, tongue rolling is not a morphological variation. It is a genetic trait that is inherited and does not affect the physical appearance of an individual.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>54", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "Which of the following is found in Meiosis but not in Mitosis?", "images": [], "options": {"A": "Chromatids", "B": "Prophase", "C": "Crossing over", "D": "Spindle fibres"}, "answer": "C", "explanation": "Meiosis and Mitosis are two types of cell division. The main difference between them is that Meiosis involves two rounds of genetic separation and cellular division while Mitosis only involves one of each. In the process of Meiosis, crossing over occurs during Prophase I, where homologous chromosomes pair up and exchange segments of their genetic material. This does not occur in Mitosis, hence the correct answer is 'Crossing over'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>55", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : LINKAGE, SEX DETERMINATION AND SEX LINKED CHARACTERS", "question": "In man haemophilia is recessive and sex linked, The probability of carrier mother and a normal father having a haemophilic male is", "images": [], "options": {"A": "1/4", "B": "1/8", "C": "2/3", "D": "1/2"}, "answer": "D", "explanation": "Mother is a carrier(AS) and father is normal (AA) during test crossing the outcome are (AA,AA,AS,and AS) Probability=number of carrirer child divide by total outcome, i.e 2/4=1/2", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>56", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY", "question": "In which of the following is the knowledge of genetics not applicable?", "images": [], "options": {"A": "Development of high-yielding varieties", "B": "Preservation of seeds", "C": "Development of early maturing varieties", "D": "Improvement in quality of yield"}, "answer": "B", "explanation": "Genetics is the study of genes, genetic variation, and heredity in living organisms. It is generally considered a field of biology, but intersects frequently with many other life sciences and is strongly linked with the study of information systems. The knowledge of genetics is applicable in the development of high-yielding varieties, development of early maturing varieties, and improvement in quality of yield as these all involve manipulation and understanding of genetic material. However, the preservation of seeds does not require the knowledge of genetics. It is more related to the field of botany and environmental science.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>57", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS", "question": "In an inter-species competition, the less successful species usually", "images": [], "options": {"A": "reproduce faster", "B": "become more active", "C": "become domant", "D": "become eliminated"}, "answer": "D", "explanation": "In an inter-species competition, the less successful species usually become eliminated. This is due to the principle of competitive exclusion, which states that two species competing for the same resources cannot coexist if other ecological factors are constant. When one species has even the slightest advantage over another, the one with the advantage will dominate in the long term. This leads to the extinction of the less successful species.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1997>58", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following characteristics distinguishes the soldier termite from other members of the caste?", "images": [], "options": {"A": "Wingless, strong mandibles and large head", "B": "Small head, small thorax and large abdomen", "C": "Small head, Wingless, and small thorax", "D": "Small head, winged and small thorax"}, "answer": "A", "explanation": "The soldier termite is distinguished from other members of the caste by its wingless nature, strong mandibles, and large head. These characteristics enable it to perform its primary role of colony defense. The strong mandibles are used for fighting off predators, the large head houses the muscles that power the mandibles, and being wingless is a common trait among all termites except reproductive ones.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>59", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Bees communicate with one another to obtain information about the direction of food source through", "images": [], "options": {"A": "complicated set of dances", "B": "smell", "C": "contract notes", "D": "observation"}, "answer": "A", "explanation": "Bees communicate with each other about the location of food sources through a series of movements known as the 'waggle dance'. This dance involves a combination of circles and straight runs, with the bee 'waggling' its body during the straight runs. The direction of the straight run indicates the direction of the food source relative to the sun, while the duration of the waggle indicates the distance to the food source. Therefore, the correct answer is 'complicated set of dances'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1997>60", "subject": "Biology", "year": "1997", "type": "Objective", "topic": "EVOLUTION : ADAPTIVE COLOURATION", "question": "Which of the following behavioural patterns describes adaptive colouration?", "images": [], "options": {"A": "Counter shadding", "B": "Hibernation", "C": "Aestivation", "D": "Aggregation"}, "answer": "A", "explanation": "Adaptive coloration is a type of camouflage where an organism's coloration allows it to blend in with its environment, making it harder for predators to see. Counter shading is a form of adaptive coloration where the upper side of an animal is darker than its underside. This helps to create an illusion of flatness, which can make the animal harder to detect in its environment. Therefore, the correct answer is 'Counter shading'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>1", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "Which of the following organisms exhibits both plant and animal characteristics?", "images": [], "options": {"A": "Amoeba", "B": "Spirogyra", "C": "Mucor", "D": "Euglena"}, "answer": "D", "explanation": "Euglena, genus of more than 1,000 species of single-celled flagellated (i.e., having a whiplike appendage) microorganisms that feature both plant and animal characteristics.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>2", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "Which of the following is not an organ?", "images": [], "options": {"A": "Hair", "B": "Tongue", "C": "Rhizome", "D": "Corn"}, "answer": "A", "explanation": "An organ is a group of tissues that perform a specific function or group of functions. Hair is not an organ but rather a part of the integumentary system that includes the skin, hair, nails, and exocrine glands. Hair is made of a tough protein called keratin and has various functions such as protection, regulation of body temperature, and facilitation of evaporation of perspiration. On the other hand, the tongue, rhizome, and corn are all considered organs because they are composed of different types of tissues and perform specific functions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>3", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "One major difference between osmosis and diffusion is that diffusion", "images": [], "options": {"A": "does not need a semipermeable membrane", "B": "does not take place in living tissues", "C": "takes place only in a liquid medium", "D": "takes place only in a gaseous medium"}, "answer": "A", "explanation": "Diffusion is the movement of molecules from an area of higher concentration to an area of lower concentration. It does not require a semipermeable membrane to occur. On the other hand, osmosis is a special type of diffusion that involves the movement of water molecules across a semipermeable membrane from an area of lower solute concentration to an area of higher solute concentration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>4", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "Which of the following is a difference between mitosis and meiosis?", "images": [], "options": {"A": "Alignment of chromosomes along the equitorial plane", "B": "Replication of the chromosomes and the cell organelles", "C": "Pairing of homologous chromosomes", "D": "Formation of spindle fibers"}, "answer": "C", "explanation": "Differences between Mitosis and Meiosis: Pairing of homologous chromosomes (C): This is a key difference between mitosis and meiosis. During meiosis, homologous chromosomes (pairs of similar chromosomes from each parent) pair up in a process called synapsis during Prophase I. This pairing allows for crossing over, where genetic material is exchanged between homologous chromosomes, leading to genetic diversity. In mitosis, homologous chromosomes do not pair up; instead, each chromosome lines up individually along the metaphase plate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>5", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "Which of the following can be used for vegetative propagation?", "images": [], "options": {"A": "Ginger stem", "B": "Yam leaf", "C": "Plantain roots", "D": "Sweet potato tuber"}, "answer": "A", "explanation": "Ginger stem can be used for vegetative propagation. Ginger is one of the most popular spices in the world and comes from the underground stem of the ginger plant.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>6", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "Which of the following is a method of artificial vegetative propagation?", "images": [], "options": {"A": "Creeping stem", "B": "Layering", "C": "Corm", "D": "Rhizome"}, "answer": "B", "explanation": "Artificial methods of vegetative propagation include cutting, layering, grafting, and tissue culture. All these structures grow naturally. The seed is always produced sexually and thus propagation via seeds is not a method of vegetative propagation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>7", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The above diagram represents a", "images": ["Biology/imgs/1998/internal.png"], "options": {"A": "longitudinal section of a stem", "B": "longitudinal section of a root", "C": "cross section of a root", "D": "transverse section of stem"}, "answer": "C", "explanation": "The above diagram represents a cross section of a root. This is because the  -\tCortex (II): The layer just beneath the epidermis, involved in storage and transport.  -\tEndodermis (III): A distinctive single layer of cells separating the cortex from the vascular tissues, often with a Casparian strip, unique to roots.  -\tXylem and Phloem (IV): The arrangement of vascular tissues in a central column, typical of roots  -\tPericycle (V): Found just inside the endodermis, responsible for the formation of lateral roots.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>1998>8", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The part labelled II in the diagram is the", "images": ["Biology/imgs/1998/internal.png"], "options": {"A": "epidermis", "B": "cortex", "C": "phloem", "D": "xylem"}, "answer": "B", "explanation": "The part labelled II in the diagram is the cortex. The epidermis is the outermost layer of cells, labeled I in the diagram.  The cortex is the layer beneath the epidermis, consisting of multiple cells that store food and aid in the transport of water and nutrients.  The phloem and xylem are part of the vascular tissue, typically located in the central region of the root, which are not labeled as II.  The cuticle is a protective, waxy layer covering the epidermis, but it is not the same as the cortex.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>1998>9", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The part labelled IV in the diagram is the", "images": ["Biology/imgs/1998/internal.png"], "options": {"A": "phloem", "B": "pericycle", "C": "cortex", "D": "xylem"}, "answer": "D", "explanation": "The part labelled IV in the diagram is the xylem. The part labeled IV shows the central, star-shaped structure typical of xylem in a root cross-section.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>1998>10", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which of the following is not a function of the blood?", "images": [], "options": {"A": "Maintenance of body temperature", "B": "Formation of clot", "C": "Distribution of bile", "D": "Transportation of excretory materials."}, "answer": "C", "explanation": "The function of blood includes maintenance of body temperature, formation of clot, and transportation of excretory materials. However, the distribution of bile is not a function of the blood. Bile is produced by the liver and stored in the gallbladder. It is then released into the small intestine to aid in the digestion of fats.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>11", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "Which of the following statements about the circulation of blood is not correct?", "images": [], "options": {"A": "Deoxygenated blood flows in the heart through the vena cava", "B": "Blood is pumped out of the heart through the aorta", "C": "Oxygenated blood from the lung; is carried to the left auricle", "D": "The oxygenated blood enters the lungs through the pulmonary vein"}, "answer": "D", "explanation": "The statement 'The oxygenated blood enters the lungs through the pulmonary vein' is incorrect. The pulmonary vein carries oxygenated blood from the lungs to the left atrium of the heart, not into the lungs. The other options correctly describe the circulation of blood.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>12", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "A difference between the auricle and the ventricle of the mammalian heart is that the", "images": [], "options": {"A": "ventricles carry deoxygenated blood", "B": "ventricles do not have outlets", "C": "auricles have no valves", "D": "Walls of the ventricles are more muscular than that of the auricles"}, "answer": "D", "explanation": "A difference between the auricle and the ventricle of the mammalian heart is that the Walls of the ventricles are more muscular than that of the auricles. Walls of the ventricles are more muscular than that of the auricles: This is correct. The ventricles have thicker, more muscular walls because they need to pump blood to the entire body (left ventricle) or to the lungs (right ventricle), requiring more force compared to the auricles, which only need to pump blood into the ventricles.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>13", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Which of the following organism respires through the body surface", "images": [], "options": {"A": "Man", "B": "Fish", "C": "Tridax", "D": "Amoeba"}, "answer": "D", "explanation": "Amoeba respires through its body surface. This is because it is a single-celled organism and does not have specialized respiratory organs like lungs or gills. Instead, gases simply diffuse in and out of the cell across the cell membrane.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>14", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "The stomata of a leaf performs the same function as", "images": [], "options": {"A": "spiracles of insects", "B": "trachea of toads", "C": "pharynx of man", "D": "liver of man"}, "answer": "A", "explanation": "The stomata of a leaf performs the same function as spiracles of insects. Spiracles are respiratory openings found on the thorax and abdomen of insects. The spiracles are connected to trachea - tubes within the insect's body. Air enters the trachea via the spiracles and the oxygen then diffuses into the insect's body.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>15", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Which of the following does not happen during inspiration?", "images": [], "options": {"A": "intercostal muscles contract", "B": "Ribs move forward", "C": "Thoracic cavity increases", "D": "Diaphragm relaxes"}, "answer": "D", "explanation": "During inspiration (inhalation), the diaphragm and intercostal muscles contract. This contraction causes the diaphragm to flatten and the rib cage to expand, increasing the volume of the thoracic cavity. As a result, air is drawn into the lungs. Therefore, the statement 'Diaphragm relaxes' does not happen during inspiration, making it the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>16", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which of the these is not an excretory product of plant?", "images": [], "options": {"A": "Tannin", "B": "Gum", "C": "Alkaloid", "D": "Sweat"}, "answer": "D", "explanation": "Plants do not have sweat glands, so they do not produce sweat. Sweat is a product of animal excretion, not plant excretion. Tannin, Gum, and Alkaloids are all excretory products of plants.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>17", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which of these is not a function of the kidney?", "images": [], "options": {"A": "Production of urine", "B": "Maintenance of acid-base balance in the body", "C": "Osmo-regulation", "D": "Production of bile"}, "answer": "D", "explanation": "The kidney is responsible for the production of urine, maintenance of acid-base balance in the body, and osmo-regulation. However, the production of bile is a function of the liver, not the kidney.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>18", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "In which part of the kidney does ultrafiltration take place?", "images": [], "options": {"A": "Bowman's capsule", "B": "Distal convoluted tubule", "C": "Proximal convoluted tubule", "D": "Collecting duct"}, "answer": "A", "explanation": "Ultrafiltration in the kidney takes place in the Bowman's capsule. The Bowman's capsule is the initial part of the nephron in the kidney where blood is first filtered to form urine. The high pressure forces small molecules such as water, glucose, amino acids, urea and ions through the filter, from the blood in the glomerulus into the Bowman's capsule.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>19", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which of the following organs is concerned with detoxication of harmful compounds?", "images": [], "options": {"A": "Kidney", "B": "Lungs", "C": "Gall bladder", "D": "Liver"}, "answer": "D", "explanation": "Detoxification pathways in the liver The liver plays an important rôle in protecting the organism from potentially toxic chemical insults through its capacity to convert lipophiles into more water-soluble metabolites which can be efficiently eliminated from the body via the urine.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>20", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "The hormone that promotes secondary sexual characteristics in females is", "images": [], "options": {"A": "insulin", "B": "thyroxin", "C": "testosterone", "D": "oestrogen"}, "answer": "D", "explanation": "The hormone that promotes secondary sexual characteristics in females is oestrogen. Secondary sexual characteristics are features that distinguish the two sexes of a species, but that are not directly part of the reproductive system. In females, these characteristics include the development of breasts, widening of hips, and the growth of body hair. Oestrogen is the primary female sex hormone responsible for the development and regulation of the female reproductive system and secondary sex characteristics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>21", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The cell body in the diagram labelled", "images": ["Biology/imgs/1998/dendrite.png"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "A", "explanation": "Label I indicate the cell body (soma), which houses the nucleus and is responsible for maintaining the cell and integrating synaptic signals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>22", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The function of the part labelled II in the diagram is to", "images": ["Biology/imgs/1998/dendrite.png"], "options": {"A": "transmit impulse from one end of the cell to the other", "B": "manufacture food for the cell", "C": "protect the axon", "D": "produce energy for the cell"}, "answer": "C", "explanation": "The function of the part labelled II in the diagram is to protect the axon.In a neuron, the part labeled II is likely the myelin sheath. The myelin sheath's main function is to insulate the axon and increase the speed at which electrical impulses (action potentials) travel along the axon.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>23", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The organ responsible for equalising air pressure in the ear is the", "images": [], "options": {"A": "sacculus", "B": "utriculus", "C": "Eustachian tube", "D": "ampulla"}, "answer": "C", "explanation": "The Eustachian tube is the organ responsible for equalising air pressure in the ear. It is a small canal that connects the middle ear to the nasopharynx, which consists of the upper throat and the back of the nasal cavity. It controls the pressure within the middle ear, making it equal with the air pressure outside the body. None of the other options (sacculus, utriculus, ampulla) perform this function.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>24", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "Which of the following organisms lacks a reproductive organ?", "images": [], "options": {"A": "Chlamydomonas", "B": "Toad", "C": "Pride of Barbados", "D": "Cockroach"}, "answer": "A", "explanation": "Chlamydomonas lacks a reproductive organ. Chlamydomonas: This is a genus of green algae, which are single-celled organisms. They do not have specialized reproductive organs. Instead, they reproduce asexually by cell division or sexually by the fusion of gametes that are not part of specialized organs.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>25", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "Which of the following mammalian features acts as a shock-absorber to the developing embryo?", "images": [], "options": {"A": "Amniotic fluid", "B": "Umbilical cord", "C": "Placenta", "D": "Amnion"}, "answer": "A", "explanation": "The amniotic fluid acts as a shock-absorber to the developing embryo. It is a clear, yellow fluid which is present in the amniotic sac. Its primary role is to provide a cushioning environment for the embryo, protecting it from physical shocks and impacts. The other options, umbilical cord, placenta, and amnion, have different roles in embryonic development. The umbilical cord connects the embryo to the placenta, allowing for the exchange of nutrients and waste. The placenta is an organ that connects the developing fetus to the uterine wall to allow nutrient uptake, waste elimination, and gas exchange. The amnion is a membrane that closely covers the embryo, forming a protective sac around it along with the amniotic fluid.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>26", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The collective name for the female parts of the flower is", "images": [], "options": {"A": "gynoecium", "B": "androecium", "C": "ovary", "D": "stigma"}, "answer": "A", "explanation": "The collective name for the female parts of a flower is 'gynoecium'. The gynoecium is the group of structures that form the female reproductive organ in flowers. It is typically composed of one or more carpels. The carpel is the individual unit of the gynoecium and has a stigma, style, and ovary.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>27", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "If the petals of a flowering plant are removed. Which of the following processes is likely to be affected?", "images": [], "options": {"A": "Transpiration", "B": "Pollination", "C": "Germination", "D": "Photosynthesis"}, "answer": "B", "explanation": "If the petals of a flowering plant are removed, the process likely to be affected is 'pollination'. Petals often play a key role in attracting pollinators to the flower. Without petals, pollinators may not be attracted to the flower, which can affect the process of pollination. Pollination is the transfer of pollen from the anther (male part) to the stigma (female part) of the same or a different flower.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>28", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The part labelled II in the diagram is the", "images": ["Biology/imgs/1998/2PX63X.jpg"], "options": {"A": "plumule", "B": "endosperm", "C": "radicle", "D": "coleorhiza"}, "answer": "B", "explanation": "The diagram shows a monocot seed, likely a maize seed, with various parts labeled.   So, the part labeled II is the endosperm, which is the tissue that provides nutrition to the developing embryo.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>29", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The part labelled IV in the diagram is the", "images": ["Biology/imgs/1998/endo.png"], "options": {"A": "plumule", "B": "endosperm", "C": "radicle", "D": "coleoptile"}, "answer": "C", "explanation": "Given the labeling in the diagram, the labeled part is the Radicle. The radical is part of the embryo that will develop into the root.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>30", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The function of the part labelled V in the diagram is the", "images": ["Biology/imgs/1998/endo.png"], "options": {"A": "manufacture of food", "B": "storage of food", "C": "secretion of digestive enzymes", "D": "protection of the radicle"}, "answer": "D", "explanation": "The function of the part labelled V in the diagram is the protection of the radicle.Given this identification, the function of the coleorhiza is to protect the radicle as it grows and emerges from the seed during germination.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>31", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following is a feature of wind pollinated flowers?", "images": [], "options": {"A": "Large and brightly coloured petals", "B": "Possession of sweet scent", "C": "Presence of nectar", "D": "Smooth, light and numerous pollen grains"}, "answer": "D", "explanation": "Wind pollinated flowers, also known as anemophilous flowers, are characterized by their production of smooth, light, and numerous pollen grains. This is because the wind needs to carry the pollen grains from the male flower to the female flower, and having light and numerous pollen grains increases the chances of successful pollination. The other options are incorrect as they are characteristics of insect-pollinated flowers. Large and brightly coloured petals, sweet scent, and presence of nectar are all adaptations to attract insects for pollination, not features of wind pollinated flowers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>32", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "In testing for starch in a leaf the function of alcohol is to", "images": [], "options": {"A": "kill the cells of the leaf", "B": "soften the veins of the leaf", "C": "aid iodine to penetrate the cells", "D": "extract the chlorophyll from the leaf"}, "answer": "D", "explanation": "Starch is a carbohydrate that consists of many glucose units attached to glycosidic bonds. When a leaf is boiled in alcohol like ethanol, it helps to extract chlorophyll and help remove the green color of the leaves.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>33", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "Which of the following processes removes CO2 from the atmosphere?", "images": [], "options": {"A": "Respiration", "B": "Photosynthesis", "C": "Transpiration", "D": "Excretion"}, "answer": "B", "explanation": "Photosynthesis is the process by which green plants and some other organisms use sunlight to synthesize foods with the help of chlorophyll pigments. During this process, plants absorb carbon dioxide (CO2) from the atmosphere and release oxygen. Therefore, photosynthesis removes CO2 from the atmosphere.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>34", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : NITROGEN CYCLE", "question": "The role of bacteria in the nitrogen cycle includes the following except", "images": [], "options": {"A": "fixing atmospheric nitrogen", "B": "converting ammonia to nitrites", "C": "converting nitrites to nitrates", "D": "converting carbohydrates to carbondioxide"}, "answer": "D", "explanation": "The role of bacteria in the nitrogen cycle includes fixing atmospheric nitrogen, converting ammonia to nitrites, and converting nitrites to nitrates. However, converting carbohydrates to carbon dioxide is not a role of bacteria in the nitrogen cycle. This process is part of the carbon cycle, not the nitrogen cycle.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>35", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "The mode of nutrition which describes feeding habit in animals is", "images": [], "options": {"A": "autotrophic", "B": "holozoic", "C": "holophytic", "D": "saprophytic"}, "answer": "B", "explanation": "Holozoic nutrition (Greek: holo-whole ; zoikos-of animals) is a type of heterotrophic nutrition that is characterized by the internalization and internal processing of liquids or solid food particles.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>36", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "Which of the following organisms has homodont dentition?", "images": [], "options": {"A": "Rabbit", "B": "Man", "C": "Sheep", "D": "Lizard"}, "answer": "D", "explanation": "Homodont dentition: in this type of dentition, the organism possesses or have the same types or sets of teeth. In this types of dentition, there are no specialized set of teeth for a particular type of function. All the teeth of a typical homodont dentition are of the same sizes, shape and functions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>37", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "The pancreatic duct opens into the", "images": [], "options": {"A": "caecum", "B": "colon", "C": "ileum", "D": "duodenum"}, "answer": "D", "explanation": "The pancreatic duct opens into the duodenum. The pancreas is an organ in the digestive system that produces important enzymes and hormones that help break down foods. The pancreatic duct is a tube that runs from the pancreas and carries the digestive enzymes produced by endocrine cells to the duodenum, which is the first part of the small intestine. Therefore, the correct answer is duodenum.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>38", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "The enzyme that acts on milk in the stomach is", "images": [], "options": {"A": "invertase", "B": "trypsin", "C": "diastase", "D": "renin"}, "answer": "D", "explanation": "Milk protein is acted upon by a gastric enzyme known as rennin which digests these milk proteins called caseinogen. It is also known as chymosin and is activated by the HCl present in the stomach where it is converted from inactive prorenin to rennin. It converts the milk protein caseinogen to casein and finally to calcium paracasein thus causing curdling.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>39", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION", "question": "Which of the following plants is a carnivore?", "images": [], "options": {"A": "Desmodium", "B": "Sundew", "C": "Mushroom", "D": "Platycerium"}, "answer": "B", "explanation": "Sundew, also known as Drosera, is a genus of carnivorous plants with at least 194 species. They grow in nutrient-poor environments and get their nutrients from insects they trap on their leaves", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>40", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : FEEDING HABITS", "question": "Hydra feeds by", "images": [], "options": {"A": "digesting its food extra cellularly", "B": "absorbing food digested by other organisms", "C": "symbiotic association", "D": "masticating the food particles"}, "answer": "A", "explanation": "Hydra is a simple multicellular organism that feeds by digesting its food extracellularly. This means that the digestion of food occurs outside the cells in the gastrovascular cavity. The cells lining the gastrovascular cavity secrete digestive enzymes that break down the food into simpler substances that can be absorbed by the cells. Therefore, the correct answer is option 1: digesting its food extracellularly.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>41", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Which of the following contains a reducing sugar?", "images": [], "options": {"A": "Milk", "B": "Cassava", "C": "rice", "D": "Beans"}, "answer": "C", "explanation": "Milk contains a significant amount of lactose, a disaccharide that is a reducing sugar. In fact, lactose is the primary carbohydrate in milk, making it a rich source of reducing sugars.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>42", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS", "question": "Which of the following instrument can be used to measure relative humidity?", "images": [], "options": {"A": "Anemometer", "B": "Hygrometer", "C": "Wind gauge", "D": "Barometer"}, "answer": "B", "explanation": "Relative humidity is the amount of moisture in the air compared to the maximum amount of moisture the air could hold at the same temperature. This is measured using a hygrometer. An anemometer measures wind speed, a wind gauge is another name for an anemometer, and a barometer measures atmospheric pressure.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>43", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "In a food chain, each stage in the chain is a", "images": [], "options": {"A": "chain level", "B": "web level", "C": "consumption level", "D": "trophic level"}, "answer": "D", "explanation": "In a food chain, each stage is referred to as a trophic level. Trophic levels represent the position an organism occupies in a food chain. It starts with producers at the first level, followed by consumers at the subsequent levels. The term 'trophic' is derived from the Greek word 'trophe', meaning food or feeding. None of the other options correctly represent the stages in a food chain.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>44", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "The diagram above illustrates", "images": ["Biology/imgs/1998/king.png"], "options": {"A": "the size of various organisms", "B": "types of organisms in a habitat", "C": "the flow of energy in a habitat", "D": "the hierarchy of organisms in a habitat"}, "answer": "C", "explanation": "The diagram above illustrates the flow of energy in a habitat. The diagram represents a pyramid structure showing different levels of organisms, with each level representing who eats whom in an ecosystem. The base starts with phytoplankton, which are producers, and it progresses up to kingfishers, which are top predators. This arrangement depicts the transfer of energy through the ecosystem.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>45", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Which of these organisms occupies the 3rd trophic  level?", "images": ["Biology/imgs/1998/king.png"], "options": {"A": "King fisher", "B": "Small fish", "C": "Phytoplankton", "D": "Big fish"}, "answer": "B", "explanation": "Small fish occupies the 3rd trophic level. In a food chain, the trophic levels are defined as follows:  -\tFirst trophic level: Producers (e.g., Phytoplankton)  -\tSecond trophic level: Primary consumers (e.g., Tadpole)  -\tThird trophic level: Secondary consumers (e.g., Small fish)  -\tFourth trophic level: Tertiary consumers (e.g., Big fish)  -\tFifth trophic level: Quaternary consumers (e.g., Kingfisher)  Based on the diagram provided, the organism occupying the third trophic level is the Small fish.  Small fish consume tadpoles, which are primary consumers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>46", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Which of these organisms is a herbivore?", "images": ["Biology/imgs/1998/king.png"], "options": {"A": "Tadpole", "B": "Phytoplankton", "C": "King Fisher", "D": "Small fish"}, "answer": "A", "explanation": "In the context of the provided food chain:  - Phytoplankton are producers (autotrophs) and not herbivores.  - Tadpoles are primary consumers that feed on phytoplankton and other plant materials, making them herbivores.  - Small fish, big fish, and kingfishers are consumers that feed on other animals, so they are not herbivores. Therefore, the correct answer is Tadpole", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>47", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : ADAPTATION OF ORGANISMS TO HABITATS.", "question": "The presence of stilt and breathing roots are features of plants found in the", "images": [], "options": {"A": "tropical rain forests", "B": "fresh water swamp forests", "C": "mangrove forests", "D": "southern guinea savanna"}, "answer": "C", "explanation": "The presence of stilt and breathing roots are characteristics of plants found in mangrove forests. Mangrove forests are found in tropical and subtropical tidal areas, and they are characterized by the presence of salt-tolerant trees and shrubs that can grow in the intertidal zone, where land and sea meet.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>48", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Excessive loss of water from the leaf is prevented by the", "images": [], "options": {"A": "vascular bundle", "B": "cuticle", "C": "midrib", "D": "parenchyma"}, "answer": "B", "explanation": "Excessive loss of water from the leaf is prevented by the cuticle. The cuticle is a waxy layer present on the surface of the leaves, stems, and other aerial parts of the plants. It is hydrophobic (water-repelling) in nature and thus prevents the loss of water from the plant surfaces by evaporation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>49", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "ECOLOGY OF POPULATION : ECOLOGICAL SUCCESSION", "question": "Which of the following organisms will be a colonizing species of a heap of moist sub soil?", "images": [], "options": {"A": "Green algae", "B": "Ferns", "C": "White mangrove", "D": "Snails"}, "answer": "A", "explanation": "A colonizing species is the first species to colonize previously disrupted or damaged ecosystems, beginning a chain of ecological succession that ultimately leads to a more biodiverse steady-state ecosystem. In the case of a heap of moist sub soil, green algae would be the first to colonize. This is because green algae are pioneer species, which are hardy species which are the first to colonize previously biodiverse steady-state ecosystems. They are capable of living in harsh conditions and can photosynthesize, which allows them to start the process of succession.  The other options are not typical colonizing species of a heap of moist subsoil:  Ferns require more complex soil and light to grow.  White mangrove is a coastal plant that requires salty water and cannot grow in subsoil.  Snails require a more developed ecosystem with vegetation and organic matter.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>50", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS", "question": "The earthworm is important because", "images": [], "options": {"A": "its body is always moist", "B": "each of its segments has chaetae", "C": "It has a clitellum", "D": "it aerates the soil"}, "answer": "D", "explanation": "The earthworm is important because it aerates the soil. This is done as the earthworm burrows through the soil, creating tunnels that allow air to penetrate. This process is crucial for the health of the soil as it promotes the circulation of oxygen, which is necessary for the survival of many soil organisms. The other options, while true characteristics of earthworms, do not explain their importance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>51", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "which of the following plant parts is not a storage organ?", "images": [], "options": {"A": "Carrot root", "B": "Sugarcane stem", "C": "Onion leaf", "D": "Banana stem"}, "answer": "C", "explanation": "Storage organs in plants are parts of the plant that store nutrients and energy for the plant to use during periods of less-than-optimal conditions. These include roots, stems, and tubers. In the given options, carrot root, sugarcane stem, and banana stem are all examples of storage organs. However, onion leaf is not a storage organ. The onion bulb, not the leaf, is the storage organ in onions. Therefore, the correct answer is 'Onion leaf'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>52", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : PUBLIC HEALTH", "question": "Which of the following statements about poliomyelitis is not correct. It", "images": [], "options": {"A": "is a bacterial disease", "B": "is capable of paralysing the limbs", "C": "can be prevented by immunization", "D": "is an infant disease"}, "answer": "A", "explanation": "Poliomyelitis, also known as polio, is not a bacterial disease but a viral disease. It is caused by the poliovirus. The virus can cause paralysis by infecting and destroying motor neurons in the spinal cord. It can be prevented by immunization, and it affects both children and adults, not just infants.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>53", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT", "question": "Oil is sprayed over stagnant water in which mosquitoes breed in order to", "images": [], "options": {"A": "provide landing surface for the adult", "B": "prevent larva or pupa from attaching itself to the surface", "C": "prevent the water from overheating", "D": "lubricate the larva for easy movement"}, "answer": "B", "explanation": "Oil is sprayed over stagnant water where mosquitoes breed to prevent the larvae or pupa from attaching itself to the surface. This is because mosquito larvae and pupae breathe through tubes located on their abdominal segments. When oil is sprayed on the water surface, it forms a thin layer that prevents the larvae and pupae from getting air, causing them to suffocate and die.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>54", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "In animals the main protective covering is found in the", "images": [], "options": {"A": "adipose tissues", "B": "epithelial tissues", "C": "bone tissues", "D": "connective tissues"}, "answer": "B", "explanation": "In animals, the main protective covering is found in the epithelial tissues. Epithelial tissues cover the whole surface of the body. They are made up of cells closely packed and ranged in one or more layers. This tissue is specialized to form the covering or lining of all internal and external body surfaces. Epithelial tissues that cover the skin, the surface of the eyes, the lining of the mouth, throat, stomach, intestines, the urinary tract, the genital tract, and the respiratory tract are all derived from the ectoderm and endoderm with a small contribution from the mesoderm, forming the endothelium, a specialized type of epithelium that composes the lining of blood and lymphatic vessels. Therefore, they serve as the main protective covering in animals.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>55", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "How many chromosomes will be present in a gamete if the somatic cell has eight(8) chromosomes?", "images": [], "options": {"A": "4", "B": "6", "C": "8", "D": "10"}, "answer": "A", "explanation": "In sexually reproducing organisms, the number of chromosomes in a gamete is half the number of chromosomes in a somatic cell. This is because gametes are formed through a process called meiosis, which reduces the number of chromosomes by half. Therefore, if a somatic cell has 8 chromosomes, a gamete will have 4 chromosomes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>56", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "In a plant of genotype Tt, what is the probability that a gamete will contain gene t?", "images": [], "options": {"A": "1\\2", "B": "3\\4", "C": "1\\8", "D": "1\\6"}, "answer": "A", "explanation": "In a heterozygous organism (Tt), the probability of a gamete containing either allele (T or t) is 1/2. This is because during meiosis, the two alleles for each gene segregate from each other, so each gamete carries only one allele for each gene. Therefore, the probability that a gamete will contain the gene t is 1/2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>57", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "In a cross involving a heterozygous red flowered plant (Rr) and a white flowered plant (rr). what is the probability that the offspring will be Rr?", "images": [], "options": {"A": "1", "B": "1\\2", "C": "1\\4", "D": "3\\4"}, "answer": "B", "explanation": "In a cross involving a heterozygous red flowered plant (Rr) and a white flowered plant (rr), the possible combinations of alleles in the offspring are RR, Rr, rR, and rr. The probability of getting a heterozygous red flowered plant (Rr) is therefore 1 out of 4 or 1/2. This is because the heterozygous red flowered plant can be produced in two ways (Rr or rR), and there are four possible outcomes. Therefore, the probability is 2/4, which simplifies to 1/2.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>58", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Termites are called social insects because", "images": [], "options": {"A": "the nests are built by the nasute soldiers", "B": "they live together in communities", "C": "the queen allocates duties to the workers", "D": "the king and queen do mate"}, "answer": "B", "explanation": "Termites are called social insects because they live together in communities. Ants, Honey bees and termites are called social insects because they live and work together in groups.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1998>59", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following makes up the bee caste", "images": [], "options": {"A": "Soldiers and Queen", "B": "Drones, soldiers and workers", "C": "Queen, workers and soldiers", "D": "Queen, drones and workers"}, "answer": "D", "explanation": "A bee caste is made up of the Queen, drones, and workers. The Queen is the only sexually mature female in the hive and her primary role is to reproduce. Drones are male bees, and their primary role is to mate with the Queen. Workers are non-reproducing females who perform all the tasks necessary for the survival of the hive. Therefore, the correct answer is 'Queen, drones and workers'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1998>60", "subject": "Biology", "year": "1998", "type": "Objective", "topic": "EVOLUTION : ADAPTIVE COLOURATION", "question": "Which of the following examples best describes camouflagic colouration in organisms?", "images": [], "options": {"A": "A butterfly which has a real colouration on the wing", "B": "A green snake in a green grass", "C": "zebra with vertical stripes on the body", "D": "Certain tree frogs with bright colour patterns"}, "answer": "B", "explanation": "Cryptic or concealing or camouflage enables the organisms to blend with it's back ground and be less visible to predators. E.g the green leaf-like mantis, dark colour on the dorsal side and silvery white color on the ventral side as in most fish, changing the colour pattern of the body to blend with that of the general surrounding as in green snake in green grass.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>1", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "Which of the following organisms does not exist as a single cell?", "images": [], "options": {"A": "Amoeba", "B": "Euglena", "C": "Volvox", "D": "Chlamydomonas"}, "answer": "C", "explanation": "Volvox does not exist as a single cell. Volvox is a spherical multicellular green alga, which contains many small biflagellate somatic cells and a few large, non-motile reproductive cells called gonidia, and swims with a characteristic rolling motion with a distinct anterior and posterior.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>2", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "Which of the following features of Paramecium is not an advancement over Amoeba? The possession of", "images": [], "options": {"A": "definite shape", "B": "cilia", "C": "oral groove", "D": "nucleus"}, "answer": "D", "explanation": "Both Paramecium and Amoeba possess a nucleus, which is an essential organelle that controls all the cell activities and contains genetic material. However, the nucleus in Paramecium is fixed in one position, while that of Amoeba is not fixed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>3", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "Which of the following diseases results from the deficiency of insulin?", "images": [], "options": {"A": "Cretinism", "B": "Goitre", "C": "Beri-beri", "D": "Diabetes"}, "answer": "D", "explanation": "Diabetes mellitus is a chronic heterogeneous metabolic disorder with complex pathogenesis. It is characterized by elevated blood glucose levels or hyperglycemia, which results from abnormalities in either insulin secretion or insulin action or both.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>4", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Root hairs absorb water from the soil by", "images": [], "options": {"A": "diffusion", "B": "osmosis", "C": "plasmolysis", "D": "translocation"}, "answer": "B", "explanation": "Root hairs absorb water from the soil by the process of osmosis. The root hairs take water from the soil by a process called osmosis. In osmosis, water molecules move from a region of higher concentration to a region of lower concentration through a semi-permeable membrane. The concentration of the water molecules is lower in the root hair than in the soil. So the water moves into the root hairs through osmosis.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>5", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "One of the similarities between algae and mosses is their possession of", "images": [], "options": {"A": "chlorophyll", "B": "stem", "C": "leaves", "D": "roots"}, "answer": "A", "explanation": "Algae and mosses are both photosynthetic organisms, meaning they have the ability to convert light energy, usually from the sun, into chemical energy in the form of glucose or other sugars. This process of photosynthesis is facilitated by the pigment chlorophyll, which is present in both algae and mosses. Chlorophyll absorbs light energy, particularly energy in the blue and red wavelengths, and uses this energy to combine carbon dioxide and water to produce glucose. This is why both algae and mosses possess chlorophyll. The other options - stem, leaves, and roots - are not correct because while mosses may have structures that resemble these, algae do not have differentiated structures like stems, leaves, or roots.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>6", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "The vessel that carries blood from the heart to the lungs is called an artery because it", "images": [], "options": {"A": "contains oxygenated blood", "B": "contains more blood than the other vessels", "C": "carries blood away from the heart", "D": "has thick inelastic wall"}, "answer": "C", "explanation": "The vessel that carries blood from the heart to the lungs is called an artery because it carries blood away from the heart. The term 'artery' is used to describe any blood vessel that carries blood away from the heart, regardless of the blood's oxygenation status. The pulmonary artery, in this case, carries deoxygenated blood from the heart to the lungs for oxygenation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>7", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "During anaerobic respiration in skeletal muscles, pyruvic acid is", "images": [], "options": {"A": "reduced to lactic acid", "B": "oxidized to ethanol", "C": "oxidized to lactic acid", "D": "reduced to water"}, "answer": "A", "explanation": "During anaerobic respiration in skeletal muscles, pyruvic acid is reduced to lactic acid. When people exercise, sometimes the oxygen supply needed to power muscles is depleted more quickly than it can be restored. When this happens, muscle cells temporarily switch to anaerobic respiration to generate energy. Lactic acid builds in the muscles as a result of this process. Oversaturation of lactic acid leads to muscle cramps and fatigue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>8", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "Use the information on the stages involved in conjugation to answer the  question below  I. Transfer of one cell content into the adjacent cell   ll. Formation of a conjugation tube   III. Secretion of thick wall to form a zygospore   IV. Formation of a protuberance   V. Germination of a filament    Which of the following organisms exhibits 'the stages listed above during conjugation?", "images": [], "options": {"A": "Chlamydomonas", "B": "Euglena", "C": "Spirogyra", "D": "Volvox"}, "answer": "C", "explanation": "The conjugation processes of a filamentous freshwater green alga Spirogyra varians were examined using FITC-lectins. Conjugation comprised five steps: 1) aligning with adjacent filaments, 2) formation of conjugation protru-sion (papilla), 3) fusion of the protrusions, 4) formation of conjugation tube,and 5) formation of zygotes", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>1999>9", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "Use the information on the stages involved in conjugation to answer the  question below  I. Transfer of one cell content into the adjacent cell   ll. Formation of a conjugation tube   III. Secretion of thick wall to form a zygospore   IV. Formation of a protuberance   V. Germination of a filament   Which of the following arrangements is the correct sequence of the process?", "images": [], "options": {"A": "II, I, IV, V and III", "B": "IV, II, I, III and V", "C": "IV, I, II, V and III", "D": "V, II, III, IV and I"}, "answer": "A", "explanation": "This means that the formation of a conjugation tube comes first, followed by the transfer of one cell content into the adjacent cell, then the formation of a protuberance, germination of a filament and finally secretion of a thick wall to form a zygospore.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>10", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ALIMENTARY SYSTEM", "question": "The teeth used for tearing and cutting are", "images": [], "options": {"A": "canine and molars", "B": "premolar and incisors", "C": "molar and incisors", "D": "canine and incisors"}, "answer": "D", "explanation": "The teeth used for tearing and cutting are the canines and incisors. Canines are the sharp, pointed teeth that sit next to the incisors and are used for tearing food. Incisors are the teeth at the front of the mouth and they are used for cutting food. Therefore, the correct answer is 'canine and incisors'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>11", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Turgor pressure occurs in a cell when the?", "images": [], "options": {"A": "volume of its cell sap increases", "B": "cell loses water to its environment", "C": "volume of cell decreases", "D": "cell is put in an isotonic solution"}, "answer": "A", "explanation": "Turgor pressure occurs in a cell when the volume of its cell sap increases. Turgor pressure is the force within the cell that pushes the plasma membrane against the cell wall. It is primarily caused by the osmotic flow of water and occurs in cells that have a cell wall, such as plant cells and fungi. When water enters the cell, it causes the central vacuole to expand and push against the cell wall. This pressure is what gives the plant its rigidity and support.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>12", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following bones is illustrated in the diagram?", "images": ["Biology/imgs/1999/bone.png"], "options": {"A": "Tibia", "B": "Humerus", "C": "Patella", "D": "Scapula"}, "answer": "D", "explanation": "Scapula, also called shoulder blade, either of two large bones of the shoulder girdle in vertebrates. In humans they are triangular and lie on the upper back between the levels of the second and eighth ribs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>13", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The part labelled l in the diagram is for the attachment of", "images": ["Biology/imgs/1999/bone.png"], "options": {"A": "ribs", "B": "biceps", "C": "shoulder muscles", "D": "the vertebral column"}, "answer": "C", "explanation": "The part labelled l in the diagram is for the attachment of shoulder muscles. The diagram shown is a Scapula, also called shoulder blade.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>14", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following bones forms a joint at the point labelled II in the diagram?", "images": ["Biology/imgs/1999/bone.png"], "options": {"A": "Humerus", "B": "Sternum", "C": "Radius", "D": "Femur"}, "answer": "A", "explanation": "Humerus forms a joint at the point labelled II in the diagram.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>15", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "Which of the following is correct about the transverse section of a vein, when compared with that of an artery?", "images": [], "options": {"A": "The lumen of a vein is wider than that of an artery", "B": "The endothelium of the vein is thinner than that of an artery", "C": "There are more smooth muscles in a vein than in an artery", "D": "There are valves in veins but not in arteries."}, "answer": "D", "explanation": "There are valves in veins but not in arteries is correct.Unlike arteries, veins contain valves that ensure blood flows in only one direction. (Arteries don't require valves because pressure from the heart is so strong that blood is only able to flow in one direction.) Valves also help blood travel back to the heart against the force of gravity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>16", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "Terrestrial plants exchange gases through the following except", "images": [], "options": {"A": "chloroplast", "B": "stomata", "C": "lenticels", "D": "root-cells"}, "answer": "A", "explanation": "Chloroplasts are organelles found in plant cells where photosynthesis takes place, but they are not directly involved in gas exchange.  Stomata: These are small openings on the surface of leaves that allow for gas exchange between the plant and the atmosphere.  Lenticels: These are small openings on the surface of stems and roots that allow for gas exchange.  Root cells: While root cells themselves don't exchange gases directly, roots have tiny hair-like structures called root hairs that increase the surface area for gas exchange.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>17", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Glomerular filtrate contains", "images": [], "options": {"A": "no glucose", "B": "amino acids", "C": "no proteins", "D": "urea"}, "answer": "C", "explanation": "Glomerular filtrate is the liquid that has been filtered out of the blood by the glomerulus into the Bowman's capsule in the kidneys. It contains everything that blood plasma does (such as water, glucose, amino acids, urea) except for proteins. Proteins are too large to pass through the glomerular filter. Therefore, the glomerular filtrate contains no proteins.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>18", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which of the following is not a function of the liver in mammals?", "images": [], "options": {"A": "Storage of some vitamins", "B": "Conversion of glycogen into glucose", "C": "Deamination of excess nitrogenous substances", "D": "Filtration of urea from the blood."}, "answer": "D", "explanation": "The liver in mammals performs a variety of functions including the storage of some vitamins, conversion of glycogen into glucose, and deamination of excess nitrogenous substances. However, the filtration of urea from the blood is not a function of the liver but rather the kidneys. The kidneys filter blood, removing waste products like urea, and also maintain the balance of electrolytes in the blood.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>19", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "Iodine is needed by a patient suffering from a malfunctioning of the", "images": [], "options": {"A": "salivary gland", "B": "thyroid gland", "C": "adrenal gland", "D": "sebaceous gland"}, "answer": "B", "explanation": "Iodine is needed by a patient suffering from a malfunctioning of the thyroid gland. The thyroid gland uses iodine to produce thyroid hormones that help control growth, repair damaged cells and support a healthy metabolism. Therefore, a deficiency in iodine can lead to problems with the thyroid gland, such as goiter or hypothyroidism.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>20", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "The medulla oblongata controls all the following except", "images": [], "options": {"A": "heart beat", "B": "breathing rate", "C": "blood pressure", "D": "balance and posture"}, "answer": "D", "explanation": "The medulla oblongata is a part of the brain that controls autonomic functions such as heart rate, breathing, and blood pressure. However, balance and posture are primarily controlled by the cerebellum, not the medulla oblongata. Therefore, the correct answer is 'balance and posture'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>21", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "Which of the following statements about short sight is not correct?", "images": [], "options": {"A": "The eyeball is too short", "B": "The cornea of the eyeball is too curved", "C": "The images fall in front of the retina", "D": "It can be corrected by using concave lenses"}, "answer": "A", "explanation": "Short sight, also known as myopia, is a common vision condition in which you can see objects near to you clearly, but objects farther away are blurry. It occurs when the shape of your eye causes light rays to bend (refract) incorrectly, focusing the images in front of the retina instead of directly on the retina. This can be caused by the eyeball being too long, not too short, or the cornea being too curved. Therefore, the statement 'The eyeball is too short' is not correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>22", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "Hypermetropia is corrected by the use of", "images": [], "options": {"A": "concave lenses", "B": "convex lenses", "C": "cylindrical lenses", "D": "contact lenses"}, "answer": "B", "explanation": "Hypermetropia, also known as farsightedness, is a condition of the eye where the light that comes in does not directly focus on the retina but behind it. This condition can be corrected by the use of convex lenses. Convex lenses are thicker at the center than at the edges, they converge light rays to a point. When a convex lens is used, it bends the light rays inward to directly focus on the retina, thus correcting the vision.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>23", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "The structure labelled I is the", "images": ["Biology/imgs/1999/female.png"], "options": {"A": "oviduct", "B": "ovary", "C": "uterus", "D": "funnel"}, "answer": "A", "explanation": "The structure labelled I is the oviduct. The oviduct in mammals, is the passageway from an ovary. In human females this is more usually known as the Fallopian tube or uterine tube.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>24", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "In which of the labelled structures does implantation take place?", "images": ["Biology/imgs/1999/female.png"], "options": {"A": "I", "B": "II", "C": "IV", "D": "VI"}, "answer": "C", "explanation": "The structure labelled IV is where implantation takes place.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>25", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "Which of the following indicates the direction of the movement of a sperm introduced into the female reproductive system?", "images": ["Biology/imgs/1999/female.png"], "options": {"A": "III → II → I → IV", "B": "VI → V → IV → I", "C": "V → IV → I → III", "D": "VI → IV → I → III"}, "answer": "B", "explanation": "VI → V → IV → I indicates the direction of the movement of a sperm introduced into the female reproductive system", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>26", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "Which of the labelled parts is responsible for the release of ripe ovum?", "images": ["Biology/imgs/1999/female.png"], "options": {"A": "VI", "B": "III", "C": "II", "D": "I"}, "answer": "B", "explanation": "The labelled part III is responsible for the release of ripe ovum", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>27", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "During germination of seeds water is taken by the process of", "images": [], "options": {"A": "diffusion", "B": "hydrolysis", "C": "imbibition", "D": "translocation"}, "answer": "C", "explanation": "During the germination of seeds, water is taken up by the process of imbibition. Imbibition is the process where water is absorbed by solids-colloids causing them to enormously increase in volume. The absorption of water by seeds leads to the swelling of seeds which breaks the seed coat and leads to germination. The other options are not correct. Diffusion is the movement of molecules from an area of higher concentration to an area of lower concentration. Hydrolysis is a chemical process in which a molecule is cleaved into two parts by the addition of a molecule of water. Translocation is the movement of materials from leaves to other tissues throughout the plant.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>28", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Which of the following is not a characteristics feature of a wind dispersed fruit?", "images": [], "options": {"A": "Lightweight", "B": "winged apparatus", "C": "Flossy structure", "D": "Buoyancy"}, "answer": "D", "explanation": "Wind dispersed fruits have certain characteristics that aid their dispersal by wind. These include being lightweight, having a winged apparatus or a flossy structure to catch the wind. Buoyancy, however, is a characteristic of water-dispersed fruits/seeds, not wind-dispersed fruits. Therefore, the correct answer is 'Buoyancy'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>29", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "During photosynthesis, light energy is always absorbed by the", "images": [], "options": {"A": "shoot", "B": "water", "C": "chlorophyll", "D": "enzyme"}, "answer": "C", "explanation": "During photosynthesis, light energy is always absorbed by the chlorophyll. Chlorophyll (also chlorophyl) is any of several related green pigments found in cyanobacteria and in the chloroplasts of algae and plants.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>30", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Use the information below on factors required during photosynthesis to answer the two questions  I. CO2   II. Chlorophyll   III. Water   IV. ATP   V NADPH2.    Which of the above factors can be a limiting factor for the process to proceed?", "images": [], "options": {"A": "I and II only", "B": "I and III only", "C": "I and IV only", "D": "I, III and IV only"}, "answer": "B", "explanation": "In photosynthesis, the process can be limited by several factors including light intensity, carbon dioxide concentration and temperature. In the given options, CO2 (I) and Water (III) can be limiting factors. Chlorophyll (II) is necessary for photosynthesis but it's not typically considered a limiting factor because it's usually present in sufficient quantities in plants. ATP (IV) and NADPH (V) are products of the light-dependent reactions and are used in the light-independent reactions of photosynthesis, but they are not typically considered limiting factors because they are produced in the process itself. Therefore, the correct answer is 'I and III only'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>31", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Use the information below on factors required during photosynthesis to answer the two questions  I. CO2   II. Chlorophyll   III. Water   IV. ATP   V NADPH2.   The factors required for the dark phase of photosynthesis are", "images": [], "options": {"A": "III and IV only", "B": "III and V only", "C": "III, IV and V only", "D": "IV and V only"}, "answer": "D", "explanation": "The dark phase of photosynthesis, also known as the Calvin cycle, requires:  - ATP (IV) to provide energy  - NADPH2 (V) to provide reducing power    These two factors are produced in the light-dependent reactions and are used to convert CO2 into glucose in the Calvin cycle.  Water (III) is a reactant in the light-dependent reactions, not the dark phase.  Chlorophyll (II) is a pigment that plays a critical role in absorbing light energy in the light-dependent reactions, but is not directly involved in the dark phase.    CO2 (I) is a reactant that is used in the Calvin cycle, but it is not a factor that is required for the dark phase to proceed.    Therefore, the correct answer is  IV and V only, as ATP and NADPH2 are the only two factors that are required for the dark phase of photosynthesis to proceed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>32", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "In water- culture experiments the culture solutions are protected from sunlight in order to", "images": [], "options": {"A": "control the temperature of the culture solution", "B": "prevent algae from growing in the solution", "C": "prevent the minerals in the solution from being destroyed", "D": "allow the minerals to be used up at room temperature"}, "answer": "B", "explanation": "In water-culture experiments, the culture solutions are protected from sunlight primarily to prevent algae from growing in the solution. Algae are photosynthetic organisms that require sunlight to grow. If the culture solutions are exposed to sunlight, it can lead to the growth of algae, which can contaminate the solution and interfere with the experiment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>33", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "The importance of a balanced diet is to", "images": [], "options": {"A": "maintain constant size of an animal", "B": "provide good taste in the food", "C": "increase the effectiveness of digestion", "D": "provide good health for an individual"}, "answer": "D", "explanation": "A balanced diet is important for providing good health for an individual. A balanced diet is one that gives your body the nutrients it needs to function correctly. It consists of the proper quantities and proportions of foods needed to maintain health or growth. It does not necessarily maintain constant size of an animal, provide good taste in the food or increase the effectiveness of digestion.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>34", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : FEEDING HABITS", "question": "The dentition of a herbivore is distinct from that of other animals due to the presence of", "images": [], "options": {"A": "diastema", "B": "cusps on molar teeth", "C": "canines", "D": "ridges on molar teeth"}, "answer": "A", "explanation": "The dentition of a herbivore is distinct from that of other animals due to the presence of diastema. A diastema is a space or gap between two teeth. Many species of mammals have diastemata as a normal feature, most commonly between the incisors and molars.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>35", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Which of the following statements is true?", "images": [], "options": {"A": "Ptyalin acts on proteins to give amino acid", "B": "Lactase acts on maltose to give amino acid", "C": "Pepsin acts on proteins to give peptide", "D": "Peptide acts on starch to give maltose"}, "answer": "C", "explanation": "Pepsin is an enzyme that breaks down proteins into smaller peptides (a peptide is a compound consisting of 2 or more amino acids). This process is known as proteolysis. This is why the statement 'Pepsin acts on proteins to give peptide' is true. The other options are incorrect because Ptyalin (also known as salivary amylase) acts on starch to give maltose, not on proteins to give amino acids. Lactase acts on lactose to give glucose and galactose, not on maltose to give amino acids. And peptides are the products of protein breakdown, they do not act on starch to give maltose.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>36", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "Which of the following organisms can be found in fresh water habitat?", "images": [], "options": {"A": "Sargassum and dog fish", "B": "Red mangrove and pond skater", "C": "Sargassum and red mangrove", "D": "Spirogyra and pond skater"}, "answer": "D", "explanation": "Spirogyra and pond skater can be found in fresh water habitat. Spirogyra is a type of green algae that is commonly found in fresh water. Pond skaters, also known as water striders, are insects that are able to walk on the surface of water, and they are typically found in fresh water habitats. The other options include organisms that are not typically found in fresh water. Sargassum is a type of seaweed that is typically found in marine environments, and dog fish are a type of shark that is also found in the ocean. Red mangroves are trees that grow in salt water or brackish water environments.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>37", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Which of the following is not a biotic factor?", "images": [], "options": {"A": "Parasites", "B": "Predators", "C": "Grazers", "D": "Pressure"}, "answer": "D", "explanation": "Biotic factors are living or once-living organisms in the ecosystem. These are obtained from the biosphere and are capable of reproduction. Examples of biotic factors include any animals, plants, trees, grass, bacteria, moss, or molds that you might find in an ecosystem. In this context, parasites, predators, and grazers are all biotic factors as they are living organisms. Pressure, on the other hand, is an abiotic factor. Abiotic factors are non-living physical and chemical elements in the ecosystem. Abiotic resources are usually obtained from the lithosphere, atmosphere, and hydrosphere. Examples of abiotic factors are sunlight, water, air, soil, humidity, pH, temperature, wind, precipitation, altitude, light intensity, etc. Therefore, the correct answer is 'Pressure'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>38", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Desert plants are usually called", "images": [], "options": {"A": "hydrophytes", "B": "mesophytes", "C": "xerophytes", "D": "sporophytes"}, "answer": "C", "explanation": "Desert plants are usually called xerophytes. Plants that are adapted to survive in physiologically dry conditions are called xerophytes. They have special adaptations to prevent loss of water, and also store some water.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>39", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS", "question": "The secchi disc is used to measure", "images": [], "options": {"A": "speed of flow of water", "B": "specific gravity of water", "C": "turbidity of water", "D": "depth of water"}, "answer": "C", "explanation": "The Secchi disc is used to measure the turbidity of water. Turbidity refers to the cloudiness or haziness of a fluid caused by large numbers of individual particles that are generally invisible to the naked eye, similar to smoke in air. The measurement is done by lowering the disc in the water. The depth at which the pattern on the disc is no longer visible is taken as a measure of the transparency of the water. Thus, it indirectly measures the amount of particles present in the water.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>40", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Soil factors in an ecosystem are referred to as", "images": [], "options": {"A": "topographic", "B": "climatic", "C": "biotic", "D": "edaphic"}, "answer": "D", "explanation": "Soil factors in an ecosystem are referred to as edaphic factors. Edaphic refers to soil conditions, so it's the term used to denote the influence of soil on living organisms, including both plants and animals. These factors include soil structure, composition, moisture, pH level, and temperature. They can significantly affect the types of plant species that grow in a particular region, as well as the abundance and health of those plants. Options A, B, and C are incorrect because topographic refers to the physical features of a region, climatic refers to the weather conditions over a long period, and biotic refers to the living organisms in an ecosystem.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>41", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "A known weight of soil sample was oven-dried to obtain a constant weight. The loss in weight was due to loss of", "images": [], "options": {"A": "organic matter only", "B": "water only", "C": "water and organic matter", "D": "inorganic matter and water"}, "answer": "B", "explanation": "The process of oven-drying a soil sample is used to remove the moisture content in the soil. The heat from the oven causes the water in the soil to evaporate, leading to a loss in weight. Organic matter and inorganic matter are not affected by this process as they do not evaporate at the temperatures used in oven-drying. Therefore, the loss in weight of the soil sample is due to the loss of water only.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>42", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "Carbon is added to the atmosphere by the following processes except", "images": [], "options": {"A": "respiration", "B": "burning", "C": "photosynthesis", "D": "volcanic eruption"}, "answer": "C", "explanation": "Carbon is added to the atmosphere through processes such as respiration, burning, and volcanic eruption. However, photosynthesis is a process that removes carbon dioxide from the atmosphere. In photosynthesis, plants absorb carbon dioxide and sunlight to produce glucose and oxygen. Therefore, photosynthesis does not add carbon to the atmosphere, but rather removes it.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>43", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "Which of the following is a means of measuring primary production?", "images": [], "options": {"A": "Rate of reproduction of animals", "B": "Life span of an organism", "C": "Number of predators in an environment", "D": "harvested plants in a unit area"}, "answer": "D", "explanation": "Primary production is the synthesis of organic compounds from atmospheric or aqueous carbon dioxide. It principally occurs through the process of photosynthesis, which uses light as its source of energy. Primary production can be measured by the amount of harvested plants in a unit area. This is because the amount of harvested plants represents the amount of organic compounds (or biomass) that has been produced in that area. Therefore, the correct answer is 'harvested plants in a unit area'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>44", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "A situation whereby some mammals remain inactive throughout dry and hot seasons is known as", "images": [], "options": {"A": "aestivation", "B": "dormancy", "C": "burrowing", "D": "incubation"}, "answer": "A", "explanation": "Aestivation, also spelled estivation, is a state of animal dormancy, similar to hibernation, characterized by inactivity and a lowered metabolic rate, that is entered in response to high temperatures and arid conditions. It takes place during times of heat and dryness, the hot dry season, which are often the summer months. In contrast to hibernation, when animals slow their metabolic rate to save energy and survive the winter with scarce food, aestivation is entered in response to drought to prevent desiccation, or drying up. Therefore, the correct answer is 'aestivation'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>45", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Which of the following factors may not affect living organisms in an aquatic habitat?", "images": [], "options": {"A": "Turbidity", "B": "Temperature", "C": "Humidity", "D": "Light"}, "answer": "C", "explanation": "In an aquatic habitat, factors such as turbidity, temperature, and light can significantly affect the living organisms. Turbidity refers to the cloudiness or haziness of a fluid caused by large numbers of individual particles that are generally invisible to the naked eye. This can affect the amount of light that penetrates the water, which can in turn affect photosynthesis in aquatic plants. Temperature can affect the metabolic rates of aquatic organisms. Light is necessary for photosynthesis in aquatic plants. However, humidity refers to the amount of water vapor in the air. Aquatic organisms, living in water, would not be directly affected by the humidity of the air above their habitat. Therefore, humidity may not affect living organisms in an aquatic habitat.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>46", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION", "question": "Which of the following parasites is a flatworm?", "images": [], "options": {"A": "Plasmodium", "B": "Trypanosoma", "C": "Ascaris", "D": "Schistosoma"}, "answer": "D", "explanation": "Schistosoma is a genus of flatworms, also known as blood flukes, and they are parasitic. They belong to the phylum Platyhelminthes, which is characterized by flat, ribbon-like bodies. Plasmodium and Trypanosoma are protozoan parasites, not flatworms, and Ascaris is a roundworm, which belongs to the phylum Nematoda.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>47", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "During prolonged exercises, glucose in the muscle is convened to", "images": [], "options": {"A": "pyruvic acid", "B": "lactic acid", "C": "co- enzyme", "D": "ethanol"}, "answer": "B", "explanation": "During prolonged exercises, the body needs to produce energy for the muscles to continue functioning. This energy is produced through a process called glycolysis, where glucose is broken down in the absence of oxygen (anaerobic conditions) to produce lactic acid. This process is known as lactic acid fermentation. The lactic acid can cause muscle fatigue and pain, but it is later removed from the muscles when oxygen becomes available. Therefore, the correct answer is lactic acid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>48", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE", "question": "Which of the following is an effect of carbon monoxide on man?", "images": [], "options": {"A": "irritating the skin", "B": "Reducing oxygen carrying capacity of blood", "C": "Causing gene mutation", "D": "Destroying white blood cells."}, "answer": "B", "explanation": "Carbon monoxide (CO) is a poisonous gas that can be harmful when inhaled in large amounts. The danger of CO is its ability to bind with the hemoglobin in red blood cells, forming carboxyhemoglobin, which prevents the hemoglobin from carrying oxygen. This reduces the oxygen-carrying capacity of the blood, leading to oxygen deprivation in tissues and organs. The other options are incorrect as CO does not irritate the skin, cause gene mutation, or destroy white blood cells.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>49", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "Which of the following is a renewable natural resources?", "images": [], "options": {"A": "Air", "B": "Timber", "C": "Soil", "D": "Mineral"}, "answer": "B", "explanation": "Timber is a renewable natural resource because trees can be replanted and regrown. Air, soil, and minerals are also natural resources, but they are not considered renewable in the same way because their availability is not directly dependent on human actions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>50", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "Which of the following resources is competed for by organisms in the desert?", "images": [], "options": {"A": "Light", "B": "Temperature", "C": "Oxygen", "D": "Water"}, "answer": "D", "explanation": "In a desert environment, water is the most scarce resource and therefore, it is the resource most competed for by organisms. Light is abundant in desert environments, temperature is not a resource, and oxygen is not typically limited in desert environments.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>51", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "The major types of man's finger prints do not include", "images": [], "options": {"A": "arch", "B": "compound", "C": "simple", "D": "loop"}, "answer": "C", "explanation": "The major types of man's finger prints do not include simple.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>52", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Which of the following is an example of discontinuous variation?", "images": [], "options": {"A": "Height of students", "B": "Complexion of beauty contestants", "C": "Blood groups of patients", "D": "Weight of weight lifters"}, "answer": "C", "explanation": "Discontinuous variation is a type of genetic variation where there are distinct categories or groups, and individuals fall into one of these groups with no intermediates. Blood groups of patients is an example of discontinuous variation because blood groups are distinct categories (A, B, AB, O) with no intermediates.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>53", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Which of the following statements is correct about variation?", "images": [], "options": {"A": "Offsprings are different from their parents only", "B": "Offsprings from the same parents look alike", "C": "Offsprings differ from their ancestors but look like their immediate parents", "D": "offsprings differ from their ancestors and from each other"}, "answer": "D", "explanation": "Variation refers to the differences in physical traits among individuals from the same species. It is a fundamental aspect of life on Earth, and it is the driving force of evolution. Offsprings differ from their ancestors and from each other due to genetic variation. This variation comes from two main sources: mutation and recombination of genes during sexual reproduction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>54", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : LINKAGE, SEX DETERMINATION AND SEX LINKED CHARACTERS", "question": "Which of the following statements about sex determination is correct? At fertility", "images": [], "options": {"A": "the probability of male to female offspring is 1/2", "B": "the Y chromosome of the father decreases the probability of having a male child to 3/4", "C": "the xx chromosome of the mother decreases the probability of having a female child to 3/4", "D": "the vigour of either parents determines the sex of the offspring"}, "answer": "A", "explanation": "Sex determination in humans is determined by the 23rd pair of chromosomes, also known as the sex chromosomes. Females have two of the same kind of sex chromosome (XX), while males have two distinct sex chromosomes (XY). The sperm cells from the male can carry either an X or a Y chromosome, while the egg cells from the female only carry an X chromosome. Therefore, the probability of having a male or female offspring is 1/2, depending on whether the sperm cell carrying the X or Y chromosome fertilizes the egg. The other options are incorrect because neither the Y chromosome of the father nor the XX chromosome of the mother can alter this 1/2 probability, and the vigour of the parents has no influence on the sex of the offspring.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>55", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "The genotypic ratio of 1 : 2 : 1 in the offspring of a hybrid cross illustrates the law of", "images": [], "options": {"A": "use and disuse", "B": "dominance", "C": "segregation", "D": "linkage"}, "answer": "C", "explanation": "The genotypic ratio of 1:2:1 is a result of Mendel's law of segregation. This law states that during the formation of reproductive cells (gametes), pairs of hereditary traits (genes) for a specific trait separate so that offspring receive one factor from each parent. This results in the genotypic ratio of 1:2:1 in the offspring of a hybrid cross.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>56", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Which of the following scientists was involved with organic evolution?", "images": [], "options": {"A": "Mendel", "B": "Larmarck", "C": "Morgan", "D": "Pasteur"}, "answer": "B", "explanation": "Organic evolution refers to the process of the development of living organisms over time. Lamarck was a scientist who is known for his theory of inheritance of acquired characteristics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>57", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY", "question": "Which of the following traits may not be important in marriage counselling", "images": [], "options": {"A": "Sex-determination", "B": "Sickle-cell anaemia", "C": "Rhesus factor", "D": "Colour of skin"}, "answer": "D", "explanation": "In marriage counselling, traits that are considered are those that have a significant impact on the health of potential offspring or the compatibility of the couple. These include genetic conditions like sickle-cell anaemia, rhesus factor, and sex-determination. The colour of skin, however, is a physical trait that does not have any impact on health or compatibility, hence it is not important in marriage counselling.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>58", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "In fishes, the brooders return to their parents mouth for", "images": [], "options": {"A": "feeding", "B": "respiration", "C": "breeding", "D": "protection"}, "answer": "D", "explanation": "In certain species of fishes, the brooders return to their parents' mouth for protection. This behavior is known as mouthbrooding, where the parent fish, usually the male, keeps the eggs or young offspring in their mouth for a period of time. This is done to protect the young from predators. The options of feeding, respiration, and breeding are incorrect as the brooders do not return to their parents' mouth for these purposes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>1999>59", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "According to Charles Darwin's Theory of Evolution, natural selection involves the survival of the", "images": [], "options": {"A": "weakest", "B": "most populous", "C": "youngest", "D": "Fittest"}, "answer": "D", "explanation": "According to Charles Darwin's Theory of Evolution, natural selection involves the survival of the fittest. This means that the individuals that are best adapted to their environment are more likely to survive and reproduce. This process leads to the evolution of species over time as beneficial traits become more common in the population. The term 'fittest' in this context doesn't necessarily mean the strongest or the fastest, but rather the one that fits best into its environment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>1999>60", "subject": "Biology", "year": "1999", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "Which of the following habitats cannot be used for the study of succession?", "images": [], "options": {"A": "Savanna grassland", "B": "Abandoned farmland", "C": "A pond", "D": "Well cultivated land"}, "answer": "D", "explanation": "Succession is the process by which a series of changes occur in an ecological community over time. It often involves the gradual replacement of one plant community by another through a series of stages. For succession to occur, the land must be in a state of disuse or abandonment, allowing for natural processes to take over. A well-cultivated land is constantly being interfered with by human activities such as ploughing, planting, and harvesting, which disrupts the natural succession process. Therefore, a well-cultivated land cannot be used for the study of succession.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2000>1", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "Amoeba obtains all its oxygen requirements", "images": [], "options": {"A": "From oxidising food substance", "B": "From air trapped in vacuoles", "C": "through diffusion of air into the body", "D": "through an air cavity in the ectoplasm"}, "answer": "C", "explanation": "Ameoba obtains its oxygen requirement from diffusion of air into its body because the surface are of an amoeba is large compared to its value  i.e large surface area to volume ratio(SA/V)", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>2", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "Which of the following best describe a colony of volvox", "images": [], "options": {"A": "A sexually reproduced cells, held together in a mass, but independent of each other", "B": "sexually reproduced cell held together in a mass, and dependent on each other", "C": "single free-living acellular units irrespective of their parental origin", "D": "several units of cells, held by cytoplasmic strand and dependent on each other."}, "answer": "D", "explanation": "A colony is a visible mass of micro-organism (consisting of several unit of cells) all originating from a single mother cell.  colonial organism are joined together and dependent on one another .  The volvox is composed of several units of cells joined via cytoplasmic strand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>3", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The hydra has two body layers of cells called", "images": [], "options": {"A": "ectodermis and entron", "B": "ectodermis and endoderm", "C": "endodermis and dermis", "D": "epidermis and dermis"}, "answer": "B", "explanation": "The hydra is diploblastic meaning it has two cell body layer. The outer is known as Ectoderm or epiderm(in some texts). The inner layer is the endoderm or Gastrodermis(in some text)", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2000>4", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "All the following organelles have membrane except", "images": [], "options": {"A": "nucleus", "B": "vacuole", "C": "cell membrane", "D": "cell wall"}, "answer": "D", "explanation": "The cell wall is not an organelle and it does not have a membrane. It is a rigid layer that lies outside the cell's membrane and provides support to the cell. On the other hand, the nucleus, vacuole, and cell membrane are all organelles that have membranes. The nucleus is surrounded by a nuclear envelope (a type of membrane), the vacuole is surrounded by a vacuolar membrane, and the cell membrane (also known as the plasma membrane) is itself a membrane.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2000>5", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "Which of these has most complex level of organisation ?", "images": [], "options": {"A": "Euglena", "B": "Hydra", "C": "Heart", "D": "virus"}, "answer": "C", "explanation": "The heart has the most complex level of organization among the given options. The complexity of an organism or a part of an organism can be determined by the number of different types of cells it has and how they are organized. A heart is a part of a multicellular organism (humans) and is made up of several types of cells that work together to perform a specific function, which is to pump blood throughout the body. On the other hand, Euglena and Hydra are single-celled and simple multicellular organisms respectively, and a virus is not even considered a cell because it cannot perform life processes on its own.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>6", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "The unit contained in a cell structure responsible for changes in form and shape of organism is called", "images": [], "options": {"A": "mitochondria", "B": "gene", "C": "ribsome", "D": "lysosome"}, "answer": "B", "explanation": "The gene is the basic physical and functional unit of heredity. Genes, which are made up of DNA, act as instructions to make molecules called proteins. In humans, genes vary in size from a few hundred DNA bases to more than 2 million bases. The Human Genome Project has estimated that humans have between 20,000 and 25,000 genes. Every person has two copies of each gene, one inherited from each parent. Most genes are the same in all people, but a small number of genes (less than 1 percent of the total) are slightly different between people. These small differences contribute to each person's unique physical features. Genes are responsible for the physical characteristics of an organism, hence they are responsible for changes in form and shape of an organism.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>7", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The plant cell mostly stores food as", "images": [], "options": {"A": "glycogen", "B": "auxins", "C": "hormones", "D": "starch"}, "answer": "D", "explanation": "Plant cells primarily store food as starch. Starch is a polysaccharide produced by most green plants as an energy store. It is the most common carbohydrate in the human diet and is contained in large amounts in staple foods like potatoes, wheat, maize (corn), rice, and cassava. Glycogen is the energy storage form of glucose in animals and humans which is analogous to the starch in plants. Auxins and hormones are not energy storage forms but are involved in the regulation of growth and development in plants.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2000>8", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The presence of a large member of mitochondria in a cell indicates that", "images": [], "options": {"A": "it has little cytoplasmic content", "B": "the cell is very active", "C": "the cell is dormant", "D": "The respiration is poor"}, "answer": "B", "explanation": "Mitochondria are known as the powerhouses of the cell because they produce ATP (adenosine triphosphate), the cell's main energy source. A large number of mitochondria in a cell indicates that the cell is very active and requires a lot of energy. Therefore, the correct answer is 'the cell is very active'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>9", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "Which of the following statement is not correct about diffusion?", "images": [], "options": {"A": "it involves degradation of soluble particles in solvents", "B": "it occurs mainly in gaseous and liquid media", "C": "No membrane is needed to effect the movement of molecules", "D": "molecules move from region of lower concentration to that of higher concentration"}, "answer": "D", "explanation": "Diffusion is the process by which molecules move from an area of higher concentration to an area of lower concentration. It does not involve the movement of molecules from a region of lower concentration to that of higher concentration. Therefore, the correct answer is 'molecules move from region of lower concentration to that of higher concentration'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2000>10", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "In which of the following organism is ammonia excreted as waste product?", "images": [], "options": {"A": "man", "B": "bird", "C": "amoeba", "D": "spirogyra"}, "answer": "C", "explanation": "Ammonotelic animals are those which excretes excess nitrogen as soluble ammonia as their excretory waste product  E.g Protozoans, Crustaceans, platyhelminthes, cnidarians, poriferans,echinoderms and other aqautic invertibrates  N.B: amoeba is a unicellular protozoan", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2000>11", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The following are the function of supporting tissues in plant except", "images": [], "options": {"A": "rigidity", "B": "flexibilty", "C": "strengthening", "D": "secretory"}, "answer": "D", "explanation": "The function of supporting tissues in plants is to provide rigidity, flexibility, and strengthening to the plant structure. They do not have a secretory function. Secretory tissues are specialized tissues that produce and release substances like hormones, enzymes, etc. Therefore, the option 'secretory' is not a function of supporting tissues in plants.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2000>12", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which of the following organism has the largest surface area-to-volume ratio?", "images": [], "options": {"A": "man", "B": "earthworm", "C": "Amoeba", "D": "Grasshopper"}, "answer": "C", "explanation": "The surface area-to-volume ratio is a measure of the amount of surface area a creature has compared to its volume. The larger the surface area compared to the volume, the more efficiently the creature can exchange substances with its environment. In this case, amoeba, being a single-celled organism, has the largest surface area-to-volume ratio. This is because it is very small and thus has a lot of surface area compared to its tiny volume. Larger organisms like man, earthworm, and grasshopper have smaller surface area-to-volume ratios because as size increases, volume increases faster than surface area.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>13", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following plant parts does not perform supportive function?", "images": [], "options": {"A": "parenchyma,xylem and collenchyma", "B": "Epidermis, sclerechyma and xylem", "C": "parenchyma, collenchyma and sclerenchyma", "D": "sclerenchyma,xylem and collenchyma"}, "answer": "B", "explanation": "The important types of supporting tissue in plants are:  1. Turgid parenchyma (unspecialized plants cells)  2. collenchymas  3. sclerenchyma  4. Xylem  N.B Epidermis is not part of it  Epidermis, as it is the outermost layer of cells that provides a protective barrier, but does not typically perform a supportive function in terms of mechanical support or turgidity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>14", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : MICROORGANISMS: MAN AND HIS HEALTH.", "question": "The following are useful effect of micro-organism except", "images": [], "options": {"A": "production of vaccines", "B": "curing of tobacco", "C": "tanning of leather", "D": "decay of meat"}, "answer": "D", "explanation": "Microorganisms are used in various beneficial ways such as in the production of vaccines, curing of tobacco, and tanning of leather. However, the decay of meat is not a useful effect of microorganisms. Instead, it is a harmful effect as it leads to food spoilage and can cause foodborne illnesses if consumed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>15", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following structures is not present in the vascular bundles of a dicot stem?", "images": [], "options": {"A": "Xylem", "B": "phloem", "C": "intra-fascicular cambium", "D": "inter-fascicular cambium"}, "answer": "C", "explanation": "Intra-fascicular cambium is not present in the vascular bundles of a dicot stem. Instead, it is the inter-fascicular cambium that is present between the vascular bundles, producing new vascular tissue and allowing for secondary growth.    - Xylem: present, responsible for water and mineral transport  - Phloem: present, responsible for sugar and nutrient transport  - Intra-fascicular cambium: NOT present in the vascular bundles of a dicot stem  - Inter-fascicular cambium: present between the vascular bundles, producing new vascular tissue", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>16", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "When a mammal respire anaerobically for a long time", "images": [], "options": {"A": "pyruvic acid is converted into acetyl COA", "B": "more energy is released from fat in the body", "C": "latic acid accumulates in the muscles", "D": "the kreb's cycle is fully completed"}, "answer": "C", "explanation": "When a mammal respires anaerobically for a long time, lactic acid accumulates in the muscles. This is because, in the absence of oxygen, the body converts glucose into lactic acid to produce energy. This process is known as anaerobic respiration or fermentation. The lactic acid build-up can lead to muscle fatigue and cramps. The other options are incorrect because they describe processes that occur during aerobic respiration, not anaerobic respiration. For instance, pyruvic acid is converted into acetyl COA and the Kreb's cycle is completed in the presence of oxygen, not in its absence. Also, more energy is released from fat in the body during aerobic respiration, not anaerobic respiration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>17", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Study the diagram below      Which of the following structure in the diagram are involved with the entry of carbon dioxide for photosynthesis?", "images": ["Biology/imgs/2000/3XRHJ9.jpg"], "options": {"A": "I, II and III only", "B": "I, II, III and VI", "C": "I, II,V and VI", "D": "I, II, III and V"}, "answer": "C", "explanation": "Given the context and the labelled structures:  -\tI (Guard Cells): Regulate the opening and closing of the stomatal pore.  -\tII (Stomatal Pore): Involved in the entry of carbon dioxide.  -\tV (Chloroplasts in Guard Cells): These are directly involved in photosynthesis.  -\tAir Spaces within the Leaf (VI): Spaces that facilitate the distribution of carbon dioxide to the photosynthetic cells  Structures I, II, V, and VI are directly involved in the process of gas exchange and photosynthesis.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2000>18", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "Study the diagram below    which of the labelled structures in the diagram will shrink when plasmolysis occurs?", "images": ["Biology/imgs/2000/3XRHJ9.jpg"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "A", "explanation": "Plasmolysis is the process where cells lose water in a hypertonic solution, causing the cell membrane to pull away from the cell wall.  In the context of the diagram of stomata, the structure that will shrink during plasmolysis is the Guard Cells (I). Guard cells lose water and shrink, which causes the stomatal pore to close.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2000>19", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "Study the diagram below    The condition shown in the above diagram is due to", "images": ["Biology/imgs/2000/3XRHJ9.jpg"], "options": {"A": "conversion of starch to sugar", "B": "conversion of sugar to starch", "C": "excess water in structure labelled I", "D": "presence of carbondioxide in the structure labelled I"}, "answer": "A", "explanation": "Guard cells (labeled I) regulate the opening and closing of the stomatal pore by changing their turgidity. When guard cells take up water and become turgid, they swell, causing the stomatal pore to open. This turgidity and the associated opening of the stomatal pore can result from various factors, including:  -\tConversion of starch to sugar: This increases the osmotic potential within the guard cells, causing them to absorb water and become turgid.  -\tExcess water in the guard cells: This directly causes the guard cells to swell and the stomatal pore to open.    Given that the condition shown in the diagram is the open stomatal pore due to turgid guard cells, both options conversion of starch to sugar and excess water in structure labelled I are relevant. However, the physiological process starts with the conversion of starch to sugar, which leads to water uptake by the guard cells. Therefore, the most accurate primary cause is conversion of starch to sugar.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2000>20", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "Study the diagram below    Which of the following solution will induce the condition shown in the diagram?", "images": ["Biology/imgs/2000/3XRHJ9.jpg"], "options": {"A": "hypertonic solution", "B": "hypotonic solution", "C": "isotonic solution", "D": "distilled water"}, "answer": "B", "explanation": "The condition shown in the diagram, which is the opening of the stomatal pore due to the swelling of the guard cells, is induced when the guard cells become turgid. Turgidity occurs when water enters the guard cells, making them swell.    To induce turgidity in the guard cells, the surrounding solution must be less concentrated than the cytoplasm of the guard cells, leading to water moving into the cells by osmosis. Such a solution is a hypotonic solution.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2000>21", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "which of the following condition  will cause a decreasing body temperature?", "images": [], "options": {"A": "increased metabolism", "B": "shivering", "C": "vasoconstriction of capillaries of the skin", "D": "relaxation of erector muscles"}, "answer": "D", "explanation": "Relaxation of erector muscles will cause a decrease in body temperature. The erector muscles are tiny muscles that attach to the base of each hair follicle. When these muscles relax, the hairs lie flat on the skin which reduces the amount of heat trapped by the layer of air between the hairs. This allows more heat to be lost from the skin surface, thus lowering body temperature. The other options are incorrect because increased metabolism, shivering, and vasoconstriction of capillaries of the skin are all mechanisms that the body uses to increase body temperature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>22", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "The organs constantly in touch with the liver are", "images": [], "options": {"A": "pancreas, colon and caecum", "B": "duodenum and stomach", "C": "ileum, stomach and colon", "D": "stomach and gall bladder"}, "answer": "D", "explanation": "The liver is directly attached to the:  - Stomach: The liver is connected to the stomach by the hepatogastric ligament.  - Gall bladder: The gall bladder is attached to the liver and stores bile produced by the liver.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>23", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "Which of the following is responsible for the increased heart beat of a boy saw a python? increased production of", "images": [], "options": {"A": "adrenalin", "B": "insuline", "C": "pituitrin", "D": "thyroxin"}, "answer": "A", "explanation": "Adrenalin is usual relased in fight or flight mode sitution, in a simple language situation where you fight or run, and it is respondible for increse in heart rates and blood pressure beacause it involves symapathetic stimulation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>24", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "The nerve that arise from the brain are known as", "images": [], "options": {"A": "spinal nerve", "B": "secral nerve", "C": "cranial nerve", "D": "optic nerve"}, "answer": "C", "explanation": "The nerves that arise from the brain are known as cranial nerves. There are 12 pairs of cranial nerves that emerge directly from the brain, as opposed to spinal nerves which emerge from segments of the spinal cord. The cranial nerves serve a variety of functions including motor functions, transmitting sensory information, and controlling certain automatic functions like heart rate and digestion. The optic nerve mentioned in option 4 is actually one of the cranial nerves, but it's not the general term for nerves arising from the brain.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2000>25", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "The neuron that relay the message of effector organs are called", "images": [], "options": {"A": "efferent neurone", "B": "intermediate neurones", "C": "afferent neurones", "D": "spinal nerves"}, "answer": "A", "explanation": "Effector organs are the muscles or glands that respond to the neural signals from the brain or spinal cord. The neurons that carry these signals from the central nervous system to the effector organs are called efferent neurons. The term 'efferent' comes from Latin word 'effere' which means 'to carry away'. In the context of the nervous system, it refers to carrying signals away from the central nervous system.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2000>26", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "Each neuron consist of the following structures except", "images": [], "options": {"A": "cell body", "B": "dendrites", "C": "axon", "D": "white matter"}, "answer": "D", "explanation": "A neuron, or nerve cell, is a basic unit of the nervous system. It consists of a cell body (also known as soma), dendrites, and an axon. The cell body contains the nucleus and cytoplasm. Dendrites are branch-like structures that receive messages from other neurons. The axon is a long, tail-like structure that sends messages to other neurons. White matter, on the other hand, is not a part of the neuron but a type of tissue in the nervous system that contains bundles of axons. Therefore, the correct answer is 'white matter'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2000>27", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "The simplest form of neuron pathway which links receptors with effectors known as", "images": [], "options": {"A": "relay neuron", "B": "reflex arc", "C": "motor nerve", "D": "sensory nerve"}, "answer": "B", "explanation": "The simplest form of neuron pathway which links receptors with effectors is known as a reflex arc. A reflex arc is a neural pathway that controls a reflex action. In this pathway, an impulse from a receptor travels along a sensory neuron to the central nervous system, where it is passed on to a motor neuron that carries it to an effector. The effector then responds to the impulse. The relay neuron, motor nerve, and sensory nerve are all components of the reflex arc, but they do not represent the entire pathway.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>28", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "Which of the following parts of the eye is sensitive to light", "images": [], "options": {"A": "Retina", "B": "cornea", "C": "choroid layer", "D": "optic nerves"}, "answer": "A", "explanation": "The retina is the part of the eye that is sensitive to light. It is a thin layer of tissue that lines the back of the eye on the inside and is located near the optic nerve. The purpose of the retina is to receive light that the lens has focused, convert the light into neural signals, and send these signals on to the brain for visual recognition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>29", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "What happens to an ovule of a flower, after fetilization? it", "images": [], "options": {"A": "Becomes a fruit", "B": "withers away", "C": "becomes a seed", "D": "form the cotyledons"}, "answer": "C", "explanation": "After fertilization, the ovule of a flower develops into a seed. The ovule is the part of the ovary of the flower which, when fertilized by the pollen, becomes the seed. The seed is the reproductive unit of a flowering plant, capable of developing into another such plant. Therefore, the correct answer is 'becomes a seed'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>30", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following is not a dry indehiscent fruit?", "images": [], "options": {"A": "legume", "B": "cypsela", "C": "samara", "D": "caryopsis"}, "answer": "A", "explanation": "A dry indehiscent fruit is a type of fruit where the seeds are enclosed in a pericarp that does not split open at maturity to release the seeds. The options cypsela, samara, and caryopsis are all examples of dry indehiscent fruits. However, a legume is a type of dry dehiscent fruit, which means it splits open at maturity to release its seeds. Therefore, the correct answer is legume.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2000>31", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following group consist of only micro nutrients?", "images": [], "options": {"A": "molybdenum, sulphur and copper", "B": "boron, zinc and calcium", "C": "manganese, molybdenum and zinc", "D": "magnesium, phosphorus and mangnese."}, "answer": "C", "explanation": "Micronutrients are nutrients required in small quantities throughout life they contain manganes, molybdenum, selenium, zinc e.t.c while macronutrient are those required in  large amount. they include magnesium, calcium, soduim, phosphorus, sulphur, chloride. e.t.c", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>32", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The first stable product of photosynthesis is", "images": [], "options": {"A": "starch", "B": "glucose", "C": "oxygen", "D": "water"}, "answer": "B", "explanation": "The first stable product of photosynthesis is glucose. Photosynthesis is a process used by plants and other organisms to convert light energy into chemical energy that can later be released to fuel the organisms' activities. This chemical energy is stored in carbohydrate molecules, such as sugars, which are synthesized from carbon dioxide and water. The first stable product of this process is glucose, a simple sugar.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2000>33", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "which of the following statement about nitrogen is not correct? nitrogen is needed for", "images": [], "options": {"A": "protein synthesis", "B": "activating certain enzymes", "C": "the synthesis of chlorophyll", "D": "healthy vegetative growth of plants"}, "answer": "B", "explanation": "Nitrogen is required for the synthesis of the chlorophyll, nucleic acids, and enzymes.  NB: Nitrogen is essential for plants to synthesize amino acids, which are the building block for protein synthesis. But they are not used to acivated enzymes, they only takes parts in synthesis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>34", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "A very poor growth in plants and discolouration of leaves signifies the deficiency of", "images": [], "options": {"A": "calcium", "B": "magnesium", "C": "potassium", "D": "manganese"}, "answer": "B", "explanation": "The symptoms described in the question are indicative of a magnesium deficiency in plants. Magnesium is a vital component of chlorophyll, the molecule that gives plants their green color and is involved in photosynthesis. When a plant is deficient in magnesium, the chlorophyll breaks down, causing the leaves to discolor. None of the other options (calcium, potassium, manganese) would cause these specific symptoms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>35", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Vitamins C which is water soluble is", "images": [], "options": {"A": "cabalamine", "B": "pyridoxine", "C": "ascorbic acid", "D": "riboflavine"}, "answer": "C", "explanation": "Vitamin C is a water soluble vitamin an is also known as Ascorbic acids  N.B : vitamins can be fat or water soluble, fat soluble vitamins includes: vitamin A, D, E, K.  wile the others are water soluble i.e vitamin B and C", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2000>36", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Vitamin C deficiency result in", "images": [], "options": {"A": "ticket", "B": "beri-beri", "C": "scurvy", "D": "pellagra"}, "answer": "C", "explanation": "Vitamin C deficiency results in scurvy. Scurvy is a disease resulting from a lack of vitamin C (ascorbic acid). Early symptoms of deficiency include weakness, feeling tired, and sore arms and legs. Without treatment, decreased red blood cells, gum disease, changes to hair, and bleeding from the skin may occur. Beri-beri and pellagra are caused by deficiency of other vitamins, specifically Vitamin B1 and Niacin respectively. Ticket is not related to vitamin deficiency.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>37", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "members of the vitamin B complex are", "images": [], "options": {"A": "water-soluble", "B": "fat-soluble", "C": "water insoluble", "D": "generally insoluble"}, "answer": "A", "explanation": "The members of the vitamin B complex are water-soluble. This means they can dissolve in water and are not stored in the body. Any excess of these vitamins is excreted in urine. This is different from fat-soluble vitamins, which are stored in the body's fatty tissue and liver, and can stay in the body for days or even months.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2000>38", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Which of the statement about phosphorus is not correct ?", "images": [], "options": {"A": "helps to regulate the acid-based balance of the body", "B": "regulates the metabolism of protein, fats and carbohydrates", "C": "Required in many chemical occuring in the body", "D": "Phosphurous is major constitute of bones and teeth"}, "answer": "A", "explanation": "Phosphorus does not help to regulate the acid-base balance of the body. This is primarily the role of the kidneys and lungs. The kidneys excrete acids or bases into the urine to regulate the body's pH, while the lungs control the amount of carbon dioxide, a major acid, in the body. Phosphorus, on the other hand, is crucial for many body functions, including filtering out waste in the kidneys and managing how the body stores and uses energy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>39", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Vitamin E is concerned with", "images": [], "options": {"A": "bone formation", "B": "reproduction", "C": "normal growth", "D": "formation of red blood cells"}, "answer": "B", "explanation": "Function of vitamin E  1.Acts as an antioxidant  2. Helps protects cell from damage caused by free radicals  3.Helps maintain skin health  4. Helps in reproduction (because its deficiency leads to degeneration of germinal epithelium and leydig cells in seminiferous tubule)", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>40", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "A balance meal for an adult person may consist of", "images": [], "options": {"A": "two pieces of chicken, four balls of bean cake, two eggs and two cups of tea with milk", "B": "four slices of bread, one bowl of pap, two oranges and two bananas", "C": "four slices of yam and stew, two piece of beef, one cup of tea with milk and two oranges", "D": "a plates pf beans, two pieces of meat, two eggs, one cup of tea with milk and two oranges"}, "answer": "C", "explanation": "A balanced meal should contain a mix of proteins, carbohydrates, and fruits. Option 3 provides this balance. It has yam (carbohydrate), beef (protein), tea with milk (dairy), and oranges (fruits).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>41", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Which of the following food substance turn bright red when warmed with sudan III solution?", "images": [], "options": {"A": "starch", "B": "reducing sugar", "C": "protein", "D": "fat"}, "answer": "D", "explanation": "Sudan III is a lipid soluble dye that is used to identify lipids, triglycerides, and lipoproteins in liquids. It stains these substances red. Therefore, when a food substance is warmed with Sudan III solution, it is the fat (lipid) in the food that will turn bright red.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>42", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "mammals required a relatively high amount of carbonhydrate because", "images": [], "options": {"A": "They maintain the weight of the body", "B": "they are required for growth", "C": "they initiate enzymes production", "D": "they yield energy for activities"}, "answer": "D", "explanation": "Mammals require a relatively high amount of carbohydrates because they yield energy for activities. Carbohydrates are the body's main source of energy. They are broken down into glucose, which can be used by the body cells for energy. This energy is used for various activities such as movement, growth, repair, and other metabolic activities. The other options are not entirely correct because carbohydrates do not directly maintain body weight, initiate enzyme production, or are required for growth. These processes may require energy derived from carbohydrates, but they are not the direct functions of carbohydrates.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>43", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "All the available places on earth which support life constitute the", "images": [], "options": {"A": "lithospere", "B": "atmosphere", "C": "biosphere", "D": "hydrosphere"}, "answer": "C", "explanation": "The biosphere is the global sum of all ecosystems. It can also be termed the zone of life on Earth, a closed system (apart from solar and cosmic radiation and heat from the interior of the Earth), and largely self-regulating. By the most general biophysiological definition, the biosphere is the global ecological system integrating all living beings and their relationships, including their interaction with the elements of the lithosphere, geosphere, hydrosphere, and atmosphere. Therefore, all the available places on earth which support life constitute the biosphere.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2000>44", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "The abiotic factor which determines the depth to which light penetrates in pond is", "images": [], "options": {"A": "current", "B": "turbidity", "C": "wind", "D": "salinity"}, "answer": "B", "explanation": "Turbidity is the cloudiness or the property of water that makes the intensity of light passing through it reduced due to the presence of different particles that makes it unclear", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>45", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : PRODUCERS", "question": "Which of the folloing organism is a producer?", "images": [], "options": {"A": "spirogyra", "B": "mucor", "C": "Rhizopus", "D": "yeast"}, "answer": "A", "explanation": "In the context of biology, a producer, also known as an autotroph, refers to an organism that can produce its own food. This is typically done through photosynthesis, where the organism uses sunlight, water, and carbon dioxide to create glucose, a type of sugar that the organism uses for energy. Spirogyra, a type of green algae, is capable of photosynthesis, making it a producer. The other options, Mucor, Rhizopus, and yeast, are all types of fungi, which are heterotrophs, not producers. Heterotrophs cannot produce their own food and instead obtain their energy by consuming other organisms or organic material.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2000>46", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : PRODUCERS", "question": "Which of the following organism organism is  not a producer?", "images": [], "options": {"A": "Mucor, chlamydomonas and euglena", "B": "spirogyra, mucor and mushroom", "C": "man, mucor and mushroom", "D": "man, maize and cowpea"}, "answer": "C", "explanation": "Producers, also known as autotrophs, are organisms that can produce their own food from the substances available in their surroundings using light (photosynthesis) or chemical energy (chemosynthesis). In the given options, 'man, mucor and mushroom' are not producers. Man is a consumer, it cannot produce its own food. Mucor and mushrooms are fungi, which are decomposers, not producers. They obtain their nutrients by breaking down dead organic material.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>47", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : DECOMPOSERS", "question": "Which of the following organism will not bring about decomposition?", "images": [], "options": {"A": "Earthworm", "B": "bacterium", "C": "mould", "D": "spirogyra"}, "answer": "D", "explanation": "Decomposition is the process by which organic substances are broken down into simpler organic matter. The process is a part of the nutrient cycle and is essential for recycling the finite matter that occupies physical space in the biosphere. Organisms that bring about decomposition are known as decomposers. These include bacteria, fungi (like mould), and invertebrates such as earthworms. Spirogyra, however, is a type of green algae that is not involved in the process of decomposition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>48", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : DECOMPOSITION", "question": "Which of the following is not released during decay of living matter?", "images": [], "options": {"A": "ammonia", "B": "oxygen", "C": "carbon dioxide", "D": "heat energy"}, "answer": "B", "explanation": "During the decay of living matter, the process of decomposition by bacteria and fungi occurs. These microorganisms break down the complex organic substances into simpler substances. In this process, ammonia is released from the nitrogenous substances, carbon dioxide from the carbohydrates, and heat energy is also released due to the exothermic nature of the process. However, oxygen is not released during decay. Instead, it is used up by the decomposers during the process of decomposition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>49", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS", "question": "In commensalism", "images": [], "options": {"A": "one of the organism gains and other loses", "B": "both organism benefits from the association", "C": "one of the organism gains while the other neither gains nor loses", "D": "one of the organism produces extra cellular digestive juices"}, "answer": "C", "explanation": "Commensalism is a type of symbiotic relationship between two different species where one species benefits and the other is neither harmed nor benefited. Therefore, the correct answer is 'one of the organism gains while the other does not gain'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>50", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS", "question": "Parasitism can best be defined as an association between two organism in which", "images": [], "options": {"A": "both organism benefit", "B": "one organis gains and other neither gains or loses", "C": "both organisms suffer some disadvantages", "D": "one  organism gains and the other loses"}, "answer": "D", "explanation": "Parasitism is a type of symbiotic relationship between two organisms where one organism, the parasite, benefits at the expense of the other, the host. The parasite derives benefits by living either inside or on the host organism, which is harmed by the relationship. Therefore, the correct answer is 'one organism gains and the other loses'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>51", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following best describe the adaptation of the earthworm  to its habitat?", "images": [], "options": {"A": "Living in burrow during the day to prevent dessication", "B": "Burrowing into soft groud to store food", "C": "possesion of segemented body to reduce movement", "D": "possesion of a few bristles for defence"}, "answer": "A", "explanation": "Earthworm burrows through soil during the day to prevent dessication i.e drying in an organism or moisture loss  * dessication is the loss of moisture in an organism", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>52", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : CARRIERS OF MICROORGANISMS", "question": "Trypanosomiasis is associated with", "images": [], "options": {"A": "cockroach", "B": "mosquito", "C": "housefly", "D": "tsetse fly"}, "answer": "D", "explanation": "Trypanosomiasis, also known as sleeping sickness, is a disease caused by a parasite called Trypanosoma, which is transmitted to humans through the bite of a tsetse fly. Therefore, the correct answer is 'tsetse fly'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2000>53", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH", "question": "The major reasons why foods should be properly covered is that", "images": [], "options": {"A": "micro-organism in air would contaminate the food", "B": "hot food cool off easily when properly covered", "C": "the taste of the food is maintined when covered", "D": "all water easily evapourated from covered food"}, "answer": "A", "explanation": "The major reason why food should be properly covered is to prevent contamination from microorganisms in the air. Microorganisms are tiny living organisms, such as bacteria and fungi, that can be carried by air. When they land on food, they can multiply and cause foodborne illnesses. Therefore, covering food helps to reduce the risk of these illnesses. The other options do not accurately represent the primary reason for covering food. While covering food may help to maintain its temperature and taste, and prevent evaporation, these are not the main reasons for covering food. The main reason is to prevent contamination from microorganisms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>54", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Which of the foolowing is not a means of conserving natural resource?", "images": [], "options": {"A": "Establishmenr of national parks", "B": "selective logging", "C": "building of dams", "D": "bush burning"}, "answer": "D", "explanation": "Conservation of natural resources involves the sustainable use and management of natural resources including wildlife, water, air, and earth deposits. Options 1, 2 and 3 are all methods of conserving natural resources. National parks protect wildlife and their habitats. Selective logging ensures that only some trees are cut down, allowing the forest to naturally regenerate over time. Building of dams helps in water conservation. However, bush burning destroys habitats and leads to loss of biodiversity, hence it is not a means of conserving natural resources.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>55", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "Which of the following resource is non-renewable?", "images": [], "options": {"A": "forest", "B": "wildfire", "C": "mineral deposits", "D": "water"}, "answer": "C", "explanation": "A non-renewable resources is a natural resources that cannot be readily replaced by natural means at a quick enough pace to keep up with consumption e.g mineral deposit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2000>56", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "A character which fails to express itself in the first filial generation but emerges in the second is", "images": [], "options": {"A": "heterozygote", "B": "homozygote", "C": "dominant", "D": "recessive"}, "answer": "D", "explanation": "A recessive trait cannot express itself in the presence of a dominant trait. Hence though it is present in the first filial generation it cannt be expressed    The t can only be expressed as shortness when is tt, it cannot express itself when we have Tt.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>57", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "The concept of use and disuse of parts was postulated by", "images": [], "options": {"A": "Darwin", "B": "lamarck", "C": "miller", "D": "wallace"}, "answer": "B", "explanation": "The concept of use and disuse, also known as Lamarckism, was postulated by Jean-Baptiste Lamarck. According to this theory, an organism can change during its lifetime in response to its environment, and those changes are then passed onto its offspring. For example, he proposed that the long neck of a giraffe evolved over time as giraffes stretched their necks to reach leaves higher in the trees. Although this theory has been largely discredited in favor of Darwin's theory of natural selection, it was an important early contribution to the study of evolution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>58", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY", "question": "Which of the following represent mendel's second law of inheritance? The factor for two pairs of contrasting charaters are", "images": [], "options": {"A": "dependent on each other", "B": "on homologous chromosomes", "C": "allelomorphic", "D": "inherited independently of each other"}, "answer": "D", "explanation": "According to mendel's second law also known as the law of independent assortment of gene  The factor for two pair of contrasting charater are inerited independently of each other", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2000>59", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "which of the following terms is not associated with fingerprint and classification?", "images": [], "options": {"A": "whorl", "B": "contour", "C": "arch", "D": "loop"}, "answer": "B", "explanation": "In the context of fingerprint classification, the terms 'whorl', 'arch', and 'loop' are all types of fingerprint patterns. 'Whorl' is a pattern where the ridges form circularly around a central point. 'Arch' is a pattern where the ridges enter from one side, rise in the center forming an arc, and then exit the other side of the finger. 'Loop' is a pattern where the ridges enter from one side, loop around, and exit from the same side they entered. However, 'contour' is not associated with fingerprint classification. It is a term used in topography to describe the shape of a landscape or a surface.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2000>60", "subject": "Biology", "year": "2000", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "During blood transfusion, agglutination could be prevented if a patient having blood group O is given blood from group", "images": [], "options": {"A": "AB", "B": "A", "C": "O", "D": "B"}, "answer": "C", "explanation": "Blood group O can recieve blood from an individual with blood group O.   Note:  Donor-recipient comatibility in blood transfusion  Group can donate to can recieve fromA A and AB A and OB B and AB B and OAB AB All groupsO All groups O", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>1", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "which of the following indictes that Euglena is a plant?", "images": [], "options": {"A": "cospicuous 'eye' spot", "B": "presence of gullet", "C": "limited movement", "D": "presence of starch grains"}, "answer": "D", "explanation": "Euglena is a unique organism that shows characteristics of both plants and animals. The presence of starch grains in Euglena indicates that it is a plant because starch is a carbohydrate storage product found in plants. Euglena can photosynthesize like plants and store the resulting glucose as starch.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2001>2", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following is a tissue?", "images": [], "options": {"A": "volvox", "B": "chlamydomonas", "C": "epidermis", "D": "paramecium"}, "answer": "C", "explanation": "A tissue is a group of cells that work together to perform a specific function. In this case, the epidermis is a type of tissue. It is the outermost layer of cells that covers an organism, for example, it is the outermost layer of the skin in animals. On the other hand, Volvox and Chlamydomonas are types of green algae, and Paramecium is a type of single-celled organism (protozoan), none of which are tissues.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2001>3", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Use the diagram below to answer questions      The structure that produces ATP is labelled", "images": ["Biology/imgs/2001/KD6NAK.jpg"], "options": {"A": "VII", "B": "V", "C": "VI", "D": "I"}, "answer": "A", "explanation": "Label VII corresponds to the mitochondrion, recognizable by its distinct oval shape and internal structure. The mitochondrion (labelled VII) is the powerhouse of the cell, where cellular respiration occurs, and ATP is generated through the process of oxidative phosphorylation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>4", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Use the diagram below to answer questions    The structure labelled V is the", "images": ["Biology/imgs/2001/KD6NAK.jpg"], "options": {"A": "cell wall", "B": "nucleus", "C": "endoplasmic reticulum", "D": "mitochondrion"}, "answer": "A", "explanation": "Based on the provided diagram, label V is situated towards the cell's perimeter, which suggests it is a part of the cell's boundary structure. Given its location and appearance: The correct answer is cell wall. Label V corresponds to the thick outer boundary, characteristic of a cell wall, which provides structural support and protection to plant cells.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>5", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The major function of the cell membrane is that it", "images": [], "options": {"A": "delimits the cytoplasm", "B": "synthesize protein", "C": "breaks down worn-out organelles", "D": "is the site for photosynthesis"}, "answer": "A", "explanation": "Cell membrane helps to regulate the passage of substance in and out of the cells, hence it can be said to be delimit the cytoplasm  Delimit this marks the limit of something, or fix the limit of something   The cytoplasmic /cell membrane hence fix or determines the limites of cytoplasm", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2001>6", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : PROPERTIES AND FUNCTIONS OF THE LIVING CELL", "question": "carbonhydrates are stored in the animals cell in the form of", "images": [], "options": {"A": "starch", "B": "glycogen", "C": "plastid", "D": "maltose"}, "answer": "B", "explanation": "In animals, carbohydrates are stored in the form of glycogen. Glycogen is a polysaccharide that the body can easily convert back into glucose when needed for energy. Starch is the form in which plants store carbohydrates, not animals. Plastids are organelles found in plant cells, not a form of carbohydrate storage. Maltose is a type of sugar, not a storage form of carbohydrates.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2001>7", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "A piece of yam weighing 1.0gm was put into some salt solution. After 3 hours, it removed and weighed. the recorded weight was 1.2 gms. The simple experiment demonstrates that the", "images": [], "options": {"A": "salt solution is more concentrated that the cell sap of the yam", "B": "cell sap of the yam is more concentrated than salt solution", "C": "salt solution has same concentration as the cell sap of the yam", "D": "the yam lost some water molecules to the salt soution"}, "answer": "B", "explanation": "The yam gained weight after being placed in the salt solution, which indicates that water molecules moved from the salt solution into the yam. This is a process known as osmosis, where water molecules move from an area of lower concentration to an area of higher concentration. In this case, the cell sap of the yam must have been more concentrated than the salt solution, causing water to move into the yam to try and balance the concentrations. Therefore, the correct answer is that the cell sap of the yam is more concentrated than the salt solution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>8", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "A major reason why red blood cell can survive in the blood is that the", "images": [], "options": {"A": "blood plasma and red blood cell are isotonic", "B": "red blood cells are hypotonic to the plasma", "C": "the red blood cell are hypotonic to the blood plasma", "D": "te red blood cells recieve digested nutrients"}, "answer": "A", "explanation": "Red blood cells can survive in the blood because the blood plasma and red blood cells are isotonic. This means that the concentration of solutes is the same inside and outside the cells, which prevents water from moving across the cell membrane by osmosis. If the red blood cells were hypotonic to the plasma, they would take in too much water and burst. On the other hand, if they were hypertonic, they would lose water and shrink. Therefore, isotonic conditions are necessary for the survival of red blood cells.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>9", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Which of the following phenomena affects plants growth in an alkaline soil?", "images": [], "options": {"A": "excessive plasmolysis", "B": "excessive transpiration", "C": "Excessive sunlight", "D": "poor drainage"}, "answer": "D", "explanation": "Acidity or alkalinity of the soil can cause water logging and the poor drainage of th soil.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>10", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "A red blood cell haemolyses when placed in the hypotonic solution because", "images": [], "options": {"A": "it contains haemoglobin", "B": "the cytoplasm is less dense", "C": "the cell lack a wall", "D": "is pigment has a high affinity for water"}, "answer": "D", "explanation": "RBC hemolyses when placed in the hypotonic solution because its pigment has a high affinity for water. Hemoglobin, the protein in red blood cells that carries oxygen, has a high affinity for water. When an RBC is placed in a hypotonic solution, water rushes into the cell to equalize the concentration. Hemoglobin's high affinity for water means that it will absorb water, causing the cell to swell and eventually burst (hemolyze).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>11", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which of the following structures are visible in the cell of a plant during mitosis?", "images": [], "options": {"A": "centrioles, chromatids and molecules", "B": "Homologous , chromosomes, nuclear membrane and spindle fibre", "C": "cell wall, centrioles and chromatids", "D": "chromosomes, nuclear membrane and centromere"}, "answer": "D", "explanation": "During mitosis, the chromosomes, nuclear membrane, and centromere are visible in a plant cell. The chromosomes condense and become visible, the nuclear membrane dissolves to allow the chromosomes to separate, and the centromere is the part of the chromosome where the spindle fibers attach to pull the chromosomes apart. - Chromosomes are indeed visible during mitosis (as sister chromatids).  - Nuclear membrane is visible, although it breaks down and reforms.  - Centromere is a region on the chromosome that becomes visible during mitosis, specifically during metaphase.    Other options are incorrect:   Centrioles, chromatids, and nucleolus:  - Centrioles are not found in plant cells.  - Nucleolus is not typically visible during mitosis.  Homologous chromosomes, nuclear membrane, and spindle fibers:  - Homologous chromosomes are not visible during mitosis (they're paired up during meiosis).  Cell wall, centrioles, and chromatids:  - Centrioles are not found in plant cells.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2001>12", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Display is a phenomenon which occurs when animal is", "images": [], "options": {"A": "ready for mating", "B": "fighting to defend itself", "C": "approaching puberty", "D": "chasing away an intruder"}, "answer": "A", "explanation": "Display in animals is a set of complex behaviors, such as visual signals, sounds, and movements, that are used primarily to attract a mate. Therefore, it occurs when an animal is ready for mating.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2001>13", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The advantages of sexual reproduction include following except", "images": [], "options": {"A": "it allows the formation of new species", "B": "it allow production of desirable traits", "C": "it permits variation of individuals", "D": "it provides means for the variation of chromosomes number from generation to generation"}, "answer": "D", "explanation": "Sexual reproduction does not provide a means for the variation of chromosome number from generation to generation. The number of chromosomes in a species remains constant from generation to generation due to sexual reproduction. This is because during sexual reproduction, the gametes (sperm and egg cells) undergo a special type of cell division called meiosis, which ensures that the number of chromosomes is halved. Therefore, when the sperm and egg combine during fertilization, the original number of chromosomes is restored. This ensures that the number of chromosomes remains constant from one generation to the next.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>14", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following groups contains a non-supporting structure in animals", "images": [], "options": {"A": "cartilage, bone and pseudopodia", "B": "pellicle, chitin and bone", "C": "humerus,ribs and cartilage", "D": "fermur, pellicle and chitin"}, "answer": "B", "explanation": "The correct answer is 'pellicle, chitin and bone'. In this option, pellicle is a non-supporting structure in animals. Pellicle is a thin layer supporting the cell membrane in various protozoa. It provides protection but does not provide structural support like bones or cartilage. Chitin and bone, on the other hand, are supporting structures. Chitin is a long-chain polymer of a N-acetylglucosamine, a derivative of glucose, and is found in many places throughout the natural world. It is a characteristic component of the cell walls of fungi, the exoskeletons of arthropods such as crustaceans and insects, the radulae of mollusks, and the beaks and internal shells of cephalopods. Bone is a rigid organ that constitutes part of the vertebrate skeleton in animals. Bones protect the various organs of the body, produce red and white blood cells, store minerals, provide structure and support for the body, and enable mobility.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>15", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of the following statement is true about blood grouping?", "images": [], "options": {"A": "Group AB can denote blood to all groups", "B": "Group O are universal recipients", "C": "Group A has A antigen in its plasma", "D": "Group O has no antigen"}, "answer": "D", "explanation": "Blood group O has neither A nor B antigens on the surface of the red blood cells but does have both A and B antibodies in the blood plasma.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>16", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "Which of the following is not constituent of blood plasma", "images": [], "options": {"A": "protein", "B": "mineral salt", "C": "water", "D": "platelet"}, "answer": "D", "explanation": "Blood plasma is a yellowish liquid component of blood that holds the blood cells in whole blood in suspension. It is the liquid part of the blood that carries cells and proteins throughout the body. It makes up about 55% of the body's total blood volume. It is composed of water (90%), proteins, and mineral salts. Platelets, however, are not a constituent of blood plasma, they are a component of the blood itself. Therefore, the correct answer is 'platelet'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2001>17", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The process by which plants convey food material to different part of the body is called", "images": [], "options": {"A": "nutrition", "B": "absorption", "C": "circulation", "D": "translocation"}, "answer": "D", "explanation": "The process by which plants convey food material to different parts of the body is called translocation. Translocation in plants is the process where products of photosynthesis (sugar, amino acids, etc.) are transported from 'source' tissues (like leaves) to 'sink' tissues (the parts of the plant where the nutrients are needed or stored). This is different from nutrition (the process of obtaining food necessary for health and growth), absorption (the process by which nutrients are taken up by the plant's roots from the soil), and circulation (a term more commonly used in animal biology to describe the movement of blood through the body).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>18", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Which part of the gill of fish involved in gaseous exchange?", "images": [], "options": {"A": "gilt silts", "B": "gill bars", "C": "gill cover", "D": "gill filament"}, "answer": "D", "explanation": "The gill filament is the part of the gill of fish involved in gaseous exchange. Gaseous exchange in fish occurs through the gill filaments. These are thin structures that have a large surface area to allow for the efficient exchange of gases. Oxygen from the water diffuses into the blood in the gill filaments, while carbon dioxide diffuses out from the blood into the water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>19", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : MICROORGANISMS: MAN AND HIS HEALTH.", "question": "Which of the following is not a product of fermentation of glucose", "images": [], "options": {"A": "Energy", "B": "Alcohol", "C": "lactic acid", "D": "carbon dioxide"}, "answer": "A", "explanation": "Energy is not a product of the fermentation of glucose but rather a result or outcome of the process. During fermentation, glucose is metabolized to produce substances such as alcohol, lactic acid, and carbon dioxide, depending on the type of fermentation. The energy released during this process is in the form of ATP, which cells use for various functions. However, energy itself is not a substance or product of fermentation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>20", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Which of the following pair of structure does not perform similar functions?", "images": [], "options": {"A": "lungs and spiracles", "B": "Root hair and mammalian hair", "C": "feathers and scales", "D": "contractile vacuole"}, "answer": "B", "explanation": "Root hair: a small finger-like projection of cells near the tip of root that are important is mineral uptake   mammalian hair does not function in mineral uptake", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>21", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "The effect of the contraction of the muscles of the diaphragm is that", "images": [], "options": {"A": "The volume of the thoracic cavity increase", "B": "more carbon dioxide is expelled through the nostrils", "C": "rib cage is drawn inwards", "D": "the intercostal muscle becomes relaxed"}, "answer": "A", "explanation": "The diaphragm is a dome-shaped muscle located at the base of the lungs. When it contracts, it flattens and moves downward, increasing the volume of the thoracic cavity, which allows the lungs to expand and fill with air.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>22", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which of the following is an excretory product of Amoeba?", "images": [], "options": {"A": "urea", "B": "Ammonia", "C": "uric acid", "D": "amino acid"}, "answer": "B", "explanation": "Amoeba, being a unicellular organism, excretes waste products directly into the environment by the process of diffusion. The primary excretory product of Amoeba is Ammonia. Ammonia is a nitrogenous waste product formed due to the metabolism of proteins. It is highly soluble in water and is toxic. Therefore, it needs to be eliminated from the body quickly. In the case of Amoeba, it diffuses out of the cell into the surrounding water.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2001>23", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "Which of the followings processes occurs when the body temperature of mammal rises above the normal?  I. The arterioles in the skin dilate  II. Sweat production is reduced  III. The erector muscles contract", "images": [], "options": {"A": "I only", "B": "II only", "C": "I and III only", "D": "II and III only"}, "answer": "A", "explanation": "Whe the body temperature of a mammal rises above normal, these occur   - The arterioles of the skin dilate  -Sweat production increase  - Erector muscles relax", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>24", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS AND MECHANISMS", "question": "The following function are associated with the liver except", "images": [], "options": {"A": "regulation of blood sugar", "B": "production of heat", "C": "production of fibrinogen", "D": "production of vitamin D"}, "answer": "B", "explanation": "The liver is primarily responsible for the following functions:  -\tRegulation of blood sugar: The liver helps maintain blood glucose levels by storing glycogen and releasing glucose as needed.  -\tProduction of fibrinogen: The liver synthesizes fibrinogen, which is an essential protein for blood clotting.  -\tProduction of vitamin: The liver stores and metabolizes various vitamins, including vitamin A, D, E, and K.    However, the production of heat is not a primary function of the liver. While the liver does generate some heat as a byproduct of its metabolic processes, it is not specifically responsible for the regulation or production of heat in the body. This is a function more directly associated with muscle activity and overall metabolism.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>25", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "Short-sight could be corrected with the use of", "images": [], "options": {"A": "convex lens", "B": "cylindrical lens", "C": "concave lens", "D": "bifocal lens"}, "answer": "C", "explanation": "Short-sightedness, also known as myopia, is a common vision condition in which you can see objects near to you clearly, but objects farther away are blurry. It occurs when the shape of your eye causes light rays to bend (refract) incorrectly, focusing the images in front of the retina instead of directly on the retina. A concave lens is used to correct this condition. The lens spreads out the light rays so that they can come to a point further back in the eye, right on the retina. This allows the person to see distant objects clearly.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2001>26", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following statement about the maize grain is not correct? it", "images": [], "options": {"A": "undergoes hypogeal germination", "B": "is a fruit", "C": "is non-endospermous", "D": "has pericarp fused with testa"}, "answer": "C", "explanation": "Maize is an endospermous seed. In endospermous seeds, the endosperm is retained within the seed and the embryo utilizes the stored food in the endosperm during germination. Other options are correct. Maize undergoes hypogeal germination where the cotyledons remain underground. It is a fruit because in botanical terms, a fruit is the mature ovary of a flower. The pericarp of maize is indeed fused with the testa, forming a structure known as the caryopsis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>27", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "In mammals, fertilization usually occur in the?", "images": [], "options": {"A": "cervix", "B": "vagina", "C": "uterus", "D": "oviduct"}, "answer": "D", "explanation": "In mammals, fertilization usually occurs in the oviduct, also known as the fallopian tube. This is where the sperm meets the egg. The cervix, vagina, and uterus are parts of the female reproductive system, but they are not the sites of fertilization.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2001>28", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "Which of the following vertebrates incubates their eggs", "images": [], "options": {"A": "mammals", "B": "birds", "C": "amphibians", "D": "Reptiles"}, "answer": "B", "explanation": "Birds are known to incubate their eggs. Incubation refers to the process by which certain oviparous (egg-laying) animals hatch their eggs; it involves the maintenance of the fertile eggs within a certain temperature range for a certain period. Birds do this by sitting on their eggs. Mammals do not lay eggs, with the exception of monotremes like the platypus and echidna. Amphibians and reptiles lay eggs, but they do not typically incubate them in the same way birds do.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2001>29", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following is an agent of pollination of grasses?", "images": [], "options": {"A": "insect", "B": "water", "C": "wind", "D": "mammals"}, "answer": "C", "explanation": "Grasses are typically pollinated by wind. This type of pollination is known as anemophily. Grasses have light, dry pollen that can be easily carried by the wind. They also have feathery or plumose stigmas to catch the wind-borne pollen. This is why wind is the correct answer and not insects, water, or mammals.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2001>30", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The spinnerets found in the caterpillars of butterfly is used for", "images": [], "options": {"A": "protection against predators", "B": "feeding on vegetation", "C": "movement on twigs", "D": "production of silk thread"}, "answer": "D", "explanation": "Spinnerets in caterpillars are specialized organs that are used for the production of silk thread. This silk thread is used by the caterpillar to form a cocoon during its pupal stage. Therefore, the correct answer is 'production of silk thread'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2001>31", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The diagram below is transverse section of a leaf.      carbon dioxide enter the leaf through the structure labelled.", "images": ["Biology/imgs/2001/C6TTB6.jpg"], "options": {"A": "I", "B": "II", "C": "IX", "D": "X"}, "answer": "C", "explanation": "\"IX\" corresponds to the air space directly connected to the stoma, it is correct to state that carbon dioxide enters the leaf through the stoma itself, but for practical purposes in the diagram, this might be indicated as the air space", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>32", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The diagram below is transverse section of a leaf.    Manufactured food is transported from the leaves through the structure labelled", "images": ["Biology/imgs/2001/C6TTB6.jpg"], "options": {"A": "IV", "B": "V", "C": "VI", "D": "VII"}, "answer": "B", "explanation": "The Part labeled V is the Phloem. Phloem transports organic compounds like sugars, amino acids, and hormones produced by photosynthesis from the leaves to other parts of the plant.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>33", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The diagram below is transverse section of a leaf.    The pallisade cells are the structure labelled", "images": ["Biology/imgs/2001/C6TTB6.jpg"], "options": {"A": "III", "B": "IV", "C": "VI", "D": "VIII"}, "answer": "A", "explanation": "The pallisade cells are the structure labelled III  -\tMesophyll: The inner tissue of the leaf where photosynthesis occurs.  -\tPalisade mesophyll*: The upper layer of mesophyll with tightly packed cells containing chloroplasts.  -\tStomata: Small openings on the underside of the leaf that allow for gas exchange (CO2 in, O2 out).  Others include:   -\tGuard cells: Specialized cells that surround and regulate the stomata.  -\tEpidermis:  The outer layer of the leaf, covering both the upper and lower surfaces.   Cuticle: A thin, waxy layer on the epidermis that prevents water loss.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>34", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The diagram below is transverse section of a leaf.    which of the groups of structure listed below contains chloroplast?", "images": ["Biology/imgs/2001/C6TTB6.jpg"], "options": {"A": "I, II and III", "B": "II,III and VII", "C": "III, VIII and IX", "D": "III,VIII and XI"}, "answer": "D", "explanation": "The structure III, VIII and XI contains chloroplast", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>35", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "In which of the following processes is light energy converted to ATP?", "images": [], "options": {"A": "Osmosis", "B": "Transpiration", "C": "chemosynthesis", "D": "photosynthesis"}, "answer": "D", "explanation": "Photosynthesis is the process by which green plants and some other organisms use sunlight to synthesize foods with the help of chlorophyll pigments. During this process, light energy is converted to ATP (Adenosine Triphosphate), which is a form of energy that cells can use. Therefore, the correct answer is photosynthesis.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2001>36", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "The correct equation for photosynthesis is", "images": ["Biology/imgs/2001/v91.png", "Biology/imgs/2001/v92.png", "Biology/imgs/2001/v93.png", "Biology/imgs/2001/v94.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "C", "explanation": "6CO2 + 6H2O---sunlight/chlorophyll→C6H12O6 + 6O2 is the equation for photosynthesis", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>37", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "Which of the following is an evidence of photosynthesis?", "images": [], "options": {"A": "Aborption of light", "B": "formation of starch", "C": "Availabilty of carbon dioxide", "D": "splittting of water molecules"}, "answer": "B", "explanation": "Photosynthesis is a process used by plants and other organisms to convert light energy into chemical energy that can later be released to fuel the organisms' activities. One of the main products of photosynthesis is starch, a carbohydrate that plants use for energy storage. Therefore, the formation of starch is a direct evidence of photosynthesis.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2001>38", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : MICROORGANISMS: MAN AND HIS HEALTH.", "question": "Which of the following organisms is a chemo-autroph?", "images": [], "options": {"A": "Virus", "B": "Bacteria", "C": "paramecium", "D": "Euglena"}, "answer": "B", "explanation": "Chemoautotrophs are organisms that use inorganic molecules as a source of energy. They are able to make their own food, but unlike plants (which are phototrophs), they do not use sunlight as their energy source. Instead, they use the energy from chemical reactions, often involving inorganic molecules such as hydrogen sulfide or ammonia. Bacteria are a prime example of chemoautotrophs. Viruses, paramecium, and euglena are not chemoautotrophs. Viruses are not even considered living organisms by many scientists. Paramecium and euglena are both types of protists, and they are heterotrophs, not autotrophs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>39", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Turgidity in the cell of plant does not easily lead to bursting of the cell because the", "images": [], "options": {"A": "cell membrane can resist the turgidity", "B": "large vacuole contained in the cell, can continuously take in water", "C": "cellulose cell wall can resist the turgidity", "D": "cytoplasm is jelly-like"}, "answer": "C", "explanation": "Turgidity in plant cells does not easily lead to bursting because the cellulose cell wall can resist the turgidity. Turgidity refers to the state of being swollen due to high fluid content. In the context of plant cells, this is often due to water entering the cell by osmosis. The cellulose cell wall of plant cells is rigid and provides structural support, preventing the cell from bursting even when it is turgid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>40", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "magnesium is need by plants for", "images": [], "options": {"A": "protein synthesis", "B": "formulation of cell membrane", "C": "activation of enzymes", "D": "formation of chlorophyll"}, "answer": "D", "explanation": "Magnesium is needed by plants for the formation of chlorophyll. Chlorophyll is the pigment that gives plants their green color and is crucial for photosynthesis, the process by which plants convert light energy into chemical energy. Magnesium is a central atom in the chlorophyll molecule, and without it, plants cannot produce chlorophyll.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>41", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "which of the following is not a micronutrient?", "images": [], "options": {"A": "maganese", "B": "copper", "C": "potassium", "D": "zinc"}, "answer": "C", "explanation": "Micronutrients are nutrients required by organisms in small quantities for proper growth and development. They include vitamins and trace minerals. The options given are all minerals. However, potassium is not a micronutrient but a macronutrient. Macronutrients are nutrients required in larger quantities. They include carbohydrates, proteins, fats, and certain minerals like potassium, nitrogen, and phosphorus. Therefore, potassium is not a micronutrient.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2001>42", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "loam is the best type of soil for crop production because", "images": [], "options": {"A": "it has a high percentage of clay which prevent leaching", "B": "it has humus content", "C": "it porous and has good-water retention capacity", "D": "gravels which obstruct implements are absent from it"}, "answer": "B", "explanation": "Loam is the best type of soil for ceop production because it has high humus content.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>43", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "The mineral needed for the formlation of haemoglobin is", "images": [], "options": {"A": "magnesium", "B": "iron", "C": "phosphorus", "D": "calcium"}, "answer": "B", "explanation": "Haemoglobin is a protein in red blood cells that carries oxygen throughout the body. Iron is a key component in the formation of haemoglobin. It is the iron in haemoglobin that gives blood its red color. When there is not enough iron, the body can't produce enough of a substance in red blood cells that enables them to carry oxygen (hemoglobin). As a result, iron deficiency anemia may leave you tired and short of breath.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2001>44", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "A person who fails to detects the bitter taste of a substance swallowed, is more likely to have", "images": [], "options": {"A": "dead taste buds on the tongue", "B": "avoided the substance from contacting the back of his/her tongue", "C": "fewer taste bud on the tongue", "D": "swallowed the substance without any water"}, "answer": "C", "explanation": "The bitter taste sensation is located at the back of the tongue   \"fewer taste buds on the tongue.\" This option suggests that the person may have fewer functional taste buds, which could indeed lead to reduced ability to perceive tastes like bitterness. If a person has fewer taste buds or if their taste buds are not functioning properly (due to reasons such as age, health conditions, or genetic factors), they may have difficulty detecting certain tastes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>45", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Which of the following solution is suitable for removing chlorophyll in a green leaf?", "images": [], "options": {"A": "million reagent", "B": "methylated spirit", "C": "Benedict solution", "D": "fehlings's solution"}, "answer": "B", "explanation": "Methylated spirit is used to remove chlorophyll from a green leaf. Chlorophyll is the pigment that gives plants their green color and is involved in photosynthesis. Methylated spirit, also known as denatured alcohol, is used in this process because it can dissolve chlorophyll without damaging the leaf's structure. The other options listed, Million's reagent, Benedict's solution, and Fehling's solution, are all used in various chemical tests but are not suitable for removing chlorophyll.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>46", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Which of the following is not promoted by wind speed?", "images": [], "options": {"A": "Rill erosion", "B": "weathering of parent rock", "C": "Breeding of plant", "D": "opening of stomata"}, "answer": "C", "explanation": "Wind speed does not promote the breeding of plants. Wind speed can influence erosion, weathering of rocks, and the opening of stomata. Erosion and weathering are physical processes that can be intensified by the force of the wind. The opening of stomata, small openings on the surface of plants, can also be influenced by wind as it can cause the plant to lose water and open its stomata to take in more carbon dioxide for photosynthesis. However, the breeding of plants is a biological process that is not directly influenced by wind speed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>47", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : MICROORGANISMS: MAN AND HIS HEALTH.", "question": "micro-organism which break down dead organisms and absorb their content are called", "images": [], "options": {"A": "decomposers", "B": "consumers", "C": "parasites", "D": "commensals"}, "answer": "A", "explanation": "Decomposers are organisms that break down dead or decaying organisms, and in doing so, they carry out the natural process of decomposition. Like herbivores and predators, decomposers are heterotrophic, meaning that they use organic substrates to get their energy, carbon and nutrients for growth and development. While the terms decomposer and detritivore are often interchangeably used, detritivores ingest and digest dead matter, while decomposers directly absorb nutrients in a form that can be used by plants and other autotrophs.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2001>48", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "The substance recycled in the soil by the activities of micro-organism during the decay of dead organism are first utilised by the", "images": [], "options": {"A": "carnivores", "B": "herbivores", "C": "scavengers", "D": "autotrophs"}, "answer": "D", "explanation": "The substances recycled in the soil by the activities of micro-organisms during the decay of dead organisms are first utilised by the autotrophs. Autotrophs are organisms that can produce their own food from the substances available in their surroundings using light (photosynthesis) or chemical energy (chemosynthesis). In this case, the substances recycled in the soil serve as nutrients for the autotrophs, which are then passed up the food chain when the autotrophs are consumed by herbivores, and so on.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>49", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS", "question": "Which of the following associations can upset the balance of nature?", "images": [], "options": {"A": "epiphitism", "B": "parasitism", "C": "symbiosis", "D": "saprophytism"}, "answer": "B", "explanation": "Parasitism can upset the balance of nature. Parasitism is a type of symbiotic relationship between organisms of different species where one organism, the parasite, benefits at the expense of the host. In this relationship, the parasite lives on or in the body of the host. If the number of parasites increases significantly, it can cause harm to the host species, which can upset the balance of nature. Epiphytism, symbiosis, and saprophytism are types of interactions that generally do not upset the balance of nature. Epiphytism is a non-harmful interaction where one plant grows on another. Symbiosis is a mutually beneficial relationship. Saprophytism is a relationship where an organism feeds on dead or decaying organic matter.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>50", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "which of the following groups of factors do the agama lizard compete for?  I. space  II. Food  III. Mates", "images": [], "options": {"A": "space and food only", "B": "space, food and mate only", "C": "food and mates only", "D": "space , food and mates"}, "answer": "D", "explanation": "Agama lizards, like many other species, compete for resources that are essential for their survival and reproduction. These resources include space, food, and mates. Space is needed for shelter and territory, food is necessary for energy and growth, and mates are required for reproduction. Therefore, the correct answer is 'space, food, and mates'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>51", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : CARRIERS OF MICROORGANISMS", "question": "Which of the following structure in a housefly aids in transmission of disease in man?", "images": [], "options": {"A": "Hairs", "B": "spiracles", "C": "Antennae", "D": "wings"}, "answer": "A", "explanation": "The hairs on a housefly's body can carry pathogens from one place to another, thus aiding in the transmission of diseases in humans. When a housefly lands on a surface, it can pick up bacteria, viruses, and other pathogens on its hairs. When it later lands on food or other surfaces that humans may touch or consume, it can deposit these pathogens, potentially leading to disease transmission. The other options, spiracles, antennae, and wings, do not directly aid in disease transmission. Spiracles are involved in respiration, antennae in sensing the environment, and wings in flight.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>52", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : CARRIERS OF MICROORGANISMS", "question": "Which of the these is not correct about tse-tse fly and mosquito? they", "images": [], "options": {"A": "Habour protozoa as disease agents", "B": "posses piercing and sucking mouth part", "C": "have intermediate host", "D": "injects disease-causing organism into the blood stream"}, "answer": "C", "explanation": "Tse-tse flies and mosquitoes are both vectors for disease, meaning they can transmit disease-causing organisms from one host to another. However, they do not have intermediate hosts. An intermediate host is an organism that supports the immature or nonreproductive forms of a parasite. In the case of these insects, they are the definitive hosts, meaning they are the organisms in which the parasites reach maturity and where sexual reproduction occurs. Therefore, the statement 'have intermediate host' is not correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>53", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : CARRIERS OF MICROORGANISMS", "question": "Which of these is a vector of malaria fever?", "images": [], "options": {"A": "Female anopheles mosquito", "B": "male anopheles mosquito", "C": "female culex mosquito", "D": "male culex mosquito"}, "answer": "A", "explanation": "Malaria is transmitted to humans through the bites of infected female Anopheles mosquitoes. They are the primary vectors of malaria. Male mosquitoes do not bite and therefore do not transmit the disease. Culex mosquitoes are not vectors of malaria.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2001>54", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "ECOLOGY OF POPULATION : PRESERVATION AND STORAGE OF FOODS", "question": "Fresh milk is often kept in-refrigerated vehicles, for distribution to constumers in order to", "images": [], "options": {"A": "ensure proper share of fresh milk to all customers", "B": "ensure delivery of milk to customer in good time", "C": "improve the quality of the milk", "D": "ensure that the milk is preserved for a longer period"}, "answer": "D", "explanation": "Fresh milk is often kept in refrigerated vehicles to ensure that it is preserved for a longer period. Refrigeration slows down the growth of bacteria and other microorganisms that cause milk to spoil. This is not about ensuring proper share, delivery in good time or improving the quality of the milk, but about preserving its existing quality for a longer period.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2001>55", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION", "question": "In medicine, bacteria have proven very useful due to the production of", "images": [], "options": {"A": "nitrate", "B": "antibiotics", "C": "curred tobacco", "D": "tanned leather"}, "answer": "B", "explanation": "Bacteria are known to produce antibiotics. Antibiotics are substances produced by bacteria and fungi that are capable of killing, or inhibiting the growth of, other microorganisms. This property is used in medicine to treat bacterial infections. The other options listed are not typically associated with bacteria.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2001>56", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "use the following human charateristic to answer the questions  I. complexion   II. Height  III. Blood RH factor  IV colour blindness    Which of the above human charateristics are discontinuous variation", "images": [], "options": {"A": "I and III only", "B": "II and III only", "C": "II and IV only", "D": "III and IV only"}, "answer": "D", "explanation": "Discontinous variation involves sharp difference between the various form of a given difference.  It often arises as a result of mutation E.g colour blindness, tongue rolling, ability to taste PTC, blood groups e.t.c", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>57", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "use the following human charateristic to answer the questions  I. complexion   II. Height  III. Blood RH factor  IV colour blindness  which of the charateristics can be expressed phenotypically?", "images": [], "options": {"A": "I and II only", "B": "I, II and IV only", "C": "I,III and IV only", "D": "I, II and III only"}, "answer": "A", "explanation": "To be expressed phenotypically means they are features that can be observed physically. Hence, height and complexion are expressed physically.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>58", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "VARIATION IN POPULATION : PHYSIOLOGICAL VARIATIONS", "question": "Which of the following variation is applicable to a weight lifter?", "images": [], "options": {"A": "Continous variation variation", "B": "discontinuous variation", "C": "Hereditary variation", "D": "Acquired variation"}, "answer": "D", "explanation": "Weight lifting is a skill that is not inherited but acquired through training and practice. Therefore, the variation in muscle mass and strength that a weight lifter experiences is an acquired variation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2001>59", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "The character that expresses itself in the presence of the contrasting charater is", "images": [], "options": {"A": "hybrid", "B": "allele", "C": "recessive", "D": "dominant"}, "answer": "D", "explanation": "In genetics, the character that expresses itself in the presence of the contrasting character is known as the dominant trait. Dominant traits are those that are expressed or visible when a living organism has at least one copy of the dominant allele. An allele is a variant form of a gene. Some genes have a variety of different forms, which are located at the same position, or genetic locus, on a chromosome. In the given options, 'dominant' is the correct term that describes this genetic concept.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2001>60", "subject": "Biology", "year": "2001", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following animals exhibits territoriaity?", "images": [], "options": {"A": "bees", "B": "Bats", "C": "lizard", "D": "Rabbits"}, "answer": "C", "explanation": "Territoriality is a type of intraspecific interaction where an organism or group of organisms defends its territory against others. In the animal kingdom, many species exhibit territorial behavior, including lizards. Lizards are known to establish and defend their territories from other lizards, often through displays of aggression. Bees, bats, and rabbits do not typically exhibit territorial behavior in the same way. Bees live in colonies and share a common area, bats often live in large groups known as colonies, and rabbits are more social animals that live in groups. Therefore, the correct answer is 'lizard'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2002>1", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "which of the following characteristics differentiates a palisade cell from a liver cell? the possession of", "images": [], "options": {"A": "a cell wall and cytoplasm", "B": "a vacuole and a nucleus", "C": "non-cell membrane and chloroplast", "D": "a cell wall and chloroplast"}, "answer": "D", "explanation": "Palisade cells are found in the mesophyll of a leaf and their main function is the photosynthesis. They are different from liver cells because they have a cell wall and chloroplasts. The cell wall provides structural support and the chloroplast is where photosynthesis occurs. Liver cells, being animal cells, do not have these structures. Therefore, the possession of a cell wall and chloroplast differentiates a palisade cell from a liver cell.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>2", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "Which of the following organism has both plant and animals-like features?", "images": [], "options": {"A": "paramecium", "B": "euglena", "C": "amoeba", "D": "spirogyra"}, "answer": "B", "explanation": "Euglena is a single-celled organism that exhibits features of both plants and animals. Like plants, it has chloroplasts and can perform photosynthesis, and like animals, it can move around and consume food when light is not available for photosynthesis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>3", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which part of a plant cell contains celluose?", "images": [], "options": {"A": "vacuole", "B": "ctoplasm", "C": "cell wall", "D": "choroplast"}, "answer": "C", "explanation": "The cell wall of a plant cell contains cellulose. Cellulose is a complex carbohydrate, or polysaccharide, that provides structural support to the cell. It is the main component of the cell wall in plant cells. The cell wall is a rigid layer that is located outside the cell membrane and provides the cell with structural support and protection.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2002>4", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Animal cell are different from plant cell because animals have", "images": [], "options": {"A": "Definite cell wall", "B": "large vacoules", "C": "centrioles", "D": "chloroplasts"}, "answer": "C", "explanation": "Animal cells are different from plant cells in several ways, one of which is the presence of centrioles in animal cells. Centrioles are small, cylindrical organelles that are involved in the process of cell division, specifically in the formation of the spindle fibers that separate the chromosomes during mitosis. Plant cells do not have centrioles. Option 1 is incorrect because plant cells, not animal cells, have a definite cell wall. Option 2 is incorrect because both animal and plant cells can have large vacuoles. Option 4 is incorrect because chloroplasts are found in plant cells, not animal cells.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2002>5", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "Which of the following depicts the external feautures of a rat as a mammal", "images": [], "options": {"A": "long intestine", "B": "Diaphragms", "C": "milk and sweat production", "D": "fur and whiskers"}, "answer": "D", "explanation": "The external features of a rat as a mammal are depicted by its fur and whiskers. Fur is a characteristic feature of mammals, providing them with insulation and protection. Whiskers, also known as vibrissae, are sensory hairs that provide mammals with a sense of touch, helping them navigate and detect changes in their environment. The other options like long intestine, diaphragms, and milk and sweat production are internal features or physiological processes, not external features.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>6", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "Which of the following represent the correct sequence from the most simple, to the most complex of organisation", "images": [], "options": {"A": "mitochondrin, muscles, alimentary canal, rabbit ,heart, neurone", "B": "mitochodrion,neurone, muscle,heart, alimentary canal, rabbit", "C": "alimentary canal, neurone, muscle, heart, rabbit,mitochondrion", "D": "Rabbit, mitochondrin, heart, neuron , alimentary canal"}, "answer": "B", "explanation": "The level of organisation include   Cell→Tissues→organs →system→organisation  Hence  Mitochondria→neuron →muscle→alimentary canal→Rabbit.  Mitochondria→ organelle  Neuron →cell  Muscles →tissue  heart →organ  Alimentary canal →system   Rabbit →organisation", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2002>7", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "Which of the following will cause wilting in plants?", "images": [], "options": {"A": "humidity", "B": "coldness", "C": "adequates soil water", "D": "excessive transpiration"}, "answer": "D", "explanation": "Wilting in plants is caused by excessive transpiration. Transpiration is the process by which water is carried through plants from roots to small pores on the underside of leaves, where it changes to vapor and is released to the atmosphere. When this process is excessive, it can lead to wilting as the plant loses more water than it can absorb from the soil, causing it to lose turgidity and droop.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>8", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which of the following definition best describes excretion?", "images": [], "options": {"A": "liberation of energy from food", "B": "release of face from the body", "C": "breakdown of food molecules", "D": "removal of waste product of metabolism"}, "answer": "D", "explanation": "Excretion is the process by which waste products of metabolism are eliminated from an organism. These waste products are by-products or excess substances that the body cannot use, and if they are allowed to accumulate, they would be harmful. Therefore, option 4 is the correct answer.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2002>9", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "In an experiment to study the rate of water loss in plant, leaves of a potted-plant were treated as follows  I. upper surface covered with vaseline  II. lower surface covered with vaseline  III. both surface  covered with vaseline  IV. none of the above    indicate in a descending order, rate of water loss from leaves", "images": [], "options": {"A": "I, II,III and IV", "B": "II,I,III and IV", "C": "III, II, I and IV", "D": "IV,I,II and III"}, "answer": "D", "explanation": "Water loss is greatest when none of the leaf surface is covered. This is the rate of water loss in descending order.  IV→I→II →III", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>10", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE", "question": "The following are method of measuring plant growth except", "images": [], "options": {"A": "determination the fresh and dry weight of the plant", "B": "counting the number of fruits produced", "C": "measuring the increase in height of the shoot", "D": "measuring the length and breadth of a leaf"}, "answer": "B", "explanation": "Plant growth is typically measured by parameters such as the increase in the plant's height, the fresh and dry weight of the plant, and the length and breadth of the leaves. These measurements provide information about the plant's overall growth and development. However, counting the number of fruits produced is not a direct method of measuring plant growth. While it can provide information about the plant's reproductive success, it does not directly measure the plant's growth or development. Therefore, the correct answer is option 2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>11", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following will ease the friction between the ends of bones in a movables joint?", "images": [], "options": {"A": "serum", "B": "tissue", "C": "blood plasma", "D": "synovial fluid"}, "answer": "D", "explanation": "The correct answer is synovial fluid. In a movable joint, the ends of the bones are covered with a layer of cartilage. Between these layers of cartilage, there is a small amount of a thick, slippery liquid called synovial fluid. This fluid acts as a lubricant to reduce friction between the bones when they move. Therefore, synovial fluid eases the friction between the ends of bones in a movable joint.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2002>12", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "Diffusion is most effective in living organism, when the surface area is", "images": [], "options": {"A": "Large and thickness is also large", "B": "small while the thickness is large", "C": "large while the thickness is small", "D": "the same as its thickness"}, "answer": "C", "explanation": "Diffusion is the movement of molecules from an area of higher concentration to an area of lower concentration. It is most effective in living organisms when the surface area is large and the thickness is small. This is because a larger surface area allows for more molecules to diffuse at once, and a smaller thickness means the molecules have less distance to travel, making the process faster. Therefore, the correct answer is 'large while the thickness is small'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>13", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "The function of red blood cells is to", "images": [], "options": {"A": "engulf invading bacteria", "B": "aid in protein formation", "C": "transport oxygen to the cell", "D": "control blood glucose level"}, "answer": "C", "explanation": "Red blood cells, also known as erythrocytes, primarily transport oxygen from the lungs to the body's tissues. They do this by carrying a protein called hemoglobin, which binds to oxygen in the lungs and releases it in tissues that need it. The other options are incorrect because red blood cells do not engulf bacteria (that's the job of white blood cells), they do not aid in protein formation, and they do not control blood glucose levels (that's primarily the job of insulin and glucagon hormones).", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2002>14", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "which of the following is used to measure the rate of water uptake in plants?", "images": [], "options": {"A": "potometer", "B": "hydrometer", "C": "hygometer", "D": "aspirator"}, "answer": "A", "explanation": "A potometer is a device used for measuring the rate of water uptake of a leafy shoot. It is typically used to estimate transpiration rates. Transpiration is the process by which water is carried through plants from roots to small pores on the underside of leaves, where it changes to vapor and is released to the atmosphere. The other options, hydrometer, hygometer, and aspirator, are not used for this purpose. A hydrometer is used to measure the specific gravity (relative density) of liquids; a hygrometer is used to measure humidity in the air; and an aspirator is a device used to create a vacuum by flowing water through a narrow tube.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2002>15", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Which of the following does not occur during inhalation in mammals?", "images": [], "options": {"A": "Rib cage is raised up", "B": "Diaphragm contracts and becomes dome shaped", "C": "inter-coastal muscles contracts", "D": "volume of the thoraciccavity increases."}, "answer": "B", "explanation": "During inhalation in mammals, the diaphragm contracts and flattens, not becomes dome shaped. The contraction of the diaphragm increases the volume of the thoracic cavity, which decreases the pressure inside the lungs, allowing air to flow in. The other options are correct: the rib cage is raised up, the intercostal muscles contract, and the volume of the thoracic cavity increases.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2002>16", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The oxygen released during photosynthesis is obtained", "images": [], "options": {"A": "From the catalytic splitting of carbon -dioxide in plant tissues", "B": "from the breakdown of glucose molecules in cells", "C": "During the photosyls is of water using energy trapped in chlorophyll", "D": "by the excretion of excess oxygen in plant tissues"}, "answer": "C", "explanation": "During photosynthesis, plants take in carbon dioxide and water and convert them into glucose and oxygen. The oxygen that is released during this process is obtained from the photosynthesis of water using energy trapped in chlorophyll. This process is known as photolysis, where water molecules are broken down into hydrogen and oxygen in the presence of light. The oxygen is then released into the atmosphere.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>17", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "In which of the following process in mammals is liquid passed from blood capillaries to bowman's capsules?", "images": [], "options": {"A": "filtration", "B": "diffusion", "C": "osmosis", "D": "reabsorption"}, "answer": "A", "explanation": "In mammals, the process of passing liquid from blood capillaries to Bowman's capsules is called filtration. This process occurs in the kidneys, where the blood is filtered to remove waste products and excess substances. The Bowman's capsule is a part of the nephron, the functional unit of the kidney, where the filtration of blood takes place. The blood capillaries, also known as glomerulus, are surrounded by the Bowman's capsule, and the pressure in these capillaries forces water, ions, and small molecules into the Bowman's capsule. This process is not diffusion, osmosis, or reabsorption, but filtration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>18", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "Adrenalin is considered as hormone for ''fright  and flight'' because it's", "images": [], "options": {"A": "controls the fluid content of the body", "B": "is used in protein metabolism", "C": "plays a role in the pH balance of the body fluid", "D": "prepares the body for action"}, "answer": "D", "explanation": "Adrenalin, also known as epinephrine, is often referred to as the 'fight or flight' hormone because it prepares the body for action. It is released by the adrenal glands in response to stressful situations. When released, it increases heart rate, blood pressure, and blood glucose levels, thereby preparing the body for a sudden burst of energy needed for 'fight or flight'. None of the other options accurately describe the role of adrenalin.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2002>19", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which of the following organs in humans is responsible for the removal of excess water", "images": [], "options": {"A": "the spleen", "B": "the kidney", "C": "large intestine", "D": "small intestine"}, "answer": "B", "explanation": "The kidney is responsible for the removal of excess water in humans. It does this through the process of filtration, reabsorption, and secretion. Filtration is the process by which the kidneys filter out waste products, excess nutrients, and water from the blood. Reabsorption is the process by which the kidneys reabsorb useful substances back into the blood. Secretion is the process by which the kidneys secrete waste products and excess water into the urine, which is then excreted from the body. The other options, the spleen, large intestine, and small intestine, are not primarily involved in the removal of excess water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>20", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "In humans, which of the following pairs of hormones correspond to male and female respectively", "images": [], "options": {"A": "oestrogen and adrenaline", "B": "progesterone and testostrone", "C": "testosterone and oestrogen", "D": "Adrenaline and progesterone"}, "answer": "C", "explanation": "In humans, the primary male sex hormone is testosterone, which is responsible for the development of male reproductive tissues and secondary sexual characteristics. On the other hand, oestrogen is the primary female sex hormone that regulates the menstrual cycle and is crucial for the development and maintenance of female secondary sexual characteristics. Therefore, the pair of hormones that correspond to male and female respectively are testosterone and oestrogen.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>21", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "if the cerebellum of a person is slightly damage , which of the following will be impaired?", "images": [], "options": {"A": "vision", "B": "walking", "C": "breathing", "D": "digestion"}, "answer": "B", "explanation": "The cerebellum is a part of the brain that is responsible for motor control. It does not initiate movement, but it contributes to coordination, precision, and accurate timing. It receives input from sensory systems and from other parts of the brain and spinal cord, and integrates these inputs to fine-tune motor activity. Hence, if the cerebellum of a person is slightly damaged, the person's walking ability will be impaired.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>22", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The structure of the ear that is responsible for balancing is the", "images": [], "options": {"A": "semi-circular canal", "B": "pinna", "C": "auditory nerve", "D": "fenstra ovalis"}, "answer": "A", "explanation": "The semi-circular canals are part of the inner ear and are responsible for maintaining balance. They are filled with a fluid that moves when your head changes position. This movement of fluid stimulates hair cells inside the canals, sending nerve impulses to the brain that interpret these movements as a change in position, thus helping to maintain balance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2002>23", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "When a person moves from a darkroom into bright light, the pupil becomes", "images": [], "options": {"A": "red", "B": "larger", "C": "white", "D": "smaller"}, "answer": "D", "explanation": "When a person moves from a dark room into bright light, the pupil becomes smaller. This is due to the reflex action of the eye to control the amount of light entering the eye. In bright light, the iris contracts, reducing the size of the pupil to prevent damage to the retina from excessive light. This is known as the pupillary light reflex.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2002>24", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following is not example of entomophilous flower?", "images": [], "options": {"A": "Hibiscus", "B": "flambouyant", "C": "guinea grass", "D": "allamanda"}, "answer": "C", "explanation": "Entomophilous flowers are those that are pollinated by insects. Examples of entomophilous flowers include hibiscus, flambouyant, and allamanda. However, guinea grass is an anemophilous flower, meaning it is pollinated by wind, not insects. Therefore, guinea grass is not an example of an entomophilous flower.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>25", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "In flowering plants, fertilization would occur when", "images": [], "options": {"A": "The pollen grows downwards penetrating the style", "B": "a pollen grain is transferred to the stigma", "C": "one of the nuclei inside the pollen tube fuses with the ovum", "D": "the nucleus of pollen tube divide"}, "answer": "C", "explanation": "In flowering plants, fertilization occurs when one of the nuclei inside the pollen tube fuses with the ovum. This process is known as syngamy. The pollen grain lands on the stigma and grows a pollen tube down into the ovule. The pollen tube carries two sperm cells, one of which will fuse with the egg cell (ovum) to form a zygote (the first cell of the new plant), while the other fuses with two polar nuclei to form the endosperm, which serves as food storage within the seed. This is known as double fertilization, a process unique to flowering plants.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>26", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "After fertilization in the flowering plants, the zygote develops into the:", "images": [], "options": {"A": "plumule", "B": "radicle", "C": "cotyledon", "D": "embryo"}, "answer": "D", "explanation": "After fertilization in flowering plants, the zygote develops into the embryo. The embryo is the early stage of development of a multicellular organism. In the case of plants, the embryo later differentiates into different parts like the plumule, radicle, and cotyledon. Therefore, the correct answer is 'embryo'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2002>27", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following susbtances is contained in chloroplasts?", "images": [], "options": {"A": "starch", "B": "sugar", "C": "Glycogen", "D": "Dextrin"}, "answer": "A", "explanation": "Chloroplasts are the site of photosynthesis in plant cells, where light energy is converted into chemical energy in the form of glucose. During this process, glucose is stored in the form of starch granules within the chloroplasts. Therefore, the correct answer is starch. Glycogen and dextrin are forms of stored carbohydrates in animals and yeast respectively, not in chloroplasts. Sugar is a product of photosynthesis but it is not stored in the chloroplasts, it is transported out to other parts of the plant.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>28", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The diagram below is the root system of a leguminous plant.       The structure labelled II are", "images": ["Biology/imgs/2002/s33.png"], "options": {"A": "Groundnut seeds", "B": "underground root nut", "C": "root tubers", "D": "root nodules"}, "answer": "D", "explanation": "II  is the root nodules. Root nodules are small, rounded growths on the roots of certain plants, such as legumes, which contain nitrogen-fixing bacteria. These bacteria help convert atmospheric nitrogen into a form that the plant can use, thereby enhancing soil fertility.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>29", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The diagram below is the root system of a leguminous plant.     The structure labelled II are associated with", "images": ["Biology/imgs/2002/s33.png"], "options": {"A": "storage is plant nutrients", "B": "organic acids", "C": "nitrogen-fixing bacteria", "D": "putrefying microbes"}, "answer": "C", "explanation": "Root nodules, like the ones labeled II in the diagram, are formed on the roots of leguminous plants due to a symbiotic relationship with nitrogen-fixing bacteria, such as Rhizobium. These bacteria convert atmospheric nitrogen into ammonia, a form of nitrogen that plants can absorb and utilize for growth. This symbiosis is crucial for soil fertility and plant nutrition, particularly in nitrogen-poor soils.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>30", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH", "question": "The deficiency disease that results from the lack of vitamin B due to frequent eating of rice is", "images": [], "options": {"A": "rickets", "B": "night blindness", "C": "scurvy", "D": "beri beri"}, "answer": "D", "explanation": "Beri beri is a disease caused by a deficiency of vitamin B1, also known as thiamine. This vitamin is found in foods such as whole grains, beans, peas, and nuts. Rice, especially white rice, is often deficient in thiamine because the outer layer of the grain, which contains most of the vitamin, is removed during processing. Therefore, people who eat a lot of rice, especially white rice, and not many other foods can develop beri beri.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>31", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "When a food substance gives a purple colour on the addition of sodium hydroxide and drop of copper sulphate, then the food substance is likely to contain", "images": [], "options": {"A": "carbohydrate", "B": "fat", "C": "protein", "D": "sugar"}, "answer": "C", "explanation": "The test described in the question is known as the Biuret test. It is a chemical test used for detecting the presence of peptide bonds, which are the bonds holding amino acids together in a protein. When a solution of sodium hydroxide and a drop of copper sulphate (the Biuret reagent) is added to a substance containing protein, it turns a purple color. Therefore, the food substance is likely to contain protein.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>32", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "In mammals digested food is absorbed in the", "images": [], "options": {"A": "stomach", "B": "ileum", "C": "colon", "D": "duodenum"}, "answer": "B", "explanation": "In mammals, the absorption of digested food primarily occurs in the ileum, which is a part of the small intestine. The small intestine is divided into three parts: the duodenum, jejunum, and ileum. The ileum is the longest part and it is where most of the absorption process happens. Nutrients such as sugars, amino acids, and fatty acids are absorbed here through the villi, tiny finger-like projections that increase the surface area for absorption. The other options are not primarily involved in the absorption of digested food. The stomach is involved in the breakdown of food, the colon absorbs water and electrolytes, and the duodenum, while part of the small intestine, is more involved in the continuation of digestion rather than absorption.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2002>33", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "using iodine solution, biuret test, benedict reagents and ethanol, respectively in testing for reducing sugar, which of the following trend of colour changes would be observed?", "images": [], "options": {"A": "blue-black→blue→brown→clear", "B": "brown→blue→brick red→ clear", "C": "brown →violet→blue→clear", "D": "brown→blue→violet→milky"}, "answer": "C", "explanation": "Considering the context of the tests described:  -\tIodine solution: Stays brown (no starch)Biuret test: Stays blue (if we assume no proteins, or could turn violet)  -\tBenedict's reagent: Stays blue (in absence of reducing sugars without heat)  -\tEthanol test: Stays clear (no lipids)  So the correct progression of colors would be:Brown (iodine) → blue (biuret) → blue (Benedict) → clear (ethanol)", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2002>34", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS", "question": "Ecology simply means the study of", "images": [], "options": {"A": "the properties of a habitat", "B": "interrelationship between organism and environment.", "C": "several species of plant and animals", "D": "interrelationship between plants and animals"}, "answer": "B", "explanation": "Ecology is the branch of biology that studies the interactions among organisms and their biophysical environment, which includes both biotic and abiotic components. It involves understanding the interrelationship between organisms and their environment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2002>35", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : WATER CYCLE", "question": "Which of the following processes remove water from the water cycle?", "images": [], "options": {"A": "condensation", "B": "perspiration", "C": "photosynthesis", "D": "transpiration"}, "answer": "D", "explanation": "Transpiration: is loss of water by evapouration from the aerial part of plant and it removes water from the cycle.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2002>36", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE", "question": "The importance of practising crop-rotation in agriculture is to", "images": [], "options": {"A": "control soil erosion", "B": "maintain the fertility of the soil", "C": "improve the nutritional value of crops", "D": "ensure growth of cash crops"}, "answer": "B", "explanation": "Crop rotation is the practice of growing different types of crops in the same area, in sequenced seasons. It is done so that the soil of farms is not used for only one set of nutrients. It helps in reducing soil erosion and increases soil fertility and crop yield. Thus, the main importance of practising crop-rotation in agriculture is to maintain the fertility of the soil.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>37", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "In any chain, the first member must be a", "images": [], "options": {"A": "carnivore", "B": "herbivore", "C": "zooplankton", "D": "autotroph"}, "answer": "D", "explanation": "In any food chain, the first member must be an autotroph. Autotrophs are organisms that can produce their own food from the substances available in their surroundings using light (photosynthesis) or chemical energy (chemosynthesis). They are the primary producers in a food chain, such as plants on land or algae in water. They are followed by herbivores (primary consumers), and then carnivores and omnivores (secondary and tertiary consumers).", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2002>38", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT", "question": "Which of the following measure is most likely to cause a damage to ecosystem in the control of pest and weeds?", "images": [], "options": {"A": "use of the ladybird insects to feed on aphids.", "B": "introduction of bacterium to kill larve of butterfly", "C": "introduction the tilapia fish in ponds feed on mosquito larvae", "D": "spraying insecticides to destroy cotton-stainers in a cotton field"}, "answer": "D", "explanation": "Spraying of insecticides can cause damage to the ecosystem , due to the fact that it can pollute the water bodies and also makes the soil toxic(When applied in excess)admist other effects.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2002>39", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "The total amount of energy entering a food chain is that which is present in the", "images": [], "options": {"A": "consumer", "B": "ecosystem", "C": "producer", "D": "decomposers"}, "answer": "C", "explanation": "The total amount of energy entering a food chain is that which is present in the producers. Producers, such as plants, are the first level in a food chain. They convert sunlight into energy through photosynthesis, which is then passed on to consumers and decomposers. Therefore, the total energy in a food chain originates from the producers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>40", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "which of the following terms ensures the survival of an organism in the environment?", "images": [], "options": {"A": "Hibernation", "B": "succession", "C": "adaptation", "D": "competition"}, "answer": "C", "explanation": "Adaptation is the process by which an organism becomes better suited to its environment. It is a key mechanism of evolution and helps to ensure the survival of an organism in its environment. Hibernation is a state of inactivity and metabolic depression in endotherms. Succession is the process by which a plant or animal community successively gives way to another until a stable climax is reached. Competition is a relationship between organisms that strive for the same resources in the same place.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>41", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The concave shape of a birds wing during flight, ensures that a greater air pressure under wings will", "images": [], "options": {"A": "counter the effect of gravity", "B": "lift the bird so that it can remain airborne", "C": "enable the pectoral muscles to contracts easily", "D": "changes the direction of the flying bird"}, "answer": "B", "explanation": "The concave shape of a bird's wing during flight creates a pressure difference between the top and bottom of the wing. This pressure difference is what lifts the bird so that it can remain airborne. The greater air pressure under the wings doesn't counter the effect of gravity, enable the pectoral muscles to contract easily, or change the direction of the flying bird.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>42", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "The prossession of breathing roots is a charateristics of plants growing in", "images": [], "options": {"A": "mangrove swamp", "B": "coastal savanna", "C": "guniea savanna", "D": "shrub biome"}, "answer": "A", "explanation": "Breathing roots, also known as pneumatophores, are a type of root that protrudes above the ground in some plant species. They are a characteristic feature of many swamp and marsh plants, including mangroves. These roots emerge from the water or ground to access the air, which is low in the waterlogged soil, to facilitate respiration. Therefore, the correct answer is 'mangrove swamp'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>43", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION", "question": "The numbers in population would rise if there was an increase in the", "images": [], "options": {"A": "spread of disease", "B": "number of deaths", "C": "number of predators", "D": "amount of food available"}, "answer": "D", "explanation": "The number in a population would rise if there was an increase in the amount of food available. This is because food is a basic necessity for survival and reproduction. If there is more food available, it means that more individuals in the population can be supported, leading to an increase in the population size.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>44", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : PUBLIC HEALTH", "question": "measles in infants can be prevented by", "images": [], "options": {"A": "sleeping under mosquito nets", "B": "providing clean water", "C": "taking anti-malaria tablets", "D": "vaccinating young children"}, "answer": "D", "explanation": "Measles is a highly contagious viral disease that can be prevented through vaccination. The measles vaccine is typically administered to children as part of their routine immunization schedule. Therefore, the correct answer is 'vaccinating young children'. The other options are incorrect as they are not related to the prevention of measles. Sleeping under mosquito nets and taking anti-malaria tablets are measures to prevent malaria, not measles. Providing clean water can prevent diseases caused by water contamination, but not measles.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>45", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "micro-organism are important in recycling nutrient because", "images": [], "options": {"A": "they are capable of multiplying quickly", "B": "they are beaten by a organism", "C": "they break down dead organic materials", "D": "many of them ae parasites"}, "answer": "C", "explanation": "Micro organism break down dead organic material, this process aids nutrient recycling i.ebiodegradation of materials is impoertant for nutrient recycling", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>46", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE", "question": "A vegetable farmer will benefit from a cattle rearer if", "images": [], "options": {"A": "the faecal remains of the cattle are made available to the farmer", "B": "the farmer makes available fresh green vegetables for consumption by the cattle daily", "C": "the farmer provides shelter for the cattle and the cattle rearer", "D": "the cattle reare makes available meat available meat to the farmer daily"}, "answer": "A", "explanation": "The faecal remains of the cattle can be used as manure by the vegetable farmer. This manure is rich in nutrients and can improve the fertility of the soil, thereby benefiting the farmer by increasing the yield of his crops. This is a concept in agriculture known as integrated farming system where the waste product of one system becomes the input for another system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>47", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Wildlife conservation is enhanced by", "images": [], "options": {"A": "enacting laws to encourage poaching", "B": "discouraging elimination of endangered species", "C": "encouraging creation of statellite hunting unit", "D": "suppressing the activities of wildlife conservation agencies"}, "answer": "B", "explanation": "Wildlife conservation is enhanced by discouraging the elimination of endangered species. This is because the goal of wildlife conservation is to ensure that nature will be around for future generations to enjoy and to recognize the importance of wildlife and wilderness for humans and other species alike. Therefore, discouraging the elimination of endangered species is a direct way to enhance wildlife conservation. The other options do not contribute to wildlife conservation. For instance, enacting laws to encourage poaching would actually harm wildlife conservation, not enhance it. Similarly, suppressing the activities of wildlife conservation agencies would also be detrimental to wildlife conservation efforts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>48", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of these statement is true about fingerprint patterns?", "images": [], "options": {"A": "consistence for lifetime", "B": "may be exactly the same for two individuals", "C": "prominent only at puberty", "D": "correlates with the individual blood group"}, "answer": "A", "explanation": "Fingerprints are unique to each individual and remain consistent throughout a person's lifetime. They are formed during the fetal development stage and do not change as we grow. This is because the basic structure of a fingerprint is determined by the dermal papillae, which develops before birth and remains unchanged throughout life. Therefore, the statement 'consistence for lifetime' is true. The other options are incorrect. Fingerprints are not exactly the same for two individuals, they do not become prominent only at puberty, and they do not correlate with an individual's blood group.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>49", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "some species of animals and plants are considered as endangered because", "images": [], "options": {"A": "they are found in large number in most habitat", "B": "they are harmful to their natural habitats", "C": "their population have become so small that they may soon die out", "D": "they should be killed or only kept in cages"}, "answer": "C", "explanation": "Endangered species are those species of animals or plants that are considered at risk of extinction. This is often due to a drastic decline in their population numbers, usually as a result of factors like habitat loss, climate change, or overexploitation. Therefore, the statement 'their population have become so small that they may soon die out' is the correct answer. The other options are incorrect because endangered species are not necessarily harmful to their habitats, nor are they found in large numbers in most habitats. Also, the idea of killing them or keeping them only in cages does not relate to their endangered status.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>50", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Which of the following is continous variation,in human population ?", "images": [], "options": {"A": "sex", "B": "Rh factor", "C": "height", "D": "Downs syndrome"}, "answer": "C", "explanation": "Continuous variation, in biology, refers to a genetic phenomenon where individuals in a population vary in small ways from each other due to the effect of multiple genes. This variation is often represented on a spectrum or continuum rather than in discrete categories. Height in humans is a classic example of continuous variation because it is determined by the cumulative effect of many genes and environmental factors, and individuals can be any height within a certain range, not just short, medium, or tall. Therefore, the correct answer is 'height'. The other options, 'sex', 'Rh factor', and 'Downs syndrome', are examples of discontinuous variation where individuals fall into a few distinct categories.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>51", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of the following statement about blood groups in human is not correct?", "images": [], "options": {"A": "siblings may not belong to the same blood group", "B": "there are four possible blood groups", "C": "people with blood group O can recieve blood from all other groups", "D": "people with blood group AB are universal recipient"}, "answer": "C", "explanation": "People with blood group O cannot receive blood from all other groups. This statement is incorrect because people with blood group O are universal donors, not universal recipients. They can donate blood to any group, but they can only receive blood from their own group (O). The concept behind this is related to the presence or absence of antigens and antibodies in the blood. Blood group O has no antigens but both A and B antibodies, therefore, it can only receive blood from its own group to avoid agglutination (clumping of red blood cells due to antibody-antigen reaction).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>52", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "When mendel crossed round seeds with winkled seeds of pea plant, what was the ratio of wrinkled seeds to round seeds in F2 plants?", "images": [], "options": {"A": "3:1", "B": "2:1", "C": "1:3", "D": "1:2"}, "answer": "C", "explanation": "The ratio of wrinkled seeds to round seeds in F2 plants 1:3", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>53", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Which of the following is not a morphological variation in human beings?", "images": [], "options": {"A": "size", "B": "blood groups", "C": "colour", "D": "fingerprints"}, "answer": "B", "explanation": "Morphological variations refer to the observable physical differences among individuals of a species. These can include variations in size, color, and fingerprints among human beings. However, blood groups are not a morphological variation. Blood groups are a type of genetic variation, determined by the presence or absence of certain antigens on the surface of red blood cells. Therefore, the correct answer is 'blood groups'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>54", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "The name given to a sudden change in a gene or chromosome that can be passed on the offspring is", "images": [], "options": {"A": "inheritance", "B": "linkage", "C": "alleles", "D": "mutation"}, "answer": "D", "explanation": "A sudden change in a gene or chromosome that can be passed on to the offspring is called a mutation. Mutations can occur randomly or due to exposure to specific environmental factors. They can lead to new traits in individuals, and if beneficial, these traits can be passed on to future generations, contributing to evolution. Inheritance refers to the passing of traits from parents to offspring, linkage refers to the tendency of genes that are close together on a chromosome to be inherited together, and alleles are different forms of a gene.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>55", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : LINKAGE, SEX DETERMINATION AND SEX LINKED CHARACTERS", "question": "in humans, sex is determined by", "images": [], "options": {"A": "two homologous chromosomes", "B": "a dominant gene foe maleness present in a male", "C": "two similar sex chromosomes in the male and dissimiliar in the female", "D": "the difference in the nature of x and Y chromosomes in the males"}, "answer": "D", "explanation": "In humans, sex is determined by the difference in the nature of X and Y chromosomes in males. Females have two of the same kind of sex chromosome (XX), while males have two distinct sex chromosomes (XY). The presence of the Y chromosome determines maleness because it carries the SRY gene, which triggers the development of male characteristics. The X chromosome carries genes related to both male and female sexual development. Therefore, the correct answer is 'the difference in the nature of X and Y chromosomes in the males'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>56", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY", "question": "A male with heterozygous genotype for blood group B marries  a woman with heterozygous, A, what percentage (%) of their children would be universal donor?", "images": [], "options": {"A": "50%", "B": "25%", "C": "15%", "D": "10%"}, "answer": "B", "explanation": "Universal donor is blood group O. The man and woman are heterozygous B and A repectively(AO and BO) and have 25% chance of having a child who is a universal donor", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>57", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "The genes affecting the same trait and are located at the same position on the homologous chromosomes are called", "images": [], "options": {"A": "autosomes", "B": "alleles", "C": "loci", "D": "chromatids"}, "answer": "B", "explanation": "The genes affecting the same trait and are located at the same position on the homologous chromosomes are called alleles. Alleles are different forms of the same gene. They are located at the same locus (position) on homologous chromosomes. Autosomes are non-sex chromosomes. Loci is the plural form of locus, which refers to the specific location of a gene or DNA sequence on a chromosome. Chromatids are the two identical halves of a duplicated chromosome.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>58", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following is an adaptation by plants to reduce the rate of water loss in a dry habitat possession of", "images": [], "options": {"A": "a few sunken stomata on a lower epidermis only", "B": "long leaf tendrils", "C": "leaves with serrated edges", "D": "strong tap roots"}, "answer": "A", "explanation": "Stomata are tiny openings or pores in plant tissue that allow for gas exchange. In dry habitats, plants adapt by having fewer stomata that are sunken into the lower epidermis of the leaves. This reduces the surface area exposed to the air, thereby reducing the rate of water loss through transpiration. The other options do not directly relate to the reduction of water loss. Long leaf tendrils are for climbing or support, leaves with serrated edges can help deter herbivores, and strong tap roots are for anchoring the plant and reaching deep water sources, but they do not reduce the rate of water loss.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>59", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The following are social insects excepts", "images": [], "options": {"A": "wasps", "B": "termites", "C": "bees", "D": "cotton stainer"}, "answer": "D", "explanation": "Social insects are those that live in colonies or have some sort of organized social structure. Examples of social insects include bees, ants, wasps, and termites. These insects have a division of labor, with different individuals performing different roles within the colony. The cotton stainer, on the other hand, is not a social insect. It does not live in colonies or have an organized social structure. Therefore, the correct answer is 'cotton stainer'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2002>60", "subject": "Biology", "year": "2002", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Which of the following can be considered as a direct evidence of evolution?", "images": [], "options": {"A": "classification", "B": "comparative anatomy", "C": "comparative embryology", "D": "fossil record"}, "answer": "D", "explanation": "The fossil record is considered a direct evidence of evolution. Fossils are the preserved remains or traces of animals, plants, and other organisms from the past. Over time, species have changed and developed, becoming more complex. This change and development can be seen in the fossil record, making it a direct evidence of evolution. Classification, comparative anatomy, and comparative embryology are all indirect evidences of evolution. They provide support for the theory of evolution but do not show the actual process of evolution over time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>1", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which of the following is not correct about the living cell?", "images": [], "options": {"A": "The basic unit of a living organism is the cell", "B": "All living organisms are either single or groups of cell(s)", "C": "All the cells in organisms are the same", "D": "There is no life apart from the life in cells"}, "answer": "C", "explanation": "All the cells in an organism are not the same.  E.g The cells found in the muscles are called myocytes, and are different from those found in the liver, the hepatocytes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>2", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which of the following statements about ribosomes is not correct? Ribosomes", "images": [], "options": {"A": "are responsible for protein synthesis", "B": "contain a large amount of ribonucleic acid", "C": "release enzymes for the digestion of bacteria", "D": "are attached to endoplasmic reticulum"}, "answer": "C", "explanation": "Ribosomes are responsible for protein synthesis and they contain a large amount of ribonucleic acid (RNA). They can be found free in the cytoplasm or attached to the endoplasmic reticulum, forming the rough endoplasmic reticulum. However, they do not release enzymes for the digestion of bacteria. That function is performed by lysosomes, which contain digestive enzymes to break down waste materials and cellular debris.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>3", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The protoplasm of a living cell is made up of the nucleus and", "images": [], "options": {"A": "vacuole", "B": "cytoplasm", "C": "cell wall", "D": "cell sap"}, "answer": "B", "explanation": "The protoplasm of a living cell is made up of the nucleus and the cytoplasm. The protoplasm is the living part of the cell, which is divided into the nucleus and the cytoplasm. The nucleus controls the cell's activities and the cytoplasm is where these activities take place. The vacuole, cell wall, and cell sap are parts of the cell but they are not part of the protoplasm.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>4", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "A bacterial cell differs from eukaryotic cell by having no", "images": [], "options": {"A": "cell wall", "B": "nuclear membrane", "C": "nuclear material", "D": "cell membrane"}, "answer": "B", "explanation": "A bacterial cell is a type of prokaryotic cell which lacks a nuclear membrane. Prokaryotic cells do not have a true nucleus; instead, the DNA is in a region of the cell called the nucleoid. On the other hand, eukaryotic cells have a true nucleus, which is separated from the rest of the cell by a nuclear membrane. Therefore, the correct answer is 'nuclear membrane'. Bacterial cells do have a cell wall, nuclear material (DNA), and a cell membrane, so the other options are incorrect.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>5", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "When a plant shoot is placed in a dye solution, under which of the following physical conditions will the dye  move up the stem?", "images": [], "options": {"A": "Low temperature and low humidity", "B": "Low temperature and high humidity", "C": "High temperature and low humidity", "D": "High temperature and high humidity"}, "answer": "C", "explanation": "The dye will move up the stem under high temperature and low humidity. This is because high temperature increases the rate of transpiration, which is the process by which water is lost from the plant to the atmosphere. This creates a suction force that pulls up water (and dye) from the roots to the leaves. Low humidity also increases the rate of transpiration because the concentration gradient of water vapor from the leaf to the atmosphere is higher, which drives the diffusion of water out of the leaf. Therefore, under high temperature and low humidity, the rate of transpiration is high, and the dye will move up the stem faster.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>6", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "Which of the following is not true of Rhizopus or mucor?  It", "images": [], "options": {"A": "manufactures its own food", "B": "has non-septate hyphae", "C": "undergoes sexual and asexual reproduction", "D": "bears spores in sporangia"}, "answer": "A", "explanation": "Rhizopus or Mucor are types of fungi. Fungi are heterotrophic organisms, which means they cannot manufacture their own food. They obtain their nutrients from organic substances, often decaying matter. Therefore, the statement that Rhizopus or Mucor manufactures its own food is not true. The other options are true: Rhizopus or Mucor has non-septate hyphae, undergoes both sexual and asexual reproduction, and bears spores in sporangia.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>7", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "The main reason why rotten eggs should be separated from fresh eggs is that", "images": [], "options": {"A": "foul air from the rotten eggs could easily diffuse through the shells of fresh eggs.", "B": "fresh eggs could easily crack if foul air diffuses into it.", "C": "It is difficult to get rid of foul air on egg shells.", "D": "a fresh egg shrinks if foul air diffuses into it."}, "answer": "A", "explanation": "The main reason why rotten eggs should be separated from fresh eggs is that foul air from the rotten eggs could easily diffuse through the shells of fresh eggs. This is due to the semi-permeable nature of eggshells, which allows gases to pass through. If rotten eggs are kept with fresh ones, the foul-smelling gases produced by the rotten eggs can diffuse through the shells of the fresh eggs, potentially affecting their quality.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>8", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : GROWTH", "question": "Which of the following is described as an increase in dry weight?", "images": [], "options": {"A": "Reproduction", "B": "Adsorption", "C": "Ingestion", "D": "Growth"}, "answer": "D", "explanation": "Growth in biological terms is often described as an increase in the dry weight of an organism. This is because growth involves the production of new cells and tissues which contribute to the overall mass or weight of the organism. Reproduction, adsorption, and ingestion do not directly relate to an increase in dry weight. Reproduction is the process of producing offspring, adsorption is the adhesion of atoms, ions, or molecules from a gas, liquid, or dissolved solid to a surface, and ingestion is the consumption of a substance by an organism.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>9", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "When the zygote of an organism continues to grow, it produces new cells by", "images": [], "options": {"A": "meiosis", "B": "crossing-over", "C": "gestation", "D": "mitosis"}, "answer": "D", "explanation": "When the zygote of an organism continues to grow, it produces new cells by mitosis.  Mitosis results in the formation of cells whose number doubles the number of initial(precursor) cells.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>10", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which of the following substances is a common excretory product in both plants and animals?", "images": [], "options": {"A": "Urine", "B": "Oxygen", "C": "Mineral salts", "D": "Carbon dioxide"}, "answer": "D", "explanation": "Both plants and animals release carbon dioxide as a common excretory product. In animals, it is a by-product of cellular respiration, while in plants, it is released during respiration and also when there is no sunlight for photosynthesis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>11", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following tissues does not offer support in plants?", "images": [], "options": {"A": "Meristem", "B": "Sclerenchyma", "C": "Collenchyma", "D": "Xylem"}, "answer": "A", "explanation": "Meristem is a type of plant tissue that is responsible for growth. It is found in regions of the plant that grow, such as the tips of roots or shoots. Unlike the other options (Sclerenchyma, Collenchyma, and Xylem), which are all types of supportive tissue, meristem does not provide support.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>12", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "The function of the human red blood cells is to", "images": [], "options": {"A": "make antibodies", "B": "carry oxygen", "C": "absorb heat", "D": "destroy bacteria"}, "answer": "B", "explanation": "The primary function of human red blood cells, or erythrocytes, is to transport oxygen from the lungs to the body's tissues and then transport carbon dioxide back to the lungs. They do this through a molecule called hemoglobin, which can bind to oxygen and carbon dioxide. The other options (making antibodies, absorbing heat, and destroying bacteria) are not functions of red blood cells.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>13", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Which of the following structures of the human body provides the best surface for diffusion?", "images": [], "options": {"A": "Skin", "B": "Stomach", "C": "Alveolus", "D": "Oesophagus"}, "answer": "C", "explanation": "The alveolus provides the best surface for diffusion in the human body. This is because the alveoli, which are tiny air sacs in the lungs, have very thin walls which allow for the efficient exchange of gases. Oxygen from the air we breathe in diffuses across these thin walls and into the blood, while carbon dioxide diffuses from the blood into the alveoli, from where it is exhaled. This process is known as gas exchange. The other options, skin, stomach, and oesophagus, do not provide as efficient a surface for diffusion as the alveoli do.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>14", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which of the following constitutes the cellular components of the mammalian blood?  I. Haemoglobin  II. Erythrocytes  III. Leucocytes  IV. Platelets", "images": [], "options": {"A": "I, II and III only", "B": "I, III and IV only", "C": "II, III and IV only", "D": "I, II, III and IV"}, "answer": "C", "explanation": "The components of the blood is analysed as thus:    RBC = Erythrocytes  WBC = Leucocytes", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>15", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "Transpiration in plants results in the", "images": [], "options": {"A": "closure of the stomata at night", "B": "continuous streaming of water through the plant", "C": "pale, green colouration of portions of the leaves", "D": "opening of stoma"}, "answer": "B", "explanation": "Transpiration is the process by which moisture is carried through plants from roots to small pores on the underside of leaves, where it changes to vapor and is released to the atmosphere. It is essentially the evaporation of water from plant leaves. Therefore, transpiration results in the continuous streaming of water through the plant. The other options are not correct because transpiration does not directly cause the closure of stomata at night, the pale green coloration of portions of the leaves, or the opening of stomata.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>16", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which organ removes the largest quantity of water from the blood?", "images": [], "options": {"A": "Lung", "B": "Intestine", "C": "Kidney", "D": "Skin"}, "answer": "C", "explanation": "The kidney is the organ that removes the largest quantity of water from the blood. This is because one of the primary functions of the kidneys is to filter blood and remove waste products and excess substances, including water, through the production of urine. This process is known as excretion. The other options, Lung, Intestine, and Skin, also remove water from the body but not as much as the kidneys do. The lungs remove water in the form of water vapor during exhalation, the intestines remove water during the process of digestion and absorption, and the skin removes water through sweating. However, these processes do not remove as much water as the kidneys do.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>17", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "In cold condition, the mammalian body reacts in the following ways except", "images": [], "options": {"A": "shivering of the body", "B": "dilation of the capillaries supplying blood of the skin", "C": "construction of blood capillaries in the skin", "D": "increased rate of chemical changes in the body"}, "answer": "B", "explanation": "In cold conditions, the body reacts by constricting, not dilating, the blood capillaries supplying the skin. This is to reduce heat loss from the body. The other options are correct: shivering generates heat, constriction of blood capillaries in the skin reduces heat loss, and the rate of chemical changes in the body increases to generate more heat.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>18", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "The glomerular filtrate contains the following substances except", "images": [], "options": {"A": "water", "B": "urea", "C": "blood corpuscles", "D": "glucose"}, "answer": "C", "explanation": "The glomerular filtrate is the liquid that is filtered out of the blood in the glomerulus of the kidney. It contains water, urea, glucose, and other small molecules. However, it does not contain blood corpuscles (red and white blood cells and platelets) because these are too large to pass through the filtration membrane in the glomerulus. Therefore, the correct answer is 'blood corpuscles'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>19", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "Which of the following endocrine glands is a master gland?", "images": [], "options": {"A": "Pituitary gland", "B": "Thyroid gland", "C": "Pancreas", "D": "Ovary"}, "answer": "A", "explanation": "The pituitary gland is often referred to as the 'master gland' because it controls the activities of most other hormone-secreting glands. It is a small pea-sized gland located at the base of the brain. It produces a number of critical hormones, which can stimulate other glands to produce different hormones. The other options listed, such as the thyroid gland, pancreas, and ovary, are all glands that the pituitary gland can influence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>20", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "The part of the nervous system that interpretes blinking of the eye is the", "images": [], "options": {"A": "spinal cord", "B": "cerebrum", "C": "hind brain", "D": "olfactory lobe"}, "answer": "B", "explanation": "The cerebrum is the part of the brain responsible for interpreting sensory impulses from the eyes and thus controls the blinking of the eye. The cerebrum is the largest part of the brain and is divided into two hemispheres. It performs higher functions like interpreting touch, vision and hearing, as well as speech, reasoning, emotions, learning, and fine control of movement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>21", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "The endocrine gland secreting hormones that induces the thyroid gland to produce more thyroxine is", "images": [], "options": {"A": "Islets of Langerhans", "B": "adrenal gland", "C": "pituitary gland", "D": "parathyroid gland"}, "answer": "C", "explanation": "The pituitary gland secretes Thyroid Stimulating Hormone (TSH) which stimulates the thyroid gland to produce more thyroxine. The pituitary gland is a small pea-sized gland that plays a major role in regulating vital body functions and general wellbeing. It is referred to as the body's 'master gland' because it controls the activity of most other hormone-secreting glands.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>22", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The layer of light-sensitive cells in the human eye is called the", "images": [], "options": {"A": "cornea", "B": "sclerotic layer", "C": "retina", "D": "conjunctiva"}, "answer": "C", "explanation": "The layer of light-sensitive cells in the human eye is called the retina. The retina is a thin layer of tissue that lines the back of the eye on the inside. It is located near the optic nerve. The purpose of the retina is to receive light that the lens has focused, convert the light into neural signals, and send these signals on to the brain for visual recognition.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>23", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "Which of the following is the function of the iris of the mammalian eye", "images": [], "options": {"A": "Closes and opens the eye", "B": "Absorbs dangerous rays from sunlight", "C": "Regulates the amounts of light entering the eye", "D": "Bringing light rays to focus on the retina"}, "answer": "C", "explanation": "The function of the iris in the mammalian eye is to regulate the amount of light that enters the eye. It does this by adjusting the size of the pupil, which is the hole in the center of the iris through which light enters the eye. When the environment is bright, the iris contracts to make the pupil smaller and allow less light in. When the environment is dark, the iris relaxes to make the pupil larger and allow more light in.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>24", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "Placentation of plants is best described as the", "images": [], "options": {"A": "arrangement of ovule in the ovary", "B": "arrangement of fruits on the branches", "C": "development of ovules in the ovary", "D": "formation of the pericarp from the ovary wall"}, "answer": "A", "explanation": "Placentation in plants refers to the arrangement of ovules within the ovary. This is a botanical term that describes the part where the ovule is attached within the ovary of a flowering plant. The other options do not accurately describe placentation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>25", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "A flowering plant having both male and female flowers on the same plant, is said to be", "images": [], "options": {"A": "regular", "B": "monoecious", "C": "irregular", "D": "dioecious"}, "answer": "B", "explanation": "A flowering plant that has both male and female flowers on the same plant is said to be monoecious. The term 'monoecious' is derived from the Greek words 'monos' meaning 'single' and 'oikos' meaning 'house'. This term is used in botanical nomenclature to describe a species in which male and female reproductive structures are present on the same individual. The other options do not accurately describe this condition.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>26", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "The function of the amniotic fluid in humans is to", "images": [], "options": {"A": "protect the foetus against shocks", "B": "remove waste products from the foetus", "C": "supply food and water to foetus", "D": "carry oxygen to the foetus"}, "answer": "A", "explanation": "The amniotic fluid, which surrounds a fetus in the womb, serves several purposes. One of its primary functions is to protect the fetus from physical shocks and impacts. It acts as a cushion, absorbing and distributing any forces that might otherwise harm the fetus. The other options are not primary functions of the amniotic fluid. The placenta, not the amniotic fluid, is responsible for removing waste products from the fetus, supplying food and water to the fetus, and carrying oxygen to the fetus.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>27", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following groups of compounds are products of the light stage of photosynthesis?  I. Ribulose bi-phosphate (RuBP)  II. Nicotin amide di-phosphorus (NADPH2)  III. Oxygen (O2)  IV. Adenosine Triphosphate (ATP)", "images": [], "options": {"A": "I, II and III", "B": "I, III and IV", "C": "II, III and IV", "D": "I, II, III and IV"}, "answer": "C", "explanation": "The light-dependent reactions, or light reactions, are the first stage of photosynthesis, the process by which plants capture and store energy from sunlight. In this stage, energy from light is absorbed by chlorophyll and that energy is converted into stored chemical energy in the form of NADPH (Nicotin amide di-phosphorus) and ATP (Adenosine Triphosphate). Also, Oxygen (O2) is produced as a by-product of this reaction. Ribulose bi-phosphate (RuBP) is not a product of the light stage of photosynthesis, it is actually a molecule that is involved in the next stage of photosynthesis - the Calvin cycle. Therefore, the correct answer is II, III and IV.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>28", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "In the test for starch, the leaf is first placed in boiling water to", "images": [], "options": {"A": "remove the chlorophyll", "B": "dissolve the waxy cuticle", "C": "kill and make the leaf permeable", "D": "turn it blue-black"}, "answer": "C", "explanation": "In the test for starch, the leaf is first placed in boiling water to kill the cells and make the leaf permeable. This process is known as denaturation. It is done to stop any further chemical reactions in the cells that could interfere with the test for starch. It also makes the leaf permeable, allowing the iodine solution used in the test for starch to penetrate the cells.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>29", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "Which of the following statements about water in humans is not correct? It", "images": [], "options": {"A": "plays an important role in temperature regulation", "B": "acts as solvent for substances conveyed around the body", "C": "plays a role in the formation of vitamin D", "D": "is needed for many life processes"}, "answer": "C", "explanation": "Water does not play a role in the formation of vitamin D. Vitamin D is synthesized in the skin in response to exposure to ultraviolet B radiation from the sun. It can also be obtained from certain foods, such as fatty fish, beef liver, and egg yolks. Water is essential for many life processes, acts as a solvent for substances conveyed around the body, and plays an important role in temperature regulation, but it does not contribute to the formation of vitamin D.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>30", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following is considered to be the first product of photosynthesis?", "images": [], "options": {"A": "Protein", "B": "Energised chlorophyll", "C": "Hydroxyl ions", "D": "Starch"}, "answer": "D", "explanation": "Starch is the first product formed during photosynthesis because the simple sugar formed is partly used by plant and excess of it is converted into starch", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>31", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Which of the following organisms exhibits extracellular digestion?", "images": [], "options": {"A": "Moulds", "B": "Green plants", "C": "Algae", "D": "Bryophytes"}, "answer": "A", "explanation": "Extracellular digestion is a process where digestion occurs outside the cell. Moulds, a type of fungi, exhibit this type of digestion. They secrete enzymes into the environment to break down large food molecules into smaller ones. These smaller molecules can then be absorbed into the cell.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>32", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following essential substance is contained in vegetables?", "images": [], "options": {"A": "Chlorophyll", "B": "Glucose", "C": "Mineral Salts", "D": "Carbon dioxide"}, "answer": "C", "explanation": "Vegetables are rich in essential substances such as vitamins, fiber, and mineral salts. Mineral salts are essential for the body's metabolic processes, including nerve and muscle function, pH balance, and enzyme reactions. Chlorophyll is the green pigment in plants that absorbs sunlight for photosynthesis, and it's not an essential substance for human nutrition. Glucose is a type of sugar that provides energy, but it's not typically found in high amounts in vegetables. Carbon dioxide is a gas that's exhaled as a waste product of respiration, and it's not a substance that's consumed in the diet.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>33", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Good quality food will perform the following functions in humans except", "images": [], "options": {"A": "supplying energy", "B": "providing resistance against malaria", "C": "sustaining growth", "D": "maintaining health"}, "answer": "B", "explanation": "Good quality food provides nutrients that are essential for the body's functions, including supplying energy, sustaining growth, and maintaining health. However, food does not provide resistance against specific diseases like malaria. Malaria is a disease caused by a parasite that's transmitted through the bite of an infected mosquito. Resistance against malaria depends on the immune system and is typically provided by medications or vaccines, not food.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>34", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION", "question": "The type of nutrition shown by Spirogyra is", "images": [], "options": {"A": "symbiosis", "B": "holophytic", "C": "holozoic", "D": "chemosynthetic"}, "answer": "B", "explanation": "Spirogyra is a type of green algae that is found in fresh water habitats. It performs photosynthesis, a process by which green plants and some other organisms use sunlight to synthesize foods with the help of chlorophyll pigments. During photosynthesis, light energy is converted into chemical energy in the form of glucose. This type of nutrition where an organism makes its own food using light, water and carbon dioxide is known as holophytic nutrition. Therefore, the correct answer is holophytic.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>35", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "The term ecosystem refers to", "images": [], "options": {"A": "different groups of green plants in a habitat", "B": "living members of a habitat", "C": "living organisms interacting with the physical environment", "D": "members of particular plants and animals living in a habitat"}, "answer": "C", "explanation": "An ecosystem refers to a biological community of interacting organisms and their physical environment. This includes both the living (biotic) components, such as plants, animals, and bacteria, and the non-living (abiotic) components, such as weather, soil, and water. Therefore, the correct answer is 'living organisms interacting with the physical environment'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>36", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS", "question": "Ecology is best defined as the study of", "images": [], "options": {"A": "the characteristics of an environment", "B": "the inter-relationship between living organisms and the environment", "C": "living organisms in a particular area", "D": "the habitats and wildlife"}, "answer": "B", "explanation": "Ecology is the scientific study of the interactions between organisms and their environment. This includes both the physical environment, which can be described as the sum total of local abiotic factors such as insolation (sunlight received), climate, and geology, and the biotic environment, composed of other organisms. Therefore, the correct answer is 'the inter-relationship between living organisms and the environment'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>37", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Which of the following environmental factors is not considered in a terrestrial habitats?", "images": [], "options": {"A": "Temperature", "B": "Sunlight", "C": "Humidity", "D": "Turbidity"}, "answer": "D", "explanation": "Turbidity \"implies\" the clearness of water (e.g seas, oceans, ponds, lakes, e.t.c.)  Turbidity is an abiotc factor that is looked out for in aquatic habitat.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>38", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Which of the following values showing the total biomass of organisms in a food chain represents the secondary consumer?", "images": [], "options": {"A": "40,000", "B": "3,000", "C": "20", "D": "1"}, "answer": "C", "explanation": "In an ecosystem, the values of the total biomass of trophic levels decreases from producer to primary consumer to secondary consumers then to the decomposers.  Producers > Primary consumer > Secondary Consumer > Decomposers   e.g: (40,000) &nbsp &nbsp (3,000) &nbsp &nbsp (20) &nbsp &nbsp (1)", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>39", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "The gas produced during decomposition of matter is", "images": [], "options": {"A": "hydrogen sulphide", "B": "carbon monoxide", "C": "chlorine", "D": "oxygen"}, "answer": "A", "explanation": "During the decomposition of organic matter, several gases are produced. One of the most common gases is hydrogen sulphide. This gas is produced by bacteria during the breakdown of organic materials that contain sulfur. Therefore, the correct answer is 'hydrogen sulphide'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>40", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Fish cannot survive on land because it has", "images": [], "options": {"A": "a body covered with scales", "B": "a streamlined body", "C": "no lungs", "D": "no walking appendages"}, "answer": "C", "explanation": "Fish cannot survive on land because they do not have lungs to breathe air. They have gills, which are designed to extract oxygen from water, not air.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>41", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Pneumatophores are essential for", "images": [], "options": {"A": "nutrition", "B": "movement", "C": "breathing", "D": "growth"}, "answer": "C", "explanation": "Pneumatophores are specialized root structures that grow out from the water surface and facilitate the aeration necessary for root respiration in hydrophytic trees such as many mangrove species.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>42", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION", "question": "Which of the following will have the least effect on the rate of change of the numbers in a population.", "images": [], "options": {"A": "Food supply", "B": "Mutation", "C": "Predation", "D": "Disease"}, "answer": "B", "explanation": "Mutation is the least likely to have an immediate effect on the rate of change of the numbers in a population. Mutation is a change in the DNA sequence within a gene or chromosome of an organism resulting in the creation of a new character or trait not found in the parental type. The effects of mutation on a population are usually not immediate, they take generations to manifest and influence the population size.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>43", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION", "question": "Competition among individual of a population increases the", "images": [], "options": {"A": "number of organisms", "B": "survival of the fittest", "C": "availability of nutrient supplied", "D": "enlargement of the territory"}, "answer": "B", "explanation": "Competition among individuals of a population increases the survival of the fittest. This is a concept derived from Darwinian evolutionary theory, where competition for limited resources leads to survival of the individuals best adapted to the conditions. These individuals pass on their traits to the next generation, leading to evolution of the species over time.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>44", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : ADAPTATION OF ORGANISMS TO HABITATS.", "question": "Rabbits cannot survive in an aquatic habitat because they have", "images": [], "options": {"A": "fore and hind-limbs", "B": "no gills", "C": "no fins", "D": "no scales"}, "answer": "B", "explanation": "Rabbits cannot survive in an aquatic habitat because they do not have gills. Gills are the respiratory organ found in many aquatic organisms that extracts dissolved oxygen from water and excretes carbon dioxide. Rabbits, being terrestrial mammals, have lungs for respiration, not gills.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>45", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION", "question": "Viruses are pathogens of the following disease except", "images": [], "options": {"A": "measles", "B": "small pox", "C": "poliomyelitis", "D": "tuberculosis"}, "answer": "D", "explanation": "Tuberculosis is not caused by a virus, but by a bacterium called Mycobacterium tuberculosis. The other diseases listed (measles, small pox, and poliomyelitis) are all caused by viruses. Therefore, viruses are not pathogens of tuberculosis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>46", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "Renewable resources are formed by", "images": [], "options": {"A": "animals that reproduce sexually", "B": "organisms confined to forest reserves", "C": "organisms that are constantly regenerating themselves", "D": "plants and animals that can reproduce sexually"}, "answer": "C", "explanation": "Renewable resources are resources that are replenished naturally and over relatively short periods of time. This includes resources that are constantly regenerating themselves. Animals that reproduce sexually, organisms confined to forest reserves, and plants and animals that can reproduce sexually do not necessarily form renewable resources. The key factor is the ability of the resource to regenerate itself.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>47", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Forest conservation includes the following except", "images": [], "options": {"A": "prevention of bush-fires", "B": "extensive felling of forest-trees", "C": "replacing of harvested trees by planting seedlings", "D": "selective exploitation of forest trees"}, "answer": "B", "explanation": "Forest conservation includes measures to protect and preserve forest ecosystems. This includes prevention of bush-fires, replacing of harvested trees by planting seedlings, and selective exploitation of forest trees. Extensive felling of forest trees is not a conservation measure, but rather a destructive activity that leads to deforestation and loss of biodiversity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>48", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Legumes incorporates nitrogen gas into their protein because", "images": [], "options": {"A": "of the presence of Azotoacter in their roots", "B": "they possess root nodules containing Rhizobium", "C": "they have a well developed root system", "D": "they are autotrophic"}, "answer": "B", "explanation": "Legumes are able to incorporate nitrogen gas into their protein due to the presence of Rhizobium bacteria in their root nodules. This process is known as nitrogen fixation. Nitrogen fixation is the process by which nitrogen in the atmosphere is converted into ammonia (NH3) or related nitrogenous compounds in soil. Rhizobium bacteria in the root nodules of legumes perform this process, converting atmospheric nitrogen into a form that the plants can use for growth.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>49", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE", "question": "Improper sewage disposal could be dangerous for the following reasons except", "images": [], "options": {"A": "the smell of carelessly disposed sewage water is most undesirable", "B": "the spread of gastro-intestinal diseases are enhanced", "C": "resultant out-break of water-borne diseases", "D": "there would be little space for disposal of wastes"}, "answer": "D", "explanation": "There would be little space for sewage disposal - Improper sewage disposal leads to exhaustion of land space, but is not really dangerous compared to what is stated in the rest of the options.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>50", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Which of the following is an example of continuous variation?", "images": [], "options": {"A": "Human Blood groups", "B": "Sex differences in humans", "C": "Haemoglobin types", "D": "Height in humans"}, "answer": "D", "explanation": "Continuous variation refers to a range of small differences in a shared trait among individuals. Height in humans is an example of continuous variation because it can take on any value within a range, not just distinct categories. The other options like human blood groups, sex differences in humans, and haemoglobin types are examples of discontinuous variation, where individuals fall into a number of distinct classes or categories, and is based on differences in a single gene.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>51", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Which of the following is an example of continuous variation?", "images": [], "options": {"A": "Human Blood groups", "B": "Sex differences in humans", "C": "Haemoglobin types", "D": "Height in humans"}, "answer": "D", "explanation": "Continuous variation refers to a range of small differences in a shared trait among individuals. Height in humans is an example of continuous variation because it can take on any value within a range, not just distinct categories. The other options like human blood groups, sex differences in humans, and haemoglobin types are examples of discontinuous variation, where individuals fall into a number of distinct classes or categories, and is based on differences in a single gene.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>52", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of the following pairs of scientists discovered the Rhesus factor in human blood?", "images": [], "options": {"A": "Hooke and Lavine", "B": "Darwin and Landsteiner", "C": "Landsteiner and Lavine", "D": "Hooke and Darwin"}, "answer": "C", "explanation": "The Rhesus factor in human blood was discovered by Karl Landsteiner and Alexander S. Wiener. Landsteiner and Lavine is the closest option, although it's not entirely accurate because Wiener, not Lavine, was Landsteiner's partner in this discovery.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>53", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The organic molecule(s) present in the nucleus is/are", "images": [], "options": {"A": "DNA", "B": "Protein, RNA and DNA", "C": "RNA and ATP", "D": "RNA"}, "answer": "B", "explanation": "The nucleus of a cell contains DNA, RNA, and proteins. DNA (Deoxyribonucleic acid) is the genetic material that carries information about an organism and is used in the development and functioning of its cells. RNA (Ribonucleic acid) is involved in protein synthesis and sometimes in the transmission of genetic information. Proteins in the nucleus are involved in maintaining the structure of the nucleus and also in gene expression.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>54", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "Use the following information to answer this question  In an experiment, a red-flowered plant was crossed with another white-flowered plant and the following results were obtained: 448 red flowers and 154 white flowers in the F1 generation.    Which of the following represents the genotypes of the parents if R is for red gene and r for white gene?", "images": [], "options": {"A": "RR × Rr", "B": "RR × rr", "C": "rr × rr", "D": "Rr × Rr"}, "answer": "B", "explanation": "RR × rr represents the genotypes of the parents if R is for red gene and r for white gene", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2003>55", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "Use the following information to answer this question  In an experiment, a red-flowered plant was crossed with another white-flowered plant and the following results were obtained: 448 red flowers and 154 white flowers in the F1 generation.  Which of the following represents the phenotypic ratio of the above genetic cross?", "images": [], "options": {"A": "1 : 2 : 1", "B": "4 : 1", "C": "3 : 1", "D": "2 : 2"}, "answer": "C", "explanation": "The phenotypic ratio of the above genetic cross is 3:1", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>56", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "A sudden loss of black pigment from the skin of an African can be attributed to", "images": [], "options": {"A": "a blending of black and white genes", "B": "a recombination of genes", "C": "loss of the epidermis", "D": "mutation in the skin cells"}, "answer": "D", "explanation": "The sudden loss of black pigment from the skin of an African can be attributed to a mutation in the skin cells. A mutation is a change in the DNA sequence that can lead to different phenotypes. In this case, the mutation could have affected the genes responsible for the production of melanin, the pigment that gives skin its color. The other options are not correct because blending of genes and recombination of genes are not processes that would result in a sudden loss of pigment, and loss of the epidermis would result in severe skin damage, not just a change in color.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2003>57", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "In Mendel's experiments, it was discovered that the F1 generation of a cross between a brown cock and a white hen were all brown because the gene for the", "images": [], "options": {"A": "brown colour was recessive", "B": "white colour was dominant", "C": "brown colour was dominant", "D": "white colour did not combine"}, "answer": "C", "explanation": "In Mendel's experiments, it was discovered that the F1 generation of a cross between a brown cock and a white hen were all brown because the gene for the brown colour was dominant. This is based on Mendel's law of dominance which states that in a cross of parents that are pure for contrasting traits, only one form of the trait will appear in the next generation. All the offspring will be heterozygous and express only the dominant trait. The dominant trait is the trait that is expressed when two different genetic alleles for a specific trait are present in a gene's pair.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>58", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Sickle-cell anaemia has persisted in the human race due to", "images": [], "options": {"A": "lack of proper medical care for sicklers", "B": "carriers being more resistant to malaria", "C": "mosquito vectors", "D": "wildlife intermediate hosts"}, "answer": "B", "explanation": "Sickle-cell anaemia has persisted in the human race due to carriers being more resistant to malaria. This is because the sickle-cell trait provides a survival advantage: individuals with one sickle gene (carriers) are less likely to die from malaria, a disease that is very common in Africa where the sickle cell gene is more common. This is an example of balanced polymorphism, genetic variation which leads to differing traits in a population.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>59", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following is not a behavioural adaptation used by the social animals?", "images": [], "options": {"A": "Cryptic", "B": "Mimicry", "C": "Flash", "D": "Season"}, "answer": "D", "explanation": "Behavioural adaptations are changes in the behaviour of an organism that help it to survive and reproduce in its environment. Cryptic behaviour, mimicry, and flash are all examples of behavioural adaptations used by social animals. Cryptic behaviour involves hiding or camouflage, mimicry involves imitating another species or object, and flash involves sudden, conspicuous displays to distract or confuse predators. 'Season' is not a behavioural adaptation, it is a period of the year characterized by particular conditions of weather, and associated with particular activities, celebrations, or festivals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2003>60", "subject": "Biology", "year": "2003", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "In natural selection, Darwin proposed that evolution occurred because of the following conditions except", "images": [], "options": {"A": "food and other needs are abundant", "B": "there is a fierce competition among the offsprings", "C": "that the weaker offsprings are eliminated", "D": "that nature selects those that will survive to reproduce their kind"}, "answer": "A", "explanation": "Darwin's theory of natural selection is based on the idea that resources such as food and space are limited, which leads to competition among individuals. The option 'food and other needs are abundant' contradicts this principle, as it suggests that resources are plentiful, which would eliminate the need for competition and natural selection.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>1", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "Which of the following characteristics is not possessed by most plants? Ability to", "images": [], "options": {"A": "move away from stimuli", "B": "respire", "C": "reproduce", "D": "adapt to environment"}, "answer": "A", "explanation": "Most plants do not have the ability to move away from stimuli. While some plants do exhibit movement in response to stimuli (a phenomenon known as tropism), this is not a characteristic possessed by most plants. Respiration, reproduction, and adaptation to the environment are all fundamental characteristics of plants.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2004>2", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "Hydra is able to perform all the following functions except", "images": [], "options": {"A": "feeding", "B": "movement", "C": "photosynthesis", "D": "egestion"}, "answer": "C", "explanation": "Hydra, being an aquatic animal, does not have the ability to perform photosynthesis. Photosynthesis is a process used by plants and other organisms to convert light energy, usually from the Sun, into chemical energy that can be later released to fuel the organisms' activities. This energy is stored in carbohydrate molecules, such as sugars, which are synthesized from carbon dioxide and water. Hydra can feed, move and perform egestion, but it cannot perform photosynthesis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>3", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "Euglena can be classified as an animal because of the possession of", "images": [], "options": {"A": "nucleus", "B": "cytoplasm", "C": "cell wall", "D": "pellicle"}, "answer": "D", "explanation": "Euglena is a unique organism that shows characteristics of both plants and animals. While it can photosynthesize like a plant due to the presence of chloroplasts, it also exhibits animal-like behavior such as movement. The presence of a pellicle, a thin layer supporting the cell membrane, allows Euglena to change shape and move, which is a characteristic of animals. Therefore, the possession of a pellicle can be a reason to classify Euglena as an animal.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2004>4", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which two structures are present in a palisade cell but not in a liver cell?", "images": [], "options": {"A": "Cell wall and cytoplasm", "B": "Cell wall and chloroplast", "C": "Cell membrane and cytoplasm", "D": "Cell membrane and chloroplast"}, "answer": "B", "explanation": "Palisade cells are a type of plant cell and are found in the mesophyll of a leaf under the epidermis. They contain chloroplasts for photosynthesis, which are not present in animal cells like liver cells. Also, plant cells have a rigid cell wall that provides structural support, which is also not present in animal cells. Therefore, the two structures present in a palisade cell but not in a liver cell are the cell wall and chloroplast.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>5", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The nucleus controls the activities of the cell because it", "images": [], "options": {"A": "synthesizes hormones", "B": "is like a brain in the cell", "C": "uses DNA to synthesize enzymes which are used in cell metabolism", "D": "sends out nervous impulses to ensure the functioning of the cytoplasm"}, "answer": "C", "explanation": "The nucleus controls the activities of the cell because it contains DNA, which is used to synthesize enzymes. These enzymes are crucial for cell metabolism, which includes all the chemical reactions that occur within the cell to maintain life. The nucleus does not synthesize hormones or send out nervous impulses, and while it is often referred to as the 'brain of the cell', this is a metaphor and not a literal description of its function.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>6", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "The process by which a drop of ink spreads uniformly in a beaker of water is called", "images": [], "options": {"A": "absorption", "B": "osmosis", "C": "plasmolysis", "D": "diffusion"}, "answer": "D", "explanation": "Diffusion is defined as the process in which molecule moves from a region of higher concentration to a region of lower concentration until they are evenly distributed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>7", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "When a person's urine contains a high concentration of urea, it could be the result of", "images": [], "options": {"A": "a drop in body temperature.", "B": "having diabetes melitus.", "C": "eating a meal rich in protein.", "D": "drinking a large amount of water."}, "answer": "C", "explanation": "When a person's urine contains a high concentration of urea, it could be the result of eating a meal rich in protein. This is because protein metabolism produces urea, which is excreted in the urine. Therefore, a high-protein diet can lead to an increase in the concentration of urea in the urine.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2004>8", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "How many conjugants are involved in sexual reprodution of paramecium?", "images": [], "options": {"A": "1", "B": "2", "C": "4", "D": "8"}, "answer": "B", "explanation": "In the sexual reproduction of paramecium, two conjugants are involved. This process is known as conjugation where two paramecium come in contact and exchange genetic material. Therefore, the correct answer is 2.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2004>9", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following groups of vertebrae have two branches at the end of their transverse processes?", "images": [], "options": {"A": "Sacral", "B": "Thoracic", "C": "Cervical", "D": "Lumbar"}, "answer": "C", "explanation": "The cervical vertebrae, specifically C3 to C6, have transverse processes that end in two branches known as anterior and posterior tubercles. These tubercles serve as attachment points for muscles and ligaments. This bifid (split) nature of the transverse processes is a distinctive feature of the cervical vertebrae, unlike the thoracic, lumbar, or sacral vertebrae, which do not have this characteristic branching.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>10", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The axial skeleton is made up of the following", "images": [], "options": {"A": "skull, vertebral column, rib cage and sternum", "B": "limbs and limb girdles", "C": "lumbar and thoracic vertebrae", "D": "verterbral column and lumbar vertebrae"}, "answer": "A", "explanation": "The axial skeleton is part of the skeleton that consists of the bones of the head and trunk of a vertebrate. It is made up of the skull, vertebral column, rib cage, and sternum.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>11", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The xylem elements perform the function of transport but they also help to support plants because they", "images": [], "options": {"A": "are internally located", "B": "are tubular", "C": "have rigid thick walls", "D": "constantly absorb water"}, "answer": "C", "explanation": "The xylem elements in plants perform the function of transporting water and nutrients from the roots to the leaves. They also provide structural support to the plant because they have rigid thick walls. The thick walls are due to the presence of lignin, a complex organic polymer that hardens and strengthens the cell walls of xylem.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>12", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Excessive bleeding from an injury may be due to lack of vitamin.", "images": [], "options": {"A": "A", "B": "B", "C": "D", "D": "K"}, "answer": "D", "explanation": "Vitamin K is essential for the process of blood clotting. It aids in the production of prothrombin, a protein and clotting factor that is important in blood clotting and bone metabolism. Therefore, a deficiency in Vitamin K can lead to excessive bleeding when an injury occurs.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2004>13", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "The hepatic portal vein is often heavily loaded with food-nutrients because it carries blood", "images": [], "options": {"A": "directly from the heart.", "B": "from the liver to the heart.", "C": "from the small intestine to the liver.", "D": "from the liver to join the posterior vena cava"}, "answer": "C", "explanation": "The hepatic portal vein is a blood vessel that conducts blood from the gastrointestinal tract and spleen to the liver. This blood is rich in nutrients absorbed from the small intestine, hence the hepatic portal vein is often heavily loaded with food-nutrients. Therefore, the correct answer is 'from the small intestine to the liver.'", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>14", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "The products of respiration are", "images": [], "options": {"A": "nitrogen and water", "B": "nitrogen and carbondioxide", "C": "water and oxygen", "D": "carbon dioxide and water"}, "answer": "D", "explanation": "The products of respiration are carbon dioxide and water. Respiration is a metabolic process that occurs in living cells to convert biochemical energy from nutrients into adenosine triphosphate (ATP), and then release waste products. The nutrients broken down are usually glucose, amino acids and fatty acids, and the waste products are carbon dioxide and water. Therefore, the correct answer is 'carbon dioxide and water.'", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2004>15", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "Green plants lose water to the atmosphere through the process of", "images": [], "options": {"A": "respiration", "B": "photosynthesis", "C": "transpiration", "D": "translocation"}, "answer": "C", "explanation": "Green plants lose water to the atmosphere through the process of transpiration. Transpiration is the process by which moisture is carried through plants from roots to small pores on the underside of leaves, where it changes to vapor and is released to the atmosphere. It is essentially evaporation of water from plant leaves.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2004>16", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "The body temperature of a mammal has to be maintained at a fairly constant level because", "images": [], "options": {"A": "excessive heat is continually lost by the body to the environment", "B": "their body temperature is always higher than that of the environment", "C": "evaporation of sweat cools the body", "D": "metabolic activities function best at certain temperature"}, "answer": "D", "explanation": "The body temperature of a mammal has to be maintained at a fairly constant level because metabolic activities function best at certain temperatures. This is known as homeostasis, which is the maintenance of a stable internal environment despite changes in external conditions. The metabolic reactions that occur in the body are enzyme-driven and enzymes work best at specific temperatures.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>17", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "A urine sample of a patient, tested with Benedict/Fehling solution, gave an orange coloured precipitate, indicating the presence of", "images": [], "options": {"A": "glucose", "B": "sucrose", "C": "lactose", "D": "maltose"}, "answer": "A", "explanation": "Benedict's solution is a chemical indicator for simple sugars such as glucose. When Benedict's solution and simple sugars are heated, the solution changes to green, yellow, orange, red depending on the amount of sugar. In this case, an orange precipitate indicates the presence of glucose.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>18", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "Which hormonal deficiency is likely to cause an accumulation of reducing sugar in the urine?", "images": [], "options": {"A": "Thyroxine", "B": "Insulin", "C": "Secretin", "D": "Testosterone"}, "answer": "B", "explanation": "The hormone insulin regulates the amount of glucose in the body. When there is a deficiency of insulin, the body cannot use or store glucose properly, so it accumulates in the blood and eventually spills over into the urine. This condition is known as diabetes mellitus.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2004>19", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "Which of the following structures occupies the neural canal of the vertebral column?", "images": [], "options": {"A": "Cerebellum", "B": "Hypothalamus", "C": "Medulla oblongata", "D": "Spinal cord"}, "answer": "D", "explanation": "The neural canal of the vertebral column is occupied by the spinal cord. The spinal cord is a long, thin, tubular structure made up of nervous tissue, which extends from the medulla oblongata in the brainstem to the lumbar region of the vertebral column. It encloses the central canal of the spinal cord that contains cerebrospinal fluid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>20", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "The diagram below is the dorsal view of a mammalian brain.    Use it to answer this question    The structure labelled I in the diagram above is the", "images": ["Biology/imgs/2004/D936K6.jpg"], "options": {"A": "cerebellum", "B": "cerebrum", "C": "olfactory lobe", "D": "medulla oblongata"}, "answer": "C", "explanation": "The structure labeled \"I\" in the diagram is the olfactory lobe.  - The diagram shows a brain structure with different parts labeled.   - The olfactory lobe is typically located at the front part of the brain and is responsible for the sense of smell.  - In the given diagram, the structure labeled \"I\" is positioned at the front, which aligns with the typical location of the olfactory lobe.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>21", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "The diagram below is the dorsal view of a mammalian brain.    Use it to answer this question  The structure labelled VIII in the diagram is responsible for", "images": ["Biology/imgs/2004/D936K6.jpg"], "options": {"A": "vision", "B": "involuntary actions", "C": "speech", "D": "voluntary action"}, "answer": "B", "explanation": "The structure labeled \"VIII\" in the diagram corresponds to the medulla oblongata.  - The medulla oblongata is part of the brainstem and is responsible for regulating involuntary actions such as heart rate, breathing, and digestion.  - Given its critical role in these autonomic functions, it is clear that the medulla oblongata handles involuntary actions.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2004>22", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "Which of the following occurs when a person looks at a distant, dim object and then looks at a much closer, bright object? In each eye, the pupil becomes", "images": [], "options": {"A": "larger, while the lens becomes thicker.", "B": "larger, while the lens becomes thinner.", "C": "smaller, while the lens becomes thicker.", "D": "smaller, while the lens becomes thinner."}, "answer": "C", "explanation": "When a person looks at a distant, dim object and then looks at a much closer, bright object, the pupil becomes smaller to limit the amount of light entering the eye due to the brightness of the closer object. The lens becomes thicker to increase its refractive power and focus on the closer object. This process is known as accommodation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>23", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The following insects undergo incomplete metamorphosis except", "images": [], "options": {"A": "termite", "B": "cockroach", "C": "butterfly", "D": "locust"}, "answer": "C", "explanation": "Incomplete metamorphosis is a type of insect development that includes three stages: egg, nymph, and adult. The nymph stage looks like a small version of the adult but without the wings. Insects like termites, cockroaches, and locusts undergo incomplete metamorphosis. However, butterflies undergo complete metamorphosis which includes four stages: egg, larva (caterpillar), pupa (chrysalis), and adult.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>24", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The process by which fruits develop without fertilization is called", "images": [], "options": {"A": "parthenocarpy", "B": "pathology", "C": "hermaphroditism", "D": "layering"}, "answer": "A", "explanation": "Parthenocarpy is the process by which fruits develop without fertilization. In this process, the fruit is formed without the fertilization of ovules, which results in seedless fruits. Pathology is the study of disease, hermaphroditism is the condition of having both male and female reproductive organs, and layering is a method of plant propagation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>25", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following groups contains only macro-nutrients?", "images": [], "options": {"A": "Phosphorus, nitrogen and molybdenum", "B": "Manganese, copper and zinc", "C": "Boron, sulphur and iron", "D": "Calcium, magnesium and potassium"}, "answer": "D", "explanation": "Macronutrients are nutrients that plants need in large amounts. These include primary macronutrients like nitrogen (N), phosphorus (P), and potassium (K). The secondary nutrients are calcium (Ca), magnesium (Mg), and sulfur (S). The option that contains only macronutrients is 'Calcium, magnesium and potassium'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>26", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "A solution which contains all the required elements in their correct proportions is known as a", "images": [], "options": {"A": "culture nutrient", "B": "growth medium", "C": "complete culture solution", "D": "nutrient solution"}, "answer": "C", "explanation": "A solution which contains all the required elements in their correct proportions is known as a complete culture solution. This is because it provides all the necessary nutrients for the plant to grow and develop properly. A culture nutrient is a nutrient required for the growth of culture, a growth medium is a solid, liquid or semi-solid designed to support the growth of microorganisms or cells, and a nutrient solution is a solution composed of water and essential nutrients for plant growth.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>27", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The deficiency of manganese in plants result in", "images": [], "options": {"A": "death of shoot", "B": "leaves turning yellow", "C": "stunted growth", "D": "poor root development"}, "answer": "B", "explanation": "Manganese is a crucial micronutrient for plants, playing a vital role in various physiological processes, including photosynthesis, respiration, and nitrogen assimilation. A deficiency of manganese typically manifests in plants through interveinal chlorosis, which is the yellowing of leaves while the veins remain green. This symptom is especially evident in younger leaves.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>28", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "Which of the following is not true about a potted plant left in the laboratory for one week without watering?", "images": [], "options": {"A": "The cells of the plant will be turgid.", "B": "There will be wilting of the plant.", "C": "The leaves are likely to turn yellow.", "D": "Plant will not take in enough nutrients."}, "answer": "A", "explanation": "When a plant is left without watering for a week, it will experience water stress. This will lead to the loss of turgidity in the plant cells, causing the plant to wilt. Therefore, the statement that 'The cells of the plant will be turgid' is not true in this context. Turgidity in plant cells is maintained by the presence of water. When a plant is not watered, it loses water through transpiration, and without a source to replace this lost water, the cells lose their turgidity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>29", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "The deficiency of vitamin D and calcium ions in the diet of a human causes", "images": [], "options": {"A": "anaemia", "B": "night-blindness", "C": "kwashiokor", "D": "rickets"}, "answer": "D", "explanation": "The deficiency of vitamin D and calcium ions in the diet of a human causes rickets. Vitamin D helps the body absorb calcium and phosphate from our diet. These minerals are important for healthy bones and teeth. A lack of vitamin D - known as vitamin D deficiency - can lead to a bone deformity illness called rickets in children.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>30", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION", "question": "An organism is considered a heterotroph when it", "images": [], "options": {"A": "feeds on inorganic food", "B": "feeds on already manufactured food", "C": "fixes atmospheric nitrogen", "D": "respires anaerobically"}, "answer": "B", "explanation": "An organism is considered a heterotroph when it feeds on already manufactured food. Heterotrophs are organisms that obtain their energy (nutrition) from organic compounds/materials. In other words, they cannot produce their own food, as plants do through photosynthesis, and therefore, they rely on consuming other organisms for their energy needs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>31", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "The break-down of food into simple, soluble and absorbable end-products is termed.", "images": [], "options": {"A": "absorption", "B": "ingestion", "C": "nutrition", "D": "digestion"}, "answer": "D", "explanation": "The break-down of food into simple, soluble and absorbable end-products is termed digestion. Digestion is the process by which food is broken down by enzymes into smaller, absorbable molecules. Absorption refers to the process by which these molecules are taken up by cells and tissues. Ingestion is the process of taking food into the body, and nutrition refers to the overall process of consuming and utilizing food for growth and health.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2004>32", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following teeth are well-developed to form the carnassial teeth of carnivorous mammals? The", "images": [], "options": {"A": "first lower premolar and third upper molar", "B": "first lower molar and third upper premolar", "C": "second lower premolar and first lower molar", "D": "first lower molar and last upper premolar"}, "answer": "D", "explanation": "Carnassial teeth are a pair of bladelike teeth that occur in most carnivorous mammals. The first lower molar and last upper premolar are well-developed to form the carnassial teeth of carnivorous mammals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>33", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "Biosphere is best described as", "images": [], "options": {"A": "all parts of the earth where life exist", "B": "the non-living parts of an ecosystem", "C": "all components of an ecosystem", "D": "all the members of a single species in a habitat"}, "answer": "A", "explanation": "The biosphere is the global sum of all ecosystems. It can also be termed as the zone of life on Earth, a closed system (apart from solar and cosmic radiation and heat from the interior of the Earth), and largely self-regulating. By the most general biophysiological definition, the biosphere is the global ecological system integrating all living beings and their relationships, including their interaction with the elements of the lithosphere, geosphere, hydrosphere, and atmosphere. Therefore, the biosphere is best described as all parts of the earth where life exists.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2004>34", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Which of the following is not essential in the studying of the ecological factors that directly affect plants?", "images": [], "options": {"A": "Wind", "B": "Temperature", "C": "Herbivores", "D": "Carnivores"}, "answer": "D", "explanation": "Ecological factors that directly affect plants are abiotic (non-living) and biotic (living) factors. Abiotic factors include wind, temperature, sunlight, soil, etc. Biotic factors include herbivores, parasites, etc. Carnivores do not directly affect plants as they are secondary or tertiary consumers in the food chain, feeding on herbivores or other carnivores, not on plants.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>35", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "Conservation of soil fertility employs crop rotation because", "images": [], "options": {"A": "crop are allowed to grow at their own rates", "B": "it encourages the healthy growth of plants", "C": "it allows utilization of soil nutrients at different levels", "D": "different crops grow at the same time"}, "answer": "C", "explanation": "Crop rotation is a method of soil conservation that involves growing different types of crops in the same area, in sequenced seasons. It is done so that the soil of farms is not used for only one set of nutrients. It helps in reducing soil erosion and increases soil fertility and crop yield. Different crops utilize soil nutrients at different levels, hence, rotating crops will allow for the optimal use of nutrients.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>36", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Study the diagram below showing three food chains. Use it to answer this question.    Which of the following are consumers in these food chains?", "images": ["Biology/imgs/2004/RBC6H6.png"], "options": {"A": "Maize and rabbits", "B": "Chicken, rats and maize", "C": "Eagle, maize and snakes", "D": "Humans, eagle and snakes"}, "answer": "D", "explanation": "Consumers feeds directly on the producers e.g human, eagle and snakes.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2004>37", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "An importance of food web is that living organisms", "images": [], "options": {"A": "use web to collect food", "B": "can live on their own", "C": "have to form a web", "D": "depend on one another for their existence"}, "answer": "D", "explanation": "A food web is a system of interlocking and interdependent food chains. It's a graphical representation of what eats what in an ecological community. The importance of a food web is that it shows the interdependence of organisms for their existence. Each organism in a food web relies on the others for food, either directly or indirectly. This interdependence ensures the balance and survival of an ecosystem.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>38", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "The continuity of an ecosystem depends on constant flow of energy and circulation of matter. However, the amount of energy passed on from decomposers to producers should be", "images": [], "options": {"A": "great", "B": "small", "C": "reversible", "D": "zero"}, "answer": "D", "explanation": "In an ecosystem, energy flows from producers (plants) to consumers (animals) and then to decomposers. The energy is not passed back from decomposers to producers. Instead, decomposers break down dead organic material and return nutrients to the soil, which can be used by producers. This is a one-way flow of energy, not a cycle, so the amount of energy passed from decomposers to producers is zero.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>39", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following features enables the tape worm to live successfully in the small intestine of human?", "images": [], "options": {"A": "Hooks and suckers for strong attachment", "B": "A long neck for forming young proglottis", "C": "The absence of segmentation and appendages", "D": "possession of flame cells for excretion"}, "answer": "A", "explanation": "The tapeworm has hooks and suckers on its head (scolex) which it uses to attach itself to the wall of the small intestine. This prevents it from being swept away by the movement of the intestine (peristalsis) and allows it to absorb nutrients from the host's food.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>40", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS", "question": "Which of the following explains symbiosis", "images": [], "options": {"A": "Parasites feed on dead organisms", "B": "Both organisms benefit mutually by living together", "C": "Saprophytes feed on living organisms", "D": "Organisms serve as host to parasite"}, "answer": "B", "explanation": "Symbiosis is a close and long-term biological interaction between two different biological organisms. In many cases, both organisms benefit mutually by living together. This is known as mutualistic symbiosis. Therefore, the correct answer is 'Both organisms benefit mutually by living together'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2004>41", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "Plants found in the aquatic habitat are generally referred to as", "images": [], "options": {"A": "epiphytes", "B": "halophytes", "C": "xerophytes", "D": "hydrophytes"}, "answer": "D", "explanation": "Aquatic plants are generally referred to as hydrophytes. Hydrophytes are plants that have adapted to living in aquatic environments. They are also referred to as macrophytes or aquatic macrophytes to distinguish them from algae and other microphytes. Therefore, the correct answer is 'hydrophytes'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2004>42", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE", "question": "When a farmer sprays crops with a pesticide, the pesticides becomes", "images": [], "options": {"A": "poisonous to all plants", "B": "is broken down by soil algae", "C": "easily washed down into lakes and rivers", "D": "absorbed by bodies of mammals"}, "answer": "C", "explanation": "When a farmer sprays crops with a pesticide, the pesticide can be washed off by rain or irrigation and can then enter lakes and rivers. This is a major source of water pollution and can harm aquatic life. This process is known as pesticide runoff.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>43", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING", "question": "Which of the following methods is best for the determination of population density of Tridax in an open field?", "images": [], "options": {"A": "Transect", "B": "Quadrat", "C": "Sweep-net", "D": "Pit-fall"}, "answer": "B", "explanation": "The best method for determining the population density of Tridax in an open field is the Quadrat method. This method involves laying out a square frame (quadrat) of a known area in several different parts of the habitat. The number of individuals within each quadrat is then counted and an average density is calculated. This method is particularly useful for plants or slow-moving organisms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>44", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "ECOLOGY OF POPULATION : ECOLOGICAL SUCCESSION", "question": "If a piece of abandoned farmland went through a series of floral and faunal changes and became established with a permanent plant and animal population, it could be said to have undergone.", "images": [], "options": {"A": "transformation", "B": "succession", "C": "competition", "D": "evolution"}, "answer": "B", "explanation": "The process described in the question is known as succession. Succession is a series of progressive changes in the species composition of a natural community over time. It begins with the colonization of a habitat by pioneer species, followed by intermediate stages, and ends with a climax community. The climax community is a stable, mature community that undergoes little change in species over time. It is the final stage of succession, whether it be primary or secondary succession.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>45", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH", "question": "The drugs which inhibit the growth of disease causing organisms and thus used in the treatment of infections are referred to as", "images": [], "options": {"A": "antibodies", "B": "antibiotics", "C": "antitoxics", "D": "septics"}, "answer": "B", "explanation": "The drugs which inhibit the growth of disease causing organisms and thus used in the treatment of infections are referred to as antibiotics. Antibiotics are substances produced by a microorganism that, at low concentrations, inhibit or kill other microorganisms. They are used to treat bacterial infections by either killing bacteria or slowing their growth.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2004>46", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE", "question": "An abandoned refuse dump may be a good site for an intending vegetable farmer because", "images": [], "options": {"A": "very little manual work would be done by the farmer", "B": "microbial activity had released nutrients into soil", "C": "the roots of vegetable seedling easily get enough light", "D": "refuse dumps possess plenty of gas which scares away rodents"}, "answer": "B", "explanation": "An abandoned refuse dump may be a good site for an intending vegetable farmer because microbial activity had released nutrients into the soil. Over time, the organic matter in the refuse decomposes due to microbial activity, releasing nutrients into the soil. These nutrients enrich the soil, making it fertile and suitable for farming.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>47", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "The following are natural resources except", "images": [], "options": {"A": "rubber", "B": "soil", "C": "water", "D": "cellophane"}, "answer": "D", "explanation": "Natural resources are resources that exist without any actions of humankind. This includes all valued characteristics such as magnetic, gravitational, and electrical properties and forces. Rubber, soil, and water are all natural resources because they occur naturally in the environment. Cellophane, on the other hand, is a thin, transparent sheet made of regenerated cellulose. Its low permeability to air, oils, greases, bacteria, and water makes it useful for food packaging. Therefore, cellophane is not a natural resource because it is man-made.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>48", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Which of the following practices does not contribute to intensive depletion of forest resources in West Africa?", "images": [], "options": {"A": "Use of powerful tools for felling trees", "B": "Regrowing of forest trees", "C": "Clearance of forests for cash crops", "D": "Use of fire for hunting in forests"}, "answer": "B", "explanation": "Intensive depletion of forest resources in West Africa is caused by several practices such as the use of powerful tools for felling trees, clearance of forests for cash crops, and the use of fire for hunting in forests. These practices lead to deforestation and loss of biodiversity. However, the regrowing of forest trees, also known as reforestation, does not contribute to the depletion of forest resources. Instead, it helps to restore and create a healthier environment by increasing the number of trees in the area.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>49", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Tropical rain forests can be conserved by the following practices except", "images": [], "options": {"A": "agroforestry", "B": "deforestation", "C": "shifting cultivation", "D": "crop rotation"}, "answer": "B", "explanation": "Tropical rain forests can be conserved by practices such as agroforestry, shifting cultivation, and crop rotation. These practices help in maintaining the biodiversity and ecological balance of the forest. However, deforestation, which is the removal or clearing of trees in a forest, is not a conservation practice. Instead, it leads to the destruction of the forest ecosystem and loss of biodiversity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>50", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "VARIATION IN POPULATION : PHYSIOLOGICAL VARIATIONS", "question": "Which of these physiological variations is sex linked?", "images": [], "options": {"A": "Albinism", "B": "blood groups", "C": "Sickle-cell anaemis", "D": "Haemophilic condition"}, "answer": "D", "explanation": "Sex-linked traits are those that are associated with genes found on sex chromosomes. In humans, the sex chromosomes are X and Y. Haemophilia is a sex-linked trait because the gene that causes it is located on the X chromosome. Therefore, the correct answer is 'Haemophilic condition'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>51", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "VARIATION IN POPULATION : PHYSIOLOGICAL VARIATIONS", "question": "The ability of some individuals to taste phenylthiocarbamide (PTC) is a", "images": [], "options": {"A": "morphological adaptation", "B": "morphological variation", "C": "physiological adaptation", "D": "physiological variation"}, "answer": "D", "explanation": "The ability to taste phenylthiocarbamide (PTC) is a physiological variation. Physiological variations are differences in the function of an organism's body. In this case, some people can taste PTC while others cannot, which is a variation in the function of taste perception.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>52", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : SEX DETERMINATION AND SEX LINKED CHARACTERS", "question": "In man, sex is determined by the inheritance of", "images": [], "options": {"A": "a pair of homologous chromosomes", "B": "an extra chromosome in the cells of a female", "C": "a dominant gene for maleness present in man", "D": "two similar X chromosomes in the female and X and Y chromosomes in the male"}, "answer": "D", "explanation": "In humans, sex is determined by the X and Y chromosomes. Females have two of the same kind of sex chromosome (XX), and are called the homogametic sex. Males have two distinct sex chromosomes (XY), and are called the heterogametic sex. This means the correct answer is 'two similar X chromosomes in the female and X and Y chromosomes in the male'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>53", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "What will be the genotypic ratio when two heterozygous red pea plants are crossed?", "images": [], "options": {"A": "1:0", "B": "1:2:1", "C": "2:1", "D": "3:1"}, "answer": "B", "explanation": "The genotypic ratio when two heterozygous red pea plants are crossed is 1:2:1.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>54", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "VARIATION IN POPULATION : PHYSIOLOGICAL VARIATIONS", "question": "Which of the following traits in humans can be affected by environmental factors?", "images": [], "options": {"A": "Skin colour", "B": "Eye colour", "C": "Baldness", "D": "Tongue-rolling"}, "answer": "A", "explanation": "While all the traits listed can be influenced by genetics, skin color is the most directly influenced by environmental factors, particularly sunlight exposure. The more sunlight exposure, the more melanin the skin produces, which can lead to a darker skin tone. Therefore, the correct answer is 'Skin colour'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>55", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "Heterozygous tall plants were crossed with pure-breeding dwarf plants of the same species.  What were the approximate percentages of the offspring?", "images": [], "options": {"A": "100% tall  0% dwarf", "B": "75% tall  25% dwarf", "C": "50% tall  50% dwarf", "D": "25% tall  75% dwarf"}, "answer": "C", "explanation": "In genetics, a heterozygous organism has two different alleles of a gene. If a heterozygous tall plant (Tt) is crossed with a pure-breeding dwarf plant (tt), the offspring will have a 1:1 ratio of tall to dwarf plants. This is because the tall plant can pass on either the T allele (resulting in a Tt, or tall, offspring) or the t allele (resulting in a tt, or dwarf, offspring). Therefore, approximately 50% of the offspring will be tall and 50% will be dwarf.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>56", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "In the F1 generation of Mendel's experiment obtained by crossing pea plants of long stems with those of short stems, what was his observation?", "images": [], "options": {"A": "Some were short while others were long.", "B": "All were long.", "C": "Half of them were long while half were short.", "D": "Three-quarters were long while one-quarter were short"}, "answer": "B", "explanation": "In Mendel's experiment, when he crossed pea plants of long stems (dominant trait) with those of short stems (recessive trait), all the offspring in the F1 generation exhibited the dominant trait, which is long stems. This is because the dominant trait masks the recessive trait in the heterozygous condition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>57", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "Which of the following statements is correct about the chromosomes in the gametes? At the end of the second meiotic division", "images": [], "options": {"A": "each gamete contains only paternal hereditary information", "B": "chromosomes contain a random mixture of paternal and maternal chromosomes", "C": "chromosomes in the four gamete cells are diploid in number", "D": "chromosomes contain only maternal hereditary information"}, "answer": "B", "explanation": "At the end of the second meiotic division, each gamete contains a random mixture of paternal and maternal chromosomes. This is due to the process of crossing over that occurs during meiosis I, where homologous chromosomes exchange genetic material. This results in new combinations of genes, which is why each gamete contains a mixture of paternal and maternal chromosomes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>58", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following organisms exhibit division of labour?", "images": [], "options": {"A": "House flies", "B": "Butter flies", "C": "Cockroaches", "D": "Termites"}, "answer": "D", "explanation": "Termites exhibit division of labour. In a termite colony, there are different types of termites that perform specific tasks. For example, there are worker termites that gather food, soldier termites that protect the colony, and reproductive termites that reproduce. This division of labour allows the colony to function more efficiently.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>59", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Which of the following is not included in the theory of natural selection?", "images": [], "options": {"A": "Struggle for existence", "B": "Offspring show variation", "C": "Inheritance of adaptive structures", "D": "Disappearance of functionless organs"}, "answer": "D", "explanation": "The theory of natural selection includes the concepts of struggle for existence, offspring showing variation, and inheritance of adaptive structures. However, it does not include the concept of disappearance of functionless organs. This is because natural selection does not necessarily lead to the disappearance of functionless organs. These organs may persist in a population if they do not confer a significant disadvantage to the individuals possessing them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2004>60", "subject": "Biology", "year": "2004", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "The theory of evolution by natural selection was first put forward by", "images": [], "options": {"A": "Aristotle", "B": "Darwin", "C": "Linnaeus", "D": "Boyle"}, "answer": "B", "explanation": "The theory of evolution by natural selection was first put forward by Charles Darwin. This theory proposes that species evolve over time through a process of natural selection, where traits that enhance survival and reproduction become more common in successive generations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>1", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "Which of the following groups embraces the rest?", "images": [], "options": {"A": "Class", "B": "Kingdom", "C": "Phylum", "D": "Species"}, "answer": "B", "explanation": "In the biological classification hierarchy, Kingdom is the highest level and it embraces all other groups. The hierarchy is as follows: Kingdom > Phylum > Class > Order > Family > Genus > Species. Therefore, Kingdom is the group that embraces the rest.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>2", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "The group Mollusca is characterized by the presence of", "images": [], "options": {"A": "jointed appendages", "B": "star-shaped bodies", "C": "backbones", "D": "soft, non-segmented bodies"}, "answer": "D", "explanation": "The group Mollusca, which includes animals like snails, clams, and squids, is characterized by soft, non-segmented bodies. They do not have jointed appendages, star-shaped bodies, or backbones, which are characteristics of other animal groups.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>3", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "CONCEPT OF LIVING : PROPERTIES AND FUNCTIONS OF THE LIVING CELL", "question": "A virus can sometimes be regarded as a living organism because it", "images": [], "options": {"A": "causes disease in plants and animals", "B": "exist in a variety of shapes", "C": "reproduces in living cells", "D": "is easily visible with the aid of an electron microscope"}, "answer": "C", "explanation": "A virus can sometimes be regarded as a living organism because it reproduces in living cells. Viruses are considered borderline entities between living and non-living. They show characteristics of life only when they are inside a host cell. Outside a host cell, they are non-living as they cannot carry out any metabolic function or reproduce on their own. They reproduce by infecting the cells of a host organism and using the host's cellular machinery to replicate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>4", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "A major difference between plants and animals is that", "images": [], "options": {"A": "there is free movement in animals while this is limited in plants", "B": "there is indefinite growth in animals only", "C": "animals consume inorganic materials as food, while plants consume organic materials", "D": "animals give up carbon - dioxide as a waste product of respiration while plants do not"}, "answer": "A", "explanation": "A major difference between plants and animals is that there is free movements in animals (locomotion) while it is limited in Plants (Non-locomotion) .", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>5", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Which of the following adaptation is not found in fruits and seeds dispersed by the wind?", "images": [], "options": {"A": "Small and light body", "B": "Spongy coats", "C": "Turfs of hairs", "D": "Wings on pericarp"}, "answer": "B", "explanation": "Fruits and seeds that are dispersed by the wind usually have adaptations that allow them to be carried by the wind. These adaptations include being small and light, having wings or other structures that catch the wind, and having tufts of hairs. However, having a spongy coat is not a typical adaptation for wind dispersal. A spongy coat would make the seed or fruit heavier and less likely to be carried by the wind.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>6", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "The main similarity between unicellular and multicellular organisms is that both", "images": [], "options": {"A": "perform all life activities", "B": "exist as filaments", "C": "are plants", "D": "exist as colonies"}, "answer": "A", "explanation": "Both unicellular and multicellular organisms perform all life activities. Unicellular organisms, like bacteria and protozoa, carry out all life processes within one single cell. Multicellular organisms, like humans and plants, have specialized cells that perform different functions, but collectively, they perform all life activities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>7", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "One important characteristic of green plants is that they", "images": [], "options": {"A": "possess specialized sense organs", "B": "are usually motile", "C": "are autotrophic", "D": "respond slowly to stimuli"}, "answer": "C", "explanation": "Green plants are autotrophic, meaning they can produce their own food through the process of photosynthesis. They use sunlight, carbon dioxide, and water to produce glucose, which is their food, and oxygen. This is a key characteristic that distinguishes them from animals, which are heterotrophic and must consume other organisms for food.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>8", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "A serious disadvantage of complexity in higher organisms is", "images": [], "options": {"A": "a high demand for food and energy", "B": "ability to function in many specialized roles", "C": "little amount of energy dissipated in functioning", "D": "specialization of parts of the body"}, "answer": "A", "explanation": "Complexity in higher organisms leads to a high demand for food and energy. This is because complex organisms have more cells and systems to maintain, which requires more energy. For example, a human being has a much higher energy requirement than a single-celled organism like a bacterium. This energy is obtained from food, so complex organisms also need to consume more food.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>9", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "EVOLUTION : ADAPTATION FOR SURVIVAL", "question": "Which of these organs can be considered vestigial in humans but functional in other mammals? The", "images": [], "options": {"A": "liver", "B": "appendix", "C": "rectum", "D": "stomach"}, "answer": "B", "explanation": "The appendix is considered a vestigial organ in humans. This means it's an organ that has lost its function over the course of evolution. In other mammals, like rabbits and rodents, the appendix is a large and important part of the digestive system, where it helps in the processing of cellulose.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>10", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following pairs of organisms are photosynthetic?", "images": [], "options": {"A": "Amoeba and Paramecium", "B": "Volvox and Rhizopus", "C": "Chlamydomonas and Euglena", "D": "Nostoc and Plasmodium"}, "answer": "C", "explanation": "Chlamydomonas and Euglena are both photosynthetic organisms. Photosynthesis is the process by which green plants and some other organisms use sunlight to synthesize foods with the help of chlorophyll pigments. In this process, light energy is converted into chemical energy. Chlamydomonas is a genus of green algae, and Euglena is a genus of single-celled flagellate eukaryotes, both of which are capable of photosynthesis.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2005>11", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "Which of the following pairs of organism exist as colonies?", "images": [], "options": {"A": "Obedia and Euglena", "B": "Pandorina and Volvox", "C": "Chlamydomonas and Amoeba", "D": "Hydra and Spirogyra"}, "answer": "B", "explanation": "Colonies are organisms made up of many similar cells which are joined or massed together but cannot be differentiated from each other. e.g volvox, pandorina, sponges.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>12", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "Which of the following best explains why it is difficult to see clearly in dim light?", "images": [], "options": {"A": "Initially the eyes cannot operate when the light is dim", "B": "The choroid reflect all the light that enters the eye", "C": "Too little light reaches the retina and so the cones may not be stimulated at all", "D": "Dim light causes the pupil to close up so that much light enters the eye"}, "answer": "C", "explanation": "In dim light, it is difficult to see clearly because too little light reaches the retina, and so the cones may not be stimulated at all. The cones are photoreceptor cells in the retina of the eye that are responsible for color vision. They function best in relatively bright light. In dim light, the rods, another type of photoreceptor cell, are more active. However, rods do not provide color information, resulting in a less clear image.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>13", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "In active transport, molecules move against a concentration gradient, therefore", "images": [], "options": {"A": "molecules move from a region of low concentration to a region of high concentration", "B": "molecules move from a region of high concentration to a region of low concentration", "C": "the concentration gradient has little effect on the movement of molecules", "D": "molecules force their way through special channels"}, "answer": "A", "explanation": "Active transport is a process that moves molecules from a region of lower concentration to a region of higher concentration. This process requires energy because it is moving substances against the concentration gradient, which is the difference in concentration between two areas. The concentration gradient has a significant effect on the movement of molecules, but in the case of active transport, energy is used to move molecules against this gradient.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>14", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "Which of the following substances pass through the root cell membrane by osmosis?", "images": [], "options": {"A": "Cell sap", "B": "Carbon dioxide", "C": "Oxygen", "D": "Water"}, "answer": "D", "explanation": "Osmosis is a process by which water molecules move across a semi-permeable membrane from an area of lower solute concentration to an area of higher solute concentration. Therefore, water is the substance that passes through the root cell membrane by osmosis. Cell sap, carbon dioxide, and oxygen do not pass through the root cell membrane by osmosis.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2005>15", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "Which of the following statement defines plasmolysis?", "images": [], "options": {"A": "Shrinking of a plant cell in a solution", "B": "Shrinking away of cytoplasm from an animal cell membrane", "C": "Shrinking away of the cytoplasm from the plant cell wall", "D": "Shrinking of the vacuole and leaving the cytoplasm attached to the cell wall"}, "answer": "C", "explanation": "Plasmolysis is the process in plant cells where the cytoplasm pulls away from the cell wall due to the loss of water through osmosis. It occurs when a cell is placed in a solution that is hypertonic (more concentrated) than the cell contents and water moves out of the cell and into the surrounding solution. This causes the cell to shrink away from the cell wall, a process known as plasmolysis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>16", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Raw materials required by green plants to manufacture their food are", "images": [], "options": {"A": "mainly fluids", "B": "inorganic substances", "C": "living materials", "D": "mainly gases"}, "answer": "B", "explanation": "Green plants manufacture their food through a process called photosynthesis. The raw materials required for photosynthesis are carbon dioxide and water, which are inorganic substances. These are absorbed from the environment; carbon dioxide from the air, and water from the soil. Therefore, the correct answer is 'inorganic substances'.  Green plants utilize simple inorganic materials to prepare their own food(glucose) for energy. The raw materials used are carbon dioxide and water.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2005>17", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The role of ATP include all the following activities except", "images": [], "options": {"A": "provision of energy to do work in living organisms", "B": "transmission of nerve impulse", "C": "keeping the body warm in homoithermic animals", "D": "producing water during aerobic respiration"}, "answer": "D", "explanation": "ATP (Adenosine Triphosphate) is a molecule that carries energy within cells. It is the main energy currency of the cell, and it is an end product of the processes of photophosphorylation (adding a phosphate group to a molecule using energy from light), cellular respiration, and fermentation. All living things use ATP. However, ATP does not produce water during aerobic respiration. In aerobic respiration, water is produced as a byproduct of the electron transport chain when oxygen accepts electrons and picks up protons to form water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>18", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "The basis of growth involves the following processes except", "images": [], "options": {"A": "cell reduction", "B": "cell division", "C": "cell differentiation", "D": "cell enlargement"}, "answer": "A", "explanation": "Growth in organisms is generally based on the increase in the number and size of cells. This involves processes such as cell division, cell differentiation, and cell enlargement. Cell reduction, however, is not a basis for growth. In fact, it is the opposite of growth as it involves a decrease in the number of cells, which can occur during certain processes such as apoptosis (programmed cell death).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>19", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following statements is true about movement of the forearm? In", "images": [], "options": {"A": "bending the arm, the biceps relax and the triceps contract", "B": "bending the arm, the biceps contract and the triceps relax", "C": "straightening the arm the biceps contract and the triceps relax", "D": "straightening the arm, both biceps and triceps contract"}, "answer": "B", "explanation": "When you bend your arm, the biceps muscle in your upper arm contracts, while the triceps muscle, which is the antagonist, relaxes. This is because muscles work in pairs to move your body parts. The contracting muscle is called the agonist, and the relaxing muscle is called the antagonist. So, when you bend your arm, the biceps (agonist) contracts and the triceps (antagonist) relaxes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>20", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION", "question": "Only specially adapted micro-organisms are found in", "images": [], "options": {"A": "salty water", "B": "humid air", "C": "moist soil", "D": "mouth cavities"}, "answer": "A", "explanation": "Only specially adapted micro-organisms, known as halophiles, can survive in salty water. These organisms have special adaptations that allow them to live in high salt concentrations, which would be deadly to most other types of micro-organisms. Therefore, the correct answer is 'salty water'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>21", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH", "question": "Which of the following organism causes syphilis?", "images": [], "options": {"A": "Mycobacterium tuberculosis", "B": "Bordella pertusis", "C": "Treponema pallidum", "D": "Clostridium tetani"}, "answer": "C", "explanation": "Syphilis is caused by the bacterium Treponema pallidum. This bacterium is a spirochete, a type of bacterium that is long, thin, and spirally twisted. It is transmitted primarily through sexual contact and can also be passed from mother to fetus during pregnancy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>22", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "In plants, respiration occurs in", "images": [], "options": {"A": "mesophyll cell only", "B": "the root only", "C": "the stomata and lenticel only", "D": "all living cells"}, "answer": "D", "explanation": "Respiration is a process that occurs in all living cells of a plant, not just in specific parts. It is a metabolic process that involves the breakdown of food substances to release energy. This process happens in the cells of roots, stems, leaves, flowers, etc. Therefore, the correct answer is 'all living cells'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>23", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "A faster colour change of a dry cobalt chloride paper affixed to the lower surface of a leaf than the upper one, indicates that", "images": [], "options": {"A": "sunlight slows down water loss from the upper surface", "B": "the lower surface of the leaf has more stomata.", "C": "sunlight causes the stomata on the upper surface to close", "D": "stomata are not present on the upper surface of a leaf"}, "answer": "B", "explanation": "Stomata are tiny openings on the surface of leaves that allow for gas exchange and transpiration (water loss through evaporation). In most plant species, the lower surface of the leaf typically has more stomata than the upper surface. This is an adaptation to reduce water loss due to direct sunlight and to minimize the entry of pathogens.    When cobalt chloride paper, which changes color in the presence of moisture, is used on both surfaces of the leaf, a faster color change on the lower surface indicates that more water vapor is being released from that surface. This is because the lower surface has more stomata, leading to higher rates of transpiration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>24", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "Which of the following takes place when a person's body temperature rises above 37°C?", "images": [], "options": {"A": "Sweating and vasoconstriction", "B": "Panting and vasoconstriction", "C": "Sweating and vasodilation", "D": "Panting and vasodilation"}, "answer": "C", "explanation": "When a person's body temperature rises above 37°C, the body responds by initiating sweating and vasodilation. Sweating helps to cool the body down as the evaporation of sweat from the skin surface removes heat. Vasodilation is the widening of blood vessels, which increases blood flow to the skin and allows for more heat to be lost to the environment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>25", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "Which of the following glands secretes a substance into the blood stream of a frightened person?", "images": [], "options": {"A": "Adrenal glands", "B": "Salivary glands", "C": "Gastric glands", "D": "Parathyroid glands"}, "answer": "A", "explanation": "The adrenal glands secrete adrenaline, a hormone that prepares the body for a 'fight or flight' response in times of stress, such as when a person is frightened. This hormone is released into the bloodstream, increasing heart rate, blood pressure, and energy supplies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>26", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "Reading the verdict of a case by a judge or magistrate is an example of", "images": [], "options": {"A": "a reflex action", "B": "an instinct", "C": "a conditioned reflex", "D": "a voluntary action"}, "answer": "D", "explanation": "Reading the verdict of a case by a judge or magistrate is an example of a voluntary action. Voluntary actions are those that are under conscious control. They are performed deliberately and a person has control over when these actions start and stop. This is different from reflex actions which are automatic and not under conscious control, instincts which are inherent tendencies to behave in a certain way, and conditioned reflexes which are learned responses to specific stimuli.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2005>27", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "Which of the following describes an example of fertilization in higher organism?", "images": [], "options": {"A": "Fusion of sperm and egg nuclei", "B": "Ejaculating of sperm into a female body", "C": "Male gametes germinating in the pollen tube", "D": "A pollen grain landing on a sticky stigma"}, "answer": "A", "explanation": "Fertilization in higher organisms is described as the fusion of sperm and egg nuclei. This is because fertilization is the process where the male gamete (sperm) and the female gamete (egg) combine to form a zygote. The nuclei of these two cells fuse together to share their genetic material and create a new organism.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>28", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "When both ovaries of the human female ovulate simultaneously and both ova fertilized, then", "images": [], "options": {"A": "identical twins are produced", "B": "fraternal twins are produced", "C": "siamese twins are produced", "D": "the children produced are genetically identical"}, "answer": "B", "explanation": "When both ovaries of the human female ovulate simultaneously and both ova are fertilized, fraternal twins are produced. Fraternal twins are also known as 'non-identical twins' and they occur when two separate eggs are fertilized by two separate sperm. Each twin has its own placenta and amniotic sac. The twins can be either the same sex or different sexes and they do not look identical.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>29", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following statements is not true of the light stage of photosynthesis?", "images": [], "options": {"A": "chlorophyll is energized by sunlight", "B": "water molecules split into hydrogen and hydroxyl ions", "C": "carbon(IV)oxide is reduced by hydrogen atoms in NADPH2", "D": "water is formed"}, "answer": "C", "explanation": "The light stage of photosynthesis involves the absorption of light by chlorophyll, which leads to the splitting of water molecules into hydrogen and oxygen. This process also produces ATP and NADPH. However, the reduction of carbon(IV)oxide by hydrogen atoms in NADPH2 does not occur in the light stage of photosynthesis. This process happens in the dark stage of photosynthesis, also known as the Calvin cycle.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>30", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following elements is required in large amounts by plant?", "images": [], "options": {"A": "Molybdenum", "B": "Boron", "C": "Copper", "D": "Phosphorus"}, "answer": "D", "explanation": "Elements required in large amount by plants (essential or macro nutrient or elements) are Nitrogen, Phosphorus, Potassium, Magnesium, Calcium, Oxygen, Hydrogen, Carbon, Sulphur and Iron", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>31", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "Which of the following substances has the highest amount of energy in joules per unit weight?", "images": [], "options": {"A": "Carbohydrates", "B": "Proteins", "C": "Fats", "D": "Vitamins"}, "answer": "C", "explanation": "Fats have the highest amount of energy in joules per unit weight. This is because fats are more energy-dense than carbohydrates and proteins. Each gram of fat provides about 9 calories of energy, while each gram of carbohydrates and proteins provides only about 4 calories of energy. Vitamins do not provide energy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>32", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Which of the following juices contains the enzyme ptyalin?", "images": [], "options": {"A": "Gastric juice", "B": "Pancreatic juice", "C": "Succus", "D": "Saliva"}, "answer": "D", "explanation": "The enzyme ptyalin, also known as salivary amylase, is found in saliva. It begins the process of digestion by breaking down starch and glycogen into maltose, a disaccharide. Gastric juice, pancreatic juice, and succus do not contain ptyalin.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>33", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Trees in savannah habitats usually have heavy thick bark which mainly", "images": [], "options": {"A": "reduces the rate of transpiration", "B": "protect them from the scorching sun", "C": "protect them from heavy winds", "D": "resist bush"}, "answer": "A", "explanation": "Trees in savannah habitats usually have heavy thick bark which mainly reduces the rate of transpiration. Transpiration is the process where plants lose water through the stomata (small openings) in their leaves. By having a thick bark, the rate of water loss is reduced, helping the tree to conserve water in a typically dry savannah environment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>34", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "In the marine food web, the source of energy to the producer comes from", "images": [], "options": {"A": "sea waves", "B": "sea water", "C": "sun", "D": "air"}, "answer": "C", "explanation": "In the marine food web, the source of energy to the producer comes from the sun. Producers, such as phytoplankton, use sunlight to perform photosynthesis, a process where they convert light energy into chemical energy (food). This energy is then transferred through the food web as other organisms consume the producers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>35", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING", "question": "A population is best described as", "images": [], "options": {"A": "a group of the same species of organisms living together", "B": "a group of animals and plant living together", "C": "a group of insects and grasses", "D": "different species of wild animals"}, "answer": "A", "explanation": "A population in biology refers to a group of individuals of the same species living in a particular geographic area. Therefore, the correct answer is 'a group of the same species of organisms living together'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2005>36", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : ADAPTATION OF ORGANISMS TO HABITATS.", "question": "Possession of strong adhesives is a feature of animals living in/on", "images": [], "options": {"A": "sandy beaches", "B": "rocky shores", "C": "benthic zones", "D": "deserts"}, "answer": "B", "explanation": "Animals living on rocky shores often have strong adhesives to help them cling to the rocks and resist the force of waves. Therefore, the correct answer is 'rocky shores'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>37", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "A stable self sustaining environment produced by an interaction between the biotic and abiotic components is best described as", "images": [], "options": {"A": "a niche", "B": "a community", "C": "an ecosystem", "D": "a habitat"}, "answer": "C", "explanation": "A stable self-sustaining environment produced by an interaction between the biotic (living organisms) and abiotic (non-living factors like temperature, light, water, etc.) components is best described as an ecosystem. An ecosystem includes all the living things (plants, animals and organisms) in a given area, interacting with each other, and also with their non-living environments (weather, earth, sun, soil, climate, atmosphere).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>38", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Which of the following factors is not associated with aquatic habitats?", "images": [], "options": {"A": "Salinity", "B": "Turbidity", "C": "Temperature", "D": "Edaphic"}, "answer": "D", "explanation": "Edaphic factors are not associated with aquatic habitats. Edaphic refers to soil conditions, so it's more related to terrestrial habitats. Aquatic habitats are influenced by factors such as salinity (the saltiness or dissolved salt content of a body of water), turbidity (the cloudiness or haziness of a fluid caused by large numbers of individual particles), and temperature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>39", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS", "question": "Which of the following instruments is used to measure the speed of a stream?", "images": [], "options": {"A": "Simple float", "B": "Secchi disc", "C": "Quadrat frame", "D": "Rain gauge"}, "answer": "A", "explanation": "A simple float is used to measure the speed of a stream. This is done by timing how long it takes for the float to travel a certain distance downstream. The other options, Secchi disc, Quadrat frame, and Rain gauge, are not used for this purpose. A Secchi disc is used to measure water transparency in bodies of water. A Quadrat frame is used in ecology and biology to isolate a standard unit of area for study of the distribution of an item over a large area. A Rain gauge is used to measure the amount of liquid precipitation over a set period of time.  To measure the stream speed, you release the float at a known starting point and measure the time it takes to travel a known distance downstream. The speed is then calculated by dividing the distance by the time.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2005>40", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "In an ecosystem the organism which changes light into stored chemical energy is the", "images": [], "options": {"A": "consumer", "B": "decomposer", "C": "producer", "D": "carnivore"}, "answer": "C", "explanation": "In an ecosystem, the organism which changes light into stored chemical energy is the producer. Producers, also known as autotrophs, convert energy from the sun into chemical energy through a process called photosynthesis. Consumers, decomposers, and carnivores do not have this ability. Consumers, also known as heterotrophs, obtain energy by consuming other organisms. Decomposers break down dead or decaying organisms, and they are the final link in an ecosystem's food chain. Carnivores are animals that eat other animals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>41", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : NITROGEN CYCLE", "question": "Which of the following processes does not contribute to the maintenance of the nitrogen content of the soil?", "images": [], "options": {"A": "Decomposition", "B": "Denitrification", "C": "Nitrification", "D": "Nitrogen fixation"}, "answer": "B", "explanation": "Denitrification is a process by which nitrates in the soil are converted back into nitrogen gas by bacteria, thus reducing the nitrogen content of the soil. The other processes, decomposition, nitrification, and nitrogen fixation, all contribute to increasing the nitrogen content of the soil. Decomposition breaks down organic matter into simpler substances, releasing nitrogen into the soil. Nitrification is the process by which ammonia is converted into nitrates by bacteria. Nitrogen fixation is the process by which nitrogen gas from the atmosphere is converted into a form that plants can use.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>42", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : FEEDING HABITS", "question": "Which of the following organisms is well adapted for fluid feeding?", "images": [], "options": {"A": "Cockroach", "B": "Mosquito", "C": "Grasshopper", "D": "Ants"}, "answer": "B", "explanation": "Mosquito, tsetsefly, human louse feed on fluid (blood from animals), having a proboscis mouth part nature with feeding mechanisms of piercing and sucking.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2005>43", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION", "question": "The density dependent factors that operate to regulate a population size may include the following except", "images": [], "options": {"A": "shortage of food supply", "B": "fire outbreak", "C": "spread of diseases", "D": "increased competition"}, "answer": "B", "explanation": "Density dependent factors are factors whose effects on the size or growth of the population vary with the population density. They are biological or biotic factors in the environment, including competition, predation, parasitism and disease. Fire outbreak is not a density dependent factor, it is a density independent factor because its occurrence and impact is not directly related to population size or density.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>44", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH", "question": "Which of the following infections is unlikely to respond to antibiotic treatment?", "images": [], "options": {"A": "Typhoid fever", "B": "Ring worm", "C": "Measles", "D": "Tetanus"}, "answer": "C", "explanation": "Antibiotics are effective against bacterial infections but not viral infections. .  Measles: Measles is caused by the measles virus (a paramyxovirus). There is no specific antiviral treatment for measles, and antibiotics are ineffective against viral infections. Treatment primarily involves supportive care to manage symptoms and complications.    Therefore, the infection unlikely to respond to antibiotic treatment is measles, as it is caused by a virus against which antibiotics have no effect.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>45", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE", "question": "Algal bloom depletes oxygen content of bodies of water polluted by", "images": [], "options": {"A": "industrial effluents", "B": "thermal plant discharge", "C": "raw sewage disposal", "D": "crude oil spillage"}, "answer": "C", "explanation": "Algal bloom is a rapid increase in the population of algae in an aquatic system. It often occurs in response to changes in nutrients (such as nitrogen and phosphorus), sunlight, and temperature, creating an optimal environment for algae growth. These changes are often caused by the disposal of raw sewage into the water bodies. The algae that grow during a bloom can deplete oxygen in the water when they die and decompose, leading to a decrease in oxygen levels which can harm other organisms in the water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>46", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Conservation of wild life is necessary mainly because", "images": [], "options": {"A": "wild species cannot resist disease better than their domesticated species", "B": "many predator wild animals help in control of pests", "C": "many people derive pleasure from observing wild animals", "D": "it helps to prevent extinction of species"}, "answer": "D", "explanation": "Conservation of wildlife is necessary mainly to prevent the extinction of species. Every species plays a specific role in maintaining the ecological balance of our planet. The extinction of a single species can have disastrous effects on the food chain where it belongs. Moreover, the extinction of a species is irreversible. Therefore, it is crucial to conserve wildlife to maintain biodiversity and the health of our planet's ecosystems.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>47", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Which of the following is not a means of conservation?", "images": [], "options": {"A": "Controlling excessive deforestation", "B": "Prevention of poaching", "C": "Replacing harvested mature trees with seedlings", "D": "Burning of vegetation before cropping"}, "answer": "D", "explanation": "Conservation refers to the preservation, protection, or restoration of the natural environment, natural ecosystems, vegetation, and wildlife. Burning of vegetation before cropping is not a means of conservation. Instead, it can lead to deforestation, loss of biodiversity, and soil degradation. Therefore, it is not a means of conservation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>48", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of the following statements about mutation is true?", "images": [], "options": {"A": "The genotype is not affected", "B": "The genotype is affected", "C": "The phenotype is not affected", "D": "It cannot be induced by artificial means"}, "answer": "B", "explanation": "Mutation refers to a change in the DNA sequence within a gene or chromosome of an organism resulting in the creation of a new character or trait not found in the parental type. It affects the genotype because it is a change in the genetic material. Therefore, the statement 'The genotype is affected' is true about mutation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>49", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Variation which exhibits a wide range from one extreme to the other with very little differences between the intermediated is described as", "images": [], "options": {"A": "phenotypic", "B": "discontinuous", "C": "continuous", "D": "genotypic"}, "answer": "C", "explanation": "Continuous variation is the type of variation that exhibits a wide range from one extreme to the other with very little differences between the intermediates. This is because continuous variation is influenced by many genes (polygenic) and environmental factors, leading to a wide range of phenotypes that do not fall into discrete categories. Examples include height, weight, and skin color in humans.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2005>50", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "VARIATION IN POPULATION : PHYSIOLOGICAL VARIATIONS", "question": "Which of the following is an example of physiological variation?", "images": [], "options": {"A": "Blood groups", "B": "Skin colour", "C": "Fingerprints", "D": "Human height"}, "answer": "A", "explanation": "Blood groups is an example of physiological variation. Every human being belong to one of the four blood groups known as A, B,AB and O.  It provides the basic for discontinuous variation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2005>51", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "A person with blood groups B can only donate blood to individuals with blood groups", "images": [], "options": {"A": "A and B", "B": "B and AB", "C": "O only", "D": "B only"}, "answer": "B", "explanation": "Group B can donate red blood cells to B's and AB's. Group A can donate red blood cells to A's and AB's. There are more than 600 other known antigens, the presence or absence of which creates \"rare blood types.\"", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>52", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "If the pink colour of a petal is dominant over white what would be the colour of the flower of the F1 generation when a pure pink flowered plant is crossed with a white flowered plant?", "images": [], "options": {"A": "Purple", "B": "Pink", "C": "White", "D": "Yellow"}, "answer": "B", "explanation": "In genetics, dominance is a relationship between alleles of a gene, in which one allele masks the expression of another allele at the same locus. In this case, the pink colour of a petal is dominant over white. This means that when a pure pink flowered plant (homozygous for the pink allele) is crossed with a white flowered plant (homozygous for the white allele), all the offspring in the F1 generation will have pink flowers. This is because they will all inherit one pink allele from the pink parent, and this pink allele will mask the expression of the white allele inherited from the white parent.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>53", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "If two parents are sickle cell carriers then their genotypes would be", "images": [], "options": {"A": "HbA HbA and HbSHbS", "B": "HbSHbS and HBSHbS", "C": "HbAHbS and HbAHbS", "D": "HbAHbA and HbAHbA"}, "answer": "C", "explanation": "Sickle cell carriers are individuals who carry one copy of the gene for sickle cell anaemia but do not have the disease. This is because sickle cell anaemia is a recessive disease, meaning that it only manifests when an individual has two copies of the gene. Therefore, the genotype of sickle cell carriers is HbAHbS.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>54", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : LINKAGE, SEX DETERMINATION AND SEX LINKED CHARACTERS", "question": "Which disease is sex-linked and mainly afflicts male offspring?", "images": [], "options": {"A": "Sickle cell anaemia", "B": "Haemophilia", "C": "Diabetes", "D": "Malaria"}, "answer": "B", "explanation": "Haemophilia is a sex-linked disease that mainly afflicts male offspring. This is because the gene for haemophilia is located on the X chromosome. Males have only one X chromosome, so if they inherit the gene for haemophilia, they will have the disease. Females, on the other hand, have two X chromosomes, so they would need to inherit the gene from both parents to have the disease. Therefore, haemophilia is more common in males.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2005>55", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "In a living cell, factors which are responsible for inheritance are located", "images": [], "options": {"A": "on the nuclear membrane", "B": "on the nucleolus", "C": "on the chromosomes", "D": "in the nucleoplasm"}, "answer": "C", "explanation": "In a living cell, the factors responsible for inheritance are located on the chromosomes. Chromosomes are thread-like structures located inside the nucleus of animal and plant cells. Each chromosome is made of protein and a single molecule of deoxyribonucleic acid (DNA), which carries the cell's genetic instructions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2005>56", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of the following is not a correct base pairing on the DNA strand?", "images": [], "options": {"A": "Adenine, Thymine", "B": "Cytosine, Guanine", "C": "Guanine, Cytosine", "D": "Uracil, Thymine"}, "answer": "D", "explanation": "In DNA, the base pairing is always Adenine with Thymine and Cytosine with Guanine. Uracil is a component of RNA and pairs with Adenine in RNA. Therefore, Uracil, Thymine is not a correct base pairing on the DNA strand.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2005>57", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following organisms is a social insect?", "images": [], "options": {"A": "Grasshopper", "B": "Honey bee", "C": "Butterfly", "D": "Housefly"}, "answer": "B", "explanation": "Honey bee is a social insect. social insects are specialised groups of insects of the same species which live together cooperatively in organised communities such as colonies, examples are termites , ants and bees.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2005>58", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Territoriality is a phenomenon among", "images": [], "options": {"A": "lower organisms", "B": "plants of different species", "C": "male animals with a group of females", "D": "animals and plant"}, "answer": "C", "explanation": "Territoriality is a type of behaviour in which an animal, the 'territory holder', attempts to adopt and defend a particular area, or territory, from others. This is common among male animals with a group of females. The male animal marks and defends its territory to ensure exclusive mating rights with the females. This behaviour is not common among lower organisms, plants of different species, or between animals and plants.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2005>59", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "A honey bee worker communicates with others on locating a source of food by", "images": [], "options": {"A": "dancing", "B": "stinging", "C": "instinct", "D": "flares"}, "answer": "A", "explanation": "Honey bees communicate the location of a food source to other members of the colony through a series of movements known as the 'waggle dance'. This dance involves a combination of circles and straight runs, and the direction and length of the straight runs indicate the direction and distance of the food source.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2005>60", "subject": "Biology", "year": "2005", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Which of the following is not an evidence of evolution?", "images": [], "options": {"A": "Fossil records", "B": "Comparative embryology", "C": "Polymorphism", "D": "Comparative anatomy"}, "answer": "C", "explanation": "Polymorphism is not an evidence of evolution. It refers to the occurrence of different forms or types in individual organisms of a species. On the other hand, fossil records, comparative embryology, and comparative anatomy are all evidences of evolution. Fossil records show the existence of species that have become extinct or have evolved into other species over time. Comparative embryology and anatomy show similarities in the structures of different species, indicating a common ancestry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>1", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The following life process are common to both plants and animals except", "images": [], "options": {"A": "Respiration", "B": "Growth", "C": "Reproduction", "D": "Photosynthesis"}, "answer": "D", "explanation": "Both plants and animals undergo respiration, growth, and reproduction. However, photosynthesis is a process that is unique to plants. Photosynthesis is the process by which green plants and some other organisms use sunlight to synthesize foods with the help of chlorophyll pigments. During photosynthesis, plants convert light energy (usually from the sun) into chemical energy (glucose). Animals do not have this ability.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>2", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which of these organelles is common to both plant and animal cells?", "images": [], "options": {"A": "Chloroplast", "B": "Centriole", "C": "Mitochondrion", "D": "Pyrenoid"}, "answer": "C", "explanation": "Both plant and animal cells contain mitochondria. Mitochondria are known as the powerhouses of the cell because they produce the energy-rich molecule adenosine triphosphate (ATP), which powers various cellular activities. Chloroplasts, on the other hand, are only found in plant cells and are responsible for photosynthesis. Centrioles are found in most animal cells and some lower plant forms but not in most plant cells. Pyrenoids are found in algae and are not common to both plant and animal cells.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>3", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The epidermis of the mammalian skin is an example of a tissue because the cells", "images": [], "options": {"A": "prevent light from passing through them", "B": "have similar structure and function", "C": "prevent excessive loss of water", "D": "are impregnated with keratin"}, "answer": "B", "explanation": "The epidermis of the mammalian skin is an example of a tissue because the cells have a similar structure and function. A tissue is a group similar cells that perform a particular function.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>4", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "Which of the following statements is correct about organs?", "images": [], "options": {"A": "They are composed of specialized cells", "B": "They perform a certain overall function", "C": "They are not found in plants", "D": "Unicellular animals have few organs"}, "answer": "B", "explanation": "Organs are composed of different types of tissues that work together to perform a certain overall function. For example, the heart is an organ that is composed of muscle tissue, nerve tissue, and connective tissue, all working together to pump blood throughout the body.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>5", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "The structure used for movement in Amoeba is", "images": [], "options": {"A": "cilia", "B": "pseudopodia", "C": "flagella", "D": "endoplasm"}, "answer": "B", "explanation": "Amoeba moves using pseudopodia. Pseudopodia, also known as 'false feet', are temporary projections of the cell. The amoeba moves by extending the pseudopodia and flowing its cytoplasm into the pseudopod.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>6", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which of the following parts of a cell is not an organelle?", "images": [], "options": {"A": "Food vacuole", "B": "Mitochondrion", "C": "Cell wall", "D": "Nucleus"}, "answer": "C", "explanation": "The cell wall is not an organelle. An organelle is a specialized subunit within a cell that has a specific function, and is usually separately enclosed within its own lipid bilayer. The cell wall is a rigid layer that is outside the cell membrane, providing the cell with structural support and protection, but it is not enclosed within its own lipid bilayer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>7", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The folded portion of mitochondrion is called", "images": [], "options": {"A": "cristae", "B": "cell membrane", "C": "nucleolus", "D": "partition"}, "answer": "A", "explanation": "Cristae is the internal compartments formed by the inner membrane of a mitochondrion where many chemical reactions take place. It is the folded portion of mitochondrion.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>8", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "The physical process which occurs when a red cell is placed in distilled water causing it to burst and break down is known as", "images": [], "options": {"A": "crenation", "B": "plasmolysis", "C": "turgidity", "D": "haemolysis"}, "answer": "D", "explanation": "Haemolysis is defined as the process by which red blood cells or corpuscles become split or burst as a result of too much water passing into it.  This situation will occur when a red blood cell is placed in a weaker or hypotonic solution where the red blood cell takes in water and becomes swollen and even bursts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>9", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "During the process of osmosis, a semi-permeable membrane allows", "images": [], "options": {"A": "only solute molecules to pass through it", "B": "both solute and solvent molecules to pass through it", "C": "only solvent molecules to pass through it", "D": "only gaseous molecules to pass through it"}, "answer": "C", "explanation": "Osmosis is the process by which solvent molecules move from an area of lower solute concentration to an area of higher solute concentration through a semi-permeable membrane. A semi-permeable membrane is a type of barrier that allows certain substances to pass through while blocking others. In the case of osmosis, it allows only solvent molecules to pass through it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>10", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Which of the following environmental conditions is ideal for plant cells to remain turgid?", "images": [], "options": {"A": "Hot, dry weather", "B": "Windy weather", "C": "Cold, dry weather", "D": "Cool, humid weather"}, "answer": "D", "explanation": "Turgidity in plant cells is maintained when the cells are in a hypotonic solution, where the concentration of solutes is higher inside the cell than outside. This causes water to move into the cell by osmosis, making the cell turgid. Cool, humid weather provides the ideal conditions for this as the air is saturated with water, reducing the rate of transpiration (loss of water from the plant), thus helping the plant cells to remain turgid.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>11", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which of the following processes does not contribute towards growth?", "images": [], "options": {"A": "Cell division", "B": "Cell enlargement", "C": "Cell differentiation", "D": "Cell plasmolysis"}, "answer": "D", "explanation": "Growth in organisms is generally contributed by cell division, cell enlargement, and cell differentiation. Cell division leads to an increase in the number of cells, cell enlargement leads to an increase in the size of the cells, and cell differentiation leads to the specialization of cells for specific functions. However, cell plasmolysis, which is the process of water loss from a cell in a hypertonic environment leading to the shrinkage of the cell membrane, does not contribute to growth. Instead, it can lead to cell death if severe.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>12", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The aspects of growth in living organisms include all the following processes except", "images": [], "options": {"A": "increase in dry weight", "B": "reversible increase in size", "C": "irreversible increase in length", "D": "increase in number of cells"}, "answer": "B", "explanation": "- Increase in dry weight is not an aspect of growth.  - Weight is not a parameter that is normally used to measure growth.  - Mass.  - Length, height or width and  - Area or volume, are the parameters used in measuring growth.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>13", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Support in young herbaceous plants is provided by", "images": [], "options": {"A": "translocation", "B": "guttation", "C": "turgidity", "D": "osmosis"}, "answer": "C", "explanation": "Support in young herbaceous plants is provided by turgidity. Turgidity refers to the state of being turgid or swollen, especially due to high fluid content. In the context of plants, it is the rigidity of the cells and tissues, which results from being filled with water. When plant cells are filled with water, they become rigid and give the plant structure and support.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>14", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "Which of the following heart structures is best adapted to cope with double circulation?", "images": [], "options": {"A": "One auricle and one ventricle", "B": "Two auricle and one ventricle", "C": "Two auricles and partially divided ventricle", "D": "Two auricles and two ventricles"}, "answer": "D", "explanation": "The heart structure best adapted to cope with double circulation is two auricles and two ventricles. Double circulation refers to the separate systems of pulmonary and systemic circulation. In this system, the blood passes through the heart twice during each complete cycle of the body. This is best facilitated by a heart structure with two auricles and two ventricles, as it allows for the separation of oxygenated and deoxygenated blood, which is a key feature of double circulation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>15", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "Which of these factors does not contribute towards the ascent of water in plants?", "images": [], "options": {"A": "Root pressure", "B": "Capillarity", "C": "Transpiration pull", "D": "Turgor pressure"}, "answer": "D", "explanation": "The ascent of water in plants is facilitated by three main factors: root pressure, capillarity, and transpiration pull. Root pressure is the osmotic pressure within the cells of a root system that causes water to move up to the plant. Capillarity is the ability of a liquid to flow in narrow spaces without the assistance of external forces like gravity. Transpiration pull is the main mechanism of water movement in plants. However, Turgor pressure, which is the pressure of water pushing the plasma membrane against the cell wall of a plant cell, does not contribute to the ascent of water in plants. Therefore, the correct answer is 'Turgor pressure'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>16", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "The ventricles of the mammalian heart have thicker muscular walls than the auricles because the", "images": [], "options": {"A": "ventricles are larger", "B": "ventricles receive more blood", "C": "ventricles pump blood to longer distances", "D": "auricles have smaller capacity"}, "answer": "C", "explanation": "The ventricles of the mammalian heart have thicker muscular walls than the auricles because they have to pump blood to longer distances. The right ventricle pumps blood to the lungs, while the left ventricle pumps blood to the rest of the body. This requires more force, hence the thicker muscular walls. The size of the ventricles or the amount of blood they receive does not directly influence the thickness of their walls. Similarly, the capacity of the auricles is not a determining factor for the thickness of the ventricular walls. Therefore, the correct answer is 'ventricles pump blood to longer distances'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>17", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Gaseous exchange occurs through the following structures in some organisms except", "images": [], "options": {"A": "spiracle and trachea", "B": "alveoli and lungs", "C": "stomata and lenticels", "D": "chloroplast and plastids"}, "answer": "D", "explanation": "Gaseous exchange in organisms occurs through specialized structures that allow the passage of gases. These structures include spiracles and trachea in insects, alveoli and lungs in mammals, and stomata and lenticels in plants. However, chloroplasts and plastids are not involved in gaseous exchange. They are involved in photosynthesis, a process in which light energy is converted into chemical energy in plants.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>18", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which of the following organs in mammals is not excretory in function?", "images": [], "options": {"A": "Liver", "B": "Kidney", "C": "Pancreas", "D": "Lungs"}, "answer": "C", "explanation": "The excretory system in mammals includes organs that are involved in the removal of waste products from the body. These organs include the liver, which excretes bile, the kidneys, which excrete urine, and the lungs, which excrete carbon dioxide. However, the pancreas is not an excretory organ. It is an organ of the digestive and endocrine systems. It produces digestive enzymes and hormones such as insulin and glucagon.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>19", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which of the following substances is not an excretory product in mammals?", "images": [], "options": {"A": "Carbon dioxide", "B": "Water", "C": "Faeces", "D": "Urea"}, "answer": "C", "explanation": "Faeces is not an excretory product in mammals. Excretion involves the removal of metabolic waste products from the body. Faeces, however, is composed of undigested food material, bacteria, and other non-metabolic waste, thus it is eliminated from the body via egestion, not excretion. The other options, carbon dioxide, water, and urea, are all products of metabolism and are therefore excreted from the body.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>20", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "An organism which maintains a constant temperature irrespective of environmental temperature fluctuation is", "images": [], "options": {"A": "an insect", "B": "a mammal", "C": "an amphibian", "D": "a fish"}, "answer": "B", "explanation": "An organism which maintains a constant temperature irrespective of environmental temperature fluctuation is a mammal. This is because mammals are endothermic or warm-blooded animals, meaning they can regulate their body temperature internally, regardless of the external environment. This is different from ectothermic animals like insects, amphibians, and fish, which rely on the external environment to regulate their body temperature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>21", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "Which of the following conditions is responsible for the presence of sugar in the blood of diabetic patients?", "images": [], "options": {"A": "High intake of carbohydrates", "B": "Low production of insulin", "C": "Low intake of carbohydrate", "D": "High production of insulin"}, "answer": "B", "explanation": "- Low production of insulin is responsible for the presence of sugar in the blood of diabetic patients.  - Insulin helps to maintain blood sugar level. It converts glucose to glycogen by stimulating the liver thereby lowering the blood sugar level.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>22", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "The central nervous system in humans is made up of", "images": [], "options": {"A": "brain, medulla oblongata and nerves", "B": "brain, spinal cord and cranial nerves", "C": "brain and spinal nerves", "D": "brain and spinal cord"}, "answer": "D", "explanation": "The central nervous system (CNS) in humans is made up of the brain and the spinal cord. The CNS is responsible for integrating sensory information and responding accordingly. It does not include nerves or other structures, although the peripheral nervous system—which includes all nerves—does connect directly to it.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>23", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The part of the ear in mammals responsible for the detection of sounds is the", "images": [], "options": {"A": "utriculus", "B": "tympanum", "C": "cochlea", "D": "semi-circular canal"}, "answer": "C", "explanation": "The cochlea is the part of the ear in mammals responsible for the detection of sounds. It is a spiral-shaped, fluid-filled inner ear structure and is lined with cilia (tiny hairs) that move when vibrated and cause a nerve impulse to form. This impulse is then sent to the brain to be interpreted as sound.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>24", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE", "question": "Which of the following statements best describes pollination? The transfer of pollen grain from", "images": [], "options": {"A": "anther to stigmas", "B": "stigmas to stamens", "C": "the anther of a flower to the stigma of another flower of a different species", "D": "anther to the ovary"}, "answer": "A", "explanation": "Pollination is the transfer of pollen grains from the anther (male part of the flower) to the stigma (female part of the flower). This can occur within the same flower (self-pollination) or between different flowers (cross-pollination). The option 'anther to stigmas' correctly describes this process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>25", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following vertebrae provide articulating surfaces for the ribs?", "images": [], "options": {"A": "Thoracic", "B": "Lumbar", "C": "Cervical", "D": "Sacral"}, "answer": "A", "explanation": "The thoracic vertebrae provide articulating surfaces for the ribs. The human spine is divided into four sections, cervical, thoracic, lumbar, and sacral. The thoracic spine is the only section that provides articulating surfaces for the ribs. This is because the ribs are designed to protect the heart and lungs, which are located in the thoracic cavity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>26", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following is not a component of the appendicular skeleton?", "images": [], "options": {"A": "Ulna", "B": "Atlas", "C": "Femur", "D": "Pelvic girdle"}, "answer": "B", "explanation": "The appendicular skeleton consists of the bones of the upper limbs (arms), the lower limbs (legs), and the girdles (shoulder bones and hip bones) that connect the limbs to the axial skeleton. The Atlas is a part of the axial skeleton, not the appendicular skeleton. The axial skeleton consists of the skull, the spine, and the rib cage. The Atlas is the first cervical vertebra - it holds up the head.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>27", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "If the mucus in the air track of mammals dry up and the hairs in the nostrils are removed", "images": [], "options": {"A": "impure air will be breathed into their lungs", "B": "the speed of air movement into their lungs would increase", "C": "breathing air into their lungs would be difficult", "D": "more air would be taken into their lungs"}, "answer": "A", "explanation": "If the mucus in the air track of mammals dry up and the hairs in the nostrils are removed, impure air will be breathed into their lungs. The mucus and hairs in the nostrils serve as a filter, trapping dust and other particles that could be harmful if they reach the lungs. Without these, the air breathed in would be less filtered and therefore more 'impure'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>28", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "A one-seeded fruit in which the  pericarp has fused with the seed coat is classified as", "images": [], "options": {"A": "a berry", "B": "a caryopsis", "C": "a legume", "D": "an achene"}, "answer": "B", "explanation": "A caryopsis is a type of fruit in which the pericarp (the part of the fruit formed from the ovary wall) and seed coat are fused together. This is common in grasses like wheat, rice, and corn. The other options do not fit this description. A berry is a fleshy fruit without a stone produced from a single flower containing one ovary. A legume is a dry fruit contained within a shed or a pod. An achene is a type of fruit in which the seed and the fruit wall are not fused together.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>29", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Study the following list of deficiency symptoms in animals. Use it to answer this question.  I. Loss of appetite and weight  II. Delayed healing of wounds  III. Rickets  IV. Sterility in animals  V. Failure of blood to clot  VI. Night blindness    Which of the following deficiencies is caused by lack of vitamin A", "images": [], "options": {"A": "I", "B": "III", "C": "V", "D": "VI"}, "answer": "D", "explanation": "Vitamin A deficiency is associated with night blindness. Night blindness is a condition that makes it difficult to see in low light or darkness. This is because vitamin A plays a crucial role in maintaining the health of our eyes and is a component of the protein rhodopsin, which supports the health of the retina and helps the eye to effectively detect light and dark.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>30", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Study the following list of deficiency symptoms in animals. Use it to answer this question.  I. Loss of appetite and weight  II. Delayed healing of wounds  III. Rickets  IV. Sterility in animals  V. Failure of blood to clot  VI. Night blindness  Which of the following vitamins would correct the deficiency numbered V?", "images": [], "options": {"A": "Vitamin K", "B": "Vitamin A", "C": "Vitamin C", "D": "Vitamin B"}, "answer": "A", "explanation": "Vitamin K is essential for the process of blood clotting. It is involved in the production of prothrombin, a protein and clotting factor that is important in blood clotting and bone metabolism. Deficiency of Vitamin K can lead to excessive bleeding and bruising.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>31", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Study the following list of deficiency symptoms in animals. Use it to answer this question.  I. Loss of appetite and weight  II. Delayed healing of wounds  III. Rickets  IV. Sterility in animals  V. Failure of blood to clot  VI. Night blindness  Which of the following combination of food substances would correct the deficiency numbered II?", "images": [], "options": {"A": "Tomatoes, oranges and mangoes", "B": "Yeast, liver and rice", "C": "Red palm oil, carrot and egg yolk", "D": "Green vegetables, butter and meat"}, "answer": "D", "explanation": "Vitamin K, found in green vegetables, plays a crucial role in blood clotting and wound healing. Butter and meat provide fat and protein, respectively, which support the healing process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>32", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Which of the following food substances would produce a translucent mark when rubbed on a white paper?", "images": [], "options": {"A": "Potato", "B": "Beans", "C": "Mango", "D": "Groundnut"}, "answer": "D", "explanation": "Groundnut oil is a type of fat, and fats leave a translucent mark when rubbed on a white paper. This is because fats are not completely absorbed by the paper, instead they fill the pores in the paper, making it appear translucent.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>33", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "If an enzyme works best in an acid medium, in which of the following parts of the human gut is the pH for enzyme activities? In the", "images": [], "options": {"A": "ileum, pH 9.0", "B": "stomach, pH 2.0", "C": "duodenum, pH 7.0", "D": "mouth cavity, pH 8.0"}, "answer": "B", "explanation": "The stomach is the part of the human gut where the pH is most acidic, around pH 2.0. This acidic environment is ideal for the activity of certain enzymes, such as pepsin, which works best in an acidic medium. The pH scale ranges from 0 to 14, with 7 being neutral. Lower values are more acidic, while higher values are more alkaline or basic.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>34", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS", "question": "Which of the following organisms is not considered as a parasitic plant?", "images": [], "options": {"A": "Cassytha", "B": "Rhizopus", "C": "Dodder", "D": "Mistletoe"}, "answer": "B", "explanation": "Rhizopus is a genus of common saprophytic fungi, not a parasitic plant. Parasitic plants are plants that derive some or all of their nutritional requirements from another living plant. The other options, Cassytha, Dodder, and Mistletoe, are examples of parasitic plants.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>35", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION", "question": "The examples of autotrophic organisms include the following except", "images": [], "options": {"A": "Euglena", "B": "Chlamydomonas", "C": "Hydra", "D": "Spirogyra"}, "answer": "C", "explanation": "Hydra is a genus of small, simple aquatic animals that are not autotrophic. Autotrophic organisms are those that can produce their own food from the substances available in their surroundings using light (photosynthesis) or chemical energy (chemosynthesis). Euglena, Chlamydomonas, and Spirogyra are examples of autotrophic organisms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>36", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION", "question": "Which of the following organisms feeds both autotrophically and heterotrophically?", "images": [], "options": {"A": "Hydra", "B": "Paramecium", "C": "Mucor", "D": "Euglena"}, "answer": "D", "explanation": "Euglena is a unique single-celled organism that is both a plant and an animal. It is an autotroph, meaning it can produce its own food through photosynthesis, like plants do. However, when sunlight is not available, it can also feed heterotrophically by absorbing nutrients from its environment, like an animal. Therefore, Euglena feeds both autotrophically and heterotrophically.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>37", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Siphons and gills structures in aquatic organisms used for", "images": [], "options": {"A": "gaseous exchange", "B": "buoyancy", "C": "excretion", "D": "movement"}, "answer": "A", "explanation": "Siphons and gills are structures found in many aquatic organisms that are used for gaseous exchange. Gills are specialized organs that extract dissolved oxygen from water and excrete carbon dioxide. Siphons, on the other hand, are tube-like structures that allow water to enter and exit the body of the organism, facilitating the flow of water over the gills. Therefore, these structures are primarily used for gaseous exchange, not for buoyancy, excretion, or movement.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>38", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT", "question": "The first step in carrying out ecological studies in a terrestrial habitat is", "images": [], "options": {"A": "quadrant sampling", "B": "mapping the area", "C": "collection of organisms", "D": "measuring abiotic factors"}, "answer": "B", "explanation": "The first step in carrying out ecological studies in a terrestrial habitat is mapping the area. This is because before any other activity can be carried out, it is important to understand the layout of the area, its size, and its boundaries. This will guide subsequent activities such as quadrant sampling, collection of organisms, and measuring abiotic factors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>39", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "Which of the following components of an ecosystem does not contribute to the biomass of the system?", "images": [], "options": {"A": "Producers", "B": "Consumers", "C": "Micro-organisms", "D": "Habitat"}, "answer": "D", "explanation": "The habitat does not contribute to the biomass of the system. Biomass refers to the total mass of organisms in a given area or volume. Producers, consumers, and micro-organisms are all living entities and therefore contribute to the biomass. However, the habitat, which refers to the physical environment in which an organism lives, does not contribute to the biomass as it is not a living entity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>40", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "The physical and chemical factors which affect the life of organisms in an environment are described as", "images": [], "options": {"A": "biotic", "B": "edaphic", "C": "abiotic", "D": "physiographic"}, "answer": "C", "explanation": "- Abiotic factors are the physical and chemical factors which contribute the life of organisms  - Abiotic factors include   i. climatic factors   ii. chemical factors  iii. edaphic factors  iv. topographic factors", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>41", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "The group of several populations that interact and share a habitat, form", "images": [], "options": {"A": "a species", "B": "a community", "C": "an ecotype", "D": "a tribe"}, "answer": "B", "explanation": "- Community is a group of plants and animals that occupy a given area and are adaptable to the conditions of their environment.  - A community is made up of several populations of organisms of the same species.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>42", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Which of these factors are common to both aquatic and terrestrial habitats?", "images": [], "options": {"A": "Light, rainfall and turbidity", "B": "Light, temperature and tide", "C": "Light, rainfall and temperature", "D": "Rainfall, turbidity and salinity"}, "answer": "C", "explanation": "Light, rainfall and temperature are factors common to both aquatic and terrestrial habitats. Light is essential for photosynthesis in plants, temperature affects the metabolic rates of organisms, and rainfall provides water, a necessary resource for all life forms. Turbidity and tide are specific to aquatic habitats, while salinity can vary between different types of aquatic habitats and is not a factor in most terrestrial habitats.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>43", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : FEEDING HABITS", "question": "Organisms that feed essentially on plants within any ecosystem may be referred to as", "images": [], "options": {"A": "carnivores", "B": "herbivores", "C": "saprophytes", "D": "omnivores"}, "answer": "B", "explanation": "Herbivores are organisms that feed essentially on plants within any ecosystem. Carnivores are meat eaters, saprophytes feed on decaying organic matter, and omnivores eat both plants and animals.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>44", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "If a pond contains water weed, tadpoles, Tap-minnows (fish) and is visited after by Herons (bird) what would be the possible food chain?", "images": [], "options": {"A": "Water weed → Tap-minnow → Heron → Tadpole", "B": "Water weed → Tadpole →  Tap-minnow → Heron", "C": "Water weed → Heron → Tap-minnow → Tadpole", "D": "Water weed → Tadpole → Heron → Tap-minnow"}, "answer": "B", "explanation": "The correct food chain would be: Water weed (producer) → Tadpole (primary consumer) → Tap-minnow (secondary consumer) → Heron (tertiary consumer). This is because tadpoles eat plants, tap-minnows eat tadpoles, and herons eat tap-minnows.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>45", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Which of the following statements about feeding relationships is correct?", "images": [], "options": {"A": "In a food web on land, grasshopper feeds on praying mantis and on predator bugs", "B": "In a food chain on land, green plant is the producer", "C": "In an aquatic food chain, mollies larvae are the producers", "D": "In an aquatic food web, various copepods feed on mollies larvae and on sand eel"}, "answer": "B", "explanation": "For every feeding relationship on land, green plants are the producer while the herbivores, the carnivores and the omnivores are the consumer then the decomposer i.e  I. Plant → Goat → Lion → Man  II. Grass → Grasshopper → Frog → Snake e.t.c", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>46", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : CARRIERS OF MICROORGANISMS", "question": "Which of these diseases cannot be spread by an insect?", "images": [], "options": {"A": "Cholera", "B": "Malaria", "C": "Trypanosomiasis", "D": "Measles"}, "answer": "D", "explanation": "Measles is a viral disease that is spread through direct contact with an infected person or through the air when an infected person coughs or sneezes. It is not spread by insects. The other diseases listed - Cholera, Malaria, and Trypanosomiasis - can all be spread by insects.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>47", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE", "question": "Which of the following orders correctly represents the trend in eutrophication?", "images": [], "options": {"A": "Lack of oxygen → Death of aquatic organisms → Massive algal growth", "B": "Excess nitrates and phosphates → Massive algal growth → Lack of oxygen → Death of aquatic organisms", "C": "Heavy mineralization → Lack of oxygen → Massive algal growth", "D": "Excess nitrates and phosphates → Lack of oxygen → Massive algal growth → Death of aquatic organisms"}, "answer": "B", "explanation": "Eutrophication is the process whereby there is a super abundant growth of plants in lakes and rivers resulting from the release of nitrogen and phosphorus containing fertilizer, which leads to accelerated decomposition of dead plants by bacteria, which uses up oxygen, causing fish and aquatic organism to die of suffocation.  Excess nitrates and phosphates → Massive algal growth → lack of oxygen → Death of aquatic organism", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>48", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE", "question": "Air pollution can be reduced by the following methods except", "images": [], "options": {"A": "building tall factory chimneys", "B": "passing waste gases through filters and absorbers", "C": "using lead-free petrol in cars", "D": "recycling tins, cans and bottles"}, "answer": "D", "explanation": "- The process of \"recycling tins\" is not used in the control of air pollution.  - Recycling of tins is used in the control of land pollution and in the conservation of resources.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>49", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "An effective management of natural resources to ensure their continued yield from generation to generation may involve all the following except", "images": [], "options": {"A": "protection of wildlife", "B": "prevention of habitat destruction", "C": "biological control of pests", "D": "disposal of raw sewage into the sea"}, "answer": "D", "explanation": "Disposal of raw sewage into the sea is not an acceptable process, as it contributes to water pollution.  Hence, it is not a method/way through which resources can be conserved.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>50", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "The following practices contribute towards the conservation of natural resources except", "images": [], "options": {"A": "afforestation", "B": "deforestation", "C": "contour ploughing", "D": "establishment of Game Reserves"}, "answer": "B", "explanation": "Deforestation is a process that involves cutting of trees in the forest, this reduces the number of trees species.  Hence, it is not in congruence with the purpose of conservation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>51", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Variation is a factor which", "images": [], "options": {"A": "differentiates between individuals of the same species", "B": "qualifies an organism to live with others", "C": "enables organisms to adapt to the environment", "D": "states the external features of an organism"}, "answer": "A", "explanation": "* Variation is the morphological and physiological differences which occur within a species, which could be hereditary or acquired from the environment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>52", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Which of the following traits in humans is not a morphological variation?", "images": [], "options": {"A": "Height", "B": "Shape of head", "C": "Colour of skin", "D": "Ability of roll the tongue"}, "answer": "D", "explanation": "- Height shape of the head and skin colour are morphological variations as they are noticeable physical appearances.  - The ability to role the tongue is a physiological variation as it is a behaviour of an organism.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>53", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "The blood group in humans referred to as a universal recipient is", "images": [], "options": {"A": "O", "B": "A", "C": "B", "D": "AB"}, "answer": "D", "explanation": "The blood group AB is referred to as the universal recipient because it can receive blood from donors of any blood type: A, B, AB, or O. This is due to the fact that AB blood does not have any antibodies against A or B antigens.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>54", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "If a heterozygous red flowered plant, (Rr) was self fertilized, the offspring would be expected to be", "images": [], "options": {"A": "all red flowered plants", "B": "all white flowered plants", "C": "3/4 red flowered, 1/4 white flowered plants", "D": "3/4 white flowered, 1/4 red flowered plants"}, "answer": "C", "explanation": "In Mendelian genetics, a heterozygous organism has two different alleles of a gene. If a heterozygous red flowered plant (Rr) is self-fertilized, the expected ratio of the offspring would be 3/4 red flowered plants and 1/4 white flowered plants. This is based on the Punnett square, a diagram that is used to predict the outcome of a particular cross or breeding experiment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>55", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "The contrasting pair of genes affecting a trait and located at the same position on homologous chromosomes is referred to as", "images": [], "options": {"A": "chromatids", "B": "mutants", "C": "alleles", "D": "chromatin"}, "answer": "C", "explanation": "The contrasting pair of genes affecting a trait and located at the same position on homologous chromosomes is referred to as alleles. Alleles are different forms of the same gene. They are located at the same position (locus) on homologous chromosomes. They are responsible for variations in inherited characteristics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>56", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "The haploid number of chromosome in humans is", "images": [], "options": {"A": "48", "B": "46", "C": "24", "D": "23"}, "answer": "D", "explanation": "The haploid number of chromosomes in humans is 23. In humans, the diploid number of chromosomes is 46, which means there are 23 pairs. The haploid number refers to the number of chromosomes in a gamete (sperm or egg), which is half the diploid number. Therefore, the haploid number in humans is 23.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2006>57", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "If a pure breeding white cat (homozygous dominant) mates with a pure breeding black cat (recessive), what would be the fur colour of the F1 generation?", "images": [], "options": {"A": "Homozygous white", "B": "Homozygous black", "C": "Heterozygous white", "D": "Heterozygous black"}, "answer": "C", "explanation": "- Let the pure breeding white cat be r r - dominant  - Let the pure breeding red cat be R R - recessive    F1 generation   Since white is dominant, the colour of the cat in the first filial generation is heterozygous white.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>58", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Courtship behaviour in animals may include all of the following except", "images": [], "options": {"A": "howling of a dog", "B": "dancing of the worker bee", "C": "croaking of a toad", "D": "basking in the sun by a lizard"}, "answer": "D", "explanation": "Courtship behaviour in animals is a set of display behaviours in which an animal attempts to attract a mate and exhibit their desire to copulate. These behaviours often include visual displays, sound production, or specific movements to attract mates. Options 1, 2 and 3 are examples of courtship behaviours. However, basking in the sun by a lizard is not a courtship behaviour but a thermoregulatory behaviour where lizards absorb heat from the sun, which is necessary for their metabolic processes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>59", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Honey-bee workers carry out the following functions except", "images": [], "options": {"A": "laying eggs", "B": "building nests", "C": "cleaning the nests", "D": "gathering food"}, "answer": "A", "explanation": "In a honey bee colony, the queen is the only bee that lays eggs. The worker bees, which are sterile females, perform all other duties such as building the hive, cleaning the nest, and gathering food. Therefore, the statement 'laying eggs' is not a function of honey-bee workers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2006>60", "subject": "Biology", "year": "2006", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "The long necks and legs of the present day giraffes were some of the basis of", "images": [], "options": {"A": "Darwins theory of evolution", "B": "Mendel's theory of inheritance", "C": "Lamarck's theory of evolution", "D": "De Vries theory of evolution"}, "answer": "C", "explanation": "The long necks and legs of the present day giraffes were some of the basis of Lamarck's theory of evolution. Lamarck's theory, also known as Lamarckism, proposed that an organism can change during its lifetime in response to its environment, and those changes are inheritable. In the case of giraffes, Lamarck believed that the continual stretching of their necks to reach leaves high in trees led to their long necks, which were then passed on to their offspring.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>1", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : IRRITABILITY AS A BASIC CHARACTERISTIC OF PROTOPLASM", "question": "A change in the environment of an organism is termed", "images": [], "options": {"A": "Sensitivity", "B": "Impulse", "C": "Response", "D": "Stimulus"}, "answer": "D", "explanation": "From the characteristics of living Organism 'irritability'  meaning response to stimulus is the factors that causes change in the environment of an organism.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>2", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "Organisms that interbreed to produce fertile offspring belong to the same.", "images": [], "options": {"A": "Class", "B": "Family", "C": "Species", "D": "Order"}, "answer": "C", "explanation": "Organisms that interbreed to produce fertile offspring belong to the same species. This is a basic definition of a species, which is the lowest and most specific level of biological classification. The other options, Class, Family, and Order, are higher levels of classification and do not necessarily include organisms that can interbreed to produce fertile offspring.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>3", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The transfer of ripe pollen grains from the anther to the stigma of the same flower is termed.", "images": [], "options": {"A": "Fertilization", "B": "Self pollination", "C": "Reproduction", "D": "Conjugation"}, "answer": "B", "explanation": "The transfer of ripe pollen grains from the anther to the stigma of the same flower is termed self-pollination. This is a type of pollination where pollen from the same plant is used to fertilize the ovules. Fertilization is the process that occurs after pollination, where the sperm cell from the pollen grain merges with the egg cell in the ovule. Reproduction is a broader term that includes all processes involved in producing offspring, and conjugation is a type of sexual reproduction in bacteria and other single-celled organisms.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>4", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "The hereditary material in a living organism is located inside the", "images": [], "options": {"A": "Protein wall", "B": "Cytoplasm", "C": "Nucleus", "D": "Lysosome"}, "answer": "C", "explanation": "The hereditary material in a living organism is located inside the nucleus. The nucleus of a cell contains chromosomes, which are made up of DNA. DNA is the hereditary material that carries genetic information used in the growth, development, functioning and reproduction of all known living organisms and many viruses.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>5", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Respiration is an essential life process providing the living cells with", "images": [], "options": {"A": "Oxygen", "B": "Sugars", "C": "Energy", "D": "Carbon dioxide"}, "answer": "C", "explanation": "Respiration is an essential life process providing the living cells with energy. During respiration, cells break down simple food molecules such as sugar and release the energy they contain. This process is called cellular respiration which takes place in the mitochondria of the cell.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>6", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The organelle involved in the transport of substances within a cell is", "images": [], "options": {"A": "Golgi body", "B": "Endoplasmic reticulum", "C": "Ribosome", "D": "Mitochondrion"}, "answer": "A", "explanation": "The Golgi body is used to transport materials within the cell.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>7", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "Which of the following processes takes place when a plant cell is put in a hypotonic solution?", "images": [], "options": {"A": "Water moves into the cell and the cell bursts", "B": "Water leaves the cell and the cell becomes flabby", "C": "Water moves into the cell and the cell becomes turgid", "D": "The cell becomes  plasmolysis"}, "answer": "C", "explanation": "When a plant cell is put in a hypotonic solution, water moves into the cell and the cell becomes turgid. This is because a hypotonic solution has a lower solute concentration than the inside of the cell, causing water to move into the cell by osmosis. This influx of water causes the cell to swell and become turgid. Turgidity is important in plant cells as it helps them maintain their shape and structure.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>8", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The dominant stage in the life cycle of a fern is the", "images": [], "options": {"A": "Antheridium", "B": "Gametophyte", "C": "Prothallus", "D": "Sporophyte"}, "answer": "D", "explanation": "The dominant stage in the life cycle of a fern is the sporophyte. In the life cycle of a fern, the sporophyte is the diploid multicellular stage that is usually visible to the naked eye. It grows out of the gametophyte, which is the haploid multicellular stage. The sporophyte is dominant because it lasts longer and is generally larger than the gametophyte stage.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>9", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION", "question": "Yeast is added to the dough during the preparation of bread because it produces", "images": [], "options": {"A": "Ethanol", "B": "Heat", "C": "Carbon dioxide", "D": "Carbohydrate"}, "answer": "C", "explanation": "Yeast is added to the dough during the preparation of bread because it produces carbon dioxide. Yeast is a type of fungus that ferments the sugars in the dough, producing carbon dioxide as a byproduct. This carbon dioxide gets trapped in the dough, causing it to rise and giving bread its fluffy texture.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>10", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL THEORY", "question": "Growth includes the following processes except", "images": [], "options": {"A": "Differentiation", "B": "Enlargement", "C": "Mitosis", "D": "Meiosis"}, "answer": "D", "explanation": "Growth in biology refers to the process where an organism increases in size through cell multiplication and development. This involves processes such as differentiation (specialization of cells for specific functions), enlargement (increase in size of the cells), and mitosis (cell division that results in two identical daughter cells). However, meiosis is a type of cell division that results in four daughter cells each with half the number of chromosomes of the parent cell. It is involved in sexual reproduction, not growth.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>11", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "Which of the following processes is a form of sexual reproduction?", "images": [], "options": {"A": "Budding by yeast cells", "B": "Conjugation in spirogyra", "C": "Binary fission in Amoeba", "D": "Rhizome production by ginger"}, "answer": "B", "explanation": "Sexual reproduction is a type of reproduction that involves the combination of genetic material from two parent organisms to create offspring with a unique genetic identity. This process involves the fusion of gametes (sex cells) from each parent. Among the options, only conjugation in spirogyra represents a form of sexual reproduction. Spirogyra, a type of green algae, reproduces sexually through a process called conjugation where two filaments align side by side and form bridges between corresponding cells, allowing for the transfer and recombination of genetic material.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>12", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The fine adjustment of the light microscope is used to", "images": [], "options": {"A": "Admit more light into the microscope", "B": "Focus the object under low power", "C": "Focus the object under high power", "D": "Raise the stage upwards"}, "answer": "C", "explanation": "The fine adjustment knob on a microscope is used to move the objective lenses slightly to sharpen the focus. It's typically used after the coarse adjustment knob has brought the object into general focus under low power. The fine adjustment knob is then used to fine-tune the focus under high power, hence the correct answer is 'Focus the object under high power'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>13", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "Which of these statements about white blood cells is true? They", "images": [], "options": {"A": "are clotting of blood", "B": "carry oxygen round the body", "C": "are the most numerous blood cells", "D": "are large nucleated cells"}, "answer": "D", "explanation": "White blood cells, also known as leukocytes, are a key part of the immune system. They are larger than red blood cells and are nucleated, meaning they contain a nucleus. They do not carry oxygen around the body, that's the function of red blood cells. They are also not the most numerous blood cells, red blood cells are. They do not clot blood, that's the function of platelets. Hence, the correct answer is 'are large nucleated cells'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>14", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "Which of the following blood vessels have valves?", "images": [], "options": {"A": "Capillary", "B": "Artery", "C": "Vein", "D": "Arteriole"}, "answer": "C", "explanation": "Veins are the type of blood vessels that have valves. The valves in veins help prevent the backflow of blood and ensure that it flows in one direction towards the heart. Other blood vessels like arteries, capillaries, and arterioles do not have valves.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>15", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "The malpighian body of the mammalian kidney is made up of", "images": [], "options": {"A": "cortex and medulla", "B": "Bowman's capsule and loop of Henle", "C": "glomerulus's and Bowman's capsule", "D": "pelvis and pyramid"}, "answer": "C", "explanation": "The malpighian body of the mammalian kidney is made up of the glomerulus and Bowman's capsule. The glomerulus is a network of capillaries that performs the first step of filtering blood. The Bowman's capsule is a cup-like sac that surrounds the glomerulus and collects the filtrate from the blood. The other options are incorrect as they either represent different parts of the kidney or include structures not part of the malpighian body.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>16", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "The persistence presence of glucose in a person's urine indicates malfunctioning of the", "images": [], "options": {"A": "Heat", "B": "Bladder", "C": "Pancreas", "D": "Stomach"}, "answer": "C", "explanation": "- The pancreas produces a hormone called insulin   * Insulin is a polypeptide hormone that regulates carbohydrate metabolism.  - If the pancreas is not functioning properly, insulin will not be produced properly and carbohydrates like glucose will not be metabolised properly.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>17", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "The endocrine gland which co-ordinates the action of other glands and is also associated with the nervous system is the", "images": [], "options": {"A": "adrenal gland", "B": "thyroid gland", "C": "pituitary gland", "D": "thymus gland"}, "answer": "C", "explanation": "The pituitary gland is often referred to as the 'master gland' because it controls the function of most other endocrine glands. It is also associated with the nervous system because it is directly controlled by the hypothalamus, a region of the brain that links the nervous system to the endocrine system through the pituitary gland. The pituitary gland secretes hormones that regulate a variety of bodily functions, including growth, blood pressure, and reproduction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>18", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "Insulin is produced by the", "images": [], "options": {"A": "Adrenal gland", "B": "Gonads", "C": "Pituitary gland", "D": "Pancreas"}, "answer": "D", "explanation": "Insulin is a hormone that is produced in the body by the pancreas. It's responsible for regulating the amount of glucose in the bloodstream. It allows cells in the body to take in sugar (glucose) from the bloodstream and use it as a source of energy. When the body needs more insulin, the beta cells in the pancreas produce more.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>19", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "Which of the following statements about nerves cells is not correct?", "images": [], "options": {"A": "The axons relay impulse from the cell body", "B": "The cell body is always found at the end of the neurone", "C": "Each neurone has a cell body", "D": "The dendrites of one neurone transmit impulses to the cell body"}, "answer": "B", "explanation": "- The axon chance the easy transmission of impulse from the body cells  - The dendrons are long fibres which transmits impulses towards the cell body  - The cell body consists of the nucleus and the cytoplasm  -  the cell body is always found at the end of the neuron is not correct", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>20", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "The smallest branches on the cell body of a neurone are called", "images": [], "options": {"A": "Dendrites", "B": "Dendrons", "C": "Ganglia", "D": "Schwan cells"}, "answer": "A", "explanation": "- Dendrites are the smallest branches on the cell body of a neurone.  - The dendrites are short cytoplasmic filaments which conduct impulses towards the cell body.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>21", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "A neurone that transmits impulses directly from sensory cells is called", "images": [], "options": {"A": "an afferent neurone", "B": "an efferent neurone", "C": "a relay neurone", "D": "a peripheral neurone"}, "answer": "A", "explanation": "A neuron that transmits impulses directly from sensory cells is called an afferent neuron. The term 'afferent' comes from Latin roots that mean 'to bring to'. In the context of the nervous system, afferent neurons bring information from sensory receptors toward the central nervous system. An efferent neuron, on the other hand, carries information away from the central nervous system to effectors such as muscles or glands. A relay neuron transmits impulses between neurons, typically within the central nervous system. A peripheral neuron is a neuron located outside the central nervous system.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>22", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Protection of the body cells of mammals against ultraviolet rays of the sun is brought about by", "images": [], "options": {"A": "Keratin", "B": "Melanin", "C": "Sebum", "D": "Scales"}, "answer": "B", "explanation": "Melanin is a pigment produced by cells called melanocytes in the skin of most organisms. It provides some protection against skin damage from the sun, and the melanocytes increase their production of melanin in response to sun exposure. This pigment absorbs ultraviolet light, which both prevents direct damage to DNA and absorbs heat that could otherwise cause indirect DNA damage.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>23", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "In which of the following organisms is parental care manifested?", "images": [], "options": {"A": "Tilapia", "B": "Toad", "C": "Cockroach", "D": "Snail"}, "answer": "A", "explanation": "Parental care is the behavior of an adult towards its offspring. This includes activities that improve the survival of the offspring. Tilapia, a type of fish, is known for its parental care. The female tilapia carries the eggs and young fish in her mouth to protect them from predators. This is a form of parental care known as mouthbrooding.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>24", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The site for production of ATP in a cell is", "images": [], "options": {"A": "Ribosome", "B": "Cytoplasm", "C": "Golgi body", "D": "Mitochondrion"}, "answer": "D", "explanation": "The site for production of ATP (Adenosine Triphosphate) in a cell is the Mitochondrion. ATP is often called the 'energy currency of life' because it is the main energy source that cells use for their functions. The process of ATP production in the mitochondrion is called cellular respiration, where glucose and other metabolites are oxidized to produce ATP.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>25", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "In testing for starch in a leaf, the leaf is boiled in alcohol to", "images": [], "options": {"A": "Kill the cells", "B": "Soften the leaf", "C": "Enable chemicals penetrate the leaf", "D": "Decolourise the leaf"}, "answer": "D", "explanation": "In testing for starch in a leaf, the leaf is boiled in alcohol to decolourise the leaf. The green color in the leaf is due to chlorophyll. To test for starch, the green color needs to be removed so that the blue-black color of iodine-starch complex can be clearly seen. Boiling the leaf in alcohol removes the chlorophyll and decolourises the leaf.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>26", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION", "question": "The mode of nutrition common to green plants is", "images": [], "options": {"A": "Autotrophic", "B": "Heterotrophic", "C": "Holozoic", "D": "Saprophytic"}, "answer": "A", "explanation": "The mode of nutrition common to green plants is autotrophic. Autotrophic nutrition is a type of nutrition where organisms make their own food from simple inorganic substances like carbon dioxide and water using sunlight (in case of green plants) or chemical energy (chemoautotrophs). Green plants are known as photoautotrophs because they use sunlight to synthesize food through a process known as photosynthesis.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>27", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Micro-nutrients essential for the synthesis of chlorophyll include", "images": [], "options": {"A": "Iron and potassium", "B": "Iron and magnesium", "C": "Magnesium and calcium", "D": "Magnesium and potassium"}, "answer": "B", "explanation": "Micro-nutrients essential for the synthesis of chlorophyll include Iron and Magnesium. Chlorophyll is the green pigment found in green plants that is responsible for absorbing sunlight for photosynthesis. Iron (Fe) is necessary for chlorophyll synthesis and is also a component of many enzymes associated with energy transfer, nitrogen reduction and fixation, and lignin formation. Magnesium (Mg) is a central atom in the chlorophyll molecule and is essential for photosynthesis.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>28", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Biuret's test is carried out on a food substance to indicate the presence of", "images": [], "options": {"A": "Vitamins", "B": "Fats", "C": "Protein", "D": "Starch"}, "answer": "C", "explanation": "Biuret's test is a chemical test used for detecting the presence of peptide bonds. In the presence of peptides, a copper(II) ion forms violet-colored coordination complexes in an alkaline solution. Proteins, being made up of peptides, will give a positive result for this test. Therefore, Biuret's test is carried out on a food substance to indicate the presence of Protein.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>29", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "In a test for non-reducing sugars like sucrose, what is the significance of adding dilute hydrochloric acid to the original sugar solution? To", "images": [], "options": {"A": "Hydrolyse the non-reducing sugar", "B": "Accelerate the rate of the reaction", "C": "Stabilize the medium", "D": "Sterilize the solution"}, "answer": "A", "explanation": "In a test for non-reducing sugars like sucrose, dilute hydrochloric acid is added to the original sugar solution to hydrolyse the non-reducing sugar. Non-reducing sugars do not have a free aldehyde or ketone group and hence do not reduce copper(II) ions to copper(I) ions. However, when treated with dilute hydrochloric acid, these sugars get hydrolysed to their constituent monosaccharides which are reducing sugars. Therefore, the significance of adding dilute hydrochloric acid to the original sugar solution is to hydrolyse the non-reducing sugar.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>30", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "The colour that is associated with a positive iodine test is", "images": [], "options": {"A": "Brown", "B": "Red", "C": "Blue-black", "D": "Yellow"}, "answer": "C", "explanation": "Iodine test is a test for starch and it involves the addition of iodine to a starch material, the colour will change blue-black, indicating the presence of glucose.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>31", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : PROPERTIES AND FUNCTIONS OF THE LIVING CELL", "question": "Enzymes can be inactivated by certain substances in the body called", "images": [], "options": {"A": "catalysts", "B": "inhibitors", "C": "substrates", "D": "activators"}, "answer": "B", "explanation": "Enzymes are biological catalysts that speed up chemical reactions in the body. However, their activity can be affected by various factors, including the presence of certain substances known as inhibitors. Enzyme inhibitors are molecules that bind to enzymes and decrease their activity. They can bind to the active site of the enzyme or to other parts of the enzyme molecule, often causing a change in the enzyme's shape, which prevents it from binding to its substrate and carrying out its catalytic function.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>32", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : PROPERTIES AND FUNCTIONS OF THE LIVING CELL", "question": "Which of the following enzymes is not one of the main classes of enzymes?", "images": [], "options": {"A": "Sucrase", "B": "Amylases", "C": "Proteases", "D": "Lipases"}, "answer": "A", "explanation": "Amylase - It is present in the saliva that breaks starch down into glucose  Proteases - It is an enzyme that break down protein  Lipases - It is an enzymes that catalyse the hydrolysis of ester bonds in fats & oils  Sucrase - It is an enzyme that Hydrolyzes sucrose into fructose and glucose  Amylase, Proteases and Lipases are the main classes of enzymes that enhance digestion  sucrose Is not a main class of enzymes 3 main classes of enzymes are Amylase , proteases and lipase", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>33", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : PROPERTIES AND FUNCTIONS OF THE LIVING CELL", "question": "Use the following equations to answer this question  I. Boiled saliva + starch → x  II. Fresh saliva + starch → Y    What substances do x and Y represent?", "images": [], "options": {"A": "X = Maltose and Y = Sugar", "B": "X = Starch and Y = Maltose", "C": "X = Sugar and Y = Starch", "D": "X = Maltose and Y = Starch"}, "answer": "B", "explanation": "In the first equation, boiled saliva (which has its enzymes denatured) is mixed with starch, so no enzymatic reaction occurs and the starch remains as starch. Hence, X = Starch. In the second equation, fresh saliva (which contains active amylase enzymes) is mixed with starch. The amylase breaks down the starch into maltose. Hence, Y = Maltose.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2007>34", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONCEPT OF LIVING : PROPERTIES AND FUNCTIONS OF THE LIVING CELL", "question": "Which of the following enzymes does not belong to proteases?", "images": [], "options": {"A": "Sucrase", "B": "Pepsin", "C": "Trypsin", "D": "Erepsin"}, "answer": "A", "explanation": "Proteases consists of enzymes that helps to break down protein in food which include:  Pepsin → Trypsin → Erepsin  while sucrose helps to convert sucrose to fructose and glucose.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>35", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION", "question": "Which of the following protozoans feeds parasitically?", "images": [], "options": {"A": "Paramecium", "B": "Chlamydomonas", "C": "Plasmodium", "D": "Euglena"}, "answer": "C", "explanation": "Plasmodium is a genus of parasitic protozoans. They are responsible for causing malaria in humans. Parasitic feeding is a type of heterotrophic nutrition where an organism (the parasite) lives on or in another organism (the host) and causes harm to it. The other options, Paramecium, Chlamydomonas, and Euglena, are not known to be parasitic.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>36", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : FEEDING HABITS", "question": "Which of the following features of the tadpole indicates that the animal is herbivorous? Possession of", "images": [], "options": {"A": "Operculum", "B": "Muscular tail", "C": "Long coiled intestine", "D": "Internal gills"}, "answer": "C", "explanation": "Herbivores are known to have long coiled intestines. This is because plant matter is generally harder to break down than meat, and a longer digestive tract allows more time for the body to break down and absorb the nutrients from plant matter. Therefore, the feature of the tadpole that indicates it is herbivorous is the possession of a long coiled intestine.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>37", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS", "question": "The term community is defined as", "images": [], "options": {"A": "the different groups of plants and animals in the same area and interacting with each other", "B": "the consumers and producers living in a habitat", "C": "living organisms interacting with physical factors of an environment", "D": "animals which mutually derive benefit from their association"}, "answer": "A", "explanation": "A community in biology refers to the different groups of plants and animals in the same area that interact with each other. This includes all the species in a certain area, including plants, animals, fungi, and microorganisms. They interact with each other in various ways, such as through competition, predation, symbiosis, and other types of interactions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>38", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS", "question": "Which of the following organisms are the producers in an aquatic habitat?", "images": [], "options": {"A": "Benthos", "B": "Phytoplanktons", "C": "Zooplanktons", "D": "Nektons"}, "answer": "B", "explanation": "In an aquatic habitat, the producers are the Phytoplanktons. Producers, also known as autotrophs, are organisms that can produce their own food from the substances available in their surroundings using light (photosynthesis) or chemical energy (chemosynthesis). Phytoplanktons are microscopic plants that live in the ocean and they are the primary producers in the aquatic food chain because they produce their own food through photosynthesis.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>39", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS", "question": "Wind speed is measured with", "images": [], "options": {"A": "a maximum-minimum thermometer", "B": "a hygrometer", "C": "a wet and dry bulb hygrometer", "D": "an anemometer"}, "answer": "D", "explanation": "Wind speed is measured with an anemometer. An anemometer is a device used for measuring the speed of wind, and is also a common weather station instrument. The term is derived from the Greek word anemos, which means wind, and is used to describe any wind speed instrument used in meteorology.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>40", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "The amount of energy passed from one trophic level to the next decreases because", "images": [], "options": {"A": "Many organisms are present at the first trophic level", "B": "Many organisms occur at the higher trophic level", "C": "More energy is conserved at lower trophic levels", "D": "Parts of the organisms remain unutilized at each trophic level"}, "answer": "D", "explanation": "In an ecological food chain, not all the energy from one trophic level is transferred to the next. Some energy is always lost as heat in the process of metabolic activities by the organisms. Also, some parts of the organisms at each trophic level are not eaten or cannot be digested, thus remaining unutilized. Therefore, the amount of energy passed from one trophic level to the next decreases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>41", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "Which of these values in kj/m2 likely represents the energy content of the producers in a habitat?", "images": [], "options": {"A": "5033", "B": "100", "C": "12", "D": "10"}, "answer": "A", "explanation": "The energy content of a particular food chain usually decrease from the producer to the decomposer. Therefore, the producer tends to have  the most energy content", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>42", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE", "question": "The major pollutant around airport residential areas is", "images": [], "options": {"A": "oil spillage", "B": "soot", "C": "noise", "D": "dust"}, "answer": "C", "explanation": "Airports are a major source of noise pollution due to the take-off and landing of aircraft. This noise can be particularly disruptive in residential areas near airports, making noise the major pollutant in these areas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>43", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE", "question": "The effect of chlorofluorocarbon is", "images": [], "options": {"A": "reduction of oxygen concentration in the atmosphere", "B": "depletion of the ozone layer", "C": "screening of ultra violet rays", "D": "increase in carbon dioxide concentration"}, "answer": "B", "explanation": "Chlorofluorocarbons (CFCs) are a type of compound that, when released into the atmosphere, can lead to the depletion of the ozone layer. This is because CFCs can rise to the stratosphere (the second major layer of Earth's atmosphere), where they are broken apart by solar energy, releasing chlorine atoms. These chlorine atoms are capable of catalyzing the breakdown of ozone into oxygen, thereby depleting the ozone layer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>44", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "ECOLOGY OF POPULATION : ECOLOGICAL SUCCESSION", "question": "The order of primary succession by plants in a very dry habitat is", "images": [], "options": {"A": "xerophytes → mesophytes → shrub", "B": "mesophytes → xerophytes → shrub", "C": "mesophytes → shrub → xerophytes", "D": "xerophytes → shrub → mesophytes"}, "answer": "D", "explanation": "Primary succession in a very dry habitat starts with xerophytes, which are plants adapted to extremely dry conditions. Mesophytes, on the other hand, are adapted to moderate moisture levels and wouldn't typically establish themselves until later in the succession process when soil moisture and organic content have improved.     1. Xerophytes: These are the pioneer species in very dry habitats because they can survive and establish themselves in harsh, arid conditions with minimal soil and moisture.  2. Shrubs: Once xerophytes have established and started to improve the soil quality (by adding organic matter and retaining some moisture), shrubs, which require slightly better conditions than xerophytes, can take root.  3. Mesophytes: Finally, mesophytes, which require moderate moisture levels and more developed soil, can colonize the area as conditions improve due to the presence of earlier plant species.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>45", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION", "question": "A population which exceeds its carrying capacity and then collapses is represented graphically as a", "images": [], "options": {"A": "bell shaped curve", "B": "skewed curve", "C": "s-shaped curve", "D": "linear curve"}, "answer": "A", "explanation": "A population which exceeds its carrying capacity and then collapses is represented graphically as a bell-shaped curve. This is because the population grows rapidly at first (the upward slope of the curve), then slows as it approaches the carrying capacity (the top of the curve), and finally collapses (the downward slope of the curve). The carrying capacity is the maximum population size that the environment can sustain indefinitely, given the food, habitat, water, and other necessities available in the environment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>46", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH", "question": "Which of the following infections would not respond to an antibiotic treatment?", "images": [], "options": {"A": "Gonorrhea", "B": "Measles", "C": "Diarrhoea", "D": "Tuberculosis"}, "answer": "B", "explanation": "Measles will not respond to anti-biotic treatment because it is not caused by organisms like bacteria, and other biotic communities, it is caused by air and body.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>47", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : CARRIERS OF MICROORGANISMS", "question": "The vector of the sleeping sickness disease parasite is the", "images": [], "options": {"A": "cockroach", "B": "mosquito", "C": "black fly", "D": "tse-tse fly"}, "answer": "D", "explanation": "The vector of the sleeping sickness disease parasite is the tse-tse fly. A vector in medical terms is an organism that does not cause disease itself but which spreads infection by conveying pathogens from one host to another. In this case, the tse-tse fly is the vector that carries the Trypanosoma brucei parasite, which causes sleeping sickness.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>48", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following bacteria lives in the root nodules of leguminous plants?", "images": [], "options": {"A": "Azotobacter", "B": "Nitrobacter", "C": "Rhizobium", "D": "Nitrosomonas"}, "answer": "C", "explanation": "Rhizobium bacteria live in the root nodules of leguminous plants. These bacteria have a symbiotic relationship with the plants, where they convert atmospheric nitrogen into a form that the plants can use, a process known as nitrogen fixation. The other options, Azotobacter, Nitrobacter, and Nitrosomonas, are also involved in the nitrogen cycle but they do not live in the root nodules of leguminous plants.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>49", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Endangered species are organisms that ought to be", "images": [], "options": {"A": "Hunted", "B": "Killed", "C": "Poached", "D": "Protected"}, "answer": "D", "explanation": "Endangered species are organisms that are at risk of becoming extinct. Therefore, they ought to be protected to ensure their survival and prevent their extinction. Hunting, killing, or poaching them would only increase their risk of extinction, which is contrary to the goal of preserving biodiversity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>50", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "Which of the following substances is not a conservable natural resource?", "images": [], "options": {"A": "Minerals", "B": "Air", "C": "Soil", "D": "Water"}, "answer": "B", "explanation": "A conservable natural resource is a resource that can be conserved or preserved for future use. Minerals, soil, and water are all resources that can be conserved. For example, minerals can be mined and stored, soil can be conserved through sustainable farming practices, and water can be conserved through efficient use and treatment. However, air is not a conservable resource because it cannot be stored or conserved in the same way. While air quality can be improved and pollution can be reduced, the air itself cannot be conserved for future use.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>51", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Which of the following actions do not reflect the objectives of conservation of natural resources?", "images": [], "options": {"A": "Protection of the ecosystem", "B": "Saving some species from extinction", "C": "Elimination of some wild animals to enable others survive", "D": "Prevention of indiscriminate killing of organism"}, "answer": "C", "explanation": "Elimination of some wild animals to enable others survive is not one one of the objectives of conservation.  - Conservation is aimed at protecting resources in order to ensure their continuous existence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>52", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Which of the following forms of variation will give a normal distribution?", "images": [], "options": {"A": "Blood group", "B": "Tongue rolling", "C": "Body weight", "D": "Finger prints"}, "answer": "C", "explanation": "A normal distribution is a type of statistical distribution where the data has a bell-shaped curve. This means that most of the data falls around the mean, or average, and decreases on either side. Body weight is a trait that would follow a normal distribution as it varies among individuals due to factors like diet, exercise, genetics, etc. The other options like blood group, tongue rolling and finger prints are discrete traits and do not follow a normal distribution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>53", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "Two tall plants were crossed; some of their offspring were tall and others short, the possible genotypes of the parent plants were", "images": [], "options": {"A": "TT and TT", "B": "TT and tt", "C": "Tt and Tt", "D": "Tt and TT"}, "answer": "C", "explanation": "The genotype of the parents are possibly, Tt and Tt.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>54", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "The character that is manifested in an organism in the presence of a Contrasting  character is known as", "images": [], "options": {"A": "Genotype", "B": "Phenotype", "C": "Recessive", "D": "Dominant"}, "answer": "D", "explanation": "Dominant character: this is a trait or character that is expressed in an offspring when two individuals with contrasting characters or traits are crossed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>55", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "What is the probability of producing a child of blood group O* by a woman of blood group O and a man of blood group A**?", "images": [], "options": {"A": "25%", "B": "50%", "C": "75%", "D": "100%"}, "answer": "A", "explanation": "The probability of producing a child of blood group O by a woman of Blood group O and a man of blood group A is usually 25%.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>56", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "An albino man marries a normal woman (homozygous for skin pigmentation). What is the probability that the couple could have an albino child?", "images": [], "options": {"A": "0%", "B": "0.5%", "C": "25%", "D": "60%"}, "answer": "A", "explanation": "Abino man = aa  Normonal woman = AA    None of the children will be Albino, but will have the traits of albino in them.  04×100%=0%", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>57", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "If a cross between a red-flowered plant and a white flowered plant produced red flowered plants, the result can be described as an example of", "images": [], "options": {"A": "Partial recessiveness", "B": "Dominance", "C": "Incomplete dominance", "D": "Out breeding"}, "answer": "B", "explanation": "- Let the red-flowered plant be RR.  - Let the white-flowered plant be rr.    - The offspring in the F1 generation have rr as their genotype.  - This is an example of complete dominance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>58", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of the following inherited conditions usually shows incomplete dominance?", "images": [], "options": {"A": "Sickle cell anaemia", "B": "Haemophilia", "C": "Tongue rolling ability", "D": "Baldness"}, "answer": "D", "explanation": "Baldness is an inherited condition which usually shows incomplete dominance. Baldness is an example of incomplete dominance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2007>59", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "The theory of survival of the fittest was propounded by", "images": [], "options": {"A": "Darwin", "B": "Lamarck", "C": "Linnaeus", "D": "Mendel"}, "answer": "A", "explanation": "The theory of survival of the fittest was propounded by Charles Darwin. This theory, also known as natural selection, states that in nature, the organisms best adapted to their environment are the ones most likely to survive and pass on their traits to the next generation. Darwin's theory of evolution by natural selection is one of the foundational concepts in biology.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2007>60", "subject": "Biology", "year": "2007", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "A termite with a relatively large head and powerful jaws is likely to be a", "images": [], "options": {"A": "king", "B": "queen", "C": "soldier", "D": "reproduction"}, "answer": "C", "explanation": "In a termite colony, the termite with a relatively large head and powerful jaws is likely to be a soldier. Soldier termites are responsible for defending the colony from predators. Their large heads and powerful jaws are adaptations that enable them to perform this role effectively.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>1", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "In the binomial system of naming organisms, the second name is called the", "images": [], "options": {"A": "scientific name", "B": "common name", "C": "generic name", "D": "specific name"}, "answer": "D", "explanation": "In the binomial system of naming organisms, the first name is the genus name and the second name is the species name, also known as the specific name. This system was developed by Carl Linnaeus, and it helps to avoid confusion by providing each species with a unique, scientifically accepted name.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2008>2", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "Which of the following features does not necessarily place paramecium at a higher level of organization over Amoeba?", "images": [], "options": {"A": "Presence of cilia", "B": "Absence of pseudopodia", "C": "Presence of micro and mega nuclei", "D": "Presence of more than one food vacuole"}, "answer": "D", "explanation": "Both Paramecium and Amoeba are single-celled organisms, or protozoans. While Paramecium has cilia and both micro and mega nuclei, Amoeba does not, which places Paramecium at a higher level of organization. However, both Paramecium and Amoeba can have more than one food vacuole. Food vacuoles are structures within the cell that contain food particles engulfed by the cell. Therefore, the presence of more than one food vacuole does not necessarily place Paramecium at a higher level of organization over Amoeba.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>3", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The living material of the cell consists of", "images": [], "options": {"A": "nucleus and cytoplasm", "B": "cytoplasm and vacuole", "C": "cytoplasm and cell membrane", "D": "nucleus and cell membrane"}, "answer": "A", "explanation": "The living material of a cell, also known as protoplasm, consists of the nucleus and the cytoplasm. The nucleus is the control center of the cell, containing the cell's DNA, while the cytoplasm is the jelly-like substance that contains the cell's organelles. The cell membrane and vacuole, while important parts of the cell, are not considered part of the living material.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2008>4", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "Use the information below to answer this question  A pupil accidentally \"watered\" a potted plant with concentrated salt solution. After sometime the plant began to wilt.    The wilting of the plant is due to the fact that", "images": [], "options": {"A": "the root hairs die off and can no longer absorb water", "B": "the salt solution causes faster rate of transpiration leading to the death of the plant cells", "C": "the salt solution has caused water to be lost from the plant cells leading to loss of turgor", "D": "the plant tissue has been poisoned by the salt which is absorbed by the plant"}, "answer": "C", "explanation": "- The wilting of plant is due to the fact that the salt solution has caused water to be lost from the plant cells leading to loss of turgor.  - Wilting is when a plant becomes limp and flascid.  - Turgor is the pressure produced by a solution in a space that is enclosed by a differentially permeable membrane.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>5", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "Use the information below to answer this question  A pupil accidentally \"watered\" a potted plant with concentrated salt solution. After sometime the plant began to wilt.  Which of the following activities would revive the plant?", "images": [], "options": {"A": "Covering the plant with dark paper to prevent further water loss from its surfaces", "B": "Leaving the plant to adapt to the condition", "C": "Exposing the plant to high concentration of oxygen", "D": "Adding more water to the soil"}, "answer": "D", "explanation": "- Adding more water to the plant will revive the plant.  - Covering the leaf or placing it in a dark environment will prevent/inhibit photosynthesis.  - Leaving the plant to adapt to the condition might kill the plant  N:B  1. Water is essential in the process of photosynthesis.  2. Carbon dioxide is readily available in the atmosphere, this combines with water to produce organic compounds and oxygen as a by-product in the process of photosynthesis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>6", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "Primary growth in plants is brought about by the activity of the", "images": [], "options": {"A": "meristem", "B": "endodermis", "C": "epidermis", "D": "mesophyll"}, "answer": "A", "explanation": "- Primary growth in plant is brought by the activities of the meristem.  - Primary growth in a plant is the first growth of the plant and it takes place in the apical meristem.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2008>7", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Study the diagram and use it to answer this question      To form a ball and socket joint, the structure labelled I fits into another structure in the scapula called the", "images": ["Biology/imgs/2008/pix1.png"], "options": {"A": "blade", "B": "glenoid cavity", "C": "olecranon fossa", "D": "patella"}, "answer": "B", "explanation": "The glenoid cavity has a notch which the head of the humerus can fit into.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>8", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Study the diagram and use it to answer this question      The structure labelled II is called", "images": ["Biology/imgs/2008/pix1.png"], "options": {"A": "deltoid ridge", "B": "trochanter", "C": "shaft", "D": "trochlea"}, "answer": "C", "explanation": "The structure labelled II is the shaft. The shaft (or diaphysis) is the long, cylindrical, central part of a long bone. In this diagram, it represents the middle section of the bone, distinct from the ends (epiphyses) and other specific features like the deltoid ridge, trochanter, or trochlea.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>9", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following parts of the skeleton does not have a protective function?", "images": [], "options": {"A": "Ribs", "B": "Carpals", "C": "Skull", "D": "Pelvis"}, "answer": "B", "explanation": "The protective function of the skeleton is to protect the internal organs of the body. The ribs protect the heart and lungs, the skull protects the brain, and the pelvis protects the reproductive and lower digestive systems. The carpals, however, are the small bones in the wrist and do not have a protective function. They are primarily involved in providing flexibility and movement to the hand.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2008>10", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Carbon dioxide is carried in the plasma", "images": [], "options": {"A": "in combination with haemoglobin", "B": "in combination with antibodies", "C": "by capillary action", "D": "as bicarbonate ion"}, "answer": "D", "explanation": "In the blood, most carbon dioxide is present in the form of bicarbonate ions (HCO3-). Carbon dioxide from the body's cells is transported to the lungs or gills for removal from the body. It does this by diffusing into red blood cells within capillaries. Once inside the red blood cells, carbon dioxide combines with water to form carbonic acid (H2CO3), under the influence of an enzyme called carbonic anhydrase. This carbonic acid quickly dissociates to form bicarbonate ions and hydrogen ions. The bicarbonate ions diffuse out of the red blood cells into the plasma of the blood. Hence, carbon dioxide is carried in the plasma as bicarbonate ion.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2008>11", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "In the adult frog gaseous exchange takes place through the", "images": [], "options": {"A": "buccal cavity, skin and lungs", "B": "buccal cavity, skin and spiracles", "C": "gills, skin and buccal cavity", "D": "tympanic membrane, lungs and gills"}, "answer": "A", "explanation": "In adult frogs, gaseous exchange or respiration takes place through three routes: the buccal cavity, the skin, and the lungs. The buccal cavity and skin are used for respiration when the frog is in water or in a moist environment, while the lungs are used when the frog is on land. The skin of the frog is moist and thin, which makes it permeable to gases. Oxygen can diffuse directly into the blood vessels that are close to the surface of the skin. The buccal cavity also has a moist lining where gas exchange can occur. The lungs are used for respiration when the frog is active or in a dry environment. Spiracles are not present in frogs, they are openings for respiration in insects. Gills are used for respiration in the tadpole stage of the frog, not in the adult stage. The tympanic membrane in frogs is used for hearing, not for respiration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>12", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "The process of regulating the amount of water and solutes in the body fluids is called", "images": [], "options": {"A": "osmosis", "B": "diffusion", "C": "osmoregulation", "D": "homeostasis"}, "answer": "C", "explanation": "Osmoregulation is the process of maintaining the balance of water and solutes in the body fluids. It is a type of homeostasis specifically dealing with the regulation of water and electrolyte concentration in the body. Osmosis and diffusion are processes involved in osmoregulation, but they are not the regulation itself. Homeostasis is a broader term that includes all processes that maintain the body's internal environment in a stable, relatively constant state, including but not limited to osmoregulation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>13", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "The presence of glucose in the urine of a patient is an indication of malfunctioning of the", "images": [], "options": {"A": "pancreas", "B": "gall bladder", "C": "liver", "D": "spleen"}, "answer": "A", "explanation": "The presence of glucose in the urine, a condition known as glucosuria, is often a sign of diabetes mellitus. This condition is caused by a malfunctioning pancreas, which is unable to produce enough insulin to regulate blood sugar levels. Insulin is a hormone that helps cells in the body absorb glucose from the bloodstream. When there's not enough insulin, glucose can build up in the blood and eventually be excreted in the urine.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>14", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "Which of the following statements is not true about hormones?", "images": [], "options": {"A": "Hormones are manufactured in ductless glands and poured straight into the blood stream", "B": "Hormones are carried by the blood plasma to the required target organs", "C": "Hormonal responses are usually swift, instant and electrical", "D": "Once the effects of hormones are over, they are inactivated and excreted from the body"}, "answer": "C", "explanation": "Hormones are chemical messengers that are secreted directly into the blood, which carries them to organs and tissues of the body to exert their functions. They are produced by various glands in the body, including the pituitary, thyroid, and adrenal glands. However, hormonal responses are not usually swift, instant, and electrical. Instead, they are slower and longer-lasting than the responses of the nervous system. This is because hormones must travel through the bloodstream to reach their target cells, which can take some time. Once the effects of hormones are over, they are indeed inactivated and excreted from the body.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>15", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "Which of the following actions is not a function of adrenalin? It increases", "images": [], "options": {"A": "body blood sugar by conversion of liver glycogen into glucose", "B": "muscular power and resistance to fatigue", "C": "the rate of heart beat", "D": "the passage of food"}, "answer": "D", "explanation": "* The following are the functions of adrenalines  1. It increases heartbeat and respiration  2. It increases the sugar content of the blood  3. It aids dilation of the pupils  4. It increases muscular tone   5. It is responsible for shivering during cold  6. It is associated with fear and anxiety  7. It prepares the body for emergency.    Except for the passage of food", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>16", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "Plant hormones include the following except", "images": [], "options": {"A": "insulin", "B": "auxin", "C": "cytokinin", "D": "gibberellin"}, "answer": "A", "explanation": "Plant hormones, also known as phytohormones, are chemicals that regulate plant growth. Insulin is not a plant hormone, it is a hormone produced by the pancreas in animals to control blood sugar levels. Auxin, cytokinin, and gibberellin are all examples of plant hormones. Auxin is involved in cell elongation, cytokinin in cell division and gibberellin in stem elongation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>17", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "The passage of nerve impulse across a synapse is facilitated by the secretion of", "images": [], "options": {"A": "acetylcholine", "B": "thyroxine", "C": "insulin", "D": "progesterone"}, "answer": "A", "explanation": "The passage of nerve impulse across a synapse is facilitated by the secretion of a neurotransmitter called acetylcholine. A synapse is a small gap at the end of a neuron that allows a signal to pass from one neuron to the next. Acetylcholine is released into this gap to transmit the signal to the next neuron. Thyroxine, insulin, and progesterone are hormones, not neurotransmitters.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>18", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "The part of the brain which controls and coordinates body posture is the", "images": [], "options": {"A": "cerebellum", "B": "hypothalamus", "C": "medulla oblongata", "D": "pons varolii"}, "answer": "A", "explanation": "The cerebellum is a part of the brain that is responsible for motor control. It receives information from the sensory systems, the spinal cord, and other parts of the brain and then regulates motor movements. The cerebellum coordinates voluntary movements such as posture, balance, coordination, and speech, resulting in smooth and balanced muscular activity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>19", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "Which of the following processes is not an example of a reflex action?", "images": [], "options": {"A": "Blinking of the eye", "B": "Reading", "C": "Beating of the heart", "D": "Sneezing"}, "answer": "B", "explanation": "- Reading is not a reflex action.  - A reflex action is an involuntary or automatic action in response to impulses initiated stimulus.  - Reflex actions are not consciously controlled.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>20", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The eyes can properly focus images of objects of various distances on", "images": [], "options": {"A": "refraction", "B": "reflection", "C": "accommodation", "D": "correction"}, "answer": "C", "explanation": "The eyes can properly focus images of objects of various distances on the retina through a process called accommodation. Accommodation is the process by which the vertebrate eye changes optical power to maintain a clear image or focus on an object as its distance varies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>21", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "Which of the following sensations may not be detected by the skin?", "images": [], "options": {"A": "Touch", "B": "Pressure", "C": "Stress", "D": "Pain"}, "answer": "C", "explanation": "The skin is an important sense organ. In the dermis of the skin, there are different types of sensory cells or nerve endings, each of which receives one of the following stimuli - pain - heat - cold - touch - pressure.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2008>22", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The process by which flowers produce fruit without the process of fertilization is called", "images": [], "options": {"A": "viviparity", "B": "parthenocarpy", "C": "propagation", "D": "metamorphosis"}, "answer": "B", "explanation": "The process by which flowers produce fruit without the process of fertilization is called parthenocarpy. This is a natural or artificially induced process in which fruits are produced without fertilization. The resulting fruits are seedless.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>23", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The part of the young root that pushes its way through the soil is the", "images": [], "options": {"A": "root hair", "B": "tap root", "C": "root cap", "D": "lateral root"}, "answer": "C", "explanation": "The part of the young root that pushes its way through the soil is the root cap. The root cap is a type of tissue at the tip of a plant root. It serves to protect the growing tip in plants. It secretes mucilage to ease the movement of the root through soil, and may also be involved in communication with the soil microbiota.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2008>24", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "An example of a dehiscent fruit is", "images": [], "options": {"A": "crotalaria", "B": "tomato", "C": "mango", "D": "orange"}, "answer": "A", "explanation": "Dehiscent fruits are those that split along a built-in line of weakness in a valve where they dehisce (split open) to release their seeds. Crotalaria is an example of a dehiscent fruit. Tomato, mango, and orange are examples of indehiscent fruits, which do not split open to release their seeds when ripe. Hence, the correct answer is option 1.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2008>25", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Which of the following food substances gives the least amount of calories?", "images": [], "options": {"A": "Rice", "B": "Groundnuts", "C": "Cabbage", "D": "Egg yolk"}, "answer": "C", "explanation": "Calories are a measure of energy, and different foods provide different amounts of energy. Among the options provided, cabbage provides the least amount of calories. This is because cabbage is primarily made up of water and fiber, which do not provide a significant amount of energy when consumed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2008>26", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : FEEDING HABITS", "question": "Analysis of the gut content of an animal showed that it contained small pieces of bone, seeds, roughage and insects. The animal is likely to be a/an", "images": [], "options": {"A": "carnivore", "B": "herbivore", "C": "insectivore", "D": "omnivore"}, "answer": "D", "explanation": "The content of the gut include:  1. Bone   2. Seeds  3. Roughage  4. Insects  - Bones and insects are mostly found in the guts of carnivores  - Seed and roughage are usually found in the guts of herbivores  - Organisms that exhibit the feeding habit of herbivores and carnivores are called omnivores", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>27", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : MICROORGANISMS: MAN AND HIS HEALTH.", "question": "Filaments of Spirogyra placed in a beaker of tap water in a dark cupboard died because", "images": [], "options": {"A": "the filaments could not photosynthesize", "B": "conjugation could not take place", "C": "the temperature was too high", "D": "the plant was overloaded"}, "answer": "A", "explanation": "- The filaments of spirogyra placed in a beaker in a dark cupboard dies because the filaments could not photosynthesis.  - The dark environment inhibits photosynthesis in the spirogyra.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>28", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "The importance of the concentration of chloroplast in the palisade layer of the leaf is for maximum exposure to", "images": [], "options": {"A": "carbon dioxide", "B": "light", "C": "water", "D": "oxygen"}, "answer": "B", "explanation": "Chloroplasts are the site of photosynthesis in plant cells. They contain chlorophyll, the pigment that absorbs light energy. The concentration of chloroplasts in the palisade layer of the leaf is for maximum exposure to light, which is the primary energy source for photosynthesis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>29", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS", "question": "A community is best defined as", "images": [], "options": {"A": "living things in a habitat interacting with the non-living part of the environment.", "B": "the total number of individuals of one species of organisms living in a particular habitat", "C": "populations of different species living together and interacting with each other in one habitat", "D": "the individuals of a particular group living together in an area and sharing the same resources"}, "answer": "C", "explanation": "A community in ecology is defined as a group of populations of different species living together and interacting with each other in one habitat. It includes all the different species within a certain area, interacting with each other and with their physical environment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>30", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Which of the following physical factors is likely to affect the distribution of plants in a pond?", "images": [], "options": {"A": "Light", "B": "Humidity", "C": "Wind", "D": "Temperature"}, "answer": "A", "explanation": "Light affects the distribution of plants in a pond because it is necessary for photosynthesis, the process by which plants make food. In a pond, light can be a limiting factor because it decreases with depth. Therefore, plants are usually distributed according to the availability of light, with more light-requiring species near the surface and less light-requiring species in deeper parts.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2008>31", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS", "question": "Which of the following instruments is used to measure wind speed?", "images": [], "options": {"A": "Thermometer", "B": "Barometer", "C": "Hygrometer", "D": "Anemometer"}, "answer": "D", "explanation": "An anemometer is used to measure wind speed. A thermometer measures temperature, a barometer measures atmospheric pressure, and a hygrometer measures humidity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2008>32", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Study the food web below carefully and use it to answer this question      Tertiary consumers within the web are", "images": ["Biology/imgs/2008/pix2.png"], "options": {"A": "cat and lion only", "B": "man and lion only", "C": "man and cat only", "D": "man, cat and lion"}, "answer": "D", "explanation": "Given: The food web in the question; the tertiary consumers are: cat, man and lion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>33", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Study the food web below carefully and use it to answer this question      What would be the effect of taking the lion out of the web?", "images": ["Biology/imgs/2008/pix2.png"], "options": {"A": "The number of organisms at each trophic level would increase", "B": "Man would occupy the apex of the web", "C": "There would be more rabbits in the web", "D": "The energy reaching the remaining trophic levels would increase"}, "answer": "B", "explanation": "Man would occupy the apex of the web if lion is removed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>34", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "Which of the following statements about the transfer of energy in an ecosystem is correct?", "images": [], "options": {"A": "Energy increases at higher trophic levels", "B": "More organisms can be supported at higher levels", "C": "There are fewer organisms at lower trophic levels", "D": "Energy is lost at each trophic level"}, "answer": "D", "explanation": "- Energy is lost at each trophic level in an ecosystem.  - The producers is fed on by the primary consumer, the amount of energy in the producer reduces to a level, when the primary consumer is fed on by the secondary consumer, the amount of energy in the primary consumer reduces to another level.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>35", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Pond weeds normally lack thick layers of cuticle because", "images": [], "options": {"A": "their system of photosynthesis is not efficient", "B": "there is no danger of becoming desiccated", "C": "their leaves are either dissected or ribbon-shaped", "D": "there are numerous stomata on their upper epidermis"}, "answer": "B", "explanation": "Pond weeds lack a thick cuticle layer because they live in an aquatic environment where there is no danger of water loss or desiccation. The cuticle layer in plants is a waxy, water-repelling layer that prevents water loss from the plant's surface. In an aquatic environment, this is not necessary as there is an abundance of water.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2008>36", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "Shrubs do not survive on newly weathered soils because", "images": [], "options": {"A": "the top soil is shallow", "B": "drainage on such soil is poor", "C": "humus is absent from the soil", "D": "the soil tends to be sandy"}, "answer": "A", "explanation": "Newly weathered soils often have a shallow layer of topsoil, which can restrict the growth of shrubs and other plants due to limited nutrient availability and poor root development.  But typically, newly weathered soils lack mature humus or organic matter, which is crucial for nutrient availability and soil structure. This can indeed affect plant growth, but in the context of shrubs not surviving, the shallow topsoil is usually the more critical factor because it limits root penetration and nutrient access.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>37", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "The speed of the flow of water in a river is faster in the middle than along the banks due to", "images": [], "options": {"A": "differences in turbidity at different parts of the river", "B": "the abundance of fishes and other organisms along the bank", "C": "reduced force of gravity in the middle portion of the river", "D": "resistance offered by the walls of the banks"}, "answer": "D", "explanation": "The speed of the flow of water in a river is faster in the middle than along the banks due to the resistance offered by the walls of the banks. This is because the friction between the water and the river bank slows down the water flow near the banks. This concept is known as 'boundary layer' in fluid dynamics, where the velocity of fluid (in this case, water) is zero at the boundary (river bank) and increases as we move towards the center.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>38", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "The effects of environmental degradation caused by human activities can be controlled by the following measures except", "images": [], "options": {"A": "reclaiming the land", "B": "converting mining pits into fish ponds", "C": "resettling indigenous inhabitants", "D": "educating people"}, "answer": "B", "explanation": "- Converting mining pits into fish ponds promotes environmental degradation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>39", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "ECOLOGY OF POPULATION : ECOLOGICAL SUCCESSION", "question": "The following observations concerning succession are true except that the", "images": [], "options": {"A": "pioneer community has fewer species", "B": "middle stages communities are most diverse", "C": "climax community has the greatest number of species", "D": "total biomass of the community increase as succession progresses"}, "answer": "C", "explanation": "The climax community, also known as the maximum or stable community, does not have the greatest number of species. Instead, it is characterized by a stable equilibrium with a relatively constant number of species and populations, which may not necessarily be the highest in terms of species diversity compared to earlier stages of succession. The highest diversity often occurs in the intermediate stages of succession.    Note: In ecological succession, the climax community does not typically have the greatest number of species; rather, it is characterized by stability and equilibrium, while the highest species diversity is often found in the intermediate stages.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>40", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH", "question": "A vaccine is introduced into a person's body to", "images": [], "options": {"A": "destroy all disease-causing organisms in the body", "B": "stimulate the body to produce antibodies", "C": "enhance the production of red blood cells", "D": "isolate disease-causing pathogens from the blood"}, "answer": "B", "explanation": "A vaccine is a biological preparation that provides active acquired immunity to a particular infectious disease. A vaccine typically contains an agent that resembles a disease-causing microorganism and is often made from weakened or killed forms of the microbe, its toxins, or one of its surface proteins. The agent stimulates the body's immune system to recognize the agent as a threat, destroy it, and to further recognize and destroy any of the microorganisms associated with that agent that it may encounter in the future. Hence, the correct answer is 'stimulate the body to produce antibodies'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2008>41", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : ADAPTATION OF ORGANISMS TO HABITATS.", "question": "Which of the following activities constitutes biological control?", "images": [], "options": {"A": "A small bony fish transported on the back of a shark", "B": "Adding manure to crops in a garden", "C": "Tilapia feeding on the larvae and pupae of mosquito", "D": "A vulture feeding on the carcass of a goat"}, "answer": "C", "explanation": "Biological control is a method of controlling pests such as insects, mites, weeds and plant diseases using other organisms. It relies on predation, parasitism, herbivory, or other natural mechanisms, but typically also involves an active human management role. In this case, 'Tilapia feeding on the larvae and pupae of mosquito' is an example of biological control because the Tilapia (a type of fish) is being used to control the population of mosquitoes by feeding on their larvae and pupae.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>42", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH", "question": "Many diseases caused by bacteria can be treated and cured by using", "images": [], "options": {"A": "antiseptics", "B": "antibiotics", "C": "antigens", "D": "antibodies"}, "answer": "B", "explanation": "Bacterial diseases can be treated and cured using antibiotics. Antibiotics are drugs that either kill bacteria or prevent them from multiplying, thus helping the body's immune system to fight the bacterial infection.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2008>43", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "To avoid over-fishing in a lake, the following measures may be helpful except", "images": [], "options": {"A": "limiting fishing periods", "B": "regulating the size of nets", "C": "fishing throughout the year", "D": "fish breeding exercise"}, "answer": "C", "explanation": "Fishing throughout the year can lead to over-fishing as it does not allow time for the fish population to replenish. The other options like limiting fishing periods, regulating the size of nets, and fish breeding exercises are measures that can help avoid over-fishing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>44", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Conservation may be promoted by", "images": [], "options": {"A": "encouraging tree planting", "B": "systematic deforestation", "C": "overgrazing of pastures", "D": "unabated bush burning"}, "answer": "A", "explanation": "Conservation is the practice of caring for natural resources so they can sustainably support life. One of the ways to promote conservation is by encouraging tree planting. Trees help to conserve soil and water, provide habitat for wildlife, and absorb carbon dioxide from the atmosphere. Therefore, encouraging tree planting promotes conservation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>45", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "Which of the following substances is not recycled in an ecosystem?", "images": [], "options": {"A": "Carbon", "B": "Energy", "C": "Water", "D": "Nitrogen"}, "answer": "B", "explanation": "In an ecosystem, substances like carbon, water, and nitrogen are recycled through various biogeochemical cycles. However, energy is not recycled in an ecosystem. Instead, it flows through the ecosystem in one direction, from producers to consumers and decomposers. This is known as the 'one-way flow of energy'. The energy that enters the ecosystem as sunlight is used by producers (like plants) in photosynthesis to make food. Consumers (like animals) eat the producers and get energy. Finally, decomposers break down dead plants and animals, releasing the energy back into the environment as heat. Therefore, energy is not recycled in an ecosystem.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>46", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of the following statements about phenylthiocarbamide (PTC) is not correct?", "images": [], "options": {"A": "Some people find the taste of PTC to be bitter", "B": "Others find this substance to be tasteless", "C": "Ability to taste this chemical is heritable", "D": "Ability to taste the chemical is not heritable"}, "answer": "D", "explanation": "The ability to taste phenylthiocarbamide (PTC) is indeed heritable. This is a well-known example of a simple genetic trait in humans. People who find PTC to taste bitter have a dominant gene for tasting PTC, while those who find it tasteless have a recessive gene. Therefore, the statement 'Ability to taste the chemical is not heritable' is not correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>47", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Which of the following characters is not an example of discontinuous variation?", "images": [], "options": {"A": "Skin colour", "B": "Fingerprint", "C": "Ability to roll tongue", "D": "Sex type"}, "answer": "A", "explanation": "Discontinuous variation refers to the variation in characteristics that have a limited number of appearances, such as blood type or eye color. These characteristics are typically controlled by a single gene pair. Skin color, on the other hand, is an example of continuous variation, where characteristics fall into a range and are controlled by multiple gene pairs. Therefore, skin color is not an example of discontinuous variation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>48", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Which of the following human traits in a class of school children may give an approximate normal distribution curve when the variation is plotted?", "images": [], "options": {"A": "Blood groups", "B": "Ear shapes", "C": "Sex distribution", "D": "Heights"}, "answer": "D", "explanation": "A normal distribution curve is a statistical analysis that results in a bell-shaped curve. It is used to represent data that clusters around a mean or average. Height in a class of school children is likely to give an approximate normal distribution curve when the variation is plotted because height varies among individuals and tends to cluster around an average value. Other options like blood groups, ear shapes, and sex distribution are not likely to give a normal distribution as they are discrete variables.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>49", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "The observable characteristic of an individual usually resulting from the interaction between the gene composition and the environment is referred to as", "images": [], "options": {"A": "allele", "B": "genotype", "C": "phenotype", "D": "chromosome"}, "answer": "C", "explanation": "The observable characteristic of an individual, usually resulting from the interaction between the gene composition and the environment, is referred to as the phenotype. The phenotype is the physical expression, or characteristics, of that individual. It is influenced by both the individual's genotype, which is the set of genes an individual carries, and by the environment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>50", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "The sudden change in a gene structure or chromosome number in an organism likely to cause an inheritable change in the phenotype is known as", "images": [], "options": {"A": "migration", "B": "mutation", "C": "mitosis", "D": "meiosis"}, "answer": "B", "explanation": "This is the definition of 'mutation'   - Mutation is the sudden change in a gene structure or chromosome number in an organism and its likely to cause an inheritable change in the phenotype.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2008>51", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "The defective cells involved in sickle-cell anaemia disease are", "images": [], "options": {"A": "phagocytes", "B": "lymphocytes", "C": "erythrocytes", "D": "thrombocytes"}, "answer": "C", "explanation": "Sickle-cell anaemia is a genetic disease that affects the erythrocytes, or red blood cells. In this disease, the red blood cells become rigid and sticky, and are shaped like sickles or crescent moons. These irregularly shaped cells can get stuck in small blood vessels, which can slow or block blood flow and oxygen to parts of the body.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>52", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "What does the chemical composition of the genetic material of all living organisms consist of?", "images": [], "options": {"A": "Deoxyribonucleic acid", "B": "Adenosine diphosphate", "C": "Adenosine triphosphate", "D": "Follicle stimulating hormone"}, "answer": "A", "explanation": "The genetic material of all living organisms consists of Deoxyribonucleic acid (DNA). DNA is a molecule composed of two chains that coil around each other to form a double helix carrying genetic instructions for the development, functioning, growth and reproduction of all known organisms and many viruses. DNA and RNA are nucleic acids; alongside proteins, lipids and complex carbohydrates (polysaccharides), nucleic acids are one of the four major types of macromolecules that are essential for all known forms of life.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>53", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "Which of the following occurrences  is not a feature of meiosis", "images": [], "options": {"A": "Formation of four haploid cells", "B": "Two successive nuclear cell divisions", "C": "Pairing of homologous chromosomes at prophase", "D": "Formation of two diploid cells"}, "answer": "D", "explanation": "Meiosis is a type of cell division that reduces the number of chromosomes in the parent cell by half and produces four gamete cells. This process is required to produce egg and sperm cells for sexual reproduction. During meiosis, diploid cells undergo two cell divisions to produce haploid cells. Therefore, the formation of two diploid cells is not a feature of meiosis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>54", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : LINKAGE, SEX DETERMINATION AND SEX LINKED CHARACTERS", "question": "Which of the following diseases is commonly observed in human males and is sex-linked?", "images": [], "options": {"A": "Beriberi", "B": "Down's syndrome", "C": "Sickle-cell anaemia", "D": "Colour blindness"}, "answer": "D", "explanation": "Colour blindness is a sex-linked disease. Sex-linked diseases are diseases that are determined by genes found on sex chromosomes. In humans, the genes for color blindness are located on the X chromosome. Since males have only one X chromosome, they are more likely to have color blindness than females, who have two X chromosomes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>55", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "If red is dominant to white and homozygous red pea-plants are crossed with homozygous white pea-plants, the first filial generation will have", "images": [], "options": {"A": "2 red flowers, 2 white flowers", "B": "4 red flowers", "C": "4 white flowers", "D": "4 pink flowers"}, "answer": "B", "explanation": "- Let the white pea plants be rr  - Let the red pea plants be RR  Given: Red is dominant to while      Since red is dominant to white, the offspring in the first filial generation are all red.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>56", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The resemblance of a palatable insect to a poisonous insect is an example of", "images": [], "options": {"A": "a chemical deterrent to a predator", "B": "an escape from the predator by camouflage", "C": "an escape from the predator by mimicry", "D": "a defence against the predator by warning colouration"}, "answer": "C", "explanation": "The resemblance of a palatable insect to a poisonous insect is an example of mimicry. Mimicry is a survival strategy where an organism, in this case a palatable insect, resembles another organism, a poisonous insect, in order to deceive predators into thinking it is harmful. This helps the palatable insect to avoid being eaten by predators.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>57", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following statements is not true of the worker termites? They", "images": [], "options": {"A": "build and repair the nest", "B": "produce enzymes to digest cellulose", "C": "search for food to feed the colony", "D": "look after the nymph"}, "answer": "B", "explanation": "The worker termites do not help to digest cellulose, the only cultivate fungus garden, this is to digest the wood on which it grows to a state the termite can use.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2008>58", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Which of the following occurrences cannot be taken as a direct observation of Natural Selection in recent times?", "images": [], "options": {"A": "Industrial melanism in moths", "B": "Selective breeding in cattle", "C": "Insecticide resistance of some mosquitoes", "D": "Development of long necks in giraffes"}, "answer": "B", "explanation": "Selective breeding in cattle is not a direct observation of Natural Selection. Natural Selection is a process where organisms that are better adapted to their environment tend to survive and produce more offspring. This process is natural and not influenced by human intervention. On the other hand, selective breeding is a process where humans intentionally breed animals with desirable traits to produce offspring with those traits. This is a form of artificial selection, not natural selection.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>59", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "The accepted concepts for the theory of Natural Selection does not include", "images": [], "options": {"A": "tendency for organisms to overproduce", "B": "struggle for existence", "C": "survival of the fittest", "D": "use and disuse of body parts"}, "answer": "D", "explanation": "The concept of 'use and disuse of body parts' is not included in the theory of Natural Selection. This concept is actually part of Lamarck's theory of evolution, which suggests that an organism can change during its lifetime in response to its environment, and those changes are then passed onto its offspring. However, this theory has been largely discredited in favor of Darwin's theory of Natural Selection, which states that genetic changes occur randomly, and those that benefit the organism are more likely to be passed on to the next generation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2008>60", "subject": "Biology", "year": "2008", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "The order of evolutionary trend in plants is", "images": [], "options": {"A": "Bryophyta, Thallophyta,  Pteridophyta and Spermatophyta", "B": "Thallophyta, Bryophyta, Pteridophyta and Spermatophyta", "C": "Spermatophyta, Pteridophyta, Bryophyta and Thallophyta", "D": "Bryophyta, Pteridophyta, Spermatophyta and Thallophyta"}, "answer": "B", "explanation": "The correct order of evolutionary trend in plants is Thallophyta, Bryophyta, Pteridophyta and Spermatophyta. Thallophyta are the most primitive plants, followed by Bryophyta (mosses and liverworts), Pteridophyta (ferns and their relatives), and finally Spermatophyta (seed plants), which are the most advanced.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>1", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "A group of closely related organism capable of interbreeding to produce fertile offspring are known as members of  a", "images": [], "options": {"A": "kingdom", "B": "class", "C": "family", "D": "species"}, "answer": "D", "explanation": "A group of closely related organisms capable of interbreeding to produce fertile offspring are known as members of a species. This is the basic unit of biological classification and a taxonomic rank. A species is often defined as the largest group of organisms in which any two individuals of the appropriate sexes or mating types can produce fertile offspring, typically by sexual reproduction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>2", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION", "question": "Viruses are economically important because they", "images": [], "options": {"A": "do not have cell structures", "B": "can only reproduce inside living cells", "C": "cause disease in plants and animals", "D": "exist as crystals outside living cells"}, "answer": "C", "explanation": "Viruses are economically important because they cause diseases in plants and animals. This can lead to significant economic losses in agriculture and livestock industries. Viruses are infectious agents that can only reproduce inside living cells, and they can cause a wide range of diseases. For example, the Tobacco mosaic virus can cause significant damage to tobacco crops, and the Avian influenza virus can cause severe disease in poultry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>3", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION", "question": "A beaker of pond water containing few specimens of Euglena was placed in a dark room for two weeks. At the end of this period, the specimens of Euglena were still alive because they were", "images": [], "options": {"A": "able to carry out holozoic nutrition", "B": "able to carry out photosynthesis using carbon dioxide in the pond water", "C": "better adapted in life in darkness than to life in light", "D": "not overcrowded"}, "answer": "A", "explanation": "-  Euglena viridis  is a protist that exhibits both animal-like and plant-like characteristics   - It can carryout photosythesis and also, it can feed holozocally.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>4", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The cytoplasm of the cell is considered a very important component because it", "images": [], "options": {"A": "regulates the amount of energy in the cell", "B": "suspends all cell organelles", "C": "is the outermost part of the cell", "D": "is solely responsible for cell division"}, "answer": "B", "explanation": "The cytoplasm is a jelly-like substance where all the organelles of a cell are suspended. It fills each cell and is enclosed by the cell membrane. It plays a crucial role in a cell's survival; it is where many metabolic reactions occur. It does not regulate the amount of energy in the cell, it is not the outermost part of the cell, and it is not solely responsible for cell division.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>5", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "Use the diagram below to answer this question.      After an hour, the level of water in the thistle funnel will", "images": ["Biology/imgs/2009/94KTJA.jpg"], "options": {"A": "rise", "B": "fall", "C": "remain the same", "D": "double"}, "answer": "A", "explanation": "This is because water will move from the area of lower solute concentration (distilled water) outside the funnel into the area of higher solute concentration (sugar solution) inside the funnel through the selectively permeable membrane, resulting in a rise in the water level in the thistle funnel.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>6", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "Use the diagram below to answer this question.    The experiment above is used to demonstrate the process of", "images": ["Biology/imgs/2009/94KTJA.jpg"], "options": {"A": "transpiration", "B": "water culture", "C": "diffusion", "D": "osmosis"}, "answer": "D", "explanation": "Osmosis is the movement of water molecules through a selectively permeable membrane from an area of lower solute concentration (distilled water) to an area of higher solute concentration (sugar solution). In this experiment, the membrane tied over the funnel acts as the selectively permeable membrane, allowing water to move into the sugar solution, thereby demonstrating osmosis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>7", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Use the diagram below to answer this question.    In plant cells the role of the membrane is played by the", "images": ["Biology/imgs/2009/94KTJA.jpg"], "options": {"A": "nucleolus", "B": "cell wall", "C": "cytoplasm", "D": "mitochondrion"}, "answer": "B", "explanation": "The cell wall provides structural support and protection, acting as a semi-permeable membrane that regulates the movement of substances in and out of the cell. However, it's important to note that the actual selective permeability function in plant cells is performed by the plasma membrane (cell membrane), which is located just inside the cell wall. The cell wall provides additional rigidity and support.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>8", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "Red blood cells were found to have burst open after being placed in distilled water for an hour. This phenomenon is known as", "images": [], "options": {"A": "plasmolysis", "B": "diffusion", "C": "haemolysis", "D": "wilting"}, "answer": "C", "explanation": "- The red blood cell burst due to haemolysis  - Haemolysis is when an animal cell e.g red blood cell is placed in a hypotonic solution which makes it to swell and may also burst because it does not have a cell wall.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>9", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "The overall reaction in glycolysis can be summarized as", "images": [], "options": {"A": "C6H12O6 → C3H4O3 + 4H + ATP", "B": "C6H12O6 → 2C3H4O3 + 4H + 2ATP", "C": "C6H12O6 → 2C3H4O3 + 4H + ADP", "D": "C6H12O6 → 2C3H4O3 + 4H + 2ADP"}, "answer": "B", "explanation": "Glycolysis is the metabolic pathway that converts glucose C6H12O6, into pyruvate, CH3COCOO−, and a hydrogen ion, H+. The free energy released in this process is used to form the high-energy molecules ATP (adenosine triphosphate) and NADH (reduced nicotinamide adenine dinucleotide). The overall reaction of glycolysis is: Glucose + 2 NAD+ + 2 ADP + 2 Pi → 2 pyruvate + 2 NADH + 2 ATP + 2 H+ + 2 H2O + heat. However, the given options do not include NADH, so the closest correct answer is option 2, which correctly represents the conversion of glucose into two molecules of pyruvate, the production of 4 hydrogen ions, and the generation of 2 ATP.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2009>10", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : IRRITABILITY AS A BASIC CHARACTERISTIC OF PROTOPLASM", "question": "The curvature movement of plants in response to the stimulus of water is called", "images": [], "options": {"A": "hydrotropism", "B": "geotropism", "C": "phototropism", "D": "thigmotropism"}, "answer": "A", "explanation": "Hydrotropism is the growth of a plant towards or away from water. The roots of a plant grow towards a water sources and thus show positive hydrotropism.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>11", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Two organelles directly involved in mitotic cell division are", "images": [], "options": {"A": "nucleus and mitochondrion", "B": "ribosome and nucleus", "C": "centriole and golgi apparatus", "D": "nucleus and centriole"}, "answer": "D", "explanation": "Mitotic cell division involves the replication of a cell's DNA (which is stored in the nucleus) and the separation of this DNA into two identical sets. The centrioles play a crucial role in this process by forming the spindle fibers that help separate the chromosomes. Therefore, the nucleus and the centriole are the two organelles directly involved in mitotic cell division.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>12", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The following statements about mitotic cell division are correct except that", "images": [], "options": {"A": "it occurs only in young cells", "B": "it occurs in somatic cells", "C": "the chromosome number of the daughter cell is the same as that of the parent", "D": "the genetic composition of the mother cell is the same as that of the daughter cell"}, "answer": "A", "explanation": "- Mitotic cell division occurs both in young cells and old cells  - It occurs in somatic cells i.e cells that those not involve reproduction (germ cell)  - The parent chromosome number is the same to that of the parent  - There is not always variation among the organism", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>13", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The longest bone in the body is the", "images": [], "options": {"A": "humerus", "B": "femur", "C": "scapula", "D": "tibia"}, "answer": "B", "explanation": "The femur, or thighbone, is the longest, largest, and strongest bone in the human body. All of the body's weight is supported by the femurs during many activities, such as running, jumping, walking, and standing. Hence, the correct answer is femur.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2009>14", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following structures is not a skeletal materials?", "images": [], "options": {"A": "Chitin", "B": "Cartilage", "C": "Bone", "D": "Muscle"}, "answer": "D", "explanation": "Muscle is not a skeletal material. Skeletal materials are materials that make up the skeleton, or the structural framework of an organism. This includes bones, cartilage, and chitin (in some invertebrates). Muscles, on the other hand, are soft tissues that produce force and motion.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2009>15", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "The reason why the flow of blood through the capillaries is very slow is", "images": [], "options": {"A": "because the walls of capillaries are very thin", "B": "to avoid high blood pressure", "C": "to ensure that the individual does not get dizzy", "D": "to allow adequate time for exchange of materials"}, "answer": "D", "explanation": "The flow of blood through the capillaries is very slow to allow adequate time for exchange of materials. Capillaries are the smallest blood vessels where the exchange of oxygen, carbon dioxide, nutrients, and waste materials occurs between the blood and the body's cells. The slow flow of blood in capillaries allows for this exchange to take place effectively.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>16", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "Which of the following features is not characteristic of arteries? Arteries", "images": [], "options": {"A": "possess valves at intervals throughout their length", "B": "have thick, muscular and elastic walls", "C": "carry blood away from the heart", "D": "transport oxygenated blood with the exception of the pulmonary artery"}, "answer": "A", "explanation": "Arteries do not possess valves at intervals throughout their length. This is a characteristic of veins, not arteries. Arteries are designed to carry blood away from the heart under high pressure, and their structure reflects this - they have thick, muscular and elastic walls to withstand this pressure. The presence of valves is not necessary in arteries because the pressure of the blood flowing from the heart is sufficient to prevent backflow.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>17", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "A group of rats placed in an air-tight box for some hours died because they", "images": [], "options": {"A": "breathed in air containing nitrogen", "B": "produced carbon dioxide", "C": "ran short of energy", "D": "used up the available oxygen"}, "answer": "D", "explanation": "Rats, like all mammals, require oxygen to survive. They breathe in oxygen and breathe out carbon dioxide, a process known as respiration. In an air-tight box, the available oxygen would eventually be used up, and the rats would die from lack of oxygen, not from the presence of carbon dioxide or nitrogen, or from running out of energy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>18", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which of the following organism have kidney as their excretory organ?", "images": [], "options": {"A": "Fishes, amphibians, birds, man", "B": "Fishes, amphibians, annelids, insects", "C": "Fishes, reptiles, birds, tape worms", "D": "Fishes, protozoans, amphibians, man"}, "answer": "A", "explanation": "The kidney is an excretory organ found in many higher-level organisms, including fishes, amphibians, birds, and humans. It helps in the removal of waste products from the body, particularly the by-products of metabolism. Other organisms like annelids, insects, tape worms, and protozoans have different excretory systems.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2009>19", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "The graph below shows the results of a laboratory investigation which measured the body temperatures of a lizard and a bird under changing artificial conditions.    Use it to answer this question    Which of the statements below is valid?", "images": ["Biology/imgs/2009/24FB4N.png"], "options": {"A": "The bird's blood was always warmer than that of the lizard", "B": "The body temperature of the bird varied less than that of the lizard during changes in environmental temperature", "C": "The body temperature of the bird remained constant despite changes in environmental temperature", "D": "The body temperature of the lizard was always close to that of the environmental temperature"}, "answer": "C", "explanation": "From the graph of the body temperature of lizard and a bird under artificial condition. It can deduce that  * Lizard  - It is a poikiothermic organism  - It body temperature varies with the temperature of the environment  - The lizard need to change with respects to the environment temperature so that it can survive.    * Bird  - It is an homothermic organism  - It body temperature is always constant with respect to the environment   - The environment temperature those not affect the temperature of the body of the bird.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2009>20", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "The graph below shows the results of a laboratory investigation which measured the body temperatures of a lizard and a bird under changing artificial conditions.    Use it to answer this question  What physiological term can be used to describe the regulation of the body temperature of the lizard?", "images": ["Biology/imgs/2009/24FB4N.png"], "options": {"A": "Homeostasis", "B": "Homoiothermic", "C": "Poikilothermic", "D": "Osmoregulation"}, "answer": "C", "explanation": "Poikilothermy is the acts by which the body of living organisms varies with that of the environment. The organism temperature changes with a slight change in that of the environment, in other to survive.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>21", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "The reason why hospitals use saline solutions as drip instead of water is", "images": [], "options": {"A": "because salt is a preservative", "B": "to prevent contamination of the body", "C": "to maintain the composition of body fluids", "D": "to increase the number of blood cells"}, "answer": "C", "explanation": "Saline solutions are used in hospitals as drips instead of water to maintain the composition of body fluids. The human body has a certain concentration of salt in its fluids, including blood. If pure water were used, it could cause a condition called water intoxication or hyponatremia, where the balance of electrolytes in the body is disrupted. Saline solution, which is water with 0.9% salt, closely matches the natural salt concentration in the body, helping to maintain the right balance of electrolytes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2009>22", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The part of the ear which contains nerve cells sensitive to sound vibrations is the", "images": [], "options": {"A": "cochlea", "B": "ampulla", "C": "tympanum", "D": "malleus"}, "answer": "A", "explanation": "The cochlea is the part of the ear that contains nerve cells sensitive to sound vibrations. It is a spiral-shaped cavity in the inner ear that produces nerve impulses in response to sound vibrations. The cochlea is filled with a fluid that moves in response to the vibrations coming from the middle ear via the oval window. As the fluid moves, thousands of 'hair cells' are set in motion, and they in turn produce electrical signals that are sent to the brain via the auditory nerve.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2009>23", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "Spectacles with convex lenses correct long-sightedness by", "images": [], "options": {"A": "converging the light rays before they enter the eye", "B": "diverging the light rays before they enter the eye", "C": "reducing light intensity before it enters the eye", "D": "increasing light intensity before it enters the eye"}, "answer": "A", "explanation": "Long-sightedness, also known as hypermetropia, is a common eye condition where nearby objects appear blurry, while far objects can be seen clearly. This condition occurs when the light that enters the eye does not focus on the retina but behind it. Convex lenses correct this by converging the light rays before they enter the eye, ensuring that the light focuses on the retina.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2009>24", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "A seed of a flowering plant can best be described as", "images": [], "options": {"A": "radicle and plumule", "B": "the developed ovule", "C": "the embryo and endosperm", "D": "developed ovary"}, "answer": "B", "explanation": "A seed in a flowering plant is essentially a mature ovule following fertilization. It contains an embryo (which develops into a new plant) and is enclosed in a protective seed coat. The ovule, after fertilization, develops into a seed. Therefore, a seed can best be described as the developed ovule.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2009>25", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "Which of the following processes removes carbon from the atmosphere?", "images": [], "options": {"A": "Putrefaction", "B": "Photosynthesis", "C": "Volcanic eruption", "D": "Burning of fuels"}, "answer": "B", "explanation": "Photosynthesis is the process by which green plants and some other organisms use sunlight to synthesize foods with the help of chlorophyll pigments. During this process, plants absorb carbon dioxide from the atmosphere and release oxygen. Therefore, photosynthesis removes carbon from the atmosphere.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2009>26", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "Which of the following cycles involves the process of precipitations and transpiration?", "images": [], "options": {"A": "Water cycle", "B": "Carbon cycle", "C": "Nitrogen cycle", "D": "Oxygen cycle"}, "answer": "A", "explanation": "- Water cycle involves the process of precipitation and transpiration.  * Transpiration is the loss of water vapour from the aerial part of a plant especially through the stomata of the leaves.  * Precipitate is the process through which water vapour in the atmosphere condenses and drops in form of water droplets.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2009>27", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "The mesophyll layer of a leaf consists of", "images": [], "options": {"A": "wax and cutin", "B": "cells with lignified walls", "C": "irregularly shaped collenchyma cells", "D": "photosynthetic parenchyma cells"}, "answer": "D", "explanation": "The mesophyll layer of a leaf is made up of photosynthetic parenchyma cells. These cells contain chloroplasts, which are the sites of photosynthesis. The mesophyll layer is typically divided into two regions: the palisade parenchyma, which is directly beneath the upper epidermis and absorbs a major portion of the light energy used by the leaf; and the spongy parenchyma, which are more loosely arranged and allow for the interchange of gases (CO2 and O2) that are needed for photosynthesis.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2009>28", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Which of the following treatments would increase the rate of transpiration in a potted plant?", "images": [], "options": {"A": "Placing it in a cold room", "B": "Placing it under a fan in a room", "C": "Putting it in a cupboard", "D": "Smearing grease on the lower surface of the leaves"}, "answer": "B", "explanation": "\"Strong wind\" is one of the factors that affect the rate of transpiration. The stronger the wind, the higher the rate of transpiration and vice-versa.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2009>29", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Pepsin is secreted as an inactive precursor called pepsinogen because", "images": [], "options": {"A": "pepsin as an enzyme is quickly destroyed by the alkaline food from the mouth", "B": "all digestive enzymes pass through a precursor stage", "C": "pepsin is a  proteolytic  enzyme and might attack the stomach tissues", "D": "pepsin is not required in large quantities"}, "answer": "C", "explanation": "Pepsin is secreted as an inactive precursor called pepsinogen because it is a proteolytic enzyme and might attack the stomach tissues. A proteolytic enzyme is an enzyme that performs proteolysis, protein catabolism by hydrolysis of peptide bonds. If pepsin was not secreted in an inactive form, it could digest the cells that produce it, which would be harmful to the organism.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>30", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION", "question": "An organism whose source of carbon is inorganic is likely to be a/an", "images": [], "options": {"A": "heterotrophic organism", "B": "autotrophic organism", "C": "symbiotic organism", "D": "parasitic organism"}, "answer": "B", "explanation": "An organism whose source of carbon is inorganic is likely to be an autotrophic organism. Autotrophs are organisms that can produce their own food from the substances available in their surroundings using light (photosynthesis) or chemical energy (chemosynthesis). They use inorganic carbon sources like carbon dioxide to create organic compounds for their own energy needs.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2009>31", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : CARRIERS OF MICROORGANISMS", "question": "Which of the following organisms is an endoparasite?", "images": [], "options": {"A": "Mice", "B": "Mosquito", "C": "Ascaris", "D": "Dodder"}, "answer": "C", "explanation": "An endoparasite is a parasite that lives inside the body of its host. Ascaris is a type of roundworm that lives in the intestines of its host, making it an endoparasite. Mice and Mosquitoes are not parasites, and Dodder is a type of parasitic plant, but it is an ectoparasite, not an endoparasite.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2009>32", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "Which of the following statements about ecosystems is false?", "images": [], "options": {"A": "All the energy entering the ecosystem is passed on to decomposers", "B": "The primary producers provide energy for herbivores and carnivores", "C": "Ecosystems must start with the capture of energy by autotrophs", "D": "Energy transfer from one trophic level to the other is not 100% efficient"}, "answer": "A", "explanation": "The statement 'All the energy entering the ecosystem is passed on to decomposers' is false. In an ecosystem, energy is transferred from one trophic level to the next, with a significant amount of energy being lost as heat at each level. Not all energy is passed on to decomposers. The other statements are true: primary producers (plants) do provide energy for herbivores and carnivores, ecosystems do start with the capture of energy by autotrophs (plants), and energy transfer from one trophic level to the other is not 100% efficient due to energy loss as heat.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>33", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "What is the critical limiting factor for plants below the photic zone in an aquatic ecosystem?", "images": [], "options": {"A": "Availability of nutrients", "B": "Availability of water", "C": "Intensity of light", "D": "Carbon dioxide concentration"}, "answer": "C", "explanation": "The photic zone in an aquatic ecosystem is the upper layer of water that receives enough sunlight for photosynthesis to occur. Below this zone, the intensity of light decreases significantly, making it the critical limiting factor for plants. Without sufficient light, plants cannot perform photosynthesis effectively.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>34", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING", "question": "Which of the following instruments is used to estimate the number of plants in a habitat?", "images": [], "options": {"A": "Pooter", "B": "Pitfall trap", "C": "Quadrat", "D": "Sweep net"}, "answer": "C", "explanation": "- Quadrat is used to estimate the number of plants in a habitat.  - A Quadrat is a plastic metal or wooden portable frame that is placed on an area under study, it is best used for studying plants or stationary species.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2009>35", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "Which of the following statement is true about sandy soil? It", "images": [], "options": {"A": "has limited air space", "B": "is light and easy to dig", "C": "drains slowly", "D": "is heavy and poorly aerated"}, "answer": "B", "explanation": "Sandy soil is light and easy to dig. This is because it has larger particles which create large air spaces that make it easy to work with. The large air spaces also allow water to drain quickly, which is contrary to option 3 that suggests it drains slowly. It is not heavy and poorly aerated as suggested in option 4, and it does not have limited air space as suggested in option 1.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2009>36", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Which of the following organisms is a primary consumer?", "images": [], "options": {"A": "Dog", "B": "Sheep", "C": "Grass", "D": "Fungus"}, "answer": "B", "explanation": "A primary consumer is an organism that eats producers. Producers are organisms that produce their own food through photosynthesis, such as plants. In this case, the sheep, which eats grass (a producer), is a primary consumer. Dogs are typically secondary or tertiary consumers as they eat other animals, fungi decompose organic matter and are decomposers, and grass is a producer, not a consumer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2009>37", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "Study the diagram of a food chain shown below and use it to answer this question  P → Q → R → S → T    The organism designated P in the food chain above is normally sustained by energy from", "images": [], "options": {"A": "sunlight", "B": "carbohydrates", "C": "green plants", "D": "mineral"}, "answer": "A", "explanation": "In a food chain, the first organism, also known as the producer, is usually a plant that gets its energy from the sun through the process of photosynthesis. Therefore, organism P, being the first in the chain, is sustained by energy from sunlight.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>38", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Study the diagram of a food chain shown below and use it to answer this question  P → Q → R → S → T  Which of the following statements best describes the organism designated R? It", "images": [], "options": {"A": "feeds on S", "B": "is a primary consumer", "C": "is a producer as well as a consumer", "D": "is a secondary consumer"}, "answer": "D", "explanation": "In a food chain, the organisms are classified based on their feeding habits. The first organism (P) is the producer, the second organism (Q) is the primary consumer, and the third organism (R) is the secondary consumer. Therefore, organism R is a secondary consumer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>39", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "Food chains are relatively short because", "images": [], "options": {"A": "of energy recycling in the ecosystem", "B": "energy gain at each trophic level is high", "C": "of energy loss at each trophic level", "D": "energy flow in an ecosystem is uni-directional"}, "answer": "C", "explanation": "Food chains are relatively short because of energy loss at each trophic level. In an ecosystem, energy flows from one trophic level to the next. However, at each trophic level, a significant amount of energy is lost, primarily as heat. This is in accordance with the second law of thermodynamics, which states that whenever energy is transferred or transformed, a significant portion is lost as heat. As a result, the amount of energy available to the next trophic level is reduced, limiting the length of the food chain.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>40", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "EVOLUTION : ADAPTIVE COLOURATION", "question": "Which of the following organisms does not show colour adaptation to its environment?", "images": [], "options": {"A": "Chameleon", "B": "Earthworm", "C": "Fish", "D": "Toad"}, "answer": "B", "explanation": "Earthworms do not show colour adaptation to their environment. Colour adaptation is a survival strategy used by many organisms to blend in with their environment and avoid predators. This is achieved by changing their skin colour to match the surrounding environment. Chameleons, fish, and toads are known to exhibit this behaviour. However, earthworms, which live underground, do not have this ability. Their colour is generally consistent and does not change in response to their environment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2009>41", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Most tropical plants shed their leaves during dry weather conditions in order to", "images": [], "options": {"A": "reduce their growth rate", "B": "conserve water", "C": "reduce competition", "D": "minimise the rate of photosynthesis"}, "answer": "B", "explanation": "Tropical plants shed their leaves during dry weather conditions to conserve water. This is because water is lost from the plant mainly through the leaves in a process called transpiration. By shedding their leaves, plants reduce the surface area available for transpiration, thus conserving water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>42", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following features is not an adaptation of plants to aquatic habitat?", "images": [], "options": {"A": "Breathing roots for entry of air", "B": "Flowers raised above water for the purpose of pollination", "C": "Spongy tissues containing gases for buoyance", "D": "Hairy structures on the leaves to reduce water loss"}, "answer": "D", "explanation": "Hairy structures on the leaves to reduce water loss is not an adaptation of plants to aquatic habitat. This is an adaptation of plants to arid or dry habitats. In aquatic habitats, water is abundant and there is no need for plants to develop adaptations to reduce water loss.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>43", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "ECOLOGY OF POPULATION : ECOLOGICAL SUCCESSION", "question": "The following habitats can be used in the study of succession except", "images": [], "options": {"A": "savanna grassland", "B": "abandoned farmland", "C": "a pond", "D": "a well cultivated land"}, "answer": "D", "explanation": "A well cultivated land cannot be used in the study of succession, as succession involves the systematic changes that take place in an area of land (usually a fallowed land or a land where there was never cultivation).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>44", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION", "question": "Population growth rate may be defined as the", "images": [], "options": {"A": "mortality rate per unit area over a period", "B": "number of times an organism occurs within a given period", "C": "number of a particular species per unit area", "D": "net rate of natality and mortality in the habitat over a period"}, "answer": "D", "explanation": "Population growth rate is defined as the net rate of natality (births) and mortality (deaths) in the habitat over a period. It is a measure of how the population of a species changes over time in a particular habitat. It takes into account both the births and deaths in the population. The other options do not accurately define population growth rate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>45", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "ECOLOGY OF POPULATION : ECOLOGICAL SUCCESSION", "question": "In ecological succession, since lichens grow on bare rock, they are considered to be", "images": [], "options": {"A": "primary consumers", "B": "pioneer organisms", "C": "climax organism", "D": "producers"}, "answer": "B", "explanation": "In ecological succession, lichens are considered to be pioneer organisms. This is because they are the first to colonize previously disrupted or damaged ecosystems, beginning a chain of ecological succession that ultimately leads to a more biodiverse steady-state ecosystem. They are able to survive in harsh conditions where other organisms can't, and they help to break down rocks into soil that other plants can use.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>46", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION", "question": "Which of the following factors will most likely lead to overcrowding within a population?", "images": [], "options": {"A": "Absence of predators", "B": "Emigration", "C": "Food shortage", "D": "Absence of territorial behaviour"}, "answer": "A", "explanation": "The absence of predators will most likely lead to overcrowding within a population. This is because predators help control the population of certain species. If there are no predators, the population of their prey can increase rapidly, leading to overcrowding. Emigration, food shortage, and territorial behavior are factors that can reduce overcrowding.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>47", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "A species whose population has become extinct if not protected is a/an", "images": [], "options": {"A": "special species", "B": "dangerous species", "C": "endangered species", "D": "important species"}, "answer": "C", "explanation": "An endangered species is a species of wild animal or plant that is in danger of extinction throughout all or a significant portion of its range. This is due to factors such as habitat loss, pollution, or predation. The term 'endangered species' is often used in conservation biology, a field of biology that focuses on the study and conservation of biodiversity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>48", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Which of the following practices does not contribute to the preservation and improvement of the environment?", "images": [], "options": {"A": "Pollution reduction", "B": "Material recycling", "C": "Reafforestation", "D": "Overgrazing"}, "answer": "D", "explanation": "Overgrazing is the practice of grazing too many livestock for too long on land, which can damage the land's usefulness. It does not contribute to the preservation and improvement of the environment, but rather it leads to land degradation and desertification. On the other hand, practices like pollution reduction, material recycling, and reafforestation contribute positively to the environment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>49", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Variation is important in human life and can be used for the following activities except", "images": [], "options": {"A": "crime detection", "B": "population distribution", "C": "blood transfusion", "D": "determination of paternity"}, "answer": "B", "explanation": "Variation refers to the differences in physical traits among individuals within a population. It is important in many aspects of human life such as crime detection (through DNA fingerprinting), blood transfusion (through blood grouping), and determination of paternity (through genetic testing). However, it does not directly influence population distribution, which is determined by factors such as birth rates, death rates, immigration, and emigration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>50", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "An example of continuous variation is", "images": [], "options": {"A": "fingerprint", "B": "tongue rolling", "C": "blood grouping", "D": "body size"}, "answer": "D", "explanation": "Continuous variation refers to a range of small differences in a shared trait among individuals within a population. Body size is an example of continuous variation because it can take on any value within a range, and is influenced by both genetic and environmental factors. Fingerprint, tongue rolling, and blood grouping are examples of discontinuous variation, where individuals fall into a few distinct classes or categories.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2009>51", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "The outward appearance of an organism is referred to as", "images": [], "options": {"A": "phenotype", "B": "genotype", "C": "dominance", "D": "recessiveness"}, "answer": "A", "explanation": "The outward appearance of an organism is referred to as its phenotype. This is the physical expression of an organism's genes, including its appearance, development, and behavior. The genotype, on the other hand, refers to the genetic makeup of an organism, or the set of genes it carries. Dominance and recessiveness are terms used to describe the expression of different versions (alleles) of a particular gene in an organism's phenotype.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2009>52", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "The allele responsible for sickle-cell anemia first appeared in the tropical and subtropical regions of Asia, the Middle East and Africa. It entered the United State of America when individuals'were forcibly brought over from Africa. In micro-evolutionary terms, this is an example of", "images": [], "options": {"A": "mutation", "B": "gene flow", "C": "genetic drift", "D": "natural selection"}, "answer": "B", "explanation": "'Gene flow' refers to the movement of genes from one population of organisms to another. This results when individuals from two populations interbreed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>53", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "Which of the following disease is not hereditary?", "images": [], "options": {"A": "Albinism", "B": "Scabies", "C": "Haemophilia", "D": "Colour blindness"}, "answer": "B", "explanation": "Scabies is not a hereditary disease. It is a contagious skin condition caused by a tiny burrowing mite. The other options, Albinism, Haemophilia, and Colour blindness, are all hereditary diseases. Hereditary diseases are disorders that are inherited genetically. They are determined by the combination of genes for a particular trait that are on the chromosomes received from the father and the mother.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2009>54", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The immediate product of meiosis in flowering plants is the", "images": [], "options": {"A": "sporophyte", "B": "gametophyte", "C": "zygote", "D": "pollen grain"}, "answer": "D", "explanation": "The immediate product of meiosis in flowering plants is the pollen grains", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2009>55", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "DNA in eukaryotic cells contained in the", "images": [], "options": {"A": "central vacuole", "B": "nucleus", "C": "lysosome", "D": "Golgi body"}, "answer": "B", "explanation": "DNA in eukaryotic cells is contained in the nucleus. The nucleus is a double-membraned cell organelle that contains the cell's genetic material (DNA) and controls the cell's growth and reproduction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2009>56", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "A man who is heterozygous for the disease haemophilia marries a woman who is double recessive for haemophilia. What percentage of their offspring would have the disease?", "images": [], "options": {"A": "0%", "B": "25%", "C": "50%", "D": "75%"}, "answer": "C", "explanation": "Conventionally, when a man who is heterozygous for haemophilia marries a woman who is double recessive for the disease, 50% of their offspring will have the disease.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>57", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "APPLICATION OF VARIATIONS :", "question": "A dairy farmer allowed only his best milk producing cows to mate. In succeeding generations of cows, milk production increased. This outcome is an example of", "images": [], "options": {"A": "artificial selection", "B": "natural selection", "C": "competition", "D": "cross fertilization"}, "answer": "A", "explanation": "The dairy farmer is selecting which cows to breed based on their milk production. This is a form of artificial selection, where humans intervene in the breeding to produce desired traits in the offspring. Natural selection, on the other hand, is the process by which species evolve over time as a result of changes in their physical or behavioral traits that make them more or less able to survive and reproduce. Competition and cross fertilization do not directly relate to the scenario described.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>58", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Cytokinesis of mitosis is a process that ensures that", "images": [], "options": {"A": "each daughter cell gets the necessary organelles", "B": "there is distribution of a complete set of genes into each daughter cell", "C": "daughter cells inherit new genetic combinations", "D": "worn out organelles are excluded from daughter cells"}, "answer": "B", "explanation": "Cytokinesis is the physical process of cell division, which divides the cytoplasm of a parental cell into two daughter cells. It occurs after the cell nucleus has divided in a process called mitosis. During mitosis, the cell's chromosomes are duplicated and then separated, ensuring that each daughter cell receives a complete set of genes. The other options do not accurately describe the purpose of cytokinesis in mitosis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2009>59", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "An animal which is active during the day is known as a", "images": [], "options": {"A": "nocturnal animal", "B": "diurnal animal", "C": "terrestrial animal", "D": "homoiothermic animal"}, "answer": "B", "explanation": "An animal which is active during the day is known as a diurnal animal. The term 'diurnal' comes from the Latin 'dies', which means day. Diurnal animals are active during the day and sleep at night. This is opposite to nocturnal animals, which are active at night. Terrestrial animals are those that live on land, and homoiothermic animals are those that can regulate their body temperature, regardless of the external environment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2009>60", "subject": "Biology", "year": "2009", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Evidence for evolution include the following except", "images": [], "options": {"A": "fossils records", "B": "comparative anatomy", "C": "mutation of genes", "D": "geographical distribution of organism"}, "answer": "C", "explanation": "Mutation of genes is not an evidence for evolution. Evolution is the process of change in all forms of life over generations. Evidence for evolution comes from many different areas of biology, including fossil records, comparative anatomy, and geographical distribution of organisms. However, mutation of genes is a process that can lead to new variations within a species, which can then be acted upon by natural selection, potentially leading to evolution. But it is not an evidence of evolution itself.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>1", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "Which of the following organisms is not classified as an animal?", "images": [], "options": {"A": "Amoeba", "B": "Paramecium", "C": "Euglena", "D": "Obelia"}, "answer": "C", "explanation": "Euglena is not classified as an animal. It is a unicellular organism that is often classified as a protist. Protists are a diverse group of eukaryotic microorganisms, which are not animals, plants or fungi. They are primarily unicellular, but there are some multicellular species. Euglena has characteristics of both plants and animals. Like plants, it can perform photosynthesis, but like animals, it can also take in food from its environment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>2", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "An organism that operates at the cellular level of organization carries out its physiological activities by using its", "images": [], "options": {"A": "cell membrane", "B": "organelles", "C": "nucleus", "D": "cell wall"}, "answer": "B", "explanation": "An organism that operates at the cellular level of organization carries out its physiological activities by using its organelles. Organelles are specialized structures within the cell that work together to help the cell function. They include structures such as the nucleus (which controls the cell's activities), the mitochondria (which produce energy), and the ribosomes (which make proteins). The cell membrane and cell wall are involved in protecting the cell and regulating the movement of substances in and out of the cell, but they do not carry out the cell's physiological activities.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>3", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "The organelle which eliminates water from the body of a protozoan is the", "images": [], "options": {"A": "plasma membrane", "B": "contractile vacuole", "C": "nucleus", "D": "cell wall"}, "answer": "B", "explanation": "The removal of water from the body of a protozoan is part of the process of osmoregulation. Contractile vacuole performs the function of osmoregulation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>4", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which of the following cell types has the least number of mitochondria?", "images": [], "options": {"A": "Cardiac cells of the heart", "B": "Cells of the cornified layer", "C": "Muscle cells of the bladder", "D": "Muscle cells of the diaphragm"}, "answer": "B", "explanation": "The cells of the cornified layer, also known as the stratum corneum in the skin, have the least number of mitochondria. This is because these cells are dead and filled with keratin, a protein that provides a barrier against environmental damage. They do not require energy for metabolic processes, unlike other cells such as cardiac cells or muscle cells, which have a high energy demand and therefore a high number of mitochondria.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>5", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "A typical plant cell is mainly distinguished from an animal cell by the possession of", "images": [], "options": {"A": "chloroplast and nucleus", "B": "cell wall and cytoplasm", "C": "chloroplast and cell wall", "D": "cell wall and mitochondrion"}, "answer": "C", "explanation": "A typical plant cell is mainly distinguished from an animal cell by the possession of chloroplast and cell wall. Chloroplasts are the site of photosynthesis in plant cells, a process that is not present in animal cells. The cell wall, made of cellulose, provides structural support to the plant cell, another feature not found in animal cells.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>6", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "Which of the following characteristics do fungi share in common with animals?", "images": [], "options": {"A": "Presence of digestive tract", "B": "Movement from one place to another", "C": "Storage of carbohydrate as glycogen", "D": "Movement of centrioles during cell division"}, "answer": "C", "explanation": "Fungi and animals both store carbohydrates as glycogen. This is a form of energy storage used by animals and fungi that is efficient for rapid energy release. Unlike plants which store energy as starch, animals and fungi convert glucose into glycogen for storage.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>7", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "Which of the following processes involves diffusion?", "images": [], "options": {"A": "Opening and closing of stomatal pores", "B": "Turgidity of herbaceous plants", "C": "Absorption of water through the root hairs", "D": "Absorption of digested food into the villi"}, "answer": "D", "explanation": "Diffusion is the movement of particles from an area of higher concentration to an area of lower concentration. Here's how it relates to the options given:    -Opening and closing of stomatal pores: This is controlled by the turgidity of guard cells, primarily influenced by osmosis and the active transport of ions, not diffusion.    -Turgidity of herbaceous plants: This involves osmosis, which is the movement of water across a semi-permeable membrane, not diffusion.    -Absorption of water through the root hairs: This primarily occurs through osmosis, where water moves from the soil (higher water potential) to the root cells (lower water potential).    -Absorption of digested food into the villi: This involves diffusion. Nutrients like glucose and amino acids, once broken down, move from the intestinal lumen (where they are in higher concentration) into the blood capillaries within the villi (where they are in lower concentration).    Thus, the process of absorbing digested food into the villi is an example of diffusion.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>8", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "The mechanism of opening and closing of stomata in plants is based on", "images": [], "options": {"A": "turgidity and diffusion", "B": "turgidity and flaccidity", "C": "osmosis and diffusion", "D": "diffusion and flaccidity"}, "answer": "B", "explanation": "The opening and closing of the stomata is controlled by turgidity and flaccidity respectively. When the guard cells are turgid, the guard cells which control the opening and closing of stomata opens and when the guard cells are flaccid, the stomata closes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>9", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "In cellular respiration energy is made available to organism by", "images": [], "options": {"A": "removal of a phosphate group from ADP", "B": "breaking off a phosphate group from ATP", "C": "adding a phosphate group to glucose", "D": "breaking off a hydrogen ion from NADPH"}, "answer": "B", "explanation": "When ATP is converted to adenosine diphosphate (ADP), it loses a phosphate (P1). Energy us released when the bond connecting the phosphate is broken.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>10", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Excretion in paramecium sp, is by diffusion because", "images": [], "options": {"A": "its habitat is water and moist places", "B": "it has simple, small and few internal organs", "C": "it has a large surface area to volume ratio", "D": "it has a large efficient meganucleus"}, "answer": "C", "explanation": "Excretion in Paramecium sp., is by diffusion because it has a large surface area to volume ratio. Diffusion is the movement of molecules from an area of higher concentration to an area of lower concentration. In the case of Paramecium, which is a unicellular organism, the large surface area to volume ratio allows for efficient diffusion of waste materials out of the cell.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>11", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The axial skeleton is composed of the", "images": [], "options": {"A": "skull and vertebral column", "B": "limbs and girdles", "C": "atlas and axis", "D": "radius and ulna"}, "answer": "A", "explanation": "The axial skeleton is part of the skeleton that consists of the bones of the head and trunk of a vertebrate. It is composed of the skull, the vertebral column, the ribs, and the sternum. Therefore, the correct answer is 'skull and vertebral column'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>12", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The inorganic components of bone consist of", "images": [], "options": {"A": "magnesium, sodium and calcium", "B": "magnesium, phosphorus and calcium", "C": "sodium, phosphorus and calcium", "D": "potassium, magnesium and calcium"}, "answer": "B", "explanation": "The inorganic components of bone consist of hydroxyapatite, a crystalline structure composed of calcium, phosphate, and hydroxide ions. Other minerals present in bone include magnesium and sodium. Therefore, the correct answer is 'magnesium, phosphorus and calcium'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>13", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "A pulse is best described as", "images": [], "options": {"A": "contraction of arteries to let out blood", "B": "contraction of veins to allow blood into them", "C": "dilation of arteries to accomodate blood rushing through", "D": "pumping action of the heart to move blood round the body"}, "answer": "C", "explanation": "When the heart beats, it pumps blood into the arteries, causing them to expand (dilate) to accommodate the surge of blood. This expansion and subsequent recoil can be felt as a pulse at various points on the body where the arteries are close to the skin.  why the other options are incorrect:  -Contraction of arteries to let out blood: Arteries do not contract to let out blood. The heart's pumping action forces blood into the arteries, causing them to expand. Arteries can contract to help regulate blood pressure, but this is not what creates the pulse.    -Contraction of veins to allow blood into them. Veins do not significantly contract to allow blood into them. Blood flow through veins is aided by the contraction of surrounding muscles and valves that prevent backflow, not by the veins themselves contracting in a way that would generate a pulse.    -Pumping action of the heart to move blood round the body**: While the heart's pumping action is crucial for moving blood around the body and creating the pulse, the pulse itself is specifically the result of the dilation of arteries in response to the surge of blood. This option is too broad and does not describe the pulse as the arterial dilation does.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>14", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "The following characteristics are associated with the mammalian lungs except", "images": [], "options": {"A": "large surface area", "B": "expandable lungs", "C": "moist surface", "D": "highly vascularized"}, "answer": "B", "explanation": "The mammalian lungs are not expandable. They are elastic, meaning they can stretch and then return to their original shape, but they do not expand in the sense of growing larger. The other options are correct: the lungs do have a large surface area, a moist surface for gas exchange, and are highly vascularized, meaning they have a large number of blood vessels.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>15", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "The excretory system in mammals consists of the following parts except", "images": [], "options": {"A": "two kidney", "B": "two ureters", "C": "two bladders", "D": "one urethra"}, "answer": "C", "explanation": "The excretory system in mammals consists of two kidneys, two ureters, and one urethra. However, mammals do not have two bladders. They only have one bladder. Therefore, the option 'two bladders' is incorrect.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>16", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "The organ that receives reduced flow of blood during vigorous exercise is the", "images": [], "options": {"A": "brain", "B": "heart", "C": "lung", "D": "limb"}, "answer": "A", "explanation": "During vigorous exercise, the body prioritizes sending blood to the muscles that are working hard, such as the limbs. As a result, organs like the brain receive a reduced flow of blood. The heart and lungs, on the other hand, receive increased blood flow because they are working harder to supply oxygen and remove carbon dioxide from the body.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>17", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The ear pinna is strengthened by", "images": [], "options": {"A": "blood pressure", "B": "cartilage", "C": "bone", "D": "turgor pressure"}, "answer": "B", "explanation": "The pinna or auricle is the exposed funnel-shaped part of the ear that directs sound waves into the ear. It is a flap made of cartilageneous tissue, the  cartilaginous  tissue maintains the shape of the pinna and offers some flexibility.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>18", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "The relationship between the retina and the brain is similar to that between the", "images": [], "options": {"A": "cochlea and the auditory nerve", "B": "cochlea and the brain", "C": "cochlea and the semi-circular canals", "D": "eardrum and the brain"}, "answer": "B", "explanation": "The relationship between the retina and the brain is similar to that between the cochlea and the brain in that the stereo cilia in the cochlea respond to vibrations of the fluid in the cochlea and send electric impulses to the brain via the cochlea nerve.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>19", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "Which of the following statements about the development of the foetus is not correct?", "images": [], "options": {"A": "The circulatory system of the foetus is directly connected to the maternal blood vessels", "B": "The foetus depends on the mother's blood for its food and oxygen", "C": "The foetus is surrounded by a water sac", "D": "Food and oxygen are carried across the placenta to the embryo's blood"}, "answer": "A", "explanation": "The circulatory system of the foetus is not directly connected to the maternal blood vessels. Instead, the mother's and foetus's blood supplies are separated by the placenta, which allows for the exchange of nutrients and waste products without the two blood supplies mixing. This is a crucial aspect of foetal development as it protects the foetus from potential infections and harmful substances that may be present in the mother's blood.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>20", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "Use the diagram beside to answer this question      The parts that supply food and water to the developing embryo are labelled", "images": ["Biology/imgs/2010/B773AH.jpg"], "options": {"A": "I and II", "B": "III and V", "C": "V and VI", "D": "II and III"}, "answer": "C", "explanation": "The parts labelled V and VI supply food and water to the developing embryo. The part labelled V is the albumen which provides food (mainly protein and salts) and water for embryo. The part labelled VI is the yolk which provides food (mainly fats and proteins) for embryo.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>21", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "Use the diagram beside to answer this question    The part labelled III is the", "images": ["Biology/imgs/2010/B773AH.jpg"], "options": {"A": "albumen", "B": "chalaza", "C": "yolk", "D": "air space"}, "answer": "B", "explanation": "The part labelled III is the chalaza. The chalaza is a strands of albumen that supports the yolk.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>22", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "Which of the following statements is true about transpiration? It is the", "images": [], "options": {"A": "loss of water in the form of vapour from the surface of the leaf", "B": "loss of water in the form of vapour from the surface of the root", "C": "absorption of water in the form of vapour from the body of the plant", "D": "movement of water through the body of the plant"}, "answer": "A", "explanation": "Transpiration is the process by which water is lost from a plant in the form of water vapour. This primarily occurs at the leaves of the plant, specifically through tiny openings called stomata. The water vapour is created when water from the plant's cells evaporates into the air spaces within the leaf, and then exits the leaf through the stomata. Therefore, the statement 'loss of water in the form of vapour from the surface of the leaf' is true about transpiration.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>23", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "Transportation of water in the xylem tissue involves the following except", "images": [], "options": {"A": "root pressure", "B": "capillary action", "C": "transpiration pull", "D": "translocation"}, "answer": "D", "explanation": "Root pressure, capillary action and transpiration pull are the factors involved in the movement of water in the xylem. Xylem is a tissue that conducts water in plants.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>24", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The following are the major reasons why the butterfly lays eggs under the surface of a leaf except to", "images": [], "options": {"A": "shade the eggs from the direct rays of the sun", "B": "protect the eggs from predators", "C": "protect the eggs from being washed away by rain drops", "D": "camouflage the eggs"}, "answer": "D", "explanation": "All the options given are reasons why a butterfly lays its eggs under the surface of a leaf except for camouflage. While it's true that the underside of a leaf can provide some degree of camouflage, this is not the primary reason why butterflies choose to lay their eggs there. The main reasons are to protect the eggs from predators, shield them from the direct rays of the sun, and prevent them from being washed away by rain.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>25", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "In which of the following organic compounds is the hydrogen-oxygen ratio equal to 2:1?", "images": [], "options": {"A": "Protein", "B": "Carbohydrates", "C": "Lipids", "D": "Vitamins"}, "answer": "B", "explanation": "The hydrogen-oxygen ratio in carbohydrates is 2:1. This is because carbohydrates are organic compounds composed of carbon, hydrogen, and oxygen, and the hydrogen and oxygen are usually in the ratio of 2:1, similar to water. This is not the case for proteins, lipids, or vitamins.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>26", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "A man suffering from obesity must avoid meals containing", "images": [], "options": {"A": "margarine and butter", "B": "rice and beans", "C": "carrots and oranges", "D": "beef and fish"}, "answer": "A", "explanation": "Obesity is a condition that arises mainly due to excess fat in the body. Margarine and better are fat-containing food. A person suffering from obesity should avoid meals containing fat.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>27", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "In testing for starch in a leaf, the leaf is first boiled in water for about a minute so that the", "images": [], "options": {"A": "cells walls are hardened", "B": "cells are killed", "C": "chrolophyl is dissolved out", "D": "iodine will penetrate"}, "answer": "B", "explanation": "The leaf is first boiled in order to kill the cells.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>28", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Which of the following food substances is incorrectly linked to its enzyme?", "images": [], "options": {"A": "Protein - trypsin", "B": "Fat - lipase", "C": "Sucrose - pepsin", "D": "Starch- amylase"}, "answer": "C", "explanation": "The enzyme pepsin does not break down sucrose. Pepsin is a protease enzyme that breaks down proteins into smaller peptides. It is produced in the stomach and is one of the main digestive enzymes in the digestive systems of humans and many other animals. On the other hand, sucrose is a type of sugar that is broken down by the enzyme sucrase, not pepsin.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>29", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Which of the following pH values is the best for the action of the enzymes - renin and pepsin in the stomach?", "images": [], "options": {"A": "pH 2", "B": "pH 7", "C": "pH 8", "D": "pH 9"}, "answer": "A", "explanation": "Renin and pepsin are enzymes found in the stomach that help in the digestion of proteins. These enzymes work best in an acidic environment, which is provided by the hydrochloric acid in the stomach. The pH of the stomach is typically around 2, which is highly acidic. Therefore, the best pH for the action of renin and pepsin is pH 2.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>30", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "The bacterium in a mutualistic association with legumes converts", "images": [], "options": {"A": "nitrates to ammonia", "B": "ammonium compounds to nitrites", "C": "nitrogen gas to ammonia", "D": "nitrites to nitrates"}, "answer": "C", "explanation": "The Rhizobium bacteria are found in the root nodules of leguminous plants. The bacteria obtain carbohydrates from the plants and at the same time provide the plants with ammonium compounds which they obtain through nitrogen fixation. Bacteria like Rhizobium that lives in the root nodules of leguminous plants are able to fix nitrogen found in the soil particles to ammonium compounds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>31", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : FEEDING HABITS", "question": "A herbivore cannot feed on a piece of meat because it has no", "images": [], "options": {"A": "incisors to cut the meat", "B": "canines to tear up the meat", "C": "premolars to grind the meat", "D": "molar to mash the meat"}, "answer": "B", "explanation": "Herbivores lack canines, hence, they cannot feed on a piece of meat. Instead of the canines, between the incisors and the premolars there is a gap, the diastema.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>32", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS", "question": "In a particular habitat the role of an organism is referred to as its", "images": [], "options": {"A": "level", "B": "biomass", "C": "niche", "D": "space"}, "answer": "C", "explanation": "In ecology, the term 'niche' refers to the role or function of an organism within its ecosystem. This includes its interactions with other organisms, its diet, its behavior, and the physical conditions necessary for its survival. Therefore, in a particular habitat, the role of an organism is referred to as its niche.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>33", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "The distribution of organisms in a fresh water habitat like a stream or pond is determined by the following factors except", "images": [], "options": {"A": "light penetration", "B": "pH of the soil", "C": "rainfall", "D": "temperature"}, "answer": "B", "explanation": "The pH of the soil does not affect the distribution of organisms in a fresh water habitat.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>34", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS", "question": "The speed of wind is measured using the", "images": [], "options": {"A": "wind vane", "B": "anemometer", "C": "photometer", "D": "barometer"}, "answer": "B", "explanation": "The speed of wind is measured using an anemometer. An anemometer is a device used for measuring the speed of wind, and is also a common weather station instrument. The term is derived from the Greek word anemos, which means wind, and is used to describe any wind speed instrument used in meteorology. The other options, wind vane, photometer, and barometer, are used for measuring wind direction, light intensity, and atmospheric pressure respectively.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>35", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS", "question": "Which of the following is a biotic component of an ecosystem?", "images": [], "options": {"A": "Soil", "B": "Rainfall", "C": "Light", "D": "Fungi"}, "answer": "D", "explanation": "A biotic component of an ecosystem refers to the living organisms that inhabit the ecosystem. This includes animals, plants, fungi, and bacteria. In the given options, 'Fungi' is the only biotic component. Soil, Rainfall, and Light are all abiotic components, which refer to the non-living physical and chemical elements in an ecosystem.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>36", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "A moss plant can withstand drought by means of its", "images": [], "options": {"A": "spores", "B": "rhizoids", "C": "antheridia", "D": "archegonia"}, "answer": "A", "explanation": "Moss plants are non-vascular plants that can withstand drought by means of their spores. Spores are a means of reproduction for moss, but they also allow the moss to survive in harsh conditions. When conditions are too dry for the moss to survive, it can release its spores, which are resistant to drought. The spores can then germinate when conditions become more favorable. Rhizoids, antheridia, and archegonia are also parts of a moss plant, but they do not help the plant withstand drought.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>37", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Which of the following factors is the main problem facing xerophytic plants?", "images": [], "options": {"A": "Competition for sunlight", "B": "Conservation of excess water", "C": "Inadequate roots for water absorption", "D": "Lack of adequate water"}, "answer": "D", "explanation": "Xerophytic plants are plants that have adapted to survive in an environment with little liquid water, such as an arid desert or an ice- or snow-covered region in the Alps or the Arctic. The main problem facing xerophytic plants is the lack of adequate water. This is because water is essential for photosynthesis, a process in which plants convert light energy, usually from the Sun, into chemical energy that can be later released to fuel the organisms' activities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>38", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE", "question": "The following are greenhouse gases except", "images": [], "options": {"A": "carbon dioxide", "B": "chlorofluorocarbon", "C": "methane", "D": "oxygen"}, "answer": "D", "explanation": "Greenhouse gases are gases in Earth's atmosphere that trap heat. They let sunlight pass through the atmosphere, but they prevent the heat that the sunlight brings from leaving the atmosphere. The main greenhouse gases are: water vapor, carbon dioxide, methane, nitrous oxide, and chlorofluorocarbons. Oxygen is not a greenhouse gas because it does not trap heat in the Earth's atmosphere.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>39", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT", "question": "Rural-urban migration in developing countries can be prevented by", "images": [], "options": {"A": "increasing the number of years in school", "B": "putting up more factories in urban areas", "C": "having boarding schools in rural areas", "D": "even distribution of facilities in both regions"}, "answer": "D", "explanation": "Rural-urban migration in developing countries can be prevented by even distribution of facilities in both regions. This is because one of the main reasons for rural-urban migration is the search for better facilities and opportunities which are often concentrated in urban areas. If facilities such as schools, hospitals, and job opportunities are evenly distributed in both rural and urban areas, people would have less incentive to migrate.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>40", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Muscles are attached to bones by means of", "images": [], "options": {"A": "tendons", "B": "ligaments", "C": "cartilage", "D": "nerves"}, "answer": "A", "explanation": "Muscles are attached to bones by means of tendons. Tendons are tough bands of fibrous connective tissue that usually connect muscle to bone and are capable of withstanding tension. Ligaments, on the other hand, connect bone to bone, cartilage is a flexible connective tissue found in many areas in the bodies of humans and other animals, and nerves are the core components of the body's nervous system.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>41", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION", "question": "In a population, food shortage may lead to", "images": [], "options": {"A": "an increased survival rate", "B": "high reproduction rate", "C": "intra-specific competition", "D": "low rate of migration"}, "answer": "C", "explanation": "In a population, food shortage may lead to intra-specific competition. Intra-specific competition refers to the competition between members of the same species for limited resources, such as food. When there is a food shortage, individuals within the same species will compete for the limited food resources, leading to intra-specific competition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>42", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "The following effects are associated with deforestation except", "images": [], "options": {"A": "gully erosion", "B": "extinction of plant species", "C": "migration of wild life", "D": "increase in rainfall"}, "answer": "D", "explanation": "The damaging effects of soil erosion include:  1. Soil erosion  2. Flooding   3. Desertification: which also leads to   a. A loss of habitat  b. an extinction of many species of organisms (plants & animals)  c. climatic changes", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>43", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "The main reason for the conservation of wildlife is to", "images": [], "options": {"A": "create national parks for recreation", "B": "maintain ecological balance in communities", "C": "prevent hunters from being cruel to animals", "D": "save some species from extinction"}, "answer": "D", "explanation": "The main reason for conservation is to save some species from extinction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>44", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Which of the following is an example of variation?", "images": [], "options": {"A": "Blood", "B": "Tongue rolling", "C": "Reproduction", "D": "Growth"}, "answer": "B", "explanation": "Variation refers to the differences in physical traits among individuals from the same species. Tongue rolling is an example of variation because not everyone can roll their tongue into a tube shape. This is a genetic trait, and it varies from person to person. The other options like Blood, Reproduction, and Growth are not examples of variation as they are common biological processes or components in all individuals of a species.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>45", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "The parameters of size, height, weight and colour in a population of living things are examples of", "images": [], "options": {"A": "environmental variations", "B": "non-heritable variations", "C": "continuous variations", "D": "discontinuous variations"}, "answer": "C", "explanation": "Continuous variations are those that have a complete range of measurements from one extreme to another. They are usually quantitative and can be measured. Examples include height, weight, and skin color in a population. These traits are controlled by two or more genes, which makes them polygenic. The genes interact with each other and the environment to bring about a wide range of phenotypes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>46", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Fingerprints are useful in crime detection because", "images": [], "options": {"A": "the police have sophisticated fingerprint machines", "B": "thieves may leave their prints at the scene of a crime", "C": "no two people have the same fingerprint", "D": "fingerprints are easy to make"}, "answer": "C", "explanation": "Fingerprints are unique to each individual, even identical twins do not have exactly the same fingerprints. This uniqueness makes fingerprints a very reliable method of identification. This is why they are used in crime detection, as they can help to identify the person who was at the scene of a crime.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>47", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "A person with blood group O can be given blood from persons who have blood belonging to", "images": [], "options": {"A": "group O only", "B": "group A only", "C": "groups A and O", "D": "group A, B and O"}, "answer": "A", "explanation": "A person with blood group O is considered a universal donor, but they can only receive blood from individuals of the same blood group, which is O. This is because blood group O does not have any antigens that would cause an immune response if transfused into another person. However, if a person with blood group O receives blood from any other group (A, B, or AB), their immune system would recognize the antigens on the red blood cells as foreign and mount an immune response, leading to a transfusion reaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>48", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "A man heterozygous for albino gene marries a woman who is also heterozygous for the gene. Both have normal skin colour. The probability that they will have an albino child is", "images": [], "options": {"A": "1/3", "B": "1/4", "C": "4/4", "D": "2/4"}, "answer": "B", "explanation": "Albinism is a recessive trait, meaning that an individual must inherit two copies of the albino gene (one from each parent) to express the trait. If both parents are heterozygous for the albino gene (meaning they each carry one copy of the albino gene and one copy of the normal gene), then there is a 1 in 4 chance that any given child will inherit two copies of the albino gene and therefore be albino. This is determined using a Punnett square, a diagram that is used to predict the outcome of a particular cross or breeding experiment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>49", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of the following statements about heredity is not true? In hereditary the traits are", "images": [], "options": {"A": "carried by genes", "B": "contained in the ovum and sperm", "C": "always transmitted by one parent", "D": "transmitted from parents to offspring"}, "answer": "C", "explanation": "Heredity is the process by which traits are passed from parents to offspring. These traits are carried by genes, which are contained in the ovum and sperm. However, it is not true that traits are always transmitted by one parent. In most cases, traits are inherited from both parents, which is why offspring often have characteristics of both parents. Therefore, the statement 'always transmitted by one parent' is not true.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>50", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS", "question": "An example of a saprophytic relationship is a/an", "images": [], "options": {"A": "vulture feeding on decaying meat", "B": "mushroom growing on decaying vegetation", "C": "boy eating stale bread", "D": "earthworm feeding on decaying vegetation"}, "answer": "B", "explanation": "In a saprophyte relationship, only one living organism is involved. The living organism is usually the decomposer (fungus or bacterium) and the non-living component is the dead-decaying matter.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>51", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "In artificial selection, individuals without desirable traits may be prevented from mating by", "images": [], "options": {"A": "outbreeding", "B": "sterilization", "C": "inbreeding", "D": "genetic engineering"}, "answer": "B", "explanation": "Artificial selection is a process used by humans to develop new organisms with desirable characteristics. Breeders select two parents that have beneficial phenotypic traits to reproduce, yielding offspring with those desired traits. Individuals without desirable traits may be prevented from mating by sterilization. Sterilization is a process that eliminates or kills all forms of life, including transmissible agents (such as fungi, bacteria, viruses, spore forms, etc.) present on a surface, contained in a fluid, in medication, or in a compound.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>52", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : SEX DETERMINATION AND SEX LINKED CHARACTERS", "question": "In a family of eight (8) all the children are girls. Which of the following reasons correctly explains this?", "images": [], "options": {"A": "The woman cannot produce male children", "B": "The man has a low sperm count", "C": "The Y component of the man's sex chromosome was always involved", "D": "The X component of the man's sex chromosomes was always involved"}, "answer": "D", "explanation": "- This is because the X component of the man's sex chromosome was always involved.  - In men, we have XY genotype and in female, we have XX genotype.  During sex determination, when the X component of the female sex chromosome is released and the X component of the male sex chromosome is released, the baby will be female also, when the X component of the female sex chromosome is released, and the Y component of the male sex chromosome is released, the baby will be male.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>53", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "Which of the following statements is correct about the structure of a chromosome? A chromosome consists of", "images": [], "options": {"A": "two chromatids joined at the centromere", "B": "two chromatids joined at the spindle", "C": "two chromatin threads joined at the centrioles", "D": "threas-like structures not joined together"}, "answer": "A", "explanation": "During cell division, the chromosomes are duplicated and become visible under the microscope as long and thin threads that are between 0.25μm and 50μm in length. Each duplicated chromosome is made up of two sister chromatids attached by a centromere.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>54", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "Mr. Andrew, his wife and child belong to blood group A, B and O respectively. The genotypes of both parents are", "images": [], "options": {"A": "IAIO and IBIB", "B": "IAIA and IBIB", "C": "IAIB and IAIO", "D": "IAIO and IBIO"}, "answer": "D", "explanation": "|A|B |A|o |B|o |O|o - the child/offspring", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>55", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "What would be the phenotypic ratio of the offspring of a cross between a heterozygous dominant parent and a double recessive parent?", "images": [], "options": {"A": "1 : 2 : 1", "B": "1 : 1", "C": "3 : 1", "D": "2 : 1"}, "answer": "B", "explanation": "Let the heterozygous dominant parent be Rr the double recessive parent rr  Parent Rr &nbsp &nbsp &nbsp &nbsp X &nbsp &nbsp &nbsp &nbsp rr", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>56", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : LINKAGE, SEX DETERMINATION AND SEX LINKED CHARACTERS", "question": "The percentage probability that a normal male married to a carrier woman would have a haemophilic male child is", "images": [], "options": {"A": "35%", "B": "50%", "C": "75%", "D": "100%"}, "answer": "B", "explanation": "Let the normal man be XY  the carries woman be XcXc    Hemophilic male is 2  24×100=50%", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2010>57", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The importance of courtship in animals includes the following except", "images": [], "options": {"A": "ensuring that the female choose the right male species", "B": "arousing both male and female partners", "C": "protection of territory", "D": "to coincide with the ovulation period and ensure fertilization"}, "answer": "C", "explanation": "Courtship in animals serves several purposes such as ensuring that the female chooses the right male species, arousing both male and female partners, and to coincide with the ovulation period to ensure fertilization. However, courtship does not directly involve the protection of territory. While some animals may use courtship displays to assert dominance or territorial control, the act of courtship itself is not a mechanism for territory protection.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>58", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "In evolution, analogous structures are significant because they show", "images": [], "options": {"A": "physiological diversity", "B": "functional diversity", "C": "genetic diversity", "D": "structural diversity"}, "answer": "B", "explanation": "Analogous structures in evolution are significant because they show functional diversity. Analogous structures are those that perform similar functions but are not necessarily structurally similar or have a common ancestor. They are a result of convergent evolution where different species have independently evolved similar solutions to similar environmental challenges. This shows functional diversity as different species have developed similar functions to adapt to their environment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>59", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Which of the following statements reflects the mechanism of natural selection?", "images": [], "options": {"A": "There are variations within every species", "B": "Individuals of every species are generally identical", "C": "No organism in a species dies before sexual maturity", "D": "Organism with selective advantages are less likely to survive"}, "answer": "A", "explanation": "The statement that reflects the mechanism of natural selection is 'There are variations within every species'. Natural selection is a process where organisms with variations that make them better adapted to their environment tend to survive and reproduce more than those without these variations. This leads to the changes in the species over time. The other options do not accurately reflect the mechanism of natural selection.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2010>60", "subject": "Biology", "year": "2010", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following animals exhibits territoriality?", "images": [], "options": {"A": "Rabbit", "B": "Earthworm", "C": "Lizard", "D": "Toad"}, "answer": "C", "explanation": "Territoriality is a type of behavior in which an animal defends a bounded physical space against intrusion by other individuals, usually of its own species. Lizards are known to exhibit this behavior, marking and defending their territories from other males and sometimes females, too.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2011>1", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "The branch of Biology that deals with the principles of classification of organisms is known as", "images": [], "options": {"A": "biological index", "B": "nomenclature", "C": "taxonomy", "D": "ecology"}, "answer": "C", "explanation": "Taxonomy is the branch of biology that categorizes all living things. It was developed by the Swedish botanist Carolus Linnaeus, who lived during the 18th Century, and his system of classification is still used today. Taxonomy involves the classification of organisms into a hierarchy of taxa, including kingdom, phylum, class, order, family, genus, and species.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>2", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following structures is a tissue?", "images": [], "options": {"A": "Vessel element", "B": "Blood", "C": "Sieve tube element", "D": "Erythrocyte"}, "answer": "B", "explanation": "A tissue is a group of cells that work together to perform a specific function. In this case, blood is considered a tissue because it is composed of different types of cells (red blood cells, white blood cells, and platelets) that work together to perform various functions such as oxygen transportation, immune response, and clotting. The other options (Vessel element, Sieve tube element, Erythrocyte) are individual cell types, not tissues.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2011>3", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which of the following cells are not regarded as specialized?", "images": [], "options": {"A": "Sperm cells", "B": "Root tip cells", "C": "Muscle cells", "D": "Somatic cells"}, "answer": "D", "explanation": "Specialized cells are cells that have a specific role to perform in the body, they are adapted to carry out this role. Sperm cells, root tip cells, and muscle cells are all examples of specialized cells as they have specific roles in reproduction, growth, and movement respectively. However, somatic cells are not specialized because they make up the majority of the body's cells and perform the basic functions of life, they are not adapted for a specific role.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2011>4", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which of the following pairs of cells carry out the same functions?", "images": [], "options": {"A": "Cheek cell and red blood cell", "B": "Spermatozoan and ovum", "C": "Palisade cell and epidermal cell", "D": "Root tips cell and guard cell"}, "answer": "B", "explanation": "Spermatozoan and ovum both carry out the function of reproduction. The spermatozoan (male gamete) and ovum (female gamete) fuse during fertilization to form a zygote, which develops into a new organism. Other options are incorrect because the cells listed do not carry out the same functions. For example, cheek cells are involved in protection and secretion, while red blood cells are involved in oxygen transport.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2011>5", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "If Amoeba is placed in a salt solution, the contractile vacuoles would", "images": [], "options": {"A": "be bursting more frequently", "B": "be more numerous", "C": "be formed less frequently", "D": "grow bigger before they burst"}, "answer": "C", "explanation": "In a hypertonic solution (such as a salt solution), water moves out of the Amoeba's cell to balance the external salt concentration. This leads to a decrease in the internal water content of the cell.     The primary function of the contractile vacuole in Amoeba is to expel excess water that enters the cell. In a hypertonic environment, less water enters the cell, so the contractile vacuole doesn't need to expel water as frequently.    Therefore, the contractile vacuole would not be bursting more frequently; instead, it would be formed less frequently due to the decreased water intake.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>6", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "In which of the following habitats is Paramecium not found?", "images": [], "options": {"A": "Pond", "B": "Aquarium", "C": "Lake", "D": "Puddle"}, "answer": "B", "explanation": "Amoeba, Paramecium, Sporozoans and some other protists cannot survive in the aquarium.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2011>7", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The following processes are involved in water movement in the endodermis except", "images": [], "options": {"A": "osmosis", "B": "vacuolar pathway", "C": "diffusion", "D": "active transport"}, "answer": "C", "explanation": "The endodermis is a layer of cells in plant roots that plays a crucial role in water and nutrient uptake. The following processes are involved in water movement in the endodermis:    Osmosis: Water enters the endodermis through osmosis, driven by a concentration gradient.    Vacuolar pathway: Water can move through the vacuoles of endodermal cells, allowing for the transport of water and solutes.    Active transport: Endodermal cells can actively transport solutes and water into the plant, using energy-dependent mechanisms.    However, diffusion is not directly involved in water movement in the endodermis. Diffusion is the random movement of molecules from high to low concentration, but it's not a primary mechanism for water uptake in the endodermis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>8", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Cells that utilize a lot of energy are characterised by the presence of a large number of", "images": [], "options": {"A": "vacuoles", "B": "mitochondria", "C": "endoplasmic reticulum", "D": "ribosomes"}, "answer": "B", "explanation": "Cells that utilize a lot of energy are characterized by the presence of a large number of mitochondria. Mitochondria are known as the powerhouses of the cell because they produce ATP (adenosine triphosphate), the cell's main energy-carrying molecule. This is why cells that require a lot of energy, such as muscle cells, have a large number of mitochondria.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>9", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The diagram beside represents the phenomenon of growth in a meristematic cell of a plant        Use it to answer this question     The part labelled II in the diagram is the", "images": ["Biology/imgs/2011/XXHKDM.jpg"], "options": {"A": "centriole", "B": "chloroplast", "C": "chromatid", "D": "tonoplast"}, "answer": "C", "explanation": "The part labelled II is one of the sister chromatids", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>10", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The diagram beside represents the phenomenon of growth in a meristematic cell of a plant        Use it to answer this question    The part labelled I is called the", "images": ["Biology/imgs/2011/XXHKDM.jpg"], "options": {"A": "nucleolus", "B": "centromere", "C": "centriole", "D": "spindle"}, "answer": "D", "explanation": "The spindle fibre is closely attached to the centriole.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>11", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Secondary growth is brought about by the activities of the", "images": [], "options": {"A": "phellogen and phelloderm", "B": "phellogen and procambium", "C": "vascular cambium and phelloderm", "D": "vascular cambium and phellogen"}, "answer": "D", "explanation": "Secondary growth in plants is brought about by the activities of the vascular cambium and the cork cambium (also known as phellogen). The vascular cambium is responsible for producing new transport cells in the xylem and phloem, while the cork cambium (phellogen) produces cells that eventually become the bark of the plant. Therefore, the correct answer is 'vascular cambium and phellogen'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>12", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "A monocot root is different from a dicot root by having", "images": [], "options": {"A": "endodermis", "B": "cambium", "C": "wide pith", "D": "root hairs"}, "answer": "C", "explanation": "A monocot root is different from a dicot root by having a wide pith. The pith is the central part of the root or stem containing parenchyma tissue. In monocots, this pith is wide, while in dicots it is comparatively smaller. The other options like endodermis, cambium, and root hairs are common to both monocot and dicot roots.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>13", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Which of the following statements best describes haemoglobin? It is", "images": [], "options": {"A": "yellowish in colour", "B": "a red blood cell", "C": "an oxygen carrying pigment", "D": "needed for blood clotting"}, "answer": "C", "explanation": "Haemoglobin is an oxygen-carrying pigment. It is a protein in red blood cells that carries oxygen from the lungs to the body's tissues and returns carbon dioxide from the tissues back to the lungs. It is not yellowish in colour, it is not a red blood cell (but is found within them), and it is not needed for blood clotting (that's the role of platelets and clotting factors).", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2011>14", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Inhaled air is made warm and moist in the", "images": [], "options": {"A": "epiglottis", "B": "nasal cavity", "C": "trachea", "D": "mouth"}, "answer": "B", "explanation": "The nasal cavity is responsible for warming and moistening the air we inhale. This is because the nasal cavity is lined with a mucous membrane that secretes mucus to moisten the air and has a rich blood supply that warms the air.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2011>15", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Which of the following structures is not involved in respiration?", "images": [], "options": {"A": "Lungs Books", "B": "Mouth", "C": "Stomach", "D": "Trachea"}, "answer": "C", "explanation": "The stomach is not involved in respiration. Respiration is the process of gas exchange between the body and the environment, and it involves structures like the lungs, trachea, and mouth. The stomach, on the other hand, is involved in digestion, not respiration.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2011>16", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Filtrate in the Bowman's capsule contains vitamins because", "images": [], "options": {"A": "only a little amount is required by the body", "B": "they can be reabsorbed into the blood.", "C": "they have low molecular weight.", "D": "most of them are fat soluble"}, "answer": "C", "explanation": "The filtrate in the Bowman's capsule contains vitamins because they have low molecular weight. The Bowman's capsule is a part of the nephron in the kidneys that performs the first step in the filtration of blood to form urine. It filters out small molecules such as water, glucose, amino acids, and urea, along with vitamins, which are small enough to pass through the filtration membrane. Larger molecules like proteins and blood cells are too large to pass through and remain in the blood.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>17", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "More sweat is produced during muscular exercise because", "images": [], "options": {"A": "the contracting  muscles produce water", "B": "fermentation occurs in muscles", "C": "the temperature of the body rises", "D": "the muscles fatigues"}, "answer": "C", "explanation": "More sweat is produced during muscular exercise because the temperature of the body rises. When we exercise, our muscles generate heat as a byproduct of energy production. This heat increases our body temperature. To cool down, our body produces sweat, which evaporates from the skin surface and helps to dissipate the heat, thereby regulating body temperature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>18", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "Which of the following neutrons may not have myelin sheath", "images": [], "options": {"A": "Effector cells", "B": "Intermediate neurons", "C": "Motor neurons", "D": "Sensory neurons"}, "answer": "B", "explanation": "Intermediate neurons (also known as interneurons) typically lack myelin sheaths. They are primarily involved in relaying signals between sensory and motor neurons within the central nervous system and often have short axons that do not require myelination.    Effector cells, are not neurons. Effector cells refer to muscle or gland cells that carry out the body's responses to stimuli. These cells receive signals from motor neurons but are not themselves neurons, so the concept of a myelin sheath does not apply to them. Therefore, the correct answer is Intermediate neurons, which are typically not myelinated.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>19", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "Which of the following is not an effector organ?", "images": [], "options": {"A": "Tongue", "B": "Skin", "C": "Nose bridge", "D": "Ear glands"}, "answer": "B", "explanation": "External sense organs e.g skin are receptor hence it is not an effector organ.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2011>20", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "During sexual reproduction in Paramecium, how many times does the zygote divide to produce eight nuclei?", "images": [], "options": {"A": "1", "B": "2", "C": "3", "D": "4"}, "answer": "C", "explanation": "In Paramecium, during sexual reproduction, the zygote (fertilized cell) undergoes three rounds of cell division to produce eight nuclei. This process is called multiple fission.    This is the division sequence:    1. Zygote (1 nucleus) → 2 nuclei (1st division)  2. 2 nuclei → 4 nuclei (2nd division)  3. 4 nuclei → 8 nuclei (3rd division)    The resulting eight nuclei will then develop into eight daughter cells, each with a complete set of chromosomes", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>21", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "The testes in male mammals descend into the scrotal sac because", "images": [], "options": {"A": "there is congestion in the lower abdomen", "B": "they run the risk of being destroyed", "C": "they need special support", "D": "they require a relatively low temperature"}, "answer": "D", "explanation": "The testes in male mammals descend into the scrotal sac because they require a relatively low temperature for the production of sperm. This is a process known as testicular descent. The temperature in the scrotal sac is lower than the body temperature, which is necessary for the proper development and functioning of the sperm.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>22", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Some animals return to water bodies to reproduce because", "images": [], "options": {"A": "natural enemies destroy their egg on land", "B": "water nourishes the embryos and their young ones", "C": "they are close to their ancestors and imitate them", "D": "the temperature on land is not suitable for the development of their embryos"}, "answer": "D", "explanation": "This is due to the fact that the absolute temperature of the land is not suitable enough for the embryo to develop.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>23", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE", "question": "Which of the following methods is appropriate for the cultivation of cassava?", "images": [], "options": {"A": "Budding", "B": "Fragmentation", "C": "Root cutting", "D": "Stem cutting"}, "answer": "D", "explanation": "Cassava is propagated through stem cutting. This is a type of vegetative propagation where a section of the stem is planted in the ground and it grows into a new plant. This method is preferred because it ensures that the new plants will have the same characteristics as the parent plant.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2011>24", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "What will be the chromosome number of the hybrid of two varieties of a plant with 36 chromosomes in the endosperm cell?", "images": [], "options": {"A": "12", "B": "24", "C": "36", "D": "48"}, "answer": "B", "explanation": "In plants, the endosperm cell is triploid (3n), resulting from the fusion of a sperm nucleus with the polar nuclei in the embryo sac. Since the endosperm cell has 36 chromosomes, we can set up the equation:    3n = 36    To find the haploid chromosome number (n), we divide by 3:    n = 36 ÷ 3  n = 12    Since the hybrid is formed by the fusion of two haploid gametes (sperm and egg), the chromosome number of the hybrid will be 2n, or:    2n = 2 × 12  2n = 24    So, the chromosome number of the hybrid will be 24.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2011>25", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Kreb's cycle occurs in the", "images": [], "options": {"A": "mitochondria", "B": "cytoplasm", "C": "nucleus", "D": "ribosomes"}, "answer": "A", "explanation": "Kreb's cycle, also known as the citric acid cycle or the tricarboxylic acid cycle, occurs in the mitochondria of a cell. It is a series of chemical reactions used by all aerobic organisms to generate energy through the oxidation of acetyl-CoA derived from carbohydrates, fats, and proteins into carbon dioxide and chemical energy in the form of adenosine triphosphate (ATP).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>26", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "The process whereby electrons are emitted from chlorophyll and returned to it unchanged is known as", "images": [], "options": {"A": "non-cyclic phosphorylation", "B": "photochemical reaction", "C": "phosphorylation", "D": "cyclic  phosphorylation"}, "answer": "D", "explanation": "The process whereby electrons are emitted from chlorophyll and returned to it unchanged is known as cyclic phosphorylation. In cyclic phosphorylation, the electron travels a short circuit (it returns to the chlorophyll molecule from which it was excited), and the only product is ATP.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>27", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "Which of the following statements about photosynthesis is not true?", "images": [], "options": {"A": "Plants can photosynthesize without an increase in dry weight", "B": "Carbon dioxide is absorbed by the leaves in bright light", "C": "Oxygen is produced during photosynthesis from the breakdown of water", "D": "Photosynthesis occurs in green plants"}, "answer": "A", "explanation": "Carbon dioxide is absorbed by the leaves in bright light:takes place in green plants during photosynthesis as if (CO2) enters the leaves through the stomata opening on the leaf surface.    Oxygen is produced during photosynthesis from the breakdown of water:takes place during the light reaction stage of photosynthesis.   Photosynthesis takes place in green plants.  Plants can photosynthesize without an increase in dry weight is not true", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>28", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The equation below represents the process of glycolysis        X in the equation represents", "images": ["Biology/imgs/2011/bio1128.png"], "options": {"A": "Glucose diphosphate", "B": "Glucose phosphate", "C": "Glucose triphosphate", "D": "Fructose phosphate"}, "answer": "B", "explanation": "X in the equation represents Glucose phosphate in glycolysis", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2011>29", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "The removal of all the phloem tissues of the stem of a plant close to the root system for a long period of time is likely to", "images": [], "options": {"A": "provide more energy to the roots", "B": "accumulate more starch in the roots", "C": "cause the underground roots to develop buds", "D": "cause the plant to wither and die"}, "answer": "D", "explanation": "Phloem is a type of tissue in vascular plants that transports nutrients, including sugars produced during photosynthesis, from the leaves (where they are produced) to other parts of the plant. If all the phloem tissues are removed, the plant will not be able to transport these nutrients, leading to nutrient deficiency and eventually causing the plant to wither and die.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>30", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Conversion of glucose to starch in the leaf during the day principally", "images": [], "options": {"A": "enables photosynthesis", "B": "prevents osmotic problems", "C": "enables the leaf to store the starch", "D": "enables glucose to be used up."}, "answer": "C", "explanation": "The sugar produced during photosynthesis is converted to starch till night-time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>31", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Which of the following groups of substances are not six-carbon compounds?", "images": [], "options": {"A": "Glucose and Lactose", "B": "Lactose and Cellulose", "C": "Glucose, Lactose and Pyruvate", "D": "Pyruvate ad cellulose"}, "answer": "D", "explanation": "The question asks for substances that are not six-carbon compounds. Glucose and lactose are both six-carbon compounds. Pyruvate, however, is a three-carbon compound, and cellulose is a polymer made up of glucose units. Therefore, the correct answer is 'Pyruvate and cellulose'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>32", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "A purple colour was obtained when Sodium Hydroxide solution and a drop of Copper Sulphate solution were added to a food substance. The food substance is likely to be a", "images": [], "options": {"A": "carbohydrate", "B": "fat", "C": "protein", "D": "sugar"}, "answer": "C", "explanation": "The test described in the question is the Biuret test, which is used to detect the presence of proteins. When sodium hydroxide and copper sulphate are added to a protein, a purple color is produced. Therefore, the food substance is likely to be a protein.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>33", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Which of the following enzymes is active in the duodenum?", "images": [], "options": {"A": "Pepsin", "B": "Renin", "C": "Trypsin", "D": "Amylase"}, "answer": "C", "explanation": "The duodenum is the first part of the small intestine where the process of digestion continues. Trypsin is one of the enzymes that is active in the duodenum. It is produced in the pancreas and released into the duodenum where it helps in the digestion of proteins into smaller peptides.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2011>34", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "The following organisms are producers except", "images": [], "options": {"A": "Hibiscus", "B": "Mushroom", "C": "Cactus", "D": "Spirogyra"}, "answer": "B", "explanation": "Producers, also known as autotrophs, are organisms that can produce their own food from the substances available in their surroundings using light (photosynthesis) or chemical energy (chemosynthesis). Hibiscus, Cactus, and Spirogyra are all producers because they can perform photosynthesis. However, mushrooms are not producers. They are fungi, which are heterotrophs, meaning they cannot produce their own food and rely on other organisms for nutrition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>35", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Which of the following structures produces the greatest variety of digestive enzymes?", "images": [], "options": {"A": "Salivary glands", "B": "Pancreas", "C": "Stomach", "D": "Colon"}, "answer": "B", "explanation": "The pancreas produces the greatest variety of digestive enzymes. These include amylase, which breaks down carbohydrates; lipase, which breaks down fats; and protease, which breaks down proteins. The salivary glands produce salivary amylase, the stomach produces pepsin, and the colon does not produce digestive enzymes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2011>36", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS", "question": "The following are abiotic components of an ecosystem except", "images": [], "options": {"A": "temperature", "B": "oxygen", "C": "bacteria", "D": "soil"}, "answer": "C", "explanation": "Bacteria are biotic components of an ecosystem. Biotic components refer to all the living organisms in an ecosystem, including animals, plants, fungi, and microorganisms such as bacteria. Abiotic components, on the other hand, refer to non-living physical and chemical elements in an ecosystem, such as temperature, oxygen, and soil.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>37", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING", "question": "Use the information on capture-recapture method to calculate the total number of organisms in a habitat     First capture = 200   Second capture = 120    Number of organisms with mark in second capture = 40  `  The total number of organisms therefore is", "images": [], "options": {"A": "200", "B": "360", "C": "600", "D": "800"}, "answer": "C", "explanation": "The capture-recapture method is a method used in ecology to estimate an animal's population size. A portion of the population is captured, marked, and released. Later, another portion is captured and the number of marked individuals within the sample is counted. The total population is estimated using the formula: (first capture * second capture) / number of marked recaptures. In this case, (200 * 120) / 40 = 600. Therefore, the total number of organisms in the habitat is estimated to be 600.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2011>38", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT", "question": "Ecological investigation in a habitat includes the following procedures except", "images": [], "options": {"A": "choosing a habitat", "B": "identification of specimen", "C": "determining the genetic make-up of specimen", "D": "measuring abiotic and biotic factors"}, "answer": "C", "explanation": "Ecological investigation in a habitat includes choosing a habitat, identification of specimen, and measuring abiotic (non-living) and biotic (living) factors. However, determining the genetic make-up of a specimen is not a standard procedure in ecological investigation. This is more related to the field of genetics and molecular biology, where the genetic material of an organism is studied.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>39", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "Which of the following substances when lost from the body of a mammal will *not* be returned to the ecosystem?", "images": [], "options": {"A": "Sweat", "B": "Urea", "C": "Heat Energy", "D": "Carbon dioxide"}, "answer": "C", "explanation": "Heat energy, once lost from the body of a mammal, is not returned to the ecosystem. This is because heat energy is a form of kinetic energy that is dissipated into the environment and cannot be recycled or reused. On the other hand, substances like sweat, urea, and carbon dioxide can be returned to the ecosystem through various biological processes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>40", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "The rate of decomposition of organisms is faster in the tropical rain forest than in other biomes because", "images": [], "options": {"A": "of the relatively constant daylight", "B": "there are more plants per square feet", "C": "of abundance of water", "D": "of constant cool temperature"}, "answer": "C", "explanation": "The rate of decomposition of organisms is faster in the tropical rain forest than in other biomes because of the abundance of water. Water is a key factor in decomposition as it aids in the breakdown of organic matter and promotes the growth and activity of decomposers like bacteria and fungi. The other options do not directly contribute to the rate of decomposition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>41", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "A xerophyte conserves water by possession of the following features except", "images": [], "options": {"A": "thick cuticle", "B": "sunken stomata", "C": "broad leaves", "D": "fleshy stems"}, "answer": "C", "explanation": "A xerophyte is a plant that is adapted to survive in an environment with little liquid water, such as an arid desert or an ice- or snow-covered region in the Alps or the Arctic. They have adaptations that help them conserve water, such as thick cuticles, sunken stomata, and fleshy stems. However, they do not have broad leaves. Broad leaves would increase the surface area for evaporation, which would lead to more water loss. Therefore, the correct answer is 'broad leaves'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>42", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The falling off of leaves of deciduous trees is helpful to the plant because it", "images": [], "options": {"A": "reduces the rate of transpiration", "B": "enables the plant to conveniently  eliminate its excretory products", "C": "enables the plants to bear more fruits", "D": "ensures that the limited mineral salts get to only growing regions"}, "answer": "A", "explanation": "Deciduous trees are trees that shed their leaves annually as an adaptation to a cold or dry season. The falling off of leaves reduces the rate of transpiration (water loss) because there are fewer leaves to lose water. This is particularly important in winter when water can be hard to absorb from frozen ground. Therefore, the correct answer is 'reduces the rate of transpiration'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>43", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "A sample of wet garden soil of known weight was heated to constant weight. The loss of weight is due to loss of", "images": [], "options": {"A": "water", "B": "organic matter", "C": "water and organic matter", "D": "water and inorganic matter"}, "answer": "A", "explanation": "Water, only contribute to the weight of the garden soil.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>44", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION", "question": "Assuming that a period of stable population size is followed by a period when natality increases by ten(10)percent and immigration increases by twenty(2)) percent of population size. The population size will", "images": [], "options": {"A": "be at equilibrium", "B": "increase by forty(40) percent", "C": "begin to increase", "D": "begin to decrease"}, "answer": "C", "explanation": "If natality (birth rate) increases by 10 percent and immigration (influx of individuals into a population) increases by 20 percent, the population size will begin to increase. This is because both natality and immigration contribute to an increase in population size. Therefore, if both of these factors increase, the overall population size will also begin to increase.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2011>45", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH", "question": "Which of the following methods does not make water fit for drinking?", "images": [], "options": {"A": "Addition of chlorine", "B": "Boiling", "C": "Distillation", "D": "Addition of alum"}, "answer": "D", "explanation": "The addition of alum does not make water fit for drinking. Alum is used in water purification to cause impurities to coagulate and settle at the bottom, but it does not kill bacteria or other microorganisms that may be present in the water. Therefore, while it can help to clarify water, it does not make it safe to drink.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2011>46", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH", "question": "Vaccination results in", "images": [], "options": {"A": "aiding red bloods cells to carry more oxygen", "B": "production of antibodies which destroy toxins of germs", "C": "arresting excessive bleeding", "D": "production of white blood cells which engulf and digest bacteria"}, "answer": "B", "explanation": "Vaccination works by stimulating the immune system to produce antibodies, which are proteins that can recognize and neutralize specific pathogens. These antibodies can destroy toxins produced by germs, thereby preventing disease. The other options are not correct because vaccination does not aid red blood cells to carry more oxygen, arrest excessive bleeding, or directly produce white blood cells that engulf and digest bacteria.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>47", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE", "question": "Leguminous crops are incorporated into crop rotation in order to", "images": [], "options": {"A": "improve aeration of the soil", "B": "promote nitrogen fixation", "C": "increase the rate of soil formation", "D": "improve upon the water holding capacity of the soil."}, "answer": "B", "explanation": "Leguminous crops are incorporated into crop rotation to promote nitrogen fixation. Nitrogen fixation is a process by which nitrogen in the atmosphere is converted into ammonia (NH3) or related nitrogenous compounds in soil. Leguminous plants have symbiotic bacteria called Rhizobium in their root nodules that help in nitrogen fixation, thus enriching the soil with nitrogen and improving its fertility.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>48", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE", "question": "Which of the following practices improves crop yield in a clayey soil? Addition of", "images": [], "options": {"A": "more water and humus", "B": "lime and humus", "C": "fertilizers", "D": "weedicides and fertilizers"}, "answer": "B", "explanation": "Clayey soil is compact and has poor drainage. Adding lime and humus improves the structure of the clayey soil. Lime increases the pH of the soil, making it less acidic, and humus improves the soil's nutrient content and water holding capacity, thus improving crop yield.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>49", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Which of the following activities promotes forest conservation?", "images": [], "options": {"A": "Lumbering", "B": "Use of firewood for cooking", "C": "Afforestation", "D": "Production of paper"}, "answer": "C", "explanation": "Forest conservation involves the upkeep of the natural resources within a forest that are beneficial to both humans and the environment. It's a broad term that includes activities like reforestation, afforestation, and preventing deforestation. Afforestation, which is the process of establishing a forest, or stand of trees, in an area where there was no forest, is a direct action towards forest conservation. Lumbering, use of firewood for cooking, and production of paper are activities that actually lead to deforestation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>50", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Which of the following statements is not true about continuous variation? It", "images": [], "options": {"A": "is usually controlled by several genes", "B": "can be influenced by environmental factors", "C": "follows a normal distribution curve", "D": "is usually controlled by one or two pairs(s) of genes"}, "answer": "D", "explanation": "Continuous variation refers to a range of small differences in a shared trait among individuals. It is usually controlled by several genes (polygenic), can be influenced by environmental factors, and follows a normal distribution curve. The statement that it is usually controlled by one or two pairs of genes is incorrect because this describes discrete variation, not continuous variation. Discrete variation is controlled by a single gene or a small number of genes and results in distinct categories, such as blood type or sex.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>51", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Acquired characters are", "images": [], "options": {"A": "received from parents", "B": "passed to offspring", "C": "caused by the environment", "D": "caused by mutation"}, "answer": "C", "explanation": "Acquired characters are traits that an organism develops during its lifetime as a result of environmental influences or other external factors. These traits are not inherited from parents or passed on to offspring. They are caused by the environment, not by mutation. Therefore, the correct answer is 'caused by the environment'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>52", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Differences in characteristics observed between individuals of the same species is known as", "images": [], "options": {"A": "trait", "B": "phenotype", "C": "mutation", "D": "variation"}, "answer": "D", "explanation": "Differences in characteristics observed between individuals of the same species is known as variation. Traits are specific characteristics, phenotype is the physical expression of an organism's genetic makeup, and mutation is a change in the DNA sequence. Variation, on the other hand, refers to the differences in characteristics among individuals of the same species. Therefore, the correct answer is 'variation'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2011>53", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "Which of the following statements best describes protein synthesis?", "images": [], "options": {"A": "DNA is directly involved in translation", "B": "Translocation of the ribosomes exposes a new codon for base pairing with an amino acid", "C": "Each tRNA with a particular anticodon always carries a different protein in the process.", "D": "One amino acid is always carried by more than one tRNA"}, "answer": "B", "explanation": "Protein synthesis is a two-step process that includes transcription and translation. During translation, the ribosome moves along the mRNA, which is a process known as translocation. This exposes a new codon for base pairing with an amino acid. Therefore, the statement 'Translocation of the ribosomes exposes a new codon for base pairing with an amino acid' best describes protein synthesis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>54", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "If a person has two alleles of the sickle cell anaemia gene, the person", "images": [], "options": {"A": "is a heterozygous carrier of the disease", "B": "is immune to the disease and cannot pass on it on to an offspring.", "C": "has the disease", "D": "is probably of Asian ancestry"}, "answer": "C", "explanation": "Sickle cell anaemia is a genetic disease that is caused by the presence of two sickle cell genes. If a person has two alleles of the sickle cell anaemia gene, it means that the person has the disease. Therefore, the statement 'has the disease' is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>55", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "What is the probability of a man of blood group AB married to a woman of blood group O producing a child of blood group O?", "images": [], "options": {"A": "0%", "B": "25%", "C": "50%", "D": "75%"}, "answer": "A", "explanation": "The probability is 0. In genetics, blood type gene has two alleles, each allele has genotype A, B or O. The A and B are dominant, and O is recessive. So allele A combined with allele O is type A. Similarly, BO is type B, AA is type A, BB is type B, OO is type O, and AB is type AB.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>56", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "A man with blood group IAIA is married to a woman with blood group IAIO. The blood group of their son is likely to be", "images": [], "options": {"A": "A", "B": "0", "C": "B", "D": "AB"}, "answer": "A", "explanation": "The man with blood group IAIA can only pass on an A allele to his offspring. The woman with blood group IAIO can pass on either an A or O allele. Therefore, their son could either be blood group A (IAIA or IAi) or blood group O (ii), but not B or AB. The most likely blood group is A, because there are two ways to get this (IAIA or IAi), compared to only one way to get blood group O (ii).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>57", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Natural selection is a consequence of", "images": [], "options": {"A": "distribution of organisms", "B": "adverse conditions", "C": "variation in organisms", "D": "inbreeding"}, "answer": "C", "explanation": "Natural selection is a consequence of variation in organisms. This is because natural selection is a process where organisms that are better adapted to their environment tend to survive and produce more offspring. This is based on the variations that exist within a species, where some individuals are more adapted to the environment than others. The individuals with the beneficial traits are more likely to survive and pass on these traits to the next generation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>58", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Which of the following components of Larmark's theory of evolution is considered faulty?", "images": [], "options": {"A": "Individuals of the same species growing under different environmental conditions differ from each other", "B": "Use of certain organs results in development of those parts", "C": "Unused organs degenerate", "D": "Changes that result in individuals of the same species are transmitted to offspring"}, "answer": "B", "explanation": "Due to unfavourable and adverse conidition situation of survival of thee fittest come up which leads to natural selection", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>59", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "A vestigial in humans is", "images": [], "options": {"A": "earlobe", "B": "toe bone", "C": "tail bone", "D": "spleen"}, "answer": "C", "explanation": "A vestigial structure is an anatomical feature that no longer seems to have a purpose in the current form of an organism of the given species. The tail bone, or coccyx, in humans is a vestigial structure. It is the remnant of a lost tail, all that remains of the tail that most mammals still use.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2011>60", "subject": "Biology", "year": "2011", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "Adenine pairs with Thymine because", "images": [], "options": {"A": "the two occur in the same nucleic acid", "B": "one is a strong base and the other a weak base", "C": "two purine bases easily pair up", "D": "one is purine base and the other a pyrimidine"}, "answer": "D", "explanation": "In DNA, adenine (A) forms a base pair with thymine (T). This is because adenine is a purine and thymine is a pyrimidine, and their molecular structures allow them to bond together with hydrogen bonds. Purines and pyrimidines are the two types of nitrogenous bases found in nucleic acids. Purines are larger, two-ring compounds, and pyrimidines are smaller, one-ring compounds. This size complementarity allows for a purine to always pair with a pyrimidine, which ensures consistent distance between DNA strands in a double helix and thus its structural stability.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>1", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "The science of life is referred to as", "images": [], "options": {"A": "Anatomy", "B": "Biology", "C": "Ecology", "D": "phylogeny"}, "answer": "B", "explanation": "Biology is the scientific study of life and living organisms. It involves the study of structure, function, growth, origin, evolution, and distribution of living organisms. The other options do not accurately define the science of life. Anatomy is the study of the structure of organisms and their parts; ecology is the study of the interactions between organisms and their environment; and phylogeny is the study of the evolutionary history and relationships among individuals or groups of organisms.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2012>2", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The epidermis of a leaf is considered an example of a tissue because the cells", "images": [], "options": {"A": "allow sunlight to pass through", "B": "are covered by waxy cuticle", "C": "all possess a similar structure and function", "D": "allow water pass through them by osmosis"}, "answer": "C", "explanation": "A tissue is a group of cells that have a similar structure and act together to perform a specific function. In the case of the epidermis of a leaf, the cells all possess a similar structure and function, which is to protect the leaf and prevent water loss. The other options are characteristics of the epidermis but do not explain why it is considered a tissue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>3", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "The organism at the organ organisation of life is", "images": [], "options": {"A": "Euglena", "B": "Spirogyra", "C": "Ginger", "D": "Tapeworm"}, "answer": "C", "explanation": "Euglena and Spirogyra are at the cellular level of organisation    Ginger is an advanced plant which at the organ level of organization.    Tapeworm has organ and organ system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>4", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "The disadvantage of complexity of organisation in the higher organisms is that it leads to", "images": [], "options": {"A": "mutual interdependence between component cells", "B": "internal structural specialization", "C": "increased adaptation to environment", "D": "slower rate of diffusion of oxygen to individual cells"}, "answer": "D", "explanation": "The complexity of organization in higher organisms does lead to a slower rate of diffusion of oxygen to individual cells. This is because in complex organisms, cells are not in direct contact with the external environment, and oxygen has to travel a longer distance to reach each cell. This is not a disadvantage per se, as complex organisms have developed efficient circulatory systems to overcome this. However, among the given options, this is the most accurate. The other options are not disadvantages but rather characteristics or advantages of complex organisms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>5", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "In which of the following multicellular organisms is interdependence of cells maintained?", "images": [], "options": {"A": "Spirogyra", "B": "Volvox", "C": "Endocrine", "D": "Pandorina"}, "answer": "B", "explanation": "Interdependence of cells is maintained in Volvox. Volvox is a type of green algae that forms spherical colonies of up to 50,000 cells. They live in a variety of freshwater habitats, and were among the first examples of multicellular organisms. Each cell in a Volvox colony is interconnected to other cells by strands of cytoplasm, allowing them to coordinate their movements and function as a single organism. Spirogyra is a filamentous green algae, but it does not form colonies like Volvox. Endocrine is a system in animals, not a multicellular organism. Pandorina is a green algae that forms colonies, but the cells are not as interconnected as in Volvox.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>6", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "Which of the following processes occurs in the second phase of meiosis?", "images": [], "options": {"A": "Homologous chromosomes separate", "B": "Two daughter cells are formed", "C": "Fertilization occurs", "D": "Segregation of genes occurs"}, "answer": "A", "explanation": "The second phase of meiosis is called meiosis II, which is similar to mitosis. In this phase, the sister chromatids of each chromosome separate and move to opposite poles of the cell. This is what is referred to as 'Homologous chromosomes separate'. The other options are incorrect. Two daughter cells are formed at the end of meiosis I, not II. Fertilization is not a part of meiosis, it is a separate process that can follow meiosis in sexual reproduction. Segregation of genes occurs in the first phase of meiosis (meiosis I), not the second.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2012>7", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "The muscle cell fluid of an athlete was tested immediately after a 100m race and was found to contain a high concentration of lactic acid. Explain what could have caused this. The", "images": [], "options": {"A": "athlete must have eaten food containing lactic acid just before the race", "B": "athlete must have injected lactic acid into his blood just before the race", "C": "athlete's muscle must have carried out anaerobic respiration during the race", "D": "athlete must have inhaled lactic acid from the environment during the race"}, "answer": "C", "explanation": "During intense physical activity like a 100m race, the body's demand for energy exceeds the oxygen supply. This causes the muscles to switch from aerobic respiration (which requires oxygen) to anaerobic respiration (which doesn't require oxygen). Anaerobic respiration in muscles produces lactic acid, which can build up in the muscle cells, causing the high concentration observed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>8", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING", "question": "The graph beside represents the growth pattern of an animal. Which of the following groups of animals shows this pattern of growth?", "images": ["Biology/imgs/2012/bio1208.png"], "options": {"A": "Cestoda", "B": "Reptila", "C": "Amphibia", "D": "Insecta"}, "answer": "D", "explanation": "Insecta shows this pattern of growth. Growth in insects is usually regular.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2012>9", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "The pulmonary circulation involves movement of the blood to and from the", "images": [], "options": {"A": "brain", "B": "kidneys", "C": "liver", "D": "lungs"}, "answer": "D", "explanation": "Pulmonary circulation is the portion of the cardiovascular system which carries deoxygenated blood away from the heart, to the lungs, and returns oxygenated (oxygen-rich) blood back to the heart.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2012>10", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "The table below shows the blood composition of four individuals.  Blood Composition/IndividualPlasmaRed blood cellsWhite blood cellsPlateletsI NormalNormalHighNormalIINormalNormalNormalNormalIIINormalNormalLowNormalIVNormalNormalNormalLow   Use the information contained in the table to answer this question    Which of the individuals is likely to be suffering from haemophilia?", "images": [], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "D", "explanation": "When the blood platelets in an organism is low, the blood clots slowly.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2012>11", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH", "question": "The table below shows the blood composition of four individuals.  Blood Composition/IndividualPlasmaRed blood cellsWhite blood cellsPlateletsI NormalNormalHighNormalIINormalNormalNormalNormalIIINormalNormalLowNormalIVNormalNormalNormalLow   Use the information contained in the table to answer this question  Which of the individuals is likely to have HIV?", "images": [], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "C", "explanation": "III. A person with low white blood cells won't have enough lymphocytes to fight against infections and they will be prone to many illnesses including HIV.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>12", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "A student dissecting an animal specimen discovered that it had two auricles and one ventricle. The animal is likely to be a/an", "images": [], "options": {"A": "fish", "B": "reptile", "C": "amphibian", "D": "bird"}, "answer": "C", "explanation": "The heart of an amphibian has two auricles and one ventricle. The two auricles receive blood from the two different sources (the body and the lungs/gills), while the single ventricle pumps the blood out of the heart. This is different from the hearts of fish (which have one auricle and one ventricle) and reptiles and birds (which have two auricles and two ventricles).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>13", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "The diagrams above are parts of a human lung. Which of the labelled parts is diagram Z taken from?", "images": ["Biology/imgs/2012/bio1213.png"], "options": {"A": "II", "B": "III", "C": "IV", "D": "V"}, "answer": "C", "explanation": "The labelled part IV is where diagram Z is taken fromIV.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>14", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "The diagram beside is an illustration of the human excretory system. Which of the labelled parts contains the highest amount of nitrogenous waste?", "images": ["Biology/imgs/2012/bio1214.png"], "options": {"A": "I", "B": "II", "C": "IV", "D": "VI"}, "answer": "A", "explanation": "The part labelled I contains the highest amount of nitrogenous waste", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>15", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "Increasing adrenaline content of the blood would be expected to decrease the flow of blood to the", "images": [], "options": {"A": "liver", "B": "heart", "C": "lungs", "D": "brain"}, "answer": "B", "explanation": "Adrenaline: it prepares the body for fright, decreases the rate at which blood flows to the heart.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>16", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "The following are all examples of a simple reflex action except", "images": [], "options": {"A": "swallowing", "B": "sneezing", "C": "walking", "D": "blinking"}, "answer": "C", "explanation": "- Walking is usually done in a way which is not rapid.    - Walking is a voluntary action that we think about first before doing.    - Walking  usually  involves numerous neurones.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2012>17", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "Impulses are conducted towards the nerve cell through the", "images": [], "options": {"A": "myelin sheath", "B": "dendrons", "C": "axons", "D": "synaptic nodes"}, "answer": "B", "explanation": "In a neuron, impulses are conducted towards the nerve cell through the dendrites (also known as dendrons). The dendrites are the branched projections of a neuron that act to propagate the electrochemical stimulation received from other neural cells to the cell body, or soma, of the neuron from which the dendrites project. The myelin sheath, axons, and synaptic nodes are involved in the transmission of the impulse away from the cell body.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>18", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The function of the convex lens in the correction of eye defects is to", "images": [], "options": {"A": "diverge light rays from far objects to focus image on the retina", "B": "converge light rays to focus image behind the retina", "C": "converge light rays to focus the image before the retina", "D": "converge light rays from far objects to focus their image on the retina"}, "answer": "D", "explanation": "The convex lens is used in the correction of long sightedness in order for light rays to converge from far objects and focus their image on the retina.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>19", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "Which of the following parts of the eye contains light sensitive cells?", "images": [], "options": {"A": "Choroids", "B": "Iris", "C": "Retina", "D": "Lens"}, "answer": "C", "explanation": "The retina is the part of the eye that contains light-sensitive cells. These cells, known as photoreceptors, convert light into electrical signals that can be interpreted by the brain. There are two types of photoreceptors: rods, which are sensitive to low light levels and provide black-and-white vision, and cones, which are responsible for color vision and detail. The other options, the choroids, iris, and lens, do not contain light-sensitive cells.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>20", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "The hair on the human skin will stand erect when the person is", "images": [], "options": {"A": "in an air-conditioned room", "B": "strolling in the sun", "C": "taking a hot drink", "D": "doing strenuous exercise"}, "answer": "A", "explanation": "A fall in body temperature stimulates the following processes to produce and conserve heat    - Vasoconstriction    - Sweating (little)    - Increasing metabolic rate    - Raising Hairs", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2012>21", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "When fertilization occurs that leads to formation of a zygote, which of the following processes takes place?", "images": [], "options": {"A": "The tail of the sperm fuses with the egg cell", "B": "Both tail and head of the sperm fuse with the egg cell", "C": "The nucleus of the sperm fuses with the egg cell", "D": "The egg cell develops on its own without the sperm"}, "answer": "C", "explanation": "During fertilization, the nucleus of the sperm cell fuses with the nucleus of the egg cell to form a zygote. The tail of the sperm does not fuse with the egg cell, it only helps the sperm to move towards the egg. The head of the sperm contains the nucleus which carries the genetic material. Therefore, the correct answer is that the nucleus of the sperm fuses with the egg cell.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>22", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "Which of the following structures in a flower develops into the seed?", "images": [], "options": {"A": "Testa", "B": "Integument", "C": "Ovule", "D": "Ovary"}, "answer": "C", "explanation": "In a flower, the ovule develops into the seed after fertilization. The ovule is the part of the ovary of the seed plant where the egg cell is formed. After fertilization, the ovule develops into a seed. The other options are incorrect because the testa and integument are parts of the seed, not the structures that develop into the seed, and the ovary develops into the fruit, not the seed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2012>23", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "An illustration of a human male reproductive system is shown beside. Which of the labelled parts can be cut to ensure permanent sterility?", "images": ["Biology/imgs/2012/76MX8E.jpg"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "B", "explanation": "The vas deferens could be cut to ensure permanent sterility.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>24", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "EVOLUTION : ADAPTIVE COLOURATION", "question": "The brightly coloured petals in some plants is an adaptive colouration for", "images": [], "options": {"A": "feeding", "B": "pollination", "C": "dispersal", "D": "shedding"}, "answer": "B", "explanation": "The brightly coloured petals in some plants are an adaptive colouration for pollination. The bright colours attract pollinators like bees, butterflies, and birds, which then transfer pollen from the male parts of the flower to the female parts, facilitating fertilization. The other options are incorrect because the petals do not play a direct role in feeding, dispersal, or shedding.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>25", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "Squirrels easily kill some trees because", "images": [], "options": {"A": "they inject poisonous substances into the trees", "B": "most trees are susceptible to squirrels bites", "C": "they feed voraciously on the roots.", "D": "they gnaw the bark and destroy them"}, "answer": "D", "explanation": "Squirrels can cause damage to trees by gnawing on their barks. This can lead to the tree's death as the bark serves as a protective layer for the tree. When this layer is damaged, it exposes the tree to diseases and pests. The other options are incorrect because squirrels do not inject poisonous substances into trees, not all trees are susceptible to squirrel bites, and squirrels do not feed on tree roots.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>26", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The major role played by accessory pigments during photosynthesis is to", "images": [], "options": {"A": "add colour to plants but not to trap light energy", "B": "trap light energy that chlorophyll cannot absorb", "C": "transfer energy from chlorophyll to other pigments", "D": "prevent chlorophyll from absorbing unnecessary light"}, "answer": "B", "explanation": "Accessory pigments, such as carotenoids and phycobilins, absorb light wavelengths that chlorophyll cannot absorb effectively. This broadens the range of light wavelengths that can be utilized for photosynthesis, thereby increasing the overall efficiency of light energy capture by the plant.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>27", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The main raw materials required for photosynthesis are", "images": [], "options": {"A": "oxygen and water", "B": "oxygen and carbon dioxide", "C": "oxygen and chlorophyll", "D": "carbon dioxide and water"}, "answer": "D", "explanation": "Photosynthesis is the process by which green plants and some other organisms use sunlight to synthesize foods with the help of chlorophyll pigments. The main raw materials for photosynthesis are carbon dioxide and water. Carbon dioxide is obtained from air through the stomata while water is obtained from the soil through the roots.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2012>28", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "What is the benefit of thunder and lightening to farmers?", "images": [], "options": {"A": "Addition of nitrates to the soil", "B": "Aeration of the soil", "C": "Removal of harmful bacteria from the soil", "D": "Addition of rain water to the soil"}, "answer": "A", "explanation": "During a thunderstorm, the high temperatures and pressure caused by lightning cause the nitrogen in the air to react with oxygen, forming nitrates. These nitrates are then carried to the ground by rainwater, enriching the soil with nitrogen. This process is beneficial to farmers as nitrogen is a vital nutrient for plant growth.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>29", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following substances must be present in the soil for growth of a healthy green plant?", "images": [], "options": {"A": "Amino Acids", "B": "Carbon", "C": "Glucose salts", "D": "Magnesium ions"}, "answer": "D", "explanation": "Magnesium ions must be present in the soil for the growth of a healthy green plant. Magnesium is a vital nutrient for plants as it is a part of chlorophyll, the compound that plants use for photosynthesis to produce food. It is also used in the creation of DNA, RNA and proteins. The other options, Amino Acids, Carbon, and Glucose salts, while important, are not necessarily required from the soil as plants can produce or obtain them through other means.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2012>30", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "The purpose of proteins in the diet of a mammal is to", "images": [], "options": {"A": "promote growth and repair cells", "B": "break down molecules", "C": "regulate the flow of chyme", "D": "serve as co-factors for enzymes"}, "answer": "A", "explanation": "The purpose of proteins in the diet of a mammal is to promote growth and repair cells. Proteins are essential nutrients for the human body. They are one of the building blocks of body tissue and can also serve as a fuel source. As a fuel, proteins provide as much energy density as carbohydrates. The other options, while related to functions of proteins, are not the primary purpose of proteins in the diet of a mammal.  Protein can be found in foods like:    seafood.  eggs.  lean meat.  beans.  peas.  nuts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>31", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Excess carbohydrates can be stored in the muscles in the form of", "images": [], "options": {"A": "cellulose", "B": "glycogen", "C": "Chitin", "D": "lipids"}, "answer": "B", "explanation": "Excess carbohydrates in the body are stored as glycogen in the liver and muscles. Glycogen is a form of energy storage readily available for use by the body when needed. It is not stored as cellulose or chitin as these are structural components of plant and fungal cells respectively, and not used for energy storage in humans. Lipids are a form of long-term energy storage but are not the primary form of carbohydrate storage.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2012>32", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "The bones of the legs of a six year old boy are observed to be weak and crooked. Which of the following elements were deficient in his mother's diet at pregnancy?", "images": [], "options": {"A": "Sodium and Iron", "B": "Iron and manganese", "C": "Calcium and phosphorus", "D": "Magnesium and sulphur"}, "answer": "C", "explanation": "The bones of a six-year-old boy being weak and crooked indicates a deficiency in calcium and phosphorus. These two elements are essential for bone health and development. Calcium is the main component of bones and teeth, and phosphorus works with calcium to build strong bones and teeth. Deficiencies in these nutrients can lead to bone deformities. Sodium, iron, manganese, magnesium, and sulphur, while important for other bodily functions, are not primarily responsible for bone health.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>33", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION", "question": "The diagram beside is an illustration of an experimental set-up to test the action of yeast. What test would be used to confirm the nature of the gas given off  at I?", "images": ["Biology/imgs/2012/bio1233.png"], "options": {"A": "Insert a glowing splint", "B": "Pass the gas through lime water", "C": "Insert a piece of litmus paper", "D": "Smell the gas"}, "answer": "B", "explanation": "- A fermentation process will take place and which will lead to the evolution of carbon(IV)oxide.    - Lime water is a reagent that absorbs CO2", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>34", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Which of the following digestive enzymes  would be greatly affected if the liver fails to produce bile?", "images": [], "options": {"A": "Amylase", "B": "Cellulose", "C": "Lipase", "D": "Protease"}, "answer": "C", "explanation": "Bile, produced by the liver, plays a crucial role in the digestion and absorption of fats in the small intestine. The enzyme that breaks down fats (lipids) is Lipase. If the liver fails to produce bile, the activity of Lipase would be greatly affected because bile emulsifies fats, increasing the surface area for Lipase to act upon. Therefore, the digestion of fats would be greatly affected.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>35", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : FEEDING HABITS", "question": "The appropriate food to be given to the child in the picture above is", "images": ["Biology/imgs/2012/bio1235.png"], "options": {"A": "beans", "B": "garri", "C": "bread", "D": "avocado pear"}, "answer": "A", "explanation": "The child is deficient of protein; Beans is a source of protein.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2012>36", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Which of the following food substances will have little or no calorific value?", "images": [], "options": {"A": "Proteins", "B": "Carbohydrate", "C": "Lipids", "D": "Water"}, "answer": "D", "explanation": "Calorific value refers to the amount of energy that can be obtained from a substance when it is completely burned. Among the options given, water has no calorific value because it does not undergo combustion and hence does not release energy. Proteins, carbohydrates, and lipids all have calorific values as they can be metabolized to release energy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2012>37", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "A space containing a group of interactive organisms is called", "images": [], "options": {"A": "community", "B": "habitat", "C": "ecosystem", "D": "population"}, "answer": "C", "explanation": "An ecosystem refers to a community of living organisms in conjunction with the nonliving components of their environment, interacting as a system. These biotic and abiotic components are linked together through nutrient cycles and energy flows.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2012>38", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "The area around the earth where life activities go on is referred to as", "images": [], "options": {"A": "biosphere", "B": "lithosphere", "C": "habitat", "D": "ecosystem"}, "answer": "A", "explanation": "The biosphere is the global sum of all ecosystems. It can also be termed as the zone of life on Earth, a closed system (apart from solar and cosmic radiation and heat from the interior of the Earth), and largely self-regulating.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2012>39", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS", "question": "The following are abiotic components of the ecosystem except", "images": [], "options": {"A": "bacteria", "B": "topography", "C": "water", "D": "wind"}, "answer": "A", "explanation": "Abiotic components of an ecosystem are the non-living physical and chemical elements in the environment. These include elements such as sunlight, temperature, wind, water, soil and atmospheric gases. Bacteria, however, are living organisms and are therefore not considered abiotic components of an ecosystem. They are part of the biotic components which include all living organisms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>40", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS", "question": "Which of the following instruments would be most appropriate in comparing the air pressure at different places in a habitat?", "images": [], "options": {"A": "Hygrometer", "B": "Barometer", "C": "Photometer", "D": "Air pressure disc"}, "answer": "B", "explanation": "A barometer is an instrument used to measure atmospheric pressure. It can be used to forecast short term changes in the weather, to determine altitude, and to help in creating surface weather analysis maps. Therefore, it would be the most appropriate instrument for comparing the air pressure at different places in a habitat. A hygrometer measures humidity, a photometer measures light intensity, and an air pressure disc is not a recognized instrument for measuring air pressure.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>41", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Study the diagram below and use it to answer this question      The best title for the above diagram is", "images": ["Biology/imgs/2012/FYTGFP.jpg"], "options": {"A": "terrestrial food web", "B": "terrestrial food chain", "C": "aquatic food chain", "D": "aquatic food web"}, "answer": "A", "explanation": "The diagram is a food web that comprises terrestrial organisms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>42", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Study the diagram below and use it to answer this question    How many food chains are in the diagram?", "images": ["Biology/imgs/2012/FYTGFP.jpg"], "options": {"A": "Three", "B": "Four", "C": "Five", "D": "Six"}, "answer": "C", "explanation": "We have 5 food chains in the food web    1. Grass → Grasshopper → Toad → Snake → Hawk → Man    2. Grass → Grasscutter → Man    3. Grass → FieldMouse → Snake → Hawk → Man    4. Grass → Goat → Lion → Man    5. Grass → FieldMouse → Hawk → Man.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>43", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "Plants with breathing roots are characteristic features of vegetation in", "images": [], "options": {"A": "tropical grassland", "B": "temperature grassland", "C": "salt water swamp", "D": "tropical rain forest"}, "answer": "C", "explanation": "Breathing roots, also known as pneumatophores, are a type of root that protrudes above the ground in some plant species. They are found in swampy or marshy environments where the soil is waterlogged and oxygen levels are low. These roots grow upwards out of the water or ground to access the oxygen in the air. This is a characteristic feature of vegetation in salt water swamps.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>44", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "Study the diagram of the zones of a marine habitat below and use it to answer this question      In which of the zones can very few organisms be found?", "images": ["Biology/imgs/2012/HFJPRG.jpg"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "D", "explanation": "IV is called the benthic zone, which is characterised with the presence of cold dark waters with very few living organisms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>45", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Study the diagram of the zones of a marine habitat below and use it to answer this question    Which of the following factors exerts a major effect on the distribution of living organisms in the habitat?", "images": ["Biology/imgs/2012/HFJPRG.jpg"], "options": {"A": "Salt", "B": "pH", "C": "Light", "D": "Rainfall"}, "answer": "C", "explanation": "Light is necessary for photosynthesis, a process that is vital for life on Earth. Since plants cannot grow in the absence of light, it affects their distribution. This inturn affects the distribution of organisms that are directly or indirectly associated with the green plants.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>46", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE", "question": "The use of water closet and septic tanks is preferred to use bucket and pit latrines because", "images": [], "options": {"A": "it is cost effective", "B": "contaminated faeces are completely kept away from flies", "C": "the water for flushing contains chlorine which kills germs", "D": "it prevents flies from breeding"}, "answer": "B", "explanation": "The use of water closets and septic tanks is preferred to bucket and pit latrines because they are more sanitary. In these systems, human waste is flushed away with water into a septic tank, where it is stored and broken down by bacteria. This keeps the waste completely isolated from the environment, preventing flies from coming into contact with it and spreading diseases. Therefore, the statement that 'contaminated faeces are completely kept away from flies' is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>47", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : PUBLIC HEALTH", "question": "The detection of vibro cholera in public drinking water is a sign of", "images": [], "options": {"A": "clean water", "B": "outbreak of disease", "C": "water pollution", "D": "decayed organisms in the water"}, "answer": "C", "explanation": "Vibrio cholerae is a bacterium that causes cholera. It is usually found in water or food sources that have been contaminated by feces from a person infected with cholera. Hence, the detection of Vibrio cholerae in public drinking water is a sign of water pollution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>48", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION", "question": "Which of the following factors would be least likely to act as a density dependent limiting factor in a population of mice?", "images": [], "options": {"A": "Build up of waste products", "B": "Predation", "C": "Parasitism", "D": "Unfavourable climate"}, "answer": "C", "explanation": "Parasitism would least act as a density dependent limiting factor", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>49", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "The primary cause of species endangerment is", "images": [], "options": {"A": "disappearing habitats", "B": "increase in temperatures", "C": "acid rain", "D": "exposure to hazardous wastes"}, "answer": "A", "explanation": "The primary cause of species endangerment is disappearing habitats. This is because when habitats disappear, species lose their homes and the resources they need to survive, such as food, water, and shelter. This can lead to a decrease in population size and eventually, endangerment. The other options, while they can contribute to species endangerment, are not the primary cause.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>50", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "The following pairs of traits are examples of continuous and discontinuous variations respectively except", "images": [], "options": {"A": "eye colour and body weight", "B": "height and blood group", "C": "skin colour and fingerprints", "D": "body weight and tongue rolling"}, "answer": "A", "explanation": "Continuous variation is a type of variation that has no limit on the value that can occur within a population. Examples include height, weight. Discontinuous variation is a type of variation in which an individual either has a characteristic or they do not. Examples include blood group, tongue rolling. Eye colour is an example of discontinuous variation, not continuous.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>51", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of the following statement is true about the ABO blood group system?", "images": [], "options": {"A": "Antigens are located on the surface of white blood cells", "B": "Antibodies are located in the blood plasma", "C": "Antibodies are located on the surface of red blood cells", "D": "Antigens are located in the blood plasma"}, "answer": "B", "explanation": "In the ABO blood group system, antigens are located on the surface of red blood cells, not white blood cells or in the plasma. These antigens are what determine a person's blood type (A, B, AB, or O). Antibodies, on the other hand, are located in the blood plasma. They are proteins that the immune system uses to identify and neutralize foreign objects, such as bacteria and viruses. If a person with type A blood (which has type A antigens) were to receive type B blood (which has type B antigens), their immune system would recognize the type B antigens as foreign and would attack them with antibodies. This is why it's important to match blood types for transfusions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>52", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "The classes of fingerprints in man are", "images": [], "options": {"A": "whorl, alternate, opposite and compound", "B": "compound, loop, whorl and alternate", "C": "whorl, arch, compound and loop", "D": "arch, simple, compound and opposite"}, "answer": "C", "explanation": "The three basic classes of fingerprints are loops, whorls, and arches. These categories are based on the patterns that the ridges on the fingertips make. Loops have one or more ridges entering from one side, curving, then going out on the same side they came in. Whorls have one or more ridges making a complete circuit. Arches have ridges that enter on one side and exit on the other. The option 'whorl, arch, compound and loop' is the closest to the correct answer, although 'compound' is not a standard category of fingerprint. It's possible that 'compound' is being used here to refer to fingerprints that have characteristics of more than one category.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2012>53", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "Which of the following diseases is transmittable through genes?", "images": [], "options": {"A": "HIV/AIDS", "B": "Sickle cell anaemia", "C": "Diabetic", "D": "Presbyopia"}, "answer": "B", "explanation": "Sickle cell anaemia is a genetic disease that is passed down through families in which red blood cells form an abnormal crescent shape. It is caused by an abnormal type of hemoglobin called hemoglobin S. Hemoglobin is a protein inside red blood cells that carries oxygen. It is not a disease that is transmitted through contact or environment but through genes from parents to offspring.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>54", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "Two plants with red flowers were back crossed, which of the following results indicate that the plants are heterozygous red flowers, where red flowers are dominant?", "images": [], "options": {"A": "75% red and 25% white", "B": "50% red and 50%white", "C": "100% white", "D": "100% red"}, "answer": "A", "explanation": "In genetics, a backcross (BC) is a cross between a hybrid and one of its parents or an individual genetically similar to its parent. If two heterozygous (Rr) plants (where R represents the dominant red allele and r represents the recessive white allele) are crossed, the expected phenotypic ratio would be 75% red and 25% white. This is because three out of the four possible combinations (RR, Rr, rR) would result in red flowers, while only one combination (rr) would result in white flowers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>55", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "In the structure of DNA, which of the following statements is true?", "images": [], "options": {"A": "The double helix are held together by covalent bonds", "B": "Nucleotide is made up of ribose, phosphate and an organic nitrogen compound", "C": "Guanine is the opposite of cytosine", "D": "Adenine is the opposite of cytosine"}, "answer": "C", "explanation": "In the structure of DNA, the statement 'Guanine is the opposite of cytosine' is true. This is because in the DNA structure, the nitrogenous bases pair up in a specific way: Adenine (A) pairs with Thymine (T), and Guanine (G) pairs with Cytosine (C). This is known as complementary base pairing. The other options are incorrect. The double helix in DNA is held together by hydrogen bonds, not covalent bonds. Nucleotides in DNA are made up of deoxyribose, not ribose. Adenine is not the opposite of cytosine; it pairs with thymine.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>56", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "In a case of complete dominance, what is the phenotypic ratio of the cross Bb x Bb; where B = black and b = white?", "images": [], "options": {"A": "1 black : 1 grey : 2 whites", "B": "1 black : 3 whites", "C": "1 black : 2 blues : 1 white", "D": "3 blacks : 1 white"}, "answer": "D", "explanation": "In a case of complete dominance, the phenotypic ratio of the cross Bb x Bb is 3 blacks : 1 white. This is because in a Punnett square for this cross, three of the four possible combinations (BB, Bb, and bB) would result in the dominant phenotype (black), while only one combination (bb) would result in the recessive phenotype (white). The other options do not correctly represent the phenotypic ratio for this cross.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>57", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "Two yellow-flowered hybrid plants each carrying a recessive factor for flowers with green colour were crossed. Which of the following ratios shoes the correct proportion of offspring that have green flowers?", "images": [], "options": {"A": "2 in 2", "B": "1 in 3", "C": "1 in 4", "D": "1 in 5"}, "answer": "C", "explanation": "This is a classic Mendelian genetics problem. When two heterozygous (hybrid) organisms are crossed, the offspring will exhibit a 3:1 ratio of dominant to recessive traits. In this case, the yellow flower color is dominant and the green color is recessive. Therefore, 1 in 4 offspring will have green flowers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2012>58", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "What name is given to a sudden change in a gene or chromosome?", "images": [], "options": {"A": "Allele", "B": "Genotype", "C": "Mutation", "D": "Phentype"}, "answer": "C", "explanation": "Mutation is the changing of the structure of a gene, resulting in a variant form which may be transmitted to subsequent generations, caused by the alteration of single base units in DNA, or the deletion, insertion, or rearrangement of larger sections of genes or chromosomes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2012>59", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE", "question": "Bees are of great importance to the farmer because they", "images": [], "options": {"A": "provide him with honey", "B": "pollinate flowers", "C": "sting crop pest to death", "D": "destroy flowers by sucking nectar from them"}, "answer": "B", "explanation": "Bees are of great importance to farmers because they help in the pollination of flowers. Pollination is the transfer of pollen from the male parts of a flower to the female parts of a flower of the same species, which results in fertilization and the production of seeds. Bees, as they move from flower to flower in search of nectar, inadvertently carry pollen on their bodies and thus aid in this process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2012>60", "subject": "Biology", "year": "2012", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Which of the following sequences is the correct evolutionary trend in plants?", "images": [], "options": {"A": "Algae → Liverworts → mosses → ferns", "B": "Liverwort → mosses  → ferns → algae", "C": "Mosses → algae → ferns →liverworts", "D": "Ferns → liverworts → mosses → algae"}, "answer": "A", "explanation": "Algae are thallophytes which has simple structure than the liverworts and moss which are bryophytes. It should be noted that ferns are trichophytes  (Vascular plants) which tend to be more complex than algae and bryophytes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>1", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "In which of the following levels of classification are the members most similar?", "images": [], "options": {"A": "Order", "B": "Genus", "C": "Species", "D": "Phylum"}, "answer": "C", "explanation": "In the hierarchy of biological classification, species is the lowest and most specific level. Members of the same species are the most similar to each other because they share the most characteristics and can interbreed to produce fertile offspring. Therefore, the members are most similar at the species level.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2013>2", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "Use the diagram below to answer this question       The diagram represents a", "images": ["Biology/imgs/2013/BDFW36.jpg"], "options": {"A": "cell", "B": "filament", "C": "colony", "D": "part of a living organism"}, "answer": "B", "explanation": "The diagram represents a filament. The organism is spirogyra", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>3", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "Use the diagram below to answer this question     Pyrenoid is present in the structure labelled", "images": ["Biology/imgs/2013/BDFW36.jpg"], "options": {"A": "IV", "B": "III", "C": "II", "D": "I"}, "answer": "A", "explanation": "Pyrenoid is present in the structure labelled IV. Pyrenoid(IV) is used in the storage of starch.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>4", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "Spirogyra is regarded as a multicellular plant because", "images": [], "options": {"A": "the cylindrical cells are linked end to end.", "B": "its cells are linked together by cytoplasmic strands", "C": "its cells are large", "D": "it is an algae containing a large vacuole."}, "answer": "A", "explanation": "Spirogyra is considered a multicellular plant because its cylindrical cells are linked end to end, forming filamentous chains. This arrangement allows for the sharing of nutrients and other substances, which is a characteristic of multicellular organisms. The other options do not accurately describe why Spirogyra is considered multicellular.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>5", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which of the following pairs of structures in living organisms do not perform similar functions?", "images": [], "options": {"A": "Lungs and spiracles", "B": "Root hairs and mammalian hairs", "C": "Feathers and scales", "D": "Contractile vacuole and kidneys"}, "answer": "B", "explanation": "Contractile vacuole and kidneys are osmoregulators    Lungs and Spiracles are used in respiration    Feathers and scales are used in the covering of the skin of vertebrates.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>6", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following sequences is the correct arrangement of tissues in the anatomy of a young dicotyledonous stem from the inside to the outside?", "images": [], "options": {"A": "Pith, Phloem, cambium, xylem, parenchyma, collenchyma and epidermis", "B": "Xylem, phloem, cambium, cortex, endodermis, collenchyma and epidermis", "C": "Pith, xylem, cambium, phloem, collenchyma, parenchyma and epidermis", "D": "Phloem xylem, cambium, cortex, endodermis, collenchyma and epidermis"}, "answer": "C", "explanation": "Pith → Xylem → Cambium → Phloem → Collenchyma → Parenchyma → Epidermis. 1. Pith: The central part of the stem, made up of parenchyma cells.  2. Xylem: Located just outside the pith, responsible for water and nutrient transport.  3. Cambium: A layer of meristematic cells between the xylem and phloem, responsible for secondary growth.  4. Phloem: Located outside the cambium, responsible for transporting food (sugars) produced by photosynthesis.  5. Collenchyma: Found just beneath the epidermis, provides structural support to the stem.  6. Parenchyma (Cortex): A layer of cells between the vascular tissues (xylem and phloem) and the epidermis, often involved in storage and photosynthesis.  7. Epidermis: The outermost layer, providing protection to the stem.    This arrangement reflects the typical organization of tissues in a young dicot stem, ensuring the correct functions of support, transport, and protection are met.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>7", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "An animal which possesses scales, nares and a back bone is likely to be a", "images": [], "options": {"A": "toad", "B": "lizard", "C": "rat", "D": "bat"}, "answer": "B", "explanation": "The animal that possesses scales, nares (nostrils), and a backbone is a lizard. Scales are a type of epidermal layer found in reptiles, such as lizards. Nares are the openings of the respiratory tract, and a backbone is a characteristic of vertebrates, which includes lizards. Therefore, the correct answer is a lizard.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>8", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The opening of the guard cells of the epidermis in plants is by the process of", "images": [], "options": {"A": "osmosis", "B": "diffusion", "C": "active transport", "D": "transpiration"}, "answer": "A", "explanation": "The opening and closing of the guard cells in plants is regulated by the process of osmosis. Osmosis is the movement of water from an area of lower solute concentration to an area of higher solute concentration through a semi-permeable membrane. When water enters the guard cells, they swell and become turgid, causing the stomata to open. Conversely, when water leaves the guard cells, they become flaccid, causing the stomata to close. Therefore, the correct answer is osmosis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>9", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "What happens to a plant if the shoot tip is cut off and replaced by an agar block containing auxin? It will", "images": [], "options": {"A": "grow rapidly", "B": "continue to grow normally", "C": "stop growing", "D": "die completely"}, "answer": "B", "explanation": "Auxin is a hormone which facilitate the normal growth of plants.   Auxin is a hormone which facilitates the growth of a plant . if the shoot of a plant is cut off and replaced by an agar block containing auxin , it will grow rapidly", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2013>10", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Anaerobic respiration results in the production of", "images": [], "options": {"A": "more energy than aerobic respiration", "B": "no energy", "C": "an equal amount of energy to aerobic respiration", "D": "less energy than aerobic respiration"}, "answer": "D", "explanation": "Anaerobic respiration is a type of respiration that occurs in the absence of oxygen. It results in the production of less energy than aerobic respiration. This is because the breakdown of glucose is incomplete in anaerobic respiration, resulting in the production of lactic acid or ethanol and carbon dioxide, along with a small amount of energy. On the other hand, aerobic respiration, which occurs in the presence of oxygen, results in the complete breakdown of glucose, producing carbon dioxide, water, and a large amount of energy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2013>11", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following is not a skeletal tissue?", "images": [], "options": {"A": "Plasma", "B": "Chitin", "C": "Cartilage", "D": "Bone"}, "answer": "A", "explanation": "Skeletal tissues are tissues that provide support and structure to the body. They include bone, cartilage, and connective tissues. Plasma is not a skeletal tissue, it is a component of blood that carries cells and proteins throughout the body.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2013>12", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "Which of the following statements is not correct about the mammalian heart?", "images": [], "options": {"A": "Oxygenated blood enters the left auricle from the pulmonary vein", "B": "The walls of the ventricle are thicker than those of the auricle", "C": "Blood passes from the right ventricle to the left auricle through the aorta", "D": "The tricuspid valve prevents the back flow of blood into the right auricle"}, "answer": "C", "explanation": "In the mammalian heart, blood does not pass from the right ventricle to the left auricle through the aorta. The right ventricle pumps deoxygenated blood to the lungs via the pulmonary artery. The left auricle (or atrium) receives oxygenated blood from the lungs via the pulmonary veins. The aorta is the main and largest artery in the human body, originating from the left ventricle of the heart and extending down to the abdomen.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>13", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Which of the following structures is used for respiration in insect?", "images": [], "options": {"A": "Lungs", "B": "Thorax", "C": "Cuticle", "D": "Spiracles"}, "answer": "D", "explanation": "Insects respire through tiny tubes called tracheae. Air enters and leaves the tracheae through openings called spiracles. Hence, spiracles are used for respiration in insects.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2013>14", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Which of the following statements about the diaphragm of a mammal is not correct? It", "images": [], "options": {"A": "separates the thorax and the abdomen", "B": "is a thick layer of muscle", "C": "is made of epithelial cells.", "D": "is part of the human respiratory apparatus"}, "answer": "C", "explanation": "The diaphragm is a sheet of muscle that separates the thorax from the abdomen in mammals and is part of the respiratory system. It is not made of epithelial cells, which are cells that line the outer surfaces of organs and blood vessels, as well as the inner surfaces of cavities in many internal organs. Therefore, the statement 'is made of epithelial cells' is not correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>15", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "A substance present in the glomerular filtrate in the mammalian kidney is", "images": [], "options": {"A": "glucose", "B": "fibrinogen", "C": "albumen", "D": "blood platelets"}, "answer": "A", "explanation": "The glomerular filtrate in the mammalian kidney contains substances that are small enough to pass through the filtration membrane in the glomerulus. This includes water, glucose, amino acids, urea, and various ions. Fibrinogen, albumen, and blood platelets are too large to pass through the filtration membrane, so they are not present in the glomerular filtrate.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2013>16", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "In humans, excretion of hypertonic urine is associated with the", "images": [], "options": {"A": "Bowman's capsule", "B": "Loop of Henle", "C": "distal convoluted tubule", "D": "proximal convoluted tubule"}, "answer": "B", "explanation": "The Loop of Henle in the nephron of the kidney is responsible for the concentration of urine, making it hypertonic. This is achieved by the counter-current multiplier system, which involves the active transport of salts and passive movement of water, creating a concentration gradient in the medulla of the kidney. This gradient allows for the reabsorption of water from the collecting duct, making the urine hypertonic. The other options, Bowman's capsule, distal convoluted tubule, and proximal convoluted tubule, are not directly involved in the concentration of urine.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>17", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "The maintenance of a stable internal environment within the body of a mammal is known as", "images": [], "options": {"A": "osmosis", "B": "plasmolysis", "C": "homeostasis", "D": "excretion"}, "answer": "C", "explanation": "The maintenance of a stable internal environment within the body of a mammal is known as homeostasis. Homeostasis is the ability of an organism to maintain constant internal conditions despite changes in external conditions. It involves various biological mechanisms that work together to maintain things like body temperature, pH levels, and water balance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>18", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which part of the nephron is associated with ultra-filtration?", "images": [], "options": {"A": "Distal convoluted tubule", "B": "Proximal convoluted tubule", "C": "Collecting duct", "D": "Bowman's capsule"}, "answer": "D", "explanation": "Ultra-filtration in the kidney occurs in the Bowman's capsule. The Bowman's capsule is the initial filtering component of the nephron in the kidneys. It contains a network of capillaries, known as the glomerulus, from which waste products are filtered from the blood.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2013>19", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "Which of the following conditions would result in a decrease in the production of antidiuretic hormone?", "images": [], "options": {"A": "Abnormally high blood sugar level", "B": "Drinking large quantities of water", "C": "Increase in osmotic pressure of blood", "D": "Period of strenuous exercise"}, "answer": "B", "explanation": "Antidiuretic hormone (ADH) is a hormone that helps your kidneys manage the amount of water in your body. The hypothalamus makes a hormone called vasopressin. The nearby pituitary gland stores the vasopressin and releases it when the body is low on water. Vasopressin is also known as antidiuretic hormone (ADH). It tells your kidneys to conserve water. Drinking large quantities of water would decrease the production of ADH because the body would have an excess of water, and therefore, the need to conserve water would be reduced.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>20", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following structures is not essential in a wind pollinated flower?", "images": [], "options": {"A": "Anther", "B": "Ovary", "C": "Stigma", "D": "Petal"}, "answer": "D", "explanation": "Wind pollinated flowers are usually small, inconspicuous and without scent and nectar. They do not attract insects or birds for pollination. Therefore, they do not need petals which are usually used to attract pollinators. The anther, ovary, and stigma are all essential parts of a flower for pollination and fertilization. The anther produces pollen which is the male gamete, the stigma receives the pollen, and the ovary houses the female gamete.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2013>21", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "Study the diagram below and use it to answer this question        Which part of the flower produces the structure labelled III?", "images": ["Biology/imgs/2013/29XHWX.jpg"], "options": {"A": "Carpel", "B": "Pollen", "C": "Stigma", "D": "Anther"}, "answer": "B", "explanation": "The structure labelled III is the pollen of the flower.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>22", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "Study the diagram below and use it to answer this question      The parts labelled III  and IV respectively are called", "images": ["Biology/imgs/2013/29XHWX.jpg"], "options": {"A": "pollen tube and style", "B": "pollen grain and pollen tube", "C": "anther and filament", "D": "stigma and style"}, "answer": "C", "explanation": "When a pollen grain lands on a mature stigma of the same type of flower , it germinates to form a pollen tube.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>23", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "Study the diagram below and use it to answer this question      Which of the labelled parts would become a component of the seed after fertilization?", "images": ["Biology/imgs/2013/29XHWX.jpg"], "options": {"A": "I", "B": "II", "C": "IV", "D": "V"}, "answer": "A", "explanation": "The labelled part I would become a component of the seed after fertilization. The part labelled I is the nucleus.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>24", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The resolution of a microscope refers to its power to", "images": [], "options": {"A": "increase an object's apparent size", "B": "distinguish clearly between two objects", "C": "scan the surface of an object", "D": "focus on an object"}, "answer": "B", "explanation": "The resolution of a microscope refers to its ability to distinguish two points or objects in the microscopic field as separate entities. This is also known as the resolving power of the microscope. It does not refer to the magnification (increasing an object's apparent size), scanning the surface of an object, or focusing on an object.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2013>25", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The process by which plants manufacture food from carbon dioxide and water using energy from the sun is called", "images": [], "options": {"A": "chemosynthesis", "B": "photosynthesis", "C": "anabolism", "D": "catabolism"}, "answer": "B", "explanation": "The process by which plants manufacture food from carbon dioxide and water using energy from the sun is called photosynthesis. Chemosynthesis is a process by which some organisms, such as certain bacteria, use chemical energy to produce carbohydrates. Anabolism is the process by which the body utilizes the energy released by catabolism to synthesize complex molecules. Catabolism is the breakdown of complex molecules in the body to form simpler ones.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2013>26", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Conduction of water and mineral salts through the xylem vessels is enhanced because the xylem cells are", "images": [], "options": {"A": "thickened with lignin", "B": "long, narrow tubes placed end to end", "C": "close to the endodermis", "D": "centrally placed in the roots"}, "answer": "B", "explanation": "The xylem vessels are long, narrow tubes placed end to end. This structure allows for the efficient conduction of water and mineral salts from the roots to the rest of the plant. The xylem vessels are dead cells that lack end walls between them, creating a continuous tube for water to move up the plant.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>27", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Which of the following factors is likely to increase the rate of transpiration in plants?", "images": [], "options": {"A": "a reduction in the number of stomata per unit surface area.", "B": "Increase in humidity around the leaves of plants", "C": "An increase in leaf surface area to volume ratio", "D": "Removal of leaves from plant"}, "answer": "C", "explanation": "An increase in leaf surface area to volume ratio is likely to increase the rate of transpiration in plants. Transpiration is the process by which water is lost from the plant to the atmosphere through the stomata. The larger the surface area of the leaf, the more stomata are available for transpiration to occur, hence increasing the rate of transpiration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>28", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "The name of the enzyme that catalyses the conversion of glucose to glucose-6-phosphate at the beginning of glycolysis is", "images": [], "options": {"A": "phospho-fructokinase", "B": "glucose isomerase", "C": "hexokinase", "D": "glucose-6-kinase"}, "answer": "C", "explanation": "The enzyme that catalyses the conversion of glucose to glucose-6-phosphate at the beginning of glycolysis is hexokinase. Glycolysis is the metabolic pathway that converts glucose into pyruvate. The free energy released in this process is used to form the high-energy molecules ATP (adenosine triphosphate) and NADH (reduced nicotinamide adenine dinucleotide).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>29", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "The correct arrangement of food classes of the same quantity in the order of magnitude of energy value in animals in descending order is", "images": [], "options": {"A": "Carbohydrates, fats and oils, water, protein", "B": "Fats and oils, Carbohydrates, protein, water", "C": "Water, fats and oils, carbohydrates, protein", "D": "Protein, fats and oils, water and carbohydrates"}, "answer": "B", "explanation": "The correct arrangement of food classes of the same quantity in the order of magnitude of energy value in animals in descending order is Fats and oils, Carbohydrates, protein, water. Fats and oils provide the highest energy value, followed by carbohydrates, then proteins. Water does not provide any energy value.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>30", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Which of the following substances is not a complex carbohydrate?", "images": [], "options": {"A": "Glycogen", "B": "Cellulose", "C": "Starch", "D": "Glucose"}, "answer": "D", "explanation": "Complex carbohydrates are made up of sugar molecules that are strung together in long, complex chains. Complex carbohydrates are found in foods such as peas, beans, whole grains, and vegetables. Both glycogen, cellulose and starch are complex carbohydrates. Glucose, however, is a simple sugar and not a complex carbohydrate.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2013>31", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS", "question": "Which of the following associations is an example of epiphytism?", "images": [], "options": {"A": "Lice in the human hair", "B": "Mistletoe on citrus fruit", "C": "Egret on cow", "D": "Fern on palm tree"}, "answer": "D", "explanation": "Epiphytes are plants that grows on another, using it for physical support but obtaining no nutrient from it and neither causing damage nor offering benefit. In this view, fern is an epiphyte.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2013>32", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Study the diagrams below carefully and use them to answer this qusetion.        What is the likely food of the bird in I?", "images": ["Biology/imgs/2013/bio1333.png"], "options": {"A": "Worms", "B": "Seed", "C": "Nectar", "D": "Fishes"}, "answer": "C", "explanation": "That is a pointed beak adapted for sucking nectar usually in SUN BIRDS.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>33", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Study the diagrams below carefully and use them to answer this qusetion.       The food of the bird in II is", "images": ["Biology/imgs/2013/bio1333.png"], "options": {"A": "worms", "B": "seeds", "C": "nectar", "D": "fishes"}, "answer": "B", "explanation": "That is a ridged beak adapted for cracking nuts and seeds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>34", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS", "question": "Ecology simply means the study of", "images": [], "options": {"A": "particular species of plants and animals", "B": "the interrelationship between organisms and their environment", "C": "the properties of a habitat.", "D": "the interrelationship between plants and animals."}, "answer": "B", "explanation": "Ecology is the branch of biology that studies the interactions among organisms and their biophysical environment, which includes both biotic and abiotic components. It involves understanding the interrelationship between organisms and their environment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2013>35", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION", "question": "The maximum size of a population that a given area can support is known as", "images": [], "options": {"A": "population density", "B": "carrying capacity", "C": "population growth", "D": "maximum population"}, "answer": "B", "explanation": "The carrying capacity of an environment is the maximum population size of a biological species that can be sustained in that specific environment, given the food, habitat, water, and other resources available.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2013>36", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "The producers in a food chain in an aquatic environment are", "images": [], "options": {"A": "birds", "B": "phytoplankton", "C": "zooplankton", "D": "fishes"}, "answer": "B", "explanation": "In an aquatic environment, the primary producers are typically phytoplankton. Phytoplankton are microscopic plants that live in the ocean and other bodies of water. They are called producers because they can convert sunlight into energy through photosynthesis, just like plants on land. This energy is then used by other organisms in the food chain.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2013>37", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The frog is considered a better swimmer than the toad because it", "images": [], "options": {"A": "has more pronounced webbed digits", "B": "has much longer and stronger hind limbs", "C": "lives in water most of the time.", "D": "is more streamlined than the toad"}, "answer": "A", "explanation": "Frogs are considered better swimmers than toads primarily because of their more pronounced webbed digits. The webbing between their toes increases the surface area of their feet, allowing them to push against more water and swim more efficiently. While it's true that frogs also have longer and stronger hind limbs, and are more streamlined than toads, the primary reason for their superior swimming ability is their webbed digits.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>38", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : NITROGEN CYCLE", "question": "The bacteria that reduce nitrates in the soil into gaseous nitrogen are refered to as", "images": [], "options": {"A": "nitrifying bacteria", "B": "denitrifying bacteria", "C": "putrefying bacteria", "D": "saprophytic bacteria"}, "answer": "B", "explanation": "Denitrifying bacteria are the type of bacteria that convert nitrates in the soil into gaseous nitrogen. This process is part of the nitrogen cycle, where nitrogen is converted between its various chemical forms. This process is necessary to make the nitrogen in the atmosphere available to plants, which cannot use atmospheric nitrogen directly.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>39", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING", "question": "A pyramid of numbers is constructed by", "images": [], "options": {"A": "comparing living and non-living things", "B": "measuring productivity", "C": "conducting census", "D": "labelling the living organism"}, "answer": "C", "explanation": "A pyramid of numbers represents the number of individual organisms at each trophic level in an ecosystem. Constructing such a pyramid involves:    Conducting census: This means counting the number of organisms at each trophic level, from producers at the base to apex predators at the top. This provides a quantitative representation of the population sizes within each level.    By conducting a census, ecologists can determine the relative abundance of different species in an ecosystem and visualize the structure of the ecosystem in terms of population numbers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2013>40", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH", "question": "The main reason for immunizing children is to", "images": [], "options": {"A": "destroy pathogens in their bodies", "B": "increase the production of white blood cells", "C": "stimulate the production of antibodies", "D": "stimulate the production of antigens"}, "answer": "C", "explanation": "Immunizing the children is a form of vaccination- Introduction of vaccines into the body.    Vaccines are substances given to stimulate the body's production of antibodies.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2013>41", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS", "question": "Rhizobium which lives in the root modules of leguminous plants is an example of the association known as", "images": [], "options": {"A": "commensalism", "B": "epiphytism", "C": "mutualism", "D": "saprophytism"}, "answer": "C", "explanation": "Rhizobium is a type of bacteria that forms an association with the roots of leguminous plants such as peas, beans, and clover. This association is known as mutualism, a type of symbiotic relationship where both organisms benefit. In this case, the Rhizobium bacteria convert nitrogen in the air into a form that the plant can use, and in return, the plant provides the bacteria with sugars produced during photosynthesis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>42", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION", "question": "Ascaris lumbricoides is a parasitic", "images": [], "options": {"A": "flatworm", "B": "roundworm", "C": "arthropod", "D": "elastic worm"}, "answer": "B", "explanation": "Ascaris lumbricoides is a species of roundworm, not a flatworm, arthropod, or elastic worm. Roundworms are a type of parasitic worm that can infect the intestines of their host. They are characterized by their long, cylindrical shape, which is where their name comes from.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>43", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE", "question": "The following organisms are pests of plant except", "images": [], "options": {"A": "birds", "B": "nematodes", "C": "bacteria", "D": "rodents"}, "answer": "C", "explanation": "Bacteria are not considered pests of plants. While some bacteria can cause disease in plants, they are not typically classified as pests. Pests are organisms that cause harm or damage to plants, often by feeding on them. This includes organisms like birds, nematodes, and rodents, which can eat or damage plants.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2013>44", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION", "question": "The absence of alimentary canal in the parasitic flatworm can be attributed to the fact that", "images": [], "options": {"A": "its body does not feed", "B": "it has no enzymes", "C": "its body absorbs digested food", "D": "it has suckers on the scolex"}, "answer": "C", "explanation": "Parasitic flatworms, such as tapeworms, live in the intestines of their host and absorb nutrients directly from the host's digested food. They do not need an alimentary canal because they do not digest food themselves. Instead, they have a specialized body surface that allows them to absorb nutrients directly.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>45", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Which of the following statements is not a reason for conserving wild life?", "images": [], "options": {"A": "Attraction of tourists into the country", "B": "Serving as a source of food", "C": "Serving as a source of income", "D": "Increasing the amount of rainfall"}, "answer": "D", "explanation": "Conserving wildlife has many benefits including attracting tourists, serving as a source of food and income. However, it does not directly increase the amount of rainfall. Rainfall is determined by climatic and weather patterns, not the presence of wildlife. Therefore, the statement 'Increasing the amount of rainfall' is not a reason for conserving wildlife.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>46", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Which of the following human activities would help prevent endangered species from extinction ?", "images": [], "options": {"A": "Uncontrolled killing of the species", "B": "Regular clearing of the forest vegetation", "C": "Temporary maintenance of the species in zoological gardens", "D": "Regular irrigation of their natural habitats"}, "answer": "C", "explanation": "Endangered species can be protected from extinction by maintaining them temporarily in zoological gardens. This is because zoological gardens provide a controlled environment where these species can be protected from threats such as poaching, habitat destruction, and diseases. They also allow for breeding programs that can help increase the population of these species.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>47", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : LINKAGE, SEX DETERMINATION AND SEX LINKED CHARACTERS", "question": "In genetics, linkages refer to the linking of genes of the", "images": [], "options": {"A": "same chromosomes", "B": "different chromosomes", "C": "same nucleus", "D": "different nuclei"}, "answer": "A", "explanation": "In genetics, linkage refers to the phenomenon where genes that are located close together on the same chromosome are often inherited together. This is because during meiosis, chromosomes can exchange genetic material in a process called crossing over. However, genes that are close together are less likely to be separated by crossing over, and so they tend to be inherited together. This is known as genetic linkage.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>48", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "A man's blood group is AB. What is the probability of the man giving birth to a child with blood group O?", "images": [], "options": {"A": "0%", "B": "25%", "C": "50%", "D": "100%"}, "answer": "A", "explanation": "The chance of the man (blood group AB) giving birth to a child of blood group 0 is 0% - Not possible. A and B are dominant alleles while O is recessive.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>49", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : LINKAGE, SEX DETERMINATION AND SEX LINKED CHARACTERS", "question": "When a man who is Rh - positive marries a woman who is Rh-negative , there will be incidence of", "images": [], "options": {"A": "still births", "B": "sicklers", "C": "albinos", "D": "living children"}, "answer": "A", "explanation": "Rh factor is a type of protein on the surface of red blood cells. Most people are Rh-positive. Rh-negative people do not have this protein. Problems can occur when the mother is Rh-negative and the baby is Rh-positive. This is called Rh incompatibility. These problems usually do not occur in a first pregnancy, but they can occur in a later pregnancy. The Rh-negative mother's body will make antibodies against the Rh factor only if she is exposed to Rh-positive blood. This can happen during an earlier pregnancy with an Rh-positive baby or during some medical procedures. If the mother has made antibodies against the Rh factor, they can attack an Rh-positive baby's red blood cells. This can lead to stillbirths.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>50", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "The genotypic ratio of the offspring of a hybrid is 1:2:1, which of the following laws illustrates this ratio?", "images": [], "options": {"A": "Use and disuse", "B": "Dominance", "C": "Segregation", "D": "Linkage"}, "answer": "C", "explanation": "The genotypic ratio of 1:2:1 is a result of Mendel's law of segregation. This law states that during the formation of gametes, the two alleles responsible for a trait separate from each other. Alleles for a particular trait are then 'recombined' at fertilization, producing the genotype for the traits of the offspring.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>51", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : LINKAGE, SEX DETERMINATION AND SEX LINKED CHARACTERS", "question": "A gene that is only located on the X-chromosome is said to be", "images": [], "options": {"A": "expressed in females only", "B": "defective", "C": "sex-linked", "D": "expressed in males only"}, "answer": "C", "explanation": "A gene that is only located on the X-chromosome is said to be sex-linked. Sex-linked genes are genes that are carried on the sex chromosomes (X and Y chromosomes). In many organisms, one of the two sexes has two of the same kind of sex chromosome (XX), and the other sex has two distinct sex chromosomes (XY). Genes on the X chromosome are referred to as X-linked.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>52", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "If a boy has blood type O and his mother has blood type A, what is the genotype of his father?", "images": [], "options": {"A": "BB", "B": "AA", "C": "AO", "D": "AB"}, "answer": "C", "explanation": "If a man with genotype AO marries a woman with blood type A, the blood group of their child (son)will be O.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>53", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "A man who suffers from haemophilia marries a woman who is a carrier, what percentage of their children are likely to be haemophilic?", "images": [], "options": {"A": "25%", "B": "50%", "C": "75%", "D": "100%"}, "answer": "B", "explanation": "Haemophilia is a sex-linked recessive disorder. This means that a male (XY) only needs one copy of the haemophilia gene to have the disorder, while a female (XX) would need two copies. If the man has haemophilia, he will pass the gene to all his daughters but none of his sons. If the woman is a carrier, she has a 50% chance of passing the gene to her children. Therefore, 50% of their children (all daughters) are likely to be carriers, and 50% (all sons) are likely to have haemophilia.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2013>54", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of the following structures is only formed traits may be considered in marriage counselling?", "images": [], "options": {"A": "Height", "B": "Fingerprints", "C": "Rhesus factor", "D": "Colour of skin"}, "answer": "C", "explanation": "The Rhesus factor is a type of antigen present on the surface of red blood cells. It is important in marriage counselling because if a woman is Rh-negative and her partner is Rh-positive, their child could potentially be Rh-positive. If the Rh-negative mother's blood comes into contact with her Rh-positive baby's blood, her body will recognize the Rh-positive red blood cells as foreign and will produce antibodies against them. This can lead to Rh disease in their next Rh-positive baby, which can be fatal. Therefore, it is important to consider the Rhesus factor in marriage counselling.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2013>55", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which of the following structures is only formed during cell division in animal cells?", "images": [], "options": {"A": "Cell membrane", "B": "Cytoplasm", "C": "Centrosome", "D": "Ribosome"}, "answer": "C", "explanation": "The centrosome is a structure in animal cells containing two centrioles. It is only formed during cell division. The centrosome helps to organize microtubules and provide structure for the cell, as well as pulling chromatids apart during cell division. Therefore, the centrosome is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>56", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The function of the drone in a colony of bees is to", "images": [], "options": {"A": "clean the cells", "B": "mate with the queen", "C": "protect the colony", "D": "lay eggs"}, "answer": "B", "explanation": "The function of the drone in a bee colony is to mate with the queen. Drones are male bees, and their primary role is to fertilize the queen. They do not have stingers and do not participate in nectar and pollen gathering. A drone's only job is to wait for the emergence of a fertile queen. They do not clean cells, protect the colony, or lay eggs.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2013>57", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "EVOLUTION : ADAPTIVE COLOURATION", "question": "Which of the following features is used by chameleons to escape predation?", "images": [], "options": {"A": "Fearsome appearance", "B": "Coiling tail", "C": "Offensive smell", "D": "Adaptive coloration"}, "answer": "D", "explanation": "Chameleons use adaptive coloration to escape predation. This is a type of camouflage where the chameleon can change its skin color to match its surroundings, making it harder for predators to see them. This is a survival strategy that helps them avoid being eaten. They do not use fearsome appearance, coiling tail, or offensive smell to escape predation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>58", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "A scientist who was involved in the development of evolution theory is", "images": [], "options": {"A": "Lamarck", "B": "Mendel", "C": "Morgan", "D": "Pasteur"}, "answer": "A", "explanation": "Jean-Baptiste Lamarck was a French biologist who was one of the first to propose that evolution occurred and proceeded in accordance with natural laws. He is best known for his theory of inheritance of acquired characteristics, which was a precursor to the development of the modern theory of evolution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>59", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Darwin noticed that organisms in similar habitats across the world looked alike. This illustrates", "images": [], "options": {"A": "Convergent evolution", "B": "Adaptive radiation", "C": "Co-evolution", "D": "Descent with modification"}, "answer": "A", "explanation": "Convergent evolution is when many superficially similar looking species arise from different ancestral species.    - This is shown by organisms occupying very similar kinds of environment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2013>60", "subject": "Biology", "year": "2013", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following organs is used for gaseous exchange in a mature toad?", "images": [], "options": {"A": "Gills, lungs and eardrum", "B": "Lungs, mouth and eardrum", "C": "Mouth, skin and gills", "D": "Skin, lungs and mouth"}, "answer": "D", "explanation": "The toad has three respiratory surfaces on its body that it uses to exchange gas with the surroundings: the skin, in the lungs and on the lining of the mouth.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>1", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "The excretory product in protozoans is", "images": [], "options": {"A": "amino acids", "B": "uric acids", "C": "ammonia", "D": "urea"}, "answer": "C", "explanation": "Protozoans are simple, single-celled organisms. They excrete waste products directly into their environment. The primary waste product of protein metabolism in these organisms is ammonia. Ammonia is a toxic compound, but because protozoans live in aquatic environments, they can easily dilute and get rid of this waste product.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2014>2", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "Which of the following is a living organism?", "images": [], "options": {"A": "Muscle", "B": "Nucleus", "C": "Yeast", "D": "Mitochondria"}, "answer": "C", "explanation": "A living organism is a complex structure of interdependent and subordinate elements whose relations and properties are largely determined by their function in the whole. This includes the capacity for growth, reproduction, functional activity, and continual change preceding death. Among the options, Yeast is a living organism. It is a type of fungus that can grow on the surface of foods and drinks, and in the soil, on plants, and in the air because they are tiny, single-celled organisms.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2014>3", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "Which of the following organisms is the most specialized?", "images": [], "options": {"A": "Paramecium", "B": "Amoeba", "C": "Spirogyra", "D": "Rhizopus"}, "answer": "A", "explanation": "Paramecium is a highly specialized protozoan, with features such as:    - A fixed body shape  - A complex oral groove for food capture  - A specialized system of cilia for movement and sensing  - A well-developed contractile vacuole for osmoregulation    In contrast, the other options are less specialized:    - Amoeba is a generalist, with a flexible body shape and a simple structure.  - Spirogyra is a simple, multicellular alga with a basic filamentous structure.  - Rhizopus is a fungus with a relatively simple, multicellular structure.    Specialization in organisms often involves the development of unique features that allow them to thrive in specific environments or ecological niches. Paramecium's specialized features enable it to excel in its aquatic environment, making it the most specialized among the options.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>4", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "Active transport can be defined as the movement of", "images": [], "options": {"A": "substances from a regions of high concentration to a region of low concentration", "B": "substances from a region of low concentration to a region of high concentration to a across a living cell membrane", "C": "substances across a living cell membrane using energy from the cell.", "D": "movement of molecules in a medium"}, "answer": "C", "explanation": "Active transport is a process that moves molecules into cells even though they are moving against a concentration gradient. This process requires energy because it is moving substances from an area of lower concentration to an area of higher concentration. This is the opposite of passive transport, which uses no energy because substances move from areas of high concentration to areas of low concentration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>5", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which of the following cell inclusion can destroy other cell organelles?", "images": [], "options": {"A": "Centriole", "B": "Ribosome", "C": "Lysosome", "D": "Mitochondrion"}, "answer": "C", "explanation": "Lysosomes are small round sacs that contain digestive enzymes which break down structures and substances. They usually help in the removal of dead cells.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>6", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "In which of the following yam tissues will osmosis occur?", "images": [], "options": {"A": "Boiled and peeled", "B": "Raw and peeled", "C": "Boiled and unpeeled", "D": "Roasted and peeled"}, "answer": "B", "explanation": "Osmosis is the process by which water molecules move from an area of high concentration to an area of low concentration through a semi-permeable membrane. In the context of the question, osmosis can only occur in a yam tissue that has not been subjected to heat (boiling or roasting) and has its skin (peel) removed. This is because heat denatures the cell membrane making it impermeable to water, and the peel also acts as a barrier to water movement. Therefore, the correct answer is 'Raw and peeled'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2014>7", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL THEORY", "question": "The line XZ in the diagram below represents an actual distance of 10.0cm and the length of the diagram is 5.0cm. What  is the magnification of the diagram?", "images": ["Biology/imgs/2014/bio1407.png"], "options": {"A": "x 0.2", "B": "x 0.5", "C": "x 2.0", "D": "x 50.0"}, "answer": "B", "explanation": "Magnification = Image Length (distance) ÷ object length (distance)    M = 5cm ÷ 10cm; M = 0.5", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>8", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "The following events occur during mitosis in a cell.    I. Chromatids separate;    II. Chromosomes becomes visible;    III. Chromosomes align at the equator;   IV. Cytoplasm divides (Cytokinesis)   The correct sequence of the events is", "images": [], "options": {"A": "III, II, IV, I", "B": "II, III, I, IV", "C": "II, I, III, IV", "D": "II, IV, I, III"}, "answer": "B", "explanation": "During mitosis, 1. The chromosomes becomes conspicuous (visible)    2. The nuclear membrane disappears: a spindle forms, the chromosomes line up across the  middle of the cell and become attached to the spindle fibres at the centromeres.    3. The 'sister' chromatids are pulled apart to opposite ends (poles) of the cells as the spindle fibres contrast.    4. The cell divides into two daughter cells (cytokinesis).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>9", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "Which of the following statements about asexual reproduction is correct? It", "images": [], "options": {"A": "may involves two parent but the offsprings is always identical to one parent", "B": "always involves two parent and the offspring are  not genetically identical to the parent", "C": "always involves one parent and the offspring are genetically identical to the parent", "D": "involves two parents but the offspring is not genetically identical to any of the parents"}, "answer": "C", "explanation": "Asexual reproduction is a type of reproduction where only one parent is involved and the offspring are genetically identical to the parent. This is because the offspring are produced by a single parent without the involvement of sperm and egg. This leads to offspring that are genetically identical to the parent, also known as clones. Therefore, option 3 is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>10", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The diagram below is an illustration of a mammalian bone.     Use it to answer this question    The bone illustrated above is the", "images": ["Biology/imgs/2014/bio1410.png"], "options": {"A": "femur", "B": "humerus", "C": "radius", "D": "ulna"}, "answer": "A", "explanation": "The femur, or thigh bone, is the longest and strongest bone in the human body. It extends from the hip to the knee and plays a crucial role in supporting the body's weight and enabling leg movement. Here are some key features of the femur:  1.\tProximal End (Head)  2.\tGreater and Lesser Trochanters  3.\tShaft  4.\tDistal End  The diagram aligns with the structure of the femur.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>11", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The diagram below is an illustration of a mammalian bone.     Use it to answer this question  The function of the part labelled I is to", "images": ["Biology/imgs/2014/bio1410.png"], "options": {"A": "fit into the glenoid cavity of the scapula", "B": "fit into the acetabulum of the pelvic girdle", "C": "support the lower arm", "D": "prevent the arm from bending backwards"}, "answer": "B", "explanation": "The proximal end of the femur fits into the acetabulum. Specifically, the rounded head of the femur articulates with the acetabulum of the pelvis to form the hip joint, which is a ball-and-socket joint that allows for a wide range of motion.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2014>12", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which of the following processes is not a function of the mammalian skin?", "images": [], "options": {"A": "Regulation of body temperature", "B": "Reception of external stimuli", "C": "Excretion", "D": "Gaseous exchange"}, "answer": "D", "explanation": "The mammalian skin is not involved in gaseous exchange. Gaseous exchange, which involves the exchange of oxygen and carbon dioxide, primarily takes place in the lungs in mammals. The skin, however, is involved in the regulation of body temperature, reception of external stimuli, and excretion through sweat. Therefore, option 4 is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>13", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "The legs of an accident victim with a fractured vertebral column and injured spinal cord could not be raised because", "images": [], "options": {"A": "impulses from receptors in the legs cannot travel to the brain", "B": "impulses from the brain cannot travel to the legs", "C": "chemical substances will be released at synapses in the central nervous system", "D": "reflex actions cannot take place in the legs"}, "answer": "B", "explanation": "The spinal cord is a major pathway for information flowing back and forth between the brain and the skin, muscles, and visceral organs. It is also a center for coordinating many reflexes. If the spinal cord is injured, the flow of information (impulses) from the brain to the legs is disrupted, hence the legs cannot be raised.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>14", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "Which of the following conditions in flowering plants enhance self pollination?", "images": [], "options": {"A": "Cleistogamy", "B": "Heterostyly", "C": "Protandry", "D": "Protogyny"}, "answer": "A", "explanation": "Cleistogamy is a condition in flowering plants where flowers remain closed and self-pollinate without opening. This ensures that self-pollination occurs, enhancing the likelihood of self-fertilization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>15", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "The diagram below is an illustration of the left side of the human cerebrum.      The part labelled X controls", "images": ["Biology/imgs/2014/bio1415.png"], "options": {"A": "general memory", "B": "speech", "C": "sight", "D": "respiratory functions"}, "answer": "C", "explanation": "Based on the location marked \"X\" in the diagram, it appears to be pointing to the posterior part of the left cerebral hemisphere, which is typically associated with the occipital lobe.    The occipital lobe is primarily responsible for processing visual information. Therefore, the correct answer should be: Sight    The part labeled \"X\" is located in the occipital lobe, which is responsible for visual processing. This lobe interprets visual stimuli and information from the eyes. Hence, it is associated with sight.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2014>16", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "Use the diagram below to answer this question.    The diagram above is an illustration of", "images": ["Biology/imgs/2014/bio1416.png"], "options": {"A": "normal sight", "B": "short sightedness", "C": "correction of long sightedness", "D": "correction of short sightedness"}, "answer": "C", "explanation": "The diagram on the Left Hand Side indicates the defect of long sightedness and that of the Right Hand Side is the correction of the defect.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>17", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The inability to maintain proper balance of the body in humans may be due to a defect in the", "images": [], "options": {"A": "cochlea", "B": "eustachian tube", "C": "semi-circular canals", "D": "oval window"}, "answer": "C", "explanation": "The semi-circular canals in the inner ear are responsible for maintaining balance in the human body. They are filled with a fluid that moves when your head changes position, and they have sensory hair cells that send signals to the brain about the body's motion and orientation in space.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>18", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "The following substances pass into the blood of the foetus from the mother's blood via the placenta except", "images": [], "options": {"A": "carbon dioxide", "B": "glucose", "C": "viruses", "D": "antibodies"}, "answer": "A", "explanation": "The placenta allows the exchange of nutrients, gases, and waste products between the mother and the fetus. However, it does not allow the passage of most harmful substances, such as carbon dioxide. The fetus gets rid of carbon dioxide by sending it back through the placenta to the mother's bloodstream, which then removes it through the mother's lungs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>19", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "An inferior ovary of a flower is situated", "images": [], "options": {"A": "below the floral parts", "B": "above the floral parts", "C": "at the same level with all the floral parts", "D": "at the centre of the floral parts"}, "answer": "A", "explanation": "An inferior ovary is a term used in botany to describe the position of the ovary of a flower in relation to the other parts of the flower. When the ovary is said to be inferior, it means it is situated below the other floral parts. This is in contrast to a superior ovary, which is situated above the other floral parts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>20", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Older parts of plants roots do not normally absorb water because", "images": [], "options": {"A": "they lack xylem", "B": "they have small surface area", "C": "the phloem is dead", "D": "they lack root hairs"}, "answer": "D", "explanation": "Older parts of plant roots do not normally absorb water because they lack root hairs. Root hairs are tiny hair-like extensions that increase the surface area of the root allowing it to absorbs more water and nutrients from the soil. As the root ages, these root hairs die off, reducing the root's ability to absorb water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>21", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The amount of starch in a germinating seed decreases because the starch is used up", "images": [], "options": {"A": "for respiration and building up of cells", "B": "to build cellulose cell wall", "C": "to develop meristematic tissues", "D": "for the production of enzymes"}, "answer": "A", "explanation": "During germination, the stored starch in a seed is broken down into simpler sugars by enzymes. These sugars are then used for respiration to provide energy for the growing seedling and for building up of cells. Respiration is a metabolic process that converts stored energy into usable energy. The building up of cells is part of growth and development of the seedling.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>22", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "The purpose of treating poor soil with lime is to increase the quantity of", "images": [], "options": {"A": "nitrogen", "B": "phosphorus", "C": "calcium", "D": "sulphur"}, "answer": "C", "explanation": "The purpose of treating poor soil with lime (calcium carbonate) is to increase the quantity of calcium in the soil. Lime is used to neutralize the acidity of soil and improve its structure. Calcium is an essential nutrient for plant growth. It is involved in cell wall structure, cell division, and is a co-factor for some enzymes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>23", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "A meal consisting of yam and a lot of vegetables is not balanced because it does not contain", "images": [], "options": {"A": "carbohydrates", "B": "protein", "C": "vitamins", "D": "mineral"}, "answer": "B", "explanation": "A balanced diet is one that gives your body the nutrients it needs to function correctly. It must contain the right amount of all the different types of nutrients, including carbohydrates, proteins, vitamins, and minerals. In the given question, the meal consists of yam and a lot of vegetables. Yam is a good source of carbohydrates and vegetables are rich in vitamins and minerals. However, this meal lacks protein, which is essential for growth and repair in the body. Therefore, the meal is not balanced because it does not contain protein.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>24", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "CONCEPT OF LIVING : PROPERTIES AND FUNCTIONS OF THE LIVING CELL", "question": "In a Biuret, some protein was mixed with Sodium Hydroxide solution. Which of the following chemicals should be added to the mixture for a positive result?", "images": [], "options": {"A": "Mercurous Nitrate", "B": "Copper Sulphate", "C": "Sodium Carbonate", "D": "Silver Nitrate"}, "answer": "B", "explanation": "The Biuret test is a chemical test used for detecting the presence of peptide bonds. In the presence of peptides, a copper(II) ion forms violet-colored coordination complexes in an alkaline solution. In this test, Sodium Hydroxide (NaOH) is used to make the solution alkaline. Then, Copper Sulphate (CuSO4) is added. If protein is present, the solution will turn purple. Therefore, Copper Sulphate should be added to the mixture for a positive result.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>25", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "A characteristic feature of plant parasites is the", "images": [], "options": {"A": "possession of holdfast", "B": "possession of rhizoids", "C": "development of hanging roots", "D": "development of haustoria"}, "answer": "D", "explanation": "A characteristic feature of plant parasites is the development of haustoria. Haustoria are specialized structures that the parasitic plant uses to penetrate the host plant's tissue and draw nutrients from it. This is not to be confused with holdfasts, which are root-like structures that some plants use to anchor themselves to a surface, or rhizoids, which are similar but found in non-vascular plants like mosses and liverworts. Hanging roots are not a characteristic feature of parasitic plants.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>26", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : MICROORGANISMS: MAN AND HIS HEALTH.", "question": "The part of a leguminous plant where bacteria like Azotobacter can be found is", "images": [], "options": {"A": "at the nodes of the stem", "B": "at the internodes", "C": "in the root nodules", "D": "in the spongy mesophyll"}, "answer": "C", "explanation": "Bacteria like Azotobacter can be found in the root nodules of leguminous plants. These bacteria are able to fix atmospheric nitrogen into a form that the plant can use. This symbiotic relationship benefits the plant by providing it with a source of nitrogen, and benefits the bacteria by providing them with a protected environment and nutrients from the plant. The nodes of the stem, internodes, and spongy mesophyll are not typically where these bacteria are found.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>27", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The following adaptations are associated with the flight of birds except", "images": [], "options": {"A": "reduced body weight", "B": "streamlined shape", "C": "presence of powerful muscles", "D": "clawed digits"}, "answer": "D", "explanation": "The adaptations associated with the flight of birds include reduced body weight, streamlined shape, and the presence of powerful muscles. These adaptations help birds to fly efficiently. Reduced body weight makes it easier for birds to lift off the ground. A streamlined shape reduces air resistance, making flight more efficient. Powerful muscles, particularly in the wings, provide the force needed for flight. However, clawed digits are not an adaptation for flight. They are used for perching, grasping prey, or for defense, but they do not aid in the act of flying.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>28", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "The following habitats can be found in West Africa  except", "images": [], "options": {"A": "magrove swamp", "B": "sahel savanna", "C": "savanna grassland", "D": "temperate grassland"}, "answer": "D", "explanation": "They can be found in Temperate pacific grasslands of North America, the Pampas of Argentina, Brazil and Uruguay, calcareous downland, and the steppes of Europe.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>29", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING", "question": "The difference between a community and population is", "images": [], "options": {"A": "a community is made up of organisms of the same species while a population is made up of organisms of different species", "B": "a community is made up of populations of living organisms while a population is made up of organisms of the same species", "C": "an ecological niche does not exist in the community but it does in a population", "D": "a community attracts competition but a population does not"}, "answer": "B", "explanation": "A community is a group of populations of different species living in the same geographical area, and potentially interacting with each other. A population, on the other hand, is a group of individuals of the same species living in the same geographical area. Therefore, a community is made up of populations of living organisms while a population is made up of organisms of the same species.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>30", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : WATER CYCLE", "question": "Which of the following statements about the circulation of water in nature is not correct? Water", "images": [], "options": {"A": "constantly evaporates from seas, rivers, lakes and soil", "B": "vapour rises, cools, condenses and precipitates as rain and dew.", "C": "removed from oceans is permanently lost", "D": "is lost in plants by transpiration and decay"}, "answer": "C", "explanation": "Water removed from oceans vaporizes to the cloud, this water vapour condenses and precipitation occurs in form of rain, snow and hail to return the removed water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>31", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS", "question": "The diagram below illustrates an ecological instrument.      Use it to answer this question    The instrument is", "images": ["Biology/imgs/2014/bio1431.png"], "options": {"A": "an anemometer", "B": "a hygrometer", "C": "a barometer", "D": "a wind vane"}, "answer": "D", "explanation": "This is the structure of the wind-vane. The cardinal points help to identify the direction of the wind.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>32", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS", "question": "The diagram below illustrates an ecological instrument.      Use it to answer this question   The instrument is used to measure the", "images": ["Biology/imgs/2014/bio1431.png"], "options": {"A": "direction of wind", "B": "speed of wind", "C": "air pressure in a habitat", "D": "turbidity of water"}, "answer": "A", "explanation": "Wind-vane is used to indicate the direction of wind.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>33", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "The following organisms are consumers except", "images": [], "options": {"A": "earthworm", "B": "Spirogyra", "C": "Bacteria", "D": "Rhizopus"}, "answer": "B", "explanation": "Spirogyra is a type of green algae that is photosynthetic. Photosynthetic organisms are producers, not consumers. They produce their own food by converting sunlight, carbon dioxide, and water into glucose and oxygen. Consumers, on the other hand, are organisms that cannot produce their own food and must consume other organisms for energy. Therefore, Spirogyra is not a consumer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2014>34", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE", "question": "Use the substances listed below to answer this question    I. Fertilizer  II. Insecticides  III. Sewage  IV. Crude oil   V. Sulphur dioxide    The atmosphere can be polluted by", "images": [], "options": {"A": "I only", "B": "III only", "C": "IV only", "D": "II and V only"}, "answer": "D", "explanation": "Atmospheric pollution can be caused by a variety of substances, including insecticides and sulphur dioxide. Insecticides can be carried into the atmosphere when they are sprayed, and they can harm non-target organisms and disrupt ecosystems. Sulphur dioxide is a gas that is released by industrial processes, such as the burning of fossil fuels. It can react with water, oxygen, and other chemicals in the atmosphere to form acid rain, which can harm both terrestrial and aquatic ecosystems. Therefore, both insecticides (II) and sulphur dioxide (V) can pollute the atmosphere.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>35", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE", "question": "Use the substances listed below to answer this question    I. Fertilizer  II. Insecticides  III. Sewage  IV. Crude oil   V. Sulphur dioxide  Which of the substance constitute domestic waste?", "images": [], "options": {"A": "I only", "B": "III only", "C": "IV only", "D": "II and V only"}, "answer": "B", "explanation": "Domestic waste refers to waste that is generated as a result of household activities. It includes things like food scraps, paper, glass, bottles, etc. In the given options, sewage (III) is a type of domestic waste. Fertilizer (I) and Insecticides (II) are agricultural wastes, Crude oil (IV) is an industrial waste and Sulphur dioxide (V) is a type of air pollution.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2014>36", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE", "question": "The table below shows the oxygen level, number of green plants and fish in rivers flowing through four towns.   Which of the towns is likely to be discharging untreated sewage in their river?   TownOxygen LevelGreen PlantsFishAHighFewManyBLowManyManyCHighFewFewDLowManyFew", "images": [], "options": {"A": "High, Few, Many", "B": "Low, Many, Many", "C": "High, Few, Few", "D": "Low, Many, Few"}, "answer": "D", "explanation": "The town that is likely discharging untreated sewage into their river would be the one with low oxygen levels, many green plants, and few fish. This is because untreated sewage can lead to an increase in nutrients in the water, which can cause an overgrowth of plants and algae (eutrophication). This overgrowth can deplete the water's oxygen, making it hard for fish and other aquatic life to survive. Therefore, the correct answer is 'Low, Many, Few' which corresponds to town D in the table.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2014>37", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "Which of the following natural resources is non-renewable?", "images": [], "options": {"A": "Water", "B": "Coal", "C": "Forest", "D": "Air"}, "answer": "B", "explanation": "Non-renewable resources are resources that cannot be replenished within a short period of time. Coal is a non-renewable resource because it takes millions of years to form from the remains of plants and animals. Water, forest, and air are renewable resources because they can be replenished naturally in a short period of time.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2014>38", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT", "question": "Which of the following statements is not a reason for banning bush burning? It", "images": [], "options": {"A": "allows  for quick regrowth of grasses", "B": "kills soil micro-organisms", "C": "Leaves the soil bare of vegetation", "D": "burns off organic soil nutrients"}, "answer": "A", "explanation": "Bush burning is a practice that involves setting fire to vegetation in a particular area. While it can allow for quick regrowth of grasses, it is generally discouraged because it can lead to soil degradation, loss of biodiversity, and other environmental problems. Therefore, the statement that bush burning allows for quick regrowth of grasses is not a reason for banning it. On the other hand, killing soil micro-organisms, leaving the soil bare of vegetation, and burning off organic soil nutrients are all negative impacts of bush burning and valid reasons for banning it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>39", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "Which of the statements below explains why fertilizers are added to soils?", "images": [], "options": {"A": "Increasing the humus content of the soil.", "B": "Improving the water-retaining property of the soil", "C": "Increasing the nutrient level of the soil", "D": "Preventing soil erosion"}, "answer": "C", "explanation": "Fertilizers are added to soils primarily to increase the nutrient level of the soil. They provide essential nutrients like nitrogen, phosphorus, and potassium that plants need for growth. The other options, such as increasing the humus content, improving water-retaining property, and preventing soil erosion, are not the primary reasons for adding fertilizers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>40", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Characteristic that exhibit continuous variation are generally controlled by", "images": [], "options": {"A": "a single gene", "B": "recessive genes", "C": "epistatic  interactions", "D": "multiple genes"}, "answer": "D", "explanation": "Characteristics that exhibit continuous variation are generally controlled by multiple genes. This is known as polygenic inheritance, where multiple genes contribute to a single trait. A single gene or recessive genes do not control continuous variation. Epistatic interactions refer to the interaction of different genes, not the number of genes controlling a trait.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>41", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Differences in characteristics that exist among individual of the same species is referred to as", "images": [], "options": {"A": "genetics", "B": "dominance", "C": "hybrid", "D": "variation"}, "answer": "D", "explanation": "The differences in characteristics that exist among individuals of the same species is referred to as variation. Variation can be due to genetic differences, environmental factors, or a combination of both. It is a fundamental aspect of life on Earth and is a driving force behind evolution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>42", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Which of the following traits is not a morphological variation in humans?", "images": [], "options": {"A": "Ability to taste PTC", "B": "Colour", "C": "Fingerprint", "D": "Size"}, "answer": "A", "explanation": "Morphological variations refer to physical differences in form and structure among individuals of the same species. The ability to taste PTC (phenylthiocarbamide) is a genetic trait, not a morphological one. It is determined by the presence or absence of certain alleles (versions of a gene). On the other hand, color, fingerprint, and size are all examples of morphological variations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>43", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "Which of the following statements about chromosome is correct?", "images": [], "options": {"A": "All the chromosomes of a species are the same in shape", "B": "The number present in a species is constant", "C": "They are nearly arranged in the cytoplasm", "D": "They bear ribosomes on their outer membranes"}, "answer": "B", "explanation": "Chromosomes are thread-like structures located inside the nucleus of animal and plant cells. Each chromosome is made of protein and a single molecule of deoxyribonucleic acid (DNA). The number of chromosomes is a characteristic that is constant in the cells of individuals of the same species. For example, humans have 46 chromosomes in each cell, while dogs have 78. The other options are incorrect because chromosomes are not the same in shape, they are not arranged in the cytoplasm, and they do not bear ribosomes on their outer membranes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>44", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "A small stem from a hibiscus plant was placed in nutrient medium and it developed into a new plant.   The new plant was reproduced", "images": [], "options": {"A": "asexually with a different genotype from the parent plant", "B": "sexually with a different genotype from the parent plant", "C": "asexually with the same genotype as the parent plant", "D": "sexually with the same genotype as the parent plant"}, "answer": "C", "explanation": "The process described in the question is known as plant tissue culture, which is a form of asexual reproduction. In this process, a small piece of plant tissue (the stem in this case) is taken and placed in a nutrient medium where it develops into a new plant. Because this is a form of asexual reproduction, the new plant will have the same genetic makeup (genotype) as the parent plant. The other options are incorrect because the new plant is not produced sexually, and it does not have a different genotype from the parent plant.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>45", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "The F1 generation of a cross between a red cock and a white hen were all red because the gene for the", "images": [], "options": {"A": "white colour did not segregate", "B": "red colour was dominant", "C": "white colour was dominant", "D": "red colour was recessive"}, "answer": "B", "explanation": "The organisms (individual) in the F1 generation are red because of the dominance of the red colour.    The organism in the F1 generation are red because the gene for the red colour as dominant", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>46", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of the following disease can be inherited?", "images": [], "options": {"A": "Pneumonia", "B": "AIDS", "C": "Sickle cell anaemia", "D": "Goitre"}, "answer": "C", "explanation": "Sickle cell anaemia is a genetic disease that can be inherited. It is caused by a mutation in the gene that tells your body to make the red, iron-rich compound that gives blood its red color (hemoglobin). Pneumonia and AIDS are infectious diseases caused by bacteria and virus respectively, and Goitre is a condition that results from the enlargement of the thyroid gland, which is not inherited.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>47", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "In dihybrid inheritance, Mendel considered", "images": [], "options": {"A": "a pair of contrasting characters", "B": "two pairs of contrasting characters", "C": "three pairs of contrasting characters", "D": "four pairs of contrasting characters"}, "answer": "B", "explanation": "In dihybrid inheritance, Mendel considered two pairs of contrasting characters. Dihybrid inheritance is a term used in genetics to describe the simultaneous inheritance of two distinct traits. It was first discovered by Gregor Mendel who conducted experiments on pea plants. He studied two traits at a time, hence the term 'dihybrid'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>48", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The main reason for nuptial flight in termites is to", "images": [], "options": {"A": "escape unfavourable conditions", "B": "search for food", "C": "form new colonies", "D": "communicate with one another"}, "answer": "C", "explanation": "The main reason for nuptial flight in termites is to form new colonies. Nuptial flight is an important phase in the reproduction of most ant, termite, and some bee species. During the flight, virgin queens mate and then land to start a new colony, or, in the case of honey bees, to continue the succession of an existing hived colony.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>49", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following organisms is not a social insect?", "images": [], "options": {"A": "Termites", "B": "Ants", "C": "Grasshoppers", "D": "Bees"}, "answer": "C", "explanation": "Social insects are those that live in colonies or have a division of labor. Termites, ants, and bees are all examples of social insects. Grasshoppers, on the other hand, are not social insects. They are solitary insects that do not live in colonies or have a division of labor.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2014>50", "subject": "Biology", "year": "2014", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Lamarck's theory of evolution is based on the fact that", "images": [], "options": {"A": "organisms acquire genes from their parents", "B": "organisms pass on acquired characters to their offspring", "C": "characteristics of organisms are determined by the creator", "D": "characteristics of organisms are not the sum of their parents' characters."}, "answer": "B", "explanation": "Lamarck's theory of evolution, also known as Lamarckism, proposes that an organism can change during its lifetime in response to its environment, and those changes are inheritable. This means that an organism can pass on characteristics that it has acquired during its lifetime to its offspring. Therefore, the statement 'organisms pass on acquired characters to their offspring' is the correct representation of Lamarck's theory of evolution.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2015>1", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "Which of the following organisms is not a protozoan?", "images": [], "options": {"A": "Amoeba", "B": "Ascaris", "C": "Plasmodium", "D": "Paramecium"}, "answer": "B", "explanation": "Protozoa are a group of single-celled microorganisms, which include Amoeba, Plasmodium, and Paramecium. Ascaris, on the other hand, is a genus of parasitic nematode worms, not a protozoan.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>2", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The structure of the cell membrane is a", "images": [], "options": {"A": "double layer and a double protein layer", "B": "middle bi-layer of protein with a lipid layer on either surface", "C": "middle bi-layer of lipid with a protein layer on either surface", "D": "protein layer with two inner lipid layers"}, "answer": "C", "explanation": "The structure of the cell membrane is a phospholipid bilayer, which is a middle bi-layer of lipid with a protein layer on either surface. This structure allows the cell membrane to be flexible and selectively permeable to substances.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>3", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which of the following cells is a specialized cell?", "images": [], "options": {"A": "Amoeba", "B": "Plasmodium", "C": "Guard cell", "D": "Meristematic cell"}, "answer": "C", "explanation": "A specialized cell is a cell that performs a specific function in an organism. The guard cell is a specialized cell in plants that controls the opening and closing of stomata, which are small openings on the surface of leaves that allow for gas exchange. Amoeba and Plasmodium are organisms, not cells. Meristematic cells are undifferentiated cells in plants that can divide and become any type of plant cell.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>4", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "The following organisms have structures for movement except", "images": [], "options": {"A": "Amoeba", "B": "Spirogyra", "C": "Volvox", "D": "Paramecium"}, "answer": "B", "explanation": "Spirogyra is a type of green algae that does not have any structures for movement. It is a free-floating algae that moves with the current of the water. On the other hand, Amoeba uses pseudopodia (false feet) for movement, Volvox uses flagella (whip-like structures), and Paramecium uses cilia (short, hair-like structures).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>5", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "CONCEPT OF LIVING : PROPERTIES AND FUNCTIONS OF THE LIVING CELL", "question": "Which of the following statements about protoplasm of a cell is not correct? It", "images": [], "options": {"A": "is a gelatinous mass", "B": "consist of cytoplast", "C": "doesn't have a cytoplasm", "D": "has a nucleus"}, "answer": "C", "explanation": "Protoplasm is the living part of a cell that is often referred to as the 'life substance' of the cell. It includes the cytoplasm and the nucleus. Therefore, the statement that protoplasm 'doesn't have a cytoplasm' is incorrect.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>6", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "When a Spirogyra filament is placed in a concentrated salt solution for 30 minutes, the cell would become", "images": [], "options": {"A": "plasmolysed", "B": "turgid", "C": "shortened", "D": "elongated"}, "answer": "A", "explanation": "When a cell is placed in a concentrated salt solution, it loses water by osmosis, causing the cell to shrink away from the cell wall, a process known as plasmolysis. Therefore, the cell would become plasmolysed, not turgid, shortened, or elongated.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2015>7", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The diagram below is an illustration of a crocodile       Use it to answer this question     Which of the labelled parts enable the animal to stay under water most of the time?", "images": ["Biology/imgs/2015/bio1507.png"], "options": {"A": "I, IV and V", "B": "I, II and V", "C": "I, III and IV", "D": "III, IV and V"}, "answer": "B", "explanation": "Its transparent eyelid, the position of its eyes and the location of its nostrils adapted it to life in water.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2015>8", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The diagram below is an illustration of a crocodile       Use it to answer this question    Two characteristic features of the class to which the crocodile belongs are labelled.", "images": ["Biology/imgs/2015/bio1507.png"], "options": {"A": "I and II", "B": "III and IV", "C": "II and IV", "D": "II and V"}, "answer": "B", "explanation": "The scaly skin and the homodont teeth arrangement are the features of reptiles.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>9", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Water and salts are both lost from the human body in", "images": [], "options": {"A": "breath and sweat", "B": "breath and urine", "C": "breath, urine and sweat", "D": "sweat and urine"}, "answer": "D", "explanation": "Water and salt are removed from the body during urination and sweating.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>10", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS", "question": "Which of the following features could be used to determine the growth of a seedling?", "images": [], "options": {"A": "Number of flowers", "B": "Number of leaves", "C": "Length of flowers", "D": "Length of radicle"}, "answer": "D", "explanation": "The length of the radicle is a factor considered in the determination of the growth rate of a seedling.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2015>11", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The following diagrams show the sequence of events in early cell division. Study the diagram and answer this question    In which of the following cells is this division likely to take place?", "images": ["Biology/imgs/2015/bio1511.png"], "options": {"A": "Sperm cell", "B": "Blood cell", "C": "Muscle cell", "D": "Uterine cell"}, "answer": "C", "explanation": "This cell division takes place in the somatic cells. These cells are not involved in the production of gametes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>12", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "A plant that commonly undergoes vegetative propagation by means of leaves is", "images": [], "options": {"A": "Hibiscus", "B": "Bryophylum", "C": "Crotalaria", "D": "Spirogyra"}, "answer": "B", "explanation": "Bryophyllum is a plant that commonly undergoes vegetative propagation by means of leaves. Vegetative propagation is a form of asexual reproduction in plants. It does not involve flowers, pollination and seed production. Instead, a new plant grows from a vegetative part, usually a stem, of the parent plant. In the case of Bryophyllum, new plants grow from the margins of the leaves.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2015>13", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The diagram illustrates a part of the mammalian skeleton. Use it to answer this question      The part of the mammalian skeleton illustrated in the diagram is the", "images": ["Biology/imgs/2015/bio1513.png"], "options": {"A": "atlas vertebrae", "B": "axis vertebrae", "C": "cervical vertebrae", "D": "thoracic vertebrae"}, "answer": "C", "explanation": "The part of the mammalian skeleton illustrated in the diagram is the cervical vertebrae.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>14", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The diagram illustrates a part of the mammalian skeleton. Use it to answer this question     The function of the part labelled I is to", "images": ["Biology/imgs/2015/bio1513.png"], "options": {"A": "provide support to the spinal cord", "B": "provide surface for attachment of the muscle", "C": "carry the spinal cord", "D": "articulate with adjacent vertebrae"}, "answer": "C", "explanation": "The neural canal carries the spinal cord, that is it allows for the passage of the spinal cord.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>15", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "Blood pressure is higher in the arteries as a result of", "images": [], "options": {"A": "stress", "B": "contraction and relaxation", "C": "blockage in the arteries", "D": "presence of valves"}, "answer": "B", "explanation": "Blood pressure is higher in the arteries as a result of contraction and relaxation of the heart. When the heart contracts (systole), it pumps blood into the arteries, causing them to expand and accommodate the surge of blood, which results in higher pressure. When the heart relaxes (diastole), the pressure in the arteries decreases. This cycle of contraction and relaxation results in the pressure differences observed in the circulatory system.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2015>16", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "A farmer who wants to keep seeds for three years before planting and wants to prevent them from sprouting uses.", "images": [], "options": {"A": "auxin", "B": "gibberellins", "C": "abscisin", "D": "cytokines"}, "answer": "C", "explanation": "Abscising is the suitable hormone for this purpose.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>17", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "A person had an accident that affected the skull but not the nose and later lost the sense of smell. The accident must have affected the", "images": [], "options": {"A": "nose by extension", "B": "olfactory lobes of the brain", "C": "passage from the nose to the brain", "D": "part of the skull near the nose"}, "answer": "B", "explanation": "The olfactory lobes of the brain are responsible for the sense of smell. If a person had an accident that affected the skull but not the nose and later lost the sense of smell, it means the accident must have affected the olfactory lobes of the brain. The nose by extension, the passage from the nose to the brain, and the part of the skull near the nose are not directly responsible for the sense of smell.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>18", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "Ability of the human eye to focus images accurately on the retina is called", "images": [], "options": {"A": "astigmatism", "B": "myopia", "C": "adjustment", "D": "accommodation"}, "answer": "D", "explanation": "The ability of the human eye to focus images accurately on the retina is called accommodation. This is a process by which the eye changes optical power to maintain a clear image or focus on an object as its distance varies. Astigmatism and myopia are types of refractive errors, not the ability to focus images.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2015>19", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "Which of the following characteristic features is not associated with monocotyledonous plants?", "images": [], "options": {"A": "Well differentiated sepals and petals", "B": "Presence of fibrous root system", "C": "Presence of narrow leaves", "D": "Floral parts are in multiples of three."}, "answer": "A", "explanation": "Monocotyledonous plants typically have floral parts in multiples of three, narrow leaves, and a fibrous root system. However, they do not have well-differentiated sepals and petals. Instead, their floral parts are often indistinguishable and are referred to as tepals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>20", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The main difference between a seed and a fruit is that a fruit", "images": [], "options": {"A": "is large while a seed is small", "B": "has two scars while a seed has one", "C": "is pigmented while a seed is not", "D": "can be dispersed  by animals while a seed cannot"}, "answer": "B", "explanation": "Fruit bear remains of style or scar left by it while a seed does not have any such remains or scar.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2015>21", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "Which of the following processes removes Carbon(IV) Oxide from the atmosphere?", "images": [], "options": {"A": "Burning fuels", "B": "Putrefaction", "C": "Photosynthesis", "D": "Respiration in plants"}, "answer": "C", "explanation": "Photosynthesis is the process by which green plants and some other organisms use sunlight to synthesize foods with the aid of chlorophyll pigments. During photosynthesis, plants absorb carbon dioxide (CO2) from the atmosphere and release oxygen. This process helps in reducing the amount of carbon dioxide in the atmosphere, thereby serving as a natural air purifier. Therefore, photosynthesis is the process that removes Carbon(IV) Oxide from the atmosphere.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2015>22", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "A student  used the following step in testing for a non-reducing sugar.   I. added Benedict's solution to the sugar solution   II. added dilute hydrochloric acid to the sugar solution and boiled it   III. added sodium hydroxide solution to the solution in II and boiled;   IV. added Benedict's solution to the cooled solution in III.  Use the information above to answer this question    Why did the student add the dilute hydrochloric acid to the sugar solution in step II? To", "images": [], "options": {"A": "oxidize the sugar solution", "B": "hydrolyse the sugar solution", "C": "dry the sugar solution", "D": "increase the volume of the sugar solution"}, "answer": "B", "explanation": "The dilute hydrochloric acid is added to the sugar solution to hydrolyse the sugar solution. Hydrolysis is a chemical reaction in which water is used to break down a compound. In this case, the non-reducing sugar is broken down into its constituent monosaccharides.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>23", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "A student  used the following step in testing for a non-reducing sugar.   I. added Benedict's solution to the sugar solution   II. added dilute hydrochloric acid to the sugar solution and boiled it   III. added sodium hydroxide solution to the solution in II and boiled;   IV. added Benedict's solution to the cooled solution in III.  Use the information above to answer this question  What is the importance of step II in the testing process? To", "images": [], "options": {"A": "neutralize the sugar solution", "B": "soften the sugar solution", "C": "change the colour of the sugar solution", "D": "increase the acid content of the sugar solution"}, "answer": "A", "explanation": "The importance of step II in the testing process to neutralize the sugar solution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>24", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "A student  used the following step in testing for a non-reducing sugar.   I. added Benedict's solution to the sugar solution   II. added dilute hydrochloric acid to the sugar solution and boiled it   III. added sodium hydroxide solution to the solution in II and boiled;   IV. added Benedict's solution to the cooled solution in III.  Use the information above to answer this question  The colour change to be observed in step IV is", "images": [], "options": {"A": "blue-black", "B": "brick-red", "C": "purple", "D": "violet"}, "answer": "B", "explanation": "In the test for non-reducing sugars, Benedict's solution is used. Benedict's solution is a chemical reagent that changes color in the presence of reducing sugars, such as glucose and fructose, but not in the presence of non-reducing sugars, such as sucrose. However, if a non-reducing sugar is first hydrolyzed (broken down) into its component monosaccharides by the addition of an acid (step II) and then neutralized by the addition of a base (step III), it can then be detected by Benedict's solution. The color change observed in step IV, after the addition of Benedict's solution, would be from blue (the original color of Benedict's solution) to brick-red (indicating the presence of reducing sugars, which were produced by the hydrolysis of the non-reducing sugar). Therefore, the correct answer is 'brick-red'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>25", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ALIMENTARY SYSTEM", "question": "Which of the following organs of the alimentary canal is not correctly matched with its function?", "images": [], "options": {"A": "Gall bladder-stores bile", "B": "Liver -stores glycogen", "C": "Appendix - releases enzymes", "D": "Teeth - grind food"}, "answer": "C", "explanation": "The appendix is a small, finger-shaped pouch that is located where the small intestine and large intestine meet. It is known as a vestigial organ, meaning it has lost most of its original function through evolution. In humans, the appendix does not release enzymes and does not play a significant role in digestion. Therefore, the option 'Appendix - releases enzymes' is not correctly matched with its function.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>26", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "A person suffering from obstruction of the bile duct is advised not to eat fats and oil because", "images": [], "options": {"A": "bile digest fats and oil", "B": "fats and oil can only be absorbed when bile is absent", "C": "bile emulsifies fats and oil", "D": "bile adds water to digesting food."}, "answer": "C", "explanation": "Bile is a digestive fluid produced by the liver and stored in the gallbladder. It plays a crucial role in the digestion and absorption of fats and oils in the small intestine. Bile emulsifies fats and oils, breaking them down into smaller droplets that can be easily digested by enzymes. Therefore, if a person has an obstruction in the bile duct, the bile cannot reach the small intestine to perform its function, making the digestion of fats and oils difficult.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>27", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "ECOLOGY OF POPULATION : ECOLOGICAL SUCCESSION", "question": "A community reaches a climax when", "images": [], "options": {"A": "only pioneer organisms are present", "B": "new habitats are constantly being formed", "C": "there is an introduction of new plants and animal species within the community", "D": "the composition and size of a community remains constant  over a long period"}, "answer": "D", "explanation": "A climax community is the final stage of succession, remaining relatively unchanged until destroyed by an event such as fire or human interference. It is characterized by a stable and mature community where the composition and size remain constant over a long period. Therefore, a community reaches a climax when the composition and size of a community remains constant over a long period.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2015>28", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "Which of the following components make up an ecosystem?", "images": [], "options": {"A": "Decomposers, animals and non-living factors", "B": "Living and non-living factors", "C": "Plants and non-living factors", "D": "Plants decomposers and non-living factors"}, "answer": "B", "explanation": "An ecosystem is a community of living organisms in conjunction with the nonliving components of their environment, interacting as a system. These biotic and abiotic components are linked together through nutrient cycles and energy flows. Therefore, an ecosystem is made up of both living and non-living factors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>29", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "The major problem experience by organisms living in small water bodies is", "images": [], "options": {"A": "drying up", "B": "oxygen deficiency", "C": "scarcity of food", "D": "wave action"}, "answer": "A", "explanation": "Organisms living in small water bodies are majorly threatened by the possibility of the water body drying up. This is because the smaller the water body, the more susceptible it is to evaporation and other factors that can cause it to dry up. When the water body dries up, the organisms lose their habitat and may not survive. Oxygen deficiency, scarcity of food, and wave action can also be problems, but they are not as immediate or severe as the threat of the water body drying up.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2015>30", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "The capillarity of a soil refers to", "images": [], "options": {"A": "the particle size of soil", "B": "how easily water passes through soil", "C": "how well water rises up in soil", "D": "proportion of water a soil holds"}, "answer": "C", "explanation": "Capillarity in soil refers to the ability of the soil to transmit water against gravity. Water moves up from the water table to the soil surface through the capillary action. This is why the correct answer is 'how well water rises up in soil'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2015>31", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "An organism at the start of a food chain which provides the total input energy into an ecosystem is the", "images": [], "options": {"A": "sun", "B": "producer", "C": "consumer", "D": "decomposer"}, "answer": "B", "explanation": "In an ecosystem, the total input energy is provided by the producers. Producers are organisms that can make their own food from sunlight and/or chemical energy from deep sea vents. These are typically plants that perform photosynthesis, but can also include other organisms such as bacteria. The sun is the source of energy but not an organism, consumers eat producers or other consumers, and decomposers break down dead or decaying organisms.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2015>32", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION", "question": "Study the diagram and use it to answer this question.    The mode of nutrition of the plant in the diagram is", "images": ["Biology/imgs/2015/bio1532.png"], "options": {"A": "photosynthetic and chemosynthetic", "B": "saprophytic and carnivorous", "C": "photosynthetic and carnivorous", "D": "chemosynthetic and saprophytic"}, "answer": "C", "explanation": "This is a structure of the pitch plant which feeds in a photosynthetic and carnivorous manner.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>33", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION", "question": "Study the diagram and use it to answer this question.   The structure labelled I is", "images": ["Biology/imgs/2015/bio1532.png"], "options": {"A": "a pitcher", "B": "an onion", "C": "a flower", "D": "a tendril"}, "answer": "A", "explanation": "The structure labelled I in the plant is a pitcher.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>34", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : ADAPTATION OF ORGANISMS TO HABITATS.", "question": "Study the diagram and use it to answer this question.   In which type of soil is the plant found?    Soil that is", "images": ["Biology/imgs/2015/bio1532.png"], "options": {"A": "poorly aerated", "B": "waterlogged", "C": "exposed", "D": "nitrogen deficient"}, "answer": "D", "explanation": "Pitcher plant is usually deficient of nitrogen, mainly because it is normally found in a soil that is nitrogen deficient.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>35", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : CARRIERS OF MICROORGANISMS", "question": "Which of the following organisms is an endo-parasite?", "images": [], "options": {"A": "Tapeworm", "B": "Flea", "C": "Tick", "D": "Aphid"}, "answer": "A", "explanation": "An endo-parasite is a parasite that lives inside the body of its host. Tapeworms are a type of endo-parasite as they live in the intestines of their host. Fleas, ticks, and aphids are ectoparasites, meaning they live on the outside of their host.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2015>36", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH", "question": "Oil applied to the surface of water kills the larvae of mosquitoes through", "images": [], "options": {"A": "dehydration", "B": "poisoning", "C": "starvation", "D": "suffocation"}, "answer": "D", "explanation": "When oil is applied to the surface of water, it forms a thin layer that prevents air (oxygen) from reaching mosquito larvae that are under the water surface. This causes the larvae to suffocate and die. The oil does not dehydrate, poison, or starve the larvae.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>37", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "Which of the following natural resources is non-renewable?", "images": [], "options": {"A": "Forest reserve", "B": "Mineral deposit", "C": "Water", "D": "Wild life"}, "answer": "B", "explanation": "A non-renewable resource is a natural resource that cannot be readily replaced by natural means at a quick enough pace to keep up with consumption. An example is carbon-based, organically-derived fuel. The original organic material, with the aid of heat and pressure, becomes a fuel such as oil or gas. Mineral deposits are non-renewable because they do not regenerate within human timescales. Forest reserves, water, and wildlife are renewable resources because they can regenerate naturally if they are not over-exploited.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2015>38", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "Which of the following resources is non-renewable?", "images": [], "options": {"A": "Forest reserve", "B": "Mineral deposit", "C": "Water", "D": "Wild life"}, "answer": "B", "explanation": "A non-renewable resource is a natural resource that cannot be readily replaced by natural means at a quick enough pace to keep up with consumption. An example is carbon-based, organically-derived fuel. The original organic material, with the aid of heat and pressure, becomes a fuel such as oil or gas. Mineral deposits are non-renewable because they do not regenerate within human timescales. Forest reserves, water, and wildlife are renewable resources because they can regenerate naturally if they are not over-exploited.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2015>39", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Soil erosion could be prevented by", "images": [], "options": {"A": "flooding a farmland", "B": "cover-cropping", "C": "deforestation", "D": "leaving the soil bare"}, "answer": "B", "explanation": "Soil erosion can be prevented by cover-cropping. Cover-cropping is a farming practice where crops are grown to cover the soil rather than for the purpose of being harvested. Cover crops help to prevent soil erosion by reducing the impact of raindrops on the soil surface, slowing down the flow of water across the soil surface, and holding the soil in place with their roots.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>40", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of the following statements about human blood groups is not true?", "images": [], "options": {"A": "A is dominant over B", "B": "O is recessive", "C": "B is dominant over O", "D": "A and B are co - dominant"}, "answer": "A", "explanation": "The statement 'A is dominant over B' is not true. In human blood groups, A and B are co-dominant, which means that neither is dominant or recessive over the other. This is why we can have blood type AB where both A and B are expressed. Dominance in genetics is a relationship between alleles of a gene, in which one allele masks the expression of another allele at the same locus.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>41", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of the following traits is not inheritable? Ability to", "images": [], "options": {"A": "taste PTC", "B": "roll the tongue", "C": "move the ear", "D": "roll the eyeball"}, "answer": "D", "explanation": "Rolling the eyeball is not considered an inheritable trait. It is more related to voluntary muscle control and eye movement skills, which are learned rather than inherited.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>42", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "A woman with blood group A gives birth to a child with blood group O. Which of the following blood groups cannot belong to the father?", "images": [], "options": {"A": "A", "B": "B", "C": "AB", "D": "O"}, "answer": "C", "explanation": "Blood group inheritance is determined by the ABO gene, which has three alleles: A, B, and O. A person with blood group A can either have AA or AO genotype, while a person with blood group O has OO genotype. If a woman with blood group A (which means she could have AA or AO genotype) gives birth to a child with blood group O (OO genotype), the father must have contributed an O allele. Therefore, the father cannot have blood group AB (which means he has both A and B alleles), as he would not be able to contribute an O allele.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>43", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "How many chromosomes will be in a gamete if the normal cell has four chromosomes?", "images": [], "options": {"A": "2", "B": "4", "C": "6", "D": "8"}, "answer": "A", "explanation": "In sexual reproduction, gametes are formed by a process called meiosis. During meiosis, the number of chromosomes is halved, so a gamete will have half the number of chromosomes as the normal cell. If a normal cell has four chromosomes, a gamete will have two chromosomes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2015>44", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY", "question": "Use the diagram to answer this question.    Which of the following statement about the cross is correct", "images": ["Biology/imgs/2015/bio1544.png"], "options": {"A": "The gene for the spotted coat is recessive to the gen for the black coat", "B": "Black coat and spotted coat are co-dominant", "C": "The gene for the spotted coat is dominant over the gene for the black coat", "D": "The genotype for the F1 are homozygous dominant"}, "answer": "C", "explanation": "The gene for the spotted leopard is dominant over the black panther.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2015>45", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY", "question": "Use the diagram to answer this question.   What are  the genotypes of the parents if the gene for skin colour is H?", "images": ["Biology/imgs/2015/bio1544.png"], "options": {"A": "Spotted Leopard - HH, Black Panther -hh", "B": "Spotted Leopard - HH,  Black Panther - Hh", "C": "Spotted Leopard - Hh, Black Panther - Hh", "D": "Spotted Leopard - Hh, Black Panther - hh"}, "answer": "A", "explanation": "The genotypes of the parents if the gene for skin colour is H are HH, hh", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2015>46", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY", "question": "According to Mendel's first law of inheritance, segregation of genes occur when", "images": [], "options": {"A": "tall plants are crossbred", "B": "short plants are crossbred", "C": "tall plants and short plants are crossbred", "D": "plants are crossbred"}, "answer": "C", "explanation": "According to Mendel's first law of inheritance, also known as the Law of Segregation, gene pairs separate or 'segregate' from each other when gametes are formed. This means that each gamete carries only one allele for each inherited characteristic. This segregation of genes occurs when any plants are crossbred, but it is most noticeable when plants with contrasting characteristics, such as tall and short plants, are crossbred.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2015>47", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : LINKAGE, SEX DETERMINATION AND SEX LINKED CHARACTERS", "question": "Which of the following statements about sex-linked characters is not true?", "images": [], "options": {"A": "They are usually borne on the X-chromosome", "B": "They are more common in males", "C": "Males are usually carriers", "D": "They are not usually carried on the Y chromosomes"}, "answer": "C", "explanation": "Sex-linked characters are traits that are determined by genes located on sex chromosomes. They are usually borne on the X-chromosome and are more common in males because males have only one X chromosome, so a single recessive gene on the X chromosome will cause the trait to be expressed. However, males cannot be carriers of sex-linked traits because they have only one X chromosome. A carrier is an individual who has one copy of a recessive allele that causes a genetic disease in individuals that are homozygous for this allele. Since males have only one X chromosome, they will express the trait if they have the gene, they cannot be carriers. Therefore, the statement 'Males are usually carriers' is not true.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2015>48", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "EVOLUTION : ADAPTIVE COLOURATION", "question": "In explaining the term camouflage, to a class, the diagram below show four varieties, P, Q, R and S of the same species of fish living amongst water plants in a river were used.      Use the diagram to answer this question    Which of the varieties is likely to decrease most in number if a predatory fish is introduced into the river?", "images": ["Biology/imgs/2015/bio1548.png"], "options": {"A": "P", "B": "Q", "C": "R", "D": "S"}, "answer": "C", "explanation": "The R-fish does not really have a colour that blends with the plants. This will expose it to predators.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2015>49", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "EVOLUTION : ADAPTIVE COLOURATION", "question": "In explaining the term camouflage, to a class, the diagram below show four varieties, P, Q, R and S of the same species of fish living amongst water plants in a river were used.      Use the diagram to answer this question  Which of the varieties is most likely to outlive the others?", "images": ["Biology/imgs/2015/bio1548.png"], "options": {"A": "P", "B": "Q", "C": "R", "D": "S"}, "answer": "B", "explanation": "The varieties which is most likely to outlive the others is Q. Q looks most likely as the plants in the habitat.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2015>50", "subject": "Biology", "year": "2015", "type": "Objective", "topic": "EVOLUTION : ADAPTIVE COLOURATION", "question": "In explaining the term camouflage, to a class, the diagram below show four varieties, P, Q, R and S of the same species of fish living amongst water plants in a river were used.      Use the diagram to answer this question  The  variety selected in the above question will outlive the others because the", "images": ["Biology/imgs/2015/bio1548.png"], "options": {"A": "variety is the most beautiful", "B": "variety does not have markings", "C": "markings of the variety are similar to those of the environment.", "D": "predator does not like eating the variety."}, "answer": "C", "explanation": "Q looks most likely as the plants in the environment. Hence it will blend with the colour of the plants and this will protect it from predators.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>1", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "An example of an organism that exists as a colony is", "images": [], "options": {"A": "Spirogyra", "B": "Paramecium", "C": "Euglena", "D": "Volvox"}, "answer": "D", "explanation": "A colony is a group of organisms of the same species living closely together, usually for mutual benefit such as stronger defense or the ability to attack bigger prey. Volvox is a genus of chlorophytes, a type of green algae. It forms spherical colonies of up to 50,000 cells. They live in a variety of freshwater habitats, and were first reported by Antonie van Leeuwenhoek in 1700. Volvox is a colonial organism that resembles a hollow ball whose wall is composed of biflagellate cells embedded in a gelatinous matrix. Therefore, Volvox is an example of an organism that exists as a colony.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2016>2", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "Gymnosperms bear naked seeds because they lack", "images": [], "options": {"A": "ovary", "B": "colourful flowers", "C": "pollen grains", "D": "stigma"}, "answer": "A", "explanation": "Gymnosperms are a group of plants that produce seeds not enclosed within an ovary or fruit. These are known as 'naked seeds'. The term 'gymnosperm' comes from the Greek word gymnospermos, meaning 'naked seeds'. The seeds develop on the surface of cone scales or other structures, which are often modified to form a 'cone-like' appearance. Hence, they lack an ovary.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2016>3", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "DNA formation is associated with", "images": [], "options": {"A": "Golgi bodies", "B": "Lysosomes", "C": "Mitochondria", "D": "Nucleus"}, "answer": "D", "explanation": "DNA (Deoxyribonucleic acid) is a molecule that carries most of the genetic instructions used in the development, functioning and reproduction of all known living organisms and many viruses. DNA is located in the cell nucleus (as nuclear DNA), but a small amount of DNA can also be found in the mitochondria (as mitochondrial DNA or mtDNA). However, the formation and replication of DNA primarily occur in the nucleus, making 'Nucleus' the correct answer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2016>4", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Plant A was seen to appear as plant B after seven hours.  Study the diagram carefully and answer this question      The term that can be used to describe what happened to plant A after seven hours is", "images": ["Biology/imgs/2016/pix1.png"], "options": {"A": "wilting", "B": "competition", "C": "transpiration", "D": "osmosis"}, "answer": "A", "explanation": "From the Observation of plant A and plant B after seven hour is writing. This occurs as a result of loss of water from the plant than its take in.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>5", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Plant A was seen to appear as plant B after seven hours.  Study the diagram carefully and answer this question    The environmental factors responsible for the condition in plant B are", "images": ["Biology/imgs/2016/pix1.png"], "options": {"A": "low humidity and low temperature", "B": "high humidity and low temperature", "C": "low humidity and high temperature", "D": "high humidity and high temperature"}, "answer": "C", "explanation": "The environment factors responsible for the condition in plant B are as a result of low humidity and high temperature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>6", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "Hydra is considered to be at a tissue level of organization of life because it", "images": [], "options": {"A": "has numerous cells that perform different functions", "B": "has developed organs and systems", "C": "has a poorly developed nervous system", "D": "reproduces by budding"}, "answer": "A", "explanation": "Hydra is considered to be at a tissue level of organization of life because it has numerous cells that perform different functions. This is because, in the tissue level of organization, cells of a similar type join together to perform a shared function. In Hydra, there are different types of cells that perform different functions, such as nerve cells, muscle cells, and gland cells.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>7", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Study the diagrams below and answer this question.      Which of the following statements about the diagrams is correct?", "images": ["Biology/imgs/2016/pix2.png"], "options": {"A": "They are both organs", "B": "One of them is an organism", "C": "They both form part of tissues", "D": "They are harmful to humans"}, "answer": "B", "explanation": "I - Yeast  II - White blood cell  Yeast is an Organism.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>8", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING", "question": "Study the diagrams below and answer this question.    A decrease in the number of II will result in", "images": ["Biology/imgs/2016/pix2.png"], "options": {"A": "an increase in urine production", "B": "an increase in energy production", "C": "a decreased population", "D": "decreased immunity"}, "answer": "D", "explanation": "A decrease in the number of II [white blood cell] will decreased immunity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>9", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "Flaccidity in plants is associated with", "images": [], "options": {"A": "cessation of photosynthesis", "B": "wilting", "C": "turgidity", "D": "discoloration of leaves"}, "answer": "B", "explanation": "Flaccidity in plants is associated with wilting. This is because flaccidity refers to the condition where the plant cells lose water and become less rigid, causing the plant to wilt. This is different from turgidity, which is the state of being swollen due to high fluid content, and it helps to keep the plant rigid and upright.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>10", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which of the following substances is not usually present in the urine of a healthy person?", "images": [], "options": {"A": "Urea", "B": "Mineral salts", "C": "Glucose", "D": "Water"}, "answer": "C", "explanation": "In a healthy person, glucose is not usually present in the urine. This is because the kidneys reabsorb all the filtered glucose from the urine into the blood. If glucose is found in the urine, it can be a sign of diabetes or other health problems.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2016>11", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "CONCEPT OF LIVING : MUSCULAR SYSTEM", "question": "Muscles act in opposite directions in order to", "images": [], "options": {"A": "cause a bone to move", "B": "prevent dislocation at joints", "C": "prevent muscle fatigue", "D": "regulate bodily activities"}, "answer": "A", "explanation": "Muscles act in opposite direction in order to cause a bone to move. In the case of the bicep and the triceps, when the biceps  contracts the triceps relax thereby moving in opposite direction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>12", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "CONCEPT OF LIVING : PLANT STRUCTURE", "question": "Lateral meristem in flowering plants is found in the", "images": [], "options": {"A": "cortex", "B": "pericycle", "C": "cambium", "D": "pith"}, "answer": "C", "explanation": "Lateral meristem is found in the cambium of flowering plants. The cambium is a type of meristem, which is a tissue in plants consisting of undifferentiated cells (meristematic cells) capable of division and giving rise to cells that can differentiate into various types of cells. The cambium is specifically responsible for the secondary growth of the plants, which increases the width of the plant.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>13", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "The cells and tissues of the nose, throat, chest diaphragm and lungs form the", "images": [], "options": {"A": "circulatory system", "B": "respiratory system", "C": "transport system", "D": "digestive system"}, "answer": "B", "explanation": "The cells and tissues of the nose, throat, chest diaphragm and lungs form the respiratory system. The respiratory system is a biological system consisting of specific organs and structures used for gas exchange in animals and plants. The anatomy and physiology that make this happen varies greatly, depending on the size of the organism, the environment in which it lives and its evolutionary history.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>14", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "The exchange of gases between the environment and the respiratory organs of vertebrates is referred to as", "images": [], "options": {"A": "inhalation", "B": "respiration", "C": "expiration", "D": "breathing"}, "answer": "D", "explanation": "The exchange of gases between the environment and the respiratory organs of vertebrates is referred to as breathing. Breathing is the process that moves air in and out of the lungs, to allow the diffusion of oxygen and carbon dioxide to and from the external environment into and out of the blood.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>15", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "The maintenance of a constant internal environment in an organism is known as", "images": [], "options": {"A": "homeostasis", "B": "homoiothermy", "C": "diuresis", "D": "dialysis"}, "answer": "A", "explanation": "The maintenance of a constant internal environment in an organism is known as homeostasis. Homeostasis is the state of steady internal, physical, and chemical conditions maintained by living systems. This dynamic state of equilibrium is the condition of optimal functioning for the organism and includes many variables, such as body temperature and fluid balance, being kept within certain pre-set limits.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>16", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "Which of the following organs is responsible for the production of insulin?", "images": [], "options": {"A": "Spleen", "B": "Adrenal gland", "C": "Thyroid gland", "D": "Pancreas"}, "answer": "D", "explanation": "Insulin is a hormone that is produced in the body. It is made by beta cells in the pancreas. Insulin's main role is to control the level of glucose, or sugar, in the body. When the level of glucose in the blood is too high, insulin is released from the pancreas into the bloodstream. It then helps glucose to enter the cells of the body where it can be used for energy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>17", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "Which of the following actions is not a voluntary action?", "images": [], "options": {"A": "Stealing", "B": "Sneezing", "C": "Fighting", "D": "Cheating"}, "answer": "B", "explanation": "Voluntary actions are those that we choose to do and have control over. They are governed by the somatic nervous system and include actions like walking, talking, and eating. Involuntary actions, on the other hand, are those that happen without us having to think about them. They are controlled by the autonomic nervous system and include actions like heart beating, breathing, and sneezing. Sneezing is an involuntary action because it is an automatic response to irritation in the nasal passages.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>18", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "CONCEPT OF LIVING : PLANT STRUCTURE", "question": "In both dicotyledonous and monocotyledonous plants, the root hairs originate from the", "images": [], "options": {"A": "piliferous layer", "B": "epidermal layer", "C": "endodermal layer", "D": "cortical layer"}, "answer": "A", "explanation": "Root hairs originate from the piliferous layer, also known as the root hair zone. This is a region of the root where cells differentiate into specialized root hair cells. These cells are elongated and thin-walled, and they increase the surface area of the root for absorption of water and minerals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>19", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "Which of the following parts of the ear does not contain endolymph?", "images": [], "options": {"A": "Semi-circular canals", "B": "Utriculus", "C": "Tympanum", "D": "Sacculus"}, "answer": "C", "explanation": "The tympanum, also known as the eardrum, does not contain endolymph. Endolymph is a fluid that fills the inner ear and allows us to hear and maintain balance. It is found in the cochlea and the vestibular system, which includes the semi-circular canals, utriculus, and sacculus. The tympanum, on the other hand, is a thin membrane that separates the outer ear from the middle ear and vibrates in response to sound waves.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2016>20", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "The type of placentation illustrated in the diagram below is", "images": ["Biology/imgs/2016/pix3.png"], "options": {"A": "marginal", "B": "parietal", "C": "axile", "D": "basal"}, "answer": "D", "explanation": "This type of placentation is called Basal. Basal placentation is a type of placentation in flowering plants where the ovules are attached to the base of the ovary. In this arrangement, the ovules develop at the bottom part of the ovary, typically from a single point. This type of placentation is common in plants with a unilocular (single-chambered) ovary, such as in the families Asteraceae and Poaceae. Basal placentation can be advantageous in terms of structural support and nutrient distribution to the developing seeds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>21", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The steps below are involved in the testing of a leaf for starch.  Study them carefully and answer this question  I. Decolorize leaf  II. Dip decolorized leaf in warm water  III. Place leaf in boiling water  IV. Add iodine solution    The correct order for the test is", "images": [], "options": {"A": "I, II, III and IV", "B": "I, III, II and IV", "C": "II, III, I and IV", "D": "III, I, II and IV"}, "answer": "D", "explanation": "To test for starch on leaf  III - Place leaf in boiling water  I - Decolorize leaf in Alcohol  II - Dip decolourized leaf in warm water  IV - Add iodine solution", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>22", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The steps below are involved in the testing of a leaf for starch.  Study them carefully and answer this question  I. Decolorize leaf  II. Dip decolorized leaf in warm water  III. Place leaf in boiling water  IV. Add iodine solution  The best time to pluck the leaf for the experiment is", "images": [], "options": {"A": "after being exposed to sunlight", "B": "three hours after sunset", "C": "before sunrise", "D": "six hours after sunset"}, "answer": "A", "explanation": "The best time to pluck the leaf for the experiment is after being exposed to sunlight (option 1). This is because photosynthesis, the process by which plants produce starch, occurs during the day when the plant is exposed to sunlight. Therefore, the concentration of starch in the leaf will be highest after a period of sunlight exposure.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>23", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The steps below are involved in the testing of a leaf for starch.  Study them carefully and answer this question  I. Decolorize leaf  II. Dip decolorized leaf in warm water  III. Place leaf in boiling water  IV. Add iodine solution  In which of the plant tissues are guard cells located?", "images": [], "options": {"A": "Epidermis", "B": "Mesophyll", "C": "Vascular bundles", "D": "Meristems"}, "answer": "A", "explanation": "Guard cells are located in the epidermis of the plant. They are specialized cells in the epidermis of leaves, stems and other organs that are used to control gas exchange. They are produced by the epidermis and form a small pore, or stoma, that allows for gas exchange. The other options, Mesophyll, Vascular bundles, and Meristems, are incorrect as they are not the location of guard cells.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>24", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS", "question": "The association between two organisms in which one of the organisms gains and the other loses is referred to as", "images": [], "options": {"A": "saprophytism", "B": "commensalism", "C": "mutualism", "D": "parasitism"}, "answer": "D", "explanation": "Parasitism can be defined as an association between two whereby one is the host and the other is the parasite. In this type of association the one of the Organism (Parasites) gain while the other (Host) loses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>25", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ALIMENTARY SYSTEM", "question": "The function of the villi in the alimentary canal is to", "images": [], "options": {"A": "secrete gastric juice", "B": "curdle milk", "C": "emulsify fat", "D": "increase the surface area for absorption"}, "answer": "D", "explanation": "The function of the villi in the alimentary canal is to increase the surface area for absorption. Villi are small, finger-like projections that extend into the lumen of the small intestine. They increase the internal surface area of the intestinal walls making available a greater surface area for absorption. Absorption is the process by which the products of digestion are absorbed into the bloodstream and lymphatic system.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2016>26", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ALIMENTARY SYSTEM", "question": "Which of the following structures is not an organ of the digestive system?", "images": [], "options": {"A": "Oesophagus", "B": "Pancreas", "C": "Stomach", "D": "Kidney"}, "answer": "D", "explanation": "The kidney is not an organ of the digestive system. The digestive system is made up of the gastrointestinal tract—also called the digestive tract—and the liver, pancreas, and gallbladder. The digestive system processes food, extracts and absorbs nutrients and water, and eliminates the leftovers as waste. The kidney, on the other hand, is part of the urinary system and its main function is to filter the blood and remove waste products and excess substances.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>27", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "The diagram below shows the effect of nitrates on water bodies.  Study it carefully and answer this question      The source of the nitrates in the part labeled I is the", "images": ["Biology/imgs/2016/pix4.png"], "options": {"A": "root nodules of legumes", "B": "cloud", "C": "fertilizers", "D": "organic matter"}, "answer": "C", "explanation": "From the diagram, the source of the nitrate from part labelled I is the fertilizers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>28", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "The diagram below shows the effect of nitrates on water bodies.  Study it carefully and answer this question    The phenomenon in the diagram is termed", "images": ["Biology/imgs/2016/pix4.png"], "options": {"A": "denitrification", "B": "conservation", "C": "eutrophication", "D": "global warming"}, "answer": "C", "explanation": "Eutrophication is characterized by excessive plant and algal growth due to increased availability of one or more limiting growth factors needed for the photosynthesis e.g nutrient fertilizers", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>29", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "The diagram below shows the effect of nitrates on water bodies.  Study it carefully and answer this question    Another cause that could lead to the phenomenon in the diagram is", "images": ["Biology/imgs/2016/pix4.png"], "options": {"A": "exhaust from cars", "B": "oil spillage", "C": "dumping of sewage", "D": "excess rainfall"}, "answer": "C", "explanation": "Dumping of sewage in rivers can also helps to increase the bacteria in water bodies thereby reducing the oxygen level of the river.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2016>30", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS", "question": "In ecology, a community refers to", "images": [], "options": {"A": "a number of individuals of a given species", "B": "groups of different organisms living in a habitat", "C": "existing species in an abandoned farmland", "D": "the dominant species in a habitat"}, "answer": "B", "explanation": "In ecology, a community is a group or association of populations of two or more different species occupying the same geographical area and in a particular time, also known as a biocoenosis. The term community has a variety of uses.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2016>31", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS", "question": "The direction of wind is determined by", "images": [], "options": {"A": "an anemometer", "B": "a secchi disc", "C": "a wind vane", "D": "a barometer"}, "answer": "C", "explanation": "The direction of wind is determined by a wind vane. An anemometer measures wind speed, a secchi disc is used to measure water transparency, and a barometer measures atmospheric pressure.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2016>32", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Food webs are complex because", "images": [], "options": {"A": "the number of producers are large", "B": "many animals feed directly on producers", "C": "they include primary, secondary and tertiary consumers", "D": "some animals form part of several food chains"}, "answer": "D", "explanation": "Food webs are complex because they involve multiple interconnected food chains. An animal can be part of several food chains, meaning it can eat different types of food and be eaten by different types of animals. This creates a complex network of feeding relationships.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>33", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Special modifications which enable an organism to survive in its habitat is known as", "images": [], "options": {"A": "adaptation", "B": "tolerance", "C": "mimicry", "D": "colouration"}, "answer": "A", "explanation": "Adaptation refers to the process where an organism undergoes modifications in its structure, function or behavior to better survive in its environment. These changes are usually a result of evolution and can be physical (like the development of webbed feet in aquatic animals) or behavioral (like nocturnal activity in desert animals to avoid daytime heat).", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2016>34", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS", "question": "Which of the following relationships does not involve two organisms?", "images": [], "options": {"A": "Commensalism", "B": "Saprophytes", "C": "Symbiosis", "D": "Parasitism"}, "answer": "B", "explanation": "Saprophities does not involves two organisms. This is the process whereby organisms feed on dead or decaying substance , this form of feeding does not involve an association between organism.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2016>35", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION", "question": "Overcrowding in a population does not result in", "images": [], "options": {"A": "death", "B": "commensalism", "C": "competition", "D": "migration"}, "answer": "B", "explanation": "Overcrowding in a population can lead to death, competition, and migration as resources become scarce and individuals compete for survival. However, commensalism, which is a type of relationship where one organism benefits while the other is neither harmed nor benefited, is not a direct result of overcrowding.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2016>36", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : PUBLIC HEALTH", "question": "A pandemic is an outbreak of disease that", "images": [], "options": {"A": "is confined to a town", "B": "is widespread", "C": "will not spread", "D": "has limited spread"}, "answer": "B", "explanation": "A pandemic is an outbreak of a disease that occurs over a wide geographic area and affects an exceptionally high proportion of the population. Therefore, it is widespread, not confined to a town or has limited spread. It is also not correct to say it will not spread because by definition, a pandemic is a disease that is spreading.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2016>37", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "The rational and prudent use of natural resources is known as", "images": [], "options": {"A": "preservation", "B": "conservation", "C": "utilization", "D": "management"}, "answer": "B", "explanation": "The rational and prudent use of natural resources is known as conservation. Preservation refers to the act of maintaining something in its original or existing state, while utilization simply means the act of using something. Management could be a broader term that includes conservation, but it also includes other aspects like distribution and control. Therefore, the most accurate term for the rational and prudent use of natural resources is conservation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>38", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "Which of the following natural resources cannot be conserved?", "images": [], "options": {"A": "Soil", "B": "Water", "C": "Wildlife", "D": "Air"}, "answer": "D", "explanation": "All natural resources can be conserved. Conservation refers to the sustainable use and management of natural resources including wildlife, water, air, and earth deposits. However, the conservation of air is different from other resources because it is abundant and not subject to depletion in the same way as other resources. Therefore, while we can take measures to reduce air pollution, we cannot 'conserve' air in the traditional sense.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2016>39", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Which of the following actions support conservation? To", "images": [], "options": {"A": "protect endangered species", "B": "preserve trees for timber", "C": "permit hunting activities", "D": "provide income for the government"}, "answer": "A", "explanation": "Conservation involves actions that protect and preserve the natural environment. Protecting endangered species is a direct action that supports conservation. It involves implementing measures to prevent the extinction of species that are at risk. This can be achieved through various means such as creating wildlife reserves, implementing laws that protect endangered species, and promoting biodiversity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2016>40", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "A noticeable physical appearance of individuals of the same species is called", "images": [], "options": {"A": "physical variation", "B": "physiological variation", "C": "morphological variation", "D": "discontinuous variation"}, "answer": "C", "explanation": "The noticeable physical appearance of individuals of the same species is called morphological variation. Morphological variation refers to the differences in the physical appearance and characteristics of individuals within the same species. This can include differences in size, shape, color, structure, etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2016>41", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "A blend of inherited and acquired characteristics shows", "images": [], "options": {"A": "variation", "B": "inheritance", "C": "evolution", "D": "heredity"}, "answer": "A", "explanation": "A blend of inherited and acquired characteristics shows variation. Variation refers to the differences in physical and genetic characteristics between individuals within the same species. These differences can be due to both inherited (genetic) factors and acquired (environmental) factors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>42", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "A cross between two parent produced four offsprings with blood group AB, BB, BO and AO. What is the blood group of their parents?", "images": [], "options": {"A": "AA and BO", "B": "BB and AO", "C": "AB and BO", "D": "AB and AO"}, "answer": "C", "explanation": "The blood group of their parents are AB and BO. A cross between the two parent will result in AB, BB, BO and AO", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2016>43", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "A sick baby was successfully transfused with blood from the father who has blood group AB. What is the group of the sick baby?", "images": [], "options": {"A": "A", "B": "B", "C": "AB", "D": "O"}, "answer": "C", "explanation": "Donors with blood type A... can donate to recipients with blood types A and AB  Donors with blood type B... can donate to recipients with blood types B and AB  Donors with blood type AB... can donate to recipients with blood type AB only  Donors with blood type O... can donate to recipients with blood types A, B, AB and O", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>44", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : LINKAGE, SEX DETERMINATION AND SEX LINKED CHARACTERS", "question": "The illustration below represents a cross between a colour-blind male and a normal female.  Study it carefully and answer this question      What is the genotype ratio of carrier females to normal males in the cross?", "images": ["Biology/imgs/2016/CLNGXM.png"], "options": {"A": "1:1", "B": "2:3", "C": "3:4", "D": "4:1"}, "answer": "A", "explanation": "The Genotypic ratio is 2 : 2  The genotype ratio of carrier females to normal males in the cross= 1 : 1", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2016>45", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : LINKAGE, SEX DETERMINATION AND SEX LINKED CHARACTERS", "question": "The illustration below represents a cross between a colour-blind male and a normal female.  Study it carefully and answer this question    Which of the genotypes are carriers of colour blindness?", "images": ["Biology/imgs/2016/CLNGXM.png"], "options": {"A": "I and II only", "B": "I and III only", "C": "II and III only", "D": "I, II and III only"}, "answer": "A", "explanation": "The genotype are carrier of colour blindness is I & II.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2016>46", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Scientists who study genetics are known as", "images": [], "options": {"A": "genealogists", "B": "geneticist", "C": "medalists", "D": "gene scientists"}, "answer": "B", "explanation": "Scientists who study genetics are known as geneticists. Genetics is the study of genes, genetic variation, and heredity in organisms. A geneticist is a biologist who studies genetics, the science of genes, heredity, and variation of organisms.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2016>47", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of the following scientists did not contributes to the development of genetics?", "images": [], "options": {"A": "Wilhem Johannsen", "B": "Thomas Morgan", "C": "Gregor Mendel", "D": "Felix Durjadin"}, "answer": "D", "explanation": "Felix Durjadin is the only scientists from the option that do not contribute to the development of genetics. He contributed to the development of cell.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2016>48", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Which of the following terms is associated with natural selection?", "images": [], "options": {"A": "Adaptive radiation", "B": "Differential reproduction", "C": "Population variability", "D": "Survival of the fittest"}, "answer": "D", "explanation": "The term 'Survival of the fittest' is associated with natural selection. Natural selection is a process where organisms that are better adapted to their environment tend to survive and produce more offspring. The term 'Survival of the fittest' was coined by Herbert Spencer after reading Charles Darwin's theory of natural selection and it means that the organisms that are the most fit for their environment are the ones that will survive and reproduce.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2016>49", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "In which of the following insects is group instinct not displayed?", "images": [], "options": {"A": "Soldier ants", "B": "Cockroaches", "C": "Honeybees", "D": "Termites"}, "answer": "B", "explanation": "Group instinct is a type of social behavior displayed by certain animals, including insects, in which they work together in a way that benefits the group as a whole. Soldier ants, honeybees, and termites are known for their group instincts, where they work together for the survival of their colony. Cockroaches, on the other hand, do not display group instinct. They are generally solitary insects and do not work together in a group.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2016>50", "subject": "Biology", "year": "2016", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "The inability of an organism to adapt to its habitat can lead to", "images": [], "options": {"A": "dormancy", "B": "adaptation", "C": "extinction", "D": "survival"}, "answer": "C", "explanation": "If an organism is unable to adapt to its habitat, it may not be able to survive in that environment. This could lead to the extinction of that species. Adaptation is the process by which an organism becomes better suited to its habitat. Dormancy is a period in an organism's life cycle when growth, development, and physical activity are temporarily stopped. Survival is the state of continuing to live or exist, typically in spite of an accident, ordeal, or difficult circumstances. Therefore, the inability to adapt can lead to extinction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>1", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "Which of the following groups of animals do not posses a nervous system?", "images": [], "options": {"A": "Porifera", "B": "Cnidaria", "C": "Platyhelminthes", "D": "Nematoda"}, "answer": "A", "explanation": "Porifera, also known as sponges, do not have a nervous system. They are simple multicellular organisms that lack true tissues and organs. They do not have a nervous system, digestive system, or circulatory system. Instead, they have specialized cells that perform different functions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>2", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "The structural similarities in Paramecium and Euglena are in the", "images": [], "options": {"A": "shape of locomotory organs", "B": "blunt anterior and pointed posterior", "C": "presence of micro and mega nuclei in both", "D": "presence of anterior and posterior contractile vacuoles"}, "answer": "B", "explanation": "The structural similarities in Paramecium and Euglena is the blunt anterior and pointed posterior", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>3", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "Which of the following organisms cannot exist freely on its own?", "images": [], "options": {"A": "Chlamydomonas", "B": "Amoeba", "C": "Paramecium", "D": "Plasmodium"}, "answer": "D", "explanation": "Plasmodium is a genus of parasitic protozoans. They cannot exist freely on their own because they require a host to complete their life cycle. They are known to cause malaria in humans. The other options, Chlamydomonas, Amoeba, and Paramecium, are all free-living organisms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>4", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "The diagram below is an illustration of an Arthropod. Study it and answer this question      The Arthropod in the diagram is not an insect because it", "images": ["Biology/imgs/2017/pix1.png"], "options": {"A": "has a big head which is almost equal to the \"thorax\"", "B": "has eight legs and no wings", "C": "does not have visible eyes on its head", "D": "has head, thorax and abdomen"}, "answer": "B", "explanation": "the arthropods represented in the question has 8 legs while insect has sx legs", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>5", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which of the following cell organelles is the site for the production of ATP?", "images": [], "options": {"A": "Lysosome", "B": "Nucleus", "C": "Mitochondrion", "D": "Ribosome"}, "answer": "C", "explanation": "The mitochondrion is the site for the production of ATP (Adenosine Triphosphate). ATP is often called the 'energy currency of the cell'. It is produced in the mitochondria through a process called cellular respiration, where glucose and oxygen are used to produce ATP, carbon dioxide, and water. The other options, Lysosome, Nucleus, and Ribosome, are not involved in ATP production.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2017>6", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "An example of osmosis in plants is the", "images": [], "options": {"A": "movement of water through the xylem", "B": "loss of water vapour from the stomata", "C": "translocation of food through the phloem", "D": "absorption of water from the soil by the root."}, "answer": "D", "explanation": "Osmosis is the process by which water molecules move from an area of high concentration to an area of low concentration through a semi-permeable membrane. In plants, this process is evident in the absorption of water from the soil by the root hairs. The water in the soil is at a higher concentration than the water in the root hairs, so it moves into the root hairs by osmosis.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2017>7", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION", "question": "The organism that can carry out both autotrophic and heterotrophic modes of nutrition is", "images": [], "options": {"A": "Chlamydomonas", "B": "Eudorina", "C": "Euglena", "D": "Spirogyra"}, "answer": "C", "explanation": "Euglena is a protist which has both plant-like features, e.g chloroplast, and animal-like features, e.g pellicle, hence, it can feed both autotrophically and heterotrophically.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2017>8", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The diagram below illustrates a part of the human skeleton. Study it and answer this question      The diagram represents the bones of the", "images": ["Biology/imgs/2017/pix2.png"], "options": {"A": "upper arm", "B": "lower arm", "C": "upper leg", "D": "lower leg"}, "answer": "B", "explanation": "The bone represented is the bone of the lower arm. Lower Arm (Radius and Ulna):Radius: Located on the lateral side of the forearm (thumb side), it is thicker near the wrist.Ulna: Located on the medial side of the forearm (pinky side), it is thicker near the elbow and has a distinctive olecranon process that forms the elbow joint.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>9", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The diagram below illustrates a part of the human skeleton. Study it and answer this question    Which of the labelled parts articulates with the head of the trochlea to form a hinge joint?", "images": ["Biology/imgs/2017/pix2.png"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "B", "explanation": "II is the point of articulation with the trochlea that forms a hinge joint.  N.B: The trochlea is a structure resembling a pulley, typically in reference to the area connecting the upper and lower arm", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>10", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The diagram below illustrates a part of the human skeleton. Study it and answer this question    The labelled part that provides surface for the attachment of the triceps is", "images": ["Biology/imgs/2017/pix2.png"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "C", "explanation": "The labelled part III provides surface for the attachment of the triceps", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>11", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The diagram below illustrates the transverse section of a", "images": ["Biology/imgs/2017/pix3.png"], "options": {"A": "dicotyledonous root", "B": "monocotyledonous root", "C": "dicotyledonous stem", "D": "monocotyledonous stem"}, "answer": "C", "explanation": "The diagram represented is that of a dicot stem.  It should be noted that, dicot stems have a circular arrangement of vascular tissues whereas the stems of monocots have vascular-tissues bundles scattered through out", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>12", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Which of the following actions does not occur during exhalation in man?", "images": [], "options": {"A": "Thoracic cavity decreases in volume", "B": "Diaphragm flattens", "C": "Ribs move down and in", "D": "Air pressure increases in the thoracic cavity"}, "answer": "B", "explanation": "During exhalation, the diaphragm relaxes and moves upward, creating a dome shape. It does not flatten. The flattening of the diaphragm occurs during inhalation, not exhalation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2017>13", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "The diagram below is an illustration of the urinary tubule in a mammal. Study it and answer this question      Which of the following substances is found in the part labelled II only?", "images": ["Biology/imgs/2017/pix4.png"], "options": {"A": "Lipid", "B": "Protein", "C": "Salts", "D": "Water"}, "answer": "B", "explanation": "The diagram illustrated in the question is the nephron, the functional unit of the kidney.  The part labelled II is the renal artery it contains only blood proteins.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>14", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "The diagram below is an illustration of the urinary tubule in a mammal. Study it and answer this question    The part which contains the lowest concentration of urea is labelled", "images": ["Biology/imgs/2017/pix4.png"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "A", "explanation": "The part of the nephron which contains the lowest concentration of urea is the malphigian corpuscle (I)", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>15", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "The diagram below is an illustration of the urinary tubule in a mammal. Study it and answer this question    Which of the following substances is greater in concentration in the part labelled IV when compared to that of the part labelled I?", "images": ["Biology/imgs/2017/pix4.png"], "options": {"A": "Lipid", "B": "Glucose", "C": "Urea", "D": "Uric acid"}, "answer": "C", "explanation": "The concentration of urea is higher in the collecting tubule compared to the Malphigian corpusle", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>16", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Deamination of amino acids in the liver produces", "images": [], "options": {"A": "blood sugar", "B": "glycogen", "C": "bile", "D": "urea"}, "answer": "D", "explanation": "The process of deamination occurs in the liver. It is a process of protein metabolism, where the amino group of one protein is removed. This removed amino group is either transferred to a keto acid to form new compound or conjugated with CO2 via the urea cycle to form UREA which is later excreted through the kidney.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2017>17", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "Which of the following glands also serves as an exocrine gland?", "images": [], "options": {"A": "Ovary", "B": "Pancreas", "C": "Adrenal", "D": "Thyroid"}, "answer": "B", "explanation": "The pancreas serves as both an endocrine and an exocrine gland. As an endocrine gland, it produces hormones such as insulin and glucagon, which are released into the blood to control blood sugar levels. As an exocrine gland, it produces digestive enzymes that are released into the small intestine to aid in digestion.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2017>18", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "Which of the following sequences is the correct route of the transmission of impulses along a reflex arc?", "images": [], "options": {"A": "Receptor → sensory neurone → synapse→  intermediate neurone → synapse → motor neurone → effector", "B": "Receptor → motor neurone → synapse → intermediate neurone → synapse → sensory neurone → effector", "C": "Effector → intermediate neurone → synapse → motor neurone → synapse → sensory neurone → receptor", "D": "Effector → motor neurone → synapse → sensory neurone → synapse → intermediate neurone → receptor"}, "answer": "A", "explanation": "The transmission of impulses along a reflex can be represented as   Receptor  ↓  Sensory Neurone  ↓  Synapse intermediate neurone  ↓  Synapse  ↓  Motor neurone effector", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>19", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "When viewing an object that is close to the human eye, the", "images": [], "options": {"A": "eye lens becomes thin", "B": "ciliary muscles relax", "C": "suspensory ligaments become taut", "D": "eye lens become fat"}, "answer": "D", "explanation": "When viewing an object that is close to the human eye, the eye lens becomes fat. This is because the ciliary muscles contract, which reduces the tension on the suspensory ligaments holding the lens in place. This allows the lens to become more convex (or 'fatter') to increase its refractive power and focus on the close object. This process is known as accommodation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2017>20", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "The diagram below is an illustration of the human sperm. Study it and answer this question.      The part labelled I is the", "images": ["Biology/imgs/2017/pix5.png"], "options": {"A": "acrosome", "B": "nucleus", "C": "mitochondrion", "D": "tail"}, "answer": "A", "explanation": "The part labelled I is the acrosome. It is the pointed part of the \"head\" of the spermatozoan.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>21", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "The diagram below is an illustration of the human sperm. Study it and answer this question.    The function of the part labelled II is to", "images": ["Biology/imgs/2017/pix5.png"], "options": {"A": "fuse with the ovum during fertilization", "B": "generate the energy for the sperm to swim to the fallopian tube", "C": "help the sperm to swim forward", "D": "dissolve the membrane of the egg during fertilization"}, "answer": "C", "explanation": "The part labelled II is the tail. Its function is to propel (swim) the spermatozoon forward.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>22", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following types of placentation is not common amongst synacarpous pistils?", "images": [], "options": {"A": "Marginal", "B": "Axile", "C": "Parietal", "D": "Free central"}, "answer": "B", "explanation": "Axile placentation is not common amongst syncarpous pistil  In axile placentation ovules are borne at or around the center of a compound ovary or an axis from joined speta. This kind of placentation is not found in syncarpous ovaries in which carpets are fused by their stigmas but possess distinct ovaries", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>23", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "The complex energy-rich organic matter which living organisms need for life is", "images": [], "options": {"A": "water", "B": "air", "C": "food", "D": "mineral salts"}, "answer": "C", "explanation": "The complex energy-rich organic matter which living organisms need for life is food. Food provides the energy and nutrients that organisms need to be alive and healthy. It contains macronutrients like carbohydrates, proteins, and fats which are used for energy and growth, and micronutrients like vitamins and minerals which are needed in smaller amounts but are still essential for function and health.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2017>24", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following processes are associated with photosynthesis?  I. Energy from sunlight is absorbed   II. Carbon dioxide is evolved  III. Oxygen is given off  IV. Glucose is synthesized", "images": [], "options": {"A": "I and II only", "B": "I, II and IV only", "C": "I, III and IV only", "D": "I, II, III and IV"}, "answer": "C", "explanation": "During the process of photosynthesis.  - Energy from sunlight is absorbed  - Oxygen is given off as by-product  - Glucose is synthesized  I, III and IV are processed associated with photosynthesis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>25", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following functions is associated with calcium in plants? Formation of", "images": [], "options": {"A": "cell wall", "B": "ribosomes", "C": "proteins", "D": "cell membrane"}, "answer": "A", "explanation": "Calcium plays a crucial role in the formation of the cell wall in plants. It is a part of the middle lamella, which is the layer between the primary walls of adjacent cells. It helps in the formation of calcium pectate, which provides rigidity to the cell wall.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2017>26", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "The diagrams below are illustrations of the dentition of an organism. Study them and answer this question.      The dentition belongs to a", "images": ["Biology/imgs/2017/pix6.png"], "options": {"A": "rabbit", "B": "cat", "C": "frog", "D": "man"}, "answer": "D", "explanation": "The dental formula represented in the question is :  I &nbsp C &nbsp P &nbsp& M  2 : 1 : 2 : 3  Hence, the dentition is for man", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>27", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "The diagrams below are illustrations of the dentition of an organism. Study them and answer this question.    The function of the teeth labelled X is for", "images": ["Biology/imgs/2017/pix6.png"], "options": {"A": "biting and grasping", "B": "chewing and grinding", "C": "tearing and grasping", "D": "chewing and tearing"}, "answer": "C", "explanation": "X is the canine. The teeth labelled X are pointed and located next to the incisors, which are characteristics of canines. Canines are primarily used for tearing and grasping food.Therefore, the function of the teeth labelled X is: Tearing and grasping.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>28", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "The diagrams below are illustrations of the dentition of an organism. Study them and answer this question.    The teeth which are absent in the young of the organism are labelled", "images": ["Biology/imgs/2017/pix6.png"], "options": {"A": "W", "B": "X", "C": "Y", "D": "Z"}, "answer": "D", "explanation": "Young man (children) lack molar in their dentition", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>29", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING", "question": "The number of individuals that the environment can support over a long period of time is its", "images": [], "options": {"A": "growth rate", "B": "total capacity", "C": "population capacity", "D": "carrying capacity"}, "answer": "D", "explanation": "The carrying capacity of an environment is the maximum population size of a biological species that can be sustained over a long period of time given the availability of resources. It is a concept in population biology, which examines the dynamics of species populations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2017>30", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "ECOLOGY OF POPULATION : ECOLOGICAL SUCCESSION", "question": "A good site for secondary succession would be", "images": [], "options": {"A": "a sand dune", "B": "a bare rock", "C": "a land that has just has forest fire", "D": "a stretch of barren land"}, "answer": "C", "explanation": "A good site for secondary session would be a land that has just had forest fire.  N.B: Secondary succession is the ecological succession that occurs after the initial succession has been disrupted and some plants and animals still exist. It is usually faster than secondary succession as:  1. Soil is already present  2. There are still some remnants of seeds, roots and underground vegetative organs of plants.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>31", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION", "question": "A population which exceeds its carrying capacity and then collapses is represented graphically by a", "images": [], "options": {"A": "bell-shaped curve", "B": "linear curve", "C": "sigmoid curve", "D": "skewed curve"}, "answer": "A", "explanation": "A population which exceeds its carrying capacity and then collapses is represented graphically by a bell-shaped curve. This is because the population grows rapidly at first, then slows as it approaches the carrying capacity of the environment (the maximum population size that the environment can sustain indefinitely). Once the population exceeds the carrying capacity, it collapses, leading to a rapid decrease in population size. This creates a bell-shaped curve when graphed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>32", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "The natural dwelling place of an organism is called its", "images": [], "options": {"A": "ecological niche", "B": "habitat", "C": "population", "D": "environment"}, "answer": "B", "explanation": "The natural dwelling place of an organism is referred to as its 'habitat'. This is the place where an organism lives and grows under natural conditions. An 'ecological niche' refers to the role and position a species has in its environment; how it meets its needs for food and shelter, how it survives, and how it reproduces. A 'population' refers to a group of individuals of the same species living in a specific geographical area and 'environment' refers to the surroundings or conditions in which a person, animal, or plant lives or operates.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2017>33", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Which of the following ecological factors will result in food shortage?", "images": [], "options": {"A": "Drought", "B": "Low rate of reproduction", "C": "Emigration", "D": "Topography"}, "answer": "A", "explanation": "Drought is an ecological factor that can result in food shortage. Drought conditions mean less water availability for plants, which can lead to reduced plant growth and productivity, and subsequently less food availability for herbivores and omnivores. 'Low rate of reproduction' could potentially lead to a decrease in population size, but not necessarily a food shortage. 'Emigration' refers to the act of leaving one's own habitat to move to another, which could potentially affect food availability in the new habitat, but it's not a direct cause of food shortage. 'Topography' refers to the physical features of land, including its shapes and contours, and while it can influence where organisms live and what food sources are available, it's not a direct cause of food shortage.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>34", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS", "question": "Soil permeability refers to", "images": [], "options": {"A": "how easily water passes through the soil", "B": "the proportion of air in the soil", "C": "the proportion of water the soil holds", "D": "how well water rises up the soil"}, "answer": "A", "explanation": "Soil permeability refers to the ability of the soil to allow water to pass through it. This is determined by the size and connectivity of the pore spaces in the soil. Larger and more connected pore spaces increase the soil's permeability.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2017>35", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION", "question": "Which of the following groups of organisms do not have members that can be called autotrophs?", "images": [], "options": {"A": "Protists", "B": "Mosses", "C": "Chlorophyta", "D": "Fungi"}, "answer": "D", "explanation": "Autotrophs are organisms that can produce their own food from inorganic substances, using light or chemical energy. Fungi are not autotrophs, they are heterotrophs, meaning they obtain their food from other organisms. Protists, Mosses, and Chlorophyta all have members that can be called autotrophs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>36", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "Which of the following pyramids gives the most accurate picture of the relationships between the organisms at the various trophic levels in a food chain? A pyramid of", "images": [], "options": {"A": "numbers", "B": "energy", "C": "biomass", "D": "size"}, "answer": "B", "explanation": "A pyramid of energy gives the most accurate picture of the relationships between the organisms at the various trophic levels in a food chain. This is because it takes into account not only the number of organisms at each level, but also the amount of energy they have stored, which is a more direct measure of their role in the ecosystem. The energy pyramid shows the decreasing amounts of energy at each higher trophic level, reflecting the energy loss from metabolic processes like respiration, growth and reproduction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>37", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "Which of the following statements is not associated with pyramids of energy?", "images": [], "options": {"A": "Efficiency of energy transfer between trophic levels can be studied", "B": "Comparisons of pyramids for different ecosystems can be made", "C": "More accurate comparisons of trophic levels", "D": "Representation of numbers of organisms at different trophic levels"}, "answer": "D", "explanation": "This statement is associated with pyramids of numbers, not pyramids of energy. Pyramids of energy represent the flow of energy through trophic levels, not the number of organisms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>38", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Which of the following materials is not easily biodegradable?", "images": [], "options": {"A": "Polythene bag", "B": "Cotton bag", "C": "Hides and skin bag", "D": "Paper bag"}, "answer": "A", "explanation": "Biodegradable materials are those that can be broken down by natural processes, such as the action of bacteria, fungi, and other decomposers. Polythene bags are made from petroleum products and are not easily broken down by these natural processes, making them non-biodegradable. On the other hand, cotton bags, hides and skin bags, and paper bags are all made from natural materials that can be broken down by decomposers, making them biodegradable.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2017>39", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS", "question": "Which of the following pairs of organisms is in a mutualistic relationship?", "images": [], "options": {"A": "Hydra and Sea anemone", "B": "Hermit crab and Sea anemone", "C": "Dodder plant and Cocoa Plant", "D": "Mistletoe and Kolanut"}, "answer": "B", "explanation": "A mutualistic relationship is one in which both organisms benefit. In the case of the hermit crab and the sea anemone, the hermit crab uses the sea anemone for protection, while the sea anemone gets a free ride and access to more food. The other pairs listed do not have mutualistic relationships. The hydra and sea anemone do not interact in a way that benefits both, while the dodder plant and cocoa plant, and the mistletoe and kolanut, are examples of parasitic relationships, where one organism benefits at the expense of the other.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>40", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "The establishment of game reserves and parks is a method of", "images": [], "options": {"A": "conserving natural resources", "B": "cultivating game", "C": "controlling pollution", "D": "cultural awareness"}, "answer": "A", "explanation": "The establishment of game reserves and parks is a method of conserving natural resources. Game reserves and parks are protected areas where wildlife can live and breed without threat from hunting or habitat destruction. This helps to maintain biodiversity and conserve natural resources.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2017>41", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "Which of the following practices is not used in conserving water?", "images": [], "options": {"A": "Afforestation", "B": "Damming", "C": "Deforestation", "D": "Reforestation"}, "answer": "C", "explanation": "Deforestation is not a practice used in conserving water. In fact, it is the opposite. Deforestation involves the removal of trees which play a crucial role in the water cycle. Trees absorb water from the soil and release it into the atmosphere through a process called transpiration. When trees are removed, this process is disrupted leading to less moisture being released into the atmosphere and potentially less rainfall. The other options, afforestation, damming, and reforestation, are all practices that help in water conservation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>42", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "Which of the following resources cannot be renewed?", "images": [], "options": {"A": "Air", "B": "Petroleum", "C": "Food crop", "D": "Soil"}, "answer": "B", "explanation": "Renewable resources are those that can be replenished naturally in the course of time. Air, food crops, and soil are renewable resources because they can be naturally replenished. Petroleum, on the other hand, is a non-renewable resource because it takes millions of years to form from the remains of plants and animals. Once we have used up all the petroleum, we cannot get more in a human timescale.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>43", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Use the diagram below to answer this question      The type of variation illustrated above is", "images": ["Biology/imgs/2017/pix7.png"], "options": {"A": "continuous variation", "B": "discontinuous variation", "C": "morphological variation", "D": "environmental variation"}, "answer": "B", "explanation": "Rolling of the tongue is considered a discontinuous variation because it is a trait that is clearly distinct and is controlled by a single gene with two alleles. Discontinuous variation refers to traits that do not show a range or spectrum but instead are characterized by distinct, separate categories. Individuals can either roll their tongue or cannot, with no intermediate forms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>44", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Which of the following characters is not a morphological variation?", "images": [], "options": {"A": "Shaper of the nose", "B": "Colour of skin", "C": "Colour of hair", "D": "Tongue rolling"}, "answer": "D", "explanation": "Morphological variations refer to the physical differences between individuals of the same species. These can include differences in size, shape, and color. The shape of the nose, color of skin, and color of hair are all examples of morphological variations. Tongue rolling, however, is not a morphological variation. It is a genetic trait that is inherited from parents. It does not involve any physical differences in the structure or appearance of the body.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>45", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "An apple plant can produce sexually and asexually and it has 40 chromosomes in its leaf cells. How many chromosomes would be in each gamete and somatic cell?", "images": [], "options": {"A": "20 chromosomes in the gametes and 10 in the somatic cells", "B": "40 chromosomes in the gametes and 20 in the somatic cells", "C": "20 chromosomes in the gametes and 40 in the somatic cells", "D": "40 chromosomes in the gametes and 40 in the somatic cells"}, "answer": "C", "explanation": "The number of chromosomes in the gamete is usually half of the total chromosomes, and that in the somatic cell is usually equal to that in the cell.  Hence, there are 20 chromosomes in the gamete and 40 chromosomes in the somatic cell.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2017>46", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Assuming that A is the gene for normal skin colour and is dominant, while a is the gene for albinism and is recessive, what is the likely genotype of the couple which had 50% normal and 50% albino offspring?", "images": [], "options": {"A": "AA, aa", "B": "Aa, aa", "C": "AA, Aa", "D": "Aa, Aa"}, "answer": "B", "explanation": "The most likely genotypes of the parent that could result in 50% normal and 50% albino offsping are:  Aa aa  Proof:    Phenotypic ratio:   1 &nbsp &nbsp : &nbsp &nbsp  1  50% 50%", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>47", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of the following statements is true about mutation?", "images": [], "options": {"A": "Phenotype is not involved", "B": "Genotype is not involved", "C": "Artificial induction is not possible", "D": "Genotype is involved"}, "answer": "D", "explanation": "Mutation is a change in the DNA sequence of a gene. This change can affect the genotype (the genetic makeup of an organism) and potentially the phenotype (the physical and physiological traits of an organism). Therefore, the statement 'Genotype is involved' is true about mutation. Artificial induction of mutation is also possible, for example, by exposure to radiation or certain chemicals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>48", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "One of the structural adaptations of mammals for movement on land is the development of the", "images": [], "options": {"A": "hollow bones", "B": "pentadactyl limb", "C": "fused thoracic bones", "D": "streamlined body"}, "answer": "B", "explanation": "Mammals have developed the pentadactyl limb for movement on land. The pentadactyl limb is a limb with five digits, like a human hand or foot, that is found in most mammals. This structure allows for a wide range of movement and flexibility, enabling mammals to adapt to different environments and modes of locomotion, such as running, climbing, swimming, or flying.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>49", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following traits is not characteristic of social insects?", "images": [], "options": {"A": "All members are identical", "B": "There is division of labour", "C": "The members dwell in the same habitat", "D": "Some members protect the queen"}, "answer": "A", "explanation": "In social insects, all members are not identical. There is usually a division of labor among different types of individuals (castes), such as workers, soldiers, and reproductive individuals (queens and males). Each caste has a different appearance and role within the colony. Therefore, the statement 'All members are identical' is not characteristic of social insects.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2017>50", "subject": "Biology", "year": "2017", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "The gradual cumulative, adaptive and heritable changes in an organism over a long period of time resulting in new species is called", "images": [], "options": {"A": "adaptation", "B": "survival", "C": "organic evolution", "D": "interspecific competition"}, "answer": "C", "explanation": "The gradual cummulative, adaptive and inheritable changes in an organism over a long period of time resulting in new species is termed ORGANIC EVOLUTION  N.B: EVOLUTION means CHANGES", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>1", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "The scientist who introduced binomial nomenclature in the classification of organisms was", "images": [], "options": {"A": "Charles Darwin", "B": "Carolus Linnaeus", "C": "John Ray", "D": "Louis Pasteur"}, "answer": "B", "explanation": "The scientist who introduced binomial nomenclature in the classification of organisms was Carolus Linnaeus. Binomial nomenclature is a system of naming species of living things by giving each a name composed of two parts, both of which use Latin grammatical forms, although they can be based on words from other languages. The first part of the name identifies the genus to which the species belongs; the second part identifies the species within the genus. For example, humans belong to the genus Homo and within this genus to the species Homo sapiens.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>2", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "Which of the following statement is true about arthropods?", "images": [], "options": {"A": "Prothorax bears only legs", "B": "Mesothorax bears only legs", "C": "Metathorax bears only wings", "D": "Prothorax bears only wings"}, "answer": "A", "explanation": "Arthropods are a group of invertebrate animals in the Phylum Arthropoda. They include insects, arachnids, myriapods, and crustaceans. These organisms have segmented bodies and jointed limbs, covered by a hard exoskeleton that must be periodically shed and renewed. In insects, which are a type of arthropods, the body is divided into three parts: head, thorax, and abdomen. The thorax itself is divided into three segments: prothorax, mesothorax, and metathorax. The prothorax is the first segment of the thorax, and it bears the first pair of legs. Therefore, the statement 'Prothorax bears only legs' is true about arthropods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>3", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "Which level of organization is spirogyra?", "images": [], "options": {"A": "Organ system", "B": "Organ", "C": "Cell", "D": "Tissue"}, "answer": "C", "explanation": "Spirogyra is a genus of filamentous green algae of the order Zygnematales. It is named for the helical or spiral arrangement of the chloroplasts that is characteristic of the species. It is commonly found in freshwater habitats, and there is no multicellular stage in its life cycle. It therefore exists at the cellular level of organization. An organism at the cellular level of organization is made up of cells, which are the basic units of life. In the case of Spirogyra, each filament is composed of end-to-end rows of cells. Therefore, the level of organization of Spirogyra is 'Cell'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2018>4", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The streaming movement of cytoplasm within paramecium is known as", "images": [], "options": {"A": "transpiration", "B": "digestion", "C": "cyclosis", "D": "osmosis"}, "answer": "C", "explanation": "The streaming movement of cytoplasm within cells, such as paramecium, is known as cyclosis. Cyclosis, also known as cytoplasmic streaming, is the directed flow of cytosol (the liquid component of the cytoplasm) and organelles around the cell. This movement aids in the delivery of nutrients, proteins, and organelles to all parts of the cell.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2018>5", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which of the following organelles is found only in plant?", "images": [], "options": {"A": "Mitochondria", "B": "Ribosomes", "C": "Lysosomes", "D": "Plastids"}, "answer": "D", "explanation": "Plastids are double-membrane organelle which are found in the cells of plants and algae. Plastids are responsible for manufacturing and storing of food. These often contain pigments that are used in photosynthesis and different types of pigments that can change the colour of the cell.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2018>6", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL AND ITS ENVIRONMENT", "question": "Active transport differs from diffusion in that active transport", "images": [], "options": {"A": "is a very fast process", "B": "allows the movement of substances against concentration gradients", "C": "takes place in both light and dark reactions of photosynthesis", "D": "occurs in both plant and animal tissues"}, "answer": "B", "explanation": "Active transport is a process that moves molecules into cells even though they are moving against a concentration gradient. This is different from diffusion, which only moves molecules down a concentration gradient. Therefore, the correct answer is 'allows the movement of substances against concentration gradients'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>7", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The diagrams below are illustration of an experimental set-up to demonstrate a type of tropic response in plants. Study them and answer the questions below       The type of response demonstrated is", "images": ["Biology/imgs/2018/le.png"], "options": {"A": "phototropism", "B": "geotropism", "C": "hydrotropism", "D": "thigmotropism"}, "answer": "C", "explanation": "The plants tend to move near or towards the watered soil. Hydrotropism is a plant's growth response to water gradients in its environment. It is a type of tropism, which is the movement or growth of an organism in response to an external stimulus.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>8", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The diagrams below are illustration of an experimental set-up to demonstrate a type of tropic response in plants. Study them and answer the questions below     The conclusion drawn from the experiment is that", "images": ["Biology/imgs/2018/le.png"], "options": {"A": "shoots of the plants are negatively thigmotropic", "B": "shoots of plants are negatively geotropic", "C": "leaves of plants are positively phototropic", "D": "roots of plants are positively hydrotropic"}, "answer": "D", "explanation": "The root grows towards the source of water, i.e the root is positively hydrotropic and geotropic.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>9", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The odontoid process is found on the", "images": [], "options": {"A": "axis vertebra", "B": "atlas vertebra", "C": "thoracic vertebra", "D": "sacral vertebra"}, "answer": "A", "explanation": "The odontoid process, also known as the dens, is a protrusion of the C2 vertebra, also known as the axis. It is not found on the atlas, thoracic, or sacral vertebrae. Therefore, the correct answer is 'axis vertebra'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2018>10", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "A seedling was made to stand in solution of red ink for three hours and a transverse section of the stem was examined under the microscope. The process investigated was", "images": [], "options": {"A": "the important of micro element to plants", "B": "ascent of water through the xylem", "C": "diffusion of coloured substances", "D": "distribution of food in plants"}, "answer": "B", "explanation": "The process investigated in the question is the ascent of water through the xylem. This is a process in plants where water is transported from the roots to the rest of the plant, primarily through the xylem tissue. The red ink in the solution would have been drawn up through the xylem, demonstrating this process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>11", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Which of the following structures would carry out respiration?", "images": [], "options": {"A": "germinating cowpea", "B": "decolorized leaf", "C": "dry leaf", "D": "boiled cowpea"}, "answer": "A", "explanation": "The structure that would carry out respiration among the options is a germinating cowpea. Respiration is a metabolic process that converts nutrients into energy in the presence of oxygen. A germinating seed, such as a cowpea, would be actively respiring as it uses stored nutrients to grow. The other options (decolorized leaf, dry leaf, boiled cowpea) are not capable of respiration. A decolorized leaf lacks chlorophyll and cannot photosynthesize or respire, a dry leaf is dead and therefore not metabolically active, and a boiled cowpea has been heat-treated, killing the seed and stopping all metabolic processes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2018>12", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which of the following substances is not an excretory product of animals?", "images": [], "options": {"A": "Carbon dioxide", "B": "Urea", "C": "Sweat", "D": "Oxygen"}, "answer": "D", "explanation": "Excretion is the process by which metabolic waste is eliminated from an organism. In animals, the main excretory products are carbon dioxide, urea, and sweat. Oxygen is not an excretory product but rather a product of respiration that is used by the body for various metabolic processes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2018>13", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "An example of homeostasis in living organisms is", "images": [], "options": {"A": "cooling effect resulting from evaporation of water from the body surface.", "B": "root hairs of a plant growing towards a source of light", "C": "changing of the body colour of chameleon to match the colour of the foliage on which it is resting", "D": "the release of phosphorus into the phloem of a plant growing in a phosphorus-deficient soil"}, "answer": "A", "explanation": "Homeostasis is the ability to maintain a constant internal environment in response to environmental changes. It is a unifying principle of biology. The nervous and endocrine systems control homeostasis in the body through feedback mechanisms involving various organs and organ systems", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>14", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Ultrafiltration in the kidney takes place in the", "images": [], "options": {"A": "renal vein", "B": "medulla", "C": "loop of Henle", "D": "bowman's capsule."}, "answer": "D", "explanation": "Ultrafiltration in the kidney takes place in the Bowman's capsule. Ultrafiltration is the process by which small molecules such as water, glucose, amino acids, and urea are filtered out of the blood and into the Bowman's capsule in the kidneys. This is the first step in the process of urine formation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2018>15", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "The thyroid gland is located at the base of the", "images": [], "options": {"A": "midbrain", "B": "kidney", "C": "neck", "D": "liver"}, "answer": "C", "explanation": "The thyroid gland is located at the base of the neck. The thyroid gland is a butterfly-shaped organ located in the front of the neck, below the Adam's apple. It produces hormones that regulate the body's metabolic rate, heart and digestive function, muscle control, brain development and bone maintenance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2018>16", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "Which of the following statements about the response of neurones to stimulus is correct?", "images": [], "options": {"A": "Neurones respond to stimulus of any strength", "B": "Neurones respond to all stimuli applied in rapid succession", "C": "Neurones respond more rapidly during the absolute refractory period", "D": "Intensity of stimulus must reach a threshold value before the neurones can be excited"}, "answer": "D", "explanation": "Neurons respond to stimuli only when the intensity of the stimulus reaches a certain threshold value. This is known as the 'all-or-none' principle. If the stimulus is below the threshold, the neuron will not fire. If the stimulus is at or above the threshold, the neuron will fire. This is why option 4 is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>17", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH", "question": "Which of the following practice may lead to infection of the eye? Use of", "images": [], "options": {"A": "contact lenses", "B": "convex lenses", "C": "biconcave lenses", "D": "concave lenses"}, "answer": "A", "explanation": "The use of contact lenses can lead to eye infections if they are not properly cleaned and cared for. Bacteria, fungi, and other microorganisms can grow on the lenses and cause infections. This is not the case with convex, biconcave, or concave lenses, as they do not come into direct contact with the eye. Therefore, option 1 is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>18", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "The structures for gaseous exchange in breathing root are", "images": [], "options": {"A": "stomata", "B": "lenticels", "C": "cuticle", "D": "mitochondria"}, "answer": "B", "explanation": "The structures for gaseous exchange in breathing roots are lenticels. Lenticels are small pores in the bark of stems and roots of woody plants that allow gas exchange between the atmosphere and the internal tissues. They are not stomata, which are found on leaves, nor cuticle, which is a waxy layer on the surface of plants, nor mitochondria, which are organelles within cells.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>19", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : LIFE CYCLES", "question": "The diagram below is an illustration of the life cycle of an insect. Study it and answer questions 19 and 20.       The adult insect in this life cycle is", "images": ["Biology/imgs/2018/n.png"], "options": {"A": "housefly", "B": "butterfly", "C": "cockroach", "D": "mosquito"}, "answer": "B", "explanation": "Butterfly has a caterpillar as its larvae and its pupa wrapped up in a silk.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>20", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : LIFE CYCLES", "question": "The diagram below is an illustration of the life cycle of an insect. Study it and answer questions 19 and 20.     The larva is also known as", "images": ["Biology/imgs/2018/n.png"], "options": {"A": "nymph", "B": "maggot", "C": "caterpillar", "D": "chrysalis"}, "answer": "C", "explanation": "Caterpillar: This is the larval stage of butterflies and moths. Caterpillars are typically terrestrial, have a segmented body, and possess legs. They are known for their role in consuming large amounts of plant material before pupating and transforming into their adult forms.    Larva: This is the juvenile form of various animals that undergo metamorphosis, including insects like mosquitoes. Mosquito larvae, often called \"wrigglers,\" live in water and have a distinct appearance, different from their adult form. They do not have legs and move by wriggling through the water.    Note: A larva is not the same as a caterpillar in mosquitoes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2018>21", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "The source of energy required by plants during food production is", "images": [], "options": {"A": "photosynthesis", "B": "chlorophyll", "C": "sunlight", "D": "microorganisms"}, "answer": "C", "explanation": "The source of energy required by plants during food production is sunlight. This process is called photosynthesis, where plants convert sunlight, carbon dioxide, and water into glucose (food) and oxygen. Chlorophyll is the pigment in plants that absorbs sunlight and is crucial for photosynthesis, but it is not the source of energy. Microorganisms are not involved in this process.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2018>22", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "One major difference between plant and animal nutrition is the ability of plants to synthesize", "images": [], "options": {"A": "food for plants and animals", "B": "water for plants", "C": "water for animals", "D": "food for plants only"}, "answer": "A", "explanation": "The major difference between plant and animal nutrition is the ability of plants to synthesize food for both plants and animals. Plants, being autotrophs, can synthesize their own food through the process of photosynthesis. Animals, being heterotrophs, cannot synthesize their own food and depend on plants or other animals for their nutrition.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2018>23", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "By what process is starch converted into maltose", "images": [], "options": {"A": "hydrolysis", "B": "condensation", "C": "translocation", "D": "photosynthesis"}, "answer": "A", "explanation": "Starch is converted into maltose through the process of hydrolysis. Hydrolysis is a chemical reaction in which water is used to break down a compound. In this case, water is used to break down the starch molecule into maltose. Therefore, the correct answer is 'hydrolysis'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>24", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "The ascent of water in tall tree is mainly due to", "images": [], "options": {"A": "adhesive forces", "B": "transpiration pull", "C": "root pressure", "D": "cohesive forces"}, "answer": "B", "explanation": "The ascent of water in tall trees is mainly due to the transpiration pull. Transpiration pull is the main mechanism of water movement in plants. When water evaporates from the leaves, a negative pressure (or suction) is created that pulls water from the roots and up the stem in the xylem. This process is facilitated by the cohesive and adhesive properties of water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>25", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "The duodenum of a person was surgically removed. Which of the following food substances would have their digestion affected?", "images": [], "options": {"A": "Starch and protein only", "B": "Starch and lipids", "C": "Starch,peptones and maltose", "D": "Starch, protein and lipids"}, "answer": "D", "explanation": "The duodenum is the first part of the small intestine immediately beyond the stomach, leading to the jejunum. It is the primary site for the digestion of food in the small intestine. It receives gastric chyme from the stomach, together with digestive juices from the pancreas (digestive enzymes) and the liver (bile). Enzymes break down proteins into peptones and proteoses, fats into fatty acids and glycerol, and carbohydrates into simple sugars like glucose, fructose, etc. Therefore, if the duodenum of a person was surgically removed, the digestion of starch, protein, and lipids would be affected.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>26", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "Which of the following dental formulae represents the dentition in rabbits?", "images": [], "options": {"A": "I 2∕1 C 0∕0 P 2∕2 M 3∕3", "B": "I 2∕2 C 1∕2 P 2∕2 M 3∕3", "C": "I 1∕2 C 0∕0 P 2∕3 M 3∕3", "D": "I 2∕1 C 0∕1 P 1∕2 M 3∕3"}, "answer": "A", "explanation": "In rabbits, the dental formula should be:  I 2/1, C 0/0, P 3/2, M 3/3    This means:  Incisors (I): Rabbits have 2 upper and 1 lower incisor on each side.   Canines (C): Rabbits do not have canine teeth.  Premolars (P): Rabbits have 3 upper and 2 lower premolars on each side.  Molars (M): Rabbits have 3 upper and 3 lower molars on each side.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>27", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "The diagram below is an illustration of an experimental set-up to demonstrate a property of soil. Study it and answer questions 27 and 28.       The property of soil demonstrated is", "images": ["Biology/imgs/2018/w.png"], "options": {"A": "particle size", "B": "capillarity", "C": "colour", "D": "texture"}, "answer": "B", "explanation": "It is to determine the rate at which the soils absorb water, i.e, to know the level to which water has risen in each of the tubes. The water in this case, is known as capillarity water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>28", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "The diagram below is an illustration of an experimental set-up to demonstrate a property of soil. Study it and answer questions 27 and 28.     Which of the following statements would be a correct observation at the end of the experiment? Water moves", "images": ["Biology/imgs/2018/w.png"], "options": {"A": "highest in sandy soil", "B": "lowest in loamy soil", "C": "to the same level in all soil types", "D": "highest in clayey soil"}, "answer": "D", "explanation": "Sandy soil:  Larger particles and pores reduce capillary rise.  Loamy soil: Capillary rise varies based on soil composition; not necessarily lowest.  Same level in all soils: Capillary rise differs due to soil texture and pore size.  Clayey soil: Smaller particles and pores enhance capillary rise, making it highest.    Therefore, highest in clayey soil is correct because fine particles and small pores in clayey soil promote stronger capillary action compared to sandy or loamy soils", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>29", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "The most important factor(s) that influence(s) the ecological niche of an organism is/are the", "images": [], "options": {"A": "water, light and predator-prey relationship", "B": "food and water availability", "C": "physical environment", "D": "competition for food and space"}, "answer": "D", "explanation": "The most important factor(s) that influence(s) the ecological niche of an organism is/are competition for food and space.    Ecological niche refers to the role and position of an organism within its environment, including how it obtains food, shelter, and interacts with other species. Competition for resources like food and space is a critical factor that shapes the niche of an organism, influencing its survival and reproduction strategies", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>30", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "The diagram below is an illustration of organisms in an air-tight aquarium. The most important factor needed by the organisms is", "images": ["Biology/imgs/2018/h.png"], "options": {"A": "light energy", "B": "low humidity", "C": "oxygen", "D": "nitrate"}, "answer": "C", "explanation": "Since the aquarium is air-tight, there is a low possibility of having dissolved oxygen in it.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2018>31", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS", "question": "Which of the following instruments is used to determine the turbidity of water?", "images": [], "options": {"A": "Hygrometer", "B": "Hydrometer", "C": "Secchi disc", "D": "Rain gauge"}, "answer": "C", "explanation": "A Secchi disc is used to measure water transparency or turbidity in bodies of water. It is a circular disc, divided into quarters of alternating black and white color, which is lowered into the water until it can no longer be seen; the depth it reaches before disappearing is known as the Secchi depth, which gives a measure of the transparency or turbidity of the water.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2018>32", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "In an ecosystem, the least efficient energy transfer link is from the", "images": [], "options": {"A": "secondary consumers to decomposers", "B": "sun to producers", "C": "primary consumers to secondary consumers", "D": "producer to primary consumers"}, "answer": "A", "explanation": "In ecosystems, energy is transferred through trophic levels, starting from producers (plants) to primary consumers (herbivores), then to secondary consumers (carnivores), and so on. The efficiency of energy transfer decreases as you move up the trophic levels.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>33", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Xerophytes have the following characteristics aimed at conserving water except", "images": [], "options": {"A": "thick cuticle", "B": "broad leaf surfaces", "C": "sunken stomata", "D": "waxy cuticle"}, "answer": "B", "explanation": "Xerophytes are plants that are adapted to survive in dry environments with little water. They have several adaptations to conserve water, such as a thick cuticle, sunken stomata, and a waxy cuticle. However, they do not have broad leaf surfaces. Broad leaf surfaces would increase the surface area for evaporation, which would lead to more water loss. Therefore, xerophytes typically have small, narrow leaves or no leaves at all to minimize water loss.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>34", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS", "question": "An association between living organisms in which one lives on and feeds at the expense of the other is known as", "images": [], "options": {"A": "commensalism", "B": "predation", "C": "parasitism", "D": "mutualism"}, "answer": "C", "explanation": "The association between living organisms in which one lives on and feeds at the expense of the other is known as parasitism. In this relationship, the parasite benefits while the host is harmed. Commensalism is a relationship where one organism benefits and the other is neither harmed nor benefited. Predation is where one organism kills and eats another. Mutualism is a relationship where both organisms benefit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>35", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION", "question": "When large numbers of organisms share limited space and resources, the immediate result is", "images": [], "options": {"A": "extinction", "B": "emigration", "C": "competition", "D": "immigration"}, "answer": "C", "explanation": "When large numbers of organisms share limited space and resources, the immediate result is competition. This is because all organisms need certain resources to survive and reproduce. If these resources are limited, organisms will compete with each other to obtain them. This is a fundamental concept in ecology known as the 'competitive exclusion principle', which states that two species competing for the same resources cannot coexist at constant population values.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>36", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION", "question": "Which of the following diseases is caused by a bacterium?", "images": [], "options": {"A": "Ringworm", "B": "Poliomyelitis", "C": "Syphilis", "D": "Malaria"}, "answer": "C", "explanation": "Syphilis is caused by a bacterium called Treponema pallidum. Bacteria are single-celled organisms that can cause a variety of diseases in humans, including syphilis. The other diseases listed in the options (Ringworm, Poliomyelitis, and Malaria) are caused by fungi, viruses, and parasites, respectively, not bacteria.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2018>37", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Conservation of wildlife is necessary mainly because", "images": [], "options": {"A": "wild species cannot resist diseases better than their domesticated species", "B": "many predator wild animals help in the control of pests", "C": "it prevents the extinction of species", "D": "many people derive pleasure from observing wild animals"}, "answer": "C", "explanation": "Conservation of wildlife is primarily necessary to prevent the extinction of species. This is because every species plays a unique role in the balance of nature. The extinction of a single species can have a ripple effect on the ecosystem, leading to the imbalance of the ecosystem. Therefore, conservation efforts are necessary to maintain biodiversity and the health of the ecosystem.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>38", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "Two unconscious patient X and Y whose blood group genotypes are AO and AB respectively were transfused with blood from the same donor. Patient X immediately showed signs of difficulty in breathing while patient Y showed no negative reaction.  Use the information above to answer the question below    Patients X and Y were likely transfused with blood of genotype", "images": [], "options": {"A": "OO", "B": "AO", "C": "BO", "D": "AA"}, "answer": "C", "explanation": "In the given scenario, patient X has blood group genotype AO and patient Y has blood group genotype AB. Patient X showed signs of difficulty in breathing after the transfusion, which indicates a negative reaction to the transfused blood. This reaction could be due to the presence of B antigens in the transfused blood, which are not compatible with patient X's blood group. On the other hand, patient Y, who has blood group AB, did not show any negative reaction because blood group AB can receive blood from any group (A, B, AB, or O). Therefore, the blood transfused was likely of genotype BO.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2018>39", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY", "question": "Two unconscious patient X and Y whose blood group genotypes are AO and AB respectively were transfused with blood from the same donor. Patient X immediately showed signs of difficulty in breathing while patient Y showed no negative reaction.  Use the information above to answer the question below  What should the hospital have done to prevent patient X from showing the symptom described above? patient X should have", "images": [], "options": {"A": "undergo an agglutination test", "B": "been asked for the blood group", "C": "been screened for HIV", "D": "undergone malaria test"}, "answer": "A", "explanation": "The hospital should have performed an agglutination test on patient X. An agglutination test is a test that is used to determine blood type by mixing blood with antibodies that cause the blood cells to clump together if the antibodies are specific for the individual's blood type. In this case, if patient X's blood had been tested, it would have been found that the blood from the donor was not compatible, and the adverse reaction could have been avoided.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>40", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "The greatest contribution to genetic studies was made by", "images": [], "options": {"A": "Gregor Mendel", "B": "Thomas Morgan", "C": "Charles Darwin", "D": "Robert Hooke"}, "answer": "A", "explanation": "The greatest contribution to genetic studies was made by Gregor Mendel. Mendel's experiments with pea plants established many of the rules of heredity, now referred to as the laws of Mendelian inheritance. His work laid the foundation for the study of genetics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>41", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "The exchange of genes between homologous chromosome is called", "images": [], "options": {"A": "crossing over", "B": "back cross", "C": "test cross", "D": "mutation"}, "answer": "A", "explanation": "Crossing over is when genes from one chromosome (e.g paternal A, B, C) swap with genes from the other chromosome (maternal a, b, c) leading to a new gene combination in the resulting chromatids", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>42", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "The diagram below are illustration of the inheritance of coat colour in mice. J, K, L, M and  N are parents. The cross between two parent mice gave rise to offspring P, Q, R and S. Study the diagrams and answer the question below.       Which parent mouse is heterozygous for coat color?", "images": ["Biology/imgs/2018/r.png"], "options": {"A": "M", "B": "J", "C": "K", "D": "L"}, "answer": "D", "explanation": "Mouse L is heterozygous for coat colour, because it contains two different characters, which are white and black.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>43", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "The diagram below are illustration of the inheritance of coat colour in mice. J, K, L, M and  N are parents. The cross between two parent mice gave rise to offspring P, Q, R and S. Study the diagrams and answer the question below.     Which of the offspring are all homozygous?", "images": ["Biology/imgs/2018/r.png"], "options": {"A": "P", "B": "Q", "C": "S", "D": "R"}, "answer": "C", "explanation": "The offspring of S are all homozygous which is gotten from the parent.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>44", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : LINKAGE, SEX DETERMINATION AND SEX LINKED CHARACTERS", "question": "Genes that remain linked are those", "images": [], "options": {"A": "close to each other on the chromosome", "B": "on the same locus on the chromosome", "C": "on the homologous chromosome", "D": "which are allelic pair"}, "answer": "A", "explanation": "Genes that remain linked are those 'close to each other on the chromosome'. This is because during crossing over, the closer two genes are on a chromosome, the less likely they are to be separated. This is known as genetic linkage.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2018>45", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "A plant cell has 14 chromosomes prior to mitosis. what is the number of chromosome in the daughter cells?", "images": [], "options": {"A": "14", "B": "56", "C": "28", "D": "7"}, "answer": "A", "explanation": "Mitosis is a type of cell division that results in two daughter cells each having the same number and kind of chromosomes as the parent nucleus, typical of ordinary tissue growth. Therefore, if a plant cell has 14 chromosomes prior to mitosis, each daughter cell will also have 14 chromosomes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2018>46", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "The chemical bond that holds the bases of the two strands of DNA together is", "images": [], "options": {"A": "oxygen bond", "B": "hydrogen bond", "C": "electrovalent bond", "D": "covalent bond"}, "answer": "B", "explanation": "The two strands of DNA are held together by hydrogen bonds. These bonds occur between the bases of the two strands. Each base forms a hydrogen bond with a base on the opposite strand: Adenine pairs with Thymine, and Guanine pairs with Cytosine.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>47", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "The diagram below is an illustration of one of the theories of evolution. Study it and answer the question below      Who proposed the theory in the illustration?", "images": ["Biology/imgs/2018/Y24J9N.jpg"], "options": {"A": "Louis Pasteur", "B": "Gregor Mendel", "C": "Robert Hook", "D": "Jean Lamarck"}, "answer": "D", "explanation": "This is the theory of use and disuse of body parts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2018>48", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "The diagram below is an illustration of one of the theories of evolution. Study it and answer the question below    The theory supports", "images": ["Biology/imgs/2018/Y24J9N.jpg"], "options": {"A": "struggle for survival", "B": "natural selection", "C": "independent assortment", "D": "the use and disuse of body parts"}, "answer": "D", "explanation": "Jean Larmack explained the theory of use and disuse of body parts using giraffes as it illustration specimen.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2018>49", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "In evolution, fossils are naturally preserved in", "images": [], "options": {"A": "rocks", "B": "water", "C": "chemicals", "D": "trees"}, "answer": "A", "explanation": "Fossils are naturally preserved in rocks. Fossils are the remains or traces of plants and animals that lived in the past. Over time, layers of sediment build up and harden into rock, preserving the shape of the organisms. This process is known as fossilization and the resulting preserved remains are called fossils. Therefore, the correct answer is rocks.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2018>50", "subject": "Biology", "year": "2018", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following insects is not a social insect?", "images": [], "options": {"A": "Termite", "B": "Housefly", "C": "Honeybee", "D": "Ant"}, "answer": "B", "explanation": "Social insects are those species of insects that live in colonies and have a division of labor among the different types of individuals (castes). These include ants, bees, wasps, and termites. Houseflies, on the other hand, do not live in colonies and do not have a division of labor among individuals. Therefore, the housefly is not a social insect.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>1", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which of the following structures will not be found in the nucleus of a cell?", "images": [], "options": {"A": "DNA", "B": "Nucleolus", "C": "Lysosome", "D": "Centriole"}, "answer": "C", "explanation": "Lysosome is an extranuclear cell organelle, i.e it is found outside the nucleus. The orgaelles found within the nucleus include ⇒ Chromosome (DNA), nucleolus, centriole, chromatin, mRNA.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>2", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "An example of organ level of organization is", "images": [], "options": {"A": "bird", "B": "kidney", "C": "spermatozoon", "D": "xylem"}, "answer": "B", "explanation": "Kidney is the organ level of organization.  Xylem is in the tissue level of organization  Bird is in the organism level of organization  Spermatozoon is in the cellular level of organization.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>3", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "A structural similarity between Paramecium and Amoeba is the presence of", "images": [], "options": {"A": "one food vacuole", "B": "two contractile vacuoles", "C": "two nuclei", "D": "one gullet"}, "answer": "A", "explanation": "A structural similarity between Paramecium and Amoeba is the presence of one food vacuole.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>4", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The classes of plants the root systems in diagrams I and II below represent respectively are", "images": ["Biology/imgs/2019/img1.png"], "options": {"A": "Dicotyledoneae and Monocotyledoneae", "B": "Monocotyledoneae and Dicotyledoneae", "C": "Dicotyledoneae and Dicotyledoneae", "D": "Monocotyledoneae and Monocotyledoneae"}, "answer": "A", "explanation": "It should be noted that the root systems of monocots and dicots differ in that dicots have a tap root system while monocots have a fibrous root system.  In the diagrams given, I and II represent dicotyledoneae and monocotyledoneae respectively.  dicotyledon has a tap root while monocotyledon has fibrous root", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>5", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "The diagram below is an illustration of a stage in a biological process. Study it and answer this question      What stage of cell division is illustrated in the diagram?", "images": ["Biology/imgs/2019/img2.png"], "options": {"A": "Prophase", "B": "Metaphase", "C": "Anaphase", "D": "Telophase"}, "answer": "C", "explanation": "The diagram represents \"anaphase\".  Anaphase is a stage of mitosis after the metaphase, when replicated chromosomes are split and the newly-copied chromosomes are moved to opposite poles of the cell.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>6", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "The diagram below is an illustration of a stage in a biological process. Study it and answer this question    The part labelled I is the", "images": ["Biology/imgs/2019/img2.png"], "options": {"A": "centromere", "B": "spindle fibre", "C": "centriole", "D": "chiasmata"}, "answer": "C", "explanation": "The part labelled I is the centriole. Centrioles are cylindrical structures found in animal cells that play a crucial role during cell division, particularly in mitosis. Centrioles are  located at the poles of the cell during certain stages of mitosis. centrioles are essential for the accurate and equal distribution of chromosomes to daughter cells during mitosis.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>7", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "The rate of diffusion of molecules between two media will be higher if", "images": [], "options": {"A": "the difference in concentration of the two media is low.", "B": "the difference in concentration of the two media is negligible.", "C": "the difference in concentration of the two media is high.", "D": "there is no difference in the concentration of the two media."}, "answer": "C", "explanation": "According to the principle of diffusion, molecules move from an area of higher concentration to an area of lower concentration. Therefore, the rate of diffusion will be higher if the difference in concentration of the two media is high.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>8", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Anaerobic respiration in the organism illustrated in the diagram below produces carbon dioxide and", "images": ["Biology/imgs/2019/img3.png"], "options": {"A": "ethanol.", "B": "water.", "C": "oxygen.", "D": "glucose."}, "answer": "A", "explanation": "Anaerobic respiration produces carbon dioxide and ethanol.  N.B: Anaerobic respiration breaks down glucose (in the absence of oxygen) to give CO2 and C2H5OH.  C6H12O6 → 2C2H5OH + 2CO2  ⇒ (Glucose) → [Ethanol] + [Carbon dioxide]", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>9", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Underground storage stems which grow horizontally in the soil are", "images": [], "options": {"A": "bulbs.", "B": "runners.", "C": "rhizomes.", "D": "corms."}, "answer": "C", "explanation": "Rhizomes are a type of plant stem situated either at the soil surface or underground that contain nodes from which roots and other shoots originate. They grow horizontally in the soil, allowing the plant to propagate or survive underground during unfavorable seasons. Bulbs, runners, and corms are also types of plant stems, but they do not specifically grow horizontally underground.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>10", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Muscle fatigue in the body of an athlete is due to", "images": [], "options": {"A": "low pH.", "B": "high oxygen content.", "C": "accumulation of lactic acid.", "D": "accumulation of carbonic acid."}, "answer": "C", "explanation": "Muscle fatique in the body of an athlete is due to accumulation of lactic acid.  It should be noted that it is the lactic acid that causes pains in the muscles.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>11", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "The heart can beat continuously without being fatigued because it is composed of", "images": [], "options": {"A": "skeletal muscles", "B": "smooth muscles", "C": "cardiac muscles", "D": "renal muscles"}, "answer": "C", "explanation": "The heart is composed of cardiac muscles. Cardiac muscles are a type of muscle tissue that is found only in the heart and is responsible for pumping blood throughout the body. Cardiac muscle tissue, like skeletal muscle tissue, appears striated or striped. The cells of cardiac muscle tissue are connected to each other through intercalated discs, which allow the synchronization of the heart beat. This unique feature of cardiac muscles helps the heart to beat continuously without fatigue.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>12", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "The products of tissue respiration are", "images": [], "options": {"A": "glucose, oxygen and water.", "B": "oxygen, water and energy.", "C": "glucose, carbon dioxide and energy.", "D": "water, carbon dioxide and energy."}, "answer": "D", "explanation": "The products of tissue respiration are water, carbondixode and energy. It should be noted that \"tissue respiration\" according to the context of the question implies aerobic respiration.  C6H12O6 + 6O2 → 6CO2 + 6H2O + 38ATP.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>13", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Excretory products in plants responsible for the the colouration of flowers are called", "images": [], "options": {"A": "alkaloids.", "B": "tannins.", "C": "anthocyanins.", "D": "resins."}, "answer": "C", "explanation": "Anthocyanins are polyphenols which are found in plants as red pigments. Anthocyanins are responsible for the blue, purple, red, and intermediate colors of many flowers, leaves, vegetables, and fruits. Nearly one thousand anthocyanins, and more than 15 anthocyanidins, exist in the vegetal kingdom.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>14", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "The process of maintaining a steady internal environment is known as", "images": [], "options": {"A": "osmoregulation", "B": "equilibration", "C": "homeostasis", "D": "plasmolysis"}, "answer": "C", "explanation": "Homeostasis is the process through which organisms maintain a stable internal environment, despite changes in external environmental conditions. This process involves the regulation of various aspects such as temperature, pH, and glucose concentration. Osmoregulation is a type of homeostasis that involves the regulation of water levels and mineral salts in the blood. Equilibration is the process of reaching equilibrium or balance, while plasmolysis is the process in plant cells where the cytoplasm pulls away from the cell wall due to the loss of water through osmosis.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>15", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "Which of the following statements is not true about hormones?", "images": [], "options": {"A": "Their responses are voluntary", "B": "They may affect more than one target organ", "C": "They are chemical messengers in animals", "D": "They are transported by the blood to the target organs"}, "answer": "A", "explanation": "Hormones are chemical substances produced in the body that control and regulate the activity of certain cells or organs. Their responses are not voluntary but rather automatic and involuntary. They are indeed transported by the blood to the target organs and can affect more than one target organ.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>16", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "The diagram below is an illustration of human brain. Study it and answer this question      The part labelled I is the", "images": ["Biology/imgs/2019/img4.png"], "options": {"A": "olfactory lobe.", "B": "cerebellum.", "C": "cerebrum.", "D": "medulla oblongata."}, "answer": "C", "explanation": "The part labelled I is the cerebrum. The cerebrum is the largest part of the brain and is responsible for most of the brain's complex functions. It is divided into two hemispheres, the left and right, and has several distinct regions and structures.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>17", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "The diagram below is an illustration of human brain. Study it and answer this question    The function of the part labelled II is that it controls", "images": ["Biology/imgs/2019/img4.png"], "options": {"A": "posture and balance of body.", "B": "all voluntary actions.", "C": "temperature and appetite.", "D": "many involuntary actions."}, "answer": "D", "explanation": "The part labelled II is the medulla oblongata, it mainly controls involuntary actions such as vomiting, sneezing, etc.  It should be noted that the diagram is the dorsal view of a rabbit brain", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>18", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "To focus on a distant object, the ciliary muscle of the eye", "images": [], "options": {"A": "contracts and the eye lens gets thicker.", "B": "relaxes and the eye lens gets thinner.", "C": "contracts and the eye lens gets thinner.", "D": "relaxes and the eye lens gets thicker."}, "answer": "B", "explanation": "To focus on a distant object, the ciliary muscle of the eye relaxes which allows the lens to get thinner. This is because the light from distant objects is nearly parallel and needs less refraction to focus on the retina. This is a process known as accommodation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>19", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "The main function of the amniotic fluid is for", "images": [], "options": {"A": "respiration in the foetus.", "B": "protection of the foetus from shock.", "C": "lubricating the birth canal.", "D": "nourishing the foetus."}, "answer": "B", "explanation": "The main function of the amniotic fluid is for protection of the foetus from shock.  The amniotic fluid is the protective fluid contained by the amniotic sac of a gravid amniote. This fluid serves as a cushion for the growing foetus, but also serves to facilitate the exchange of nutrients, water and biochemical products between mother and foetus.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>20", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The diagram below is an illustration of the longitudinal section of a flower. Study it and answer this question      Which part of the flower is responsible for the protection of young flower buds?", "images": ["Biology/imgs/2019/img5.png"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "B", "explanation": "It should be noted that sepals protect the flower bud and are behind/underneath the petals when the flower opens.  The sepal is the part labelled II.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>21", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The diagram below is an illustration of the longitudinal section of a flower. Study it and answer this question    The essential parts of the flower are labelled", "images": ["Biology/imgs/2019/img5.png"], "options": {"A": "I, II and III.", "B": "II, III and IV.", "C": "III, V and VI.", "D": "IV, V and VI."}, "answer": "D", "explanation": "The essential parts of a flower include:  Stamen   - Pollen  - Anther  - Filament     Carpel  - Ovary  - Stigma  - Style    IV - Ovary, V - Filament and VI - Ovary", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>22", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "Deficiency in insulin could lead to", "images": [], "options": {"A": "cirrhosis.", "B": "hepatitis.", "C": "diabetes.", "D": "nephritis."}, "answer": "C", "explanation": "Insulin is produced by the α- cells of the pancreas to regulate high blood glucose level which could lead to diabetes, deficiency of insulin will disturb the homoestatic regulation of the blood glucose level thereby causing hyperglycaemia or diabetes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>23", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "Which of the following forms of energy is utilized during photosynthesis?", "images": [], "options": {"A": "Potential", "B": "Kinetic", "C": "Solar", "D": "Chemical"}, "answer": "C", "explanation": "Solar energy is utilized during photosynthesis. In photosynthesis, carbon (IV) oxide and water use the energy from sunlight (trapped by chlorophyl) to initiate a reaction that will lead to the formation of glucose, and giving off oxygen as a by-product.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>24", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "Light is excluded from a water culture experiment in order to", "images": [], "options": {"A": "prevent overheating of the roots.", "B": "enable the roots to grow straight down.", "C": "prevent ionization of water molecules.", "D": "prevent the growth of algae."}, "answer": "D", "explanation": "In a water culture experiment, light is excluded to prevent the growth of algae. Algae are photosynthetic organisms that require light to grow. If light is present, algae can overgrow and compete with the plant for nutrients, potentially affecting the results of the experiment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>25", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS", "question": "The major mineral present in the shell of Molluscs is", "images": [], "options": {"A": "copper.", "B": "sodium.", "C": "iron.", "D": "calcium."}, "answer": "D", "explanation": "The major mineral present in the shell of Molluscs is calcium. Molluscs, like snails and clams, have shells that are primarily made up of calcium carbonate. This mineral gives the shell its hardness and durability.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>26", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "The digestion of proteins starts in the", "images": [], "options": {"A": "small intestine.", "B": "stomach.", "C": "large intestine.", "D": "mouth."}, "answer": "B", "explanation": "The digestion of proteins starts in the stomach. The stomach secretes an enzyme called pepsin, which breaks down proteins into smaller peptides. This is the first step in protein digestion. The process continues in the small intestine, where other enzymes further break down these peptides into amino acids.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>27", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH", "question": "Tooth decay is usually caused by", "images": [], "options": {"A": "undigested and absorbed food.", "B": "eating limited amount of sweetened food.", "C": "the bacteria in the mouth that metabolize sugar to acids.", "D": "eating a lot of proteinous foods."}, "answer": "C", "explanation": "Tooth decay is usually caused by the bacteria in the mouth that metabolize sugar to acids. This is because when you eat foods containing sugars, the bacteria in your mouth digest these sugars and produce acids. These acids can eat away at the hard, outer layer of your teeth, called enamel, leading to tooth decay.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>28", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : NITROGEN CYCLE", "question": "The conversion of ammonium salts into nitrates is called", "images": [], "options": {"A": "putrefaction.", "B": "denitrification.", "C": "fixation.", "D": "nitrification."}, "answer": "D", "explanation": "The conversion of ammonium salts into nitrates is called nitrification. Nitrification is a process by which ammonia is oxidized to nitrites (NO2-) and then to nitrates (NO3-) by bacteria. This process naturally occurs in the environment, where it is an important step in the nitrogen cycle.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>29", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "The salinity of a brackish habitat", "images": [], "options": {"A": "increases immediately after rainfall.", "B": "increases at the end of the rainy season.", "C": "decreases with an increase in the number of organisms.", "D": "increases during the dry season."}, "answer": "D", "explanation": "The salinity of a brackish habitat increases during the dry season. This is because during the dry season, the rate of evaporation is higher than the rate of precipitation. As water evaporates, it leaves behind salts, thereby increasing the salinity of the habitat.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>30", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING", "question": "If 90 ants are found in a field with a total area of 100m2, what is the population density of the ants?", "images": [], "options": {"A": "0.09", "B": "0.90", "C": "9.00", "D": "90.00"}, "answer": "B", "explanation": "Parameters give:  Number of organisms (ants) = 90  Total area = 100m2  Population density = ?  Recall:Populationdensity=No. of organismsLand area  P.D=90100=0.90", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>31", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "The complex relationship between the members of a community and their physical environment is known as", "images": [], "options": {"A": "commensalism.", "B": "symbiosis.", "C": "saprophytism.", "D": "ecology."}, "answer": "D", "explanation": "Ecology is the branch of biology that deals with the relations of organisms to one another and to their physical surroundings. So, the complex relationship between the members of a community and their physical environment is known as ecology.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>32", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "The specific role of a species within its environment is known as its", "images": [], "options": {"A": "habitat.", "B": "niche.", "C": "trophic level.", "D": "biotic community."}, "answer": "B", "explanation": "In ecology, a niche is the role or job of a species in a habitat. The niche involves the species' interactions with the other members of its ecosystem, including its diet, its behaviours, and its influence on the environment and other species.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>33", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT", "question": "Which of the following soil fertility improvement methods will have the most negative effect on the ecosystem if not controlled?", "images": [], "options": {"A": "Application of N-P-K fertilizer", "B": "Shifting cultivation", "C": "Mixed farming", "D": "Crop rotation"}, "answer": "A", "explanation": "The application of N-P-K fertilizers can have the most negative effect on the ecosystem if not controlled because it can lead to:  Water Pollution: Runoff causes eutrophication, harming aquatic life.  Soil Degradation: Overuse leads to soil acidification and structural damage.  Air Pollution: Volatilization contributes to greenhouse gas emissions.  In contrast, shifting cultivation, mixed farming, and crop rotation generally have less harmful or even beneficial effects on the ecosystem when managed properly.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>34", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Organisms in an ecosystem are usually grouped according to their trophic level into", "images": [], "options": {"A": "carnivores and omnivores.", "B": "consumers and parasites.", "C": "producers and saprophytes.", "D": "producers and consumers."}, "answer": "D", "explanation": "In an ecosystem, organisms are grouped according to their trophic level into producers and consumers. Producers, also known as autotrophs, are organisms that can produce their own food from inorganic substances using light (photosynthesis) or chemical energy (chemosynthesis). Consumers, also known as heterotrophs, are organisms that cannot produce their own food and need to consume other organisms. Consumers can be further divided into primary consumers (herbivores), secondary consumers (carnivores and omnivores), and tertiary consumers (top predators).", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>35", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "In the pyramid of energy illustrated below, the organism with the least amount of transferred energy is", "images": ["Biology/imgs/2019/img6.png"], "options": {"A": "Spirogyra", "B": "tadpole", "C": "fish", "D": "bird"}, "answer": "C", "explanation": "In a pyramid of energy, the organism with the least amount of transferred energy is: Bird  In a pyramid of energy, energy is transferred from one trophic level to the next, but with each transfer, a significant amount of energy is lost, primarily as heat. Therefore, higher trophic levels receive less energy than the levels below them.     First level (Spirogyra): Primary producers that capture the most energy from the sun.  Second level (Tadpole): Primary consumers that get energy from eating producers.  Third level (Fish): Secondary consumers that eat primary consumers.  Fourth level (Bird): Tertiary consumers that eat secondary consumers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>36", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "Tall trees with unbranched trunks which grow above the upper storey of the forest are commonly referred to as", "images": [], "options": {"A": "emergents.", "B": "herbs.", "C": "lianes.", "D": "shrubs."}, "answer": "A", "explanation": "In a forest, the tallest trees with unbranched trunks that grow above the upper storey are referred to as 'emergents'. This term is used in the context of forest ecology to describe trees that grow taller than the average canopy height, allowing them to receive more sunlight than other trees. They are a key component of the forest ecosystem, providing habitat for many species and playing a significant role in nutrient cycling.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>37", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "ECOLOGY OF POPULATION : PRESERVATION AND STORAGE OF FOODS", "question": "Maize grain are best stored against insect attacks by", "images": [], "options": {"A": "keeping in a silo.", "B": "storing in the room.", "C": "leaving them on their cobs.", "D": "covering with leaves."}, "answer": "A", "explanation": "Maize grains are best stored against insect attacks by keeping them in a silo. A silo is a structure for storing bulk materials, often used in agriculture to store grain. Silos protect the grains from weather and pests. The other options do not provide the same level of protection against insects. Storing in the room or leaving them on their cobs exposes the grains to pests, and covering with leaves is not a reliable method of protection.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>38", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : PUBLIC HEALTH", "question": "Cholera is mostly spread by", "images": [], "options": {"A": "air.", "B": "soil.", "C": "water.", "D": "noise."}, "answer": "C", "explanation": "Cholera is an infectious disease that causes severe watery diarrhea, which can lead to dehydration and even death if untreated. It is caused by eating food or drinking water contaminated with a bacterium called Vibrio cholerae. The disease is most often spread through water contaminated with the bacteria. Therefore, the correct answer is 'water'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>39", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "Which of the following resources is renewable?", "images": [], "options": {"A": "Petroleum", "B": "Coal", "C": "Iron", "D": "Trees"}, "answer": "D", "explanation": "Renewable resources are resources that can be replaced naturally and can be used again. Examples are: wind, solar, geothermal, biomass, and hydropower. Non-renewable resources, on the other hand, are those that cannot be replenished (made again) in a short period of time. Examples are: petroleum, coal, and iron. Therefore, the correct answer is 'Trees' as they can be replanted and regrown.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>40", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Which of the following roles is not performed by a government agency responsible for forest maintenance?", "images": [], "options": {"A": "Regulating the harvest of timber and poaching.", "B": "Creating, protecting and managing the forest reserves.", "C": "Tracking the movement of timber, wood and wildlife.", "D": "Regulating mining activities in the forest."}, "answer": "D", "explanation": "Government agencies responsible for forest maintenance primarily focus on conservation, management, and regulation related to forests and wildlife. While they may have some oversight related to land use and environmental impacts, direct regulation of mining activities is typically handled by specialized agencies focused on mining and minerals.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2019>41", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Which of the following factors is not a source of variation in living organisms?", "images": [], "options": {"A": "Environment", "B": "Inheritance", "C": "Mitosis", "D": "Meiosis"}, "answer": "C", "explanation": "Variation in living organisms is caused by several factors, including the environment, inheritance, and meiosis. The environment can cause variations as organisms adapt to different conditions. Inheritance leads to variation as organisms inherit different combinations of genes from their parents. Meiosis, a type of cell division that results in four daughter cells each with half the number of chromosomes of the parent cell, also leads to variation as it results in new combinations of genes. However, mitosis, a type of cell division that results in two daughter cells each having the same number and kind of chromosomes as the parent nucleus, does not lead to variation as it produces identical cells. Therefore, option 3 is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>42", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "Individuals with blood group AB can donate blood to individuals with blood group(s)", "images": [], "options": {"A": "A and B.", "B": "A and O.", "C": "AB only.", "D": "O only."}, "answer": "C", "explanation": "Individuals with blood group AB are universal recipients, meaning they can receive blood from any group. However, they can only donate blood to individuals with the same blood group, AB. This is due to the presence of both A and B antigens on the red blood cells of AB individuals. If they were to donate to a person with blood group A or B, the recipient's antibodies would react with the donor's antigens, causing a transfusion reaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>43", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The diagram below is an illustration of a process occurring in a living animal cell.  Study it and answer this question      The process occurs in the", "images": ["Biology/imgs/2019/img7.png"], "options": {"A": "nucleus.", "B": "mitochondrion.", "C": "Golgi body.", "D": "Cytoplasm."}, "answer": "A", "explanation": "The process depicted in the diagram is replication of DNA. It occurs in the nucleus.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>44", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The diagram below is an illustration of a process occurring in a living animal cell.  Study it and answer this question    The process is called", "images": ["Biology/imgs/2019/img7.png"], "options": {"A": "replication.", "B": "cell maturation.", "C": "crossing over.", "D": "mutation."}, "answer": "A", "explanation": "The process is called replication of DNA. DNA replication is the process by which a double-stranded DNA molecule is copied to produce two identical DNA molecules.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>45", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of the following nucleotides is not found in the DNA molecule?", "images": [], "options": {"A": "Adenine", "B": "Cytosine", "C": "Granine", "D": "Uracil"}, "answer": "D", "explanation": "DNA (Deoxyribonucleic acid) is a molecule composed of two chains that coil around each other to form a double helix carrying genetic instructions. It is made up of four types of nucleotides: Adenine (A), Thymine (T), Cytosine (C), and Guanine (G). Uracil is not found in DNA; it is instead a component of RNA (Ribonucleic acid), where it pairs with Adenine.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>46", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "In a complete dominance monohybrid cross between a pure breeding yellow flowered plant Y and a pure breeding white flowered plant y, the result of the first filial generation is", "images": [], "options": {"A": "50% yellow flowers.", "B": "75% yellow flowers.", "C": "all yellow flowers.", "D": "all white flowers."}, "answer": "C", "explanation": "The result of the filial generation is heterozygous yellow flowers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>47", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "A man whose blood group is heterozygous B is married to a woman whose blood group is also heterozygous B. Which of the following statements is correct about the blood group of their four offspring?", "images": [], "options": {"A": "Three of them belong to blood group B", "B": "Three of them belong to blood group O", "C": "None of them belongs to blood group O", "D": "Two of them belong to blood group B"}, "answer": "A", "explanation": "Three of them (75%) belong to blood group B while just one of them (25%) belongs to blood group O.  Note that this is a measure of probability (chance)", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>48", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "The cross between RrTt and rrtt where R is a gene for red colour and T for tallness will result in", "images": [], "options": {"A": "all the offspring being tall with red fruits.", "B": "25% tall with red fruits.", "C": "50% tall with red fruits.", "D": "75% tall with red fruits."}, "answer": "B", "explanation": "Given:  - RrTt (heterozygous for both traits: red color and tallness)  - rrtt (homozygous recessive for both traits: white color and short)    When we cross RrTt with rrtt:    - RrTt can produce gametes RT, Rt, rT, and rt.  - rrtt can only produce gametes rt.    Crossing these gametes gives us the following possible offspring genotypes:  - RT (red and tall)  - Rt (red and short)  - rT (white and tall)  - rt (white and short)    Now, let's count the phenotypic ratios:  - Red and tall (RT, Rt): 2 out of 4 possible combinations = 50%  - White and tall (rT): 1 out of 4 possible combinations = 25%  - White and short (rt): 1 out of 4 possible combinations = 25%    Therefore, based on the cross between RrTt and rrtt, the correct answer is: 50% tall with red fruits.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>49", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "EVOLUTION : ADAPTIVE COLOURATION", "question": "The yellow and black stripes on the body of wasps is an example of", "images": [], "options": {"A": "mimicry.", "B": "courtship behaviour.", "C": "camouflage.", "D": "warning colouration."}, "answer": "D", "explanation": "The yellow and black stripes on the body of wasps is an example of warning colouration. Warning colouration, also known as aposematism, is a type of adaptation where a species develops bright colours, patterns, or other physical characteristics that signal to predators that it is toxic, dangerous, or unpleasant to eat or attack.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2019>50", "subject": "Biology", "year": "2019", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The biological importance of the dance by the worker honeybee is that it", "images": [], "options": {"A": "acts as signal for mating.", "B": "serves as a warning signal.", "C": "signals the availability of food.", "D": "serves as means of identifying members of the caste"}, "answer": "C", "explanation": "The dance by the worker honeybee signals the availability of food. This is known as the 'waggle dance'. The direction and duration of the dance communicates to other bees in the hive the direction and distance of a food source from the hive.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>1", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The cell as the basic unit of life consists of", "images": [], "options": {"A": "Cell wall and vacuole", "B": "Nucleus and cell wall", "C": "cytoplasm and nucleus", "D": "Cytoplasm and vacuole"}, "answer": "C", "explanation": "The cell, being the basic unit of life, consists of the cytoplasm and the nucleus. The cytoplasm is the jelly-like substance that contains all the cell's organelles, excluding the nucleus. The nucleus, on the other hand, is the control center of the cell, containing the cell's DNA and regulating the cell's activities.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2020>2", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "Use the following Classes of Arthropoda to answer the question below  I. Crustaceans  II. Insecta  III. Arachnida  IV.Chilopoda    Which members of the classes live mainly in an aquatic habitat", "images": [], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "A", "explanation": "Crustaceans are the members of the classes that live mainly in an aquatic habitat. Crustaceans include animals like crabs, lobsters, crayfish, shrimps, krill, woodlice, and barnacles. Most of these animals are aquatic, living in either freshwater or marine environments, and some are terrestrial.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2020>3", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "Use the following Classes of Arthropoda to answer the question below  I. Crustaceans  II. Insecta  III. Arachnida  IV.Chilopoda  Which of the classes is charaterised by the possession of two pairs of antennae?", "images": [], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "A", "explanation": "Crustaceans are the only arthropods that have two pairs of antennae. The pairs attached to the first segment of the head are called primary antennae or antennules. The pair attacked secondary antennae or simply antenna", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2020>4", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The organisms with spiral chloroplast and nucleus suspended by cytoplasmic strands is", "images": [], "options": {"A": "Volvox", "B": "Spirogyra", "C": "Paramecius", "D": "Euglena"}, "answer": "B", "explanation": "Spirogyra is a genus of filamentous green algae characterized by its spiral chloroplasts and a nucleus that is suspended by cytoplasmic strands. Volvox is a colonial green algae, Paramecium is a ciliate protozoan, and Euglena is a genus of single-celled flagellate eukaryotes, none of which have the described characteristics.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2020>5", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The Network of double membrane that conveys materials through the cytoplasm is the", "images": [], "options": {"A": "Plasma membrane", "B": "nuclear Membrane", "C": "Mitochondrion", "D": "Endoplasmic reticulum"}, "answer": "D", "explanation": "The network of double membrane that conveys materials through the cytoplasm is the Endoplasmic Reticulum. The Endoplasmic Reticulum (ER) is an organelle in cells that serves as a manufacturing and packaging system. It works closely with the Golgi apparatus, ribosomes, mRNA, and tRNA. Structurally, the endoplasmic reticulum is a network of membranes found throughout the cell and connected to the nucleus.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2020>6", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The diagram above is an illustration of the longitudinal section of a plant organ. Study to answer the question below      Food is stored in the part labelled", "images": ["Biology/imgs/2020/l75.png"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "B", "explanation": "Food is stored in the part labelled II. The part labelled II is the fleshy leaf. The fleshy leaves are modified leaves that store nutrients, primarily in the form of carbohydrates.  Structure: The fleshy leaves of an onion bulb are thick, succulent, and often layered. They form concentric circles around a central point, with the outer layers being more papery and the inner layers being thicker and juicier.  Function: The primary function of these fleshy leaves is to store food, mainly carbohydrates like fructans and glucose, which provide energy for the plant to grow new shoots and roots. This storage helps the plant survive periods when it cannot photosynthesize, such as during dormancy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>7", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The diagram above is an illustration of the longitudinal section of a plant organ. Study to answer the question below    The plant is a", "images": ["Biology/imgs/2020/l75.png"], "options": {"A": "stem tuber", "B": "Bulb", "C": "stolon", "D": "runner"}, "answer": "B", "explanation": "The plant is a bulb. The onion bulb is a modified stem", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>8", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The diagram above is an illustration of the longitudinal section of a plant organ. Study to answer the question below    The part labelled I is the", "images": ["Biology/imgs/2020/l75.png"], "options": {"A": "Apical bud", "B": "Scale leaf", "C": "Adventious root", "D": "Fleshy leaf"}, "answer": "B", "explanation": "The part labelled I is the scale leaf. In an onion bulb, scale leaves are thick, fleshy layers arranged in concentric circles. They store nutrients, mainly carbohydrates, for the plant's survival and regrowth. The outermost scales are dry and papery, providing protection against damage and dehydration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>9", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "Which of the following is not a living semi permeable membrane?", "images": [], "options": {"A": "Pig's bladder", "B": "Unripe pawpaw fruit", "C": "Yam tuber", "D": "sheet of cellophane"}, "answer": "D", "explanation": "A sheet of cellophane is not a living semi-permeable membrane. Semi-permeable membranes are thin layers of material capable of separating substances when a driving force is applied across the membrane. It allows certain molecules or ions to pass through it by diffusion and occasionally specialized 'facilitated diffusion'. The other options listed are all examples of living semi-permeable membranes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2020>10", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : MICROORGANISMS: MAN AND HIS HEALTH.", "question": "In an experiment, mould and yeast cells were transferred into an environment with low oxygen concerntration . After few days, the mould died while the yeast cells did not. which of the following staement best explains the above observation", "images": [], "options": {"A": "The yeast cells carried out photosynthesis while the mould did not", "B": "Photosynthesis does not take place in the absence of oxygen", "C": "Respiration can take place in yeast cells in the absence of oxygen", "D": "Respiration does not occur in the Mould"}, "answer": "C", "explanation": "The yeast cells can survive in an environment with low oxygen concentration because they can carry out anaerobic respiration, also known as fermentation. This process does not require oxygen. On the other hand, moulds are aerobic organisms that require oxygen for respiration, hence they cannot survive in an environment with low oxygen concentration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>11", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Which of the following does not provide support in flowering plants?", "images": [], "options": {"A": "Collenchyma", "B": "Parenchyma", "C": "Xylem", "D": "Phloem"}, "answer": "D", "explanation": "The supporting tissue in plants include  - The collenchyma  - The sclerenchyma  -Xylem Also responsible for the transport dispersal of water and nutrient.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2020>12", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "The diagram is an illustration of an experimental set-up. Study it and answer the question:      The set-up directly measures", "images": ["Biology/imgs/2020/l76.png"], "options": {"A": "Transpiration of water by shoot", "B": "Evaporation of water from leaves", "C": "Absorption of water by the shoot", "D": "Loss of mineral salts from the leaves"}, "answer": "A", "explanation": "The set-up measure comparatively the rate of transpiration of a single shoot of a plant under experimental condition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>13", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "The diagram is an illustration of an experimental set-up. Study it and answer the question:    The set-up can measure comparatively the rate of", "images": ["Biology/imgs/2020/l76.png"], "options": {"A": "Evapouration from leaves on a single shoot under different experimental conditions.", "B": "Salt uptake by shoots from different plants", "C": "transpiration of single shoot of plant under different experimental conditions", "D": "Water uptake by roots of different plants."}, "answer": "C", "explanation": "The set-up measure comparatively the rate of transpiration of a single shoot of a plant under experimental conditions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>14", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "The respiration organ of a cockroach is the", "images": [], "options": {"A": "air sac", "B": "trachea", "C": "lung book", "D": "lung"}, "answer": "B", "explanation": "The respiratory organ of a cockroach is the trachea. Insects like cockroaches do not have lungs. Instead, they breathe through a network of tiny tubes called tracheae. Oxygen from the air enters the tracheae through a row of holes along an insect's abdomen. The oxygen then diffuses down the blind-ended tracheae. So, the correct answer is trachea.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2020>15", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "The excretory product of some reptiles, bird and insect is", "images": [], "options": {"A": "urea", "B": "urine", "C": "ammonia", "D": "uric acid"}, "answer": "D", "explanation": "The excretory product of some reptiles, birds, and insects is uric acid. These organisms are known as uricotelic organisms. Uric acid is a compound that is excreted by these organisms instead of urea or ammonia. Uric acid is less toxic than ammonia and urea, and it is also less soluble in water. This means that it can be excreted with minimal water loss, which is beneficial for organisms that live in dry environments. So, the correct answer is uric acid.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2020>16", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "The part of the mammalian kidney that stores urine is the", "images": ["Biology/imgs/2020/l97.png"], "options": {"A": "capsule", "B": "medulla", "C": "pelvic", "D": "bladder"}, "answer": "D", "explanation": "The bladder is the part of kidney that stores urine. it stores urine before it is transferred to the ureter", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2020>17", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "The properties of endocrines system includes the following except", "images": [], "options": {"A": "secretion of hormones", "B": "transportation by blood to target organs", "C": "having specific effect", "D": "release of secretion into ducts"}, "answer": "D", "explanation": "The endocrine system is a collection of glands that produce hormones that regulate metabolism, growth and development, tissue function, sexual function, reproduction, sleep, and mood, among other things. Unlike exocrine glands (such as sweat glands), endocrine glands do not release their secretions into ducts. Instead, they release hormones directly into the bloodstream, which transports the hormones to cells throughout the body.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>18", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "The part of the central nervous system that controls unconscious actions in human is the", "images": [], "options": {"A": "cerebellum", "B": "cerebrum", "C": "spinal cord", "D": "optic nerve"}, "answer": "C", "explanation": "The spinal cord is responsible for controlling many unconscious actions in humans, such as:    - Reflexes (e.g., withdrawing a hand from a hot surface)  - Autonomic functions (e.g., heart rate, blood pressure, digestion)  - Motor functions (e.g., walking, balance, coordination)    The other options are not primarily responsible for controlling unconscious actions:    - Cerebellum: coordinates voluntary movements, balance, and posture  - Cerebrum: processes sensory information, controls voluntary actions, and manages higher-level cognitive functions  - Optic nerves: transmit visual information from the eyes to the brain", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>19", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "What happens when the ciliary muscles of the eye contracts? The", "images": [], "options": {"A": "lens becomes more concave", "B": "lens becomes more convex", "C": "lens gets a longer focal lenght", "D": "suspensory ligament becomes tight"}, "answer": "B", "explanation": "When the ciliary muscles of the eye contract, the lens becomes more convex. This is because the contraction of the ciliary muscles reduces the tension on the suspensory ligaments holding the lens in place, allowing the lens to take on a more rounded (convex) shape. This increases the lens's refractive power, allowing for closer objects to be brought into focus.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>20", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The function of the part labelled I is", "images": ["Biology/imgs/2020/l77.png"], "options": {"A": "receiving the pollen grain", "B": "passage for the male gamate to the ovary", "C": "germination of the pollen grain", "D": "site for double fertilization in the plant"}, "answer": "B", "explanation": "The part labelled I is the pollen tube and it transfers pollen grain from anther to the ovary", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>21", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "The part labelled II is the", "images": ["Biology/imgs/2020/l77.png"], "options": {"A": "unfused stigma", "B": "fused style", "C": "fused ovaries", "D": "unfused anther"}, "answer": "C", "explanation": "The part labelled II in the diagram is the fused ovaries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>22", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : MICROORGANISMS: MAN AND HIS HEALTH.", "question": "The reagent used in testing for carbon(IV) oxide is", "images": [], "options": {"A": "copper sulphate solution", "B": "lime water", "C": "hydrochloric acid", "D": "sodium hydroxide solution"}, "answer": "B", "explanation": "The reagent used in testing for carbon(IV) oxide, also known as carbon dioxide, is lime water. When carbon dioxide is bubbled through lime water, it reacts with the lime water to form calcium carbonate, which is a white precipitate. This reaction is used as a test for the presence of carbon dioxide.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2020>23", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Oxygen comes out of the stomata during photosynthesis through the process known as", "images": [], "options": {"A": "Diffusion", "B": "transpiration pull", "C": "osmosis", "D": "active transport"}, "answer": "A", "explanation": "During photosynthesis, oxygen is produced as a by-product in the chloroplasts of the plant cells. This oxygen then diffuses out of the plant through the stomata. Diffusion is a passive process where molecules move from an area of high concentration to an area of low concentration. In this case, the oxygen molecules move from inside the plant where their concentration is high, to the outside where the concentration is lower.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>24", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The first stable product of photosynthesis is", "images": [], "options": {"A": "Starch", "B": "Fructose", "C": "Glucose", "D": "Sucrose"}, "answer": "C", "explanation": "The first stable product of photosynthesis is glucose. Photosynthesis is a process used by plants and other organisms to convert light energy into chemical energy that can later be released to fuel the organisms' activities. This chemical energy is stored in carbohydrate molecules, such as sugars, which are synthesized from carbon dioxide and water. The first stable product of this process is glucose.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2020>25", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "An example of trace element is", "images": [], "options": {"A": "potassium", "B": "Calcuim", "C": "Magnesium", "D": "Copper"}, "answer": "D", "explanation": "Trace elements are elements required by an organism in only minute quantities. Copper is a trace element because it is needed in very small amounts. It is used by the body to help make red blood cells and keep nerve cells and the immune system healthy. Other options like potassium, calcium, and magnesium are macro-elements, not trace elements, because they are needed by the body in larger amounts.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2020>26", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Which of the following statement about a mixture of a protein-digesting enzyme and starch solution would be correct ? The protein-digesting enzyme.", "images": [], "options": {"A": "has no effect on the starch solution", "B": "Leads to production of amino acids", "C": "leads to the production of glucose", "D": "Digest the starch"}, "answer": "A", "explanation": "A protein-digesting enzyme, such as pepsin or trypsin, would have no effect on a starch solution because these enzymes are specific to proteins and do not act on starch. Enzymes are biological catalysts that speed up chemical reactions in living organisms, and they are highly specific, meaning each enzyme only catalyzes a specific reaction. In this case, the protein-digesting enzyme would not lead to the production of amino acids, glucose, or digest the starch because it does not act on starch.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>27", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS", "question": "A mutualism type of relationship is different from a parasitic relationship because in mutualism", "images": [], "options": {"A": "Both organisms involved benefit", "B": "none of the organism benefits or harm each other", "C": "Both organism harm each other", "D": "Only one of the organism is harmed"}, "answer": "A", "explanation": "In a mutualistic relationship, both organisms involved benefit from the relationship. This is different from a parasitic relationship where only one organism (the parasite) benefits at the expense of the other (the host).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>28", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "The table shows the number of some organism in habitats W and Y.   Organismnumber in the habitatnumber in the habitathabitat W habitat YPlankton1260Antelope051Water flea100Tilapia230Lion 06Frog60Grass0250    What type of habitat is W?", "images": [], "options": {"A": "Rainforest", "B": "Pond", "C": "Desert", "D": "Ocean"}, "answer": "B", "explanation": "Habitat W is likely a pond. This is inferred from the presence of organisms such as plankton, water fleas, tilapia, and frogs, which are typically found in freshwater environments like ponds. Rainforests, deserts, and oceans would not typically have this combination of organisms.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2020>29", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "The table shows the number of some organism in habitats W and Y.   Organismnumber in the habitatnumber in the habitathabitat W habitat YPlankton1260Antelope051Water flea100Tilapia230Lion 06Frog60Grass0250  Which of the following statement about habitat W is correct ? The", "images": [], "options": {"A": "Absence of lions and antelope shows that the habitat is terrestial", "B": "Presence of Tilapia and Planktons shows that the habitat is not aquatic", "C": "Type of organism present indicate that the habitat is aquatic", "D": "Absence of grass indicates that the habitat is terrestial"}, "answer": "C", "explanation": "The presence of organisms such as Plankton, Water flea, Tilapia, and Frog in habitat W indicates that the habitat is aquatic. Plankton and Water flea are small organisms that live in water bodies. Tilapia is a type of fish, and frogs are amphibians that live both on land and in water but breed in water. Therefore, the type of organisms present indicates that the habitat is aquatic.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2020>30", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "The table shows the number of some organism in habitats W and Y.   Organismnumber in the habitatnumber in the habitathabitat W habitat YPlankton1260Antelope051Water flea100Tilapia230Lion 06Frog60Grass0250  The number of lions and antelopes in habitat Y shows that lion", "images": [], "options": {"A": "Is the prey while the antelope is the predator", "B": "is the predator while the antelope is the prey", "C": "and the antelope are prey to each other", "D": "and the antelopes are predators"}, "answer": "B", "explanation": "In a typical ecological habitat the prey is usually more than the predator. In the table presented in the question , there are 6 lions and 51 antelopes in the habitat (terrestial)", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2020>31", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS", "question": "The diagram below is an illustration of an ecological instrusment.      A disadvantage of the abiotic factor measured by the instrument is that it.", "images": ["Biology/imgs/2020/l78.png"], "options": {"A": "is an agent of pollination", "B": "is necessary for gemination", "C": "leads to flooding when is excess", "D": "is used for irrigation."}, "answer": "C", "explanation": "The diagram in the question is a rain gauge. Rain gauge is used to measure rainfall. When rainfall is an excess it could lead to flooding", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>32", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS", "question": "The diagram below is an illustration of an ecological instrusment.    When the instrument is in use, it is usually", "images": ["Biology/imgs/2020/l78.png"], "options": {"A": "Placed slightly above soil level", "B": "placed on a table", "C": "suspended in air", "D": "suspended on moving water"}, "answer": "A", "explanation": "When raingauge is in use, it is usually placed above the soil level in an open space. Where there are no obstacles to prevent rainfall.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>33", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "Soil with the finest texture is", "images": [], "options": {"A": "Silt", "B": "clay", "C": "sand", "D": "Gravel"}, "answer": "B", "explanation": "Clay soil has the finest texture. The texture of the soil is determined by the size of the particles that make up the soil. The smallest particles are found in clay soil, making it have the finest texture. Silt, sand, and gravel have larger particles and therefore do not have as fine a texture as clay.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2020>34", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "The position occupied by organism in a food chain is the", "images": [], "options": {"A": "energy level", "B": "niche", "C": "Trophic level", "D": "Biomass"}, "answer": "C", "explanation": "The position occupied by an organism in a food chain is the trophic level. A food chain represents the flow of energy from one organism to another. The trophic level of an organism is its position in a food chain or food web, which is determined by its feeding relationships. The energy level and biomass are related to the trophic level, but they are not the position an organism occupies in a food chain. The niche of an organism is its role in the ecosystem, not its position in the food chain.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2020>35", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE", "question": "The depletion of ozone layer will result in the earth surface receiving more", "images": [], "options": {"A": "gamma ray", "B": "infra-red rays", "C": "Ultraviolet rays", "D": "X-rays"}, "answer": "C", "explanation": "The ozone layer in the earth's stratosphere absorbs most of the Sun's ultraviolet (UV) radiation. It contains high concentrations of ozone (O3) in relation to other parts of the atmosphere. If the ozone layer depletes, more UV rays will reach the earth's surface.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>36", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH", "question": "Using the list of insects below to answer the question below:  I - cotton stainer   II - honeybee  III - Termite   IV - Weevil    The insects whose activities are both beneficial and harmful to human are", "images": [], "options": {"A": "I and II", "B": "II and III", "C": "II and IV", "D": "III and IV"}, "answer": "B", "explanation": "Honeybees are beneficial to humans as they help in pollination of flowers, and also produce honey which is used by humans. However, they can also be harmful as their stings can cause allergic reactions. Termites are harmful as they destroy wooden structures, but they are also beneficial as they play a crucial role in nutrient cycling, soil formation and the flow of water and energy through ecosystems.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>37", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH", "question": "Using the list of insects below to answer the question below:  I - cotton stainer   II - honeybee  III - Termite   IV - Weevil  Which of the insect destroys grains", "images": [], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "D", "explanation": "Weevils are known to be pests of stored grains. They lay their eggs in the grain kernels and the larvae feed on the grain from the inside, causing destruction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2020>38", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Conversation of natural resources does not", "images": [], "options": {"A": "Maintain a balance ecosystem", "B": "Preserve the beauty of nature", "C": "attract tourist", "D": "Threaten the survival of species"}, "answer": "D", "explanation": "Coversion of natural resources does not threaten the survival of species . converstion of natural resources involves the judious use of natural resources .", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>39", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WILDLIFE, FOREST AND MINERALS", "question": "A company was prohibited from producing bags made from natural leopard skin. This is an attempt to conserve", "images": [], "options": {"A": "Land", "B": "water", "C": "wildlife", "D": "minerals"}, "answer": "C", "explanation": "The prohibition of a company from producing bags made from natural leopard skin is an attempt to conserve wildlife. This is because leopards are part of wildlife and their skin is a natural resource that needs to be conserved to prevent their extinction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2020>40", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "Which of the following susbtance is not a conversable natural resource ?", "images": [], "options": {"A": "Mineral", "B": "Air", "C": "Soil", "D": "Water"}, "answer": "B", "explanation": "Air is not a conservable natural resource because it is inexhaustible and cannot be depleted. Unlike minerals, soil, and water, air is constantly being replenished in the atmosphere and does not require conservation efforts to maintain its supply.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>41", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "A child that can recieve blood donation from anybody belongs to the blood group", "images": [], "options": {"A": "O", "B": "A", "C": "B", "D": "AB"}, "answer": "D", "explanation": "A person with AB blood type is considered a universal recipient for blood transfusions because they can receive blood from donors of any blood type: A, B, AB, or O. This is because they have both A and B antigens on their red blood cells, so their body won't see any donated blood as foreign and attack it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>42", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Variation which exhibits a wide range from one extreme to other is", "images": [], "options": {"A": "Phenotypic variation", "B": "Discontinuous variation", "C": "Continuous variation", "D": "genotypic variation"}, "answer": "C", "explanation": "Continuous variation is the type of variation that exhibits a wide range from one extreme to the other. This type of variation is usually quantitative and results from the combined effect of many genes (polygenic), and often environmental factors also influence it. Examples include height, skin color, and body mass index (BMI).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>43", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Measurement of height and weight of students in a class show", "images": [], "options": {"A": "Discontinuous variation", "B": "Continuous variation", "C": "Shortness is more prevalent.", "D": "Fatness is less prevalent"}, "answer": "B", "explanation": "The measurement of height and weight of students in a class shows continuous variation. Continuous variation is a type of genetic variation where the individuals in a population vary in small ways from each other. This variation is usually due to the combined effect of multiple genes and environmental factors. Examples of continuous variation include height, weight, skin color, etc. In this case, the height and weight of students in a class will not be exactly the same for everyone, but will vary in a continuous manner.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>44", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "Which of the following statements about chromosomes is correct?", "images": [], "options": {"A": "All the chromosomes of a species are the same in shape", "B": "The number present in a species is constant", "C": "They are neatly aranged in the cytoplasm", "D": "They bear ribosomes on their outer memberanes"}, "answer": "B", "explanation": "The correct statement about chromosomes is that the number present in a species is constant. This is because each species has a specific number of chromosomes that is constant and unique to that species. For example, humans have 46 chromosomes, dogs have 78, and cats have 38. This number is constant and does not change, regardless of the individual's age, sex, or physical condition. The other options are incorrect because chromosomes can vary in shape, they are not neatly arranged in the cytoplasm, and they do not bear ribosomes on their outer membranes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>45", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "Which of the following disease an be inherited ?", "images": [], "options": {"A": "Pnuemonia", "B": "AIDS", "C": "Sickle cell anaemia", "D": "Goitre"}, "answer": "C", "explanation": "Sickel cell anaemia can be inherited when the parent are carries of the sickl cell trait , there is high tendency for the offspring to be a sickel cell patient.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>46", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY", "question": "The diagram below is an illustration of a cross between plants A and B of the same species.      If the F1 generation are plants with high yield and resistance, the genotype of th F1 generation plants would be", "images": ["Biology/imgs/2020/ENAJ4E.jpg"], "options": {"A": "YYRR", "B": "YyRr", "C": "yyRr", "D": "yyrr"}, "answer": "B", "explanation": "Given the genotypes of the parent plants (A: YYrr and B: yyRR), the F1 generation, which are plants with high yield and resistance, would have the genotype:YyRr.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>47", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY", "question": "The diagram below is an illustration of a cross between plants A and B of the same species.    The process that gave rise to the F1 generation is", "images": ["Biology/imgs/2020/ENAJ4E.jpg"], "options": {"A": "Self fertilization", "B": "Cross fertilization", "C": "Out-breeding", "D": "test cross"}, "answer": "D", "explanation": "A test cross is a genetic technique used to determine the genotype of an individual organism with a dominant phenotype. It involves crossing the individual with a recessive homozygote (an individual with two recessive alleles) to produce offspring with a known genotype.    The purpose of a test cross is to:    1. Determine the genotype of an individual with a dominant phenotype   2. Identify whether an individual is homozygous dominant or heterozygous  3. Analyze the segregation of alleles and genes in the offspring.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>48", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Replication of DNA Molecules is catalysed by an enzyme called", "images": [], "options": {"A": "Polymerase", "B": "Ptyalin", "C": "Pepsin", "D": "amylase"}, "answer": "A", "explanation": "The replication of DNA molecules is catalysed by an enzyme called DNA polymerase. This enzyme adds nucleotides to the growing DNA chain and also has proofreading capabilities to ensure the accuracy of DNA replication. Ptyalin, Pepsin, and Amylase are all enzymes involved in the digestion of food, not in DNA replication.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>49", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Who proposed the theory of evolution by natural selection?", "images": [], "options": {"A": "Darwin", "B": "Lamarck", "C": "Aristotle", "D": "Linnaeus"}, "answer": "A", "explanation": "The theory of evolution by natural selection was proposed by Charles Darwin. This theory states that organisms that are better adapted to their environment are more likely to survive and reproduce, leading to the evolution of species over time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2020>50", "subject": "Biology", "year": "2020", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following statement best explains the reason why termites swarm at night?", "images": [], "options": {"A": "Light is not necessary for swarming", "B": "They avoid day-flying birds", "C": "Light destroys their wings", "D": "they can only see in the dark."}, "answer": "B", "explanation": "Termites swarm at night to avoid predators such as day-flying birds. This is a survival strategy that allows them to reproduce and spread their colonies without being eaten.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>1", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which of the following organelles is common to both plant and animal cells?", "images": [], "options": {"A": "cellulose cell wall", "B": "Chlorophyll", "C": "cell membrane", "D": "large vacuole"}, "answer": "C", "explanation": "Both plant and animal cells have a cell membrane. The cell membrane, also known as the plasma membrane, is a biological membrane that separates the interior of all cells from the outside environment. It provides protection and also allows the passage of ions and organic molecules in and out of the cell.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2021>2", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The diagram below illustrate different sections of  a particular fruit, study the diagram and answer the question      The section in X and Y respectively, are", "images": ["Biology/imgs/2021/m65.jpg"], "options": {"A": "longitudinal and transverse", "B": "transverse and longitudinal", "C": "cross and transverse", "D": "transverse and cross"}, "answer": "B", "explanation": "A transverse section (or cross-section) and a longitudinal section refer to different ways of cutting or viewing an object, typically in biological contexts.  Transverse Section:    Direction: Cut across the short axis.    Example: Cutting a tree trunk into round slices.    View: Cross-section (circular shape).  Longitudinal Section:    Direction: Cut along the long axis.    Example: Cutting a tree trunk lengthwise.    View: Lengthwise section (long shape).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>3", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The diagram below illustrate different sections of  a particular fruit, study the diagram and answer the question    The fruit that has the illustrated sections is a", "images": ["Biology/imgs/2021/m65.jpg"], "options": {"A": "Hesperidium", "B": "capsule", "C": "drupe", "D": "cypsela"}, "answer": "A", "explanation": "The fruit that has the illustrated sections is a hesperidum (plural : hesperidia) is a modified berry with with a tough, leathery, and a juicing pulp divided into segment  as an orange or other citrus fruit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>4", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION", "question": "The diagram below is the illustration of a fungus. study it and answer the question      The structure labelled I is associated with", "images": ["Biology/imgs/2021/m66.jpg"], "options": {"A": "sexual reproduction", "B": "asexual reproduction", "C": "bud formation", "D": "gamete formation"}, "answer": "B", "explanation": "The structure labelled I is the sporangium contains  spores which ar used to reproduce fungal cells asexually", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>5", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION", "question": "The diagram below is the illustration of a fungus. study it and answer the question    The structure labelled II is the", "images": ["Biology/imgs/2021/m66.jpg"], "options": {"A": "Spore", "B": "stolon", "C": "Columella", "D": "sporangium"}, "answer": "C", "explanation": "The structure labelled II is the columella. It is found at the base of sporangium and it is responsible for its bursting", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>6", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION", "question": "The diagram below is the illustration of a fungus. study it and answer the question    Which of the following statement about the structure labelled III is correct ? it", "images": ["Biology/imgs/2021/m66.jpg"], "options": {"A": "secretes digestive enzymes into the substrate", "B": "absorbs minerals salts from the soil", "C": "forms the root hairs of the organism", "D": "develops into stolon"}, "answer": "A", "explanation": "The structure labeled III in the diagram is representing rhizoids, which are root-like structures in fungi. Among the given options, the correct statement about the structure labeled III is: A. secretes digestive enzymes into the substrate. Rhizoids are involved in anchoring the fungus to the substrate and also in nutrient absorption. They secrete digestive enzymes that break down complex organic materials into simpler substances, which can then be absorbed by the fungus.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>7", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "The diagram below is an illustration of a living organism .       The level of organisation of the organism is", "images": ["Biology/imgs/2021/m67.jpg"], "options": {"A": "tissue", "B": "cell", "C": "organ", "D": "system"}, "answer": "B", "explanation": "The organism illustrated is euglena. Euglena is unicellular organism, hence it belongs to the cellular level of organization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>8", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "The diagram below is an illustration of a living organism .     The organism belongs to the phylum", "images": ["Biology/imgs/2021/m67.jpg"], "options": {"A": "Rhizopoda", "B": "ciliophora", "C": "Euglenophyta", "D": "Rhodophyta"}, "answer": "C", "explanation": "Euglena belongs to the phylum Euglenophyta. This group is characterized by organisms that are unicellular, have flagella, and can photosynthesize due to the presence of chloroplasts, although they can also feed heterotrophically.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>9", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "A plant cell placed in a solution with a higher water potential will", "images": [], "options": {"A": "expand and then shrink", "B": "enlarge and become turgid", "C": "expand and then burst", "D": "Decrease in size and become flaccid"}, "answer": "B", "explanation": "When a plant cell is placed in a solution with a higher water potential , water moves into the cells sap by osmosis(endosmosis) because the cell sap (solution of sugar and salts) in the vacuole is more concentrated . the vacuole increases in Volume (expands) ad distends towards the cytoplasm and cell wall . The cell wall distend(expands) until no further distension , At this point the cell is said to be turgid", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>10", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "Offspring formed by sexual reproduction exhibit more variation than those formed by asexual reproduction because", "images": [], "options": {"A": "greater amount of DNA is involved in sexual reproduction", "B": "gametes of parents have different genetic composition", "C": "genetic material come from parents of two different species", "D": "sexual reproduction"}, "answer": "B", "explanation": "sexual reproduction permits variability of individuals which enhances survival in a new environment, This is possible because gametes of parents have different genetic composition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>11", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Radius and ulna are bones of the", "images": [], "options": {"A": "pectoral girdle", "B": "upper arm", "C": "pelvic girdle", "D": "lower arm"}, "answer": "D", "explanation": "The radius and ulna are the two long bones located in the forearm (the area between the elbow and the wrist). The radius is on the lateral side (thumb side) and the ulna is on the medial side (little finger side). Therefore, they are not part of the pectoral girdle, upper arm, or pelvic girdle.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2021>12", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "The blood vessel which carries blood from the alimentary canal to the liver is the", "images": [], "options": {"A": "hepatic artery", "B": "hepatic vein", "C": "hepatic portal vein", "D": "mesenteric artery"}, "answer": "C", "explanation": "The hepatic portal vein is the blood vessel that carries blood from the alimentary canal to the liver. The alimentary canal is the whole passage along which food passes through the body from mouth to anus. It includes the esophagus, stomach, and intestines. The hepatic portal vein carries nutrient-rich blood from the digestive system to the liver for processing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>13", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "which of the labelled parts is the cortex?", "images": ["Biology/imgs/2021/m68.jpg"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "D", "explanation": "The structure labelled III is the ureter which is a continuation or extension of the pelvis , however , the part labelled IV can be related to the kidney's cortex, although , it is not directly on the cortex, but on the medulla, but this is the closest option to the cortex", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>14", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Which is the main function of the organ ?", "images": ["Biology/imgs/2021/m68.jpg"], "options": {"A": "excretion", "B": "respiration", "C": "reproduction", "D": "locomotion"}, "answer": "A", "explanation": "The kidney are organs responsible for the excretion of all nitrogenous wastes  from the body and also responsible for osmoregulation of the blood and body fluid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>15", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Detoxification of urea takes place in the", "images": [], "options": {"A": "pancreas", "B": "heart", "C": "liver", "D": "testes"}, "answer": "C", "explanation": "The liver is the organ that detoxifies urea. Urea is a waste product formed in the liver. The liver breaks down excess amino acids to form ammonia, which is then converted to a less toxic substance called urea. This urea is then transported by the blood to the kidneys, where it is excreted in urine.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2021>16", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "Which of the following hormones is suddenly secretes into the bloodstream of the frightened person", "images": [], "options": {"A": "insulin", "B": "adrenaline", "C": "Thyroxine", "D": "parathormone"}, "answer": "B", "explanation": "The hormone that is suddenly secreted into the bloodstream of a frightened person is adrenaline. Adrenaline is a hormone released from the adrenal glands and its major action, together with noradrenaline, is to prepare the body for 'fight or flight'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2021>17", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "The temperature control centre in mammals is located in the", "images": [], "options": {"A": "skin", "B": "hypothalamus", "C": "pituitary gland", "D": "adrenal gland"}, "answer": "B", "explanation": "The temperature control centre in mammals is located in the hypothalamus. The hypothalamus is a small region of the brain. It's located at the base of the brain, near the pituitary gland. While it's very small, the hypothalamus plays a crucial role in many important functions, including: releasing hormones, regulating body temperature.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2021>18", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "the diagram is an illustration of a type of eye defect in humans. Study it and answer the question below      The eye defect illustrated in the diagram is", "images": ["Biology/imgs/2021/m80.jpg"], "options": {"A": "hypermetropia", "B": "astigmatism", "C": "presbyopia", "D": "myopia"}, "answer": "D", "explanation": "In the diagram illustrated, eye ball is too long hence this is a case of short sightedness or myopia", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>19", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "the diagram is an illustration of a type of eye defect in humans. Study it and answer the question below    The eye defect can be corrected by the use of", "images": ["Biology/imgs/2021/m80.jpg"], "options": {"A": "convex lens", "B": "concave lens", "C": "bifocal lens", "D": "cylindrical lens"}, "answer": "B", "explanation": "Myopia can be corrected by using concave lens eye-glasses which diverge (blend light rays outwards) parallel light rays from distant object before falling on the eyeball and thus focusing them on the retina", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>20", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "How many gametes are produced in the pollen grain of a flowing plant before fertilization ?", "images": [], "options": {"A": "One", "B": "two", "C": "three", "D": "four"}, "answer": "B", "explanation": "In flowering plants, each pollen grain produces two male gametes. This process is part of the double fertilization mechanism in angiosperms, where one male gamete fuses with the egg cell to form the zygote, and the other fuses with two polar nuclei to form the endosperm.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2021>21", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following organism does not undergo incomplete metamorphosis?", "images": [], "options": {"A": "locust", "B": "Grasshopper", "C": "Butterfly", "D": "cockroach"}, "answer": "C", "explanation": "Butterflies undergo complete metamorphosis, which includes four stages: egg, larva (caterpillar), pupa (chrysalis), and adult. In contrast, insects like locusts, grasshoppers, and cockroaches undergo incomplete metamorphosis, which includes three stages: egg, nymph, and adult. The nymph stage resembles the adult but is smaller and lacks mature wings.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>22", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "An enzyme reaction may begin to decline when", "images": [], "options": {"A": "the optimum temperature is attained", "B": "The pH of the medium is altered", "C": "There is an increase in substrate concentration", "D": "The atmospheric pressure is altered"}, "answer": "B", "explanation": "Enzymes function at specific pH, so when the pH of a medium in which an enzyme is supposed to function changes from what it normally is ot something else, the enzyme's function with decline", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>23", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "The diagram below is an illustration of the growth of plant in water culture. After a few days, the solution turn green and the plant died. Use the informatin to answer the question below       What is the precaution should be taken to prevent the solution from turning green", "images": ["Biology/imgs/2021/m85.jpg"], "options": {"A": "Use a non-green plant for the experiment", "B": "Aerate the solution daily", "C": "cover the culture vessel with opaque paper", "D": "Keep cotton wool around the seedling to make it dry"}, "answer": "C", "explanation": "The culture solution should be covered with an opaque paper to prevent the entry of sunlight", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2021>24", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "The diagram below is an illustration of the growth of plant in water culture. After a few days, the solution turn green and the plant died. Use the informatin to answer the question below     The death of the plant was likely caused by", "images": ["Biology/imgs/2021/m85.jpg"], "options": {"A": "excess supply of nutrients to the plant", "B": "inadequate supply of water to the plant", "C": "Algal growth in the solution that used up the nutrient", "D": "inability of the plant to make food due to lack of sunlight"}, "answer": "C", "explanation": "The death of the plant was due to algal growth in the solution that used up the nutrients making the plant nutrient-deficient", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2021>25", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following factors is not necessary for photosynthesis?", "images": [], "options": {"A": "water", "B": "carbon(iv) oxide", "C": "wind", "D": "sunlight"}, "answer": "C", "explanation": "Photosynthesis is the process by which green plants and some other organisms use sunlight to synthesize foods with the aid of chlorophyll pigments. The necessary factors for photosynthesis include sunlight, water, and carbon dioxide. Wind is not a necessary factor for photosynthesis. While it can affect the rate of transpiration (which can indirectly influence photosynthesis), it is not directly involved in the photosynthesis process itself.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2021>26", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION", "question": "Autotrophic nutrition is a process whereby an organism obtains food", "images": [], "options": {"A": "by utilizing it stored energy", "B": "by synthesizing simple substance using energy", "C": "from other organism in exchange for some products", "D": "in a synthesized form, from other living organism"}, "answer": "B", "explanation": "In autotrophic nutrition, the organism manufactures it food from simple substance using energy (from sunlight as in photosynthesis or chemical compound as in chemosynthesis)", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2021>27", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The process that takes place at the light stage of photosynthesis is", "images": [], "options": {"A": "splitting of water molecules to form hydrogen ions", "B": "reduction of carbon (IV) oxide to form carbohydrate.", "C": "formation of two molecules of Phosphoglyceric acid", "D": "breaking down of ATP molecules to produce energy"}, "answer": "A", "explanation": "One of the processes that takes place in the light-dependent stage of photosynthesis in the photolysis of water, i.e the splitting of water molecules.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>28", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The diagram below is an illustration of the foot of an animal      The adaptation of this type of foot is that it is", "images": ["Biology/imgs/2021/m84.jpg"], "options": {"A": "used as a bait to catch fish in water", "B": "used as a paddle for swimming", "C": "effective in scratching the soil for food", "D": "used for killing prey in water"}, "answer": "B", "explanation": "Webbed feet are adapted for swimming by functioning like paddles. The webbing between the toes expands the surface area, allowing the animal to push more water with each stroke. This paddle-like action provides increased propulsion, making swimming more efficient and enabling the animal to move quickly and smoothly through the water. The webbed feet also help with steering and maneuverability, allowing for precise control while swimming.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>29", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The following organism are examples of carnivorous plants except", "images": [], "options": {"A": "Gloriosa", "B": "venus flytrap", "C": "pitcher plant", "D": "utricularia"}, "answer": "A", "explanation": "Gloriosa is not a carnivorous plants. Carnivorous plants are plants that grow in environment/soil with low nitrogen, hence, they derive their nitrogen from insect which they trap with special modified  body parts. Examples include: pitcher, utricularia, venus  fly trap e.t.c.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2021>30", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : COMMUNITY", "question": "Plant and animals of an ecosystem make up a", "images": [], "options": {"A": "habitat", "B": "succession", "C": "community", "D": "population"}, "answer": "C", "explanation": "In an ecosystem, the plants and animals together make up a community. A community in biology refers to an interacting group of various species in a common location. For example, a forest of trees and undergrowth plants, inhabited by animals and rooted in soil containing bacteria and fungi, constitutes a biological community. A habitat, on the other hand, is the natural home or environment of an animal, plant, or other organism. Succession is a series of progressive changes in the species composition of an ecological community over time, and a population refers to all the organisms of the same group or species who live in a particular geographical area.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2021>31", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Rabbits cannot survive in an aquatic habitat because they have", "images": [], "options": {"A": "no scales", "B": "no gills", "C": "fore limbs", "D": "lateral line"}, "answer": "B", "explanation": "Rabbits cannot survive in an aquatic habitat for many reason. One important reasons is that they do not use gills for respiration, hence, they will suffocate due to lack of oxygen", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2021>32", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "The illustration below is a food chain   grass →grasshopper→domestic fowl →hawk  What would happen if the population of domestic fowl decrease? The population of", "images": [], "options": {"A": "grasshoppers would decrease", "B": "Hawks would increase", "C": "grasshoppers would increase", "D": "grass available to grasshopper would increase"}, "answer": "C", "explanation": "The domestic fowl is directly related to the grasshopper in the food chain, when the population of domestic fowl decrease, it implies that the survival rate of th grasshopper will increase, and hence their population.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>33", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Which of the following feature is a characteristics of aquatic plants? possession of", "images": [], "options": {"A": "multiple epidermis", "B": "heavily lignified tissue", "C": "finely divided leaves", "D": "succulent stem"}, "answer": "C", "explanation": "Aquatic plants often have finely divided leaves to increase their surface area for maximum absorption of sunlight and gases. This is because water absorbs light, so the plants need to capture as much light energy as possible. The other options are not characteristic of aquatic plants. Multiple epidermis and heavily lignified tissue are more common in terrestrial plants, which need to retain water and support their own weight. Succulent stems are a feature of desert plants, which store water in their stems to survive in arid conditions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2021>34", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS", "question": "an association between living organism in which one organism lives on and feeds at the  expense of the other organism is known as", "images": [], "options": {"A": "mutualism", "B": "commensalism", "C": "parasitism", "D": "predation"}, "answer": "C", "explanation": "This is known as parasitism, the organism that lives on and feeds at the expense of the other organism is the parasite, while the other organism which is expended or deprived is the host", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>35", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION", "question": "When a large number of organism share limited resources, the result is", "images": [], "options": {"A": "mutualism", "B": "extinction", "C": "commensalism", "D": "competition"}, "answer": "D", "explanation": "When a large number of organisms share limited resources, the result is competition. This is because all the organisms are trying to use the same limited resources to survive and reproduce, leading to a struggle for survival. This is a fundamental concept in ecology known as 'competition'. None of the other options (mutualism, extinction, commensalism) accurately describe this scenario.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2021>36", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH", "question": "Which of the following behaviours is correctly matched with the corresponding disease?", "images": [], "options": {"A": "Behaviour Diseasesmoking  cigarette liver cirrhosis; lung cancer; Aids.", "B": "Behaviour Diseasehaving multiple sex partners  liver cirrhosis; syphilis; Aids.", "C": "Behaviour Diseaseliving near dirty gutter syphilis; lung cancer; Aids.", "D": "Behaviour Diseaseeating uncooked meat  dysentery; cholera;food poisoning."}, "answer": "D", "explanation": "- Having multiple sexual partners increases the risk of contracting sexually transmitted infections (STIs) like syphilis and AIDS.  - Liver cirrhosis is not directly related to having multiple sexual partners, but alcohol consumption, which can increase the risk of liver cirrhosis, may be more common among people with risky sexual behavior.    The other options are not correctly matched:  Smoking cigarettes is linked to lung cancer, but not liver cirrhosis or AIDS.  Living near a dirty gutter may increase the risk of waterborne diseases like cholera or dysentery, but not lung cancer or syphilis.  Eating uncooked meat can lead to food poisoning, dysentery, or cholera, but not liver cirrhosis or syphilis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>37", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "Endangered species are organism that are", "images": [], "options": {"A": "likely to migrate to other favourable lands", "B": "likely to disappear from the surface of the earth", "C": "reproducing profusely in an area", "D": "dangerous to humans and attacking other animals"}, "answer": "B", "explanation": "Endangered species are organisms that are at risk of becoming extinct, or disappearing from the surface of the earth. This can be due to a variety of factors such as habitat loss, climate change, or overexploitation. The other options do not accurately describe what it means for a species to be endangered.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2021>38", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Which of the following practices is a wildlife conservation method?", "images": [], "options": {"A": "use of cover crops", "B": "crop rotation", "C": "mulching", "D": "discouraging poaching"}, "answer": "D", "explanation": "Wildlife conservation methods are practices that help to protect and preserve wildlife and their habitats. Discouraging poaching is a wildlife conservation method because poaching, or the illegal hunting or capturing of wild animals, is a major threat to many species. The other options listed are agricultural practices, not wildlife conservation methods.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2021>39", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "Which of the following resources cannot be conserved", "images": [], "options": {"A": "forest", "B": "water", "C": "soil", "D": "Garbage"}, "answer": "D", "explanation": "Garbage cannot be conserved. Conservation refers to the sustainable use and management of natural resources including wildlife, water, air, and earth deposits. While garbage can be managed and recycled, it is not a natural resource and thus cannot be conserved in the same sense as forests, water, or soil.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>40", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "the diagram below are illustration of types of comb found in domestic fowl      The type of comb show", "images": ["Biology/imgs/2021/m83.jpg"], "options": {"A": "variation", "B": "inheritance", "C": "cell theory", "D": "courtship behaviour"}, "answer": "A", "explanation": "The type of comb illustrated show variation , variation refers to the difference between individual.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>41", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "the diagram below are illustration of types of comb found in domestic fowl    which factor is most likely responsible for the variation type of comb?", "images": ["Biology/imgs/2021/m83.jpg"], "options": {"A": "environment", "B": "Genetics", "C": "physiology", "D": "morphology"}, "answer": "B", "explanation": "Genetics is most likely responsible for different types of comb.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>42", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Which of the following statement about mitosis is not correct?", "images": [], "options": {"A": "Chiasmata are found", "B": "Bivalents are not formed", "C": "it does lead to variation", "D": "four daughter cells are produced"}, "answer": "D", "explanation": "Mitosis produces two diploid cells from one parent diploid cell.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>43", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "A mixture of blood with antigen A and blood containing antibody a will", "images": [], "options": {"A": "lead to agglutination", "B": "facilitate dissolution of clot", "C": "have no effect on blood composition", "D": "change the blood group"}, "answer": "A", "explanation": "When blood with antigen A is mixed with blood containing antibody a, it will lead to agglutination. Agglutination is the clumping of particles. The word agglutination comes from the Latin agglutinare (glueing to). In biology, it is a process that occurs if an antigen is mixed with its corresponding antibody. In this case, antigen A will bind with antibody a, causing the blood cells to clump together, which is known as agglutination.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>44", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY", "question": "Plants suitable for experiment in genetics must not", "images": [], "options": {"A": "produce numerous seeds within short time", "B": "have small number of chromosomes", "C": "have a relatively short life cycle", "D": "produced one generation in a long period"}, "answer": "D", "explanation": "Plants suitable for experiments in genetics should not produce one generation in a long period. This is because genetic experiments often require multiple generations to observe patterns of inheritance and genetic variation. If a plant takes a long time to produce a new generation, it would slow down the research process. Therefore, ideal plants for genetic experiments should have a relatively short life cycle, produce numerous seeds within a short time, and have a small number of chromosomes for easier genetic analysis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>45", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of the following statement about sickle cell anaemia is correct ?", "images": [], "options": {"A": "it is caused by sex-linked genes", "B": "it is more common in males than in females", "C": "two sickle cell carrier parents may have a sickling child", "D": "it is caused by recessive genes"}, "answer": "C", "explanation": "Sickle cell anemia is a genetic disorder that affects the shape of the red blood cells, causing them to become sickle-shaped. It is caused by a mutation in the HBB gene, which is not sex-linked but autosomal recessive. This means that both parents must carry the sickle cell trait for a child to potentially have the disease. Therefore, the statement 'two sickle cell carrier parents may have a sickling child' is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>46", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "In humans, pointed eyebrows (B) is dominant trait over smooth eyebrows (b). A student and the mother have smooth eyebrows while father has pointed eyebrows. what is the genotype of the father", "images": [], "options": {"A": "BB", "B": "Bb", "C": "BBb", "D": "BBbb"}, "answer": "B", "explanation": "Parameter given :  B - pointed eyebrow   b - smooth eyebrow   Student  - bb (one of these allels must be from the father)  Mother - bb  Father - pointed eyebrow  The geneotype of the father is Bb.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>47", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "A woman with Rhesus negative blood group was advised not marry a man with rhesus positive blood group because", "images": [], "options": {"A": "it hinder her from having blood transfusion from her husband", "B": "it will result in sickness and probably death of the offspring", "C": "her children may all resemble her husband", "D": "it may affect her child bearing ability"}, "answer": "B", "explanation": "A woman with Rhesus negative blood group marrying a man with Rhesus positive blood group can lead to a condition called Rhesus disease in their offspring. This happens when the mother's body produces antibodies against the Rhesus positive blood of the baby. This can lead to severe illness and even death of the baby.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>48", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Which of the following organisms exhibits division of labour", "images": [], "options": {"A": "butterfly", "B": "cockroach", "C": "termite", "D": "housefly"}, "answer": "C", "explanation": "Termites are social insects which exhibit labour division . The names of different castes of termites nest are :  - workers  - Soliders  - queen   - king  - winged reproductive (alates)", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>49", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Natural selection arises as a result of", "images": [], "options": {"A": "gene mutation", "B": "change of habitat", "C": "reduction in population", "D": "climate change"}, "answer": "A", "explanation": "Natural selection arises as a result of gene mutation . Mutation provides raw material for organic evolution through natural selection of new species.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2021>50", "subject": "Biology", "year": "2021", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Which of the following statement is not Lamarck's postulate on evolution ?", "images": [], "options": {"A": "Great changes in the environment result in corresponding changes in species", "B": "frequently used organs become well developed while the ones not used becomes vestigial", "C": "well developed acquired characters are inheritable", "D": "survivors  in a competitive community must have inherited useful traits."}, "answer": "D", "explanation": "The statement 'survivors in a competitive community must have inherited useful traits' is not a postulate of Lamarck's theory of evolution. This statement is more aligned with Darwin's theory of natural selection, which posits that individuals with advantageous traits are more likely to survive and reproduce. Lamarck's theory, on the other hand, proposed that an organism can change during its lifetime in response to its environment, and those changes are inheritable.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2022>1", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONCEPT OF LIVING : PROPERTIES AND FUNCTIONS OF THE LIVING CELL", "question": "Which of the following statements about living things is correct?", "images": [], "options": {"A": "Animals respire using carbon (IV) oxide as a raw material", "B": "Growth in plants is limited after some time", "C": "Most plants respond to stimulus slowly", "D": "Higher animals can reproduce asexually"}, "answer": "C", "explanation": "Living things respond to stimuli, and this is one of the characteristics of life. However, the rate of response varies. Plants, for instance, respond to stimuli but at a slower pace compared to animals. This is due to their lack of a nervous system. The other options are incorrect. Animals respire using oxygen, not carbon (IV) oxide. Growth in plants is not necessarily limited after some time, it depends on the species and environmental conditions. Higher animals generally reproduce sexually, not asexually.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>2", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "Organ level of organization in living things is found in", "images": [], "options": {"A": "waterleaf plant", "B": "virus particle", "C": "kidney", "D": "spermatozoon"}, "answer": "C", "explanation": "In the level of biological organization, the kidney is an organ. In all animals that have complex levels of organization, a kidney is always an organ", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2022>3", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Diagrams X and Y below are illustrations of transverse sections of a part of plants. Study them and answer the question below      Which of the following statements is not correct? Diagrams X and Y are sections of", "images": ["Biology/imgs/2022/xy.png"], "options": {"A": "roots", "B": "a dicotyledonous root and a monocotyledonous root respectively", "C": "vascular bundles.", "D": "stems."}, "answer": "D", "explanation": "Stem is the main trunk of a plant that bear branches, leaves and fruits", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>4", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Diagrams X and Y below are illustrations of transverse sections of a part of plants. Study them and answer the question below  The part responsible for conducting water and dissolved mineral salts from the soil to the leaves is labelled", "images": ["Biology/imgs/2022/xy.png"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "A", "explanation": "The xylem is the tissue in plants responsible for the conduction of water and dissolved mineral salts from the roots to the leaves. It consists of various cell types, including tracheids and vessel elements, which are specialized for the upward transport of water and minerals absorbed from the soil. The root, on the other hand, is primarily involved in anchoring the plant and absorbing water and minerals from the soil, but it is not the tissue that conducts these substances to the leaves", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2022>5", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Diagrams X and Y below are illustrations of transverse sections of a part of plants. Study them and answer the question below  The part labelled II is the", "images": ["Biology/imgs/2022/xy.png"], "options": {"A": "pith", "B": "xylem", "C": "phloem", "D": "endodermis"}, "answer": "A", "explanation": "II is the pith. The pith is typically found in the roots of monocot plants but not in the roots of dicot plants. In monocot roots, the pith is a central region of parenchyma cells. In contrast, dicot roots usually have a solid core of vascular tissue without a distinct pith, with xylem and phloem arranged in a radial pattern around a central core.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2022>6", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The organelles in cells which are also referred to as suicidal bags are the", "images": [], "options": {"A": "mitochondria", "B": "lysosomes", "C": "ribosomes", "D": "nuclei"}, "answer": "B", "explanation": "Lysosomes are called \"suicide bags\" of the cell because they have hydrolytic enzymes stored in them. These enzymes are used to digest complex molecules in a cell. When released into the cytoplasm, these enzymes can \"digest\" or destroy the cell itself. Therefore, they are called \"suicide bags.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2022>7", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "The process that brings about the shrinking of a Spirogyra cell when placed in a strong solution is", "images": [], "options": {"A": "osmosis", "B": "autolysis", "C": "plasmolysis", "D": "diffusion"}, "answer": "C", "explanation": "When a Spirogyra cell is placed in a strong (hypertonic) solution, water moves out of the cell due to osmosis, causing the cell to shrink. This process is known as plasmolysis. Osmosis is the movement of water molecules from an area of high concentration to an area of low concentration through a semi-permeable membrane. Autolysis is the self-destruction of cells by its own enzymes, and diffusion is the movement of particles from an area of high concentration to an area of low concentration, hence these options are not correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>8", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The region of a plant stem in which cells divide to increase its diameter is the", "images": [], "options": {"A": "cambium", "B": "phloem", "C": "xylem", "D": "collenchyma"}, "answer": "A", "explanation": "The vascular cambium is responsible for increasing the diameter of stems and roots and for forming woody tissue. The cork cambium produces some of the bark.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>9", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS", "question": "The total number of caudal vertebrae in animals X and Y is 4 and 27 respectively. The animals are likely to be", "images": [], "options": {"A": "fish and human.", "B": "toad and rat", "C": "toad and fish.", "D": "humans and rat"}, "answer": "D", "explanation": "The number of caudal (tail) vertebrae varies among different animal species. Humans typically have 3 to 5 caudal vertebrae, which are fused to form the coccyx or tailbone. Rats, on the other hand, have a long tail with up to 28 caudal vertebrae. Therefore, the animals X and Y are likely to be humans and rats, respectively. Fish and toads do not have such a number of caudal vertebrae, and the number of caudal vertebrae in humans is not as high as 27.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>10", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Which of the following blood components has the greatest affinity for oxygen and carbon (IV) oxide?", "images": [], "options": {"A": "Lymphocyte", "B": "Erythrocyte", "C": "Blood plasma", "D": "Thrombocyte"}, "answer": "B", "explanation": "Erythrocyte is a red blood cell, which (in humans) is typically a biconcave disc without a nucleus. Erythrocytes contain the pigment haemoglobin, which imparts the red colour to blood, and transport oxygen and carbon dioxide to and from the tissues.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>11", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Use the following processes to answer the question below.  I - Ribs move upward and outward  II - Diaphragm relaxes  III -Volume of thorax increases  IV - Air is forced out of the lungs    Which of the processes take place during inspiration?", "images": [], "options": {"A": "I and III only", "B": "II and III only", "C": "II and IV only", "D": "III and IV only"}, "answer": "A", "explanation": "When the lungs inhale, the diaphragm contracts and pulls downward. At the same time, the muscles between the ribs contract and pull upward. This increases the size of the thoracic cavity and decreases the pressure inside. As a result, air rushes in and fills the lungs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>12", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "Use the following processes to answer the question below.  I - Ribs move upward and outward  II - Diaphragm relaxes  III -Volume of thorax increases  IV - Air is forced out of the lungs   Which of the processes is a direct result of contraction of the intercostal muscles?", "images": [], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "B", "explanation": "When the internal intercostal muscles contract and diaphragm relax, the ribs move downward and inward and the diaphragm becomes convex {dome shaped)", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>13", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "The process by which the amount of water and solutes in the blood are controlled is known as", "images": [], "options": {"A": "haemolysis", "B": "diffusion", "C": "turgidity", "D": "osmoregulation"}, "answer": "D", "explanation": "Osmoregulation is the process of maintaining salt and water balance (osmotic balance) across membranes within the body. The fluids inside and surrounding cells are composed of water, electrolytes, and nonelectrolytes", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>14", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "The table below shows the effect of hormones  I, II, III and IV on some parts of the human body. Where (√) represents effect and (X) represents no effect of hormone on the corresponding part of the body. Study it and answer the question below  Hormone Effect on HeartEffect on Digestive systemEffect on KidneyEffect on UterusI√√√√ IIXX√XIIIXXX√IVX√XX    -Which of the following hormones are I, II, III and IV respectively?", "images": [], "options": {"A": "ADH, Glucagon, Oestrogen, Adrenaline", "B": "Adrenaline, Glucagon, Oestrogen, ADH", "C": "Glucagon, ADH, Oestrogen, Adrenaline", "D": "Adrenaline, ADH, Oestrogen, Glucagon"}, "answer": "D", "explanation": "Adrenaline- increases blood pressure, heart rate, and metabolism in reaction to stress        ADH-Antidiuretic hormone (ADH) helps regulate the amount of water in your body. It works to control the amount of water your kidneys reabsorb as they filter out waste from your blood. This hormone is also called arginine vasopressin (AVP).  Oestrogen is a female sex hormone that has many roles in the body, from controlling puberty to strengthening bones.  Glucagon is a hormone that is involved in controlling blood sugar (glucose) levels.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2022>15", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "The table below shows the effect of hormones  I, II, III and IV on some parts of the human body. Where (√) represents effect and (X) represents no effect of hormone on the corresponding part of the body. Study it and answer the question below  Hormone Effect on HeartEffect on Digestive systemEffect on KidneyEffect on UterusI√√√√ IIXX√XIIIXXX√IVX√XXThe hormone responsible for anxiety is", "images": [], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "A", "explanation": "Anxiety can be caused by your body initiating its fight-or-flight response due to stress or even just due to anxious thoughts. This response produces adrenaline, which prepares your body for danger. Adrenaline causes many of the symptoms you experience with anxiety", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>16", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The diagram below is an illustration of  some parts of a mammalian ear. Study it and answer the question below.        The parts labelled I are the", "images": ["Biology/imgs/2022/ear.png"], "options": {"A": "semi circular canals.", "B": "ossicles", "C": "cochlea", "D": "external auditory meatus."}, "answer": "B", "explanation": "The ossicles are actually tiny bones - the smallest in the human body. The three bones are named after their shapes: the malleus (hammer), incus (anvil) and stapes (stirrup). The ossicles further amplify the sound.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>17", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The diagram below is an illustration of  some parts of a mammalian ear. Study it and answer the question below.     Which of the parts are correctly grouped?  Inner ear\tMiddle ear\tOuter ear", "images": ["Biology/imgs/2022/ear.png"], "options": {"A": "I  IV,\tIII,\t     II", "B": "III,\t II  IV,\t      I", "C": "I,               II,                 III   IV", "D": "II,\t  I   III,\t        IV"}, "answer": "D", "explanation": "The inner ear is made up of the cochlea, the auditory nerve and the brain. The middle ear consists of the middle ear bones called the ossicles (malleus, incus, stapes). The outer ear includes the pinna, the ear canal and the eardrum.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>18", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The diagram below is an illustration of  some parts of a mammalian ear. Study it and answer the question below.     The middle ear is connected to the pharynx by the part labelled", "images": ["Biology/imgs/2022/ear.png"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "C", "explanation": "The Eustachian tube connects the middle ear space to the upper part of the throat.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2022>19", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The diagrams below are illustrations of two different cells involved in a biological process in mammals. Study them and answer the question below.      Which parts of P and Q fuse to complete the biological process?", "images": ["Biology/imgs/2022/sexcell.png"], "options": {"A": "III and I", "B": "IV and I", "C": "III and II", "D": "IV and II"}, "answer": "A", "explanation": "When the sperm cell finally reaches the egg cell, the plasma membranes of the two cells fuse together", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2022>20", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The diagrams below are illustrations of two different cells involved in a biological process in mammals. Study them and answer the question below.   Which of the following statements about P and Q is correct?", "images": ["Biology/imgs/2022/sexcell.png"], "options": {"A": "Both cells are structures for asexual reproduction", "B": "Both cells normally belong to the same individual", "C": "Both cells are found in plants", "D": "The union of both cells gives rise to a new mammal"}, "answer": "D", "explanation": "Fertilization is the process in which gametes (an egg and sperm) fuse to form a zygote", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>21", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "The diagrams below are illustrations of two different cells involved in a biological process in mammals. Study them and answer the question below.   If the number of chromosomes in the skin cells of mammals is 46, how many chromosomes would be found in P and Q respectively?", "images": ["Biology/imgs/2022/sexcell.png"], "options": {"A": "23 and 23", "B": "23 and 46", "C": "46 and 23", "D": "46 and 46"}, "answer": "A", "explanation": "A gamete is a mature haploid (having half the number of chromosomes i.e., 23 chromosomes) male or female germ cell which is able to unite with another of the opposite sex in sexual reproduction to form a diploid (having the complete number of chromosomes i.e., 46 chromosomes) zygote, which results in Fertilisation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>22", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "In which of the following structures is simple sugar produced?", "images": [], "options": {"A": "Vacuole", "B": "Cytoplasm", "C": "Chloroplast", "D": "Cell wall"}, "answer": "C", "explanation": "Plants can produce their own food. During the process of photosynthesis they use water sunlight, carbon dioxide and sunlight to produce simple sugar and also release oxygen in the environment. The most common sugars are glucose, fructose and sucrose.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2022>23", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "An evidence of the occurrence of photosynthesis in an experiment is the", "images": [], "options": {"A": "release of carbon (IV) oxide.", "B": "release of oxygen.", "C": "formation of water molecules.", "D": "formation and release of fructose."}, "answer": "B", "explanation": "The release of oxygen is a direct evidence of the occurrence of photosynthesis. During photosynthesis, plants take in carbon dioxide and water, and with the help of sunlight, they convert these into glucose and oxygen. The oxygen is released into the atmosphere, which is a visible sign that photosynthesis is taking place.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>24", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "The major sources of vitamin A are", "images": [], "options": {"A": "egg yolk, carrot and palm oil.", "B": "mango, pawpaw and eggs.", "C": "sorghum, soya bean and liver.", "D": "rice bran, green vegetables and milk."}, "answer": "A", "explanation": "Vitamin A is a fat-soluble vitamin that is good for healthy vision, skin, bones and other tissues in the body. Vitamin A often works as an antioxidant, fighting cell damage, but it also has many other uses. Some of the major sources of Vitamin A are egg yolk, carrot and palm oil. Egg yolk is a rich source of Vitamin A. Carrots are high in beta carotene, a compound our bodies change into vitamin A. Palm oil is also rich in beta carotene.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2022>25", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Diagram J is a protease while diagrams K, L,M and N are food substances. Study them and answer question the question below      Which of the illustrated food substances would form a reaction with protease J?", "images": ["Biology/imgs/2022/protease.png"], "options": {"A": "K", "B": "L", "C": "M", "D": "N"}, "answer": "B", "explanation": "Diagram L would form a reaction with protease J because of the shape of L which will fit into the hollow shape of diagram J", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>26", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Diagram J is a protease while diagrams K, L,M and N are food substances. Study them and answer question the question below   Protease J would react with the particular illustrated substance because enzymes", "images": ["Biology/imgs/2022/protease.png"], "options": {"A": "are denatured at a high frequency.", "B": "are specific in their action.", "C": "remain unchanged after a reaction.", "D": "speed up the rate of chemical reaction."}, "answer": "B", "explanation": "Enzymes, such as proteases, have specific shapes that fit only particular substrates, similar to a lock and key mechanism. This specificity ensures that each enzyme reacts only with a specific substance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>27", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Diagram J is a protease while diagrams K, L,M and N are food substances. Study them and answer question the question below   After a reaction between protease J and the food substance, the end-product would be", "images": ["Biology/imgs/2022/protease.png"], "options": {"A": "fatty acids.", "B": "glucose.", "C": "amino acids.", "D": "water."}, "answer": "C", "explanation": "protease (also called a peptidase or proteinase) is an enzyme that catalyzes (increases reaction rate or \"speeds up\") proteolysis, breaking down proteins into smaller polypeptides or single amino acids, and spurring the formation of new protein products.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>28", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "The property of clayey soil that prevents it from supporting thick vegetation is its", "images": [], "options": {"A": "composition of chemically weathered granite rocks.", "B": "inability to retain much water.", "C": "tendency of becoming waterlogged.", "D": "porosity and low water-retention ability."}, "answer": "C", "explanation": "Clayey soil is a type of soil that is characterized by small particle size and high capacity for holding water. This property makes it prone to becoming waterlogged, especially during heavy rains. When soil is waterlogged, the water fills up all the air spaces between the soil particles, leaving no room for air. This lack of air can suffocate roots of plants and can cause them to rot, which can make it difficult for thick vegetation to grow. Therefore, the property of clayey soil that prevents it from supporting thick vegetation is its tendency of becoming waterlogged.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>29", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT", "question": "Which of the following practices will not maintain soil fertility?", "images": [], "options": {"A": "Preventing soil erosion", "B": "Bush fallowing", "C": "Leaving the land bare", "D": "Planting cover crops"}, "answer": "C", "explanation": "Leaving the land bare will not maintain soil fertility. This is because when the land is left bare, it is exposed to the elements, which can lead to soil erosion and the loss of nutrients. Soil erosion is the process where wind, water, or other natural agents move soil from one place to another, causing the fertile topsoil to be washed or blown away. This can lead to a decrease in soil fertility as the topsoil contains the majority of the soil's nutrients and organic matter.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2022>30", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING", "question": "A group of organisms of the same species living in a particular place is known as", "images": [], "options": {"A": "colony.", "B": "community.", "C": "ecosystem.", "D": "population."}, "answer": "D", "explanation": "A population is the number of organisms of the same species that live in a particular geographic area at the same time, with the capability of interbreeding.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2022>31", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "The diagram below is an illustration of an experiment on sedimentation of soil. Use it to answer the question below       The organic component of the soil is labelled", "images": ["Biology/imgs/2022/soil.png"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "A", "explanation": "The organic component of the soil is labelled I. Organic component forms the topmost layer", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>32", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "The diagram below is an illustration of an experiment on sedimentation of soil. Use it to answer the question below    The part labelled IV is", "images": ["Biology/imgs/2022/soil.png"], "options": {"A": "silt.", "B": "sand.", "C": "humus.", "D": "clay."}, "answer": "B", "explanation": "The part labelled IV is sand. Sand particles settles at the bottom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>33", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "Which of the following pyramids is not used in ecology? Pyramid of", "images": [], "options": {"A": "energy", "B": "numbers", "C": "biomass", "D": "organisms"}, "answer": "D", "explanation": "An ecological pyramid is a graphical representation showing the relationship between different organisms in an ecosystem. It shows the flow of energy at different trophic levels in an ecosystem.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>34", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Study the food chain illustrated below and use it to answer the question below  J → K→  L→  M → N    Organism J is normally sustained by energy from", "images": [], "options": {"A": "green plants.", "B": "carbohydrates.", "C": "organism K.", "D": "sunlight"}, "answer": "D", "explanation": "The sun is the major source of energy for organisms and the ecosystem.J are producers which use the energy from the sunlight to make organic matter from carbon dioxide and water", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>35", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Study the food chain illustrated below and use it to answer the question below  J → K→  L→  M → N  Which of the following statements about organism L is correct? It", "images": [], "options": {"A": "feeds on organism M", "B": "is a primary consumer", "C": "is the producer", "D": "is a secondary consumer"}, "answer": "D", "explanation": "Secondary consumer are the group in the food chain that eats primary consumers. This means that secondary consumers can either be omnivores or carnivores.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>36", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Study the food chain illustrated below and use it to answer the question below  J → K→  L→  M → N  The position occupied by each of organisms  J, K, L, M and N in the food chain is known as the", "images": [], "options": {"A": "energy level.", "B": "trophic level.", "C": "food web.", "D": "pyramid of numbers."}, "answer": "B", "explanation": "The trophic level of an organism is the number of steps it is from the start of the chain. A trophic level is the group of organisms within an ecosystem which occupy the same level in a food chain.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>37", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : ADAPTATION OF ORGANISMS TO HABITATS.", "question": "Which of the following features is not an adaptation of plants to aquatic habitats?", "images": [], "options": {"A": "Breathing roots for entry of air", "B": "Flowers are raised above water to attract pollinators", "C": "Spongy tissues containing gases for buoyancy", "D": "Hairy structures on the leaves to reduce water loss"}, "answer": "D", "explanation": "Aquatic plants are referred to as hydrophytes. Plants need special adaptations to exchange  gases, reproduce and mantain a balance of salt and water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>38", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "ECOLOGY OF POPULATION : ECOLOGICAL SUCCESSION", "question": "The biological association that contributes directly to succession in a community is", "images": [], "options": {"A": "competition.", "B": "predation.", "C": "parasitism.", "D": "commensalism"}, "answer": "A", "explanation": "Succession in a community is a process where the structure of a biological community evolves over time. This process is directly influenced by competition among species for resources. In this context, competition refers to the struggle between individuals or different species for limited resources. This competition leads to the survival of the fittest and contributes to the succession in a community. Predation, parasitism, and commensalism are also biological associations, but they do not contribute directly to succession.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>39", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "The conservation of natural resources is enhanced by the following practices except", "images": [], "options": {"A": "controlling farming activities.", "B": "protecting endangered species.", "C": "poaching in game reserves", "D": "establishing parks and gardens."}, "answer": "C", "explanation": "The conservation of natural resources is a practice that involves protecting, preserving, and managing the use of our natural resources in a sustainable way. This includes controlling farming activities to prevent soil erosion and degradation, protecting endangered species to maintain biodiversity, and establishing parks and gardens to preserve natural habitats. However, poaching in game reserves is not a conservation practice. Instead, it is a harmful activity that threatens wildlife populations and disrupts ecosystems.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>40", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "The burning of farmlands should be discouraged because it", "images": [], "options": {"A": "destroys the organic components of the soil.", "B": "increases the population of wild animals on the farm.", "C": "increases the dormancy period of some seeds.", "D": "destroys some plant pests."}, "answer": "A", "explanation": "During burning process some nutrients that are highly needed by the plants are lost out in form of gases such nutrients include phosphorus, nitrogen and sulphur. It destroy soil organisms, soil texture and soil fertility and expose the soil to erosion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>41", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS", "question": "The use of a lighter instead of match sticks is a way of conserving", "images": [], "options": {"A": "petroleum", "B": "forest", "C": "water", "D": "wildlife"}, "answer": "B", "explanation": "Forest conservation is the practice of planting more trees and maintaining the forested areas for the sustainability for future generations. The conservation of forest also stands and aims at a quick shift in the composition of trees species and age distribution.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2022>42", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "An accident victim was successfully transfused with blood from the father whose blood, group is AB. The blood group of the accident victim is", "images": [], "options": {"A": "B", "B": "O", "C": "AB", "D": "A"}, "answer": "C", "explanation": "In blood transfusion, the recipient's blood group should be compatible with the donor's blood group. Blood group AB is a universal recipient, meaning a person with AB blood group can receive blood from any group (A, B, AB, or O). Therefore, if the accident victim was successfully transfused with blood from the father whose blood group is AB, the blood group of the accident victim could be AB.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>43", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "VARIATION IN POPULATION : PHYSIOLOGICAL VARIATIONS", "question": "Which of the following traits in humans is an example of physiological variation?", "images": [], "options": {"A": "Skin colour", "B": "Fingerprint", "C": "Tongue rolling", "D": "Height"}, "answer": "C", "explanation": "other options are morphological variation.  The ability of man to roll their tongue is characterized under physiological variation. Physiological variation relates to the differences in the ways individuals of the same species behave or react to conditions in their environment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2022>44", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "Individuals belonging to blood group 0 are universal donors because", "images": [], "options": {"A": "antigens are absent in their blood cells.", "B": "members of the group constitute the  highest number of humans.", "C": "there are no antibodies in their blood plasma.", "D": "the antigens in their blood cells are easily destroyed."}, "answer": "A", "explanation": "Blood group O does not have A or B antigens on the surface of their red blood cells, and therefore, their blood can be donated to individuals of any ABO blood group without causing an immune response.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>45", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "Two tall plants were crossed and all the F1 plants were tall. When the F1 plants were selfed, some of the F2 plants were tall while others were short. What are the possible genotypes of the original plants?", "images": [], "options": {"A": "Tt and tt", "B": "TT and TT", "C": "tt and tt", "D": "TT and Tt"}, "answer": "D", "explanation": "Mendel crossed pure tall plant(TT) with a pure dwarf plant(tt). In the F1 generation, tall plants are formed(Tt). When F1 plant is subjected to self pollination, in the F2 generation, 3 tall plants and 1 dwarf plants are formed. In the one homozygous tall plant(TT), 2 heterozygous tall plants(Tt), one homozygous dwarf plant(tt) are formed", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>46", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of the following statements best describes a test cross? It is", "images": [], "options": {"A": "to determine the genotype of an individual whose phenotype is known", "B": "to determine the phenotype of an individual whose genotype is known", "C": "between the progeny of parents to ascertain their external expressions", "D": "between two homozygous recessive individuals to confirm the genotypes of the offspring"}, "answer": "A", "explanation": "A test cross is a way to determine the genotype of an individual whose phenotype is known. This is done by crossing the individual with an organism that is homozygous recessive for the trait in question. If any of the offspring display the recessive phenotype, the individual must be heterozygous. If all offspring display the dominant phenotype, the individual is likely homozygous dominant.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>47", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : LINKAGE, SEX DETERMINATION AND SEX LINKED CHARACTERS", "question": "Which of the following statements about sex-linked traits is not correct?", "images": [], "options": {"A": "Males inherit sex-linked traits from their fathers", "B": "Sex-linked traits are more common in males", "C": "Females can be carriers because they can be heterozygous for the trait", "D": "Males are never carriers since they only receive one sex chromosome"}, "answer": "A", "explanation": "This statement is not correct. Males inherit their X chromosome (which carries the majority of sex-linked traits) from their mothers and their Y chromosome from their fathers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>48", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY", "question": "When two carriers of sickle cell anaemia produce an offspring, the probability of the offspring being a sickler is", "images": [], "options": {"A": "3/4", "B": "1/4", "C": "1/2", "D": "2/3"}, "answer": "B", "explanation": "Sickle cell anemia is a genetic disorder that is inherited in an autosomal recessive manner. This means that an individual must inherit two copies of the sickle cell gene (one from each parent) in order to have the disease. If both parents are carriers of the sickle cell gene (meaning they each have one copy of the gene), then there is a 1/4 chance with each pregnancy that the child will inherit two copies of the gene and have sickle cell anemia.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2022>49", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "EVOLUTION : ADAPTIVE COLOURATION", "question": "Which of the following organisms exhibits adaptive colouration?", "images": [], "options": {"A": "Rabbit", "B": "Chameleon", "C": "Mouse", "D": "Dog"}, "answer": "B", "explanation": "Adaptive coloration is a type of camouflage where an organism's coloration pattern helps it blend in with its environment to avoid detection by predators or prey. Chameleons are known for their ability to change their skin color to match their surroundings, which is a clear example of adaptive coloration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2022>50", "subject": "Biology", "year": "2022", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Which of the following sequences is the correct evolutionary trend in organisms?", "images": [], "options": {"A": "Algae---->Liverwort---->Ferns---->Angiosperms", "B": "Liverwort---->Angiosperm---->Ferns---->Algae", "C": "Angiosperms---->Algae---->Ferns---->Liverwort", "D": "Ferns---->Liverwort---->Angiosperms---->Algae"}, "answer": "A", "explanation": "The continous change of the characters within an evoving lineage is called evolutinary trend. A lineage is an evolutionary sequence. Arranged in linear order from an ancestral group to descendant group.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>1", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)", "question": "The ability of organisms to maintain a constant internal environment is known as", "images": [], "options": {"A": "diuresis", "B": "endosmosis", "C": "homeostasis", "D": "plasmolysis"}, "answer": "C", "explanation": "The ability of organisms to maintain a constant internal environment is known as \"homeostasis.\" Homeostasis is a fundamental biological concept that refers to the ability of living organisms to maintain a stable and relatively constant internal environment despite changes in the external environment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2023>2", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The diagram below is an illustration of a mango leaf drawn by a student in a Biology test. The student failed the test. Study it and answer the question.      The likely reason why the student failed the test was that the", "images": ["Biology/imgs/2023/leaf.png"], "options": {"A": "labels were wrong and the guidelines were not touching the structures", "B": "net venation shown were few, rough, not properly drawn and wrongly placed.", "C": "leaf was too tapered at the apex, the leaf stalk was too short and the shape of leaf was wrong.", "D": "leaf venation should have been parallel and the midrib should be thicker."}, "answer": "A", "explanation": "The likely reason why the student failed the test was that the labels were wrong and the guidelines were not touching the structures.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2023>3", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The diagram below is an illustration of a mango leaf drawn by a student in a Biology test. The student failed the test. Study it and answer the question.  Which other features of the diagram, if shown, would have earned the student more marks? The", "images": ["Biology/imgs/2023/leaf.png"], "options": {"A": "colour and size", "B": "title and magnification", "C": "habitat and agricultural qualities of leaf", "D": "spelling of label and length of midrib"}, "answer": "B", "explanation": "Importance of Title and Magnification in Biology Diagrams  Title:  Clarity: Indicates what the diagram represents.  Context: Places the diagram within the larger discussion.  Reference: Facilitates easy referencing in text.  Magnification:  Scale Understanding: Shows how much the object is enlarged.  Accuracy: Helps understand true sizes and relationships.  Comparison: Allows for accurate comparison between diagrams.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>4", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "The diagrams below are illustrations of forms in which a particular group of organisms exist. Study them and answer the question.       Which group of organisms is illustrated?", "images": ["Biology/imgs/2023/bacteria.png"], "options": {"A": "Bacteria", "B": "Viruses", "C": "Fungi", "D": "Protozoa"}, "answer": "A", "explanation": "Bacteria are single-celled microorganisms that exhibit a wide range of shapes. The three most common bacterial shapes are:  Coccus (plural: cocci): Cocci are spherical or round-shaped bacteria.   Bacillus (plural: bacilli): Bacilli are rod-shaped bacteria. They are elongated and cylindrical in appearance.   Spirillum (plural: spirilla) or Spirochete: These are spiral-shaped bacteria.   Vibrio: These are comma-shaped bacteria.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2023>5", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "The diagrams below are illustrations of forms in which a particular group of organisms exist. Study them and answer the question.   In which of the illustrated forms does the organism that causes cholera exist?", "images": ["Biology/imgs/2023/bacteria.png"], "options": {"A": "II", "B": "III", "C": "IV", "D": "V"}, "answer": "D", "explanation": "V.  Vibrio: These are comma-shaped bacteria. They are curved rods and often found in aquatic environments. Vibrio cholerae is an example, responsible for causing cholera.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>6", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "Study the list of organisms below and use them to answer the questions.  I-Hydra  II-Owl  III-Snake  IV-Snail    Arrangement of the organisms in order of increasing complexity is", "images": [], "options": {"A": "I-II-III-IV", "B": "II-III-I-IV", "C": "I-IV-III - II.", "D": "IV-III-II - I."}, "answer": "C", "explanation": "The arrangement of organisms in order of increasing complexity is Hydra (a simple multicellular organism), Snail (a more complex invertebrate), Snake (a simple vertebrate), and Owl (a more complex vertebrate). This is because as we move from invertebrates to vertebrates, the level of organization and complexity increases. The complexity of an organism can be determined by its level of organization, from cellular to tissue to organ to system level.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>7", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "Study the list of organisms below and use them to answer the questions.  I-Hydra  II-Owl  III-Snake  IV-Snail   The Phylum of the organism labelled IV is", "images": [], "options": {"A": "Coelenterata", "B": "Platyhelminthes", "C": "Mollusca", "D": "Arthropoda"}, "answer": "C", "explanation": "The organism labelled IV is a Snail. Snails belong to the Phylum Mollusca. This phylum is characterized by soft-bodied animals that usually have an external shell, like snails, clams, and squids.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2023>8", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The diagram below is an illustration of a cell in which photosynthesis takes place. Study it and answer the question.       In which of the labelled parts would molecules of water and carbon (IV) oxide combine to form sugar?", "images": ["Biology/imgs/2023/cyto.png"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "D", "explanation": "Molecules of water and carbon (IV) oxide will combine to form sugar in the part labelled IV.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2023>9", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The diagram below is an illustration of a cell in which photosynthesis takes place. Study it and answer the question.     The oxygen gas formed in the cell diffuses out of the cytoplasm into the air spaces through the part labelled", "images": ["Biology/imgs/2023/cyto.png"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "C", "explanation": "The oxygen gas formed in the cell diffuses out of the cytoplasm into the air spaces through the part labelled III", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2023>10", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT", "question": "An example of a process that involves osmosis is the", "images": [], "options": {"A": "movement of digested food from ileum into blood capillaries.", "B": "translocation of starch from leaves to all parts of a plant.", "C": "reabsorption of food nutrients from the kidney into blood capillaries", "D": "movement of water from root hairs into cortical cell."}, "answer": "D", "explanation": "Movement of water from root hairs into cortical cells involves osmosis. When a plant's roots absorb water from the soil, it passes through the root hairs and moves into the cortical cells (which are part of the root's inner layer) through osmosis. This osmotic movement of water helps maintain water balance and nutrient distribution within the plant.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>11", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "Growth in animals differs from that in plants because growth in", "images": [], "options": {"A": "plants is intercalary.", "B": "animals is apical.", "C": "plants is from within.", "D": "plants is indefinite"}, "answer": "D", "explanation": "Growth in plants is indefinite: Unlike animals, which typically have a determinate growth, many plants exhibit indeterminate growth, especially in their early stages of life. Indeterminate growth means that plants can continue to grow throughout their lives, adding new tissues and expanding in size as long as favorable conditions are present.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>12", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The diagram below is an illustration of a structure in the skeletal system of humans. Study it and answer the question      The illustrated structure is a part of the", "images": ["Biology/imgs/2023/skull.png"], "options": {"A": "cervical vertebrae.", "B": "axial skeleton.", "C": "axis vertebrae.", "D": "appendicular skeleton."}, "answer": "B", "explanation": "The skull is part of the axial skeleton. It is the bony structure that forms the head and encloses and protects the brain. The skull is located along the central axis of the body, and it is one of the key components of the axial skeleton.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>13", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The diagram below is an illustration of a structure in the skeletal system of humans. Study it and answer the question    An individual was involved in a car accident and the illustrated structure was badly injured. Which of the following structures would most likely be affected?", "images": ["Biology/imgs/2023/skull.png"], "options": {"A": "Lumbar, eye and teeth", "B": "Ear, brain and hinge joint", "C": "Eye, cerebellum and ear", "D": "Clavicle, tongue and pelvis"}, "answer": "C", "explanation": "Eye, cerebellum and ear would most likely be affected.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>14", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "The tricuspid valve is located between the", "images": [], "options": {"A": "left auricle and left ventricle.", "B": "right auricle and the superior vena cava.", "C": "aorta and the left ventricle.", "D": "right auricle and right ventricle."}, "answer": "D", "explanation": "The heart has four chambers: two atria (auricles) and two ventricles. The tricuspid valve is one of the heart's valves and is located between the right atrium (right auricle) and the right ventricle.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>15", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "The diagram below is an illustration of some structures used for gaseous exchange in humans. Study it and answer the question      The parts labelled 1, II, III and IV respectively are", "images": ["Biology/imgs/2023/resp.png"], "options": {"A": "larynx, bronchus, bronchiole and trachea.", "B": "bronchus, bronchiole, trachea and larynx", "C": "bronchiole, trachea, bronchus and  larynx", "D": "larynx, trachea, bronchiole and bronchus"}, "answer": "D", "explanation": "The parts labelled 1, II, III and IV respectively are larynx, trachea, bronchiole and bronchus  The larynx, commonly known as the voice box, is a cartilaginous structure located in the neck, just below the pharynx and above the trachea.  The trachea, also known as the windpipe, is a long tube made of C-shaped rings of cartilage that extend from the larynx to the bronchi.   Bronchioles are small, narrow tubes that branch out from the bronchi. They represent the smaller airways within the lungs.  The bronchi are the two main branches that arise from the lower end of the trachea, one leading to each lung.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>16", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "The diagram below is an illustration of some structures used for gaseous exchange in humans. Study it and answer the question    The part labelled III would be found in the", "images": ["Biology/imgs/2023/resp.png"], "options": {"A": "heart", "B": "lung", "C": "kidney", "D": "sternum"}, "answer": "B", "explanation": "Bronchioles are small, narrow tubes that are part of the respiratory system and are found within the lungs. After the air passes through the trachea and bronchi, it enters the bronchioles, which represent the smaller airways within the lungs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>17", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "Which of the following hormones is wrongly paired with its secretory organ?", "images": [], "options": {"A": "Insulin and pancreas", "B": "Oestrogen and ovary", "C": "Oxytocin and hypothalamus", "D": "Adrenalin and kidney"}, "answer": "D", "explanation": "Adrenalin, also known as epinephrine, is not secreted by the kidney. It is secreted by the adrenal glands, specifically the adrenal medulla. The adrenal glands are small, triangular glands located on top of both kidneys. Therefore, the option 'Adrenalin and kidney' is incorrect.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>18", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The eye defect caused by an uneven curvature of the cornea or lens or both is", "images": [], "options": {"A": "myopia", "B": "astigmatism", "C": "presbyopia", "D": "hypermetropia"}, "answer": "B", "explanation": "Astigmatism is a common refractive error of the eye that occurs when the cornea or lens has an irregular shape. In a normal eye, the cornea and lens have a smooth, evenly curved surface, similar to a sphere. However, in astigmatism, the cornea or lens may be more curved in one direction than the other, resulting in a refractive error.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>19", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The androecium in a flowering plant is a collection of", "images": [], "options": {"A": "ovules", "B": "stamens", "C": "filaments", "D": "sperms"}, "answer": "B", "explanation": "The androecium is the male reproductive part of a flowering plant, and it is composed of stamens. Each stamen consists of two main parts:  Filament  Anther", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>20", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "Placentation in fruits is referred to as the", "images": [], "options": {"A": "part of the ovary where the ovules originate and remain till maturity.", "B": "formation of a single carpel joined at the two edges of an ovule.", "C": "arrangement of ovules in the ovary of a flower.", "D": "ovules borne on a central column of tissues in an ovary."}, "answer": "C", "explanation": "Placentation in fruits refers to the arrangement of ovules within the ovary of a flower, and it is directly related to seed development and fruit formation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>21", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following processes does not occur during photosynthesis?", "images": [], "options": {"A": "Carbon (IV) oxide is evolved", "B": "Water is split", "C": "Oxygen is evolved", "D": "Energy from sunlight is absorbed"}, "answer": "A", "explanation": "During photosynthesis, carbon dioxide is taken in by the plant, and water is split to produce glucose and oxygen in the presence of sunlight and chlorophyll.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2023>22", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Stunted growth and small yellow leaves in plants are symptoms of the deficiencies of", "images": [], "options": {"A": "sulphur", "B": "iron", "C": "magnesium", "D": "nitrogen"}, "answer": "B", "explanation": "Iron deficiency in plants leads to chlorosis, which is the yellowing of leaves. Chlorosis occurs because iron is necessary for the formation of chlorophyll, which is the green pigment in plants that absorbs light energy for use in photosynthesis. Without sufficient iron, the plant cannot produce enough chlorophyll, leading to yellow leaves. Stunted growth is also a symptom of iron deficiency as iron is essential for various metabolic processes including DNA synthesis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>23", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONCEPT OF LIVING : RESPIRATORY SYSTEM", "question": "The structure that its action could result in choking when talking and eating at the same time is", "images": [], "options": {"A": "epiglottis", "B": "oesophagus", "C": "liver", "D": "stomach"}, "answer": "A", "explanation": "The structure that could result in choking when talking and eating at the same time is the epiglottis.  The epiglottis is a flap-like structure located at the base of the tongue, near the entrance of the windpipe (trachea). Its primary function is to prevent food and liquids from entering the trachea and lungs during swallowing. When you swallow, the epiglottis covers the opening of the trachea, directing food and liquids into the esophagus, which leads to the stomach. This prevents choking and aspiration of food into the respiratory system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>24", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "The food substance that would produce the highest amount of energy is", "images": [], "options": {"A": "glucose", "B": "fat", "C": "amino acid", "D": "protein"}, "answer": "B", "explanation": "The food substance that would produce the highest amount of energy is fat.  Fat is the most energy-dense macronutrient, providing 9 calories per gram. On the other hand, both carbohydrates (including glucose) and proteins provide 4 calories per gram. While amino acids are the building blocks of proteins, they are not a direct source of energy like fat and carbohydrates.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2023>25", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION", "question": "Organisms that feed on dead, decaying tissues of other organisms are known as", "images": [], "options": {"A": "parasites", "B": "autotrophs", "C": "heterotrophs", "D": "saprophytes"}, "answer": "D", "explanation": "Organisms that feed on dead, decaying tissues of other organisms are known as \"saprophytes.\" Saprophytes, also known as saprotrophs or decomposers, are organisms that obtain their nutrition by feeding on dead, decaying organic matter (detritus) from other organisms.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2023>26", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION", "question": "The type of nutrition in which organisms take solid organic materials into their body is", "images": [], "options": {"A": "holozoic", "B": "symbiotic", "C": "saprophytic", "D": "parasitic"}, "answer": "A", "explanation": "Holozoic nutrition is a type of nutrition in which organisms consume solid organic materials. This is the type of nutrition seen in most animals, where food is ingested and then broken down through digestion. This is different from symbiotic (where two organisms live together and benefit from each other), saprophytic (where organisms feed on dead and decaying matter), and parasitic (where one organism benefits at the expense of another) nutrition.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2023>27", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The mouthparts of a grasshopper are adapted for", "images": [], "options": {"A": "chewing", "B": "grinding", "C": "sucking", "D": "absorption"}, "answer": "A", "explanation": "Grasshoppers are herbivorous insects that primarily feed on plant material. Their mouthparts are well adapted for chewing, allowing them to consume various parts of plants, such as leaves, stems, and flowers.The mouthparts of a grasshopper consist of several structures that work together during feeding:  Mandibles, Maxillae and Labium and Labrum", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>28", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING", "question": "A group of organisms belonging to different species that coexist in the same habitat and interact is referred to as", "images": [], "options": {"A": "population", "B": "biosphere", "C": "niche", "D": "community"}, "answer": "D", "explanation": "A community in ecology refers to a group of different species that inhabit the same geographic area and interact with one another. These species share a common habitat and are interconnected through various ecological relationships. In a community, the interactions between different species can be complex and can include competition, predation, mutualism, commensalism, and parasitism.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>29", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : ADAPTATION OF ORGANISMS TO HABITATS.", "question": "Which of the following factors is the main problem facing xerophytes?", "images": [], "options": {"A": "Conservation of excess water", "B": "Competition for sunlight", "C": "Lack of adequate water", "D": "Poor formation of roots"}, "answer": "C", "explanation": "Xerophytes are plants that have adapted to survive and thrive in arid or dry environments, where water availability is limited. They have evolved various adaptations to cope with the scarcity of water. However, the primary challenge for xerophytes remains the lack of adequate water.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2023>30", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "Fishes survive in water mainly because they possess", "images": [], "options": {"A": "streamlined body.", "B": "scales", "C": "paired fins.", "D": "gills"}, "answer": "D", "explanation": "Gills are specialized respiratory organs found in fish that allow them to extract oxygen from water. While a streamlined body, scales, and paired fins are all essential adaptations for fish to navigate and survive in water, none of them directly relate to the process of oxygen extraction and respiration like gills do. However, without gills, fish would not be able to respire efficiently underwater and would not survive in their aquatic habitats.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2023>31", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS", "question": "Which of the following instruments is not used in measuring abiotic factors in a habitat?", "images": [], "options": {"A": "Thermometer", "B": "Microscope", "C": "Hygrometer", "D": "Wind vane"}, "answer": "B", "explanation": "Abiotic factors refer to the non-living components of an ecosystem or habitat that can influence the living organisms within it. Microscope: A microscope is not used to measure abiotic factors. Instead, it is an instrument used to observe and magnify tiny living or non-living things, such as cells, microorganisms, or small structures.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>32", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "Which of the following soil types have a high capillarity?", "images": [], "options": {"A": "Sand and clay", "B": "Silt and clay", "C": "Silt and sand", "D": "Loam and sand"}, "answer": "B", "explanation": "Both silt and clay particles have very small pores, which contribute to higher capillarity. When combined, the silt and clay would likely result in a soil with relatively high capillarity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>33", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION", "question": "The capturing and digestion of insects by a pitcher plant is a special form of nutrition that is", "images": [], "options": {"A": "chemosynthetic", "B": "saprophytic", "C": "heterotrophic", "D": "autotrophic"}, "answer": "C", "explanation": "Heterotrophic nutrition is a type of nutrition in which an organism obtains its food by consuming organic matter from other organisms. In the case of pitcher plants, they capture and digest insects as a source of nutrients to supplement their diet, especially in nutrient-poor environments. This carnivorous adaptation is a specialized form of heterotrophic nutrition, as the pitcher plant relies on consuming other living organisms (insects) to meet its nutritional needs. The pitcher plant is a carnivorous plant that has modified leaves forming pitcher-like structures.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>34", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Which of the following organisms would be the producer in a food chain?", "images": [], "options": {"A": "Goat", "B": "Maize", "C": "Man", "D": "Bacterium"}, "answer": "B", "explanation": "The producer in a food chain is the organism that produces its food directly from non-living sources (abiotic factors) through processes like photosynthesis or chemosynthesis. Among the options provided, the producer is \"Maize.\" As a plant, maize is the producer in a food chain, serving as the primary source of energy for other organisms.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2023>35", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM", "question": "The rate of decomposition of dead organisms is faster in the tropical rainforest than in other biomes because", "images": [], "options": {"A": "of consistent cool temperature.", "B": "of the relatively constant day light.", "C": "there are more plants", "D": "of availability of moisture"}, "answer": "D", "explanation": "Decomposition is the process by which dead organic matter, such as dead plants and animals, is broken down and recycled back into the ecosystem as nutrients. The rate of decomposition is influenced by various factors, and in the tropical rainforest biome, the availability of moisture is a critical factor that accelerates decomposition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>36", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS", "question": "The diagrams below are illustrations of organisms in a habitat. Study them and answer the question       The feeding relationship between the organisms labelled III and IV in the diagrams is", "images": ["Biology/imgs/2023/bird.png"], "options": {"A": "mutualism", "B": "parasitism", "C": "predation", "D": "saprophytism"}, "answer": "C", "explanation": "Predation in biology refers to the act of one organism (the predator) capturing, killing, and consuming another organism (the prey) for nourishment.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2023>37", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "The diagrams below are illustrations of organisms in a habitat. Study them and answer the question     The producer in the diagrams is", "images": ["Biology/imgs/2023/bird.png"], "options": {"A": "I because it contains the least amount of energy.", "B": "I because it uses sunlight to manufacture food", "C": "IV because it is the largest organism in the diagram.", "D": "IV because it is the organism that receives the highest amount of sunlight."}, "answer": "B", "explanation": "The producer in the diagrams is I because it uses sunlight to manufacture food.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2023>38", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Which of the following activities is against the conservation of natural resources?", "images": [], "options": {"A": "Afforestation", "B": "Deforestation", "C": "Establishment of game reserves", "D": "Contour ploughing"}, "answer": "B", "explanation": "Deforestation: Deforestation is the opposite of afforestation. It involves the clearing or removal of forests or trees from an area. Deforestation leads to the loss of valuable natural resources like timber, biodiversity, soil fertility, and water regulation. It disrupts ecosystems, accelerates soil erosion, and releases stored carbon dioxide, contributing to climate change. Deforestation is detrimental to the conservation of natural resources and has serious environmental consequences.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>39", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Use the information below to answer the question   I - making shoes from crocodile skin  II - making tables with plastic  III - using elephant tusk for decoration  IV - using firewood for cooking    The act that should be encouraged for the conservation of wildlife and forests is", "images": [], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "B", "explanation": "II - making tables with plastic: Encouraging the use of plastic for making tables is beneficial for wildlife and forests. By using plastic instead of wood for furniture, we reduce the demand for wood, which can help curb deforestation and preserve forest ecosystems. Reducing deforestation is vital for the conservation of wildlife, as forests provide critical habitat for numerous species.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>40", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Use the information below to answer the question   I - making shoes from crocodile skin  II - making tables with plastic  III - using elephant tusk for decoration  IV - using firewood for cooking  In order to avoid some of the acts that would have negative effects on conservation. Government should", "images": [], "options": {"A": "enact and enforce laws towards conservation of resources", "B": "promote felling of trees without planting new ones.", "C": "encourage indiscriminate killing of wildlife.", "D": "encourage over-utilization of forest resources."}, "answer": "A", "explanation": "In order to avoid some of the acts that would have negative effects on conservation. Government should enact and enforce laws towards conservation of resources", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>41", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Which of the following characteristics shows discontinuous variation in plants?", "images": [], "options": {"A": "Colour of flower", "B": "Height of plant", "C": "Leaf size", "D": "Fruit size"}, "answer": "A", "explanation": "Colour of flower: The colour of flowers in plants typically shows discontinuous variation. Flowers can have specific colors like red, blue, yellow, or white, and individuals within a population will usually exhibit one of these distinct flower colors. There are no intermediate or blending colors between the different categories.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>42", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "A Rhesus negative woman may experience stillbirth of the second child that is Rhesus positive because", "images": [], "options": {"A": "the woman is susceptible to diseases during pregnancy", "B": "the blood of the foetus might clump.", "C": "they have poor circulatory system", "D": "the foetus is deprived of nourishment."}, "answer": "B", "explanation": "The stillbirth of a second child that is Rh-positive in an Rh-negative woman can occur due to the clumping of fetal blood caused by the production of Rh antibodies in the mother's immune system during a previous pregnancy with an Rh-positive baby. This condition, known as hemolytic disease of the newborn, can be prevented with appropriate medical interventions like Rh immunoglobulin injections.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>43", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "A sudden change in the genetic composition of an organism is termed", "images": [], "options": {"A": "epistasis", "B": "linkage", "C": "mutation", "D": "variation"}, "answer": "C", "explanation": "Mutation is the process by which there is a permanent alteration in the DNA sequence of an organism's genome. These changes can occur due to various factors such as exposure to radiation, chemicals, or errors during DNA replication. Mutations can happen in somatic cells, which affect only the individual, or in germ cells (egg or sperm cells), which can be passed on to offspring.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>44", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY", "question": "Paternity disputes could be resolved accurately through", "images": [], "options": {"A": "finger printing", "B": "blood group", "C": "DNA test", "D": "tongue rolling"}, "answer": "C", "explanation": "Paternity testing, also known as DNA testing for paternity, is a reliable and accurate method used to determine the biological father of a child. It is based on the analysis of DNA (deoxyribonucleic acid), which is the genetic material found in cells. Every individual inherits their DNA from their biological parents, half from the mother and half from the father.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>45", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "The illustration below is a genetic diagram. Study it and answer the question  EEEIIIeIIIIV    What is the name of the genetic diagram?", "images": [], "options": {"A": "Genetic cross", "B": "Punnett square", "C": "Inheritance diagram", "D": "Genetic square"}, "answer": "B", "explanation": "A Punnett square is a graphical representation used in genetics to predict the possible genotypes of offspring in a cross between two individuals. It is named after Reginald Punnett, a British geneticist who developed the method. In a Punnett square, the genotypes of the parents are represented on the top and left sides of the square. The possible combinations of alleles from each parent are then filled in the cells of the square to show the potential genotypes of their offspring.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2023>46", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "The illustration below is a genetic diagram. Study it and answer the question  EEEIIIeIIIIVWhat do the labels I, II, III and IV respectively represent?", "images": [], "options": {"A": "EE, EE, EE and EE", "B": "Ee, Ee, EE and E", "C": "EE, EE, Ee and Ee", "D": "EE, EE, Ee and ee"}, "answer": "C", "explanation": "The labels I, II, III and IV represent the genotypes of the offspring from a cross between two heterozygous parents (Ee). I and II represent the homozygous dominant (EE) and heterozygous (Ee) offspring, respectively, while III and IV represent the heterozygous (Ee) and homozygous recessive (ee) offspring, respectively.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2023>47", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "The illustration below is a genetic diagram. Study it and answer the question  EEEIIIeIIIIVThe genotypic ratio of the offspring in the genetic diagram is", "images": [], "options": {"A": "1:1.", "B": "1:2:1.", "C": "1:3", "D": "4:0."}, "answer": "A", "explanation": "The genotypic ratio is the ratio of the number of individuals with different genotypes. In this case, the genotypic ratio is 1:1", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2023>48", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : SEX DETERMINATION AND SEX LINKED CHARACTERS", "question": "What is the probability that a pregnancy would result in a male child?", "images": [], "options": {"A": "1", "B": "3/4", "C": "1/2", "D": "1/4"}, "answer": "C", "explanation": "In humans, the sex of a child is determined by the combination of sex chromosomes received from the parents. The mother contributes an X chromosome, and the father contributes either an X chromosome (resulting in a female child) or a Y chromosome (resulting in a male child).    Since the father can contribute either an X or a Y chromosome, there are two possible outcomes for the sex of the child: male (XY) or female (XX). The chance of having a male child (XY) is equal to the chance of having a female child (XX).  Therefore, the probability of having a male child is 1 out of 2, which is represented as 1/2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>49", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "EVOLUTION : ADAPTATION FOR SURVIVAL", "question": "A vestigial structure in humans is", "images": [], "options": {"A": "gall bladder", "B": "villus", "C": "earlobe", "D": "tail bone."}, "answer": "D", "explanation": "A vestigial structure in humans is the tailbone, also known as the coccyx.  Vestigial structures are anatomical features that have lost their original function over the course of evolution. These structures were once functional and served a purpose in the ancestors of the species but have become reduced or non-functional in the present-day descendants. The tailbone, or coccyx, is a small triangular bone located at the base of the vertebral column in humans. It is a vestige of the tail that was present in the early ancestors of mammals, which had tails for various functions, such as balance, communication, or grasping.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2023>50", "subject": "Biology", "year": "2023", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The following activities are associated with termites except", "images": [], "options": {"A": "nuptial flight.", "B": "communication", "C": "pollination", "D": "searching for food."}, "answer": "C", "explanation": "Pollination is not an activity associated with termites. Pollination is primarily carried out by various animals, such as bees, butterflies, birds, and bats, which transfer pollen from one flower to another, leading to fertilization and seed production. While some insects, like bees, are important pollinators, termites are not known for their role in pollination.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2024>1", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following organisms contains chlorophyll in its cells?", "images": [], "options": {"A": "Caterpillar", "B": "Paramecium", "C": "Euglena", "D": "Grasshopper"}, "answer": "C", "explanation": "Euglena is a type of protist that contains chlorophyll and can perform photosynthesis, allowing it to produce its own food using light energy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2024>2", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "Species are groups of organisms that", "images": [], "options": {"A": "are of different origins and are always found together", "B": "are of common origin but cannot interbreed freely", "C": "have similar features and can interbreed freely", "D": "resemble each other and occupy different niches"}, "answer": "C", "explanation": "A species is defined as a group of organisms that share common characteristics and can interbreed under natural conditions to produce fertile offspring. Members of the same species generally have similar features and genetic makeup.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>3", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "A plant with short, vertical underground stem is a", "images": [], "options": {"A": "bulb", "B": "corm", "C": "rhizome", "D": "tuber"}, "answer": "B", "explanation": "Corm: A corm is a short, vertical underground stem that stores nutrients. It is a swollen, solid, underground stem that grows vertically and is found in plants like crocuses and taro.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2024>4", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The diagram below is an illustration of a reproductive process in an organism. Study it and answer the question      The type of reproduction illustrated is", "images": ["Biology/imgs/2024/FXX7YP.png"], "options": {"A": "budding", "B": "binary fission", "C": "grafting", "D": "vegetative propagation"}, "answer": "B", "explanation": "Binary fission is a process of asexual reproduction in unicellular organisms in which a single cell(parent) divides into two equal parts by mitosis to produce two new daughter cells.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>5", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The diagram below is an illustration of a reproductive process in an organism. Study it and answer the question    The illustrated organism is capable of reproducing by", "images": ["Biology/imgs/2024/FXX7YP.png"], "options": {"A": "sexual means only", "B": "asexual means only", "C": "vegetative propagation only", "D": "sexual and asexual means"}, "answer": "D", "explanation": "The organism in the diagram is paramecium. Paramecium reproduces in two ways: These are asexual reproduction (binary fission) and sexual reproduction (conjugation)", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>6", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST", "question": "Which of the following organisms consists of unicellular cells joined to form a filament?", "images": [], "options": {"A": "Amoeba", "B": "Spirogyra", "C": "Euglena", "D": "Clamydomonas"}, "answer": "B", "explanation": "Spirogyra is a filamentous green algae consisting of long chains of unicellular cells. Each cell in the filament has chloroplasts arranged in a spiral pattern, which gives the algae its name.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2024>7", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The structure in the cell that controls the movement of substances in and out of the cell is the", "images": [], "options": {"A": "cytoplasmic membrane", "B": "nuclear membrane", "C": "protoplasm", "D": "endoplasm"}, "answer": "A", "explanation": "Cytoplasmic membrane (or plasma membrane): This is a selective barrier that regulates the movement of substances into and out of the cell. It maintains the cell's internal environment by controlling the flow of ions, nutrients, and waste products.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>8", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL AND ITS ENVIRONMENT", "question": "The bursting of a red blood cell placed in a hypotonic solution is called", "images": [], "options": {"A": "crenation", "B": "haemolysis", "C": "plasmolysis", "D": "cytolysis"}, "answer": "B", "explanation": "Haemolysis refers to the rupture or destruction of red blood cells, often occurring when they are placed in a hypotonic solution where water enters the cells, causing them to swell and burst.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>9", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL AND ITS ENVIRONMENT", "question": "The function of the root hair in plants is to", "images": [], "options": {"A": "absorb soil water by the process of osmosis", "B": "excrete water and mineral salts by simple diffusion", "C": "purify the soil for the plant", "D": "translocate manufactured food"}, "answer": "A", "explanation": "Absorb soil water by the process of osmosis: Root hairs increase the surface area for water and nutrient absorption from the soil. They help in the uptake of water through osmosis and minerals through active transport.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2024>10", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "CONCEPT OF LIVING : IRRITABILITY AS A BASIC CHARACTERISTIC OF PROTOPLASM", "question": "If a germinating seed is attached horizontally to a revolving klinostat, what would be the effect on the seedling after three days? The", "images": [], "options": {"A": "plumule will curve vertically upward while the radicle will not show any curvature", "B": "radicle will curve towards the ground while the plumule will not show any curvature", "C": "plumule and radicle will not show any curvature", "D": "plumule will curve vertically. upwards while the radicle will curve towards the ground"}, "answer": "C", "explanation": "A klinostat is a device that rotates the seedling to counteract the effects of gravity. This rotation ensures that the seedling experiences an even distribution of gravitational forces. As a result, both the plumule (the part of the seedling that develops into the shoot) and the radicle (the part that develops into the root) will grow straight without showing the typical curvatures that occur in response to gravity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>11", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "The lumbar vertebra differs from the thoracic vertebra because it possesses a", "images": [], "options": {"A": "longer neural spine", "B": "wider neural canal", "C": "thicker centrum", "D": "shorter transverse process"}, "answer": "C", "explanation": "Thicker centrum: Lumbar vertebrae have a thicker and more robust centrum (the body of the vertebra) compared to thoracic vertebrae. This is because the lumbar region supports more weight from the upper body and needs a stronger base.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>12", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "CONCEPT OF LIVING : TRANSPORT SYSTEM", "question": "Which of the following blood vessels carries oxygenated blood into the heart?", "images": [], "options": {"A": "Pulmonary artery", "B": "Anterior vena cava", "C": "Pulmonary vein", "D": "Posterior vena cava"}, "answer": "C", "explanation": "The pulmonary vein carries oxygenated blood from the lungs to the left atrium of the heart.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2024>13", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "Filtrates in the Bowman's capsule contain vitamins because", "images": [], "options": {"A": "they have low molecular weight", "B": "most of them are fat soluble", "C": "they cannot be reabsorbed into the blood", "D": "little amount is required by the blood"}, "answer": "A", "explanation": "Many vitamins, especially water-soluble ones like the B-complex vitamins and vitamin C, have relatively low molecular weights. This allows them to pass through the filtration barrier into the Bowman's capsule.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>14", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "The structures that contain grey matter and white matter are found in the", "images": [], "options": {"A": "reproductive system", "B": "nervous system", "C": "respiratory system", "D": "digestive system"}, "answer": "B", "explanation": "Grey Matter and White Matter:    Grey Matter: This consists primarily of neuronal cell bodies, dendrites, and unmyelinated axons. It is involved in processing and interpreting information in the brain and spinal cord.  White Matter: This consists mainly of myelinated axons, which form the communication pathways between different parts of the grey matter and between the grey matter and other parts of the nervous system.  Locations in the Nervous System:    In the brain, grey matter is found in regions such as the cerebral cortex and the basal ganglia, while white matter is found in the deeper tissues of the brain, underlying the grey matter.  In the spinal cord, grey matter is located in the central part (forming an H-shaped structure), while white matter surrounds it on the outside.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2024>15", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The diagram below is an illustration of a sense organ in humans. Study it and answer the question.      The part that protects the organ is labelled", "images": ["Biology/imgs/2024/G7WH67.png"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "B", "explanation": "II. The parts that protect the eye are the upper and lower eyelids. These structures help to shield the eye from debris, excessive light, and injury, as well as to keep it moist.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>16", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "The diagram below is an illustration of a sense organ in humans. Study it and answer the question.    The part labelled III is the", "images": ["Biology/imgs/2024/G7WH67.png"], "options": {"A": "iris", "B": "pupil", "C": "sclera", "D": "cornea"}, "answer": "B", "explanation": "Pupil: The black circular opening in the center of the iris that allows light to enter the eye.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>17", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The diagram below is an illustration of two plants P and Q. Arrows I, II and III illustrate the transfer of pollen grains among flowers of plants P and Q. Study it and answer the question      The types of pollination illustrated as I, II and III,respectively are", "images": ["Biology/imgs/2024/2NDMJG.png"], "options": {"A": "cross,self and cross", "B": "self,self and cross", "C": "self,cross and self", "D": "self,cross and cross"}, "answer": "D", "explanation": "Arrow I represents self-pollination within plant P.  Arrow II represents cross-pollination from plant P to plant Q.  Arrow III represents cross-pollination from plant Q to plant P.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>18", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The diagram below is an illustration of two plants P and Q. Arrows I, II and III illustrate the transfer of pollen grains among flowers of plants P and Q. Study it and answer the question    The condition necessary for reproduction to occur between plants P and Q after pollination is that plants P and Q should be", "images": ["Biology/imgs/2024/2NDMJG.png"], "options": {"A": "of the same species", "B": "brightly coloured", "C": "well scented", "D": "of different species"}, "answer": "A", "explanation": "The condition necessary for reproduction to occur between plants P and Q after pollination is that plants P and Q should be of the same species.  Of the same species: For successful reproduction and fertilization to occur, the pollen from one plant must be compatible with the ovules of the other plant. This compatibility is ensured if both plants are of the same species. The genetic material must match for fertilization to lead to viable seeds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>19", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The diagram below illustrates a dry dehiscent fruit. Use it to answer the question      The agent of dispersal of the fruit is", "images": ["Biology/imgs/2024/76YJ2A.png"], "options": {"A": "animal", "B": "explosive mechanism", "C": "water", "D": "wind"}, "answer": "D", "explanation": "Tridax, commonly known as Tridax daisy (Tridax procumbens), has seeds that are adapted for wind dispersal. The seeds are typically lightweight and equipped with structures like pappi (hair-like appendages) that allow them to be carried by the wind.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2024>20", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "CONCEPT OF LIVING : REPRODUCTION", "question": "The diagram below illustrates a dry dehiscent fruit. Use it to answer the question    The parachute-like tuft of hairs developed from the", "images": ["Biology/imgs/2024/76YJ2A.png"], "options": {"A": "pedicel", "B": "petals", "C": "receptacle", "D": "sepals"}, "answer": "D", "explanation": "The parachute-like tuft of hairs found on some seeds, such as those of Tridax and other members of the Asteraceae family, is typically developed from the sepals.    In these plants, the sepals transform into a structure known as a pappus, which is a modified calyx that aids in wind dispersal. The pappus consists of fine hairs that create a parachute-like structure, enabling the seeds to be carried away by the wind.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2024>21", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "Which of the following events does not occur in the light reaction stage of photosynthesis?", "images": [], "options": {"A": "Chlorophyll absorbs sunlight", "B": "Carbon (IV) oxide combines with hydrogen", "C": "Photolysis of water occurs", "D": "Hydroxyl ions are produced"}, "answer": "B", "explanation": "The light reaction stage of photosynthesis, also known as the light-dependent reactions, primarily involves the absorption of light by chlorophyll, the photolysis (splitting) of water, and the production of energy-rich molecules (ATP and NADPH). This event occurs during the Calvin cycle, also known as the light-independent reactions or the dark reactions. In the Calvin cycle, carbon dioxide is fixed into organic molecules using the ATP and NADPH produced during the light reactions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>22", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The rate of photosynthesis decreases in a wilted herbaceous plant because the", "images": [], "options": {"A": "enzymes in the leaf were denatured", "B": "chlorophyll in the leaves was not broken down", "C": "amount of light reaching the plant was reduced", "D": "amount of carbon dioxide entering the leaf decreased"}, "answer": "D", "explanation": "The rate of photosynthesis can decrease in a wilted herbaceous plant due to several factors, but the most relevant one is related to the availability of carbon dioxide. In a wilted plant, the stomata (pores on the leaf surface) often close to prevent further water loss. When the stomata close, the exchange of gases is restricted, reducing the amount of carbon dioxide that can enter the leaf.    Since carbon dioxide is a crucial reactant in the photosynthesis process, a decrease in its availability directly impacts the rate of photosynthesis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>23", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : PLANT NUTRITION", "question": "The element required for chlorophyll formation in plants is", "images": [], "options": {"A": "iron", "B": "calcium", "C": "phosphorus", "D": "sulphur"}, "answer": "A", "explanation": "The element required for chlorophyll formation in plants is iron. Iron is a crucial component of the enzyme systems involved in the synthesis of chlorophyll. It acts as a catalyst in the formation of chlorophyll and plays a vital role in the overall process of photosynthesis.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2024>24", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ALIMENTARY SYSTEM", "question": "The process of food digestion in mammals would", "images": [], "options": {"A": "make energy immediately available to the body", "B": "promote growth and repair of tissues", "C": "provide sufficient food materials within the body", "D": "render food substances soluble and absorbable"}, "answer": "D", "explanation": "The primary function of food digestion in mammals is to break down complex food substances into simpler, soluble forms that can be absorbed into the bloodstream and utilized by the body. This process involves mechanical and chemical breakdown of food in the digestive system, leading to the formation of nutrients that can be absorbed through the walls of the intestines.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>25", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION", "question": "Which of the following food substances would give a negative reaction with Benedict's reagent?", "images": [], "options": {"A": "Fructose", "B": "Glucose", "C": "Galactose", "D": "Sucrose"}, "answer": "D", "explanation": "Benedict's reagent is used to test for the presence of reducing sugars. Reducing sugars, such as fructose, glucose, and galactose, have free aldehyde or ketone groups that can reduce the copper(II) ions in Benedict's reagent to copper(I) oxide, resulting in a colour change.    Sucrose, however, is a non-reducing sugar. It is composed of glucose and fructose linked by a glycosidic bond, which prevents the free aldehyde or ketone group from reacting with Benedict's reagent. Therefore, sucrose would give a negative reaction with Benedict's reagent, meaning there would be no color change when sucrose is present.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2024>26", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "Sunlight is the major source of", "images": [], "options": {"A": "vitamin D", "B": "vitamin C", "C": "vitamin B", "D": "vitamin A"}, "answer": "A", "explanation": "Sunlight is the major source of vitamin D because exposure to ultraviolet (UV) rays from the sun triggers the synthesis of vitamin D in the skin. Specifically, UVB radiation converts 7-dehydrocholesterol in the skin to previtamin D3, which is then converted to vitamin D3 (cholecalciferol). This process is the primary natural method for humans to obtain vitamin D, which is essential for maintaining healthy bones and supporting the immune system.    Vitamins C, B, and A are obtained from dietary sources rather than being synthesized through exposure to sunlight.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>27", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "Discouraging the use of poison to kill fish in a large water body is a way of", "images": [], "options": {"A": "impoverishing the people", "B": "conserving the fish species", "C": "allowing the fittest organism to survive", "D": "making the fish adapt to their environment"}, "answer": "B", "explanation": "Discouraging the use of poison to kill fish in a large water body is a conservation measure aimed at protecting fish species. Using poison can have detrimental effects on the aquatic ecosystem, including killing a wide range of organisms indiscriminately, disrupting the food chain, and contaminating the water. By preventing the use of poison, the natural populations of fish and other aquatic organisms can be preserved, ensuring the sustainability and health of the ecosystem.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>28", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : NITROGEN CYCLE", "question": "The pathway through which nutrients are replenished and circulated in an ecosystem is called a", "images": [], "options": {"A": "cycle", "B": "pyramid of energy", "C": "pyramid of numbers", "D": "food chain"}, "answer": "A", "explanation": "The pathway through which nutrients are replenished and circulated in an ecosystem is referred to as a cycle. This includes processes like the water cycle, carbon cycle, nitrogen cycle, and phosphorus cycle. These cycles ensure that essential nutrients are continuously recycled and made available to living organisms within the ecosystem.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>29", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "The illustration below is a food chain. Study it and answer the question.  Grasses →Grasshoppers→Lizards→Hawks    Which of the following statements is not correct about the food chain? The number of", "images": [], "options": {"A": "grasses eaten by grasshoppers is greater than the number of grasshoppers", "B": "grasses eaten by grasshoppers is fewer than the number of grasshoppers", "C": "grasshoppers eaten by lizards is greater than the number of lizards", "D": "lizards eaten by hawks is greater than the number of hawks"}, "answer": "B", "explanation": "In a food chain, the number of organisms and the amount of biomass generally decrease as you move up trophic levels. This means that:    There are more grasses than grasshoppers because grasshoppers feed on grasses.  There are more grasshoppers than lizards because lizards feed on grasshoppers.  There are more lizards than hawks because hawks feed on lizards.  Therefore, the statement \"grasses eaten by grasshoppers is fewer than the number of grasshoppers\" is incorrect because there must be more grass (in terms of biomass and number) than grasshoppers to support their population.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>30", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "The illustration below is a food chain. Study it and answer the question.  Grasses →Grasshoppers→Lizards→Hawks  If the individual species of organisms in the food chain are counted and arranged as a pyramid, the result would be a pyramid of", "images": [], "options": {"A": "numbers", "B": "energy", "C": "biomass", "D": "biomes"}, "answer": "A", "explanation": "A pyramid of numbers represents the number of individual organisms at each trophic level in a food chain. In the given food chain (Grasses → Grasshoppers → Lizards → Hawks), if you count the individuals and arrange them in a pyramid, you will have:    A large number of grasses at the base.  Fewer grasshoppers feeding on the grasses.  Even fewer lizards feeding on the grasshoppers.  The fewest hawks at the top feeding on the lizards.  This arrangement, based on the number of organisms at each trophic level, forms a pyramid of numbers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>31", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS", "question": "Which of the following gases is released during the decomposition of organic matter?", "images": [], "options": {"A": "Carbon (II) oxide", "B": "Sulphur (IV) oxide", "C": "Hydrogen sulphide", "D": "Nitrous oxide"}, "answer": "C", "explanation": "During the decomposition of organic matter, especially under anaerobic conditions (in the absence of oxygen), various gases are released as by-products. One of these gases is hydrogen sulphide (H₂S), which is produced by the action of bacteria breaking down proteins and other sulfur-containing compounds in the organic matter.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2024>32", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The diagrams below are illustrations of organisms from different habitats. Study them and answer the question      The structures labelled I are for", "images": ["Biology/imgs/2024/W2F3BR.png"], "options": {"A": "camouflage", "B": "chemical offence", "C": "physical defence", "D": "mimicry"}, "answer": "C", "explanation": "The structures labelled \"I\" in the illustration are spines or thorns on the plant. These structures serve as a form of physical defence to protect the plant from being eaten by herbivores. The spines can deter animals from approaching or consuming the plant by causing physical discomfort or injury.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>33", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "The diagrams below are illustrations of organisms from different habitats. Study them and answer the question    Habitats of the organisms respectively, are", "images": ["Biology/imgs/2024/W2F3BR.png"], "options": {"A": "river and stream", "B": "rainforest and stream", "C": "pond and leaf litter", "D": "garden and desert"}, "answer": "D", "explanation": "The organism on the left is a snail, which is commonly found in gardens where it feeds on plants.  The organism on the right appears to be a cactus, which is typically found in desert environments. Cacti have spines as an adaptation to reduce water loss and protect against herbivores.  Thus, the respective habitats of the organisms illustrated are likely a garden for the snail and a desert for the cactus.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2024>34", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT", "question": "An environmental problem caused by Sulphur (IV) oxide is", "images": [], "options": {"A": "acid rain", "B": "deforestation", "C": "global warming", "D": "erosion"}, "answer": "A", "explanation": "Sulphur (IV) oxide is a significant contributor to the formation of acid rain. When SO₂ is released into the atmosphere, it reacts with water vapor and other chemicals to form sulphuric acid (H₂SO₄). This sulfuric acid can then fall to the earth as acid rain, which can harm ecosystems, damage buildings, and negatively affect plant and animal life.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>35", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT", "question": "The phenomenon by which a farmland that is left to fallow for several years develops into a forest is called", "images": [], "options": {"A": "succession", "B": "afforestation", "C": "population", "D": "colonization"}, "answer": "A", "explanation": "Succession is the process by which the structure of a biological community evolves over time. There are two main types of succession:    Primary succession occurs in lifeless areas where there is no soil, such as on a lava flow or a new sand dune.  Secondary succession occurs in areas where a disturbance (such as farming) has occurred, but soil and some organisms still exist.  When farmland is abandoned and left to fallow, secondary succession typically takes place. Over time, grasses and weeds first colonize the land, followed by shrubs and eventually trees, leading to the development of a forest.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>36", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT", "question": "A farmer planted many seeds on a small piece of land. The plants that germinated are as shown below.    Which of the following effects would not be observed among the population of the plants?", "images": ["Biology/imgs/2024/JACWWR.png"], "options": {"A": "Rise in disease condition", "B": "Death", "C": "Mutualistic relationship", "D": "Competition"}, "answer": "D", "explanation": "Competition in plants refers to the interaction between plants where they vie for the same resources such as light, water, nutrients, and space. This competition can influence plant growth, survival, and reproduction, and it occurs both within a single species (intraspecific competition) and between different species (interspecific competition).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>37", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "The bar chart below shows the data of sources of energy used for cooking in a community. Study it and answer the question      The source of energy that is mostly used in the community is", "images": ["Biology/imgs/2024/3M3ECY.png"], "options": {"A": "solar", "B": "kerosene", "C": "coal", "D": "wind"}, "answer": "B", "explanation": "The source of energy that is mostly used in the community is kerosene. The bar chart shows six(6) number of households using kerosene which is the highest.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>38", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT", "question": "The bar chart below shows the data of sources of energy used for cooking in a community. Study it and answer the question    The two sources of energy that would mostly lead to pollution in the community are", "images": ["Biology/imgs/2024/3M3ECY.png"], "options": {"A": "solar and kerosene", "B": "coal and wind", "C": "kerosene and coal", "D": "solar and wind"}, "answer": "C", "explanation": "The two sources of energy that would mostly lead to pollution in the community are kerosene and coal. Kerosene is a liquid fossil fuel and Coal is a solid fossil fuel. Both kerosene and coal are significant sources of pollution, impacting air quality, human health, and the environment. Transitioning to cleaner energy sources, such as solar, wind, and hydroelectric power, can help reduce these negative impacts and promote a healthier and more sustainable community.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2024>39", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "An individual found a strange bird that is tagged as an endangered specie. What should the individual do?", "images": [], "options": {"A": "Kill it", "B": "Take it to an aquatic environment", "C": "Return it to its natural habitat", "D": "Sell it at a very high price"}, "answer": "C", "explanation": "Endangered species are protected by laws and regulations due to their risk of extinction. Returning the bird to its natural habitat ensures that it remains in the environment it is adapted to, which supports its survival and the overall ecosystem's health. If the exact location of its natural habitat is unknown, contacting local wildlife authorities or conservation organizations for guidance is advisable.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>40", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "Which of the following traits is not inheritable? Ability to", "images": [], "options": {"A": "taste P.T.C", "B": "roll the tongue", "C": "move the ear", "D": "roll the eyeball"}, "answer": "D", "explanation": "Rolling the eyeball is not considered an inheritable trait. It is more related to voluntary muscle control and eye movement skills, which are learned rather than inherited.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>41", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "APPLICATION OF VARIATIONS :", "question": "Which of the following statements is correct about the ABO blood group system?", "images": [], "options": {"A": "Antigens are located on the surface of white blood cells", "B": "Antibodies are located in the blood plasma", "C": "Antibodies are located on the surface of red blood cells", "D": "Antigens are located in the blood plasma"}, "answer": "B", "explanation": "In the ABO blood group system:    Antigens are located on the surface of red blood cells. These antigens determine the blood type (A, B, AB, or O).  Antibodies are located in the blood plasma. These antibodies are specific to the antigens that are not present on the individual's red blood cells.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>42", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "APPLICATION OF VARIATIONS :", "question": "A woman with blood group A gives birth to a child with blood group O. Which of the following blood groups cannot belong to the father?", "images": [], "options": {"A": "B", "B": "A", "C": "AB", "D": "O"}, "answer": "C", "explanation": "Blood group A can have the genotype AA or AO.  Blood group B can have the genotype BB or BO.  Blood group AB has the genotype AB.  Blood group O has the genotype OO.  For a child to have blood group O, they must inherit an O allele from each parent, resulting in the genotype OO. This means both parents must carry at least one O allele.  B – The father could be BO, contributing an O allele to the child.  A – The father could be AO, contributing an O allele to the child.  AB – The father has the genotype AB and cannot contribute an O allele.  O – The father has the genotype OO, contributing an O allele to the child.  The blood group that cannot belong to the father is:AB  The father must be able to contribute an O allele for the child to have the blood group O. Since an AB individual does not have an O allele to pass on, they cannot be the father.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>43", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "The diagram below is an illustration of the genetic cross between two parents. The parental gametes I,II,III and IV gave rise to the offspring below. Study it and answer the question      Gametes I, II, III and IV, respectively are", "images": ["Biology/imgs/2024/YKW62H.png"], "options": {"A": "T,T,T and t", "B": "T,t,t and t", "C": "T,T,t and t", "D": "T,t,T and t"}, "answer": "B", "explanation": "Gametes I, II, III and IV, respectively are T,t,t and t.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2024>44", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "The diagram below is an illustration of the genetic cross between two parents. The parental gametes I,II,III and IV gave rise to the offspring below. Study it and answer the question    Which of the following statements is correct about the cross?", "images": ["Biology/imgs/2024/YKW62H.png"], "options": {"A": "Both parents are heterozygous", "B": "The male is not heterozygous", "C": "The female is homozygous", "D": "Both parents are homozygous"}, "answer": "A", "explanation": "The genetic cross is between a heterozygous individual (Tt) and a homozygous recessive individual (tt).", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2024>45", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES", "question": "The physical appearance of an organism is described as its", "images": [], "options": {"A": "phenotype", "B": "genotype", "C": "allele", "D": "chromosome"}, "answer": "A", "explanation": "Phenotype refers to the observable characteristics or traits of an organism, such as its physical appearance, behavior, or biochemical properties. These traits result from the interaction of the organism's genotype (genetic makeup) with the environment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2024>46", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "Mutation leads to evolution because it", "images": [], "options": {"A": "kills all organisms where it has occurred", "B": "gives rise to offspring having same characteristics as the parents", "C": "does not confer adaptability to the offspring", "D": "gives rise to new individuals that differ from their parents"}, "answer": "D", "explanation": "Mutation is a change in the DNA sequence of an organism's genome. It can introduce new genetic variations by altering the genetic code, which can lead to new traits or characteristics in individuals. Mutations introduce genetic diversity by creating new alleles. This diversity is the raw material for evolution, as it can lead to new traits in individuals that may be subject to natural selection, driving evolutionary changes in populations over time.  Mutations are a fundamental source of genetic variation, which is essential for the process of evolution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>47", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "The male and female gametes which bear genes for inheritance in plants are locatèd in the", "images": [], "options": {"A": "anthers and petals", "B": "sepals and petals", "C": "stamens and pistils.", "D": "stamens and petals"}, "answer": "C", "explanation": "Stamens (male reproductive parts): The stamen is the male part of a flower and consists of the anther and filament. The anther produces pollen, which contains the male gametes (sperm cells). These gametes are involved in fertilizing the ovules.    Pistils (female reproductive parts): The pistil is the female part of a flower and consists of the stigma, style, and ovary. The ovary contains the ovules, which are the female gametes (egg cells).    So, the male gametes are located in the anthers of the stamens, and the female gametes are located in the ovules within the ovary of the pistils. This is where the processes of pollination and fertilization occur, leading to the formation of seeds and the continuation of plant species.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2024>48", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "Which type of breeding is represented by industrial melanism in peppered moths?", "images": [], "options": {"A": "Artificial selection", "B": "Natural selection", "C": "Inbreeding", "D": "Outbreeding"}, "answer": "B", "explanation": "Industrial melanism refers to the darkening of the peppered moth (Biston betularia) populations in industrial areas due to pollution. Before the Industrial Revolution, the light-colored form of the moth was more common because it was better camouflaged against lichen-covered tree bark. However, as industrial pollution killed the lichens and darkened the tree bark with soot, the dark-colored (melanic) form of the moth became better camouflaged and thus had a survival advantage.    Natural selection is the process through which individuals with traits that are better suited to their environment have a higher chance of survival and reproduction. In the case of the peppered moths, the dark-colored variant had a selective advantage in polluted environments, leading to an increase in its frequency within the population.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>49", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "In a test, a student paired some scientists with their famous work as shown below. Use it to answer the question  Scientist---Famous work  I. Charles Darwin → preservation of some food with heat  II. Gregor Mendel → natural selection  III. Jean Baptiste → inheritance of Lamarck                    IV Louis Pasteur → independent assortment of genes    The scientists that are not correctly paired with their famous work are", "images": [], "options": {"A": "I and II only", "B": "II and III only", "C": "I,II and IV", "D": "II,III and IV"}, "answer": "C", "explanation": "Charles Darwin: Known for his work on natural selection. Darwin's theory of natural selection explains how species evolve over time through the preservation of advantageous traits.    Gregor Mendel: Known for his work on the inheritance of genes. Mendel's experiments with pea plants established the basic principles of heredity, including the concepts of dominant and recessive traits.    Jean-Baptiste Lamarck: Known for his theory of inheritance of acquired characteristics (often referred to as Lamarckism), which is a different idea from natural selection. Lamarck proposed that traits acquired during an organism's lifetime could be passed on to offspring.    Louis Pasteur: Known for his work on pasteurization, which involves the preservation of food and liquids by heat to kill harmful microbes. He is also famous for his experiments disproving spontaneous generation.  The scientists that are not correctly paired with their famous work are: I, II, and IV", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2024>50", "subject": "Biology", "year": "2024", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION", "question": "In a test, a student paired some scientists with their famous work as shown below. Use it to answer the question  Scientist---Famous work  I. Charles Darwin → preservation of some food with heat  II. Gregor Mendel → natural selection  III. Jean Baptiste → inheritance of Lamarck                    IV Louis Pasteur → independent assortment of genes              Which of the scientists were involved in the study of evolution?", "images": [], "options": {"A": "I and III", "B": "II and III", "C": "I,II and IV", "D": "II,III and IV"}, "answer": "A", "explanation": "Charles Darwin: He is best known for his theory of natural selection, which is a fundamental concept in the study of evolution. Darwin's work laid the foundation for the modern understanding of how species evolve over time.  Jean-Baptiste Lamarck: He proposed an early theory of evolution known as Lamarckism, which suggested that organisms could pass on traits acquired during their lifetime to their offspring. Although his ideas were later replaced by Darwin's theory of natural selection, Lamarck was involved in early evolutionary theory.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>1", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "CONCEPT OF LIVING : CLASSIFICATION", "question": "The Genus into which man is classified is", "images": [], "options": {"A": "Chordata", "B": "Mammalia", "C": "Homo", "D": "Sapiens"}, "answer": "C", "explanation": "The genus into which man is classified is 'Homo'. In biological classification, the genus is a rank in the hierarchy of taxonomy that is one level above species. The full scientific name for humans is Homo sapiens, where 'Homo' is the genus.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2025>2", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : LIFE CYCLES", "question": "The diagram below is an illustration of the nymph of an insect. Study it and answer the question below      The organism illustrated is a stage in the development of", "images": ["Biology/imgs/2025/F7D4DR.png"], "options": {"A": "grasshopper", "B": "mosquito", "C": "termite", "D": "cockroach"}, "answer": "D", "explanation": "The nymph is the immature stage of insects that undergo incomplete metamorphosis (also called hemimetabolous development).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>3", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "CONCEPT OF LIVING : GROWTH", "question": "The diagram below is an illustration of the nymph of an insect. Study it and answer the question below    The growth process that would occur in the organism before it becomes an adult is", "images": ["Biology/imgs/2025/F7D4DR.png"], "options": {"A": "respiration", "B": "locomotion", "C": "moulting", "D": "sensitivity"}, "answer": "C", "explanation": "For a nymph (like in cockroach), the growth process it must undergo before becoming an adult is moulting (ecdysis).  Insects with incomplete metamorphosis grow by repeatedly shedding their exoskeleton as they increase in size.    This shedding process is called moulting or ecdysis.    After each moult, the nymph looks more like the adult, and with the final moult it develops fully formed wings and reproductive organs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>4", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "CONCEPT OF LIVING : PLANT STRUCTURE", "question": "The diagram below is an illustration of a dicot leaf. Study it and answer the question      The parts labelled I, II, III and IV respectively are", "images": ["Biology/imgs/2025/A8F3B6.png"], "options": {"A": "veins, apex, midrib, stalk", "B": "midrib, petiole, margin, stalk", "C": "apex, lamina, blade, axil", "D": "apex, midrib, lamina, axil"}, "answer": "D", "explanation": "Apex    The tip or end of the leaf, opposite the petiole (leaf stalk).    It can be pointed, rounded, notched, or other shapes depending on the plant.    2. Midrib    The central/main vein of the leaf.    It runs from the base (near the petiole) to the apex.    Provides support and helps in the transport of water, minerals, and food.    3. Lamina (Leaf blade)    The broad, flat surface of the leaf.    It is the main site of photosynthesis because it contains many chloroplasts.    It also helps in transpiration and gas exchange.    4. Axil    The angle formed between the upper side of a leaf/branch and the stem.    Usually contains a bud (axillary bud) that can grow into a new shoot or flower.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>5", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "CONCEPT OF LIVING : PLANT STRUCTURE", "question": "The diagram below is an illustration of a dicot leaf. Study it and answer the question    The part that contains the phloem and xylem is labelled", "images": ["Biology/imgs/2025/A8F3B6.png"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "B", "explanation": "Xylem → transports water and mineral salts from the roots to the leaves.    Phloem → transports manufactured food (sugar, amino acids, etc.) from the leaves to other parts of the plant.    Together, they form the vascular tissue system, usually arranged in vascular bundles inside stems, roots, and leaves.    In a leaf, the midrib and veins contain the vascular bundles", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>6", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The functions of vacuoles in plants are storage and", "images": [], "options": {"A": "protection", "B": "strength", "C": "support", "D": "sensitivity"}, "answer": "A", "explanation": "The functions of vacuoles in plants include storage and protection. Vacuoles are membrane-bound organelles that store nutrients, waste products, and help maintain turgor pressure in plant cells, which is essential for structural support.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2025>7", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "Four cells each with osmotic potential of about 3% salt solution were immersed respectively into solutions of different concentrations as follows.  I- 1% salt solution  II- 3% salt solution  III- 6% salt solution  IV- 10% salt solution  Use the information to answer the question below    Which of the solutions would cause an increase in osmotic pressure within the cell?", "images": [], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "C", "explanation": "An increase in osmotic pressure within the cell occurs when the cell is placed in a solution with a higher concentration of solutes than its own. In this case, solution III (6% salt solution) has a higher concentration than the 3% salt solution of the cells, leading to water moving into the cell and increasing osmotic pressure.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2025>8", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL AND ITS ENVIRONMENT", "question": "Four cells each with osmotic potential of about 3% salt solution were immersed respectively into solutions of different concentrations as follows.  I- 1% salt solution  II- 3% salt solution  III- 6% salt solution  IV- 10% salt solution  Use the information to answer the question below  If the cells are plant cells, what would happen to the cell in solution III? It would become", "images": [], "options": {"A": "turgid", "B": "crenated", "C": "haemolysed", "D": "plasmolysed"}, "answer": "D", "explanation": "If the plant cells are placed in solution III (6% salt solution), which has a higher concentration of solutes than the cells' internal environment (3% salt solution), the cells would lose water and undergo plasmolysis. Plasmolysis is the process where the cell membrane pulls away from the cell wall due to loss of water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>9", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE", "question": "How many molecules of oxygen are required for the aerobic respiration of three molecules of glucose?", "images": [], "options": {"A": "3", "B": "6", "C": "12", "D": "18"}, "answer": "D", "explanation": "For the aerobic respiration of glucose, the general equation is C6H12O6 + 6O2 → 6CO2 + 6H2O.   1 molecule of glucose requires 6 molecules of oxygen.  Therefore, for three molecules of glucose, the equation would be 3C6H12O6 + 18O2 → 18CO2 + 18H2O. . Thus, 18 molecules of oxygen are required for the aerobic respiration of three molecules of glucose.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2025>10", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS", "question": "Sclerenchyma tissue in plants is for", "images": [], "options": {"A": "water conduction", "B": "mechanical support", "C": "food storage", "D": "food transport"}, "answer": "B", "explanation": "Sclerenchyma tissue in plants provides mechanical support due to its thickened cell walls, which are often lignified. This tissue is important for maintaining the structural integrity of plants, especially in areas that require strength.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2025>11", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.", "question": "The diagram below is an illustration of a cell carrying out a biological process. Study it and answer the question below.      The process is referred to as", "images": ["Biology/imgs/2025/LXEB3T.png"], "options": {"A": "phagocytosis", "B": "pinocytosis", "C": "endocytosis", "D": "exocytosis"}, "answer": "A", "explanation": "The process by which a cell engulfs bacteria is called phagocytosis.  Phagocytosis is a type of endocytosis (\"cell eating\").    The cell membrane surrounds and engulfs large particles like bacteria, forming a phagosome.    The phagosome then fuses with lysosomes, which release enzymes to digest and destroy the bacteria.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>12", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "CONCEPT OF LIVING : ORGANIZATION OF LIFE", "question": "The diagram below is an illustration of a cell carrying out a biological process. Study it and answer the question below.    The biological system that contains cells that carry out the illustrated biological process in humans is", "images": ["Biology/imgs/2025/LXEB3T.png"], "options": {"A": "reproduction", "B": "circulatory", "C": "respiratory", "D": "nervous"}, "answer": "B", "explanation": "The biological system in humans that contains cells which carry out this process is the immune system (specifically, the circulatory system/blood where white blood cells are found).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>13", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : LIFE CYCLES", "question": "Which of the following statements is not correct about respiration in plants?", "images": [], "options": {"A": "It occurs in all plant tissues", "B": "Light and chlorophyll must be present for it to occur", "C": "Energy is produced as the end product", "D": "It occurs in the presence of oxygen"}, "answer": "B", "explanation": "The statement 'Light and chlorophyll must be present for it to occur' is not correct about respiration in plants. Respiration is a metabolic process that occurs in all plant tissues and does not require light or chlorophyll, as it primarily involves the breakdown of glucose to produce energy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2025>14", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "CONCEPT OF LIVING : EXCRETORY SYSTEMS", "question": "Urine, when compared with blood in mammals is hypertonic because", "images": [], "options": {"A": "urine contains high percentage of all cells", "B": "all traces of sugar have been removed from urine", "C": "urea is actively secreted into the renal tubules", "D": "much water has been removed from urine"}, "answer": "D", "explanation": "Urine is hypertonic compared to blood because much water has been removed from urine during the filtration and reabsorption processes in the kidneys. This results in a higher concentration of solutes, such as urea, in urine compared to blood.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>15", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "CONCEPT OF LIVING : HORMONAL COORDINATION", "question": "The naturally produced auxin in plants is", "images": [], "options": {"A": "indole acetic acid", "B": "dichlorophenoxyacetic acid", "C": "aldone", "D": "florigen"}, "answer": "A", "explanation": "The naturally produced auxin in plants is indole acetic acid (IAA). Auxins are a class of plant hormones that play a crucial role in regulating growth and development, including cell elongation and response to light.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2025>16", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "CONCEPT OF LIVING : NERVOUS COORDINATION", "question": "The sympathetic nervous system causes", "images": [], "options": {"A": "constriction of the arteries", "B": "heartbeat to slow down", "C": "increase in the secretion of saliva", "D": "contraction of the bladder"}, "answer": "A", "explanation": "The sympathetic nervous system is responsible for the 'fight or flight' response, which includes the constriction of arteries to redirect blood flow to essential organs and muscles. This response increases heart rate and decreases non-essential functions, such as saliva secretion.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2025>17", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "Long sightedness could be corrected using a", "images": [], "options": {"A": "biconvex lens", "B": "convex lens", "C": "biconcave lens", "D": "concave lens"}, "answer": "A", "explanation": "Long sightedness, or hyperopia, is a condition where distant objects can be seen clearly, but close ones do not come into proper focus. This condition can be corrected using a biconvex lens, which converges light rays before they enter the eye, allowing the image to be focused on the retina. The correct option is 'biconvex lens'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>18", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "CONCEPT OF LIVING : SENSE ORGANS", "question": "During the process of hearing in mammals, the structure in the middle ear which receives the first vibration is the", "images": [], "options": {"A": "oval window", "B": "round window", "C": "incus", "D": "malleus"}, "answer": "D", "explanation": "In the process of hearing, the malleus (also known as the hammer) is the first bone in the middle ear that receives vibrations from the eardrum. It transmits these vibrations to the incus and then to the stapes, which ultimately leads to the oval window. Therefore, the correct option is 'malleus'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2025>19", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : HABITATS", "question": "An important characteristic of fruits dispersed by water is the presence of", "images": [], "options": {"A": "fibrous covering", "B": "smooth surface", "C": "water content", "D": "pericarp"}, "answer": "A", "explanation": "Fruits that are dispersed by water typically have a fibrous covering that helps them float. This adaptation allows them to be carried by water currents to new locations where they can germinate. Thus, the correct option is 'fibrous covering'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2025>20", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : LIFE CYCLES", "question": "Plants which grow and produce fruits within a year are called", "images": [], "options": {"A": "biennials", "B": "perennials", "C": "annuals", "D": "herbs"}, "answer": "C", "explanation": "Plants that grow and produce fruits within a year are classified as annuals. They complete their life cycle, from germination to seed production, within a single growing season. Therefore, the correct option is 'annuals'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2025>21", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION", "question": "Chemical digestion in organisms is the", "images": [], "options": {"A": "breakdown of starch into carbohydrates", "B": "breakdown of complex molecules into simple molecules", "C": "build up of simple insoluble molecules into complex soluble molecules", "D": "build up of simple soluble molecules into complex insoluble molecules"}, "answer": "B", "explanation": "Chemical digestion refers to the process of breaking down complex molecules into simpler molecules, which can be absorbed by the body. This process involves enzymes that catalyze the breakdown of food substances. Therefore, the correct option is 'breakdown of complex molecules into simple molecules'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>22", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "Excessive bleeding from an injury could be due to the lack of vitamin", "images": [], "options": {"A": "K", "B": "E", "C": "B", "D": "A"}, "answer": "A", "explanation": "Excessive bleeding from an injury is often due to a lack of vitamin K, which is essential for the synthesis of clotting factors in the liver. Without sufficient vitamin K, the blood coagulation process is impaired, leading to increased bleeding.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2025>23", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ALIMENTARY SYSTEM", "question": "The diagram below is an illustration of a system in humans. Study it and answer the question      Enzymatic digestion of protein begins in the part labelled", "images": ["Biology/imgs/2025/4G3EPB.png"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "A", "explanation": "The enzymatic digestion of protein in man begins in the stomach.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>24", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ALIMENTARY SYSTEM", "question": "The diagram below is an illustration of a system in humans. Study it and answer the question    The parts that secrete substances involved in the digestion of fats are labelled", "images": ["Biology/imgs/2025/4G3EPB.png"], "options": {"A": "I, II and III", "B": "I and III", "C": "II and III", "D": "I, III and IV"}, "answer": "C", "explanation": "the parts that secrete these substances are:    Liver    Secretes bile (stored in the gall bladder).    Bile salts emulsify fats, breaking them into tiny droplets (micelles) → increases surface area for enzymes to act.    Pancreas    Secretes pancreatic juice, which contains pancreatic lipase.    Lipase breaks down emulsified fats into fatty acids and glycerol", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>25", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : ALIMENTARY SYSTEM", "question": "If the small intestine of an organism does not have villi, the organism will have a problem with", "images": [], "options": {"A": "digestion of food only", "B": "absorption of water", "C": "absorption of nutrients only", "D": "digestion of food and absorption of nutrients"}, "answer": "D", "explanation": "If the small intestine does not have villi, the organism will struggle with both digestion and absorption of nutrients. Villi are small, finger-like projections that increase the surface area for absorption. Without them, the efficiency of nutrient absorption is significantly reduced, impacting both digestion and nutrient uptake.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>26", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION", "question": "Which of the following statements is not correct about the dental formula of humans", "images": [], "options": {"A": "One pair of canines is on the upper jaw and three pairs of premolars are on the lower jaw", "B": "Two pairs of incisors are on the upper jaw and three pairs of premolars are on the lower jaw", "C": "Two pairs of incisors are on the upper jaw and three pairs of molars are on the lower jaw", "D": "One pair of canines is on the upper jaw and four pairs of molars are on the lower jaw"}, "answer": "B", "explanation": "The statement 'Two pairs of incisors are on the upper jaw and three pairs of premolars are on the lower jaw' is incorrect. In humans, there are typically two pairs of incisors on the upper jaw and two pairs on the lower jaw, along with two pairs of canines and two pairs of premolars on both jaws.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>27", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS", "question": "The relationship between a bean plant and a Tridax plant on a farmland is", "images": [], "options": {"A": "competition", "B": "predation", "C": "parasitism", "D": "epiphytism"}, "answer": "A", "explanation": "The relationship between a bean plant and a Tridax plant on farmland is one of competition. Both plants may compete for resources such as sunlight, water, and nutrients in the soil, which can affect their growth and survival.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2025>28", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS", "question": "The following ecological factors affect all habitats except", "images": [], "options": {"A": "temperature", "B": "humidity", "C": "light", "D": "pressure"}, "answer": "D", "explanation": "Among the listed ecological factors, pressure is not typically considered an ecological factor that affects all habitats in the same way as temperature, humidity, and light. While pressure can influence certain environments (like aquatic habitats), it is not a universal factor affecting all habitats.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>29", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS", "question": "The diagram below is an illustration of an ecological instrument used in a habitat. Study it and answer the question      The ecological instrument is a", "images": ["Biology/imgs/2025/2WBG4Y.png"], "options": {"A": "wind vane", "B": "Six's thermometer", "C": "Secchi disc", "D": "hygrometer"}, "answer": "C", "explanation": "A Secchi disc is a simple scientific instrument used to measure the transparency or turbidity of water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>30", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS", "question": "The diagram below is an illustration of an ecological instrument used in a habitat. Study it and answer the question    The instrument is used to measure a factor", "images": ["Biology/imgs/2025/2WBG4Y.png"], "options": {"A": "in the atmosphere", "B": "in water", "C": "on land", "D": "on grasses"}, "answer": "B", "explanation": "The disc is lowered into the water until it just disappears from sight.  The depth at which it disappears is noted.  The disc is then slowly raised until it reappears, and this depth is also noted.  The average of these two depths is recorded as the Secchi depth.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>31", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION", "question": "When Tilapia population in a pond  reaches the carrying capacity, the population", "images": [], "options": {"A": "alternately increases and decreases", "B": "remains unchanged", "C": "increases only", "D": "decreases only"}, "answer": "B", "explanation": "When a population reaches its carrying capacity, it typically stabilizes and remains unchanged over time, assuming no external factors affect it. This is because the environment can support only a limited number of individuals, leading to a balance between birth and death rates.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>32", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS", "question": "Which of the following statements about the pyramid of energy is correct", "images": [], "options": {"A": "Energy remains constant across trophic levels", "B": "Energy decreases from the base to the apex of the pyramid", "C": "Energy increases from the base to the apex of the pyramid", "D": "Each trophic level is an independent energy source"}, "answer": "B", "explanation": "The pyramid of energy illustrates that energy decreases from the base to the apex of the pyramid. This is due to the second law of thermodynamics, which states that energy transformations are not 100% efficient, leading to energy loss at each trophic level as heat.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>33", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE", "question": "Which of the following sequences represents the trend in eutrophication?", "images": [], "options": {"A": "Heavy mineralization → lack of oxygen → massive algal growth", "B": "Excessive nitrates → massive algal growth → lack of oxygen →  death of aquatic organisms", "C": "Excessive phosphates → lack of oxygen → massive algal growth → death of aquatic organisms", "D": "Massive algal growth → excessive nitrates → lack of oxygen"}, "answer": "B", "explanation": "Eutrophication is a process that typically begins with excessive nutrients, such as nitrates, leading to massive algal growth. This algal bloom can deplete oxygen in the water, resulting in the death of aquatic organisms. The sequence provided in option 2 accurately represents this trend.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>34", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING", "question": "Which of the following statements correctly describes the term population? The number of", "images": [], "options": {"A": "Tilapia in a lake", "B": "fungus and snail on leaf litter", "C": "bees and butterflies on a flower", "D": "flatworms and roundworms in the gut of an animal"}, "answer": "A", "explanation": "A population must be of the same species in a given habitat, while the other options describe communities (different species living together).", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>35", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING", "question": "What is the population density of  Ageratum sp. of frequency 1,850 on a land area measuring 100m2?", "images": [], "options": {"A": "18.50m2", "B": "18.05m2", "C": "0.50m2", "D": "0.05m2"}, "answer": "C", "explanation": "Population density is calculated as the number of individuals per unit area. In this case, the population density of Ageratum sp. is calculated as 1850 individuals / 100 m² = 18.50 individuals per m². However, the options provided are in m², which is incorrect. The correct answer should be 18.50 individuals/m², but since none of the options correctly represent this, the answer is -1.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>36", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : PUBLIC HEALTH", "question": "Which of the following activities does not control pathogens?", "images": [], "options": {"A": "Exposure to ultraviolet radiation", "B": "Use of disinfectants", "C": "Eating balanced diet", "D": "Destroying the habitats of pathogens"}, "answer": "C", "explanation": "Eating a balanced diet does not directly control pathogens. While a balanced diet can support the immune system, it does not actively eliminate or control pathogens like the other options do (ultraviolet radiation, disinfectants, and destroying habitats). Therefore, the correct answer is option C.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2025>37", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "MICROORGANISMS: MAN AND HEALTH : PUBLIC HEALTH", "question": "Which of the following diseases could be prevented by a BCG vaccination?", "images": [], "options": {"A": "Malaria", "B": "Cholera", "C": "Tuberculosis", "D": "Diphtheria"}, "answer": "C", "explanation": "BCG vaccination is specifically used to prevent tuberculosis (TB). It is not effective against malaria, cholera, or diphtheria.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>38", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "The main effect of deforestation is", "images": [], "options": {"A": "creation of new habitats", "B": "loss of soil particles", "C": "survival of more species", "D": "reduction of carbon (IV) oxide in the atmosphere."}, "answer": "B", "explanation": "The main effect of deforestation is the loss of soil particles due to erosion and degradation of the land. Deforestation leads to habitat destruction, which can result in soil erosion and loss of nutrients, making it difficult for plants to grow. Therefore, the correct answer is option B.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>39", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Which of the following resources cannot be conserved?", "images": [], "options": {"A": "Mineral resources", "B": "Soil and water", "C": "Forest and wildlife", "D": "Domestic wastes"}, "answer": "D", "explanation": "Domestic wastes are not conserved; instead, they are reduced, reused, recycled, or disposed of.  Domestic wastes, however, are not resources in the true sense — they are by-products of human activity. While waste can be managed, recycled, or reduced, it is not something we conserve.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>40", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION", "question": "Which of the following activities is not suitable for forest conservation?", "images": [], "options": {"A": "Felling of trees", "B": "Planting seedlings", "C": "Preventing bush fires", "D": "Planting tree crops"}, "answer": "A", "explanation": "Felling of trees is not suitable for forest conservation as it leads to deforestation, which negatively impacts the ecosystem. The other options, such as planting seedlings, preventing bush fires, and planting tree crops, are all activities that contribute positively to forest conservation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2025>41", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS", "question": "Which of the following pairs of features is an examples of discontinuous variation?", "images": [], "options": {"A": "Height and blood group", "B": "Height and sex", "C": "Colour and weight", "D": "Fingerprint and blood group"}, "answer": "D", "explanation": "Fingerprint and blood group are examples of discontinuous variation because they exhibit distinct categories without intermediate forms. In contrast, height and weight are continuous variations, as they can take on a range of values.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>42", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY", "question": "The ability of some individuals to taste phenylthiocarbamide is", "images": [], "options": {"A": "morphological variation", "B": "physiological variation", "C": "morphological adaptation", "D": "physiological adaptation"}, "answer": "B", "explanation": "The ability to taste phenylthiocarbamide (PTC) is a physiological variation, as it relates to the biochemical processes in the body that allow some individuals to taste this compound while others cannot. This trait is genetically determined and reflects differences in sensory perception.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>43", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES", "question": "Alleles are found on", "images": [], "options": {"A": "nucleus", "B": "nucleolus", "C": "chromosomes", "D": "tissues"}, "answer": "C", "explanation": "Alleles are found on chromosomes. They are different forms of a gene located at specific positions (loci) on chromosomes, and they determine various traits in an organism.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2025>44", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "A couple heterozygous for albino genes have normal skin colour. What is the probability that their child would be an albino?", "images": [], "options": {"A": "1/2", "B": "1/3", "C": "1/4", "D": "1"}, "answer": "C", "explanation": "In a couple heterozygous for albino genes (Aa x Aa), where 'A' represents the normal skin color allele and 'a' represents the albino allele, the probability of their child being an albino (aa) is 1/4. This is derived from a Punnett square analysis of the genetic cross.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>45", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS", "question": "The process occurring in the illustrated molecule below is", "images": ["Biology/imgs/2025/RJJJEB.png"], "options": {"A": "protein synthesis", "B": "gene coding", "C": "DNA replication", "D": "gene mutation"}, "answer": "C", "explanation": "DNA Replication: Enzymes, Mechanism, Steps, Applications  DNA replication is the process by which a cell creates an identical copy of its DNA. This is crucial for cell division, ensuring each new cell receives the same genetic information as the parent cell. The process involves unwinding the double helix, separating the strands, and synthesizing new complementary strands. AI Overview  DNA Replication: Enzymes, Mechanism, Steps, Applications  DNA replication is the process by which a cell creates an identical copy of its DNA. This is crucial for cell division, ensuring each new cell receives the same genetic information as the parent cell. The process involves unwinding the double helix, separating the strands, and synthesizing new complementary strands.", "marks": "1", "difficulty": "3"}, {"id": "objective>Biology>2025>46", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)", "question": "If the percentage of adenine in the DNA of a human is 32%, what will be the percentage of thymine?", "images": [], "options": {"A": "10%", "B": "16%", "C": "27%", "D": "32%"}, "answer": "C", "explanation": "In DNA, adenine (A) pairs with thymine (T). According to Chargaff's rules, the amount of adenine is equal to the amount of thymine in a double-stranded DNA molecule. Therefore, if adenine is 32%, thymine must also be 32%. However, since 32% is not an option, the closest correct answer is 27%, which is incorrect. Thus, the correct answer is not present in the options.", "marks": "1", "difficulty": "1"}, {"id": "objective>Biology>2025>47", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "BIOLOGY OF HEREDITY (GENETICS) : LINKAGE, SEX DETERMINATION AND SEX LINKED CHARACTERS", "question": "Which of the following statements is not correct about colour blindness?", "images": [], "options": {"A": "it is a sex-linked trait", "B": "Males are often carriers", "C": "Females are not carriers", "D": "The trait is controlled by a recessive gene"}, "answer": "C", "explanation": "Females can be carriers of color blindness, which is a sex-linked trait typically associated with the X chromosome. Males are more frequently affected because they have only one X chromosome. Therefore, the statement 'Females are not carriers' is incorrect.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>48", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "EVOLUTION : ADAPTATION FOR SURVIVAL", "question": "Lamarck's theory of evolution states that", "images": [], "options": {"A": "characteristics of organisms are not the sum of the characters of their parents", "B": "characteristics of organisms are determined by mutation", "C": "organisms transfer acquired characters to their offspring", "D": "organisms acquire genes from their parents"}, "answer": "C", "explanation": "Lamarck's theory of evolution, known as Lamarckism, posits that organisms can pass on characteristics acquired during their lifetime to their offspring. This is in contrast to Darwin's theory of natural selection, which emphasizes genetic inheritance and variation. Therefore, the correct answer is that organisms transfer acquired characters to their offspring.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>49", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.", "question": "The castes of the organisms found in a beehive are", "images": [], "options": {"A": "drones, queen and workers", "B": "workers, soldiers and reproductives", "C": "soldiers, workers and king", "D": "king, queen and soldiers"}, "answer": "A", "explanation": "In a beehive, the castes of the organisms are drones, the queen, and workers. Drones are male bees, the queen is the reproductive female, and workers are non-reproductive females that perform various tasks in the hive. Therefore, the correct answer is 'drones, queen and workers'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Biology>2025>50", "subject": "Biology", "year": "2025", "type": "Objective", "topic": "EVOLUTION : ADAPTATION FOR SURVIVAL", "question": "The theory of natural selection in evolution was formulated by", "images": [], "options": {"A": "Mathias Schleiden", "B": "Louis Pasteur", "C": "Charles Darwin", "D": "Jean Lamarck"}, "answer": "C", "explanation": "The theory of natural selection was formulated by Charles Darwin. He proposed that organisms better adapted to their environment tend to survive and produce more offspring. This concept is a fundamental principle of evolutionary biology. Therefore, the correct answer is 'Charles Darwin'.", "marks": "1", "difficulty": "2"}];